--
-- Name: inbox_v2_advance_tenant_stream_retained_prefix_v1(text, text, bigint, bigint, bigint, bigint, text, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>_inbox_v2_retention_owner
--

CREATE FUNCTION public.inbox_v2_advance_tenant_stream_retained_prefix_v1(checked_tenant_id text, checked_stream_epoch text, checked_from_position bigint, checked_to_position bigint, checked_expected_head_revision bigint, checked_mandatory_checkpoint_floor bigint, checked_reason_id text, checked_advance_hash text, checked_changed_at timestamp with time zone) RETURNS TABLE(tenant_id text, stream_epoch text, last_position bigint, min_retained_position bigint, revision bigint, created_at timestamp with time zone, updated_at timestamp with time zone, pruned_commit_count bigint, to_position bigint)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  v_db_now timestamptz := pg_catalog.clock_timestamp();
  v_head public.inbox_v2_tenant_stream_heads%rowtype;
  v_persisted_checkpoint_floor bigint;
  v_expected_commit_count bigint;
  v_commit_count bigint;
  v_expected_change_count bigint;
  v_expected_event_count bigint;
  v_expected_intent_count bigint;
  v_expected_work_count bigint;
  v_expected_outcome_count bigint;
  v_deleted_change_count bigint;
  v_deleted_event_count bigint;
  v_deleted_intent_count bigint;
  v_deleted_work_count bigint;
  v_deleted_outcome_count bigint;
begin
  if checked_tenant_id is null
     or checked_stream_epoch is null
     or checked_from_position is null
     or checked_to_position is null
     or checked_expected_head_revision is null
     or checked_mandatory_checkpoint_floor is null
     or checked_reason_id is null
     or checked_advance_hash is null
     or checked_changed_at is null
     or checked_from_position < 0
     or checked_to_position <= checked_from_position
     or checked_expected_head_revision < 1
     or checked_mandatory_checkpoint_floor < checked_to_position
     or not pg_catalog.isfinite(checked_changed_at)
     or pg_catalog.length(checked_stream_epoch) not between 8 and 256
     or pg_catalog.length(checked_reason_id) not between 3 and 256
     or pg_catalog.strpos(checked_reason_id, ':') = 0
     or checked_advance_hash !~ '^sha256:[0-9a-f]{64}$' then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.retained_prefix_arguments_invalid';
  end if;

  if checked_changed_at > v_db_now then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.retained_prefix_changed_at_future';
  end if;

  if checked_changed_at < v_db_now - interval '1 minute' then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.retained_prefix_changed_at_stale';
  end if;

  select head_row.*
    into v_head
    from public.inbox_v2_tenant_stream_heads head_row
   where head_row.tenant_id = checked_tenant_id
   for update;

  if not found or v_head.stream_epoch <> checked_stream_epoch then
    raise exception using
      errcode = 'P0002',
      message = 'inbox_v2.tenant_stream_not_found';
  end if;
  if v_head.min_retained_position <> checked_from_position
     or v_head.revision <> checked_expected_head_revision then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.retained_prefix_cas_conflict';
  end if;
  if checked_to_position > v_head.last_position
     or checked_changed_at < v_head.updated_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.retained_prefix_head_boundary_invalid';
  end if;

  select min(checkpoint_row.position)
    into v_persisted_checkpoint_floor
    from public.inbox_v2_projection_generations generation_row
    join public.inbox_v2_projection_checkpoints checkpoint_row
      on checkpoint_row.tenant_id = generation_row.tenant_id
     and checkpoint_row.projection_id = generation_row.projection_id
     and checkpoint_row.scope_id = generation_row.scope_id
     and checkpoint_row.generation = generation_row.generation
     and checkpoint_row.stream_epoch = generation_row.stream_epoch
   where generation_row.tenant_id = checked_tenant_id
     and generation_row.stream_epoch = checked_stream_epoch
     and generation_row.state in ('active', 'shadow');

  if v_persisted_checkpoint_floor is null
     or checked_mandatory_checkpoint_floor > v_persisted_checkpoint_floor
     or checked_to_position > checked_mandatory_checkpoint_floor then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.retained_prefix_checkpoint_blocked';
  end if;

  v_expected_commit_count :=
    checked_to_position - greatest(checked_from_position, 1);
  select count(*),
         coalesce(sum(commit_row.change_count), 0),
         coalesce(sum(commit_row.event_count), 0),
         coalesce(sum(commit_row.outbox_intent_count), 0)
    into v_commit_count,
         v_expected_change_count,
         v_expected_event_count,
         v_expected_intent_count
    from public.inbox_v2_tenant_stream_commits commit_row
   where commit_row.tenant_id = checked_tenant_id
     and commit_row.stream_epoch = checked_stream_epoch
     and commit_row.position >= greatest(checked_from_position, 1)
     and commit_row.position < checked_to_position;

  if v_commit_count <> v_expected_commit_count then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.retained_prefix_commit_gap';
  end if;

  if exists (
    select 1
      from public.inbox_v2_outbox_intents intent_row
      join public.inbox_v2_outbox_work_items work_row
        on work_row.tenant_id = intent_row.tenant_id
       and work_row.intent_id = intent_row.id
     where intent_row.tenant_id = checked_tenant_id
       and intent_row.stream_position >=
           greatest(checked_from_position, 1)
       and intent_row.stream_position < checked_to_position
       and work_row.state in ('pending', 'leased')
  ) then
    raise exception using
      errcode = '55000',
      message = 'inbox_v2.retained_prefix_outbox_inflight';
  end if;

  select count(*)
    into v_expected_work_count
    from public.inbox_v2_outbox_work_items work_row
    join public.inbox_v2_outbox_intents intent_row
      on intent_row.tenant_id = work_row.tenant_id
     and intent_row.id = work_row.intent_id
   where intent_row.tenant_id = checked_tenant_id
     and intent_row.stream_position >=
         greatest(checked_from_position, 1)
     and intent_row.stream_position < checked_to_position;

  if v_expected_work_count <> v_expected_intent_count then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.retained_prefix_manifest_incoherent';
  end if;

  select count(*)
    into v_expected_outcome_count
    from public.inbox_v2_outbox_outcomes outcome_row
    join public.inbox_v2_outbox_intents intent_row
      on intent_row.tenant_id = outcome_row.tenant_id
     and intent_row.id = outcome_row.intent_id
   where intent_row.tenant_id = checked_tenant_id
     and intent_row.stream_position >=
         greatest(checked_from_position, 1)
     and intent_row.stream_position < checked_to_position;

  perform pg_catalog.set_config(
    'hulee.inbox_v2_retention_prune',
    'enabled',
    true
  );

  delete from public.inbox_v2_outbox_outcomes outcome_row
  using public.inbox_v2_outbox_intents intent_row
   where intent_row.tenant_id = checked_tenant_id
     and intent_row.stream_position >=
         greatest(checked_from_position, 1)
     and intent_row.stream_position < checked_to_position
     and outcome_row.tenant_id = intent_row.tenant_id
     and outcome_row.intent_id = intent_row.id;
  get diagnostics v_deleted_outcome_count = row_count;

  delete from public.inbox_v2_outbox_work_items work_row
  using public.inbox_v2_outbox_intents intent_row
   where intent_row.tenant_id = checked_tenant_id
     and intent_row.stream_position >=
         greatest(checked_from_position, 1)
     and intent_row.stream_position < checked_to_position
     and work_row.tenant_id = intent_row.tenant_id
     and work_row.intent_id = intent_row.id;
  get diagnostics v_deleted_work_count = row_count;

  delete from public.inbox_v2_outbox_intents intent_row
   where intent_row.tenant_id = checked_tenant_id
     and intent_row.stream_position >=
         greatest(checked_from_position, 1)
     and intent_row.stream_position < checked_to_position;
  get diagnostics v_deleted_intent_count = row_count;

  delete from public.inbox_v2_domain_events event_row
   where event_row.tenant_id = checked_tenant_id
     and event_row.stream_position >=
         greatest(checked_from_position, 1)
     and event_row.stream_position < checked_to_position;
  get diagnostics v_deleted_event_count = row_count;

  delete from public.inbox_v2_tenant_stream_changes change_row
   where change_row.tenant_id = checked_tenant_id
     and change_row.stream_position >=
         greatest(checked_from_position, 1)
     and change_row.stream_position < checked_to_position;
  get diagnostics v_deleted_change_count = row_count;

  if v_deleted_change_count <> v_expected_change_count
     or v_deleted_event_count <> v_expected_event_count
     or v_deleted_intent_count <> v_expected_intent_count
     or v_deleted_work_count <> v_expected_work_count
     or v_deleted_outcome_count <> v_expected_outcome_count then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.retained_prefix_manifest_incoherent';
  end if;

  update public.inbox_v2_tenant_stream_heads head_row
     set min_retained_position = checked_to_position,
         revision = head_row.revision + 1,
         updated_at = checked_changed_at
   where head_row.tenant_id = checked_tenant_id
     and head_row.stream_epoch = checked_stream_epoch
     and head_row.min_retained_position = checked_from_position
     and head_row.revision = checked_expected_head_revision
  returning head_row.* into v_head;
  if not found then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.retained_prefix_cas_conflict';
  end if;

  insert into public.inbox_v2_tenant_stream_retention_advances (
    tenant_id, stream_epoch, from_position, to_position,
    expected_head_revision, resulting_head_revision,
    mandatory_checkpoint_floor, pruned_commit_count, reason_id,
    advance_hash, occurred_at, created_at
  ) values (
    checked_tenant_id,
    checked_stream_epoch,
    checked_from_position,
    checked_to_position,
    checked_expected_head_revision,
    v_head.revision,
    checked_mandatory_checkpoint_floor,
    v_commit_count,
    checked_reason_id,
    checked_advance_hash,
    checked_changed_at,
    checked_changed_at
  );

  perform pg_catalog.set_config(
    'hulee.inbox_v2_retention_prune',
    'disabled',
    true
  );

  return query select
    v_head.tenant_id,
    v_head.stream_epoch,
    v_head.last_position,
    v_head.min_retained_position,
    v_head.revision,
    v_head.created_at,
    v_head.updated_at,
    v_commit_count,
    checked_to_position;
end;
$_$;


ALTER FUNCTION public.inbox_v2_advance_tenant_stream_retained_prefix_v1(checked_tenant_id text, checked_stream_epoch text, checked_from_position bigint, checked_to_position bigint, checked_expected_head_revision bigint, checked_mandatory_checkpoint_floor bigint, checked_reason_id text, checked_advance_hash text, checked_changed_at timestamp with time zone) OWNER TO hulee_inbox_v2_retention_owner;

--
-- Name: inbox_v2_apply_participant_membership_mutation_v1(jsonb); Type: FUNCTION; Schema: public; Owner: <database-owner>_inbox_v2_membership_owner
--

CREATE FUNCTION public.inbox_v2_apply_participant_membership_mutation_v1(checked_payload jsonb) RETURNS bigint
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  allowed_keys constant text[] := array[
    'version',
    'operation',
    'tenantId',
    'conversationId',
    'participantId',
    'episodeId',
    'transitionId',
    'expectedMembershipRevision',
    'resultingMembershipRevision',
    'occurredAt',
    'originKind',
    'targetState',
    'episodeOriginProviderRosterMemberEvidenceId',
    'episodeOriginProviderRosterEvidenceId',
    'episodeOriginSourceThreadBindingId',
    'episodeOriginSourceExternalIdentityId',
    'episodeOriginOrderingKind',
    'episodeOriginOrderingScopeToken',
    'episodeOriginOrderingComparatorId',
    'episodeOriginOrderingComparatorRevision',
    'episodeOriginOrderingPosition',
    'episodeProviderOrderingHeadPosition',
    'episodeOriginMigrationProvenanceId',
    'episodeOriginSystemPolicyId',
    'episodeState',
    'episodeRole',
    'episodeEvidenceClassification',
    'episodeValidFrom',
    'episodeValidTo',
    'episodeExpectedRevision',
    'episodeResultingRevision',
    'transitionIntent',
    'transitionFromState',
    'transitionToState',
    'transitionFromRole',
    'transitionToRole',
    'transitionCauseKind',
    'transitionCauseProviderEvidenceKind',
    'transitionCauseProviderRosterMemberEvidenceId',
    'transitionCauseProviderRosterEvidenceId',
    'transitionCauseSourceThreadBindingId',
    'transitionCauseSourceExternalIdentityId',
    'transitionCauseOrderingKind',
    'transitionCauseOrderingScopeToken',
    'transitionCauseOrderingComparatorId',
    'transitionCauseOrderingComparatorRevision',
    'transitionCauseOrderingPosition',
    'transitionCauseActorEmployeeId',
    'transitionCauseTrustedServiceId',
    'transitionCauseMigrationProvenanceId',
    'transitionCauseSystemPolicyId',
    'transitionReasonCodeId',
    'transitionExpectedRevision',
    'transitionCurrentRevision',
    'transitionResultingRevision'
  ]::text[];
  mutation_version integer;
  mutation_operation text;
  mutation_tenant_id text;
  mutation_conversation_id text;
  mutation_participant_id text;
  mutation_episode_id text;
  mutation_transition_id text;
  mutation_expected_membership_revision bigint;
  mutation_resulting_membership_revision bigint;
  mutation_occurred_at timestamptz;
  mutation_origin_kind public.inbox_v2_participant_membership_origin_kind;
  mutation_target_state public.inbox_v2_participant_membership_state;
  mutation_episode_expected_revision bigint;
  mutation_episode_resulting_revision bigint;
  mutation_transition_expected_revision bigint;
  mutation_transition_current_revision bigint;
  mutation_transition_resulting_revision bigint;
  affected_rows bigint;
begin
  if checked_payload is null
     or pg_catalog.jsonb_typeof(checked_payload) <> 'object'
     or not (checked_payload ?& allowed_keys)
     or checked_payload - allowed_keys <> '{}'::jsonb then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.membership_mutation_payload_shape_invalid';
  end if;

  mutation_version := (checked_payload ->> 'version')::integer;
  mutation_operation := checked_payload ->> 'operation';
  mutation_tenant_id := checked_payload ->> 'tenantId';
  mutation_conversation_id := checked_payload ->> 'conversationId';
  mutation_participant_id := checked_payload ->> 'participantId';
  mutation_episode_id := checked_payload ->> 'episodeId';
  mutation_transition_id := checked_payload ->> 'transitionId';
  mutation_expected_membership_revision :=
    (checked_payload ->> 'expectedMembershipRevision')::bigint;
  mutation_resulting_membership_revision :=
    (checked_payload ->> 'resultingMembershipRevision')::bigint;
  mutation_occurred_at := (checked_payload ->> 'occurredAt')::timestamptz;
  mutation_origin_kind :=
    (checked_payload ->> 'originKind')::public.inbox_v2_participant_membership_origin_kind;
  mutation_target_state :=
    (checked_payload ->> 'targetState')::public.inbox_v2_participant_membership_state;
  mutation_episode_expected_revision :=
    (checked_payload ->> 'episodeExpectedRevision')::bigint;
  mutation_episode_resulting_revision :=
    (checked_payload ->> 'episodeResultingRevision')::bigint;
  mutation_transition_expected_revision :=
    (checked_payload ->> 'transitionExpectedRevision')::bigint;
  mutation_transition_current_revision :=
    (checked_payload ->> 'transitionCurrentRevision')::bigint;
  mutation_transition_resulting_revision :=
    (checked_payload ->> 'transitionResultingRevision')::bigint;

  if mutation_version <> 1
     or mutation_operation not in ('start', 'transition')
     or mutation_tenant_id is null
     or mutation_conversation_id is null
     or mutation_participant_id is null
     or mutation_episode_id is null
     or mutation_transition_id is null
     or mutation_expected_membership_revision is null
     or mutation_expected_membership_revision < 0
     or mutation_resulting_membership_revision is null
     or mutation_resulting_membership_revision < 1
     or mutation_resulting_membership_revision <>
       mutation_expected_membership_revision + 1
     or mutation_occurred_at is null
     or not pg_catalog.isfinite(mutation_occurred_at)
     or mutation_occurred_at >
       pg_catalog.clock_timestamp() + interval '5 minutes'
     or mutation_origin_kind is null
     or mutation_target_state is null
     or (checked_payload ->> 'episodeState')::public.inbox_v2_participant_membership_state
       is distinct from mutation_target_state
     or (checked_payload ->> 'transitionToState')::public.inbox_v2_participant_membership_state
       is distinct from mutation_target_state
     or (checked_payload ->> 'transitionCauseKind')::public.inbox_v2_participant_membership_origin_kind
       is distinct from mutation_origin_kind
     or mutation_episode_resulting_revision is null
     or mutation_transition_resulting_revision is null
     or mutation_episode_resulting_revision <>
       mutation_transition_resulting_revision then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.membership_mutation_payload_invalid';
  end if;

  if mutation_operation = 'start' then
    if mutation_target_state not in ('pending', 'active')
       or mutation_episode_expected_revision is not null
       or mutation_episode_resulting_revision <> 1
       or mutation_transition_expected_revision is not null
       or mutation_transition_current_revision is not null
       or checked_payload ->> 'transitionFromState' is not null
       or checked_payload ->> 'transitionFromRole' is not null
       or (checked_payload ->> 'episodeValidFrom')::timestamptz <>
         mutation_occurred_at
       or checked_payload ->> 'episodeValidTo' is not null
       or (
         mutation_target_state = 'pending'
         and checked_payload ->> 'transitionIntent' <> 'initial_pending'
       )
       or (
         mutation_target_state = 'active'
         and checked_payload ->> 'transitionIntent' <> 'initial_active'
       ) then
      raise exception using
        errcode = '22023',
        message = 'inbox_v2.membership_start_payload_invalid';
    end if;
  elsif mutation_episode_expected_revision is null
     or mutation_episode_expected_revision < 1
     or mutation_transition_expected_revision is distinct from
       mutation_episode_expected_revision
     or mutation_transition_current_revision is distinct from
       mutation_episode_expected_revision
     or mutation_episode_resulting_revision <>
       mutation_episode_expected_revision + 1
     or checked_payload ->> 'transitionFromState' is null
     or checked_payload ->> 'transitionFromRole' is null
     or checked_payload ->> 'transitionIntent' in (
       'initial_pending',
       'initial_active'
     ) then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.membership_transition_payload_invalid';
  end if;

  perform public.inbox_v2_lock_participant_membership_mutation_v1(
    mutation_tenant_id,
    mutation_conversation_id,
    mutation_expected_membership_revision,
    mutation_participant_id,
    case when mutation_operation = 'transition' then mutation_episode_id end,
    mutation_origin_kind,
    mutation_target_state
  );

  insert into public.inbox_v2_conversation_membership_commits (
    tenant_id,
    conversation_id,
    expected_membership_revision,
    resulting_membership_revision,
    occurred_at
  ) values (
    mutation_tenant_id,
    mutation_conversation_id,
    mutation_expected_membership_revision,
    mutation_resulting_membership_revision,
    mutation_occurred_at
  );

  if mutation_operation = 'start' then
    insert into public.inbox_v2_participant_membership_episodes (
      tenant_id,
      id,
      participant_id,
      conversation_id,
      origin_kind,
      origin_provider_roster_member_evidence_id,
      origin_provider_roster_evidence_id,
      origin_source_thread_binding_id,
      origin_source_external_identity_id,
      origin_ordering_kind,
      origin_ordering_scope_token,
      origin_ordering_comparator_id,
      origin_ordering_comparator_revision,
      origin_ordering_position,
      provider_ordering_head_position,
      origin_migration_provenance_id,
      origin_system_policy_id,
      state,
      role,
      evidence_classification,
      valid_from,
      valid_to,
      revision
    ) values (
      mutation_tenant_id,
      mutation_episode_id,
      mutation_participant_id,
      mutation_conversation_id,
      mutation_origin_kind,
      checked_payload ->> 'episodeOriginProviderRosterMemberEvidenceId',
      checked_payload ->> 'episodeOriginProviderRosterEvidenceId',
      checked_payload ->> 'episodeOriginSourceThreadBindingId',
      checked_payload ->> 'episodeOriginSourceExternalIdentityId',
      checked_payload ->> 'episodeOriginOrderingKind',
      checked_payload ->> 'episodeOriginOrderingScopeToken',
      checked_payload ->> 'episodeOriginOrderingComparatorId',
      (checked_payload ->> 'episodeOriginOrderingComparatorRevision')::bigint,
      (checked_payload ->> 'episodeOriginOrderingPosition')::bigint,
      (checked_payload ->> 'episodeProviderOrderingHeadPosition')::bigint,
      checked_payload ->> 'episodeOriginMigrationProvenanceId',
      checked_payload ->> 'episodeOriginSystemPolicyId',
      mutation_target_state,
      (checked_payload ->> 'episodeRole')::public.inbox_v2_participant_membership_role,
      (checked_payload ->> 'episodeEvidenceClassification')::public.inbox_v2_participant_membership_evidence,
      (checked_payload ->> 'episodeValidFrom')::timestamptz,
      (checked_payload ->> 'episodeValidTo')::timestamptz,
      mutation_episode_resulting_revision
    );
  end if;

  insert into public.inbox_v2_participant_membership_transitions (
    tenant_id,
    id,
    episode_id,
    participant_id,
    conversation_id,
    membership_revision,
    intent,
    from_state,
    to_state,
    from_role,
    to_role,
    cause_kind,
    cause_provider_evidence_kind,
    cause_provider_roster_member_evidence_id,
    cause_provider_roster_evidence_id,
    cause_source_thread_binding_id,
    cause_source_external_identity_id,
    cause_ordering_kind,
    cause_ordering_scope_token,
    cause_ordering_comparator_id,
    cause_ordering_comparator_revision,
    cause_ordering_position,
    cause_actor_employee_id,
    cause_trusted_service_id,
    cause_migration_provenance_id,
    cause_system_policy_id,
    reason_code_id,
    expected_revision,
    current_revision,
    resulting_revision,
    occurred_at
  ) values (
    mutation_tenant_id,
    mutation_transition_id,
    mutation_episode_id,
    mutation_participant_id,
    mutation_conversation_id,
    mutation_resulting_membership_revision,
    (checked_payload ->> 'transitionIntent')::public.inbox_v2_participant_membership_transition_intent,
    (checked_payload ->> 'transitionFromState')::public.inbox_v2_participant_membership_state,
    mutation_target_state,
    (checked_payload ->> 'transitionFromRole')::public.inbox_v2_participant_membership_role,
    (checked_payload ->> 'transitionToRole')::public.inbox_v2_participant_membership_role,
    mutation_origin_kind,
    (checked_payload ->> 'transitionCauseProviderEvidenceKind')::public.inbox_v2_provider_membership_evidence_kind,
    checked_payload ->> 'transitionCauseProviderRosterMemberEvidenceId',
    checked_payload ->> 'transitionCauseProviderRosterEvidenceId',
    checked_payload ->> 'transitionCauseSourceThreadBindingId',
    checked_payload ->> 'transitionCauseSourceExternalIdentityId',
    checked_payload ->> 'transitionCauseOrderingKind',
    checked_payload ->> 'transitionCauseOrderingScopeToken',
    checked_payload ->> 'transitionCauseOrderingComparatorId',
    (checked_payload ->> 'transitionCauseOrderingComparatorRevision')::bigint,
    (checked_payload ->> 'transitionCauseOrderingPosition')::bigint,
    checked_payload ->> 'transitionCauseActorEmployeeId',
    checked_payload ->> 'transitionCauseTrustedServiceId',
    checked_payload ->> 'transitionCauseMigrationProvenanceId',
    checked_payload ->> 'transitionCauseSystemPolicyId',
    checked_payload ->> 'transitionReasonCodeId',
    mutation_transition_expected_revision,
    mutation_transition_current_revision,
    mutation_transition_resulting_revision,
    mutation_occurred_at
  );

  if mutation_operation = 'transition' then
    update public.inbox_v2_participant_membership_episodes
       set state = mutation_target_state,
           role = (checked_payload ->> 'episodeRole')::public.inbox_v2_participant_membership_role,
           valid_to = (checked_payload ->> 'episodeValidTo')::timestamptz,
           revision = mutation_episode_resulting_revision,
           provider_ordering_head_position =
             (checked_payload ->> 'episodeProviderOrderingHeadPosition')::bigint
     where tenant_id = mutation_tenant_id
       and id = mutation_episode_id
       and participant_id = mutation_participant_id
       and conversation_id = mutation_conversation_id
       and origin_kind = mutation_origin_kind
       and origin_provider_roster_member_evidence_id is not distinct from
         checked_payload ->> 'episodeOriginProviderRosterMemberEvidenceId'
       and origin_provider_roster_evidence_id is not distinct from
         checked_payload ->> 'episodeOriginProviderRosterEvidenceId'
       and origin_source_thread_binding_id is not distinct from
         checked_payload ->> 'episodeOriginSourceThreadBindingId'
       and origin_source_external_identity_id is not distinct from
         checked_payload ->> 'episodeOriginSourceExternalIdentityId'
       and origin_ordering_kind is not distinct from
         checked_payload ->> 'episodeOriginOrderingKind'
       and origin_ordering_scope_token is not distinct from
         checked_payload ->> 'episodeOriginOrderingScopeToken'
       and origin_ordering_comparator_id is not distinct from
         checked_payload ->> 'episodeOriginOrderingComparatorId'
       and origin_ordering_comparator_revision is not distinct from
         (checked_payload ->> 'episodeOriginOrderingComparatorRevision')::bigint
       and origin_ordering_position is not distinct from
         (checked_payload ->> 'episodeOriginOrderingPosition')::bigint
       and origin_migration_provenance_id is not distinct from
         checked_payload ->> 'episodeOriginMigrationProvenanceId'
       and origin_system_policy_id is not distinct from
         checked_payload ->> 'episodeOriginSystemPolicyId'
       and evidence_classification =
         (checked_payload ->> 'episodeEvidenceClassification')::public.inbox_v2_participant_membership_evidence
       and valid_from = (checked_payload ->> 'episodeValidFrom')::timestamptz
       and state =
         (checked_payload ->> 'transitionFromState')::public.inbox_v2_participant_membership_state
       and role =
         (checked_payload ->> 'transitionFromRole')::public.inbox_v2_participant_membership_role
       and revision = mutation_episode_expected_revision;
    get diagnostics affected_rows = row_count;
    if affected_rows <> 1 then
      raise exception using
        errcode = '40001',
        message = 'inbox_v2.membership_episode_revision_conflict';
    end if;
  end if;

  update public.inbox_v2_conversation_membership_heads
     set membership_revision = mutation_resulting_membership_revision,
         updated_at = mutation_occurred_at
   where tenant_id = mutation_tenant_id
     and conversation_id = mutation_conversation_id
     and membership_revision = mutation_expected_membership_revision;
  get diagnostics affected_rows = row_count;
  if affected_rows <> 1 then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.conversation_membership_revision_conflict';
  end if;

  return mutation_resulting_membership_revision;
end;
$$;


ALTER FUNCTION public.inbox_v2_apply_participant_membership_mutation_v1(checked_payload jsonb) OWNER TO hulee_inbox_v2_membership_owner;

--
-- Name: inbox_v2_assert_account_identity_conflict(text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_account_identity_conflict(checked_tenant_id text, checked_source_account_id text, checked_identity_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  conflict_row record;
  candidate_stats record;
  identity_row record;
  transition_row record;
begin
  select *
    into conflict_row
    from public.inbox_v2_source_account_identity_conflicts
   where tenant_id = checked_tenant_id
     and source_account_id = checked_source_account_id
     and identity_revision = checked_identity_revision;

  if not found then
    raise exception 'missing source account identity conflict evidence'
      using errcode = '23514';
  end if;

  perform public.inbox_v2_assert_account_provisional_key(
    conflict_row.tenant_id,
    conflict_row.provisional_key_digest_sha256,
    conflict_row.source_account_id,
    conflict_row.source_connection_id,
    conflict_row.declaration_contract_id,
    conflict_row.declaration_contract_version,
    conflict_row.declaration_surface_id,
    conflict_row.provisional_connector_session_subject,
    conflict_row.provisional_observed_at
  );

  select
    count(*)::integer as actual_count,
    min(candidate.ordinal)::integer as minimum_ordinal,
    max(candidate.ordinal)::integer as maximum_ordinal,
    bool_and(
      candidate.realm_id = conflict_row.declaration_realm_id
      and candidate.realm_version = conflict_row.declaration_realm_version
      and candidate.canonicalization_version = conflict_row.declaration_canonicalization_version
      and candidate.object_kind_id = conflict_row.declaration_object_kind_id
      and candidate.scope_kind = conflict_row.declaration_scope_kind
      and candidate.scope_source_connection_id
        is not distinct from conflict_row.expected_scope_source_connection_id
      and candidate.scope_owner_key = conflict_row.expected_scope_owner_key
    ) as declaration_matches
    into candidate_stats
    from public.inbox_v2_source_account_identity_conflict_candidates candidate
   where candidate.tenant_id = checked_tenant_id
     and candidate.source_account_id = checked_source_account_id
     and candidate.identity_revision = checked_identity_revision;

  if candidate_stats.actual_count <> conflict_row.candidate_count
     or candidate_stats.minimum_ordinal <> 1
     or candidate_stats.maximum_ordinal <> conflict_row.candidate_count
     or candidate_stats.declaration_matches is distinct from true then
    raise exception 'source account identity conflict candidates are not exact and contiguous'
      using errcode = '23514';
  end if;

  select *
    into identity_row
    from public.inbox_v2_source_account_identities
   where tenant_id = checked_tenant_id
     and source_account_id = checked_source_account_id
     and revision = checked_identity_revision
     and state = 'conflicted'
     and active_conflict_revision = checked_identity_revision;

  if not found then
    raise exception 'source account identity conflict evidence has no exact current result'
      using errcode = '23514';
  end if;

  select *
    into transition_row
    from public.inbox_v2_source_account_identity_transitions
   where tenant_id = checked_tenant_id
     and source_account_id = checked_source_account_id
     and resulting_revision = checked_identity_revision
     and intent = 'mark_conflicted';

  if not found then
    raise exception 'source account identity conflict evidence has no exact inducing transition'
      using errcode = '23514';
  end if;

  if transition_row.to_state is distinct from identity_row.state
     or transition_row.resulting_account_generation
       is distinct from identity_row.account_generation
     or transition_row.occurred_at is distinct from identity_row.updated_at
     or transition_row.pinned_declaration_trusted_service_id
       is distinct from identity_row.declaration_loaded_by_trusted_service_id
     or conflict_row.source_connection_id
       is distinct from identity_row.source_connection_id
     or conflict_row.expected_scope_kind
       is distinct from identity_row.expected_scope_kind
     or conflict_row.expected_scope_source_connection_id
       is distinct from identity_row.expected_scope_source_connection_id
     or conflict_row.expected_scope_owner_key
       is distinct from identity_row.expected_scope_owner_key
     or conflict_row.provisional_key_digest_sha256
       is distinct from identity_row.provisional_key_digest_sha256
     or conflict_row.provisional_key_digest_sha256
       is distinct from transition_row.provisional_key_digest_sha256
     or conflict_row.provisional_connector_session_subject
       is distinct from identity_row.provisional_connector_session_subject
     or conflict_row.provisional_observed_at
       is distinct from identity_row.provisional_observed_at
     or conflict_row.provisional_observed_at
       is distinct from transition_row.provisional_observed_at
     or conflict_row.declaration_contract_id
       is distinct from identity_row.declaration_contract_id
     or conflict_row.declaration_contract_version
       is distinct from identity_row.declaration_contract_version
     or conflict_row.declaration_revision
       is distinct from identity_row.declaration_revision
     or conflict_row.declaration_surface_id
       is distinct from identity_row.declaration_surface_id
     or conflict_row.declaration_loaded_by_trusted_service_id
       is distinct from identity_row.declaration_loaded_by_trusted_service_id
     or conflict_row.declaration_loaded_at
       is distinct from identity_row.declaration_loaded_at
     or conflict_row.declaration_realm_id
       is distinct from identity_row.declaration_realm_id
     or conflict_row.declaration_realm_version
       is distinct from identity_row.declaration_realm_version
     or conflict_row.declaration_canonicalization_version
       is distinct from identity_row.declaration_canonicalization_version
     or conflict_row.declaration_object_kind_id
       is distinct from identity_row.declaration_object_kind_id
     or conflict_row.declaration_scope_kind
       is distinct from identity_row.declaration_scope_kind
     or conflict_row.decision_actor_trusted_service_id
       is distinct from transition_row.decision_actor_trusted_service_id
     or conflict_row.decision_policy_id
       is distinct from transition_row.decision_policy_id
     or conflict_row.decision_policy_version
       is distinct from transition_row.decision_policy_version
     or conflict_row.decision_reason_code_id
       is distinct from transition_row.decision_reason_code_id
     or conflict_row.decision_verification_evidence_token
       is distinct from transition_row.decision_verification_evidence_token
     or conflict_row.decision_decided_at
       is distinct from transition_row.decision_decided_at
     or conflict_row.detected_at is distinct from identity_row.updated_at
     or conflict_row.detected_at is distinct from transition_row.occurred_at then
    raise exception 'conflicted identity does not induce its exact evidence snapshot'
      using errcode = '23514';
  end if;
end
$$;



--
-- Name: inbox_v2_assert_account_identity_transition(text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_account_identity_transition(checked_tenant_id text, checked_source_account_id text, checked_resulting_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  identity_row record;
  transition_row record;
  predecessor_row record;
  snapshot_row record;
  conflict_row record;
begin
  select *
    into identity_row
    from public.inbox_v2_source_account_identities
   where tenant_id = checked_tenant_id
     and source_account_id = checked_source_account_id
     and revision = checked_resulting_revision;

  if not found then
    raise exception 'identity transition has no exact current result'
      using errcode = '23514';
  end if;

  select *
    into transition_row
    from public.inbox_v2_source_account_identity_transitions
   where tenant_id = checked_tenant_id
     and source_account_id = checked_source_account_id
     and resulting_revision = checked_resulting_revision;

  if not found then
    raise exception 'current account identity has no inducing transition'
      using errcode = '23514';
  end if;

  if transition_row.to_state is distinct from identity_row.state
     or transition_row.resulting_account_generation
       is distinct from identity_row.account_generation
     or transition_row.occurred_at is distinct from identity_row.updated_at
     or transition_row.pinned_declaration_trusted_service_id
       is distinct from identity_row.declaration_loaded_by_trusted_service_id then
    raise exception 'identity transition does not induce the exact current result fence'
      using errcode = '23514';
  end if;

  perform 1
    from public.inbox_v2_source_account_provisional_keys provisional_key
   where provisional_key.tenant_id = checked_tenant_id
     and provisional_key.source_account_id = checked_source_account_id
     and provisional_key.provisional_key_digest_sha256 =
       transition_row.provisional_key_digest_sha256
     and provisional_key.provisional_observed_at =
       transition_row.provisional_observed_at
     and provisional_key.source_connection_id = identity_row.source_connection_id
     and provisional_key.created_at <= transition_row.occurred_at;

  if not found then
    raise exception 'identity transition provisional key belongs to another account'
      using errcode = '23514';
  end if;

  if identity_row.state in ('provisional', 'conflicted') then
    perform public.inbox_v2_assert_account_provisional_key(
      identity_row.tenant_id,
      identity_row.provisional_key_digest_sha256,
      identity_row.source_account_id,
      identity_row.source_connection_id,
      identity_row.declaration_contract_id,
      identity_row.declaration_contract_version,
      identity_row.declaration_surface_id,
      identity_row.provisional_connector_session_subject,
      identity_row.provisional_observed_at
    );
  end if;

  if transition_row.intent = 'create_provisional' then
    if identity_row.provisional_key_digest_sha256
         is distinct from transition_row.provisional_key_digest_sha256
       or identity_row.provisional_observed_at
         is distinct from transition_row.provisional_observed_at then
      raise exception 'initial identity transition does not induce its provisional key'
        using errcode = '23514';
    end if;
  else
    select *
      into predecessor_row
      from public.inbox_v2_source_account_identity_transitions
     where tenant_id = checked_tenant_id
       and source_account_id = checked_source_account_id
       and resulting_revision = transition_row.current_revision;

    if not found
       or predecessor_row.resulting_account_generation
         is distinct from transition_row.current_account_generation
       or predecessor_row.to_state is distinct from transition_row.from_state
       or (
         transition_row.intent <> 'reauthenticate_verified'
         and (
           predecessor_row.provisional_key_digest_sha256
             is distinct from transition_row.provisional_key_digest_sha256
           or predecessor_row.provisional_observed_at
             is distinct from transition_row.provisional_observed_at
         )
       )
       or predecessor_row.pinned_declaration_trusted_service_id
         is distinct from transition_row.pinned_declaration_trusted_service_id
       or predecessor_row.occurred_at > transition_row.occurred_at then
      raise exception 'identity transition predecessor is missing or discontinuous'
        using errcode = '23514';
    end if;
  end if;

  if identity_row.state = 'verified' then
    if identity_row.verified_decision_actor_trusted_service_id
         is distinct from transition_row.decision_actor_trusted_service_id
       or identity_row.verified_decision_policy_id
         is distinct from transition_row.decision_policy_id
       or identity_row.verified_decision_policy_version
         is distinct from transition_row.decision_policy_version
       or identity_row.verified_decision_reason_code_id
         is distinct from transition_row.decision_reason_code_id
       or identity_row.verified_decision_verification_evidence_token
         is distinct from transition_row.decision_verification_evidence_token
       or identity_row.verified_decision_decided_at
         is distinct from transition_row.decision_decided_at then
      raise exception 'verified identity decision differs from its transition'
        using errcode = '23514';
    end if;

    select *
      into snapshot_row
      from public.inbox_v2_source_account_identity_verified_snapshots
     where tenant_id = checked_tenant_id
       and source_account_id = checked_source_account_id
       and identity_revision = identity_row.revision;

    if not found
       or snapshot_row.source_connection_id
         is distinct from identity_row.source_connection_id
       or snapshot_row.account_generation
         is distinct from identity_row.account_generation
       or snapshot_row.state is distinct from identity_row.state
       or snapshot_row.identity_declaration
         is distinct from identity_row.identity_declaration
       or snapshot_row.canonical_key_digest_sha256
         is distinct from identity_row.canonical_key_digest_sha256
       or snapshot_row.canonical_realm_id
         is distinct from identity_row.canonical_realm_id
       or snapshot_row.canonical_realm_version
         is distinct from identity_row.canonical_realm_version
       or snapshot_row.canonicalization_version
         is distinct from identity_row.canonicalization_version
       or snapshot_row.canonical_object_kind_id
         is distinct from identity_row.canonical_object_kind_id
       or snapshot_row.canonical_scope_kind
         is distinct from identity_row.canonical_scope_kind
       or snapshot_row.canonical_scope_source_connection_id
         is distinct from identity_row.canonical_scope_source_connection_id
       or snapshot_row.canonical_scope_owner_key
         is distinct from identity_row.canonical_scope_owner_key
       or snapshot_row.canonical_external_subject
         is distinct from identity_row.canonical_external_subject
       or snapshot_row.verified_decision_actor_trusted_service_id
         is distinct from identity_row.verified_decision_actor_trusted_service_id
       or snapshot_row.verified_decision_policy_id
         is distinct from identity_row.verified_decision_policy_id
       or snapshot_row.verified_decision_policy_version
         is distinct from identity_row.verified_decision_policy_version
       or snapshot_row.verified_decision_reason_code_id
         is distinct from identity_row.verified_decision_reason_code_id
       or snapshot_row.verified_decision_verification_evidence_token
         is distinct from identity_row.verified_decision_verification_evidence_token
       or snapshot_row.verified_decision_decided_at
         is distinct from identity_row.verified_decision_decided_at
       or snapshot_row.identity_created_at is distinct from identity_row.created_at
       or snapshot_row.verified_at is distinct from identity_row.updated_at then
      raise exception 'current verified identity differs from append-only generation authority'
        using errcode = '23514';
    end if;

    perform public.inbox_v2_assert_account_verified_snapshot(
      checked_tenant_id,
      checked_source_account_id,
      identity_row.revision
    );
  elsif identity_row.state = 'conflicted' then
    select *
      into conflict_row
      from public.inbox_v2_source_account_identity_conflicts
     where tenant_id = checked_tenant_id
       and source_account_id = checked_source_account_id
       and identity_revision = identity_row.active_conflict_revision;

    if not found
       or conflict_row.source_connection_id
         is distinct from identity_row.source_connection_id
       or conflict_row.expected_scope_kind
         is distinct from identity_row.expected_scope_kind
       or conflict_row.expected_scope_source_connection_id
         is distinct from identity_row.expected_scope_source_connection_id
       or conflict_row.expected_scope_owner_key
         is distinct from identity_row.expected_scope_owner_key
       or conflict_row.provisional_key_digest_sha256
         is distinct from identity_row.provisional_key_digest_sha256
       or conflict_row.provisional_key_digest_sha256
         is distinct from transition_row.provisional_key_digest_sha256
       or conflict_row.provisional_connector_session_subject
         is distinct from identity_row.provisional_connector_session_subject
       or conflict_row.provisional_observed_at
         is distinct from identity_row.provisional_observed_at
       or conflict_row.provisional_observed_at
         is distinct from transition_row.provisional_observed_at
       or conflict_row.declaration_contract_id
         is distinct from identity_row.declaration_contract_id
       or conflict_row.declaration_contract_version
         is distinct from identity_row.declaration_contract_version
       or conflict_row.declaration_revision
         is distinct from identity_row.declaration_revision
       or conflict_row.declaration_surface_id
         is distinct from identity_row.declaration_surface_id
       or conflict_row.declaration_loaded_by_trusted_service_id
         is distinct from identity_row.declaration_loaded_by_trusted_service_id
       or conflict_row.declaration_loaded_at
         is distinct from identity_row.declaration_loaded_at
       or conflict_row.declaration_realm_id
         is distinct from identity_row.declaration_realm_id
       or conflict_row.declaration_realm_version
         is distinct from identity_row.declaration_realm_version
       or conflict_row.declaration_canonicalization_version
         is distinct from identity_row.declaration_canonicalization_version
       or conflict_row.declaration_object_kind_id
         is distinct from identity_row.declaration_object_kind_id
       or conflict_row.declaration_scope_kind
         is distinct from identity_row.declaration_scope_kind
       or conflict_row.decision_actor_trusted_service_id
         is distinct from transition_row.decision_actor_trusted_service_id
       or conflict_row.decision_policy_id
         is distinct from transition_row.decision_policy_id
       or conflict_row.decision_policy_version
         is distinct from transition_row.decision_policy_version
       or conflict_row.decision_reason_code_id
         is distinct from transition_row.decision_reason_code_id
       or conflict_row.decision_verification_evidence_token
         is distinct from transition_row.decision_verification_evidence_token
       or conflict_row.decision_decided_at
         is distinct from transition_row.decision_decided_at
       or conflict_row.detected_at is distinct from identity_row.updated_at then
      raise exception 'conflicted identity does not induce its exact evidence snapshot'
        using errcode = '23514';
    end if;

    perform public.inbox_v2_assert_account_identity_conflict(
      checked_tenant_id,
      checked_source_account_id,
      identity_row.active_conflict_revision
    );
  end if;
end
$$;



--
-- Name: inbox_v2_assert_account_provisional_key(text, text, text, text, text, text, text, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_account_provisional_key(checked_tenant_id text, checked_key_digest text, checked_source_account_id text, checked_source_connection_id text, checked_contract_id text, checked_contract_version text, checked_surface_id text, checked_connector_session_subject text, checked_provisional_observed_at timestamp with time zone) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  key_row record;
begin
  select *
    into key_row
    from public.inbox_v2_source_account_provisional_keys
   where tenant_id = checked_tenant_id
     and provisional_key_digest_sha256 = checked_key_digest;

  if not found
     or key_row.source_account_id is distinct from checked_source_account_id
     or key_row.source_connection_id is distinct from checked_source_connection_id
     or key_row.declaration_contract_id is distinct from checked_contract_id
     or key_row.declaration_contract_version is distinct from checked_contract_version
     or key_row.declaration_surface_id is distinct from checked_surface_id
     or key_row.connector_session_subject
       is distinct from checked_connector_session_subject
     or key_row.provisional_observed_at
       is distinct from checked_provisional_observed_at then
    raise exception 'provisional key registry does not match the exact raw fingerprint'
      using errcode = '23514';
  end if;
end
$$;



--
-- Name: inbox_v2_assert_account_verified_snapshot(text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_account_verified_snapshot(checked_tenant_id text, checked_source_account_id text, checked_identity_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  snapshot_row record;
  transition_row record;
  predecessor_snapshot_row record;
  alias_row record;
begin
  select *
    into snapshot_row
    from public.inbox_v2_source_account_identity_verified_snapshots
   where tenant_id = checked_tenant_id
     and source_account_id = checked_source_account_id
     and identity_revision = checked_identity_revision;

  if not found then
    raise exception 'missing verified source account generation snapshot'
      using errcode = '23514';
  end if;

  select *
    into transition_row
    from public.inbox_v2_source_account_identity_transitions
   where tenant_id = checked_tenant_id
     and source_account_id = checked_source_account_id
     and resulting_revision = checked_identity_revision;

  if not found
     or transition_row.id is distinct from snapshot_row.transition_id
     or transition_row.intent not in (
       'promote_verified', 'resolve_conflict', 'reauthenticate_verified'
     )
     or transition_row.to_state is distinct from 'verified'
     or transition_row.resulting_account_generation
       is distinct from snapshot_row.account_generation
     or transition_row.pinned_declaration_trusted_service_id
       is distinct from snapshot_row.declaration_loaded_by_trusted_service_id
     or transition_row.decision_actor_trusted_service_id
       is distinct from snapshot_row.verified_decision_actor_trusted_service_id
     or transition_row.decision_policy_id
       is distinct from snapshot_row.verified_decision_policy_id
     or transition_row.decision_policy_version
       is distinct from snapshot_row.verified_decision_policy_version
     or transition_row.decision_reason_code_id
       is distinct from snapshot_row.verified_decision_reason_code_id
     or transition_row.decision_verification_evidence_token
       is distinct from snapshot_row.verified_decision_verification_evidence_token
     or transition_row.decision_decided_at
       is distinct from snapshot_row.verified_decision_decided_at
     or transition_row.occurred_at is distinct from snapshot_row.verified_at then
    raise exception 'verified account snapshot differs from its inducing transition'
      using errcode = '23514';
  end if;

  select *
    into alias_row
    from public.inbox_v2_source_account_identity_aliases
   where tenant_id = checked_tenant_id
     and canonical_source_account_id = checked_source_account_id
     and provisional_key_digest_sha256 =
       transition_row.provisional_key_digest_sha256
     and provisional_observed_at = transition_row.provisional_observed_at
     and expected_account_identity_revision = snapshot_row.identity_revision
     and expected_account_generation = snapshot_row.account_generation
     and target_identity_state = snapshot_row.state
     and canonical_key_digest_sha256 = snapshot_row.canonical_key_digest_sha256
     and decision_actor_trusted_service_id =
       transition_row.decision_actor_trusted_service_id
     and decision_policy_id = transition_row.decision_policy_id
     and decision_policy_version = transition_row.decision_policy_version
     and decision_reason_code_id = transition_row.decision_reason_code_id
     and decision_verification_evidence_token =
       transition_row.decision_verification_evidence_token
     and decision_decided_at = transition_row.decision_decided_at
     and created_at = transition_row.occurred_at
   limit 1;

  if not found
     or alias_row.provisional_source_connection_id
       is distinct from snapshot_row.source_connection_id
     or alias_row.identity_declaration is distinct from snapshot_row.identity_declaration
     or alias_row.canonical_realm_id is distinct from snapshot_row.canonical_realm_id
     or alias_row.canonical_realm_version
       is distinct from snapshot_row.canonical_realm_version
     or alias_row.canonicalization_version
       is distinct from snapshot_row.canonicalization_version
     or alias_row.canonical_object_kind_id
       is distinct from snapshot_row.canonical_object_kind_id
     or alias_row.canonical_scope_kind
       is distinct from snapshot_row.canonical_scope_kind
     or alias_row.canonical_scope_source_connection_id
       is distinct from snapshot_row.canonical_scope_source_connection_id
     or alias_row.canonical_scope_owner_key
       is distinct from snapshot_row.canonical_scope_owner_key
     or alias_row.canonical_external_subject
       is distinct from snapshot_row.canonical_external_subject then
    raise exception 'verified account generation has no exact inducing alias'
      using errcode = '23514';
  end if;

  if transition_row.intent = 'reauthenticate_verified' then
    select *
      into predecessor_snapshot_row
      from public.inbox_v2_source_account_identity_verified_snapshots
     where tenant_id = checked_tenant_id
       and source_account_id = checked_source_account_id
       and identity_revision = transition_row.current_revision;

    if not found
       or predecessor_snapshot_row.account_generation
         is distinct from transition_row.current_account_generation
       or predecessor_snapshot_row.source_connection_id
         is distinct from snapshot_row.source_connection_id
       or predecessor_snapshot_row.identity_declaration
         is distinct from snapshot_row.identity_declaration
       or predecessor_snapshot_row.canonical_key_digest_sha256
         is distinct from snapshot_row.canonical_key_digest_sha256
       or predecessor_snapshot_row.canonical_realm_id
         is distinct from snapshot_row.canonical_realm_id
       or predecessor_snapshot_row.canonical_realm_version
         is distinct from snapshot_row.canonical_realm_version
       or predecessor_snapshot_row.canonicalization_version
         is distinct from snapshot_row.canonicalization_version
       or predecessor_snapshot_row.canonical_object_kind_id
         is distinct from snapshot_row.canonical_object_kind_id
       or predecessor_snapshot_row.canonical_scope_kind
         is distinct from snapshot_row.canonical_scope_kind
       or predecessor_snapshot_row.canonical_scope_source_connection_id
         is distinct from snapshot_row.canonical_scope_source_connection_id
       or predecessor_snapshot_row.canonical_scope_owner_key
         is distinct from snapshot_row.canonical_scope_owner_key
       or predecessor_snapshot_row.canonical_external_subject
         is distinct from snapshot_row.canonical_external_subject
       or predecessor_snapshot_row.identity_created_at
         is distinct from snapshot_row.identity_created_at
       or predecessor_snapshot_row.verified_at > snapshot_row.verified_at then
      raise exception 'reauthentication changed the canonical account history anchor'
        using errcode = '23514';
    end if;
  end if;
end
$$;



--
-- Name: inbox_v2_assert_binding_evidence_set_integrity(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_binding_evidence_set_integrity(p_tenant_id text, p_evidence_set_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_expected_count smallint;
  v_expected_digest text;
  v_actual_count bigint;
  v_min_ordinal smallint;
  v_max_ordinal smallint;
  v_actual_digest text;
begin
  select reference_count, ordered_reference_digest_sha256
    into v_expected_count, v_expected_digest
    from public.inbox_v2_source_thread_binding_evidence_sets
   where tenant_id = p_tenant_id and id = p_evidence_set_id;

  if not found then
    return;
  end if;

  select count(*), min(ordinal), max(ordinal),
         encode(sha256(convert_to(coalesce(string_agg(
           ordinal::text || '|' || kind::text || '|' ||
           octet_length(coalesce(
             raw_inbound_event_id,
             normalized_inbound_event_id,
             source_account_identity_transition_id,
             source_account_identity_alias_id
           ))::text || ':' || coalesce(
             raw_inbound_event_id,
             normalized_inbound_event_id,
             source_account_identity_transition_id,
             source_account_identity_alias_id
           ), '' order by ordinal
         ), ''), 'UTF8')), 'hex')
    into v_actual_count, v_min_ordinal, v_max_ordinal, v_actual_digest
    from public.inbox_v2_source_thread_binding_evidence_references
   where tenant_id = p_tenant_id and evidence_set_id = p_evidence_set_id;

  if v_actual_count <> v_expected_count
     or v_min_ordinal <> 0
     or v_max_ordinal <> v_expected_count - 1
     or v_actual_digest <> v_expected_digest then
    raise exception using
      errcode = '23514',
      message = 'Inbox V2 binding evidence set count, ordinals or digest mismatch';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_client_merge_commit(text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_client_merge_commit(checked_tenant_id text, checked_resulting_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  redirect_row public.inbox_v2_client_merge_redirects%rowtype;
  head_row public.inbox_v2_client_merge_graph_heads%rowtype;
  source_row public.inbox_v2_client_merge_node_states%rowtype;
  target_row public.inbox_v2_client_merge_node_states%rowtype;
begin
  select * into redirect_row
  from public.inbox_v2_client_merge_redirects event_row
  where event_row.tenant_id = checked_tenant_id
    and event_row.resulting_graph_revision = checked_resulting_revision;
  if not found then
    return;
  end if;
  select * into head_row
  from public.inbox_v2_client_merge_graph_heads current_head
  where current_head.tenant_id = checked_tenant_id;
  select * into source_row
  from public.inbox_v2_client_merge_node_states current_node
  where current_node.tenant_id = checked_tenant_id
    and current_node.client_id = redirect_row.source_root_client_id;
  select * into target_row
  from public.inbox_v2_client_merge_node_states current_node
  where current_node.tenant_id = checked_tenant_id
    and current_node.client_id = redirect_row.target_root_client_id;

  if row(head_row.revision, head_row.updated_at, head_row.latest_redirect_id)
       is distinct from row(
         redirect_row.resulting_graph_revision,
         redirect_row.head_after_updated_at,
         redirect_row.id
       )
     or row(
       source_row.state, source_row.next_client_id, source_row.redirect_id,
       source_row.maximum_inbound_depth, source_row.revision,
       source_row.last_graph_revision, source_row.updated_at
     ) is distinct from row(
       redirect_row.source_after_state,
       redirect_row.source_after_next_client_id,
       redirect_row.source_after_redirect_id,
       redirect_row.source_after_maximum_inbound_depth,
       redirect_row.source_after_revision,
       redirect_row.source_after_last_graph_revision,
       redirect_row.source_after_updated_at
     )
     or row(
       target_row.state, target_row.next_client_id, target_row.redirect_id,
       target_row.maximum_inbound_depth, target_row.revision,
       target_row.last_graph_revision, target_row.updated_at
     ) is distinct from row(
       redirect_row.target_after_state,
       redirect_row.target_after_next_client_id,
       redirect_row.target_after_redirect_id,
       redirect_row.target_after_maximum_inbound_depth,
       redirect_row.target_after_revision,
       redirect_row.target_after_last_graph_revision,
       redirect_row.target_after_updated_at
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_commit_projection_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_client_merge_head_exists(text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_client_merge_head_exists(checked_tenant_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  tenant_count integer;
  head_count integer;
begin
  select count(*)::integer into tenant_count
  from public.tenants tenant_row
  where tenant_row.id = checked_tenant_id;

  select count(*)::integer into head_count
  from public.inbox_v2_client_merge_graph_heads head_row
  where head_row.tenant_id = checked_tenant_id;

  if tenant_count = 1 and head_count <> 1 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_head_missing';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_client_merge_node_exists(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_client_merge_node_exists(checked_tenant_id text, checked_client_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  client_count integer;
  node_count integer;
begin
  select count(*)::integer into client_count
  from public.clients client_row
  where client_row.tenant_id = checked_tenant_id
    and client_row.id = checked_client_id;

  select count(*)::integer into node_count
  from public.inbox_v2_client_merge_node_states node_row
  where node_row.tenant_id = checked_tenant_id
    and node_row.client_id = checked_client_id;

  if client_count = 1 and node_count <> 1 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_node_missing';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_client_link_episode(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_client_link_episode(checked_tenant_id text, checked_link_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  link_row public.inbox_v2_conversation_client_links%rowtype;
  claim_source_external_identity_id text;
  claim_created_at timestamptz;
  claim_revoked_at timestamptz;
  role_count integer;
  legacy_role_count integer;
  create_count integer;
  end_count integer;
  create_matches boolean;
  end_matches boolean;
begin
  select * into link_row
    from public.inbox_v2_conversation_client_links candidate
   where candidate.tenant_id = checked_tenant_id
     and candidate.id = checked_link_id;
  if not found then
    return;
  end if;

  if link_row.provenance_kind = 'source_identity_claim' then
    select
      claim_row.source_external_identity_id,
      claim_row.created_at,
      claim_row.revoked_at
      into
        claim_source_external_identity_id,
        claim_created_at,
        claim_revoked_at
      from public.inbox_v2_source_identity_claims claim_row
     where claim_row.tenant_id = link_row.tenant_id
       and claim_row.id = link_row.provenance_claim_id
       and claim_row.claim_version = link_row.provenance_claim_version
       and claim_row.target_kind = 'client_contact'
       and claim_row.target_client_contact_id =
         link_row.provenance_claim_target_client_contact_id;
    if not found
       or link_row.provenance_verification_verified_at is null
       or claim_created_at > link_row.provenance_verification_verified_at
       or link_row.provenance_verification_verified_at > link_row.valid_from
       or (
         claim_revoked_at is not null
         and link_row.valid_from > claim_revoked_at
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.conversation_client_link_claim_anchor_invalid';
    end if;

  end if;

  perform public.inbox_v2_assert_conversation_client_link_evidence(
    checked_tenant_id,
    checked_link_id
  );

  select count(*)::integer,
         count(*) filter (where role_row.role_id = 'core:legacy-unspecified')::integer
    into role_count, legacy_role_count
    from public.inbox_v2_conversation_client_link_roles role_row
   where role_row.tenant_id = checked_tenant_id
     and role_row.link_id = checked_link_id;
  if role_count < 1 or role_count > 16
     or (legacy_role_count <> 0 and role_count <> 1) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_roles_invalid';
  end if;

  if link_row.provenance_migration_id = 'core:legacy-v1'
     and (
       role_count <> 1
       or legacy_role_count <> 1
       or link_row.association_confidence <> 'confirmed'
       or link_row.valid_from_basis <> 'migration_observed'
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_legacy_v1_invalid';
  end if;

  select count(*)::integer,
         coalesce(bool_and(
           transition_row.occurred_at = link_row.valid_from
           and transition_row.actor_kind = link_row.linked_actor_kind
           and transition_row.actor_employee_id is not distinct from link_row.linked_actor_employee_id
           and transition_row.actor_service_id is not distinct from link_row.linked_actor_service_id
           and transition_row.policy_id = link_row.linked_policy_id
           and transition_row.policy_version = link_row.linked_policy_version
           and transition_row.reason_code_id = link_row.linked_reason_code_id
           and transition_row.policy_family is not distinct from link_row.linked_policy_family
           and transition_row.policy_definition_contract_version is not distinct from link_row.linked_policy_definition_contract_version
           and transition_row.policy_definition_digest_sha256 is not distinct from link_row.linked_policy_definition_digest_sha256
           and transition_row.policy_activation_head_revision is not distinct from link_row.linked_policy_activation_head_revision
         ), false)
    into create_count, create_matches
    from public.inbox_v2_conversation_client_link_transition_operations operation_row
    join public.inbox_v2_conversation_client_link_transitions transition_row
      on transition_row.tenant_id = operation_row.tenant_id
     and transition_row.id = operation_row.transition_id
     and transition_row.conversation_id = operation_row.conversation_id
     and transition_row.resulting_revision = operation_row.resulting_revision
   where operation_row.tenant_id = checked_tenant_id
     and operation_row.link_id = checked_link_id
     and operation_row.operation_kind = 'create_link';
  if create_count <> 1 or not create_matches then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_create_transition_invalid';
  end if;

  select count(*)::integer,
         coalesce(bool_and(
           transition_row.occurred_at = link_row.ended_at
           and transition_row.actor_kind = link_row.ended_actor_kind
           and transition_row.actor_employee_id is not distinct from link_row.ended_actor_employee_id
           and transition_row.actor_service_id is not distinct from link_row.ended_actor_service_id
           and transition_row.policy_id = link_row.ended_policy_id
           and transition_row.policy_version = link_row.ended_policy_version
           and transition_row.reason_code_id = link_row.ended_reason_code_id
           and transition_row.policy_family is not distinct from link_row.ended_policy_family
           and transition_row.policy_definition_contract_version is not distinct from link_row.ended_policy_definition_contract_version
           and transition_row.policy_definition_digest_sha256 is not distinct from link_row.ended_policy_definition_digest_sha256
           and transition_row.policy_activation_head_revision is not distinct from link_row.ended_policy_activation_head_revision
         ), false)
    into end_count, end_matches
    from public.inbox_v2_conversation_client_link_transition_operations operation_row
    join public.inbox_v2_conversation_client_link_transitions transition_row
      on transition_row.tenant_id = operation_row.tenant_id
     and transition_row.id = operation_row.transition_id
     and transition_row.conversation_id = operation_row.conversation_id
     and transition_row.resulting_revision = operation_row.resulting_revision
   where operation_row.tenant_id = checked_tenant_id
     and operation_row.link_id = checked_link_id
     and operation_row.operation_kind = 'end_link';
  if (link_row.state = 'active' and end_count <> 0)
     or (link_row.state = 'ended' and (end_count <> 1 or not end_matches)) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_end_transition_invalid';
  end if;

  if exists (
    select 1
      from public.inbox_v2_conversation_client_links other_row
     where other_row.tenant_id = link_row.tenant_id
       and other_row.conversation_id = link_row.conversation_id
       and other_row.client_id = link_row.client_id
       and other_row.id <> link_row.id
       and tstzrange(
         other_row.valid_from,
         coalesce(other_row.ended_at, 'infinity'::timestamptz),
         '[)'
       ) && tstzrange(
         link_row.valid_from,
         coalesce(link_row.ended_at, 'infinity'::timestamptz),
         '[)'
       )
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_history_overlap';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_client_link_evidence(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_client_link_evidence(checked_tenant_id text, checked_link_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  link_row public.inbox_v2_conversation_client_links%rowtype;
  verification_count integer;
  verification_min integer;
  verification_max integer;
  verification_distinct integer;
  audit_count integer;
  audit_min integer;
  audit_max integer;
  audit_distinct integer;
  duplicate_count integer;
  invalid_count integer;
begin
  select * into link_row
    from public.inbox_v2_conversation_client_links candidate
   where candidate.tenant_id = checked_tenant_id
     and candidate.id = checked_link_id;
  if not found then
    return;
  end if;

  select
    count(*) filter (where evidence_row.purpose = 'verification')::integer,
    min(evidence_row.ordinal) filter (where evidence_row.purpose = 'verification'),
    max(evidence_row.ordinal) filter (where evidence_row.purpose = 'verification'),
    count(distinct evidence_row.ordinal) filter (where evidence_row.purpose = 'verification')::integer,
    count(*) filter (where evidence_row.purpose = 'audit')::integer,
    min(evidence_row.ordinal) filter (where evidence_row.purpose = 'audit'),
    max(evidence_row.ordinal) filter (where evidence_row.purpose = 'audit'),
    count(distinct evidence_row.ordinal) filter (where evidence_row.purpose = 'audit')::integer
    into verification_count, verification_min, verification_max,
         verification_distinct, audit_count, audit_min, audit_max,
         audit_distinct
    from public.inbox_v2_conversation_client_link_evidence_references evidence_row
   where evidence_row.tenant_id = checked_tenant_id
     and evidence_row.link_id = checked_link_id;

  if (
       link_row.provenance_kind in ('source_identity_claim', 'trusted_policy')
       and (
         verification_count < 1 or verification_count > 50
         or verification_min <> 0
         or verification_max <> verification_count - 1
         or verification_distinct <> verification_count
       )
     ) or (
       link_row.provenance_kind not in ('source_identity_claim', 'trusted_policy')
       and verification_count <> 0
     ) or audit_count > 50 or (
       audit_count > 0 and (
         audit_min <> 0
         or audit_max <> audit_count - 1
         or audit_distinct <> audit_count
       )
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_evidence_cardinality_invalid';
  end if;

  select count(*)::integer into duplicate_count
    from (
      select evidence_row.purpose, evidence_row.evidence_kind,
             coalesce(
               evidence_row.source_identity_claim_id,
               evidence_row.client_contact_id,
               evidence_row.conversation_participant_id,
               evidence_row.raw_inbound_event_id,
               evidence_row.normalized_inbound_event_id,
               evidence_row.source_occurrence_id
             ) as evidence_id
        from public.inbox_v2_conversation_client_link_evidence_references evidence_row
       where evidence_row.tenant_id = checked_tenant_id
         and evidence_row.link_id = checked_link_id
       group by evidence_row.purpose, evidence_row.evidence_kind,
                coalesce(
                  evidence_row.source_identity_claim_id,
                  evidence_row.client_contact_id,
                  evidence_row.conversation_participant_id,
                  evidence_row.raw_inbound_event_id,
                  evidence_row.normalized_inbound_event_id,
                  evidence_row.source_occurrence_id
                )
      having count(*) > 1
    ) duplicate_row;
  if duplicate_count <> 0 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_evidence_duplicate';
  end if;

  select count(*)::integer into invalid_count
    from public.inbox_v2_conversation_client_link_evidence_references evidence_row
   where evidence_row.tenant_id = checked_tenant_id
     and evidence_row.link_id = checked_link_id
     and case evidence_row.evidence_kind
       when 'source_identity_claim' then not exists (
         select 1
           from public.inbox_v2_source_identity_claims claim_row
           join public.client_contacts contact_row
             on contact_row.tenant_id = claim_row.tenant_id
            and contact_row.id = claim_row.target_client_contact_id
          where claim_row.tenant_id = link_row.tenant_id
            and claim_row.id = evidence_row.source_identity_claim_id
            and claim_row.target_kind = 'client_contact'
            and contact_row.client_id = link_row.client_id
       )
       when 'client_contact' then not exists (
         select 1 from public.client_contacts contact_row
          where contact_row.tenant_id = link_row.tenant_id
            and contact_row.id = evidence_row.client_contact_id
            and contact_row.client_id = link_row.client_id
       )
       when 'conversation_participant' then not exists (
         select 1 from public.inbox_v2_conversation_participants participant_row
          where participant_row.tenant_id = link_row.tenant_id
            and participant_row.id = evidence_row.conversation_participant_id
            and participant_row.conversation_id = link_row.conversation_id
       )
       when 'source_occurrence' then not exists (
         select 1 from public.inbox_v2_source_occurrences occurrence_row
          where occurrence_row.tenant_id = link_row.tenant_id
            and occurrence_row.id = evidence_row.source_occurrence_id
            and occurrence_row.conversation_id = link_row.conversation_id
       )
       when 'raw_inbound_event' then not exists (
         select 1
           from public.inbox_v2_conversation_client_link_evidence_references occurrence_evidence
           join public.inbox_v2_source_occurrences occurrence_row
             on occurrence_row.tenant_id = occurrence_evidence.tenant_id
            and occurrence_row.id = occurrence_evidence.source_occurrence_id
          where occurrence_evidence.tenant_id = evidence_row.tenant_id
            and occurrence_evidence.link_id = evidence_row.link_id
            and occurrence_evidence.purpose = evidence_row.purpose
            and occurrence_evidence.evidence_kind = 'source_occurrence'
            and occurrence_row.raw_inbound_event_id = evidence_row.raw_inbound_event_id
       )
       when 'normalized_inbound_event' then not exists (
         select 1
           from public.inbox_v2_conversation_client_link_evidence_references occurrence_evidence
           join public.inbox_v2_source_occurrences occurrence_row
             on occurrence_row.tenant_id = occurrence_evidence.tenant_id
            and occurrence_row.id = occurrence_evidence.source_occurrence_id
          where occurrence_evidence.tenant_id = evidence_row.tenant_id
            and occurrence_evidence.link_id = evidence_row.link_id
            and occurrence_evidence.purpose = evidence_row.purpose
            and occurrence_evidence.evidence_kind = 'source_occurrence'
            and occurrence_row.normalized_inbound_event_id =
              evidence_row.normalized_inbound_event_id
       )
     end;
  if invalid_count <> 0 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_evidence_scope_invalid';
  end if;

  select count(*)::integer into invalid_count
    from public.inbox_v2_conversation_client_link_evidence_references evidence_row
   where evidence_row.tenant_id = checked_tenant_id
     and evidence_row.link_id = checked_link_id
     and evidence_row.purpose = 'verification'
     and case evidence_row.evidence_kind
       when 'source_identity_claim' then not exists (
         select 1
           from public.inbox_v2_source_identity_claims claim_row
           join public.client_contacts contact_row
             on contact_row.tenant_id = claim_row.tenant_id
            and contact_row.id = claim_row.target_client_contact_id
          where claim_row.tenant_id = link_row.tenant_id
            and claim_row.id = evidence_row.source_identity_claim_id
            and claim_row.target_kind = 'client_contact'
            and contact_row.client_id = link_row.client_id
            and claim_row.created_at <= link_row.valid_from
            and (
              claim_row.revoked_at is null
              or claim_row.revoked_at >= link_row.valid_from
            )
            and (
              exists (
                select 1
                  from public.inbox_v2_conversation_client_link_evidence_references participant_evidence
                  join public.inbox_v2_conversation_participants participant_row
                    on participant_row.tenant_id = participant_evidence.tenant_id
                   and participant_row.id = participant_evidence.conversation_participant_id
                 where participant_evidence.tenant_id = evidence_row.tenant_id
                   and participant_evidence.link_id = evidence_row.link_id
                   and participant_evidence.purpose = 'verification'
                   and participant_evidence.evidence_kind = 'conversation_participant'
                   and participant_row.conversation_id = link_row.conversation_id
                   and participant_row.subject_kind = 'source_external_identity'
                   and participant_row.subject_source_external_identity_id =
                     claim_row.source_external_identity_id
              ) or exists (
                select 1
                  from public.inbox_v2_conversation_client_link_evidence_references occurrence_evidence
                  join public.inbox_v2_source_occurrences occurrence_row
                    on occurrence_row.tenant_id = occurrence_evidence.tenant_id
                   and occurrence_row.id = occurrence_evidence.source_occurrence_id
                 where occurrence_evidence.tenant_id = evidence_row.tenant_id
                   and occurrence_evidence.link_id = evidence_row.link_id
                   and occurrence_evidence.purpose = 'verification'
                   and occurrence_evidence.evidence_kind = 'source_occurrence'
                   and occurrence_row.conversation_id = link_row.conversation_id
                   and occurrence_row.provider_actor_source_external_identity_id =
                     claim_row.source_external_identity_id
              )
            )
       )
       when 'client_contact' then not exists (
         select 1
           from public.inbox_v2_conversation_client_link_evidence_references participant_evidence
           join public.inbox_v2_conversation_participants participant_row
             on participant_row.tenant_id = participant_evidence.tenant_id
            and participant_row.id = participant_evidence.conversation_participant_id
          where participant_evidence.tenant_id = evidence_row.tenant_id
            and participant_evidence.link_id = evidence_row.link_id
            and participant_evidence.purpose = 'verification'
            and participant_evidence.evidence_kind = 'conversation_participant'
            and participant_row.conversation_id = link_row.conversation_id
            and participant_row.subject_kind = 'client_contact'
            and participant_row.subject_client_contact_id =
              evidence_row.client_contact_id
       )
       when 'conversation_participant' then not exists (
         select 1
           from public.inbox_v2_conversation_participants participant_row
          where participant_row.tenant_id = evidence_row.tenant_id
            and participant_row.id = evidence_row.conversation_participant_id
            and participant_row.conversation_id = link_row.conversation_id
            and (
              (
                participant_row.subject_kind = 'client_contact'
                and exists (
                  select 1
                    from public.inbox_v2_conversation_client_link_evidence_references contact_evidence
                   where contact_evidence.tenant_id = evidence_row.tenant_id
                     and contact_evidence.link_id = evidence_row.link_id
                     and contact_evidence.purpose = 'verification'
                     and contact_evidence.evidence_kind = 'client_contact'
                     and contact_evidence.client_contact_id =
                       participant_row.subject_client_contact_id
                )
              ) or (
                participant_row.subject_kind = 'source_external_identity'
                and exists (
                  select 1
                    from public.inbox_v2_conversation_client_link_evidence_references claim_evidence
                    join public.inbox_v2_source_identity_claims claim_row
                      on claim_row.tenant_id = claim_evidence.tenant_id
                     and claim_row.id = claim_evidence.source_identity_claim_id
                    join public.client_contacts contact_row
                      on contact_row.tenant_id = claim_row.tenant_id
                     and contact_row.id = claim_row.target_client_contact_id
                   where claim_evidence.tenant_id = evidence_row.tenant_id
                     and claim_evidence.link_id = evidence_row.link_id
                     and claim_evidence.purpose = 'verification'
                     and claim_evidence.evidence_kind = 'source_identity_claim'
                     and claim_row.source_external_identity_id =
                       participant_row.subject_source_external_identity_id
                     and claim_row.created_at <= link_row.valid_from
                     and (
                       claim_row.revoked_at is null
                       or claim_row.revoked_at >= link_row.valid_from
                     )
                     and contact_row.client_id = link_row.client_id
                )
              )
            )
       )
       when 'source_occurrence' then not exists (
         select 1
           from public.inbox_v2_source_occurrences occurrence_row
           join public.inbox_v2_conversation_client_link_evidence_references claim_evidence
             on claim_evidence.tenant_id = occurrence_row.tenant_id
            and claim_evidence.link_id = evidence_row.link_id
            and claim_evidence.purpose = 'verification'
            and claim_evidence.evidence_kind = 'source_identity_claim'
           join public.inbox_v2_source_identity_claims claim_row
             on claim_row.tenant_id = claim_evidence.tenant_id
            and claim_row.id = claim_evidence.source_identity_claim_id
           join public.client_contacts contact_row
             on contact_row.tenant_id = claim_row.tenant_id
            and contact_row.id = claim_row.target_client_contact_id
          where occurrence_row.tenant_id = evidence_row.tenant_id
            and occurrence_row.id = evidence_row.source_occurrence_id
            and occurrence_row.conversation_id = link_row.conversation_id
            and occurrence_row.provider_actor_source_external_identity_id =
              claim_row.source_external_identity_id
            and claim_row.created_at <= link_row.valid_from
            and (
              claim_row.revoked_at is null
              or claim_row.revoked_at >= link_row.valid_from
            )
            and contact_row.client_id = link_row.client_id
       )
       when 'raw_inbound_event' then false
       when 'normalized_inbound_event' then false
     end;
  if invalid_count <> 0 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_verification_graph_invalid';
  end if;

  if link_row.provenance_kind = 'source_identity_claim'
     and not exists (
       select 1
         from public.inbox_v2_conversation_client_link_evidence_references evidence_row
        where evidence_row.tenant_id = link_row.tenant_id
          and evidence_row.link_id = link_row.id
          and evidence_row.purpose = 'verification'
          and evidence_row.evidence_kind = 'source_identity_claim'
          and evidence_row.source_identity_claim_id =
            link_row.provenance_claim_id
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_claim_evidence_missing';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_client_link_head(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_client_link_head(checked_tenant_id text, checked_conversation_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_revision bigint;
  head_primary text;
  head_updated_at timestamptz;
  latest_revision bigint;
  latest_primary text;
  latest_occurred_at timestamptz;
begin
  select head_row.revision, head_row.primary_link_id, head_row.updated_at
    into head_revision, head_primary, head_updated_at
    from public.inbox_v2_conversation_client_link_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id;
  if not found then
    if exists (
      select 1
        from public.inbox_v2_conversation_client_link_transitions transition_row
       where transition_row.tenant_id = checked_tenant_id
         and transition_row.conversation_id = checked_conversation_id
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.conversation_client_link_head_missing';
    end if;
    return;
  end if;

  select transition_row.resulting_revision,
         transition_row.resulting_primary_link_id,
         transition_row.occurred_at
    into latest_revision, latest_primary, latest_occurred_at
    from public.inbox_v2_conversation_client_link_transitions transition_row
   where transition_row.tenant_id = checked_tenant_id
     and transition_row.conversation_id = checked_conversation_id
   order by transition_row.resulting_revision desc
   limit 1;
  if not found
     or head_revision <> latest_revision
     or head_primary is distinct from latest_primary
     or head_updated_at <> latest_occurred_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_head_projection_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_client_link_transition(text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_client_link_transition(checked_tenant_id text, checked_conversation_id text, checked_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  transition_row public.inbox_v2_conversation_client_link_transitions%rowtype;
  predecessor_primary text;
  predecessor_time timestamptz;
  operation_count integer;
  invalid_operation_count integer;
  primary_create_revision bigint;
  primary_end_revision bigint;
  primary_confidence public.inbox_v2_conversation_client_link_confidence;
  primary_provenance public.inbox_v2_conversation_client_link_provenance_kind;
  primary_legacy_count integer;
begin
  select * into transition_row
    from public.inbox_v2_conversation_client_link_transitions candidate
   where candidate.tenant_id = checked_tenant_id
     and candidate.conversation_id = checked_conversation_id
     and candidate.resulting_revision = checked_revision;
  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_transition_missing';
  end if;

  if checked_revision = 1 then
    if transition_row.current_revision is not null
       or transition_row.previous_primary_link_id is not null then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.conversation_client_link_transition_predecessor_invalid';
    end if;
  else
    select predecessor.resulting_primary_link_id, predecessor.occurred_at
      into predecessor_primary, predecessor_time
      from public.inbox_v2_conversation_client_link_transitions predecessor
     where predecessor.tenant_id = checked_tenant_id
       and predecessor.conversation_id = checked_conversation_id
       and predecessor.resulting_revision = checked_revision - 1;
    if not found
       or transition_row.current_revision <> checked_revision - 1
       or transition_row.previous_primary_link_id is distinct from predecessor_primary
       or transition_row.occurred_at < predecessor_time then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.conversation_client_link_transition_predecessor_invalid';
    end if;
  end if;

  select count(*)::integer,
         count(*) filter (where (
           (operation_row.operation_kind = 'create_link' and (
             link_row.valid_from <> transition_row.occurred_at
             or link_row.linked_actor_kind <> transition_row.actor_kind
             or link_row.linked_actor_employee_id is distinct from transition_row.actor_employee_id
             or link_row.linked_actor_service_id is distinct from transition_row.actor_service_id
             or link_row.linked_policy_id <> transition_row.policy_id
             or link_row.linked_policy_version <> transition_row.policy_version
             or link_row.linked_reason_code_id <> transition_row.reason_code_id
             or link_row.linked_policy_family is distinct from transition_row.policy_family
             or link_row.linked_policy_definition_contract_version is distinct from transition_row.policy_definition_contract_version
             or link_row.linked_policy_definition_digest_sha256 is distinct from transition_row.policy_definition_digest_sha256
             or link_row.linked_policy_activation_head_revision is distinct from transition_row.policy_activation_head_revision
           ))
           or (operation_row.operation_kind = 'end_link' and (
             link_row.ended_at is distinct from transition_row.occurred_at
             or link_row.ended_actor_kind is distinct from transition_row.actor_kind
             or link_row.ended_actor_employee_id is distinct from transition_row.actor_employee_id
             or link_row.ended_actor_service_id is distinct from transition_row.actor_service_id
             or link_row.ended_policy_id is distinct from transition_row.policy_id
             or link_row.ended_policy_version is distinct from transition_row.policy_version
             or link_row.ended_reason_code_id is distinct from transition_row.reason_code_id
             or link_row.ended_policy_family is distinct from transition_row.policy_family
             or link_row.ended_policy_definition_contract_version is distinct from transition_row.policy_definition_contract_version
             or link_row.ended_policy_definition_digest_sha256 is distinct from transition_row.policy_definition_digest_sha256
             or link_row.ended_policy_activation_head_revision is distinct from transition_row.policy_activation_head_revision
           ))
         ))::integer
    into operation_count, invalid_operation_count
    from public.inbox_v2_conversation_client_link_transition_operations operation_row
    join public.inbox_v2_conversation_client_links link_row
      on link_row.tenant_id = operation_row.tenant_id
     and link_row.id = operation_row.link_id
     and link_row.conversation_id = operation_row.conversation_id
   where operation_row.tenant_id = checked_tenant_id
     and operation_row.transition_id = transition_row.id;
  if operation_count > 100
     or invalid_operation_count <> 0
     or (
       operation_count = 0
       and transition_row.previous_primary_link_id is not distinct from
         transition_row.resulting_primary_link_id
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_transition_operations_invalid';
  end if;

  if transition_row.resulting_primary_link_id is not null then
    select link_row.association_confidence,
           link_row.provenance_kind,
           count(role_row.role_id) filter (
             where role_row.role_id = 'core:legacy-unspecified'
           )::integer,
           min(operation_row.resulting_revision) filter (
             where operation_row.operation_kind = 'create_link'
           ),
           min(operation_row.resulting_revision) filter (
             where operation_row.operation_kind = 'end_link'
           )
      into primary_confidence,
           primary_provenance,
           primary_legacy_count,
           primary_create_revision,
           primary_end_revision
      from public.inbox_v2_conversation_client_links link_row
      left join public.inbox_v2_conversation_client_link_roles role_row
        on role_row.tenant_id = link_row.tenant_id
       and role_row.link_id = link_row.id
      left join public.inbox_v2_conversation_client_link_transition_operations operation_row
        on operation_row.tenant_id = link_row.tenant_id
       and operation_row.link_id = link_row.id
     where link_row.tenant_id = checked_tenant_id
       and link_row.id = transition_row.resulting_primary_link_id
       and link_row.conversation_id = checked_conversation_id
     group by link_row.association_confidence, link_row.provenance_kind;
    if not found
       or primary_confidence <> 'confirmed'
       or primary_provenance = 'migration'
       or primary_legacy_count <> 0
       or primary_create_revision is null
       or primary_create_revision > checked_revision
       or (primary_end_revision is not null and primary_end_revision <= checked_revision) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.conversation_client_link_primary_invalid';
    end if;
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_membership_commit(text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_membership_commit(checked_tenant_id text, checked_conversation_id text, checked_membership_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_revision bigint;
  transition_count integer;
  transition_time_mismatch_count integer;
begin
  select head_row.membership_revision
    into head_revision
    from public.inbox_v2_conversation_membership_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id;
  select count(*)::integer,
         count(*) filter (
           where transition_row.occurred_at is distinct from
             commit_row.occurred_at
         )::integer
    into transition_count, transition_time_mismatch_count
    from public.inbox_v2_conversation_membership_commits commit_row
    join public.inbox_v2_participant_membership_transitions transition_row
      on transition_row.tenant_id = commit_row.tenant_id
     and transition_row.conversation_id = commit_row.conversation_id
     and transition_row.membership_revision =
       commit_row.resulting_membership_revision
   where commit_row.tenant_id = checked_tenant_id
     and commit_row.conversation_id = checked_conversation_id
     and commit_row.resulting_membership_revision = checked_membership_revision;

  if head_revision is null
     or head_revision < checked_membership_revision
     or transition_count < 1
     or transition_time_mismatch_count <> 0 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_membership_commit_uninduced';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_membership_head(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_membership_head(checked_tenant_id text, checked_conversation_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  conversation_count integer;
  head_count integer;
begin
  select count(*)::integer
    into conversation_count
    from public.inbox_v2_conversations conversation_row
   where conversation_row.tenant_id = checked_tenant_id
     and conversation_row.id = checked_conversation_id;
  select count(*)::integer
    into head_count
    from public.inbox_v2_conversation_membership_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id;

  if conversation_count <> head_count then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_membership_head_missing';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_membership_projection(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_membership_projection(checked_tenant_id text, checked_conversation_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_revision bigint;
  head_created_at timestamptz;
  head_updated_at timestamptz;
  matching_commit_count integer;
  matching_commit_occurred_at timestamptz;
  newer_commit_count integer;
begin
  select head_row.membership_revision,
         head_row.created_at,
         head_row.updated_at
    into head_revision, head_created_at, head_updated_at
    from public.inbox_v2_conversation_membership_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id;
  if not found then
    return;
  end if;

  select count(*)::integer, max(commit_row.occurred_at)
    into matching_commit_count, matching_commit_occurred_at
    from public.inbox_v2_conversation_membership_commits commit_row
   where commit_row.tenant_id = checked_tenant_id
     and commit_row.conversation_id = checked_conversation_id
     and commit_row.resulting_membership_revision = head_revision;
  select count(*)::integer
    into newer_commit_count
    from public.inbox_v2_conversation_membership_commits commit_row
   where commit_row.tenant_id = checked_tenant_id
     and commit_row.conversation_id = checked_conversation_id
     and commit_row.resulting_membership_revision > head_revision;

  if (head_revision = 0 and matching_commit_count <> 0)
     or (head_revision > 0 and matching_commit_count <> 1)
     or (
       head_revision = 0
       and head_updated_at is distinct from head_created_at
     )
     or (
       head_revision > 0
       and head_updated_at is distinct from matching_commit_occurred_at
     )
     or newer_commit_count <> 0 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_membership_head_projection_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_conversation_timeline_head(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_conversation_timeline_head(checked_tenant_id text, checked_conversation_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  conversation_count integer;
  matching_head_count integer;
  latest_activity record;
begin
  if checked_tenant_id is null or checked_conversation_id is null then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_timeline_head_key_missing';
  end if;

  if not exists (
    select 1
      from public.tenants tenant_row
     where tenant_row.id = checked_tenant_id
  ) then
    return;
  end if;

  select count(*)::integer
    into conversation_count
    from public.inbox_v2_conversations conversation_row
   where conversation_row.tenant_id = checked_tenant_id
     and conversation_row.id = checked_conversation_id;

  if conversation_count = 0 then
    if exists (
      select 1
        from public.inbox_v2_conversation_heads head_row
       where head_row.tenant_id = checked_tenant_id
         and head_row.conversation_id = checked_conversation_id
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.conversation_timeline_head_orphaned';
    end if;
    return;
  end if;

  if exists (
    select 1
      from public.inbox_v2_conversation_identity_fences fence_row
     where fence_row.tenant_id = checked_tenant_id
       and fence_row.conversation_id = checked_conversation_id
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_identity_retired';
  end if;

  select item_row.id, item_row.timeline_sequence, item_row.occurred_at
    into latest_activity
    from public.inbox_v2_timeline_items item_row
   where item_row.tenant_id = checked_tenant_id
     and item_row.conversation_id = checked_conversation_id
     and item_row.activity_kind = 'eligible'
   order by item_row.timeline_sequence desc
   limit 1;

  select count(*)::integer
    into matching_head_count
    from public.inbox_v2_conversation_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id
     and head_row.latest_timeline_sequence = coalesce((
       select max(item_row.timeline_sequence)
         from public.inbox_v2_timeline_items item_row
        where item_row.tenant_id = checked_tenant_id
          and item_row.conversation_id = checked_conversation_id
     ), 0)
     and (
       (latest_activity.id is null
         and head_row.latest_activity_item_id is null
         and head_row.latest_activity_timeline_sequence is null
         and head_row.latest_activity_at is null)
       or (latest_activity.id is not null
         and head_row.latest_activity_item_id = latest_activity.id
         and head_row.latest_activity_timeline_sequence =
           latest_activity.timeline_sequence
         and head_row.latest_activity_at = latest_activity.occurred_at)
     );

  if matching_head_count <> 1 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_timeline_head_coherence';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_current_internal_membership_authority(text, text, text, public.inbox_v2_participant_membership_origin_kind, public.inbox_v2_participant_membership_state); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_current_internal_membership_authority(checked_tenant_id text, checked_participant_id text, checked_conversation_id text, checked_origin_kind public.inbox_v2_participant_membership_origin_kind, checked_state public.inbox_v2_participant_membership_state) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  employee_deactivated_at timestamptz;
  conversation_transport public.inbox_v2_conversation_transport;
begin
  if checked_origin_kind <> 'hulee_internal_command'
     or checked_state not in ('pending', 'active') then
    return;
  end if;

  select employee_row.deactivated_at, conversation_row.transport
    into employee_deactivated_at, conversation_transport
    from public.inbox_v2_conversation_participants participant_row
    join public.employees employee_row
      on employee_row.tenant_id = participant_row.tenant_id
     and employee_row.id = participant_row.subject_employee_id
    join public.inbox_v2_conversations conversation_row
      on conversation_row.tenant_id = participant_row.tenant_id
     and conversation_row.id = participant_row.conversation_id
   where participant_row.tenant_id = checked_tenant_id
     and participant_row.id = checked_participant_id
     and participant_row.conversation_id = checked_conversation_id
     and participant_row.subject_kind = 'employee'
   for no key update of employee_row;

  if not found
     or employee_deactivated_at is not null
     or conversation_transport <> 'internal' then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.internal_membership_subject_or_employee_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_outbound_dispatch_head(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_outbound_dispatch_head(checked_tenant_id text, checked_dispatch_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  dispatch_row public.inbox_v2_outbound_dispatches%rowtype;
  last_attempt_row public.inbox_v2_outbound_dispatch_attempts%rowtype;
  actual_attempt_count bigint;
  maximum_attempt_number integer;
begin
  select * into dispatch_row
    from public.inbox_v2_outbound_dispatches candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.id = checked_dispatch_id;
  if not found then
    return;
  end if;

  select count(*), max(attempt_row.attempt_number)
    into actual_attempt_count, maximum_attempt_number
    from public.inbox_v2_outbound_dispatch_attempts attempt_row
   where attempt_row.tenant_id = checked_tenant_id
     and attempt_row.dispatch_id = checked_dispatch_id;

  if actual_attempt_count <> dispatch_row.attempt_count
     or (actual_attempt_count = 0 and maximum_attempt_number is not null)
     or (actual_attempt_count > 0 and
       maximum_attempt_number <> dispatch_row.attempt_count) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_dispatch_attempt_set_invalid';
  end if;

  if dispatch_row.attempt_count = 0 then
    if dispatch_row.last_attempt_id is not null
       or dispatch_row.state in ('attempting', 'accepted', 'outcome_unknown') then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_dispatch_zero_attempt_head_invalid';
    end if;
    if dispatch_row.state = 'terminal_failure' and not exists (
      select 1
        from public.inbox_v2_outbound_routes route_row
        join public.inbox_v2_source_thread_binding_heads binding_row
          on binding_row.tenant_id = route_row.tenant_id
         and binding_row.binding_id = route_row.source_thread_binding_id
       where route_row.tenant_id = checked_tenant_id
         and route_row.id = dispatch_row.route_id
         and binding_row.updated_at <= dispatch_row.updated_at
         and (
           binding_row.remote_access_state <> 'active'
           or binding_row.administrative_state <> 'enabled'
           or binding_row.account_generation <> route_row.account_generation
           or binding_row.binding_generation <> route_row.binding_generation
           or binding_row.remote_access_revision <>
              route_row.remote_access_revision
           or binding_row.administrative_revision <>
              route_row.administrative_revision
           or binding_row.capability_revision <> route_row.capability_revision
           or binding_row.route_descriptor_revision <>
              route_row.route_descriptor_revision
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_dispatch_zero_attempt_route_failure_unproven';
    end if;
  else
    select * into last_attempt_row
      from public.inbox_v2_outbound_dispatch_attempts attempt_row
     where attempt_row.tenant_id = checked_tenant_id
       and attempt_row.id = dispatch_row.last_attempt_id
       and attempt_row.dispatch_id = checked_dispatch_id
       and attempt_row.route_id = dispatch_row.route_id
       and attempt_row.message_id = dispatch_row.message_id;

    if not found or last_attempt_row.attempt_number <> dispatch_row.attempt_count then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_dispatch_last_attempt_invalid';
    end if;

    if (dispatch_row.state = 'attempting' and last_attempt_row.outcome_kind <> 'pending')
       or (dispatch_row.state = 'accepted' and not (
         last_attempt_row.outcome_kind = 'accepted'
         or (
           last_attempt_row.outcome_kind = 'outcome_unknown'
           and exists (
             select 1
               from public.inbox_v2_outbound_dispatch_reconciliation_decisions decision_row
              where decision_row.tenant_id = checked_tenant_id
                and decision_row.unknown_attempt_id = last_attempt_row.id
                and decision_row.result_state = 'accepted'
           )
         )
       ))
       or (dispatch_row.state = 'retryable_failure' and not (
         (
           last_attempt_row.outcome_kind = 'retryable_failure'
           and dispatch_row.retry_authorization_decision_id is null
         )
         or (
           last_attempt_row.outcome_kind = 'outcome_unknown'
           and exists (
             select 1
               from public.inbox_v2_outbound_dispatch_reconciliation_decisions decision_row
              where decision_row.tenant_id = checked_tenant_id
                and decision_row.id = dispatch_row.retry_authorization_decision_id
                and decision_row.unknown_attempt_id = last_attempt_row.id
                and decision_row.result_state = 'retryable_failure'
           )
         )
       ))
       or (dispatch_row.state = 'terminal_failure' and not (
         last_attempt_row.outcome_kind = 'terminal_failure'
         or (
           last_attempt_row.outcome_kind = 'outcome_unknown'
           and exists (
             select 1
               from public.inbox_v2_outbound_dispatch_reconciliation_decisions decision_row
              where decision_row.tenant_id = checked_tenant_id
                and decision_row.unknown_attempt_id = last_attempt_row.id
                and decision_row.result_state = 'terminal_failure'
           )
         )
         or exists (
           select 1
             from public.inbox_v2_outbound_routes route_row
             join public.inbox_v2_source_thread_binding_heads binding_row
               on binding_row.tenant_id = route_row.tenant_id
              and binding_row.binding_id = route_row.source_thread_binding_id
            where route_row.tenant_id = checked_tenant_id
              and route_row.id = dispatch_row.route_id
              and binding_row.updated_at <= dispatch_row.updated_at
              and (
                binding_row.remote_access_state <> 'active'
                or binding_row.administrative_state <> 'enabled'
                or binding_row.account_generation <>
                   route_row.account_generation
                or binding_row.binding_generation <>
                   route_row.binding_generation
                or binding_row.remote_access_revision <>
                   route_row.remote_access_revision
                or binding_row.administrative_revision <>
                   route_row.administrative_revision
                or binding_row.capability_revision <>
                   route_row.capability_revision
                or binding_row.route_descriptor_revision <>
                   route_row.route_descriptor_revision
              )
         )
       ))
       or (dispatch_row.state = 'outcome_unknown' and (
         last_attempt_row.outcome_kind <> 'outcome_unknown'
         or exists (
           select 1
             from public.inbox_v2_outbound_dispatch_reconciliation_decisions decision_row
            where decision_row.tenant_id = checked_tenant_id
              and decision_row.unknown_attempt_id = last_attempt_row.id
         )
       ))
       or (dispatch_row.state = 'cancelled'
         and last_attempt_row.outcome_kind = 'pending') then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_dispatch_state_attempt_mismatch';
    end if;

    if (dispatch_row.state = 'attempting' and
         dispatch_row.updated_at <> last_attempt_row.opened_at)
       or (dispatch_row.state = 'outcome_unknown' and
         dispatch_row.updated_at <> last_attempt_row.completed_at)
       or (dispatch_row.state = 'accepted' and
         last_attempt_row.outcome_kind = 'accepted' and
         dispatch_row.updated_at <> last_attempt_row.completed_at)
       or (dispatch_row.state = 'retryable_failure' and
         last_attempt_row.outcome_kind = 'retryable_failure' and
         dispatch_row.updated_at <> last_attempt_row.completed_at)
       or (dispatch_row.state = 'terminal_failure' and
         last_attempt_row.outcome_kind = 'terminal_failure' and
         dispatch_row.updated_at <> last_attempt_row.completed_at)
       or (
         last_attempt_row.outcome_kind = 'outcome_unknown'
         and dispatch_row.state in (
           'accepted', 'retryable_failure', 'terminal_failure'
         )
         and exists (
           select 1
             from public.inbox_v2_outbound_dispatch_reconciliation_decisions
               decision_row
            where decision_row.tenant_id = checked_tenant_id
              and decision_row.unknown_attempt_id = last_attempt_row.id
              and decision_row.result_state::text = dispatch_row.state::text
         )
         and not exists (
           select 1
             from public.inbox_v2_outbound_dispatch_reconciliation_decisions
               decision_row
            where decision_row.tenant_id = checked_tenant_id
              and decision_row.unknown_attempt_id = last_attempt_row.id
              and decision_row.result_state::text = dispatch_row.state::text
              and decision_row.decided_at = dispatch_row.updated_at
         )
       ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_dispatch_transition_time_invalid';
    end if;
  end if;

  if dispatch_row.state = 'attempting' and not exists (
    select 1 from public.inbox_v2_outbound_dispatch_attempts attempt_row
     where attempt_row.tenant_id = checked_tenant_id
       and attempt_row.id = dispatch_row.active_attempt_id
       and attempt_row.dispatch_id = checked_dispatch_id
       and attempt_row.outcome_kind = 'pending'
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_dispatch_active_attempt_invalid';
  end if;

  if dispatch_row.retry_authorization_decision_id is not null and not exists (
    select 1
      from public.inbox_v2_outbound_dispatch_reconciliation_decisions decision_row
     where decision_row.tenant_id = checked_tenant_id
       and decision_row.id = dispatch_row.retry_authorization_decision_id
       and decision_row.dispatch_id = checked_dispatch_id
       and decision_row.result_state = 'retryable_failure'
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_dispatch_retry_decision_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_outbound_multi_send_children(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_outbound_multi_send_children(checked_tenant_id text, checked_operation_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  operation_row public.inbox_v2_outbound_multi_send_operations%rowtype;
  actual_count bigint;
  minimum_ordinal smallint;
  maximum_ordinal smallint;
  actual_digest text;
  all_dispatches_linked boolean;
begin
  select * into operation_row
    from public.inbox_v2_outbound_multi_send_operations candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.id = checked_operation_id;
  if not found then
    return;
  end if;

  select
    count(*),
    min(child_row.ordinal),
    max(child_row.ordinal),
    case when count(*) = 0 then null else encode(
      sha256(convert_to(string_agg(
        child_row.ordinal::text || ':' ||
        octet_length(child_row.conversation_id)::text || ':' ||
        child_row.conversation_id || ':' ||
        octet_length(child_row.external_thread_id)::text || ':' ||
        child_row.external_thread_id || ':' ||
        octet_length(child_row.binding_id)::text || ':' || child_row.binding_id || ':' ||
        octet_length(child_row.source_account_id)::text || ':' ||
        child_row.source_account_id || ':' ||
        octet_length(child_row.route_id)::text || ':' || child_row.route_id || ':' ||
        octet_length(child_row.dispatch_id)::text || ':' || child_row.dispatch_id,
        '|' order by child_row.ordinal
      ), 'UTF8')),
      'hex'
    ) end,
    coalesce(bool_and(
      dispatch_row.multi_send_operation_id = checked_operation_id
    ), true)
  into actual_count, minimum_ordinal, maximum_ordinal, actual_digest,
    all_dispatches_linked
  from public.inbox_v2_outbound_multi_send_children child_row
  join public.inbox_v2_outbound_dispatches dispatch_row
    on dispatch_row.tenant_id = child_row.tenant_id
   and dispatch_row.id = child_row.dispatch_id
   and dispatch_row.route_id = child_row.route_id
   and dispatch_row.message_id = child_row.message_id
  where child_row.tenant_id = checked_tenant_id
    and child_row.operation_id = checked_operation_id;

  if actual_count <> operation_row.child_count
     or minimum_ordinal <> 0
     or maximum_ordinal <> actual_count - 1
     or actual_digest <> operation_row.children_digest_sha256
     or not all_dispatches_linked
     or exists (
       select 1
         from public.inbox_v2_outbound_dispatches dispatch_row
        where dispatch_row.tenant_id = checked_tenant_id
          and dispatch_row.multi_send_operation_id = checked_operation_id
          and not exists (
            select 1
              from public.inbox_v2_outbound_multi_send_children child_row
             where child_row.tenant_id = dispatch_row.tenant_id
               and child_row.operation_id = checked_operation_id
               and child_row.dispatch_id = dispatch_row.id
               and child_row.route_id = dispatch_row.route_id
               and child_row.message_id = dispatch_row.message_id
          )
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_multi_send_children_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_outbound_reconciliation(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_outbound_reconciliation(checked_tenant_id text, checked_decision_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  decision_row public.inbox_v2_outbound_dispatch_reconciliation_decisions%rowtype;
  attempt_row public.inbox_v2_outbound_dispatch_attempts%rowtype;
  route_row public.inbox_v2_outbound_routes%rowtype;
  actual_count bigint;
  minimum_ordinal smallint;
  maximum_ordinal smallint;
  actual_digest text;
  snapshot_permission_count bigint;
  snapshot_permissions_digest text;
begin
  select * into decision_row
    from public.inbox_v2_outbound_dispatch_reconciliation_decisions candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.id = checked_decision_id;
  if not found then
    return;
  end if;

  select * into attempt_row
    from public.inbox_v2_outbound_dispatch_attempts candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.id = decision_row.unknown_attempt_id
     and candidate_row.dispatch_id = decision_row.dispatch_id
     and candidate_row.route_id = decision_row.route_id
     and candidate_row.message_id = decision_row.message_id
     and candidate_row.outcome_kind = 'outcome_unknown'
     and candidate_row.revision = 2;
  select * into route_row
    from public.inbox_v2_outbound_routes candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.id = decision_row.route_id;

  if attempt_row.id is null
     or route_row.id is null
     or decision_row.decided_at < attempt_row.completed_at
     or attempt_row.retry_safety_declared_by_trusted_service_id <>
        route_row.adapter_loaded_by_trusted_service_id
     or (
       decision_row.result_state in ('accepted', 'terminal_failure')
       and (
         decision_row.decided_by_kind <> 'trusted_service'
         or decision_row.decided_by_trusted_service_id <>
            attempt_row.retry_safety_declared_by_trusted_service_id
         or decision_row.authorization_epoch is not null
       )
     )
     or (
       decision_row.retry_authorization_kind = 'automatic'
       and (
         not attempt_row.automatic_retry_allowed
         or decision_row.decided_by_kind <> 'trusted_service'
         or decision_row.decided_by_trusted_service_id <>
            attempt_row.retry_safety_declared_by_trusted_service_id
       )
     )
     or (
       not attempt_row.automatic_retry_allowed
       and decision_row.result_state = 'retryable_failure'
       and decision_row.retry_authorization_kind <>
          'employee_duplicate_risk_override'
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_reconciliation_authority_invalid';
  end if;

  select
    count(*),
    min(permission_row.ordinal),
    max(permission_row.ordinal),
    case when count(*) = 0 then null else encode(
      sha256(convert_to(string_agg(
        permission_row.ordinal::text || ':' ||
        octet_length(permission_row.permission_id)::text || ':' ||
        permission_row.permission_id,
        '|' order by permission_row.ordinal
      ), 'UTF8')),
      'hex'
    ) end
  into actual_count, minimum_ordinal, maximum_ordinal, actual_digest
  from public.inbox_v2_outbound_dispatch_reconciliation_permissions permission_row
  where permission_row.tenant_id = checked_tenant_id
    and permission_row.decision_id = checked_decision_id;

  if actual_count <> decision_row.matched_permission_count
     or (actual_count = 0 and (
       minimum_ordinal is not null or maximum_ordinal is not null
       or actual_digest is not null
     ))
     or (actual_count > 0 and (
       minimum_ordinal <> 0 or maximum_ordinal <> actual_count - 1
       or actual_digest <> decision_row.matched_permissions_digest_sha256
     ))
     or (
       decision_row.retry_authorization_kind =
          'employee_duplicate_risk_override'
       and not exists (
         select 1
           from public.inbox_v2_outbound_dispatch_reconciliation_permissions permission_row
          where permission_row.tenant_id = checked_tenant_id
            and permission_row.decision_id = checked_decision_id
            and permission_row.permission_id =
               'core:outbound_dispatch.duplicate-risk-retry'
       )
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_reconciliation_permissions_invalid';
  end if;

  if decision_row.retry_authorization_kind =
       'employee_duplicate_risk_override' then
    select
      count(*),
      encode(sha256(convert_to(string_agg(
        (permission.ordinality - 1)::text || ':' ||
        octet_length(permission.permission_id)::text || ':' ||
        permission.permission_id,
        '|' order by permission.ordinality
      ), 'UTF8')), 'hex')
    into snapshot_permission_count, snapshot_permissions_digest
    from jsonb_array_elements_text(
      decision_row.operator_authorization_snapshot #> '{matchedPermissionIds}'
    ) with ordinality as permission(permission_id, ordinality);

    if snapshot_permission_count <> actual_count
       or snapshot_permissions_digest <>
          decision_row.matched_permissions_digest_sha256 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_reconciliation_authorization_snapshot_invalid';
    end if;
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_participant_membership_episode(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_participant_membership_episode(checked_tenant_id text, checked_episode_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  episode_row public.inbox_v2_participant_membership_episodes%rowtype;
  latest_transition public.inbox_v2_participant_membership_transitions%rowtype;
  initial_transition public.inbox_v2_participant_membership_transitions%rowtype;
  newer_transition_count integer;
  internal_shape_count integer;
begin
  select *
    into episode_row
    from public.inbox_v2_participant_membership_episodes episode_source
   where episode_source.tenant_id = checked_tenant_id
     and episode_source.id = checked_episode_id;
  if not found then
    return;
  end if;

  select *
    into latest_transition
    from public.inbox_v2_participant_membership_transitions transition_row
   where transition_row.tenant_id = checked_tenant_id
     and transition_row.episode_id = checked_episode_id
     and transition_row.resulting_revision = episode_row.revision;
  select *
    into initial_transition
    from public.inbox_v2_participant_membership_transitions transition_row
   where transition_row.tenant_id = checked_tenant_id
     and transition_row.episode_id = checked_episode_id
     and transition_row.resulting_revision = 1;
  select count(*)::integer
    into newer_transition_count
    from public.inbox_v2_participant_membership_transitions transition_row
   where transition_row.tenant_id = checked_tenant_id
     and transition_row.episode_id = checked_episode_id
     and transition_row.resulting_revision > episode_row.revision;

  if latest_transition.id is null
     or initial_transition.id is null
     or initial_transition.occurred_at <> episode_row.valid_from
     or latest_transition.to_state <> episode_row.state
     or latest_transition.to_role <> episode_row.role
     or newer_transition_count <> 0
     or (
       episode_row.origin_kind = 'provider_roster'
       and (
         initial_transition.cause_provider_evidence_kind <> 'member'
         or initial_transition.cause_provider_roster_member_evidence_id is distinct from
           episode_row.origin_provider_roster_member_evidence_id
         or initial_transition.cause_provider_roster_evidence_id is distinct from
           episode_row.origin_provider_roster_evidence_id
         or initial_transition.cause_ordering_position is distinct from
           episode_row.origin_ordering_position
         or latest_transition.cause_source_thread_binding_id is distinct from
           episode_row.origin_source_thread_binding_id
         or latest_transition.cause_source_external_identity_id is distinct from
           episode_row.origin_source_external_identity_id
         or latest_transition.cause_ordering_position is distinct from
           episode_row.provider_ordering_head_position
         or not exists (
           select 1
             from public.inbox_v2_provider_membership_ordering_heads ordering_head
            where ordering_head.tenant_id = episode_row.tenant_id
              and ordering_head.participant_id = episode_row.participant_id
              and ordering_head.conversation_id = episode_row.conversation_id
              and ordering_head.source_thread_binding_id =
                episode_row.origin_source_thread_binding_id
              and ordering_head.source_external_identity_id =
                episode_row.origin_source_external_identity_id
              and ordering_head.ordering_kind =
                episode_row.origin_ordering_kind
              and ordering_head.ordering_scope_token =
                episode_row.origin_ordering_scope_token
              and ordering_head.ordering_comparator_id =
                episode_row.origin_ordering_comparator_id
              and ordering_head.ordering_comparator_revision =
                episode_row.origin_ordering_comparator_revision
              and (
                (
                  ordering_head.ordering_position =
                    episode_row.provider_ordering_head_position
                  and ordering_head.episode_id = episode_row.id
                  and ordering_head.transition_id = latest_transition.id
                  and ordering_head.membership_revision =
                    latest_transition.membership_revision
                  and ordering_head.updated_at =
                    latest_transition.occurred_at
                ) or (
                  episode_row.state in ('left', 'removed')
                  and ordering_head.episode_id <> episode_row.id
                  and ordering_head.ordering_position >
                    episode_row.provider_ordering_head_position
                  and ordering_head.membership_revision >
                    latest_transition.membership_revision
                  and ordering_head.updated_at >=
                    latest_transition.occurred_at
                )
              )
         )
       )
     )
     or (
       episode_row.state in ('left', 'removed') and
       episode_row.valid_to is distinct from latest_transition.occurred_at
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.participant_membership_episode_projection_invalid';
  end if;

  if episode_row.origin_kind = 'hulee_internal_command' then
    select count(*)::integer
      into internal_shape_count
      from public.inbox_v2_conversation_participants participant_row
      join public.inbox_v2_conversations conversation_row
        on conversation_row.tenant_id = participant_row.tenant_id
       and conversation_row.id = participant_row.conversation_id
      join public.employees employee_row
        on employee_row.tenant_id = participant_row.tenant_id
       and employee_row.id = participant_row.subject_employee_id
     where participant_row.tenant_id = episode_row.tenant_id
       and participant_row.id = episode_row.participant_id
       and participant_row.conversation_id = episode_row.conversation_id
       and participant_row.subject_kind = 'employee'
       and conversation_row.transport = 'internal'
       and (
         episode_row.state in ('left', 'removed')
         or employee_row.deactivated_at is null
       );
    if internal_shape_count <> 1 then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.internal_membership_subject_or_employee_invalid';
    end if;
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_provider_roster_member_set(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_provider_roster_member_set(checked_tenant_id text, checked_roster_evidence_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  expected_count integer;
  expected_digest text;
  actual_count bigint;
  minimum_ordinal integer;
  maximum_ordinal integer;
  noncanonical_ordinal_count bigint;
  actual_digest text;
begin
  select roster_row.member_count, roster_row.ordered_member_digest_sha256
    into expected_count, expected_digest
    from public.inbox_v2_provider_roster_evidence roster_row
   where roster_row.tenant_id = checked_tenant_id
     and roster_row.id = checked_roster_evidence_id;

  if not found then
    return;
  end if;

  select count(*), min(member_row.ordinal), max(member_row.ordinal)
    into actual_count, minimum_ordinal, maximum_ordinal
    from public.inbox_v2_provider_roster_member_evidence member_row
   where member_row.tenant_id = checked_tenant_id
     and member_row.roster_evidence_id = checked_roster_evidence_id;

  select count(*)
    into noncanonical_ordinal_count
    from (
      select
        member_row.ordinal,
        row_number() over (
          order by
            convert_to(member_row.source_external_identity_id, 'UTF8'),
            convert_to(member_row.id, 'UTF8')
        ) - 1 as canonical_ordinal
      from public.inbox_v2_provider_roster_member_evidence member_row
      where member_row.tenant_id = checked_tenant_id
        and member_row.roster_evidence_id = checked_roster_evidence_id
    ) ordered_member
   where ordered_member.ordinal <> ordered_member.canonical_ordinal;

  select encode(
           sha256(
             convert_to(
               'inbox-v2-provider-roster-members:v1|' ||
               coalesce(
                 string_agg(
                   member_row.ordinal::text || '|' ||
                   octet_length(member_row.id)::text || ':' ||
                     member_row.id ||
                   octet_length(member_row.source_external_identity_id)::text ||
                     ':' || member_row.source_external_identity_id ||
                   member_row.source_external_identity_revision::text || '|' ||
                   octet_length(member_row.state::text)::text || ':' ||
                     member_row.state::text ||
                   octet_length(member_row.normalized_role::text)::text || ':' ||
                     member_row.normalized_role::text ||
                   octet_length(member_row.provider_state_code)::text || ':' ||
                     member_row.provider_state_code ||
                   case
                     when member_row.provider_role_code is null then '-1:'
                     else octet_length(member_row.provider_role_code)::text ||
                       ':' || member_row.provider_role_code
                   end ||
                   trunc(
                     extract(epoch from member_row.observed_at) * 1000
                   )::bigint::text || ';',
                   '' order by member_row.ordinal
                 ),
                 ''
               ),
               'UTF8'
             )
           ),
           'hex'
         )
    into actual_digest
    from public.inbox_v2_provider_roster_member_evidence member_row
   where member_row.tenant_id = checked_tenant_id
     and member_row.roster_evidence_id = checked_roster_evidence_id;

  if actual_count <> expected_count
     or (
       expected_count = 0
       and (minimum_ordinal is not null or maximum_ordinal is not null)
     )
     or (
       expected_count > 0
       and (
         minimum_ordinal <> 0
         or maximum_ordinal <> expected_count - 1
       )
     )
     or noncanonical_ordinal_count <> 0
     or actual_digest <> expected_digest then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.provider_roster_member_set_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_source_occurrence_children(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_source_occurrence_children(checked_tenant_id text, checked_source_occurrence_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  expected_reference_count smallint;
  expected_timestamp_count smallint;
  actual_count bigint;
  minimum_ordinal smallint;
  maximum_ordinal smallint;
begin
  select
    occurrence_row.provider_reference_count,
    occurrence_row.provider_timestamp_count
  into expected_reference_count, expected_timestamp_count
  from public.inbox_v2_source_occurrences occurrence_row
  where occurrence_row.tenant_id = checked_tenant_id
    and occurrence_row.id = checked_source_occurrence_id;

  if not found then
    return;
  end if;

  select count(*), min(reference_row.ordinal), max(reference_row.ordinal)
  into actual_count, minimum_ordinal, maximum_ordinal
  from public.inbox_v2_source_occurrence_provider_references reference_row
  where reference_row.tenant_id = checked_tenant_id
    and reference_row.source_occurrence_id = checked_source_occurrence_id;

  if actual_count <> expected_reference_count
     or minimum_ordinal <> 0
     or maximum_ordinal <> expected_reference_count - 1 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_occurrence_provider_references_invalid';
  end if;

  select count(*), min(timestamp_row.ordinal), max(timestamp_row.ordinal)
  into actual_count, minimum_ordinal, maximum_ordinal
  from public.inbox_v2_source_occurrence_provider_timestamps timestamp_row
  where timestamp_row.tenant_id = checked_tenant_id
    and timestamp_row.source_occurrence_id = checked_source_occurrence_id;

  if actual_count <> expected_timestamp_count
     or (
       expected_timestamp_count = 0
       and (minimum_ordinal is not null or maximum_ordinal is not null)
     )
     or (
       expected_timestamp_count > 0
       and (
         minimum_ordinal <> 0
         or maximum_ordinal <> expected_timestamp_count - 1
       )
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_occurrence_provider_timestamps_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_source_occurrence_resolution(text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_source_occurrence_resolution(checked_tenant_id text, checked_source_occurrence_id text, checked_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  occurrence_row public.inbox_v2_source_occurrences%rowtype;
  transition_row public.inbox_v2_source_occurrence_resolution_transitions%rowtype;
  actual_count bigint;
  minimum_ordinal smallint;
  maximum_ordinal smallint;
  actual_digest text;
begin
  select * into occurrence_row
    from public.inbox_v2_source_occurrences candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.id = checked_source_occurrence_id;
  if not found then
    return;
  end if;

  select * into transition_row
    from public.inbox_v2_source_occurrence_resolution_transitions candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.source_occurrence_id = checked_source_occurrence_id
     and candidate_row.resulting_revision = checked_revision;

  if not found
     or occurrence_row.revision <> checked_revision
     or occurrence_row.resolution_state <> transition_row.to_state
     or occurrence_row.resolved_external_message_reference_id is distinct from
        transition_row.resolved_external_message_reference_id
     or occurrence_row.resolution_candidate_count <>
        transition_row.candidate_count
     or occurrence_row.resolution_candidate_digest_sha256 is distinct from
        transition_row.candidates_digest_sha256
     or occurrence_row.resolution_diagnostic_code_id is distinct from
        transition_row.diagnostic_code_id
     or occurrence_row.resolution_diagnostic_retryable is distinct from
        transition_row.diagnostic_retryable
     or occurrence_row.resolution_diagnostic_correlation_token is distinct from
        transition_row.diagnostic_correlation_token
     or occurrence_row.resolution_diagnostic_safe_operator_hint_id is distinct from
        transition_row.diagnostic_safe_operator_hint_id
     or occurrence_row.updated_at <> transition_row.changed_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_occurrence_resolution_head_mismatch';
  end if;

  select
    count(*),
    min(candidate_row.ordinal),
    max(candidate_row.ordinal),
    case when count(*) = 0 then null else encode(
      sha256(convert_to(string_agg(
        candidate_row.ordinal::text || ':' ||
        octet_length(candidate_row.external_message_reference_id)::text || ':' ||
        candidate_row.external_message_reference_id,
        '|' order by candidate_row.ordinal
      ), 'UTF8')),
      'hex'
    ) end
  into actual_count, minimum_ordinal, maximum_ordinal, actual_digest
  from public.inbox_v2_source_occurrence_resolution_candidates candidate_row
  where candidate_row.tenant_id = checked_tenant_id
    and candidate_row.transition_id = transition_row.id
    and candidate_row.source_occurrence_id = checked_source_occurrence_id
    and candidate_row.resulting_revision = checked_revision;

  if actual_count <> transition_row.candidate_count
     or (actual_count = 0 and (
       minimum_ordinal is not null or maximum_ordinal is not null
       or actual_digest is not null
     ))
     or (actual_count > 0 and (
       minimum_ordinal <> 0 or maximum_ordinal <> actual_count - 1
       or actual_digest <> transition_row.candidates_digest_sha256
     )) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_occurrence_resolution_candidates_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_source_registry_lineage(text, text, bigint, text, text, text, text, text, bigint, text, bigint, text, bigint, text, bigint, bigint, bigint, bigint, boolean); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_source_registry_lineage(checked_tenant_id text, checked_registry_id text, checked_registry_revision bigint, checked_registry_composition_hash text, checked_data_class_id text, checked_storage_root_id text, checked_purpose_id text, checked_canonical_anchor_id text, checked_lineage_revision bigint, checked_effective_policy_id text, checked_effective_policy_version bigint, checked_effective_rule_id text, checked_effective_rule_revision bigint, checked_policy_activation_id text, checked_policy_activation_revision bigint, checked_policy_activation_head_revision bigint, checked_legal_hold_set_revision bigint, checked_restriction_set_revision bigint, checked_requires_export boolean) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform 1
    from public.inbox_v2_data_governance_registry_versions registry_row
    join public.inbox_v2_data_governance_data_use_lineages lineage_row
      on lineage_row.registry_id = registry_row.id
     and lineage_row.registry_revision = registry_row.revision
    join public.inbox_v2_data_governance_effective_policies policy_row
      on policy_row.tenant_id = checked_tenant_id
     and policy_row.policy_id = checked_effective_policy_id
     and policy_row.version = checked_effective_policy_version
     and policy_row.registry_id = registry_row.id
     and policy_row.registry_revision = registry_row.revision
    join public.inbox_v2_data_governance_effective_policy_rules rule_row
      on rule_row.tenant_id = policy_row.tenant_id
     and rule_row.policy_id = policy_row.policy_id
     and rule_row.policy_version = policy_row.version
     and rule_row.rule_id = checked_effective_rule_id
     and rule_row.rule_revision = checked_effective_rule_revision
     and rule_row.data_class_id = lineage_row.data_class_id
     and rule_row.purpose_id = lineage_row.purpose_id
     and rule_row.retention_anchor_id = lineage_row.canonical_anchor_id
    join public.inbox_v2_data_governance_policy_activation_heads activation_head
      on activation_head.tenant_id = policy_row.tenant_id
     and activation_head.policy_id = policy_row.policy_id
     and activation_head.current_policy_version = policy_row.version
     and activation_head.current_activation_id = checked_policy_activation_id
     and activation_head.current_activation_revision = checked_policy_activation_revision
     and activation_head.head_revision = checked_policy_activation_head_revision
    join public.inbox_v2_data_governance_control_set_heads control_head
      on control_head.tenant_id = policy_row.tenant_id
     and control_head.legal_hold_set_revision = checked_legal_hold_set_revision
     and control_head.restriction_set_revision = checked_restriction_set_revision
   where registry_row.id = checked_registry_id
     and registry_row.revision = checked_registry_revision
     and registry_row.composition_hash =
       'sha256:' || checked_registry_composition_hash
     and lineage_row.data_class_id = checked_data_class_id
     and lineage_row.storage_root_id = checked_storage_root_id
     and lineage_row.purpose_id = checked_purpose_id
     and lineage_row.canonical_anchor_id = checked_canonical_anchor_id
     and lineage_row.lineage_revision = checked_lineage_revision
     and lineage_row.lifecycle_handler_id is not null
     and lineage_row.delete_handler_id is not null
     and lineage_row.verification_handler_id is not null
     and (
       not checked_requires_export
       or (
         lineage_row.subject_discovery_handler_id is not null
         and lineage_row.export_projection_handler_id is not null
         and lineage_row.export_handler_id is not null
       )
     );

  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_lineage_incomplete_or_stale';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_source_thread_binding_integrity(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_source_thread_binding_integrity(p_tenant_id text, p_binding_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  h public.inbox_v2_source_thread_binding_heads%rowtype;
  t public.inbox_v2_source_thread_binding_transitions%rowtype;
  s public.inbox_v2_source_thread_binding_snapshots%rowtype;
  v_count bigint;
  v_min smallint;
  v_max smallint;
  v_digest text;
  v_head jsonb;
  v_snapshot jsonb;
begin
  select * into h from public.inbox_v2_source_thread_binding_heads
   where tenant_id = p_tenant_id and binding_id = p_binding_id;
  if not found then
    if exists (
      select 1 from public.inbox_v2_source_thread_bindings b
       where b.tenant_id = p_tenant_id and b.id = p_binding_id
    ) then
      raise exception using errcode = '23514',
        message = 'Inbox V2 binding anchor requires one current head and open episode';
    end if;
    return;
  end if;

  select * into s from public.inbox_v2_source_thread_binding_snapshots
   where tenant_id = p_tenant_id
     and binding_id = p_binding_id
     and revision = h.revision;
  if not found then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding head requires one immutable revision snapshot';
  end if;
  v_head := to_jsonb(h);
  v_snapshot := to_jsonb(s) -
    array['transition_id', 'expected_binding_revision'];
  if v_snapshot is distinct from v_head then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding revision snapshot diverges from current head';
  end if;

  if not exists (
    select 1 from public.inbox_v2_source_thread_binding_snapshots initial
     where initial.tenant_id = p_tenant_id
       and initial.binding_id = p_binding_id
       and initial.revision = 1
       and initial.transition_id is null
       and initial.expected_binding_revision is null
  ) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding requires its immutable creation snapshot';
  end if;

  if not exists (
    select 1 from public.inbox_v2_source_account_identity_verified_snapshots i
     where i.tenant_id = h.tenant_id
       and i.source_account_id = h.source_account_id
       and i.identity_revision = h.account_identity_revision
       and i.account_generation = h.account_generation
       and i.state = 'verified'
       and i.canonical_key_digest_sha256 =
           h.account_canonical_key_digest_sha256
       and i.declaration_contract_id = h.capability_contract_id
       and i.declaration_contract_version = h.capability_contract_version
       and i.declaration_surface_id = h.capability_surface_id
  ) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 account identity, capability and route adapter surfaces diverge';
  end if;

  if not exists (
    select 1
      from public.inbox_v2_source_thread_bindings b
      join public.inbox_v2_external_threads x
        on x.tenant_id = b.tenant_id and x.id = b.external_thread_id
     where b.tenant_id = h.tenant_id and b.id = h.binding_id
       and b.created_at = h.created_at
       and (x.scope_kind <> 'source_account'
         or x.scope_source_account_id = h.source_account_id)
       and (x.scope_kind <> 'source_connection'
         or x.scope_source_connection_id = h.source_connection_id)
       and x.identity_declaration #>> '{adapterContract,contractId}' =
           h.route_contract_id
       and x.identity_declaration #>> '{adapterContract,contractVersion}' =
           h.route_contract_version
       and x.identity_declaration #>> '{adapterContract,surfaceId}' =
           h.route_surface_id
  ) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding thread scope, creation clock or adapter surface diverges';
  end if;

  select * into t from public.inbox_v2_source_thread_binding_transitions
   where tenant_id = p_tenant_id and binding_id = p_binding_id
   order by resulting_binding_revision desc limit 1;

  if not found then
    if h.revision <> 1 or h.binding_generation <> 1
       or h.remote_access_revision <> 1
       or h.administrative_revision <> 1
       or h.runtime_health_revision <> 1
       or h.history_sync_revision <> 1
       or h.provider_access_revision <> 1
       or h.capability_revision <> 1
       or h.route_descriptor_revision <> 1
       or h.remote_access_since <> h.created_at
       or h.created_at <> h.updated_at then
      raise exception using errcode = '23514',
        message = 'Inbox V2 initial binding head must be an exact revision-1 projection';
    end if;
  else
    if h.revision <> t.resulting_binding_revision
       or h.updated_at <> t.occurred_at
       or s.transition_id is distinct from t.id
       or s.expected_binding_revision is distinct from
          t.expected_binding_revision then
      raise exception using errcode = '23514',
        message = 'Inbox V2 current binding head does not match its latest transition';
    end if;

    if t.kind <> 'administrative'
       and t.actor_trusted_service_id <> h.account_identity_trusted_service_id then
      raise exception using errcode = '23514',
        message = 'Inbox V2 provider transition is not pinned to the verified account actor';
    end if;

    case t.kind
      when 'remote_access' then
        if row(h.remote_access_state, h.remote_access_revision,
               h.remote_access_evidence_authority,
               h.current_remote_access_episode_id,
               h.remote_access_evidence_set_id, h.remote_access_since)
           is distinct from
           row(t.remote_to_state, t.resulting_remote_access_revision,
               t.resulting_remote_evidence_authority,
               t.opened_remote_access_episode_id,
               t.evidence_set_id, t.occurred_at)
           or not exists (
             select 1 from public.inbox_v2_source_thread_binding_remote_access_episodes e
              where e.tenant_id = p_tenant_id and e.binding_id = p_binding_id
                and e.id = t.closed_remote_access_episode_id
                and e.state = t.remote_from_state
                and e.ended_at = t.occurred_at and e.updated_at = t.occurred_at
                and e.end_evidence_set_id = t.evidence_set_id and e.revision = 2
           ) or not exists (
             select 1 from public.inbox_v2_source_thread_binding_remote_access_episodes e
              where e.tenant_id = p_tenant_id and e.binding_id = p_binding_id
                and e.id = t.opened_remote_access_episode_id
                and e.state = t.remote_to_state and e.started_at = t.occurred_at
                and e.start_evidence_set_id = t.evidence_set_id
                and e.ended_at is null and e.revision = 1
           ) then
          raise exception using errcode = '23514',
            message = 'Inbox V2 remote transition, closed episode and current episode diverge';
        end if;
      when 'administrative' then
        if row(h.administrative_state, h.administrative_revision,
               h.administrative_changed_at)
           is distinct from
           row(t.administrative_to_state,
               t.resulting_administrative_revision, t.occurred_at) then
          raise exception using errcode = '23514',
            message = 'Inbox V2 administrative head diverges from transition';
        end if;
        select count(*), min(ordinal), max(ordinal) into v_count, v_min, v_max
          from public.inbox_v2_source_thread_binding_transition_matched_permissions
         where tenant_id = p_tenant_id and transition_id = t.id;
        if v_count <> t.administrative_matched_permission_count
           or (v_count > 0 and (v_min <> 0 or v_max <> v_count - 1))
           or (t.administrative_authorization_effect = 'allow' and not exists (
             select 1
               from public.inbox_v2_source_thread_binding_transition_matched_permissions p
              where p.tenant_id = p_tenant_id and p.transition_id = t.id
                and p.permission_id = t.administrative_required_permission_id
           )) then
          raise exception using errcode = '23514',
            message = 'Inbox V2 administrative permission proof is incomplete';
        end if;
      when 'runtime_health' then
        if row(h.runtime_health_state, h.runtime_health_revision,
               h.runtime_health_checked_at, h.runtime_diagnostic_code_id,
               h.runtime_diagnostic_retryable,
               h.runtime_diagnostic_correlation_token,
               h.runtime_diagnostic_safe_operator_hint_id)
           is distinct from
           row(t.runtime_health_to_state,
               t.resulting_runtime_health_revision, t.occurred_at,
               t.resulting_runtime_diagnostic_code_id,
               t.resulting_runtime_diagnostic_retryable,
               t.resulting_runtime_diagnostic_correlation_token,
               t.resulting_runtime_diagnostic_safe_operator_hint_id) then
          raise exception using errcode = '23514',
            message = 'Inbox V2 runtime-health head diverges from transition';
        end if;
      when 'history_sync' then
        if row(h.history_sync_state, h.history_sync_revision,
               h.history_receive_cursor, h.history_cursor,
               h.history_provider_watermark,
               h.history_last_durable_raw_event_id, h.history_updated_at,
               h.history_diagnostic_code_id, h.history_diagnostic_retryable,
               h.history_diagnostic_correlation_token,
               h.history_diagnostic_safe_operator_hint_id)
           is distinct from
           row(t.history_sync_to_state, t.resulting_history_sync_revision,
               t.resulting_history_receive_cursor, t.resulting_history_cursor,
               t.resulting_history_provider_watermark,
               t.resulting_history_last_durable_raw_event_id, t.occurred_at,
               t.resulting_history_diagnostic_code_id,
               t.resulting_history_diagnostic_retryable,
               t.resulting_history_diagnostic_correlation_token,
               t.resulting_history_diagnostic_safe_operator_hint_id) then
          raise exception using errcode = '23514',
            message = 'Inbox V2 history head diverges from transition';
        end if;
      when 'capabilities' then
        if h.capability_revision <> t.resulting_capability_revision
           or h.capability_captured_at <> t.occurred_at
           or h.capability_semantic_digest_sha256 <>
              t.resulting_capability_semantic_digest_sha256
           or t.actor_trusted_service_id <>
              h.capability_loaded_by_trusted_service_id then
          raise exception using errcode = '23514',
            message = 'Inbox V2 capability head diverges from transition';
        end if;
      when 'route_descriptor' then
        if h.binding_generation <> t.resulting_binding_generation
           or h.route_descriptor_revision <>
              t.resulting_route_descriptor_revision
           or h.route_descriptor_digest_sha256 <>
              t.resulting_route_descriptor_digest_sha256
           or h.route_attributes_digest_sha256 <>
              t.resulting_route_attributes_digest_sha256
           or t.actor_trusted_service_id <>
              h.route_loaded_by_trusted_service_id then
          raise exception using errcode = '23514',
            message = 'Inbox V2 route descriptor head diverges from transition';
        end if;
      when 'account_generation' then
        if row(h.account_generation, h.account_identity_revision,
               h.account_identity_state, h.account_canonical_key_digest_sha256,
               h.account_verified_at, h.account_verification_evidence_set_id)
           is distinct from
           row(t.resulting_account_generation,
               t.resulting_account_identity_revision,
               t.resulting_account_identity_state,
               t.resulting_account_canonical_key_digest_sha256,
               t.occurred_at, t.evidence_set_id) then
          raise exception using errcode = '23514',
            message = 'Inbox V2 verified account snapshot diverges from transition';
        end if;
      when 'provider_access' then
        if h.binding_generation <> t.resulting_binding_generation
           or h.provider_access_revision <>
              t.resulting_provider_access_revision
           or h.provider_access_observed_at <> t.occurred_at
           or h.provider_roles_digest_sha256 <>
              t.resulting_provider_roles_digest_sha256
           or h.provider_access_evidence_set_id <> t.evidence_set_id then
          raise exception using errcode = '23514',
            message = 'Inbox V2 provider-access head diverges from transition';
        end if;
    end case;
  end if;

  select count(*), min(ordinal), max(ordinal),
         encode(sha256(convert_to(coalesce(string_agg(
           octet_length(provider_role_id)::text || ':' || provider_role_id,
           '' order by provider_role_id), ''), 'UTF8')), 'hex')
    into v_count, v_min, v_max, v_digest
    from public.inbox_v2_source_thread_binding_provider_roles
   where tenant_id = p_tenant_id and binding_id = p_binding_id
     and provider_access_revision = h.provider_access_revision;
  if v_count <> h.provider_role_count
     or (v_count > 0 and (v_min <> 0 or v_max <> v_count - 1))
     or v_digest <> h.provider_roles_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'Inbox V2 provider-role snapshot count, ordinals or digest mismatch';
  end if;

  if exists (
    select 1 from public.inbox_v2_source_thread_binding_capability_entries e
     left join lateral (
       select count(*) c, min(r.ordinal) min_o, max(r.ordinal) max_o
         from public.inbox_v2_source_thread_binding_capability_required_roles r
        where r.tenant_id = e.tenant_id and r.binding_id = e.binding_id
          and r.capability_revision = e.capability_revision
          and r.capability_ordinal = e.ordinal
     ) roles on true
    where e.tenant_id = p_tenant_id and e.binding_id = p_binding_id
      and e.capability_revision = h.capability_revision
      and (roles.c <> e.required_provider_role_count
        or (roles.c > 0 and (roles.min_o <> 0 or roles.max_o <> roles.c - 1)))
  ) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 capability required-role count or ordinals mismatch';
  end if;

  if exists (
    select 1 from public.inbox_v2_source_thread_binding_capability_entries e
     where e.tenant_id = p_tenant_id and e.binding_id = p_binding_id
       and e.capability_revision = h.capability_revision
       and ((e.state = 'expired' and e.valid_until > h.capability_captured_at)
         or (e.state = 'supported' and e.valid_until is not null
           and e.valid_until <= h.capability_captured_at))
  ) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 capability validity boundary contradicts capture time';
  end if;

  with entry_payload as (
    select e.ordinal, e.capability_id, e.operation_id, e.content_kind_key,
           e.capability_id || '|' || e.operation_id ||
           '|' || e.content_kind_key || '|' || e.state::text || '|' ||
           e.reference_portability::text || '|' ||
           coalesce(
             ((extract(epoch from e.valid_until) * 1000)::numeric(20, 0))::text,
             '-'
           ) || '|' ||
           coalesce(e.diagnostic_code_id, '-') || '|' ||
           coalesce(e.diagnostic_retryable::text, '-') || '|' ||
           coalesce(e.diagnostic_correlation_token, '-') || '|' ||
           coalesce(e.diagnostic_safe_operator_hint_id, '-') || '|' ||
           coalesce((select string_agg(
             octet_length(r.provider_role_id)::text || ':' ||
               r.provider_role_id,
             '' order by r.provider_role_id)
             from public.inbox_v2_source_thread_binding_capability_required_roles r
            where r.tenant_id = e.tenant_id and r.binding_id = e.binding_id
              and r.capability_revision = e.capability_revision
              and r.capability_ordinal = e.ordinal), '') as payload
      from public.inbox_v2_source_thread_binding_capability_entries e
     where e.tenant_id = p_tenant_id and e.binding_id = p_binding_id
       and e.capability_revision = h.capability_revision
  )
  select count(*), min(ordinal), max(ordinal),
         encode(sha256(convert_to(
           octet_length(h.capability_contract_id)::text || ':' ||
             h.capability_contract_id ||
           octet_length(h.capability_contract_version)::text || ':' ||
             h.capability_contract_version ||
           h.capability_declaration_revision::text || '|' ||
           octet_length(h.capability_surface_id)::text || ':' ||
             h.capability_surface_id ||
           octet_length(h.capability_loaded_by_trusted_service_id)::text || ':' ||
             h.capability_loaded_by_trusted_service_id ||
           coalesce(string_agg(payload, '' order by
             capability_id, operation_id, content_kind_key), ''),
           'UTF8')), 'hex')
    into v_count, v_min, v_max, v_digest from entry_payload;
  if v_count <> h.capability_entry_count
     or (v_count > 0 and (v_min <> 0 or v_max <> v_count - 1))
     or v_digest <> h.capability_semantic_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'Inbox V2 capability snapshot count, ordinals or digest mismatch';
  end if;

  select count(*), min(ordinal), max(ordinal),
         encode(sha256(convert_to(coalesce(string_agg(
           ordinal::text || '|' || attribute_id || '|' ||
           octet_length(value)::text || ':' || value,
           '' order by ordinal), ''), 'UTF8')), 'hex')
    into v_count, v_min, v_max, v_digest
    from public.inbox_v2_source_thread_binding_route_attributes
   where tenant_id = p_tenant_id and binding_id = p_binding_id
     and route_descriptor_revision = h.route_descriptor_revision;
  if v_count <> h.route_attribute_count
     or (v_count > 0 and (v_min <> 0 or v_max <> v_count - 1))
     or v_digest <> h.route_attributes_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'Inbox V2 route-attribute snapshot count, ordinals or digest mismatch';
  end if;

  select encode(sha256(convert_to(
           octet_length(h.route_contract_id)::text || ':' ||
             h.route_contract_id ||
           octet_length(h.route_contract_version)::text || ':' ||
             h.route_contract_version ||
           octet_length(h.route_declaration_revision::text)::text || ':' ||
             h.route_declaration_revision::text ||
           octet_length(h.route_surface_id)::text || ':' ||
             h.route_surface_id ||
           octet_length(h.route_loaded_by_trusted_service_id)::text || ':' ||
             h.route_loaded_by_trusted_service_id ||
           octet_length(h.route_descriptor_schema_id)::text || ':' ||
             h.route_descriptor_schema_id ||
           octet_length(h.route_descriptor_version)::text || ':' ||
             h.route_descriptor_version ||
           octet_length(h.route_descriptor_revision::text)::text || ':' ||
             h.route_descriptor_revision::text ||
           octet_length(h.route_destination_kind_id)::text || ':' ||
             h.route_destination_kind_id ||
           octet_length(h.route_destination_subject)::text || ':' ||
             h.route_destination_subject ||
           coalesce((select string_agg(
             octet_length(attribute_id)::text || ':' || attribute_id ||
               octet_length(value)::text || ':' || value,
             '' order by attribute_id)
             from public.inbox_v2_source_thread_binding_route_attributes a
            where a.tenant_id = p_tenant_id
              and a.binding_id = p_binding_id
              and a.route_descriptor_revision =
                  h.route_descriptor_revision), ''),
           'UTF8')), 'hex')
    into v_digest;
  if v_digest <> h.route_descriptor_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'Inbox V2 route descriptor canonical digest mismatch';
  end if;

  if octet_length(h.route_contract_id) +
       octet_length(h.route_contract_version) +
       octet_length(h.route_surface_id) +
       octet_length(h.route_descriptor_schema_id) +
       octet_length(h.route_descriptor_version) +
       octet_length(h.route_destination_kind_id) +
       octet_length(h.route_destination_subject) +
       coalesce((select sum(octet_length(attribute_id) + octet_length(value))
         from public.inbox_v2_source_thread_binding_route_attributes a
        where a.tenant_id = p_tenant_id and a.binding_id = p_binding_id
          and a.route_descriptor_revision = h.route_descriptor_revision), 0)
       > 16384 then
    raise exception using errcode = '23514',
      message = 'Inbox V2 normalized route descriptor exceeds 16 KiB';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_tenant_policy_transition_materialized(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_tenant_policy_transition_materialized() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform 1
    from public.inbox_v2_tenant_policy_activation_heads head_row
   where head_row.tenant_id = new.tenant_id
     and head_row.family = new.family
     and head_row.policy_id = new.policy_id
     and head_row.revision = new.resulting_head_revision
     and head_row.state = new.resulting_state
     and head_row.policy_version = new.resulting_policy_version
     and head_row.definition_contract_version =
         new.resulting_definition_contract_version
     and head_row.definition_digest_sha256 =
         new.resulting_definition_digest_sha256
     and head_row.approved_trusted_service_id =
         new.resulting_approved_trusted_service_id
     and (
       (
         new.operation = 'activate'
         and head_row.activated_by_employee_id = new.actor_employee_id
         and head_row.activated_at = new.occurred_at
         and head_row.revoked_at is null
       ) or (
         new.operation = 'revoke'
         and head_row.revoked_by_employee_id = new.actor_employee_id
         and head_row.revoked_at = new.occurred_at
       )
     );

  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_transition_unmaterialized';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_assert_thread_route_policy_fallbacks(text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_thread_route_policy_fallbacks(checked_tenant_id text, checked_policy_id text, checked_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  policy_row public.inbox_v2_thread_route_policy_versions%rowtype;
  actual_count bigint;
  minimum_ordinal smallint;
  maximum_ordinal smallint;
  actual_digest text;
  all_same_thread boolean;
begin
  select * into policy_row
    from public.inbox_v2_thread_route_policy_versions candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.policy_id = checked_policy_id
     and candidate_row.revision = checked_revision;
  if not found then
    return;
  end if;

  select
    count(*),
    min(fallback_row.ordinal),
    max(fallback_row.ordinal),
    case when count(*) = 0 then null else encode(
      sha256(convert_to(string_agg(
        fallback_row.ordinal::text || ':' ||
        octet_length(fallback_row.binding_id)::text || ':' ||
        fallback_row.binding_id,
        '|' order by fallback_row.ordinal
      ), 'UTF8')),
      'hex'
    ) end,
    coalesce(bool_and(
      fallback_row.external_thread_id = policy_row.external_thread_id
    ), true)
  into actual_count, minimum_ordinal, maximum_ordinal, actual_digest,
    all_same_thread
  from public.inbox_v2_thread_route_policy_fallback_bindings fallback_row
  where fallback_row.tenant_id = checked_tenant_id
    and fallback_row.policy_id = checked_policy_id
    and fallback_row.policy_revision = checked_revision;

  if actual_count <> policy_row.fallback_binding_count
     or (actual_count = 0 and (
       minimum_ordinal is not null or maximum_ordinal is not null
       or actual_digest is not null
     ))
     or (actual_count > 0 and (
       minimum_ordinal <> 0 or maximum_ordinal <> actual_count - 1
       or actual_digest <> policy_row.fallback_bindings_digest_sha256
     ))
     or not all_same_thread
     or exists (
       select 1
         from public.inbox_v2_thread_route_policy_fallback_bindings fallback_row
        where fallback_row.tenant_id = checked_tenant_id
          and fallback_row.policy_id = checked_policy_id
          and fallback_row.policy_revision = checked_revision
          and fallback_row.binding_id = policy_row.preferred_binding_id
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.thread_route_policy_fallbacks_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_assert_thread_route_policy_head(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_assert_thread_route_policy_head(checked_tenant_id text, checked_policy_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  maximum_revision bigint;
  current_revision bigint;
begin
  select max(version_row.revision)
    into maximum_revision
    from public.inbox_v2_thread_route_policy_versions version_row
   where version_row.tenant_id = checked_tenant_id
     and version_row.policy_id = checked_policy_id;

  if maximum_revision is null then
    return;
  end if;

  select head_row.revision
    into current_revision
    from public.inbox_v2_thread_route_policy_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.policy_id = checked_policy_id;

  if not found or current_revision <> maximum_revision then
    raise exception using errcode = '23514',
      message = 'inbox_v2.thread_route_policy_current_head_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_atomic_message_creation_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_atomic_message_creation_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_changed jsonb;
  v_tenant_id text;
  v_message_id text;
  v_valid_count integer;
begin
  v_changed := to_jsonb(new);
  v_tenant_id := v_changed->>'tenant_id';

  if tg_table_name =
     'inbox_v2_source_occurrence_resolution_transitions' then
    if v_changed->>'to_state' <> 'resolved' then
      return null;
    end if;
    select reference_row.message_id into v_message_id
      from public.inbox_v2_external_message_references reference_row
     where reference_row.tenant_id = v_tenant_id
       and reference_row.id =
         v_changed->>'resolved_external_message_reference_id';
    if v_message_id is null or not exists (
      select 1
        from public.inbox_v2_messages message_row
       where message_row.tenant_id = v_tenant_id
         and message_row.id = v_message_id
         and message_row.origin_kind = 'source_originated'
         and message_row.origin_source_occurrence_id =
           v_changed->>'source_occurrence_id'
         and message_row.created_at =
           (v_changed->>'changed_at')::timestamptz
    ) then
      return null;
    end if;
  elsif tg_table_name =
        'inbox_v2_atomic_source_resolution_materializations' then
    v_message_id := v_changed->>'message_id';
    if not exists (
      select 1
        from public.inbox_v2_messages message_row
        join public.inbox_v2_external_message_references reference_row
          on reference_row.tenant_id = message_row.tenant_id
         and reference_row.id =
           v_changed->>'external_message_reference_id'
         and reference_row.message_id = message_row.id
        join public.inbox_v2_source_occurrences occurrence_row
          on occurrence_row.tenant_id = message_row.tenant_id
         and occurrence_row.id = v_changed->>'source_occurrence_id'
         and occurrence_row.resolution_state = 'resolved'
         and occurrence_row.resolved_external_message_reference_id =
           reference_row.id
         and occurrence_row.revision =
           (v_changed->>'resulting_revision')::bigint
         and occurrence_row.updated_at =
           (v_changed->>'created_at')::timestamptz
        join public.inbox_v2_source_occurrence_resolution_transitions
          transition_row
          on transition_row.tenant_id = occurrence_row.tenant_id
         and transition_row.id = v_changed->>'resolution_transition_id'
         and transition_row.source_occurrence_id = occurrence_row.id
         and transition_row.resulting_revision = occurrence_row.revision
         and transition_row.to_state = 'resolved'
         and transition_row.resolved_external_message_reference_id =
           reference_row.id
         and transition_row.changed_at =
           (v_changed->>'created_at')::timestamptz
        join public.inbox_v2_tenant_stream_commits stream_row
          on stream_row.tenant_id = message_row.tenant_id
         and stream_row.id = v_changed->>'stream_commit_id'
         and stream_row.mutation_id = v_changed->>'mutation_id'
         and stream_row.position =
           (v_changed->>'stream_position')::bigint
         and stream_row.committed_at =
           (v_changed->>'created_at')::timestamptz
        join public.inbox_v2_auth_mutation_commits mutation_row
          on mutation_row.tenant_id = stream_row.tenant_id
         and mutation_row.mutation_id = stream_row.mutation_id
         and mutation_row.stream_commit_id = stream_row.id
         and mutation_row.committed_at = stream_row.committed_at
        join public.inbox_v2_tenant_stream_changes occurrence_change
          on occurrence_change.tenant_id = stream_row.tenant_id
         and occurrence_change.stream_commit_id = stream_row.id
         and occurrence_change.mutation_id = stream_row.mutation_id
         and occurrence_change.stream_position = stream_row.position
         and occurrence_change.entity_type_id = 'core:source-occurrence'
         and occurrence_change.entity_id = occurrence_row.id
         and occurrence_change.resulting_revision = occurrence_row.revision
         and occurrence_change.state_kind = 'upsert'
         and occurrence_change.state_schema_id =
           'core:inbox-v2.source-occurrence'
         and occurrence_change.state_schema_version = 'v1'
         and occurrence_change.state_hash =
           occurrence_change.payload_reference->>'digest'
         and occurrence_change.payload_reference->>'recordId' =
           occurrence_row.id
         and occurrence_change.domain_commit_reference->>'recordId' =
           transition_row.id
        join public.inbox_v2_tenant_stream_changes message_change
          on message_change.tenant_id = stream_row.tenant_id
         and message_change.stream_commit_id = stream_row.id
         and message_change.mutation_id = stream_row.mutation_id
         and message_change.stream_position = stream_row.position
         and message_change.entity_type_id = 'core:message'
         and message_change.entity_id = message_row.id
         and message_change.resulting_revision = message_row.revision
         and message_change.state_kind = 'upsert'
         and message_change.state_schema_id = 'core:inbox-v2.message'
         and message_change.state_schema_version = 'v1'
         and message_change.state_hash =
           message_change.payload_reference->>'digest'
         and message_change.payload_reference->>'recordId' = message_row.id
       where message_row.tenant_id = v_tenant_id
         and message_row.id = v_message_id
         and message_row.origin_kind = 'source_originated'
         and message_row.origin_source_occurrence_id = occurrence_row.id
         and message_row.revision = 1
         and message_row.last_changed_stream_position = stream_row.position
         and message_row.created_at = stream_row.committed_at
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.atomic_source_resolution_closure_missing';
    end if;
  else
    v_message_id := coalesce(
      v_changed->>'message_id',
      v_changed->>'id'
    );
  end if;

  if v_message_id is null
     or not exists (
       select 1 from public.tenants tenant_row
        where tenant_row.id = v_tenant_id
     ) then
    return null;
  end if;

  select count(*)::integer into v_valid_count
    from public.inbox_v2_messages message_row
    join public.inbox_v2_tenant_stream_commits stream_row
      on stream_row.tenant_id = message_row.tenant_id
     and stream_row.position = message_row.last_changed_stream_position
     and stream_row.committed_at = message_row.created_at
    join public.inbox_v2_auth_mutation_commits mutation_row
      on mutation_row.tenant_id = stream_row.tenant_id
     and mutation_row.mutation_id = stream_row.mutation_id
     and mutation_row.stream_commit_id = stream_row.id
     and mutation_row.committed_at = stream_row.committed_at
     and mutation_row.revision_effect_count = 0
     and mutation_row.relation_write_count = 0
    join public.inbox_v2_auth_command_records command_row
      on command_row.tenant_id = mutation_row.tenant_id
     and command_row.id = mutation_row.command_record_id
     and command_row.mutation_id = mutation_row.mutation_id
     and command_row.state = 'completed'
    join public.inbox_v2_tenant_stream_changes message_change
      on message_change.tenant_id = stream_row.tenant_id
     and message_change.stream_commit_id = stream_row.id
     and message_change.mutation_id = stream_row.mutation_id
     and message_change.stream_position = stream_row.position
     and message_change.entity_type_id = 'core:message'
     and message_change.entity_id = message_row.id
     and message_change.resulting_revision = message_row.revision
     and message_change.state_kind = 'upsert'
     and message_change.state_schema_id = 'core:inbox-v2.message'
     and message_change.state_schema_version = 'v1'
     and message_change.state_hash =
       message_change.payload_reference->>'digest'
     and message_change.payload_reference = command_row.result_reference
   where message_row.tenant_id = v_tenant_id
     and message_row.id = v_message_id
     and message_row.revision = 1
     and message_row.created_at = message_row.updated_at
     and (
       (
         message_row.origin_kind = 'source_originated'
         and command_row.command_type_id = 'core:message.receive'
         and (
           select count(*)
             from public.inbox_v2_atomic_source_resolution_materializations
               source_materialization
            where source_materialization.tenant_id = message_row.tenant_id
              and source_materialization.source_occurrence_id =
                message_row.origin_source_occurrence_id
              and source_materialization.message_id = message_row.id
              and source_materialization.mutation_id = stream_row.mutation_id
              and source_materialization.stream_commit_id = stream_row.id
              and source_materialization.stream_position = stream_row.position
              and source_materialization.created_at = stream_row.committed_at
         ) = 1
       )
       or (
         message_row.origin_kind = 'hulee_external'
         and (
           (
             command_row.command_type_id = 'core:message.send'
             and exists (
               select 1
                 from public.inbox_v2_outbound_routes route_row
                where route_row.tenant_id = message_row.tenant_id
                  and route_row.id = message_row.origin_outbound_route_id
                  and route_row.selection_intent_kind <> 'explicit_reroute'
             )
           )
           or (
             command_row.command_type_id = 'core:source.dispatch.reroute'
             and exists (
               select 1
                 from public.inbox_v2_outbound_routes route_row
                where route_row.tenant_id = message_row.tenant_id
                  and route_row.id = message_row.origin_outbound_route_id
                  and route_row.selection_intent_kind = 'explicit_reroute'
             )
           )
         )
         and (
           select count(*)
             from public.inbox_v2_atomic_outbound_dispatch_materializations
               dispatch_materialization
             join public.inbox_v2_outbound_dispatches dispatch_row
               on dispatch_row.tenant_id = dispatch_materialization.tenant_id
              and dispatch_row.id = dispatch_materialization.dispatch_id
            where dispatch_materialization.tenant_id = message_row.tenant_id
              and dispatch_materialization.mutation_id = stream_row.mutation_id
              and dispatch_materialization.stream_commit_id = stream_row.id
              and dispatch_materialization.stream_position = stream_row.position
              and dispatch_materialization.created_at = stream_row.committed_at
              and dispatch_row.message_id = message_row.id
              and dispatch_row.route_id = message_row.origin_outbound_route_id
              and dispatch_row.state = 'queued'
              and dispatch_row.attempt_count = 0
         ) = 1
       )
       or (
         message_row.origin_kind = 'internal'
         and command_row.command_type_id = 'core:message.send'
         and not exists (
           select 1
             from public.inbox_v2_atomic_source_resolution_materializations
               source_materialization
            where source_materialization.tenant_id = message_row.tenant_id
              and source_materialization.message_id = message_row.id
         )
         and not exists (
           select 1
             from public.inbox_v2_atomic_outbound_dispatch_materializations
               dispatch_materialization
             join public.inbox_v2_outbound_dispatches dispatch_row
               on dispatch_row.tenant_id = dispatch_materialization.tenant_id
              and dispatch_row.id = dispatch_materialization.dispatch_id
            where dispatch_materialization.tenant_id = message_row.tenant_id
              and dispatch_row.message_id = message_row.id
         )
       )
     );

  if v_valid_count <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.atomic_message_creation_closure_missing';
  end if;
  return null;
exception
  when no_data_found or too_many_rows then
    raise exception using errcode = '23514',
      message = 'inbox_v2.atomic_message_creation_closure_missing';
end;
$$;



--
-- Name: inbox_v2_atomic_outbound_creation_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_atomic_outbound_creation_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_changed jsonb;
  v_tenant_id text;
  v_route_id text;
  v_dispatch_id text;
  v_valid_count integer;
begin
  v_changed := to_jsonb(new);
  v_tenant_id := v_changed->>'tenant_id';
  if tg_table_name = 'inbox_v2_outbound_routes' then
    v_route_id := v_changed->>'id';
  elsif tg_table_name = 'inbox_v2_outbound_dispatches' then
    v_route_id := v_changed->>'route_id';
    v_dispatch_id := v_changed->>'id';
  else
    v_dispatch_id := v_changed->>'dispatch_id';
    select dispatch_row.route_id into v_route_id
      from public.inbox_v2_outbound_dispatches dispatch_row
     where dispatch_row.tenant_id = v_tenant_id
       and dispatch_row.id = v_dispatch_id;
  end if;

  if v_route_id is null
     or not exists (
       select 1 from public.tenants tenant_row
        where tenant_row.id = v_tenant_id
     ) then
    return null;
  end if;

  -- External reactions intentionally consume an exact occurrence route
  -- without manufacturing an OutboundDispatch. Their own deferred reaction
  -- invariant validates the full binding/reference/capability closure.
  if tg_table_name = 'inbox_v2_outbound_routes' and exists (
    select 1
      from public.inbox_v2_outbound_routes reaction_route
      join public.inbox_v2_outbound_route_consumptions consumption_row
        on consumption_row.tenant_id = reaction_route.tenant_id
       and consumption_row.outbound_route_id = reaction_route.id
       and consumption_row.consumer_kind = 'reaction'
      join public.inbox_v2_message_reaction_transitions transition_row
        on transition_row.tenant_id = consumption_row.tenant_id
       and transition_row.id = consumption_row.consumer_id
       and transition_row.mode = 'external_request'
       and transition_row.outbound_route_id = reaction_route.id
       and transition_row.source_account_id = reaction_route.source_account_id
       and transition_row.source_thread_binding_id =
         reaction_route.source_thread_binding_id
       and reaction_route.operation_id =
         'core:message.reaction.' || transition_row.operation::text
      join public.inbox_v2_message_reactions reaction_row
        on reaction_row.tenant_id = transition_row.tenant_id
       and reaction_row.id = transition_row.reaction_id
       and reaction_row.message_id = consumption_row.message_id
       and reaction_row.state_kind = 'pending_external'
       and reaction_row.outbound_route_id = reaction_route.id
       and reaction_row.request_transition_id = transition_row.id
     where reaction_route.tenant_id = v_tenant_id
       and reaction_route.id = v_route_id
       and reaction_route.selection_intent_kind = 'explicit_occurrence'
       and reaction_route.selection_reason = 'explicit_occurrence'
       and reaction_route.fallback_policy_ordinal is null
       and not exists (
         select 1
           from public.inbox_v2_outbound_dispatches dispatch_row
          where dispatch_row.tenant_id = reaction_route.tenant_id
            and dispatch_row.route_id = reaction_route.id
       )
  ) then
    return null;
  end if;

  select count(*)::integer into v_valid_count
    from public.inbox_v2_outbound_routes route_row
    join public.inbox_v2_outbound_dispatches dispatch_row
      on dispatch_row.tenant_id = route_row.tenant_id
     and dispatch_row.route_id = route_row.id
     and (v_dispatch_id is null or dispatch_row.id = v_dispatch_id)
     and dispatch_row.state = 'queued'
     and dispatch_row.attempt_count = 0
     and dispatch_row.active_attempt_id is null
     and dispatch_row.last_attempt_id is null
     and dispatch_row.retry_authorization_decision_id is null
     and dispatch_row.revision = 1
     and dispatch_row.created_at = dispatch_row.updated_at
    join public.inbox_v2_atomic_outbound_dispatch_materializations
      dispatch_materialization
      on dispatch_materialization.tenant_id = dispatch_row.tenant_id
     and dispatch_materialization.dispatch_id = dispatch_row.id
     and dispatch_materialization.resulting_revision = dispatch_row.revision
     and dispatch_materialization.created_at = dispatch_row.created_at
    join public.inbox_v2_tenant_stream_commits stream_row
      on stream_row.tenant_id = dispatch_materialization.tenant_id
     and stream_row.id = dispatch_materialization.stream_commit_id
     and stream_row.mutation_id = dispatch_materialization.mutation_id
     and stream_row.position = dispatch_materialization.stream_position
     and stream_row.committed_at = dispatch_materialization.created_at
    join public.inbox_v2_auth_mutation_commits mutation_row
      on mutation_row.tenant_id = stream_row.tenant_id
     and mutation_row.mutation_id = stream_row.mutation_id
     and mutation_row.stream_commit_id = stream_row.id
     and mutation_row.committed_at = stream_row.committed_at
     and mutation_row.revision_effect_count = 0
     and mutation_row.relation_write_count = 0
    join public.inbox_v2_auth_command_records command_row
      on command_row.tenant_id = mutation_row.tenant_id
     and command_row.id = mutation_row.command_record_id
     and command_row.mutation_id = mutation_row.mutation_id
     and command_row.state = 'completed'
     and (
       (
         command_row.command_type_id = 'core:message.send'
         and route_row.selection_intent_kind <> 'explicit_reroute'
       )
       or (
         command_row.command_type_id = 'core:source.dispatch.reroute'
         and route_row.selection_intent_kind = 'explicit_reroute'
         and (
           select count(*)
             from jsonb_array_elements(
               command_row.authorization_decision_refs
             ) decision_ref
             join public.inbox_v2_outbound_routes original_route
               on original_route.tenant_id = route_row.tenant_id
              and original_route.id =
                route_row.selection_intent_snapshot #>>
                  '{originalRoute,id}'
            where decision_ref->>'id' =
                    command_row.authorization_decision_id
              and decision_ref->>'authorizationEpoch' =
                    command_row.authorization_epoch
              and decision_ref->>'permissionId' =
                    'core:source.dispatch.reroute'
              and decision_ref->>'resourceScopeId' =
                    'core:source-account'
              and decision_ref->>'outcome' = 'allowed'
              and decision_ref #>> '{resource,tenantId}' =
                    route_row.tenant_id
              and decision_ref #>> '{resource,entityTypeId}' =
                    'core:source-account'
              and decision_ref #>> '{resource,entityId}' =
                    original_route.source_account_id
         ) = 1
         and route_row.selection_intent_snapshot #>>
               '{originalRoute,tenantId}' = route_row.tenant_id
         and route_row.selection_intent_snapshot #>>
               '{originalDispatch,tenantId}' = route_row.tenant_id
         and route_row.selection_intent_snapshot ->>
               'expectedOriginalDispatchRevision' = '1'
         and route_row.selection_reason = 'explicit_reroute'
         and route_row.selection_intent_snapshot #>>
               '{originalRoute,id}' <> route_row.id
         and route_row.selection_intent_snapshot #>>
               '{originalDispatch,id}' <> dispatch_row.id
         and (
           select count(*)
             from public.inbox_v2_outbound_routes original_route
             join public.inbox_v2_outbound_dispatches original_dispatch
               on original_dispatch.tenant_id = original_route.tenant_id
              and original_dispatch.route_id = original_route.id
              and original_dispatch.id =
                route_row.selection_intent_snapshot #>>
                  '{originalDispatch,id}'
             join public.inbox_v2_tenant_stream_changes original_change
               on original_change.tenant_id = stream_row.tenant_id
              and original_change.stream_commit_id = stream_row.id
              and original_change.mutation_id = stream_row.mutation_id
              and original_change.stream_position = stream_row.position
              and original_change.entity_type_id =
                'core:outbound-dispatch'
              and original_change.entity_id = original_dispatch.id
              and original_change.resulting_revision =
                original_dispatch.revision
              and original_change.state_kind = 'upsert'
              and original_change.state_schema_id =
                'core:inbox-v2.outbound-dispatch'
              and original_change.state_schema_version = 'v1'
              and original_change.state_reason_id is null
              and original_change.state_hash =
                original_change.payload_reference->>'digest'
              and original_change.payload_reference->>'tenantId' =
                original_change.tenant_id
              and original_change.payload_reference->>'recordId' =
                original_dispatch.id
              and original_change.payload_reference->>'schemaId' =
                'core:inbox-v2.outbound-dispatch'
              and original_change.payload_reference->>'schemaVersion' = 'v1'
              and original_change.domain_commit_reference->>'tenantId' =
                original_change.tenant_id
              and original_change.domain_commit_reference->>'recordId' =
                original_dispatch.id
              and original_change.domain_commit_reference->>'schemaId' =
                'core:inbox-v2.outbound-dispatch-reroute-commit'
              and original_change.domain_commit_reference->>'schemaVersion' =
                'v1'
            where original_route.tenant_id = route_row.tenant_id
              and original_route.id =
                route_row.selection_intent_snapshot #>>
                  '{originalRoute,id}'
              and original_route.conversation_id = route_row.conversation_id
              and original_route.external_thread_id =
                route_row.external_thread_id
              and original_route.source_thread_binding_id <>
                route_row.source_thread_binding_id
              and original_dispatch.message_id <> dispatch_row.message_id
              and original_dispatch.state = 'cancelled'
              and original_dispatch.attempt_count = 0
              and original_dispatch.active_attempt_id is null
              and original_dispatch.last_attempt_id is null
              and original_dispatch.retry_authorization_decision_id is null
              and original_dispatch.revision = 2
              and original_dispatch.updated_at = stream_row.committed_at
              and original_dispatch.created_at <= original_dispatch.updated_at
              and not exists (
                select 1
                  from public.inbox_v2_outbound_dispatch_attempts
                    original_attempt
                 where original_attempt.tenant_id = original_dispatch.tenant_id
                   and original_attempt.dispatch_id = original_dispatch.id
              )
              and (
                select count(*)
                  from public.inbox_v2_domain_events original_event
                  join public.inbox_v2_outbox_intents projection_intent
                    on projection_intent.tenant_id = original_event.tenant_id
                   and projection_intent.event_id = original_event.id
                   and projection_intent.stream_commit_id = stream_row.id
                   and projection_intent.mutation_id = stream_row.mutation_id
                   and projection_intent.effect_class = 'projection'
                   and projection_intent.type_id = 'core:projection.update'
                   and jsonb_array_length(projection_intent.change_ids) = 1
                   and projection_intent.change_ids ? original_change.id
                 where original_event.tenant_id = original_change.tenant_id
                   and original_event.stream_commit_id = stream_row.id
                   and original_event.mutation_id = stream_row.mutation_id
                   and original_event.type_id =
                     'core:outbound-dispatch.changed'
                   and original_event.payload_schema_id =
                     'core:inbox-v2.outbound-dispatch-reroute-commit'
                   and original_event.payload_schema_version = 'v1'
                   and original_event.payload_reference =
                     original_change.domain_commit_reference
                   and jsonb_array_length(original_event.change_ids) = 1
                   and original_event.change_ids ? original_change.id
                   and original_event.subjects @> jsonb_build_array(
                     jsonb_build_object(
                       'tenantId', original_dispatch.tenant_id,
                       'entityTypeId', 'core:outbound-dispatch',
                       'entityId', original_dispatch.id
                     )
                   )
                   and original_event.occurred_at = stream_row.committed_at
                   and original_event.recorded_at = stream_row.committed_at
              ) = 1
              and (
                select count(*)
                  from public.inbox_v2_outbox_intents original_intent
                  join public.inbox_v2_outbox_work_items original_work
                    on original_work.tenant_id = original_intent.tenant_id
                   and original_work.intent_id = original_intent.id
                   and original_work.state in ('pending', 'leased')
                 where original_intent.tenant_id = original_dispatch.tenant_id
                   and original_intent.effect_class = 'provider_io'
                   and original_intent.type_id = 'core:provider.dispatch'
                   and original_intent.payload_reference->>'tenantId' =
                     original_dispatch.tenant_id
                   and original_intent.payload_reference->>'recordId' =
                     original_dispatch.id
                   and original_intent.payload_reference->>'schemaId' =
                     'core:inbox-v2.outbound-dispatch'
                   and original_intent.payload_reference->>'schemaVersion' =
                     'v1'
              ) = 1
              and not exists (
                select 1
                  from public.inbox_v2_outbox_intents forbidden_provider_intent
                 where forbidden_provider_intent.tenant_id =
                         original_change.tenant_id
                   and forbidden_provider_intent.stream_commit_id =
                         original_change.stream_commit_id
                   and forbidden_provider_intent.mutation_id =
                         original_change.mutation_id
                   and forbidden_provider_intent.effect_class = 'provider_io'
                   and forbidden_provider_intent.change_ids ?
                         original_change.id
              )
              and (
                select count(*)
                  from public.inbox_v2_auth_audit_events reroute_audit
                 where reroute_audit.tenant_id = original_change.tenant_id
                   and reroute_audit.id = mutation_row.audit_event_id
                   and reroute_audit.mutation_id = stream_row.mutation_id
                   and reroute_audit.action_id =
                     'core:source.dispatch.reroute'
                   and reroute_audit.target_type_id =
                     'core:outbound-dispatch'
                   and reroute_audit.reason_code_id =
                     route_row.selection_intent_snapshot ->> 'reasonId'
                   and reroute_audit.evidence_reference =
                     original_change.domain_commit_reference
                   and reroute_audit.matched_permission_ids @>
                     array['core:source.dispatch.reroute']::text[]
              ) = 1
         ) = 1
         and (
           select count(*)
             from public.inbox_v2_tenant_stream_changes sibling_dispatch_change
            where sibling_dispatch_change.tenant_id = stream_row.tenant_id
              and sibling_dispatch_change.stream_commit_id = stream_row.id
              and sibling_dispatch_change.mutation_id = stream_row.mutation_id
              and sibling_dispatch_change.stream_position = stream_row.position
              and sibling_dispatch_change.entity_type_id =
                'core:outbound-dispatch'
         ) = 2
       )
     )
    join public.inbox_v2_messages message_row
      on message_row.tenant_id = dispatch_row.tenant_id
     and message_row.id = dispatch_row.message_id
     and message_row.conversation_id = dispatch_row.conversation_id
     and message_row.timeline_item_id = dispatch_row.timeline_item_id
     and message_row.origin_kind = 'hulee_external'
     and message_row.origin_outbound_route_id = route_row.id
     and message_row.revision = 1
     and message_row.last_changed_stream_position = stream_row.position
     and message_row.created_at = stream_row.committed_at
    join public.inbox_v2_tenant_stream_changes dispatch_change
      on dispatch_change.tenant_id = stream_row.tenant_id
     and dispatch_change.stream_commit_id = stream_row.id
     and dispatch_change.mutation_id = stream_row.mutation_id
     and dispatch_change.stream_position = stream_row.position
     and dispatch_change.entity_type_id = 'core:outbound-dispatch'
     and dispatch_change.entity_id = dispatch_row.id
     and dispatch_change.resulting_revision = dispatch_row.revision
     and dispatch_change.state_kind = 'upsert'
     and dispatch_change.state_schema_id = 'core:inbox-v2.outbound-dispatch'
     and dispatch_change.state_schema_version = 'v1'
     and dispatch_change.state_hash =
       dispatch_change.payload_reference->>'digest'
   where route_row.tenant_id = v_tenant_id
     and route_row.id = v_route_id
     and route_row.revision = 1
     and route_row.created_at = stream_row.committed_at
     and dispatch_row.created_at = stream_row.committed_at
     and (
       select count(*)
         from public.inbox_v2_outbox_intents provider_intent
        where provider_intent.tenant_id = dispatch_change.tenant_id
          and provider_intent.stream_commit_id = dispatch_change.stream_commit_id
          and provider_intent.mutation_id = dispatch_change.mutation_id
          and provider_intent.effect_class = 'provider_io'
          and provider_intent.type_id = 'core:provider.dispatch'
          and provider_intent.payload_reference =
            dispatch_change.payload_reference
          and jsonb_array_length(provider_intent.change_ids) = 1
          and provider_intent.change_ids ? dispatch_change.id
          and exists (
            select 1
              from public.inbox_v2_domain_events message_event
             where message_event.tenant_id = provider_intent.tenant_id
               and message_event.id = provider_intent.event_id
               and message_event.stream_commit_id =
                 provider_intent.stream_commit_id
               and message_event.mutation_id = provider_intent.mutation_id
               and message_event.type_id = 'core:message.changed'
               and message_event.change_ids ? dispatch_change.id
               and message_event.subjects @> jsonb_build_array(
                 jsonb_build_object(
                   'tenantId', dispatch_change.tenant_id,
                   'entityTypeId', 'core:message',
                   'entityId', dispatch_row.message_id
                 )
               )
          )
     ) = 1;

  if v_valid_count <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.atomic_outbound_creation_closure_missing';
  end if;
  return null;
exception
  when no_data_found or too_many_rows then
    raise exception using errcode = '23514',
      message = 'inbox_v2.atomic_outbound_creation_closure_missing';
end;
$$;



--
-- Name: inbox_v2_auth_attachment_message_change_valid(text, text, text, text, bigint, timestamp with time zone, text, text, jsonb, jsonb, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_attachment_message_change_valid(expected_tenant_id text, expected_stream_commit_id text, expected_mutation_id text, expected_change_id text, expected_stream_position bigint, expected_committed_at timestamp with time zone, expected_trusted_service_id text, expected_correlation_id text, expected_command_result_reference jsonb, expected_audit_evidence_reference jsonb, expected_audit_revision_delta_hash text) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select exists (
    select 1
      from public.inbox_v2_tenant_stream_changes message_change
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = message_change.tenant_id
       and message_row.id = message_change.entity_id
      join public.inbox_v2_timeline_items timeline_row
        on timeline_row.tenant_id = message_row.tenant_id
       and timeline_row.id = message_row.timeline_item_id
      join public.inbox_v2_timeline_contents content_row
        on content_row.tenant_id = message_row.tenant_id
       and content_row.id = message_row.content_id
      join public.inbox_v2_timeline_content_revisions content_revision_row
        on content_revision_row.tenant_id = content_row.tenant_id
       and content_revision_row.content_id = content_row.id
       and content_revision_row.revision = content_row.revision
      join public.inbox_v2_message_revisions revision_row
        on revision_row.tenant_id = message_change.tenant_id
       and revision_row.id =
         message_change.domain_commit_reference->>'recordId'
      join public.inbox_v2_action_attributions attribution_row
        on attribution_row.tenant_id = revision_row.tenant_id
       and attribution_row.id = revision_row.action_attribution_id
     where message_change.tenant_id = expected_tenant_id
       and message_change.stream_commit_id = expected_stream_commit_id
       and message_change.mutation_id = expected_mutation_id
       and message_change.id = expected_change_id
       and message_change.stream_position = expected_stream_position
       and message_change.entity_type_id = 'core:message'
       and message_change.resulting_revision >= 2
       and message_change.state_kind = 'upsert'
       and message_change.state_schema_id = 'core:inbox-v2.message'
       and message_change.state_schema_version = 'v1'
       and message_change.payload_reference->>'tenantId' =
         message_change.tenant_id
       and message_change.payload_reference->>'recordId' =
         message_change.entity_id
       and message_change.payload_reference->>'schemaId' =
         'core:inbox-v2.message'
       and message_change.payload_reference->>'schemaVersion' = 'v1'
       and message_change.payload_reference =
         expected_command_result_reference
       and message_change.state_hash =
         message_change.payload_reference->>'digest'
       and message_change.domain_commit_reference->>'tenantId' =
         message_change.tenant_id
       and message_change.domain_commit_reference->>'schemaId' =
         'core:inbox-v2.message-revision'
       and message_change.domain_commit_reference->>'schemaVersion' = 'v1'
       and message_change.domain_commit_reference =
         expected_audit_evidence_reference
       and expected_audit_revision_delta_hash <>
         'sha256:e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855'
       and message_change.audience in (
         'conversation_external', 'internal_participants'
       )
       and message_row.revision = message_change.resulting_revision
       and message_row.last_changed_stream_position = expected_stream_position
       and message_row.created_at <= expected_committed_at
       and message_row.updated_at = expected_committed_at
       and timeline_row.subject_kind = 'message'
       and timeline_row.subject_id = message_row.id
       and timeline_row.conversation_id = message_row.conversation_id
       and timeline_row.revision = message_row.revision
       and timeline_row.visibility::text = message_change.audience::text
       and timeline_row.last_changed_stream_position = expected_stream_position
       and timeline_row.created_at <= expected_committed_at
       and timeline_row.updated_at = expected_committed_at
       and content_row.owner_kind = 'message'
       and content_row.owner_id = message_row.id
       and content_row.revision = message_row.content_revision
       and content_row.state = message_row.content_state
       and content_row.state = 'available'
       and content_row.last_changed_stream_position = expected_stream_position
       and content_row.created_at <= expected_committed_at
       and content_row.updated_at = expected_committed_at
       and content_revision_row.expected_previous_revision =
         content_revision_row.revision - 1
       and content_revision_row.transition_kind = 'attachment_materialization'
       and content_revision_row.state = 'available'
       and content_revision_row.event_id is not null
       and content_revision_row.recorded_stream_position =
         expected_stream_position
       and content_revision_row.occurred_at = expected_committed_at
       and content_revision_row.recorded_at = expected_committed_at
       and message_change.timeline = jsonb_build_object(
         'conversation', jsonb_build_object(
           'tenantId', message_row.tenant_id,
           'id', message_row.conversation_id,
           'kind', 'conversation'
         ),
         'timelineSequence', timeline_row.timeline_sequence::text
       )
       and revision_row.message_id = message_row.id
       and revision_row.timeline_item_id = message_row.timeline_item_id
       and revision_row.message_revision = message_row.revision
       and revision_row.change_kind = 'attachment_materialized'
       and revision_row.expected_previous_revision =
         revision_row.message_revision - 1
       and revision_row.before_content_id = content_row.id
       and revision_row.before_content_revision = content_row.revision - 1
       and revision_row.before_content_state = 'available'
       and revision_row.after_content_id = content_row.id
       and revision_row.after_content_revision = content_row.revision
       and revision_row.after_content_state = 'available'
       and revision_row.provider_operation_id is null
       and revision_row.reason_id is null
       and revision_row.recorded_stream_position = expected_stream_position
       and revision_row.occurred_at = expected_committed_at
       and revision_row.recorded_at = expected_committed_at
       and attribution_row.conversation_id = message_row.conversation_id
       and attribution_row.action_participant_id is null
       and attribution_row.app_actor_kind = 'trusted_service'
       and attribution_row.app_trusted_service_id =
         expected_trusted_service_id
       and attribution_row.source_occurrence_id is null
       and attribution_row.automation_kind = 'system_event'
       and attribution_row.automation_cause_event_id is not null
       and attribution_row.automation_correlation_id = expected_correlation_id
       and attribution_row.automation_caused_at <= expected_committed_at
       and attribution_row.created_at = expected_committed_at
       and (
         select count(*)
           from public.inbox_v2_domain_events message_event
          where message_event.tenant_id = message_change.tenant_id
            and message_event.stream_commit_id =
              message_change.stream_commit_id
            and message_event.mutation_id = message_change.mutation_id
            and message_event.type_id = 'core:message.changed'
            and message_event.payload_schema_id =
              'core:inbox-v2.message-revision'
            and message_event.payload_schema_version = 'v1'
            and message_event.payload_reference =
              message_change.domain_commit_reference
            and content_revision_row.event_id = message_event.id
            and message_event.change_ids =
              jsonb_build_array(message_change.id)
            and message_event.subjects @> jsonb_build_array(
              jsonb_build_object(
                'tenantId', message_change.tenant_id,
                'entityTypeId', 'core:message',
                'entityId', message_change.entity_id
              )
            )
            and message_event.correlation_id = expected_correlation_id
            and message_event.occurred_at = expected_committed_at
            and message_event.recorded_at = expected_committed_at
       ) = 1
       and (
         select count(*)
           from public.inbox_v2_outbox_intents projection_intent
           join public.inbox_v2_domain_events projection_event
             on projection_event.tenant_id = projection_intent.tenant_id
            and projection_event.id = projection_intent.event_id
          where projection_intent.tenant_id = message_change.tenant_id
            and projection_intent.stream_commit_id =
              message_change.stream_commit_id
            and projection_intent.mutation_id = message_change.mutation_id
            and projection_intent.effect_class = 'projection'
            and projection_intent.type_id = 'core:projection.update'
            and projection_intent.change_ids =
              jsonb_build_array(message_change.id)
            and projection_event.stream_commit_id =
              message_change.stream_commit_id
            and projection_event.mutation_id = message_change.mutation_id
            and projection_event.type_id = 'core:message.changed'
       ) = 1
       and (
         select count(*)
           from public.inbox_v2_file_attachment_materialization_evidence
             evidence_row
           join public.inbox_v2_file_attachment_materialization_jobs job_row
             on job_row.tenant_id = evidence_row.tenant_id
            and job_row.id = evidence_row.job_id
          where evidence_row.tenant_id = message_change.tenant_id
            and evidence_row.timeline_content_id = content_row.id
            and evidence_row.resulting_content_revision = content_row.revision
            and evidence_row.expected_content_revision =
              content_row.revision - 1
            and evidence_row.outcome in ('ready', 'failed')
            and job_row.parent_message_id = message_row.id
            and job_row.timeline_item_id = timeline_row.id
            and job_row.timeline_content_id = content_row.id
            and job_row.result_content_revision = content_row.revision
            and job_row.cause_event_id =
              attribution_row.automation_cause_event_id
            and job_row.correlation_id = expected_correlation_id
            and job_row.caused_at = attribution_row.automation_caused_at
            and job_row.authorization_actor_kind = 'trusted_service'
            and job_row.authorization_actor_id =
              expected_trusted_service_id
            and job_row.updated_at = evidence_row.completed_at
            and (
              (evidence_row.outcome = 'ready' and job_row.state = 'ready')
              or (evidence_row.outcome = 'failed' and job_row.state = 'failed')
            )
       ) = 1
       and not exists (
         select 1
           from public.inbox_v2_atomic_source_resolution_materializations
             source_materialization
          where source_materialization.tenant_id = message_change.tenant_id
            and source_materialization.stream_commit_id =
              message_change.stream_commit_id
            and source_materialization.mutation_id = message_change.mutation_id
       )
  );
$$;



--
-- Name: inbox_v2_auth_audit_identifier_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_audit_identifier_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  v_invalid boolean;
begin
  select exists (
    select 1
      from (
        select identifier,
               lag(identifier) over (order by ordinal) as previous_identifier
          from unnest(new.matched_permission_ids) with ordinality
            identifier_row(identifier, ordinal)
     ) checked
     where checked.identifier is null
        or not public.inbox_v2_auth_catalog_id_safe(checked.identifier)
        or (checked.previous_identifier is not null and
            checked.previous_identifier collate "C" >=
              checked.identifier collate "C")
  ) into v_invalid;
  if v_invalid then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_audit_permission_ids_invalid';
  end if;

  select exists (
    select 1
      from (
        select identifier,
               lag(identifier) over (order by ordinal) as previous_identifier
          from unnest(new.scope_ids) with ordinality
            identifier_row(identifier, ordinal)
     ) checked
     where checked.identifier is null
        or not public.inbox_v2_auth_catalog_id_safe(checked.identifier)
        or (checked.previous_identifier is not null and
            checked.previous_identifier collate "C" >=
              checked.identifier collate "C")
  ) into v_invalid;
  if v_invalid then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_audit_scope_ids_invalid';
  end if;

  select exists (
    select 1
      from (
        select identifier,
               lag(identifier) over (order by ordinal) as previous_identifier
          from unnest(new.grant_source_ids) with ordinality
            identifier_row(identifier, ordinal)
      ) checked
     where checked.identifier is null
        or checked.identifier !~ '^internal-ref:[a-f0-9]{32,64}$'
        or (checked.previous_identifier is not null and
            checked.previous_identifier collate "C" >=
              checked.identifier collate "C")
  ) into v_invalid;
  if v_invalid then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_audit_grant_refs_invalid';
  end if;
  return new;
end;
$_$;



--
-- Name: inbox_v2_auth_catalog_id_safe(text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_catalog_id_safe(checked_value text) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
  select coalesce(char_length(checked_value) <= 256 and (
    (
      checked_value ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'
      and char_length(split_part(checked_value, ':', 2)) <= 160
    ) or (
      checked_value ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'
      and char_length(split_part(checked_value, ':', 2)) <= 80
      and char_length(split_part(checked_value, ':', 3)) <= 160
      and split_part(checked_value, ':', 2) not in (
        'core', 'hulee', 'module', 'platform', 'system'
      )
    )
  ), false);
$_$;



--
-- Name: inbox_v2_auth_command_commit_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_command_commit_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_closed boolean;
begin
  select exists (
    select 1
      from public.inbox_v2_auth_command_records command_row
      join public.inbox_v2_auth_mutation_commits mutation_row
        on mutation_row.tenant_id = command_row.tenant_id
       and mutation_row.mutation_id = command_row.mutation_id
       and mutation_row.command_record_id = command_row.id
     where command_row.tenant_id = new.tenant_id
       and command_row.id = new.id
       and command_row.state = 'completed'
       and command_row.updated_at = mutation_row.committed_at
  ) into v_closed;
  if not v_closed then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_command_orphan';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_auth_command_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_command_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then return old; end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_command_delete_forbidden';
  end if;
  if tg_op = 'INSERT' then
    if new.state <> 'pending' or new.mutation_id is not null
       or new.revision <> 1 or new.updated_at <> new.created_at then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_command_initial_state_invalid';
    end if;
    return new;
  end if;
  if old.state <> 'pending' or new.state <> 'completed'
     or old.mutation_id is not null or new.mutation_id is null
     or new.revision <> old.revision + 1
     or row(new.tenant_id, new.id, new.client_mutation_id,
            new.command_type_id, new.first_request_id, new.request_hash,
            new.actor_kind,
            new.actor_employee_id, new.actor_trusted_service_id,
            new.authorization_decision_id,
            new.authorization_epoch, new.authorization_decision_refs,
            new.authorized_at, new.authorization_not_after,
            new.occurred_at, new.created_at)
        is distinct from
        row(old.tenant_id, old.id, old.client_mutation_id,
            old.command_type_id, old.first_request_id, old.request_hash,
            old.actor_kind,
            old.actor_employee_id, old.actor_trusted_service_id,
            old.authorization_decision_id,
            old.authorization_epoch, old.authorization_decision_refs,
            old.authorized_at, old.authorization_not_after,
            old.occurred_at, old.created_at)
     or new.updated_at < old.updated_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_command_invalid_completion';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_auth_decision_refs_safe(jsonb, text, timestamp with time zone, boolean); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_decision_refs_safe(checked_value jsonb, checked_tenant_id text, checked_at timestamp with time zone, require_allowed boolean) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  decision_ref jsonb;
begin
  if jsonb_typeof(checked_value) <> 'array' then
    return false;
  end if;
  if jsonb_array_length(checked_value) not between 1 and 64
     or not public.inbox_v2_auth_json_tenant_safe(
       checked_value, checked_tenant_id
     ) then
    return false;
  end if;
  if (
    select count(*) <> count(distinct decision_value->>'id')
      from jsonb_array_elements(checked_value)
        as decision_rows(decision_value)
  ) then
    return false;
  end if;

  for decision_ref in select value from jsonb_array_elements(checked_value)
  loop
    if jsonb_typeof(decision_ref) <> 'object'
       or not (decision_ref ?& array[
         'tenantId', 'id', 'authorizationEpoch', 'principal',
         'permissionId', 'resourceScopeId', 'resource',
         'resourceAccessRevision', 'decisionRevision', 'decisionHash',
         'outcome', 'decidedAt', 'notAfter'
       ]::text[])
       or (decision_ref - array[
         'tenantId', 'id', 'authorizationEpoch', 'principal',
         'permissionId', 'resourceScopeId', 'resource',
         'resourceAccessRevision', 'decisionRevision', 'decisionHash',
         'outcome', 'decidedAt', 'notAfter'
       ]::text[]) <> '{}'::jsonb
       or decision_ref->>'tenantId' <> checked_tenant_id
       or jsonb_typeof(decision_ref->'id') <> 'string'
       or char_length(decision_ref->>'id') not between 1 and 512
       or decision_ref->>'id' !~ '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       or jsonb_typeof(decision_ref->'authorizationEpoch') <> 'string'
       or char_length(decision_ref->>'authorizationEpoch') not between 8 and 1024
       or jsonb_typeof(decision_ref->'permissionId') <> 'string'
       or not public.inbox_v2_auth_catalog_id_safe(
         decision_ref->>'permissionId'
       )
       or jsonb_typeof(decision_ref->'resourceScopeId') <> 'string'
       or not public.inbox_v2_auth_catalog_id_safe(
         decision_ref->>'resourceScopeId'
       )
       or jsonb_typeof(decision_ref->'principal') <> 'object'
       or jsonb_typeof(decision_ref->'resource') <> 'object'
       or not (
         (
           decision_ref->'principal'->>'kind' = 'employee'
           and decision_ref->'principal' ?& array['kind', 'employee']::text[]
           and ((decision_ref->'principal') -
             array['kind', 'employee']::text[]) =
             '{}'::jsonb
           and jsonb_typeof(
             decision_ref->'principal'->'employee'
           ) = 'object'
           and decision_ref->'principal'->'employee' ?&
             array['tenantId', 'kind', 'id']::text[]
           and ((decision_ref->'principal'->'employee') -
             array['tenantId', 'kind', 'id']::text[]) = '{}'::jsonb
           and jsonb_typeof(
             decision_ref->'principal'->'employee'->'tenantId'
           ) = 'string'
           and decision_ref->'principal'->'employee'->>'tenantId' =
             checked_tenant_id
           and jsonb_typeof(
             decision_ref->'principal'->'employee'->'kind'
           ) = 'string'
           and decision_ref->'principal'->'employee'->>'kind' = 'employee'
           and jsonb_typeof(
             decision_ref->'principal'->'employee'->'id'
           ) = 'string'
           and char_length(
             decision_ref->'principal'->'employee'->>'id'
           ) between 1 and 256
           and decision_ref->'principal'->'employee'->>'id' ~
             '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
         ) or (
           decision_ref->'principal'->>'kind' = 'trusted_service'
           and decision_ref->'principal' ?&
             array['kind', 'trustedServiceId']::text[]
           and ((decision_ref->'principal') -
             array['kind', 'trustedServiceId']::text[]) = '{}'::jsonb
           and jsonb_typeof(
             decision_ref->'principal'->'trustedServiceId'
           ) = 'string'
           and public.inbox_v2_auth_catalog_id_safe(
             decision_ref->'principal'->>'trustedServiceId'
           )
         )
       )
       or not (decision_ref->'resource' ?&
         array['tenantId', 'entityTypeId', 'entityId']::text[])
       or jsonb_typeof(decision_ref->'resource'->'tenantId') <> 'string'
       or decision_ref->'resource'->>'tenantId' <> checked_tenant_id
       or ((decision_ref->'resource') -
         array['tenantId', 'entityTypeId', 'entityId']::text[]) <> '{}'::jsonb
       or jsonb_typeof(decision_ref->'resource'->'entityTypeId') <> 'string'
       or not public.inbox_v2_auth_catalog_id_safe(
         decision_ref->'resource'->>'entityTypeId'
       )
       or jsonb_typeof(decision_ref->'resource'->'entityId') <> 'string'
       or char_length(decision_ref->'resource'->>'entityId') not between 1 and 512
       or decision_ref->'resource'->>'entityId' !~
         '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       or jsonb_typeof(decision_ref->'resourceAccessRevision') <> 'string'
       or decision_ref->>'resourceAccessRevision' !~ '^[1-9][0-9]{0,18}$'
       or jsonb_typeof(decision_ref->'decisionRevision') <> 'string'
       or decision_ref->>'decisionRevision' !~ '^[1-9][0-9]{0,18}$'
       or jsonb_typeof(decision_ref->'decisionHash') <> 'string'
       or decision_ref->>'decisionHash' !~ '^sha256:[0-9a-f]{64}$'
       or jsonb_typeof(decision_ref->'outcome') <> 'string'
       or decision_ref->>'outcome' not in ('allowed', 'denied')
       or jsonb_typeof(decision_ref->'decidedAt') <> 'string'
       or jsonb_typeof(decision_ref->'notAfter') <> 'string'
       or (require_allowed and decision_ref->>'outcome' <> 'allowed') then
      return false;
    end if;
    begin
      if (decision_ref->>'resourceAccessRevision')::numeric >
           9223372036854775807
         or (decision_ref->>'decisionRevision')::numeric >
           9223372036854775807
         or not isfinite((decision_ref->>'decidedAt')::timestamptz)
         or not isfinite((decision_ref->>'notAfter')::timestamptz)
         or (decision_ref->>'decidedAt')::timestamptz > checked_at
         or checked_at >= (decision_ref->>'notAfter')::timestamptz then
        return false;
      end if;
    exception when others then
      return false;
    end;
  end loop;
  return true;
end;
$_$;



--
-- Name: inbox_v2_auth_domain_mutation_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_domain_mutation_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_command public.inbox_v2_auth_command_records%rowtype;
  v_stream public.inbox_v2_tenant_stream_commits%rowtype;
  v_audit public.inbox_v2_auth_audit_events%rowtype;
  v_change_count integer;
  v_event_count integer;
  v_authorization_event_count integer;
  v_outbox_count integer;
  v_projection_count integer;
  v_facet_count integer;
  v_invalid_count integer;
  v_message_change_count integer;
  v_provider_operation_change_count integer;
  v_message_row_count integer;
  v_source_change_count integer;
  v_source_materialization_count integer;
  v_change_ids jsonb;
  v_event_ids jsonb;
  v_outbox_ids jsonb;
  v_facet_digest text;
  v_stream_manifest_digest text;
  v_mutation_manifest_digest text;
  v_decision_not_after timestamptz;
  v_closed boolean;
  v_empty_digest constant text :=
    'sha256:e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855';
begin
  if new.revision_effect_count <> 0
     or new.relation_write_count <> 0
     or new.revision_effect_digest_sha256 <> v_empty_digest
     or new.relation_write_digest_sha256 <> v_empty_digest then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_authorization_delta_forbidden';
  end if;

  select * into strict v_command
    from public.inbox_v2_auth_command_records command_row
   where command_row.tenant_id = new.tenant_id
     and command_row.id = new.command_record_id
     and command_row.mutation_id = new.mutation_id;
  select * into strict v_stream
    from public.inbox_v2_tenant_stream_commits stream_row
   where stream_row.tenant_id = new.tenant_id
     and stream_row.id = new.stream_commit_id
     and stream_row.mutation_id = new.mutation_id;
  select * into strict v_audit
    from public.inbox_v2_auth_audit_events audit_row
   where audit_row.tenant_id = new.tenant_id
     and audit_row.id = new.audit_event_id
     and audit_row.mutation_id = new.mutation_id;

  if v_command.state <> 'completed'
     or v_command.updated_at <> new.committed_at
     or v_stream.committed_at <> new.committed_at
     or v_audit.recorded_at <> new.committed_at
     or v_command.authorized_at > new.committed_at
     or new.committed_at >= v_command.authorization_not_after
     or v_command.authorization_decision_refs <>
        v_stream.authorization_decision_refs
     or row(v_audit.actor_kind, v_audit.actor_employee_id,
            v_audit.actor_trusted_service_id, v_audit.authorization_epoch,
            v_audit.client_mutation_id, v_audit.command_type_id,
            v_audit.request_hash)
       is distinct from
       row(v_command.actor_kind, v_command.actor_employee_id,
           v_command.actor_trusted_service_id, v_command.authorization_epoch,
           v_command.client_mutation_id, v_command.command_type_id,
           v_command.request_hash)
     or v_audit.correlation_id <> v_stream.correlation_id
     or v_audit.authorization_decision_refs <>
        v_stream.authorization_decision_refs
     or v_stream.command_ids <> to_jsonb(array[v_command.id]::text[])
     or v_stream.client_mutation_ids <>
        to_jsonb(array[v_command.client_mutation_id]::text[])
     or v_stream.audience_impact_kind <> 'none'
     or v_stream.audience_impact_manifest <> '{"kind":"none"}'::jsonb then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_command_audit_mismatch';
  end if;

  if not public.inbox_v2_auth_decision_refs_safe(
       v_command.authorization_decision_refs,
       new.tenant_id,
       v_command.authorized_at,
       true
     )
     or not public.inbox_v2_auth_decision_refs_safe(
       v_stream.authorization_decision_refs,
       new.tenant_id,
       new.committed_at,
       true
     )
     or not public.inbox_v2_auth_payload_reference_safe(
       v_audit.evidence_reference, new.tenant_id
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_decision_manifest_invalid';
  end if;

  select min((decision_ref->>'notAfter')::timestamptz)
    into v_decision_not_after
    from jsonb_array_elements(
      v_command.authorization_decision_refs
    ) decision_ref;
  if v_command.authorization_not_after is distinct from v_decision_not_after
     or not exists (
       select 1
         from jsonb_array_elements(
           v_command.authorization_decision_refs
         ) decision_ref
        where decision_ref->>'id' = v_command.authorization_decision_id
          and decision_ref->>'authorizationEpoch' =
            v_command.authorization_epoch
          and decision_ref->>'outcome' = 'allowed'
     )
     or exists (
       select 1
         from jsonb_array_elements(
           v_command.authorization_decision_refs
         ) decision_ref
        where decision_ref->>'authorizationEpoch' <>
            v_command.authorization_epoch
           or case v_command.actor_kind
             when 'employee' then
               decision_ref->'principal'->>'kind' <> 'employee'
               or decision_ref->'principal'->'employee'->>'tenantId' <>
                 new.tenant_id
               or decision_ref->'principal'->'employee'->>'id' <>
                 v_command.actor_employee_id
             when 'trusted_service' then
               decision_ref->'principal'->>'kind' <> 'trusted_service'
               or decision_ref->'principal'->>'trustedServiceId' <>
                 v_command.actor_trusted_service_id
             else true
           end
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_decision_manifest_invalid';
  end if;

  select count(*)::integer,
         coalesce(to_jsonb(array_agg(change_row.id order by change_row.ordinal)),
                  '[]'::jsonb)
    into v_change_count, v_change_ids
    from public.inbox_v2_tenant_stream_changes change_row
   where change_row.tenant_id = new.tenant_id
     and change_row.stream_commit_id = new.stream_commit_id
     and change_row.mutation_id = new.mutation_id;
  select count(*)::integer,
         coalesce(to_jsonb(array_agg(event_row.id order by event_row.ordinal)),
                  '[]'::jsonb),
         count(*) filter (
           where event_row.type_id = 'core:authorization.changed'
         )::integer
    into v_event_count, v_event_ids, v_authorization_event_count
    from public.inbox_v2_domain_events event_row
   where event_row.tenant_id = new.tenant_id
     and event_row.stream_commit_id = new.stream_commit_id
     and event_row.mutation_id = new.mutation_id;
  select count(*)::integer,
         coalesce(to_jsonb(array_agg(intent_row.id order by intent_row.ordinal)),
                  '[]'::jsonb),
         count(*) filter (
           where intent_row.effect_class = 'projection'
             and intent_row.type_id = 'core:projection.update'
         )::integer
    into v_outbox_count, v_outbox_ids, v_projection_count
    from public.inbox_v2_outbox_intents intent_row
   where intent_row.tenant_id = new.tenant_id
     and intent_row.stream_commit_id = new.stream_commit_id
     and intent_row.mutation_id = new.mutation_id;

  if row(v_change_count, v_event_count, v_outbox_count,
         v_change_ids, v_event_ids, v_outbox_ids)
       is distinct from
     row(v_stream.change_count, v_stream.event_count,
         v_stream.outbox_intent_count, v_stream.change_ids,
         v_stream.event_ids, v_stream.outbox_intent_ids)
     or v_projection_count <> new.projection_intent_count
     or v_projection_count < 1
     or v_authorization_event_count <> 0 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_stream_manifest_incomplete';
  end if;

  select count(*)::integer into v_invalid_count
    from public.inbox_v2_tenant_stream_changes change_row
   where change_row.tenant_id = new.tenant_id
     and change_row.stream_commit_id = new.stream_commit_id
     and (change_row.mutation_id <> new.mutation_id
       or change_row.stream_position <> v_stream.position
       or change_row.created_at <> new.committed_at
       or not public.inbox_v2_auth_payload_reference_safe(
         change_row.domain_commit_reference, new.tenant_id
       )
       or not public.inbox_v2_auth_payload_reference_safe(
         change_row.payload_reference, new.tenant_id
       )
       or not public.inbox_v2_auth_json_tenant_safe(
         change_row.timeline, new.tenant_id
       ));
  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_domain_events event_row
   where event_row.tenant_id = new.tenant_id
     and event_row.stream_commit_id = new.stream_commit_id
     and (event_row.mutation_id <> new.mutation_id
       or event_row.stream_position <> v_stream.position
       or event_row.recorded_at <> new.committed_at
       or event_row.correlation_id <> v_stream.correlation_id
       or event_row.command_ids <> v_stream.command_ids
       or event_row.client_mutation_ids <> v_stream.client_mutation_ids
       or event_row.authorization_decision_refs <>
          v_stream.authorization_decision_refs
       or event_row.access_effect <> 'none'
       or event_row.access_effect_causes <> '[]'::jsonb
       or not (v_stream.change_ids @> event_row.change_ids)
       or not public.inbox_v2_auth_payload_reference_safe(
         event_row.payload_reference, new.tenant_id
       )
       or not public.inbox_v2_auth_json_tenant_safe(
         event_row.subjects, new.tenant_id
       )
       or not public.inbox_v2_auth_decision_refs_safe(
         event_row.authorization_decision_refs,
         new.tenant_id,
         new.committed_at,
         true
       ));
  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_outbox_intents intent_row
    join public.inbox_v2_domain_events event_row
      on event_row.tenant_id = intent_row.tenant_id
     and event_row.id = intent_row.event_id
   where intent_row.tenant_id = new.tenant_id
     and intent_row.stream_commit_id = new.stream_commit_id
     and (intent_row.mutation_id <> new.mutation_id
       or intent_row.stream_position <> v_stream.position
       or intent_row.created_at <> new.committed_at
       or intent_row.available_at < new.committed_at
       or intent_row.correlation_id <> v_stream.correlation_id
       or event_row.stream_commit_id <> new.stream_commit_id
       or event_row.mutation_id <> new.mutation_id
       or event_row.correlation_id <> intent_row.correlation_id
       or (
         intent_row.type_id in (
           'core:provider.dispatch', 'core:provider.message_lifecycle',
           'core:provider.message_reaction'
         ) and intent_row.effect_class <> 'provider_io'
       )
       or (
         intent_row.effect_class = 'provider_io'
         and (
           intent_row.type_id not in (
             'core:provider.dispatch', 'core:provider.message_lifecycle',
             'core:provider.message_reaction'
           )
            or intent_row.payload_reference is null
            or intent_row.payload_reference->>'schemaVersion' <> 'v1'
            or jsonb_array_length(intent_row.change_ids) <> 1
            or event_row.type_id <> 'core:message.changed'
           or exists (
             select 1
               from public.inbox_v2_tenant_stream_changes referenced_change
              where referenced_change.tenant_id = intent_row.tenant_id
                and referenced_change.stream_commit_id =
                  intent_row.stream_commit_id
                and referenced_change.mutation_id = intent_row.mutation_id
                and referenced_change.id in (
                  select jsonb_array_elements_text(intent_row.change_ids)
                )
                and (
                  referenced_change.audience = 'staff_only'
                  or referenced_change.entity_type_id = 'core:staff-note'
                )
           )
            or (
              intent_row.type_id = 'core:provider.dispatch'
              and (
                intent_row.payload_reference->>'schemaId' <>
                  'core:inbox-v2.outbound-dispatch'
                or not exists (
              select 1
                from public.inbox_v2_tenant_stream_changes dispatch_change
              where dispatch_change.tenant_id = intent_row.tenant_id
                and dispatch_change.stream_commit_id =
                  intent_row.stream_commit_id
                and dispatch_change.mutation_id = intent_row.mutation_id
                and dispatch_change.id in (
                  select jsonb_array_elements_text(intent_row.change_ids)
                )
                and dispatch_change.entity_type_id =
                  'core:outbound-dispatch'
                and dispatch_change.entity_id =
                  intent_row.payload_reference->>'recordId'
                and dispatch_change.state_kind = 'upsert'
                and dispatch_change.state_schema_id =
                  'core:inbox-v2.outbound-dispatch'
                 and dispatch_change.state_schema_version = 'v1'
                 and dispatch_change.payload_reference =
                   intent_row.payload_reference
                 and dispatch_change.state_hash =
                   dispatch_change.payload_reference->>'digest'
                 and dispatch_change.resulting_revision = 1
                 and exists (
                   select 1
                     from public.inbox_v2_outbound_dispatches dispatch_row
                     join public.inbox_v2_atomic_outbound_dispatch_materializations
                       materialization_row
                       on materialization_row.tenant_id = dispatch_row.tenant_id
                      and materialization_row.dispatch_id = dispatch_row.id
                    where dispatch_row.tenant_id = dispatch_change.tenant_id
                      and dispatch_row.id = dispatch_change.entity_id
                      and materialization_row.mutation_id =
                        dispatch_change.mutation_id
                      and materialization_row.stream_commit_id =
                        dispatch_change.stream_commit_id
                      and materialization_row.stream_position =
                        dispatch_change.stream_position
                      and materialization_row.resulting_revision =
                        dispatch_change.resulting_revision
                      and materialization_row.created_at = new.committed_at
                      and dispatch_row.state = 'queued'
                     and dispatch_row.attempt_count = 0
                     and dispatch_row.active_attempt_id is null
                     and dispatch_row.last_attempt_id is null
                     and dispatch_row.retry_authorization_decision_id is null
                     and dispatch_row.revision = 1
                     and dispatch_row.created_at = new.committed_at
                      and dispatch_row.updated_at = new.committed_at
                      and event_row.subjects @> jsonb_build_array(
                        jsonb_build_object(
                          'tenantId', dispatch_change.tenant_id,
                          'entityTypeId', 'core:message',
                          'entityId', dispatch_row.message_id
                        )
                      )
                      and not exists (
                       select 1
                         from public.inbox_v2_outbound_dispatch_attempts
                           attempt_row
                        where attempt_row.tenant_id = dispatch_row.tenant_id
                          and attempt_row.dispatch_id = dispatch_row.id
                )
              )
            )
            or (
              intent_row.type_id = 'core:provider.message_lifecycle'
              and (
                intent_row.payload_reference->>'schemaId' <>
                  'core:inbox-v2.message-provider-lifecycle-operation'
                or not exists (
                  select 1
                  from public.inbox_v2_message_provider_lifecycle_operations
                    operation_row
                  join public.inbox_v2_outbound_route_consumptions consumption_row
                    on consumption_row.tenant_id = operation_row.tenant_id
                   and consumption_row.consumer_kind = 'provider_lifecycle'
                   and consumption_row.consumer_id = operation_row.id
                   and consumption_row.message_id = operation_row.message_id
                   and consumption_row.outbound_route_id =
                     operation_row.outbound_route_id
                  join public.inbox_v2_tenant_stream_changes lifecycle_change
                    on lifecycle_change.tenant_id = operation_row.tenant_id
                   and lifecycle_change.stream_commit_id =
                     intent_row.stream_commit_id
                   and lifecycle_change.mutation_id = intent_row.mutation_id
                   and lifecycle_change.id in (
                     select jsonb_array_elements_text(intent_row.change_ids)
                   )
                  where operation_row.tenant_id = intent_row.tenant_id
                    and operation_row.id =
                      intent_row.payload_reference->>'recordId'
                    and operation_row.origin = 'hulee_requested'
                    and operation_row.outcome = 'pending'
                    and operation_row.outbound_route_id is not null
                    and operation_row.revision = 1
                    and operation_row.created_stream_position = v_stream.position
                    and operation_row.last_changed_stream_position =
                      v_stream.position
                    and operation_row.recorded_at = new.committed_at
                    and operation_row.created_at = new.committed_at
                    and operation_row.updated_at = new.committed_at
                    and event_row.subjects @> jsonb_build_array(
                      jsonb_build_object(
                        'tenantId', operation_row.tenant_id,
                        'entityTypeId', 'core:message',
                        'entityId', operation_row.message_id
                      )
                    )
                    and lifecycle_change.entity_type_id =
                      'core:message-provider-lifecycle-operation'
                    and lifecycle_change.entity_id = operation_row.id
                    and lifecycle_change.resulting_revision =
                      operation_row.revision
                    and lifecycle_change.state_kind = 'upsert'
                    and lifecycle_change.state_schema_id =
                      'core:inbox-v2.message-provider-lifecycle-operation'
                    and lifecycle_change.state_schema_version = 'v1'
                    and lifecycle_change.payload_reference =
                      intent_row.payload_reference
                    and lifecycle_change.state_hash =
                      lifecycle_change.payload_reference->>'digest'
                    and (
                      (
                        operation_row.action = 'edit'
                        and exists (
                          select 1
                          from public.inbox_v2_tenant_stream_changes
                            message_change
                          join public.inbox_v2_message_revisions revision_row
                            on revision_row.tenant_id =
                              message_change.tenant_id
                           and revision_row.message_id =
                              message_change.entity_id
                           and revision_row.message_revision =
                              message_change.resulting_revision
                          where message_change.tenant_id =
                              operation_row.tenant_id
                            and message_change.stream_commit_id =
                              intent_row.stream_commit_id
                            and message_change.mutation_id =
                              intent_row.mutation_id
                            and message_change.entity_type_id = 'core:message'
                            and message_change.entity_id =
                              operation_row.message_id
                            and message_change.state_kind = 'upsert'
                            and message_change.state_schema_id =
                              'core:inbox-v2.message'
                            and message_change.state_schema_version = 'v1'
                            and message_change.state_hash =
                              message_change.payload_reference->>'digest'
                            and revision_row.change_kind = 'edited'
                            and revision_row.provider_operation_id =
                              operation_row.id
                            and revision_row.recorded_stream_position =
                              v_stream.position
                            and event_row.change_ids @> jsonb_build_array(
                              lifecycle_change.id,
                              message_change.id
                            )
                        )
                      ) or (
                        operation_row.action = 'delete'
                        and not exists (
                          select 1
                          from public.inbox_v2_tenant_stream_changes
                            message_change
                          where message_change.tenant_id =
                              operation_row.tenant_id
                            and message_change.stream_commit_id =
                              intent_row.stream_commit_id
                            and message_change.mutation_id =
                              intent_row.mutation_id
                            and message_change.entity_type_id = 'core:message'
                            and message_change.entity_id =
                              operation_row.message_id
                        )
                      )
                    )
                )
              )
            )
            or (
              intent_row.type_id = 'core:provider.message_reaction'
              and (
                intent_row.payload_reference->>'schemaId' <>
                  'core:inbox-v2.message-reaction-transition'
                or not exists (
                  select 1
                    from public.inbox_v2_message_reaction_transitions
                      reaction_transition
                    join public.inbox_v2_message_reactions reaction_row
                      on reaction_row.tenant_id =
                        reaction_transition.tenant_id
                     and reaction_row.id = reaction_transition.reaction_id
                    join public.inbox_v2_outbound_route_consumptions
                      consumption_row
                      on consumption_row.tenant_id =
                        reaction_transition.tenant_id
                     and consumption_row.consumer_kind = 'reaction'
                     and consumption_row.consumer_id =
                        reaction_transition.id
                     and consumption_row.message_id = reaction_row.message_id
                     and consumption_row.outbound_route_id =
                        reaction_transition.outbound_route_id
                    join public.inbox_v2_outbound_routes route_row
                      on route_row.tenant_id = reaction_transition.tenant_id
                     and route_row.id = reaction_transition.outbound_route_id
                    join public.inbox_v2_tenant_stream_changes reaction_change
                      on reaction_change.tenant_id =
                        reaction_transition.tenant_id
                     and reaction_change.stream_commit_id =
                        intent_row.stream_commit_id
                     and reaction_change.mutation_id = intent_row.mutation_id
                     and reaction_change.id in (
                       select jsonb_array_elements_text(intent_row.change_ids)
                     )
                   where reaction_transition.tenant_id = intent_row.tenant_id
                     and reaction_transition.id =
                       intent_row.payload_reference->>'recordId'
                     and reaction_transition.mode = 'external_request'
                     and reaction_transition.record_revision = 1
                     and reaction_transition.recorded_stream_position =
                       v_stream.position
                     and reaction_transition.recorded_at = new.committed_at
                     and v_command.command_type_id =
                       'core:message.reaction.' ||
                         reaction_transition.operation::text
                     and reaction_change.entity_type_id =
                       'core:message-reaction-transition'
                     and reaction_change.entity_id = reaction_transition.id
                     and reaction_change.resulting_revision =
                       reaction_transition.record_revision
                     and reaction_change.state_kind = 'upsert'
                     and reaction_change.state_schema_id =
                       'core:inbox-v2.message-reaction-transition'
                     and reaction_change.state_schema_version = 'v1'
                     and reaction_change.payload_reference =
                       intent_row.payload_reference
                     and reaction_change.state_hash =
                       reaction_change.payload_reference->>'digest'
                     and route_row.source_account_id =
                       reaction_transition.source_account_id
                     and route_row.source_thread_binding_id =
                       reaction_transition.source_thread_binding_id
                     and route_row.operation_id =
                       v_command.command_type_id
                     and route_row.selection_intent_kind =
                       'explicit_occurrence'
                     and route_row.selection_reason = 'explicit_occurrence'
                     and route_row.fallback_policy_ordinal is null
                     and event_row.subjects @> jsonb_build_array(
                       jsonb_build_object(
                         'tenantId', reaction_transition.tenant_id,
                         'entityTypeId', 'core:message',
                         'entityId', reaction_row.message_id
                       )
                     )
                )
              )
            )
         )
       )
         )
       )
       or not (v_stream.change_ids @> intent_row.change_ids)
       or not (event_row.change_ids @> intent_row.change_ids)
       or not public.inbox_v2_auth_payload_reference_safe(
         intent_row.payload_reference, new.tenant_id
       ));
  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_tenant_stream_changes dispatch_change
    left join public.inbox_v2_atomic_outbound_dispatch_materializations
      materialization_row
      on materialization_row.tenant_id = dispatch_change.tenant_id
     and materialization_row.dispatch_id = dispatch_change.entity_id
     and materialization_row.stream_commit_id =
       dispatch_change.stream_commit_id
     and materialization_row.mutation_id = dispatch_change.mutation_id
     and materialization_row.stream_position =
       dispatch_change.stream_position
    left join public.inbox_v2_outbound_dispatches dispatch_row
      on dispatch_row.tenant_id = dispatch_change.tenant_id
     and dispatch_row.id = dispatch_change.entity_id
   where dispatch_change.tenant_id = new.tenant_id
     and dispatch_change.stream_commit_id = new.stream_commit_id
     and dispatch_change.mutation_id = new.mutation_id
     and dispatch_change.entity_type_id = 'core:outbound-dispatch'
     and not (
       v_command.command_type_id = 'core:source.dispatch.reroute'
       and dispatch_change.resulting_revision = 2
       and dispatch_change.state_kind = 'upsert'
       and dispatch_change.state_schema_id =
          'core:inbox-v2.outbound-dispatch'
       and dispatch_change.state_schema_version = 'v1'
       and dispatch_change.payload_reference->>'tenantId' =
          dispatch_change.tenant_id
       and dispatch_change.payload_reference->>'recordId' =
          dispatch_change.entity_id
       and dispatch_change.payload_reference->>'schemaId' =
          'core:inbox-v2.outbound-dispatch'
       and dispatch_change.payload_reference->>'schemaVersion' = 'v1'
       and dispatch_change.state_hash =
          dispatch_change.payload_reference->>'digest'
       and dispatch_change.domain_commit_reference->>'tenantId' =
          dispatch_change.tenant_id
       and dispatch_change.domain_commit_reference->>'recordId' =
          dispatch_change.entity_id
       and dispatch_change.domain_commit_reference->>'schemaId' =
          'core:inbox-v2.outbound-dispatch-reroute-commit'
       and dispatch_change.domain_commit_reference->>'schemaVersion' = 'v1'
       and dispatch_change.domain_commit_reference =
          v_audit.evidence_reference
       and dispatch_row.id is not null
       and dispatch_row.state = 'cancelled'
       and dispatch_row.attempt_count = 0
       and dispatch_row.active_attempt_id is null
       and dispatch_row.last_attempt_id is null
       and dispatch_row.retry_authorization_decision_id is null
       and dispatch_row.revision = 2
       and dispatch_row.updated_at = new.committed_at
       and not exists (
         select 1
           from public.inbox_v2_outbound_dispatch_attempts attempt_row
          where attempt_row.tenant_id = dispatch_change.tenant_id
            and attempt_row.dispatch_id = dispatch_change.entity_id
       )
       and exists (
         select 1
           from public.inbox_v2_outbound_routes reroute_route
           join public.inbox_v2_messages reroute_message
             on reroute_message.tenant_id = reroute_route.tenant_id
            and reroute_message.origin_outbound_route_id = reroute_route.id
            and reroute_message.last_changed_stream_position =
              dispatch_change.stream_position
            and reroute_message.created_at = new.committed_at
          where reroute_route.tenant_id = dispatch_change.tenant_id
            and reroute_route.selection_intent_kind = 'explicit_reroute'
            and reroute_route.selection_intent_snapshot #>>
                '{originalDispatch,tenantId}' = dispatch_change.tenant_id
            and reroute_route.selection_intent_snapshot #>>
                '{originalDispatch,id}' = dispatch_change.entity_id
            and reroute_route.selection_intent_snapshot ->>
                'expectedOriginalDispatchRevision' = '1'
            and reroute_route.selection_intent_snapshot #>>
                '{originalRoute,id}' = dispatch_row.route_id
            and dispatch_change.state_reason_id is null
       )
     )
     and (
       dispatch_change.resulting_revision <> 1
       or dispatch_change.state_kind <> 'upsert'
       or dispatch_change.state_schema_id is distinct from
          'core:inbox-v2.outbound-dispatch'
       or dispatch_change.state_schema_version is distinct from 'v1'
       or dispatch_change.payload_reference->>'recordId' is distinct from
          dispatch_change.entity_id
       or dispatch_change.payload_reference->>'schemaId' is distinct from
          'core:inbox-v2.outbound-dispatch'
       or dispatch_change.payload_reference->>'schemaVersion' is distinct from
          'v1'
       or dispatch_change.state_hash is distinct from
          dispatch_change.payload_reference->>'digest'
       or materialization_row.dispatch_id is null
       or materialization_row.resulting_revision is distinct from
          dispatch_change.resulting_revision
       or materialization_row.created_at <> new.committed_at
       or dispatch_row.id is null
       or dispatch_row.state <> 'queued'
       or dispatch_row.attempt_count <> 0
       or dispatch_row.active_attempt_id is not null
       or dispatch_row.last_attempt_id is not null
       or dispatch_row.retry_authorization_decision_id is not null
       or dispatch_row.revision <> 1
       or dispatch_row.created_at <> new.committed_at
       or dispatch_row.updated_at <> new.committed_at
       or exists (
         select 1
           from public.inbox_v2_outbound_dispatch_attempts attempt_row
          where attempt_row.tenant_id = dispatch_change.tenant_id
            and attempt_row.dispatch_id = dispatch_change.entity_id
       )
       or (
         select count(*)
           from public.inbox_v2_tenant_stream_changes sibling_change
          where sibling_change.tenant_id = dispatch_change.tenant_id
            and sibling_change.stream_commit_id =
              dispatch_change.stream_commit_id
             and sibling_change.mutation_id = dispatch_change.mutation_id
             and sibling_change.entity_type_id = 'core:outbound-dispatch'
             and sibling_change.entity_id = dispatch_change.entity_id
       ) <> 1
       or (
         select count(*)
           from public.inbox_v2_outbox_intents provider_intent
          where provider_intent.tenant_id = dispatch_change.tenant_id
            and provider_intent.stream_commit_id =
              dispatch_change.stream_commit_id
            and provider_intent.mutation_id = dispatch_change.mutation_id
            and provider_intent.effect_class = 'provider_io'
            and provider_intent.type_id = 'core:provider.dispatch'
            and provider_intent.payload_reference->>'recordId' =
              dispatch_change.entity_id
            and provider_intent.payload_reference->>'schemaId' =
              'core:inbox-v2.outbound-dispatch'
            and provider_intent.payload_reference->>'schemaVersion' = 'v1'
            and jsonb_array_length(provider_intent.change_ids) = 1
            and provider_intent.change_ids ? dispatch_change.id
            and exists (
              select 1
                from public.inbox_v2_domain_events message_event
               where message_event.tenant_id = provider_intent.tenant_id
                 and message_event.id = provider_intent.event_id
                 and message_event.stream_commit_id =
                   provider_intent.stream_commit_id
                 and message_event.mutation_id = provider_intent.mutation_id
                 and message_event.type_id = 'core:message.changed'
                 and message_event.change_ids ? dispatch_change.id
                 and message_event.subjects @> jsonb_build_array(
                   jsonb_build_object(
                     'tenantId', dispatch_change.tenant_id,
                     'entityTypeId', 'core:message',
                     'entityId', dispatch_row.message_id
                   )
                 )
            )
       ) <> 1
       or not exists (
         select 1
           from public.inbox_v2_outbox_intents provider_intent
          where provider_intent.tenant_id = dispatch_change.tenant_id
            and provider_intent.stream_commit_id =
              dispatch_change.stream_commit_id
            and provider_intent.mutation_id = dispatch_change.mutation_id
            and provider_intent.effect_class = 'provider_io'
            and provider_intent.type_id = 'core:provider.dispatch'
            and provider_intent.payload_reference =
              dispatch_change.payload_reference
            and jsonb_array_length(provider_intent.change_ids) = 1
            and provider_intent.change_ids ? dispatch_change.id
            and exists (
              select 1
                from public.inbox_v2_domain_events message_event
               where message_event.tenant_id = provider_intent.tenant_id
                 and message_event.id = provider_intent.event_id
                 and message_event.stream_commit_id =
                   provider_intent.stream_commit_id
                 and message_event.mutation_id = provider_intent.mutation_id
                 and message_event.type_id = 'core:message.changed'
                 and message_event.change_ids ? dispatch_change.id
                 and message_event.subjects @> jsonb_build_array(
                   jsonb_build_object(
                     'tenantId', dispatch_change.tenant_id,
                     'entityTypeId', 'core:message',
                     'entityId', dispatch_row.message_id
                   )
                 )
                 )
            )
       or (
         select count(*)
           from public.inbox_v2_outbox_intents projection_intent
           join public.inbox_v2_domain_events projection_event
             on projection_event.tenant_id = projection_intent.tenant_id
            and projection_event.id = projection_intent.event_id
          where projection_intent.tenant_id = dispatch_change.tenant_id
            and projection_intent.stream_commit_id =
              dispatch_change.stream_commit_id
            and projection_intent.mutation_id = dispatch_change.mutation_id
            and projection_intent.effect_class = 'projection'
            and projection_intent.type_id = 'core:projection.update'
            and projection_intent.change_ids ? dispatch_change.id
            and projection_event.stream_commit_id =
              dispatch_change.stream_commit_id
            and projection_event.mutation_id = dispatch_change.mutation_id
            and projection_event.type_id = 'core:message.changed'
            and projection_event.change_ids ? dispatch_change.id
            and projection_event.subjects @> jsonb_build_array(
              jsonb_build_object(
                'tenantId', dispatch_change.tenant_id,
                'entityTypeId', 'core:message',
                'entityId', dispatch_row.message_id
              )
            )
       ) <> 1
     );
  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_atomic_outbound_dispatch_materializations
      materialization_row
    left join public.inbox_v2_outbound_dispatches dispatch_row
      on dispatch_row.tenant_id = materialization_row.tenant_id
     and dispatch_row.id = materialization_row.dispatch_id
   where materialization_row.tenant_id = new.tenant_id
     and materialization_row.stream_commit_id = new.stream_commit_id
     and materialization_row.mutation_id = new.mutation_id
     and materialization_row.stream_position = v_stream.position
     and (
       materialization_row.resulting_revision <> 1
       or materialization_row.created_at <> new.committed_at
       or dispatch_row.id is null
       or dispatch_row.state <> 'queued'
       or dispatch_row.attempt_count <> 0
       or dispatch_row.active_attempt_id is not null
       or dispatch_row.last_attempt_id is not null
       or dispatch_row.retry_authorization_decision_id is not null
       or dispatch_row.revision <> materialization_row.resulting_revision
       or dispatch_row.created_at <> new.committed_at
       or dispatch_row.updated_at <> new.committed_at
       or exists (
         select 1
           from public.inbox_v2_outbound_dispatch_attempts attempt_row
          where attempt_row.tenant_id = materialization_row.tenant_id
            and attempt_row.dispatch_id = materialization_row.dispatch_id
       )
       or not exists (
         select 1
           from public.inbox_v2_tenant_stream_changes dispatch_change
          where dispatch_change.tenant_id = materialization_row.tenant_id
            and dispatch_change.stream_commit_id =
              materialization_row.stream_commit_id
            and dispatch_change.mutation_id = materialization_row.mutation_id
            and dispatch_change.stream_position =
              materialization_row.stream_position
            and dispatch_change.entity_type_id = 'core:outbound-dispatch'
            and dispatch_change.entity_id = materialization_row.dispatch_id
            and dispatch_change.resulting_revision =
              materialization_row.resulting_revision
       )
     );

  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_tenant_stream_changes message_change
    left join public.inbox_v2_messages message_row
      on message_row.tenant_id = message_change.tenant_id
     and message_row.id = message_change.entity_id
    left join public.inbox_v2_timeline_items timeline_row
      on timeline_row.tenant_id = message_row.tenant_id
     and timeline_row.id = message_row.timeline_item_id
    left join public.inbox_v2_timeline_contents content_row
      on content_row.tenant_id = message_row.tenant_id
     and content_row.id = message_row.content_id
    left join public.inbox_v2_timeline_content_revisions
      content_revision_row
      on content_revision_row.tenant_id = content_row.tenant_id
     and content_revision_row.content_id = content_row.id
     and content_revision_row.revision = content_row.revision
    left join public.inbox_v2_message_revisions initial_revision_row
      on initial_revision_row.tenant_id = message_change.tenant_id
     and initial_revision_row.id =
       message_change.domain_commit_reference->>'recordId'
   where message_change.tenant_id = new.tenant_id
     and message_change.stream_commit_id = new.stream_commit_id
     and message_change.mutation_id = new.mutation_id
     and message_change.entity_type_id = 'core:message'
     and v_command.command_type_id not in (
       'core:attachment.materialization.complete',
       'core:message.edit',
       'core:message.delete_local',
       'core:message.delete_provider'
     )
     and (
       message_change.resulting_revision <> 1
       or message_change.state_kind <> 'upsert'
       or message_change.state_schema_id is distinct from
          'core:inbox-v2.message'
       or message_change.state_schema_version is distinct from 'v1'
       or message_change.payload_reference->>'tenantId' is distinct from
          message_change.tenant_id
       or message_change.payload_reference->>'recordId' is distinct from
          message_change.entity_id
       or message_change.payload_reference->>'schemaId' is distinct from
          'core:inbox-v2.message'
       or message_change.payload_reference->>'schemaVersion' is distinct from
          'v1'
       or message_change.payload_reference is distinct from
          v_command.result_reference
       or message_change.state_hash is distinct from
          message_change.payload_reference->>'digest'
       or message_change.domain_commit_reference->>'tenantId' is distinct from
          message_change.tenant_id
       or message_change.domain_commit_reference->>'schemaId' is distinct from
          'core:inbox-v2.message-creation-commit'
       or message_change.domain_commit_reference->>'schemaVersion' is distinct
          from 'v1'
       or (
         v_command.command_type_id <> 'core:source.dispatch.reroute'
         and v_audit.evidence_reference is distinct from
            message_change.domain_commit_reference
       )
       or message_change.audience not in (
         'conversation_external', 'internal_participants'
       )
       or message_row.id is null
       or message_row.revision <> message_change.resulting_revision
       or message_row.last_changed_stream_position <>
          message_change.stream_position
       or message_row.created_at <> new.committed_at
       or message_row.updated_at <> new.committed_at
       or timeline_row.id is null
       or timeline_row.subject_kind <> 'message'
       or timeline_row.subject_id <> message_row.id
       or timeline_row.conversation_id <> message_row.conversation_id
       or timeline_row.revision <> message_row.revision
       or timeline_row.visibility::text <> message_change.audience::text
       or timeline_row.last_changed_stream_position <>
          message_change.stream_position
       or timeline_row.created_at <> new.committed_at
       or timeline_row.updated_at <> new.committed_at
       or content_row.id is null
       or content_row.owner_kind <> 'message'
       or content_row.owner_id <> message_row.id
       or content_row.revision <> message_row.content_revision
       or content_row.state <> message_row.content_state
       or content_row.last_changed_stream_position <>
          message_change.stream_position
       or content_row.created_at <> new.committed_at
       or content_row.updated_at <> new.committed_at
       or content_revision_row.content_id is null
       or content_revision_row.revision <> 1
       or content_revision_row.transition_kind <> 'created'
       or content_revision_row.expected_previous_revision is not null
       or content_revision_row.recorded_stream_position <>
          message_change.stream_position
       or content_revision_row.recorded_at <> new.committed_at
       or message_change.timeline is distinct from jsonb_build_object(
         'conversation', jsonb_build_object(
           'tenantId', message_row.tenant_id,
           'id', message_row.conversation_id,
           'kind', 'conversation'
         ),
         'timelineSequence', timeline_row.timeline_sequence::text
       )
       or initial_revision_row.id is null
       or initial_revision_row.message_id <> message_row.id
       or initial_revision_row.timeline_item_id <> message_row.timeline_item_id
       or initial_revision_row.message_revision <> 1
       or initial_revision_row.change_kind <> 'created'
       or initial_revision_row.expected_previous_revision is not null
       or initial_revision_row.recorded_stream_position <>
          message_change.stream_position
       or initial_revision_row.recorded_at <> new.committed_at
       or (
         select count(*)
           from public.inbox_v2_domain_events message_event
          where message_event.tenant_id = message_change.tenant_id
            and message_event.stream_commit_id =
              message_change.stream_commit_id
            and message_event.mutation_id = message_change.mutation_id
            and message_event.type_id = 'core:message.changed'
            and message_event.payload_schema_id =
              message_change.domain_commit_reference->>'schemaId'
            and message_event.payload_schema_version =
              message_change.domain_commit_reference->>'schemaVersion'
            and message_event.payload_reference =
              message_change.domain_commit_reference
            and message_event.change_ids ? message_change.id
            and message_event.subjects @> jsonb_build_array(
              jsonb_build_object(
                'tenantId', message_change.tenant_id,
                'entityTypeId', 'core:message',
                'entityId', message_change.entity_id
              )
            )
            and message_event.occurred_at = initial_revision_row.occurred_at
            and message_event.recorded_at = new.committed_at
       ) <> 1
       or (
         select count(*)
           from public.inbox_v2_domain_events related_event
          where related_event.tenant_id = message_change.tenant_id
            and related_event.stream_commit_id =
              message_change.stream_commit_id
            and related_event.mutation_id = message_change.mutation_id
            and (
              related_event.change_ids ? message_change.id
              or related_event.subjects @> jsonb_build_array(
                jsonb_build_object(
                  'tenantId', message_change.tenant_id,
                  'entityTypeId', 'core:message',
                  'entityId', message_change.entity_id
                )
              )
            )
       ) <> 1
       or (
         select count(*)
           from public.inbox_v2_outbox_intents projection_intent
           join public.inbox_v2_domain_events projection_event
             on projection_event.tenant_id = projection_intent.tenant_id
            and projection_event.id = projection_intent.event_id
          where projection_intent.tenant_id = message_change.tenant_id
            and projection_intent.stream_commit_id =
              message_change.stream_commit_id
            and projection_intent.mutation_id = message_change.mutation_id
            and projection_intent.effect_class = 'projection'
            and projection_intent.type_id = 'core:projection.update'
            and projection_intent.change_ids ? message_change.id
            and projection_event.stream_commit_id =
              message_change.stream_commit_id
            and projection_event.mutation_id = message_change.mutation_id
            and projection_event.type_id = 'core:message.changed'
            and projection_event.change_ids ? message_change.id
       ) <> 1
       or (message_row.origin_kind = 'source_originated' and (
         select count(*)
           from public.inbox_v2_atomic_source_resolution_materializations
             source_materialization
          where source_materialization.tenant_id = message_change.tenant_id
            and source_materialization.message_id = message_change.entity_id
            and source_materialization.mutation_id = message_change.mutation_id
            and source_materialization.stream_commit_id =
              message_change.stream_commit_id
            and source_materialization.stream_position =
              message_change.stream_position
       ) <> 1)
       or (message_row.origin_kind <> 'source_originated' and exists (
         select 1
           from public.inbox_v2_atomic_source_resolution_materializations
             source_materialization
          where source_materialization.tenant_id = message_change.tenant_id
            and source_materialization.message_id = message_change.entity_id
            and source_materialization.mutation_id = message_change.mutation_id
            and source_materialization.stream_commit_id =
              message_change.stream_commit_id
       ))
     );

  -- Message lifecycle commands advance an existing Message aggregate. They
  -- must not pass through the revision-1 creation validator above: the exact
  -- Message revision, current heads, event and projection are closed here.
  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_tenant_stream_changes message_change
    left join public.inbox_v2_messages message_row
      on message_row.tenant_id = message_change.tenant_id
     and message_row.id = message_change.entity_id
    left join public.inbox_v2_timeline_items timeline_row
      on timeline_row.tenant_id = message_row.tenant_id
     and timeline_row.id = message_row.timeline_item_id
    left join public.inbox_v2_message_revisions lifecycle_revision_row
      on lifecycle_revision_row.tenant_id = message_change.tenant_id
     and lifecycle_revision_row.id =
       message_change.domain_commit_reference->>'recordId'
    left join public.inbox_v2_timeline_contents content_row
      on content_row.tenant_id = message_row.tenant_id
     and content_row.id = message_row.content_id
    left join public.inbox_v2_timeline_content_revisions
      content_revision_row
      on content_revision_row.tenant_id = content_row.tenant_id
     and content_revision_row.content_id = content_row.id
     and content_revision_row.revision = content_row.revision
   where message_change.tenant_id = new.tenant_id
     and message_change.stream_commit_id = new.stream_commit_id
     and message_change.mutation_id = new.mutation_id
     and message_change.entity_type_id = 'core:message'
     and v_command.command_type_id in (
       'core:message.edit',
       'core:message.delete_local'
     )
     and (
       message_change.resulting_revision < 2
       or message_change.state_kind <> 'upsert'
       or message_change.state_schema_id is distinct from
          'core:inbox-v2.message'
       or message_change.state_schema_version is distinct from 'v1'
       or message_change.payload_reference->>'tenantId' is distinct from
          message_change.tenant_id
       or message_change.payload_reference->>'recordId' is distinct from
          message_change.entity_id
       or message_change.payload_reference->>'schemaId' is distinct from
          'core:inbox-v2.message'
       or message_change.payload_reference->>'schemaVersion' is distinct from
          'v1'
       or message_change.payload_reference is distinct from
          v_command.result_reference
       or message_change.state_hash is distinct from
          message_change.payload_reference->>'digest'
       or message_change.domain_commit_reference->>'tenantId' is distinct from
          message_change.tenant_id
       or message_change.domain_commit_reference->>'schemaId' is distinct from
          'core:inbox-v2.message-revision'
       or message_change.domain_commit_reference->>'schemaVersion' is distinct
          from 'v1'
       or v_audit.evidence_reference is distinct from
          message_change.domain_commit_reference
       or message_change.audience not in (
         'conversation_external', 'internal_participants'
       )
       or message_row.id is null
       or message_row.revision <> message_change.resulting_revision
       or message_row.last_changed_stream_position <>
          message_change.stream_position
       or message_row.updated_at <> new.committed_at
       or timeline_row.id is null
       or timeline_row.subject_kind <> 'message'
       or timeline_row.subject_id <> message_row.id
       or timeline_row.conversation_id <> message_row.conversation_id
       or timeline_row.revision <> message_row.revision
       or timeline_row.visibility::text <> message_change.audience::text
       or timeline_row.last_changed_stream_position <>
          message_change.stream_position
       or timeline_row.updated_at <> new.committed_at
       or message_change.timeline is distinct from jsonb_build_object(
         'conversation', jsonb_build_object(
           'tenantId', message_row.tenant_id,
           'id', message_row.conversation_id,
           'kind', 'conversation'
         ),
         'timelineSequence', timeline_row.timeline_sequence::text
       )
       or lifecycle_revision_row.id is null
       or lifecycle_revision_row.message_id <> message_row.id
       or lifecycle_revision_row.timeline_item_id <> message_row.timeline_item_id
       or lifecycle_revision_row.message_revision <>
          message_change.resulting_revision
       or lifecycle_revision_row.expected_previous_revision <>
          message_change.resulting_revision - 1
       or lifecycle_revision_row.recorded_stream_position <>
          message_change.stream_position
       or lifecycle_revision_row.recorded_at <> new.committed_at
       or lifecycle_revision_row.record_revision <> 1
       or (
         v_command.command_type_id = 'core:message.edit'
         and (
           lifecycle_revision_row.change_kind <> 'edited'
           or lifecycle_revision_row.after_content_id is distinct from
              message_row.content_id
           or lifecycle_revision_row.after_content_revision is distinct from
              message_row.content_revision
           or lifecycle_revision_row.after_content_state::text is distinct from
              message_row.content_state::text
           or lifecycle_revision_row.before_content_id is null
           or lifecycle_revision_row.before_content_revision is null
           or lifecycle_revision_row.before_content_state is null
           or lifecycle_revision_row.reason_id is not null
           or message_row.lifecycle <> 'active'
           or content_row.id is null
           or content_row.owner_kind <> 'message'
           or content_row.owner_id <> message_row.id
           or content_row.revision <> message_row.content_revision
           or content_row.state <> message_row.content_state
           or content_row.last_changed_stream_position <>
              message_change.stream_position
           or content_row.updated_at <> new.committed_at
           or content_revision_row.content_id is null
           or content_revision_row.transition_kind <> 'edit'
           or content_revision_row.expected_previous_revision <>
              content_revision_row.revision - 1
           or content_revision_row.recorded_stream_position <>
              message_change.stream_position
           or content_revision_row.occurred_at <>
              lifecycle_revision_row.occurred_at
           or content_revision_row.recorded_at <> new.committed_at
           or (
             select count(*)
               from public.inbox_v2_tenant_stream_changes operation_change
              where operation_change.tenant_id = message_change.tenant_id
                and operation_change.stream_commit_id =
                  message_change.stream_commit_id
                and operation_change.mutation_id = message_change.mutation_id
                and operation_change.entity_type_id =
                  'core:message-provider-lifecycle-operation'
                and operation_change.entity_id =
                  lifecycle_revision_row.provider_operation_id
           ) <> case
             when lifecycle_revision_row.provider_operation_id is null then 0
             else 1
           end
         )
       )
       or (
         v_command.command_type_id = 'core:message.delete_local'
         and (
           lifecycle_revision_row.change_kind <>
             'local_delete_tombstone'
           or lifecycle_revision_row.provider_operation_id is not null
           or lifecycle_revision_row.reason_id is distinct from
              v_audit.reason_code_id
           or num_nonnulls(
             lifecycle_revision_row.before_content_id,
             lifecycle_revision_row.before_content_revision,
             lifecycle_revision_row.before_content_state,
             lifecycle_revision_row.after_content_id,
             lifecycle_revision_row.after_content_revision,
             lifecycle_revision_row.after_content_state
           ) <> 0
           or message_row.lifecycle <> 'local_delete_tombstone'
           or message_row.lifecycle_revision_id is distinct from
              lifecycle_revision_row.id
           or message_row.lifecycle_reason_id is distinct from
              lifecycle_revision_row.reason_id
           or exists (
             select 1
               from public.inbox_v2_tenant_stream_changes operation_change
              where operation_change.tenant_id = message_change.tenant_id
                and operation_change.stream_commit_id =
                  message_change.stream_commit_id
                and operation_change.mutation_id = message_change.mutation_id
                and operation_change.entity_type_id =
                  'core:message-provider-lifecycle-operation'
           )
         )
       )
       or (
         select count(*)
           from public.inbox_v2_domain_events message_event
          where message_event.tenant_id = message_change.tenant_id
            and message_event.stream_commit_id =
              message_change.stream_commit_id
            and message_event.mutation_id = message_change.mutation_id
            and message_event.type_id = 'core:message.changed'
            and message_event.payload_schema_id =
              message_change.domain_commit_reference->>'schemaId'
            and message_event.payload_schema_version =
              message_change.domain_commit_reference->>'schemaVersion'
            and message_event.payload_reference =
              message_change.domain_commit_reference
            and message_event.change_ids ? message_change.id
            and message_event.subjects @> jsonb_build_array(
              jsonb_build_object(
                'tenantId', message_change.tenant_id,
                'entityTypeId', 'core:message',
                'entityId', message_change.entity_id
              )
            )
            and message_event.occurred_at =
              lifecycle_revision_row.occurred_at
            and message_event.recorded_at = new.committed_at
       ) <> 1
       or (
         select count(*)
           from public.inbox_v2_domain_events related_event
          where related_event.tenant_id = message_change.tenant_id
            and related_event.stream_commit_id =
              message_change.stream_commit_id
            and related_event.mutation_id = message_change.mutation_id
            and (
              related_event.change_ids ? message_change.id
              or related_event.subjects @> jsonb_build_array(
                jsonb_build_object(
                  'tenantId', message_change.tenant_id,
                  'entityTypeId', 'core:message',
                  'entityId', message_change.entity_id
                )
              )
            )
       ) <> 1
       or (
         select count(*)
           from public.inbox_v2_outbox_intents projection_intent
           join public.inbox_v2_domain_events projection_event
             on projection_event.tenant_id = projection_intent.tenant_id
            and projection_event.id = projection_intent.event_id
          where projection_intent.tenant_id = message_change.tenant_id
            and projection_intent.stream_commit_id =
              message_change.stream_commit_id
            and projection_intent.mutation_id = message_change.mutation_id
            and projection_intent.effect_class = 'projection'
            and projection_intent.type_id = 'core:projection.update'
            and projection_intent.change_ids ? message_change.id
            and projection_event.stream_commit_id =
              message_change.stream_commit_id
            and projection_event.mutation_id = message_change.mutation_id
            and projection_event.type_id = 'core:message.changed'
            and projection_event.change_ids ? message_change.id
       ) <> 1
       or exists (
         select 1
           from public.inbox_v2_atomic_source_resolution_materializations
             source_materialization
          where source_materialization.tenant_id = message_change.tenant_id
            and source_materialization.message_id = message_change.entity_id
            and source_materialization.mutation_id = message_change.mutation_id
            and source_materialization.stream_commit_id =
              message_change.stream_commit_id
       )
     );

  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_tenant_stream_changes message_change
   where message_change.tenant_id = new.tenant_id
     and message_change.stream_commit_id = new.stream_commit_id
     and message_change.mutation_id = new.mutation_id
     and message_change.entity_type_id = 'core:message'
     and v_command.command_type_id =
       'core:attachment.materialization.complete'
     and not public.inbox_v2_auth_attachment_message_change_valid(
       message_change.tenant_id,
       message_change.stream_commit_id,
       message_change.mutation_id,
       message_change.id,
       message_change.stream_position,
       new.committed_at,
       v_command.actor_trusted_service_id,
       v_stream.correlation_id,
       v_command.result_reference,
       v_audit.evidence_reference,
       v_audit.revision_delta_hash
     );

  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_tenant_stream_changes occurrence_change
    left join public.inbox_v2_atomic_source_resolution_materializations
      source_materialization
      on source_materialization.tenant_id = occurrence_change.tenant_id
     and source_materialization.source_occurrence_id =
       occurrence_change.entity_id
     and source_materialization.mutation_id = occurrence_change.mutation_id
     and source_materialization.stream_commit_id =
       occurrence_change.stream_commit_id
     and source_materialization.stream_position =
       occurrence_change.stream_position
    left join public.inbox_v2_source_occurrences occurrence_row
      on occurrence_row.tenant_id = occurrence_change.tenant_id
     and occurrence_row.id = occurrence_change.entity_id
    left join public.inbox_v2_source_occurrence_resolution_transitions
      transition_row
      on transition_row.tenant_id = source_materialization.tenant_id
     and transition_row.id = source_materialization.resolution_transition_id
    left join public.inbox_v2_external_message_references reference_row
      on reference_row.tenant_id = source_materialization.tenant_id
     and reference_row.id =
       source_materialization.external_message_reference_id
    left join public.inbox_v2_messages message_row
      on message_row.tenant_id = source_materialization.tenant_id
     and message_row.id = source_materialization.message_id
   where occurrence_change.tenant_id = new.tenant_id
     and occurrence_change.stream_commit_id = new.stream_commit_id
     and occurrence_change.mutation_id = new.mutation_id
     and occurrence_change.entity_type_id = 'core:source-occurrence'
     and (
       occurrence_change.state_kind <> 'upsert'
       or occurrence_change.state_schema_id is distinct from
          'core:inbox-v2.source-occurrence'
       or occurrence_change.state_schema_version is distinct from 'v1'
       or occurrence_change.timeline is not null
       or occurrence_change.audience <> 'policy_filtered'
       or occurrence_change.payload_reference->>'tenantId' is distinct from
          occurrence_change.tenant_id
       or occurrence_change.payload_reference->>'recordId' is distinct from
          occurrence_change.entity_id
       or occurrence_change.payload_reference->>'schemaId' is distinct from
          'core:inbox-v2.source-occurrence'
       or occurrence_change.payload_reference->>'schemaVersion' is distinct
          from 'v1'
       or occurrence_change.state_hash is distinct from
          occurrence_change.payload_reference->>'digest'
       or occurrence_change.domain_commit_reference->>'tenantId' is distinct
          from occurrence_change.tenant_id
       or occurrence_change.domain_commit_reference->>'schemaId' is distinct
          from 'core:inbox-v2.source-occurrence-resolution-commit'
       or occurrence_change.domain_commit_reference->>'schemaVersion' is
          distinct from 'v1'
       or source_materialization.source_occurrence_id is null
       or source_materialization.resulting_revision is distinct from
          occurrence_change.resulting_revision
       or source_materialization.created_at <> new.committed_at
       or source_materialization.resolution_transition_id is distinct from
          occurrence_change.domain_commit_reference->>'recordId'
       or occurrence_row.id is null
       or occurrence_row.revision <> occurrence_change.resulting_revision
       or occurrence_row.resolution_state <> 'resolved'
       or occurrence_row.resolved_external_message_reference_id is distinct
          from source_materialization.external_message_reference_id
       or occurrence_row.updated_at <> new.committed_at
       or transition_row.id is null
       or transition_row.source_occurrence_id <> occurrence_row.id
       or transition_row.resulting_revision <>
          source_materialization.resulting_revision
       or transition_row.to_state <> 'resolved'
       or transition_row.resolved_external_message_reference_id is distinct
          from source_materialization.external_message_reference_id
       or transition_row.changed_at <> new.committed_at
       or reference_row.id is null
       or reference_row.message_id <> source_materialization.message_id
       or message_row.id is null
       or message_row.origin_kind <> 'source_originated'
       or message_row.origin_source_occurrence_id <> occurrence_row.id
       or message_row.revision <> 1
       or message_row.last_changed_stream_position <>
          occurrence_change.stream_position
       or message_row.created_at <> new.committed_at
       or (
         select count(*)
           from public.inbox_v2_domain_events occurrence_event
          where occurrence_event.tenant_id = occurrence_change.tenant_id
            and occurrence_event.stream_commit_id =
              occurrence_change.stream_commit_id
            and occurrence_event.mutation_id = occurrence_change.mutation_id
            and occurrence_event.type_id = 'core:source-occurrence.changed'
            and occurrence_event.payload_schema_id =
              occurrence_change.domain_commit_reference->>'schemaId'
            and occurrence_event.payload_schema_version =
              occurrence_change.domain_commit_reference->>'schemaVersion'
            and occurrence_event.payload_reference =
              occurrence_change.domain_commit_reference
            and occurrence_event.change_ids ? occurrence_change.id
            and occurrence_event.subjects @> jsonb_build_array(
              jsonb_build_object(
                'tenantId', occurrence_change.tenant_id,
                'entityTypeId', 'core:source-occurrence',
                'entityId', occurrence_change.entity_id
              )
            )
            and occurrence_event.occurred_at = transition_row.changed_at
            and occurrence_event.recorded_at = new.committed_at
       ) <> 1
       or (
         select count(*)
           from public.inbox_v2_domain_events related_event
          where related_event.tenant_id = occurrence_change.tenant_id
            and related_event.stream_commit_id =
              occurrence_change.stream_commit_id
            and related_event.mutation_id = occurrence_change.mutation_id
            and (
              related_event.change_ids ? occurrence_change.id
              or related_event.subjects @> jsonb_build_array(
                jsonb_build_object(
                  'tenantId', occurrence_change.tenant_id,
                  'entityTypeId', 'core:source-occurrence',
                  'entityId', occurrence_change.entity_id
                )
              )
            )
       ) <> 1
       or (
         select count(*)
           from public.inbox_v2_outbox_intents projection_intent
           join public.inbox_v2_domain_events projection_event
             on projection_event.tenant_id = projection_intent.tenant_id
            and projection_event.id = projection_intent.event_id
          where projection_intent.tenant_id = occurrence_change.tenant_id
            and projection_intent.stream_commit_id =
              occurrence_change.stream_commit_id
            and projection_intent.mutation_id = occurrence_change.mutation_id
            and projection_intent.effect_class = 'projection'
            and projection_intent.type_id = 'core:projection.update'
            and projection_intent.change_ids ? occurrence_change.id
            and projection_event.stream_commit_id =
              occurrence_change.stream_commit_id
            and projection_event.mutation_id = occurrence_change.mutation_id
            and projection_event.type_id = 'core:source-occurrence.changed'
            and projection_event.change_ids ? occurrence_change.id
       ) <> 1
     );

  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_atomic_source_resolution_materializations
      source_materialization
    left join public.inbox_v2_source_occurrences occurrence_row
      on occurrence_row.tenant_id = source_materialization.tenant_id
     and occurrence_row.id = source_materialization.source_occurrence_id
    left join public.inbox_v2_source_occurrence_resolution_transitions
      transition_row
      on transition_row.tenant_id = source_materialization.tenant_id
     and transition_row.id = source_materialization.resolution_transition_id
   where source_materialization.tenant_id = new.tenant_id
     and source_materialization.stream_commit_id = new.stream_commit_id
     and source_materialization.mutation_id = new.mutation_id
     and source_materialization.stream_position = v_stream.position
     and (
       source_materialization.resulting_revision < 2
       or source_materialization.created_at <> new.committed_at
       or occurrence_row.id is null
       or occurrence_row.revision <> source_materialization.resulting_revision
       or occurrence_row.resolution_state <> 'resolved'
       or occurrence_row.resolved_external_message_reference_id is distinct
          from source_materialization.external_message_reference_id
       or occurrence_row.updated_at <> new.committed_at
       or transition_row.id is null
       or transition_row.source_occurrence_id <>
          source_materialization.source_occurrence_id
       or transition_row.resulting_revision <>
          source_materialization.resulting_revision
       or transition_row.resolved_external_message_reference_id is distinct
          from source_materialization.external_message_reference_id
       or transition_row.changed_at <> new.committed_at
       or (
         select count(*)
           from public.inbox_v2_tenant_stream_changes occurrence_change
          where occurrence_change.tenant_id = source_materialization.tenant_id
            and occurrence_change.stream_commit_id =
              source_materialization.stream_commit_id
            and occurrence_change.mutation_id = source_materialization.mutation_id
            and occurrence_change.stream_position =
              source_materialization.stream_position
            and occurrence_change.entity_type_id = 'core:source-occurrence'
            and occurrence_change.entity_id =
              source_materialization.source_occurrence_id
            and occurrence_change.resulting_revision =
              source_materialization.resulting_revision
       ) <> 1
     );

  if v_command.command_type_id in (
    'core:message.send',
    'core:message.receive',
    'core:source.dispatch.reroute'
  )
  then
    select count(*)::integer into v_message_change_count
      from public.inbox_v2_tenant_stream_changes message_change
     where message_change.tenant_id = new.tenant_id
       and message_change.stream_commit_id = new.stream_commit_id
       and message_change.mutation_id = new.mutation_id
       and message_change.stream_position = v_stream.position
       and message_change.entity_type_id = 'core:message';
    select count(*)::integer into v_message_row_count
      from public.inbox_v2_messages message_row
     where message_row.tenant_id = new.tenant_id
       and message_row.revision = 1
       and message_row.last_changed_stream_position = v_stream.position
       and message_row.created_at = new.committed_at
       and message_row.updated_at = new.committed_at;
    select count(*)::integer into v_source_change_count
      from public.inbox_v2_tenant_stream_changes occurrence_change
     where occurrence_change.tenant_id = new.tenant_id
       and occurrence_change.stream_commit_id = new.stream_commit_id
       and occurrence_change.mutation_id = new.mutation_id
       and occurrence_change.stream_position = v_stream.position
       and occurrence_change.entity_type_id = 'core:source-occurrence';
    select count(*)::integer into v_source_materialization_count
      from public.inbox_v2_atomic_source_resolution_materializations
        source_materialization
     where source_materialization.tenant_id = new.tenant_id
       and source_materialization.stream_commit_id = new.stream_commit_id
       and source_materialization.mutation_id = new.mutation_id
       and source_materialization.stream_position = v_stream.position;

    if v_message_change_count <> 1
       or v_message_row_count <> 1
       or (
         v_command.command_type_id = 'core:message.receive'
         and (
           v_source_change_count <> 1
           or v_source_materialization_count <> 1
         )
       )
       or (
         v_command.command_type_id in (
           'core:message.send',
           'core:source.dispatch.reroute'
         )
         and (
           v_source_change_count <> 0
           or v_source_materialization_count <> 0
         )
       ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.domain_mutation_message_cardinality_invalid';
    end if;
  end if;

  if v_command.command_type_id in (
    'core:message.edit',
    'core:message.delete_local',
    'core:message.delete_provider'
  ) then
    select count(*)::integer into v_message_change_count
      from public.inbox_v2_tenant_stream_changes message_change
     where message_change.tenant_id = new.tenant_id
       and message_change.stream_commit_id = new.stream_commit_id
       and message_change.mutation_id = new.mutation_id
       and message_change.stream_position = v_stream.position
       and message_change.entity_type_id = 'core:message';
    select count(*)::integer into v_provider_operation_change_count
      from public.inbox_v2_tenant_stream_changes operation_change
     where operation_change.tenant_id = new.tenant_id
       and operation_change.stream_commit_id = new.stream_commit_id
       and operation_change.mutation_id = new.mutation_id
       and operation_change.stream_position = v_stream.position
       and operation_change.entity_type_id =
         'core:message-provider-lifecycle-operation';

    if v_event_count <> 1
       or v_projection_count <> 1
       or (
         v_command.command_type_id = 'core:message.edit'
         and (
           v_message_change_count <> 1
           or v_provider_operation_change_count not in (0, 1)
           or v_change_count <>
              1 + v_provider_operation_change_count
           or v_outbox_count <>
              1 + v_provider_operation_change_count
         )
       )
       or (
         v_command.command_type_id = 'core:message.delete_local'
         and (
           v_message_change_count <> 1
           or v_provider_operation_change_count <> 0
           or v_change_count <> 1
           or v_outbox_count <> 1
         )
       )
       or (
         v_command.command_type_id = 'core:message.delete_provider'
         and (
           v_message_change_count <> 0
           or v_provider_operation_change_count <> 1
           or v_change_count <> 1
           or v_outbox_count <> 2
         )
       ) then
      raise exception using errcode = '23514',
        message =
          'inbox_v2.domain_mutation_message_lifecycle_cardinality_invalid';
    end if;
  end if;

  if v_command.command_type_id =
     'core:attachment.materialization.complete' then
    select count(*)::integer into v_message_change_count
      from public.inbox_v2_tenant_stream_changes message_change
     where message_change.tenant_id = new.tenant_id
       and message_change.stream_commit_id = new.stream_commit_id
       and message_change.mutation_id = new.mutation_id
       and message_change.stream_position = v_stream.position
       and message_change.entity_type_id = 'core:message';
    select count(*)::integer into v_message_row_count
      from public.inbox_v2_tenant_stream_changes message_change
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = message_change.tenant_id
       and message_row.id = message_change.entity_id
     where message_change.tenant_id = new.tenant_id
       and message_change.stream_commit_id = new.stream_commit_id
       and message_change.mutation_id = new.mutation_id
       and message_change.stream_position = v_stream.position
       and message_change.entity_type_id = 'core:message'
       and message_row.revision = message_change.resulting_revision
       and message_row.revision >= 2
       and message_row.last_changed_stream_position = v_stream.position
       and message_row.updated_at = new.committed_at;
    select count(*)::integer into v_source_change_count
      from public.inbox_v2_tenant_stream_changes occurrence_change
     where occurrence_change.tenant_id = new.tenant_id
       and occurrence_change.stream_commit_id = new.stream_commit_id
       and occurrence_change.mutation_id = new.mutation_id
       and occurrence_change.stream_position = v_stream.position
       and occurrence_change.entity_type_id = 'core:source-occurrence';
    select count(*)::integer into v_source_materialization_count
      from public.inbox_v2_atomic_source_resolution_materializations
        source_materialization
     where source_materialization.tenant_id = new.tenant_id
       and source_materialization.stream_commit_id = new.stream_commit_id
       and source_materialization.mutation_id = new.mutation_id
       and source_materialization.stream_position = v_stream.position;

    if v_message_change_count <> 1
       or v_message_row_count <> 1
       or v_source_change_count <> 0
       or v_source_materialization_count <> 0
       or v_change_count <> 1
       or v_event_count <> 1
       or v_outbox_count <> 1
       or v_projection_count <> 1 then
      raise exception using errcode = '23514',
        message =
          'inbox_v2.domain_mutation_attachment_cardinality_invalid';
    end if;
  end if;

  if v_invalid_count <> 0 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_stream_child_mismatch';
  end if;

  select 'sha256:' || encode(sha256(convert_to(coalesce(string_agg(
           manifest_row.item_hash,
           chr(10) order by manifest_row.kind_ordinal, manifest_row.ordinal
         ), ''), 'UTF8')), 'hex')
    into v_stream_manifest_digest
    from (
      select 1 as kind_ordinal, change_row.ordinal,
             'change:' || change_row.state_hash as item_hash
        from public.inbox_v2_tenant_stream_changes change_row
       where change_row.tenant_id = new.tenant_id
         and change_row.stream_commit_id = new.stream_commit_id
      union all
      select 2, event_row.ordinal, 'event:' || event_row.event_hash
        from public.inbox_v2_domain_events event_row
       where event_row.tenant_id = new.tenant_id
         and event_row.stream_commit_id = new.stream_commit_id
      union all
      select 3, intent_row.ordinal, 'intent:' || intent_row.intent_hash
        from public.inbox_v2_outbox_intents intent_row
       where intent_row.tenant_id = new.tenant_id
         and intent_row.stream_commit_id = new.stream_commit_id
    ) manifest_row;
  if v_stream_manifest_digest <> v_stream.manifest_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_stream_digest_mismatch';
  end if;

  if exists (
       select 1 from public.inbox_v2_auth_revision_effects effect_row
        where effect_row.tenant_id = new.tenant_id
          and effect_row.mutation_id = new.mutation_id
     )
     or exists (
       select 1 from public.inbox_v2_auth_relation_writes write_row
        where write_row.tenant_id = new.tenant_id
          and write_row.mutation_id = new.mutation_id
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_authorization_delta_forbidden';
  end if;

  select count(*)::integer,
         'sha256:' || encode(sha256(convert_to(coalesce(string_agg(
           facet_row.facet_hash, chr(10) order by facet_row.ordinal
         ), ''), 'UTF8')), 'hex')
    into v_facet_count, v_facet_digest
    from public.inbox_v2_auth_audit_facets facet_row
   where facet_row.tenant_id = new.tenant_id
     and facet_row.audit_event_id = new.audit_event_id;
  if row(v_facet_count, v_facet_digest)
       is distinct from
     row(v_audit.facet_count, v_audit.facets_digest_sha256)
     or (
       v_command.command_type_id <>
         'core:attachment.materialization.complete'
       and v_audit.revision_delta_hash <> v_empty_digest
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_audit_manifest_incomplete';
  end if;

  select stream_head.last_position = v_stream.position
         and stream_head.stream_epoch = v_stream.stream_epoch
         and stream_head.updated_at = new.committed_at
    into v_closed
    from public.inbox_v2_tenant_stream_heads stream_head
   where stream_head.tenant_id = new.tenant_id;
  if not coalesce(v_closed, false) then
    raise exception using errcode = '40001',
      message = 'inbox_v2.domain_mutation_stream_head_not_closed';
  end if;

  v_mutation_manifest_digest := 'sha256:' || encode(sha256(convert_to(
    'effects:' || v_empty_digest || chr(10) ||
    'relations:' || v_empty_digest || chr(10) ||
    'stream:' || v_stream.commit_hash || chr(10) ||
    'audit:' || v_audit.audit_hash,
    'UTF8'
  )), 'hex');
  if v_mutation_manifest_digest <> new.manifest_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_digest_mismatch';
  end if;
  return null;
exception
  when no_data_found or too_many_rows then
    raise exception using errcode = '23514',
      message = 'inbox_v2.domain_mutation_parent_incomplete';
end;
$$;



--
-- Name: inbox_v2_auth_head_commit_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_head_commit_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_closed boolean := false;
begin
  if tg_op = 'UPDATE' and tg_table_name = 'inbox_v2_auth_tenant_heads' then
    if new.tenant_rbac_revision = old.tenant_rbac_revision + 1 then
      select exists (
        select 1 from public.inbox_v2_auth_revision_effects effect_row
         where effect_row.tenant_id = new.tenant_id
           and effect_row.effect_kind = 'tenant_rbac'
           and effect_row.before_revision = old.tenant_rbac_revision
           and effect_row.after_revision = new.tenant_rbac_revision
           and effect_row.created_at = new.updated_at
      ) into v_closed;
    else
      select exists (
        select 1 from public.inbox_v2_auth_revision_effects effect_row
         where effect_row.tenant_id = new.tenant_id
           and effect_row.effect_kind = 'shared_access'
           and effect_row.before_revision = old.shared_access_revision
           and effect_row.after_revision = new.shared_access_revision
           and effect_row.created_at = new.updated_at
      ) into v_closed;
    end if;
  elsif tg_op = 'UPDATE' and tg_table_name = 'inbox_v2_auth_employee_heads' then
    select exists (
      select 1 from public.inbox_v2_auth_revision_effects effect_row
       where effect_row.tenant_id = new.tenant_id
         and effect_row.employee_id = new.employee_id
         and effect_row.effect_kind = case
           when new.employee_access_revision = old.employee_access_revision + 1
             then 'employee_access'::public.inbox_v2_auth_revision_effect_kind
           else 'employee_inbox_relation'::public.inbox_v2_auth_revision_effect_kind
         end
         and effect_row.before_revision = case
           when new.employee_access_revision = old.employee_access_revision + 1
             then old.employee_access_revision
           else old.employee_inbox_relation_revision
         end
         and effect_row.after_revision = case
           when new.employee_access_revision = old.employee_access_revision + 1
             then new.employee_access_revision
           else new.employee_inbox_relation_revision
         end
         and effect_row.created_at = new.updated_at
    ) into v_closed;
  elsif tg_op = 'UPDATE' and tg_table_name = 'inbox_v2_auth_resource_heads' then
    if new.resource_access_revision = old.resource_access_revision + 1 then
      select exists (
        select 1 from public.inbox_v2_auth_revision_effects effect_row
         where effect_row.tenant_id = new.tenant_id
           and effect_row.effect_kind = 'resource_access'
           and effect_row.resource_head_id = new.id
           and effect_row.before_revision = old.resource_access_revision
           and effect_row.after_revision = new.resource_access_revision
           and effect_row.created_at = new.updated_at
      ) into v_closed;
    else
      select exists (
        select 1 from public.inbox_v2_auth_revision_effects effect_row
         where effect_row.tenant_id = new.tenant_id
           and effect_row.effect_kind = 'collaborator_set'
           and effect_row.resource_head_id = new.id
           and effect_row.before_revision = old.collaborator_set_revision
           and effect_row.after_revision = new.collaborator_set_revision
           and effect_row.created_at = new.updated_at
      ) into v_closed;
    end if;
  elsif tg_table_name = 'inbox_v2_auth_role_heads' then
    select exists (
      select 1
        from public.inbox_v2_auth_role_versions version_row
        join public.inbox_v2_auth_relation_writes write_row
          on write_row.tenant_id = version_row.tenant_id
         and write_row.mutation_id = version_row.mutation_id
         and write_row.relation_kind = 'role'
         and write_row.role_id = version_row.role_id
         and write_row.resulting_revision = version_row.revision
       where version_row.tenant_id = new.tenant_id
         and version_row.role_id = new.role_id
         and version_row.revision = new.current_revision
    ) into v_closed;
  elsif tg_table_name = 'inbox_v2_auth_role_binding_heads' then
    select exists (
      select 1
        from public.inbox_v2_auth_role_binding_versions version_row
        join public.inbox_v2_auth_relation_writes write_row
          on write_row.tenant_id = version_row.tenant_id
         and write_row.mutation_id = version_row.mutation_id
         and write_row.relation_kind = 'role_binding'
         and write_row.role_binding_id = version_row.binding_id
         and write_row.resulting_revision = version_row.revision
       where version_row.tenant_id = new.tenant_id
         and version_row.binding_id = new.binding_id
         and version_row.revision = new.current_revision
    ) into v_closed;
  elsif tg_table_name = 'inbox_v2_auth_direct_grant_heads' then
    select exists (
      select 1
        from public.inbox_v2_auth_direct_grant_versions version_row
        join public.inbox_v2_auth_relation_writes write_row
          on write_row.tenant_id = version_row.tenant_id
         and write_row.mutation_id = version_row.mutation_id
         and write_row.relation_kind = 'direct_grant'
         and write_row.direct_grant_id = version_row.grant_id
         and write_row.resulting_revision = version_row.revision
       where version_row.tenant_id = new.tenant_id
         and version_row.grant_id = new.grant_id
         and version_row.revision = new.current_revision
    ) into v_closed;
  elsif tg_table_name = 'inbox_v2_auth_workforce_membership_heads' then
    select exists (
      select 1
        from public.inbox_v2_auth_workforce_membership_versions version_row
        join public.inbox_v2_auth_relation_writes write_row
          on write_row.tenant_id = version_row.tenant_id
         and write_row.mutation_id = version_row.mutation_id
         and write_row.relation_kind = 'workforce_membership'
         and write_row.workforce_membership_id = version_row.membership_id
         and write_row.resulting_revision = version_row.revision
       where version_row.tenant_id = new.tenant_id
         and version_row.membership_id = new.membership_id
         and version_row.revision = new.current_revision
    ) into v_closed;
  elsif tg_table_name = 'inbox_v2_auth_structural_access_heads' then
    select exists (
      select 1
        from public.inbox_v2_auth_structural_access_versions version_row
        join public.inbox_v2_auth_relation_writes write_row
          on write_row.tenant_id = version_row.tenant_id
         and write_row.mutation_id = version_row.mutation_id
         and write_row.relation_kind = 'structural_access'
         and write_row.structural_access_binding_id = version_row.binding_id
         and write_row.resulting_revision = version_row.revision
       where version_row.tenant_id = new.tenant_id
         and version_row.binding_id = new.binding_id
         and version_row.revision = new.current_revision
    ) into v_closed;
  elsif tg_table_name = 'inbox_v2_auth_collaborator_heads' then
    select exists (
      select 1
        from public.inbox_v2_auth_collaborator_versions version_row
        join public.inbox_v2_auth_relation_writes write_row
          on write_row.tenant_id = version_row.tenant_id
         and write_row.mutation_id = version_row.mutation_id
         and write_row.relation_kind = case version_row.resource_kind
           when 'conversation' then
             'conversation_collaborator'::public.inbox_v2_auth_relation_kind
           else 'work_item_collaborator'::public.inbox_v2_auth_relation_kind
         end
         and write_row.collaborator_id = version_row.collaborator_id
         and write_row.resulting_revision = version_row.revision
       where version_row.tenant_id = new.tenant_id
         and version_row.collaborator_id = new.collaborator_id
         and version_row.revision = new.current_revision
    ) into v_closed;
  else
    v_closed := tg_op = 'INSERT';
  end if;

  if not v_closed then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_head_commit_incomplete';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_auth_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_version_matches boolean := true;
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_head_delete_forbidden';
  end if;

  if tg_op = 'INSERT' then
    case tg_table_name
      when 'inbox_v2_auth_tenant_heads' then
        if new.revision <> 1 or new.tenant_rbac_revision <> 1
           or new.shared_access_revision <> 1 then
          raise exception using errcode = '23514',
            message = 'inbox_v2.authorization_head_initial_revision_invalid';
        end if;
      when 'inbox_v2_auth_employee_heads' then
        if new.revision <> 1 or new.employee_access_revision <> 1
           or new.employee_inbox_relation_revision <> 1 then
          raise exception using errcode = '23514',
            message = 'inbox_v2.authorization_head_initial_revision_invalid';
        end if;
      when 'inbox_v2_auth_resource_heads' then
        if new.revision <> 1 or new.resource_access_revision <> 1
           or new.structural_relation_revision <> 1
           or new.collaborator_set_revision <> 1 then
          raise exception using errcode = '23514',
            message = 'inbox_v2.authorization_head_initial_revision_invalid';
        end if;
      else
        if new.current_revision <> 1 then
          raise exception using errcode = '23514',
            message = 'inbox_v2.authorization_head_initial_revision_invalid';
        end if;
    end case;
  elsif new.tenant_id is distinct from old.tenant_id
     or new.created_at is distinct from old.created_at
     or new.updated_at < old.updated_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_head_identity_invalid';
  elsif tg_table_name = 'inbox_v2_auth_tenant_heads' then
    if new.revision <> old.revision + 1
       or new.tenant_rbac_revision not in (
         old.tenant_rbac_revision, old.tenant_rbac_revision + 1
       )
       or new.shared_access_revision not in (
         old.shared_access_revision, old.shared_access_revision + 1
       )
       or (new.tenant_rbac_revision - old.tenant_rbac_revision) +
          (new.shared_access_revision - old.shared_access_revision) <> 1 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_tenant_head_invalid_advance';
    end if;
  elsif tg_table_name = 'inbox_v2_auth_employee_heads' then
    if new.employee_id is distinct from old.employee_id
       or new.revision <> old.revision + 1
       or new.employee_access_revision not in (
         old.employee_access_revision, old.employee_access_revision + 1
       )
       or new.employee_inbox_relation_revision not in (
         old.employee_inbox_relation_revision,
         old.employee_inbox_relation_revision + 1
       )
       or (new.employee_access_revision - old.employee_access_revision) +
          (new.employee_inbox_relation_revision -
            old.employee_inbox_relation_revision) <> 1 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_employee_head_invalid_advance';
    end if;
  elsif tg_table_name = 'inbox_v2_auth_resource_heads' then
    if row(new.id, new.resource_kind, new.conversation_id, new.client_id,
           new.source_account_id) is distinct from
       row(old.id, old.resource_kind, old.conversation_id, old.client_id,
           old.source_account_id)
       or new.revision <> old.revision + 1
       or not (
         (new.resource_access_revision = old.resource_access_revision + 1
          and new.structural_relation_revision =
            old.structural_relation_revision + 1
          and new.collaborator_set_revision = old.collaborator_set_revision)
         or
         (new.resource_kind = 'conversation'
          and new.resource_access_revision = old.resource_access_revision
          and new.structural_relation_revision = old.structural_relation_revision
          and new.collaborator_set_revision =
            old.collaborator_set_revision + 1)
       ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_resource_head_invalid_advance';
    end if;
  else
    if new.current_revision <> old.current_revision + 1 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_relation_head_invalid_advance';
    end if;
    case tg_table_name
      when 'inbox_v2_auth_role_heads' then
        if new.role_id is distinct from old.role_id then v_version_matches := false; end if;
      when 'inbox_v2_auth_role_binding_heads' then
        if new.binding_id is distinct from old.binding_id then v_version_matches := false; end if;
      when 'inbox_v2_auth_direct_grant_heads' then
        if new.grant_id is distinct from old.grant_id then v_version_matches := false; end if;
      when 'inbox_v2_auth_workforce_membership_heads' then
        if row(new.membership_id, new.employee_id, new.membership_kind,
               new.org_unit_id, new.team_id, new.work_queue_id) is distinct from
           row(old.membership_id, old.employee_id, old.membership_kind,
               old.org_unit_id, old.team_id, old.work_queue_id) then
          v_version_matches := false;
        end if;
      when 'inbox_v2_auth_structural_access_heads' then
        if row(new.binding_id, new.resource_head_id, new.resource_kind,
               new.conversation_id, new.client_id, new.source_account_id,
               new.target_kind, new.target_org_unit_id, new.target_team_id)
             is distinct from
           row(old.binding_id, old.resource_head_id, old.resource_kind,
               old.conversation_id, old.client_id, old.source_account_id,
               old.target_kind, old.target_org_unit_id, old.target_team_id) then
          v_version_matches := false;
        end if;
      when 'inbox_v2_auth_collaborator_heads' then
        if row(new.collaborator_id, new.resource_kind, new.conversation_id,
               new.work_item_id, new.work_item_cycle, new.employee_id)
             is distinct from
           row(old.collaborator_id, old.resource_kind, old.conversation_id,
               old.work_item_id, old.work_item_cycle, old.employee_id) then
          v_version_matches := false;
        end if;
      else
        v_version_matches := false;
    end case;
    if not v_version_matches then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_relation_head_identity_invalid';
    end if;
  end if;

  case tg_table_name
    when 'inbox_v2_auth_role_heads' then
      select exists (
        select 1 from public.inbox_v2_auth_role_versions version_row
         where version_row.tenant_id = new.tenant_id
           and version_row.role_id = new.role_id
           and version_row.revision = new.current_revision
           and version_row.occurred_at = new.updated_at
      ) into v_version_matches;
    when 'inbox_v2_auth_role_binding_heads' then
      select exists (
        select 1 from public.inbox_v2_auth_role_binding_versions version_row
         where version_row.tenant_id = new.tenant_id
           and version_row.binding_id = new.binding_id
           and version_row.revision = new.current_revision
           and version_row.occurred_at = new.updated_at
      ) into v_version_matches;
    when 'inbox_v2_auth_direct_grant_heads' then
      select exists (
        select 1 from public.inbox_v2_auth_direct_grant_versions version_row
         where version_row.tenant_id = new.tenant_id
           and version_row.grant_id = new.grant_id
           and version_row.revision = new.current_revision
           and version_row.occurred_at = new.updated_at
      ) into v_version_matches;
    when 'inbox_v2_auth_workforce_membership_heads' then
      select exists (
        select 1 from public.inbox_v2_auth_workforce_membership_versions version_row
         where version_row.tenant_id = new.tenant_id
           and version_row.membership_id = new.membership_id
           and version_row.revision = new.current_revision
           and version_row.state = new.current_state
           and version_row.occurred_at = new.updated_at
           and row(version_row.employee_id, version_row.membership_kind,
                   version_row.org_unit_id, version_row.team_id,
                   version_row.work_queue_id) is not distinct from
               row(new.employee_id, new.membership_kind, new.org_unit_id,
                   new.team_id, new.work_queue_id)
      ) into v_version_matches;
    when 'inbox_v2_auth_structural_access_heads' then
      select exists (
        select 1 from public.inbox_v2_auth_structural_access_versions version_row
         where version_row.tenant_id = new.tenant_id
           and version_row.binding_id = new.binding_id
           and version_row.revision = new.current_revision
           and version_row.state = new.current_state
           and version_row.occurred_at = new.updated_at
           and row(version_row.resource_head_id, version_row.resource_kind,
                   version_row.conversation_id, version_row.client_id,
                   version_row.source_account_id, version_row.target_kind,
                   version_row.target_org_unit_id, version_row.target_team_id)
             is not distinct from
               row(new.resource_head_id, new.resource_kind,
                   new.conversation_id, new.client_id, new.source_account_id,
                   new.target_kind, new.target_org_unit_id, new.target_team_id)
      ) into v_version_matches;
    when 'inbox_v2_auth_collaborator_heads' then
      select exists (
        select 1 from public.inbox_v2_auth_collaborator_versions version_row
         where version_row.tenant_id = new.tenant_id
           and version_row.collaborator_id = new.collaborator_id
           and version_row.revision = new.current_revision
           and version_row.state = new.current_state
           and version_row.occurred_at = new.updated_at
           and row(version_row.resource_kind, version_row.conversation_id,
                   version_row.work_item_id, version_row.work_item_cycle,
                   version_row.employee_id) is not distinct from
               row(new.resource_kind, new.conversation_id, new.work_item_id,
                   new.work_item_cycle, new.employee_id)
      ) into v_version_matches;
    else
      v_version_matches := true;
  end case;
  if not v_version_matches then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_head_version_mismatch';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_auth_invalidations_safe(jsonb, text, integer); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_invalidations_safe(checked_value jsonb, checked_tenant_id text, checked_max integer) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  invalidation jsonb;
begin
  if jsonb_typeof(checked_value) <> 'array' then
    return false;
  end if;
  if checked_max is null or checked_max < 1
     or jsonb_array_length(checked_value) not between 1 and checked_max
     or not public.inbox_v2_auth_json_tenant_safe(
       checked_value, checked_tenant_id
     ) then
    return false;
  end if;
  for invalidation in select value from jsonb_array_elements(checked_value)
  loop
    if jsonb_typeof(invalidation) <> 'object' then
      return false;
    end if;
    case invalidation->>'kind'
      when 'recipient_scope' then
        if (invalidation - array['kind']::text[]) <> '{}'::jsonb then
          return false;
        end if;
      when 'projection' then
        if not (invalidation ?& array['kind', 'projectionId']::text[])
           or (invalidation - array['kind', 'projectionId']::text[]) <> '{}'::jsonb
           or jsonb_typeof(invalidation->'projectionId') <> 'string'
           or char_length(invalidation->>'projectionId') not between 1 and 512
           or invalidation->>'projectionId' !~
             '^[A-Za-z0-9][A-Za-z0-9._~:-]*$' then
          return false;
        end if;
      when 'conversation' then
        if not (invalidation ?& array['kind', 'conversation']::text[])
           or (invalidation - array['kind', 'conversation']::text[]) <> '{}'::jsonb
           or jsonb_typeof(invalidation->'conversation') <> 'object'
           or not (invalidation->'conversation' ?&
             array['tenantId', 'kind', 'id']::text[])
           or ((invalidation->'conversation') -
             array['tenantId', 'kind', 'id']::text[]) <> '{}'::jsonb
           or jsonb_typeof(
             invalidation->'conversation'->'tenantId'
           ) <> 'string'
           or invalidation->'conversation'->>'tenantId' <>
             checked_tenant_id
           or jsonb_typeof(
             invalidation->'conversation'->'kind'
           ) <> 'string'
           or invalidation->'conversation'->>'kind' <> 'conversation'
           or jsonb_typeof(invalidation->'conversation'->'id') <> 'string'
           or char_length(invalidation->'conversation'->>'id')
             not between 1 and 256
           or invalidation->'conversation'->>'id' !~
             '^[A-Za-z0-9][A-Za-z0-9._~:-]*$' then
          return false;
        end if;
      when 'entity' then
        if not (invalidation ?& array['kind', 'entity']::text[])
           or (invalidation - array['kind', 'entity']::text[]) <> '{}'::jsonb
           or jsonb_typeof(invalidation->'entity') <> 'object'
           or not (invalidation->'entity' ?&
             array['tenantId', 'entityTypeId', 'entityId']::text[])
           or ((invalidation->'entity') -
             array['tenantId', 'entityTypeId', 'entityId']::text[]) <> '{}'::jsonb
           or jsonb_typeof(invalidation->'entity'->'tenantId') <> 'string'
           or invalidation->'entity'->>'tenantId' <> checked_tenant_id
           or jsonb_typeof(
             invalidation->'entity'->'entityTypeId'
           ) <> 'string'
           or not public.inbox_v2_auth_catalog_id_safe(
             invalidation->'entity'->>'entityTypeId'
           )
           or jsonb_typeof(invalidation->'entity'->'entityId') <> 'string'
           or char_length(invalidation->'entity'->>'entityId')
             not between 1 and 512
           or invalidation->'entity'->>'entityId' !~
             '^[A-Za-z0-9][A-Za-z0-9._~:-]*$' then
          return false;
        end if;
      else
        return false;
    end case;
  end loop;
  return true;
end;
$_$;



--
-- Name: inbox_v2_auth_json_tenant_safe(jsonb, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_json_tenant_safe(checked_value jsonb, checked_tenant_id text) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
  select checked_value is null or not exists (
    select 1
      from jsonb_path_query(checked_value, '$.**.tenantId') tenant_ref
     where jsonb_typeof(tenant_ref) <> 'string'
        or tenant_ref #>> '{}' is distinct from checked_tenant_id
  );
$_$;



--
-- Name: inbox_v2_auth_mutation_child_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_mutation_child_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_mutation public.inbox_v2_auth_mutation_commits%rowtype;
  v_stream public.inbox_v2_tenant_stream_commits%rowtype;
  v_audit public.inbox_v2_auth_audit_events%rowtype;
  v_change_count integer;
  v_event_count integer;
  v_outbox_count integer;
  v_projection_count integer;
  v_effect_count integer;
  v_relation_count integer;
  v_facet_count integer;
begin
  if tg_table_name = 'inbox_v2_auth_audit_facets' then
    select mutation_row.* into strict v_mutation
      from public.inbox_v2_auth_audit_events audit_row
      join public.inbox_v2_auth_mutation_commits mutation_row
        on mutation_row.tenant_id = audit_row.tenant_id
       and mutation_row.audit_event_id = audit_row.id
       and mutation_row.mutation_id = audit_row.mutation_id
     where audit_row.tenant_id = new.tenant_id
       and audit_row.id = new.audit_event_id;
  elsif tg_table_name in (
    'inbox_v2_tenant_stream_changes',
    'inbox_v2_domain_events',
    'inbox_v2_outbox_intents'
  ) then
    select * into v_mutation
      from public.inbox_v2_auth_mutation_commits mutation_row
     where mutation_row.tenant_id = new.tenant_id
       and mutation_row.mutation_id = new.mutation_id;
    -- The tenant stream is shared by every V2 domain writer. Only children of
    -- an authorization mutation use this authorization-specific seal.
    if not found then
      return null;
    end if;
  else
    select * into strict v_mutation
      from public.inbox_v2_auth_mutation_commits mutation_row
     where mutation_row.tenant_id = new.tenant_id
       and mutation_row.mutation_id = new.mutation_id;
  end if;

  select * into strict v_stream
    from public.inbox_v2_tenant_stream_commits stream_row
   where stream_row.tenant_id = v_mutation.tenant_id
     and stream_row.id = v_mutation.stream_commit_id
     and stream_row.mutation_id = v_mutation.mutation_id;
  select * into strict v_audit
    from public.inbox_v2_auth_audit_events audit_row
   where audit_row.tenant_id = v_mutation.tenant_id
     and audit_row.id = v_mutation.audit_event_id
     and audit_row.mutation_id = v_mutation.mutation_id;

  select count(*)::integer into v_change_count
    from public.inbox_v2_tenant_stream_changes change_row
   where change_row.tenant_id = v_mutation.tenant_id
     and change_row.stream_commit_id = v_mutation.stream_commit_id
     and change_row.mutation_id = v_mutation.mutation_id;
  select count(*)::integer into v_event_count
    from public.inbox_v2_domain_events event_row
   where event_row.tenant_id = v_mutation.tenant_id
     and event_row.stream_commit_id = v_mutation.stream_commit_id
     and event_row.mutation_id = v_mutation.mutation_id;
  select count(*)::integer,
         count(*) filter (
           where intent_row.effect_class = 'projection'
             and intent_row.type_id = 'core:projection.update'
         )::integer
    into v_outbox_count, v_projection_count
    from public.inbox_v2_outbox_intents intent_row
   where intent_row.tenant_id = v_mutation.tenant_id
     and intent_row.stream_commit_id = v_mutation.stream_commit_id
     and intent_row.mutation_id = v_mutation.mutation_id;
  select count(*)::integer into v_effect_count
    from public.inbox_v2_auth_revision_effects effect_row
   where effect_row.tenant_id = v_mutation.tenant_id
     and effect_row.mutation_id = v_mutation.mutation_id;
  select count(*)::integer into v_relation_count
    from public.inbox_v2_auth_relation_writes write_row
   where write_row.tenant_id = v_mutation.tenant_id
     and write_row.mutation_id = v_mutation.mutation_id;
  select count(*)::integer into v_facet_count
    from public.inbox_v2_auth_audit_facets facet_row
   where facet_row.tenant_id = v_mutation.tenant_id
     and facet_row.audit_event_id = v_mutation.audit_event_id;

  if row(v_change_count, v_event_count, v_outbox_count,
         v_projection_count, v_effect_count, v_relation_count,
         v_facet_count)
       is distinct from
     row(v_stream.change_count, v_stream.event_count,
         v_stream.outbox_intent_count, v_mutation.projection_intent_count,
         v_mutation.revision_effect_count,
         v_mutation.relation_write_count, v_audit.facet_count) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_mutation_sealed_manifest_changed';
  end if;
  return null;
exception
  when no_data_found or too_many_rows then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_mutation_parent_incomplete';
end;
$$;



--
-- Name: inbox_v2_auth_mutation_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_mutation_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  v_command public.inbox_v2_auth_command_records%rowtype;
  v_stream public.inbox_v2_tenant_stream_commits%rowtype;
  v_audit public.inbox_v2_auth_audit_events%rowtype;
  v_count integer;
  v_invalid_count integer;
  v_change_count integer;
  v_event_count integer;
  v_authorization_event_count integer;
  v_outbox_count integer;
  v_effect_count integer;
  v_relation_count integer;
  v_facet_count integer;
  v_projection_count integer;
  v_role_write_count integer;
  v_structural_write_count integer;
  v_direct_access_write_count integer;
  v_direct_relation_write_count integer;
  v_change_ids jsonb;
  v_event_ids jsonb;
  v_outbox_ids jsonb;
  v_effect_digest text;
  v_relation_digest text;
  v_facet_digest text;
  v_stream_manifest_digest text;
  v_mutation_manifest_digest text;
  v_closed boolean;
  v_before_revision bigint;
  v_after_revision bigint;
  v_decision_not_after timestamptz;
begin
  select * into strict v_command
    from public.inbox_v2_auth_command_records command_row
   where command_row.tenant_id = new.tenant_id
     and command_row.id = new.command_record_id
     and command_row.mutation_id = new.mutation_id;
  select * into strict v_stream
    from public.inbox_v2_tenant_stream_commits stream_row
   where stream_row.tenant_id = new.tenant_id
     and stream_row.id = new.stream_commit_id
     and stream_row.mutation_id = new.mutation_id;
  select * into strict v_audit
    from public.inbox_v2_auth_audit_events audit_row
   where audit_row.tenant_id = new.tenant_id
     and audit_row.id = new.audit_event_id
     and audit_row.mutation_id = new.mutation_id;

  if v_command.state <> 'completed'
     or v_command.updated_at <> new.committed_at
     or v_stream.committed_at <> new.committed_at
     or v_audit.recorded_at <> new.committed_at
     or v_command.authorized_at > new.committed_at
     or new.committed_at >= v_command.authorization_not_after
     or v_command.authorization_decision_refs <>
        v_stream.authorization_decision_refs
     or row(v_audit.actor_kind, v_audit.actor_employee_id,
            v_audit.actor_trusted_service_id, v_audit.authorization_epoch,
            v_audit.client_mutation_id, v_audit.command_type_id,
            v_audit.request_hash)
       is distinct from
       row(v_command.actor_kind, v_command.actor_employee_id,
           v_command.actor_trusted_service_id, v_command.authorization_epoch,
           v_command.client_mutation_id, v_command.command_type_id,
           v_command.request_hash)
     or v_audit.correlation_id <> v_stream.correlation_id
     or v_audit.authorization_decision_refs <>
        v_stream.authorization_decision_refs
     or v_stream.command_ids <> to_jsonb(array[v_command.id]::text[])
     or v_stream.client_mutation_ids <>
        to_jsonb(array[v_command.client_mutation_id]::text[]) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_mutation_command_audit_mismatch';
  end if;

  if not public.inbox_v2_auth_decision_refs_safe(
       v_command.authorization_decision_refs,
       new.tenant_id,
       v_command.authorized_at,
       true
     )
     or not public.inbox_v2_auth_decision_refs_safe(
       v_stream.authorization_decision_refs,
       new.tenant_id,
       new.committed_at,
       true
     )
     or not public.inbox_v2_auth_json_tenant_safe(
       v_stream.audience_impact_manifest, new.tenant_id
     )
     or not public.inbox_v2_auth_payload_reference_safe(
       v_audit.evidence_reference, new.tenant_id
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_decision_manifest_invalid';
  end if;

  select min((decision_ref->>'notAfter')::timestamptz)
    into v_decision_not_after
    from jsonb_array_elements(
      v_command.authorization_decision_refs
    ) decision_ref;
  if v_command.authorization_not_after is distinct from v_decision_not_after
     or not exists (
       select 1
         from jsonb_array_elements(
           v_command.authorization_decision_refs
         ) decision_ref
        where decision_ref->>'id' = v_command.authorization_decision_id
          and decision_ref->>'authorizationEpoch' =
            v_command.authorization_epoch
          and decision_ref->>'outcome' = 'allowed'
     )
     or exists (
       select 1
         from jsonb_array_elements(
           v_command.authorization_decision_refs
         ) decision_ref
        where decision_ref->>'authorizationEpoch' <>
            v_command.authorization_epoch
           or case v_command.actor_kind
             when 'employee' then
               decision_ref->'principal'->>'kind' <> 'employee'
               or decision_ref->'principal'->'employee'->>'tenantId' <>
                 new.tenant_id
               or decision_ref->'principal'->'employee'->>'id' <>
                 v_command.actor_employee_id
             when 'trusted_service' then
               decision_ref->'principal'->>'kind' <> 'trusted_service'
               or decision_ref->'principal'->>'trustedServiceId' <>
                 v_command.actor_trusted_service_id
             else true
           end
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_decision_manifest_invalid';
  end if;

  select count(*)::integer,
         coalesce(to_jsonb(array_agg(change_row.id order by change_row.ordinal)),
                  '[]'::jsonb)
    into v_change_count, v_change_ids
    from public.inbox_v2_tenant_stream_changes change_row
   where change_row.tenant_id = new.tenant_id
     and change_row.stream_commit_id = new.stream_commit_id
     and change_row.mutation_id = new.mutation_id;
  select count(*)::integer,
         coalesce(to_jsonb(array_agg(event_row.id order by event_row.ordinal)),
                  '[]'::jsonb),
         count(*) filter (
           where event_row.type_id = 'core:authorization.changed'
         )::integer
    into v_event_count, v_event_ids, v_authorization_event_count
    from public.inbox_v2_domain_events event_row
   where event_row.tenant_id = new.tenant_id
     and event_row.stream_commit_id = new.stream_commit_id
     and event_row.mutation_id = new.mutation_id;
  select count(*)::integer,
         coalesce(to_jsonb(array_agg(intent_row.id order by intent_row.ordinal)),
                  '[]'::jsonb),
         count(*) filter (
           where intent_row.effect_class = 'projection'
             and intent_row.type_id = 'core:projection.update'
         )::integer
    into v_outbox_count, v_outbox_ids, v_projection_count
    from public.inbox_v2_outbox_intents intent_row
   where intent_row.tenant_id = new.tenant_id
     and intent_row.stream_commit_id = new.stream_commit_id
     and intent_row.mutation_id = new.mutation_id;

  if row(v_change_count, v_event_count, v_outbox_count,
         v_change_ids, v_event_ids, v_outbox_ids)
       is distinct from
     row(v_stream.change_count, v_stream.event_count,
         v_stream.outbox_intent_count, v_stream.change_ids,
         v_stream.event_ids, v_stream.outbox_intent_ids)
     or v_projection_count <> new.projection_intent_count
     or v_projection_count < 1
     or v_authorization_event_count < 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_stream_manifest_incomplete';
  end if;

  select count(*)::integer into v_invalid_count
    from public.inbox_v2_tenant_stream_changes change_row
   where change_row.tenant_id = new.tenant_id
     and change_row.stream_commit_id = new.stream_commit_id
     and (change_row.stream_position <> v_stream.position
       or change_row.created_at <> new.committed_at
       or not public.inbox_v2_auth_payload_reference_safe(
         change_row.domain_commit_reference, new.tenant_id
       )
       or not public.inbox_v2_auth_payload_reference_safe(
         change_row.payload_reference, new.tenant_id
       )
       or not public.inbox_v2_auth_json_tenant_safe(
         change_row.timeline, new.tenant_id
       )
       or (change_row.timeline is not null and (
         not (change_row.timeline ?&
           array['conversation', 'timelineSequence']::text[])
         or (change_row.timeline -
           array['conversation', 'timelineSequence']::text[]) <> '{}'::jsonb
         or jsonb_typeof(change_row.timeline->'conversation') <> 'object'
         or not (change_row.timeline->'conversation' ?&
           array['tenantId', 'kind', 'id']::text[])
         or ((change_row.timeline->'conversation') -
           array['tenantId', 'kind', 'id']::text[]) <> '{}'::jsonb
         or jsonb_typeof(
           change_row.timeline->'conversation'->'tenantId'
         ) <> 'string'
         or change_row.timeline->'conversation'->>'tenantId' <>
           new.tenant_id
         or jsonb_typeof(
           change_row.timeline->'conversation'->'kind'
         ) <> 'string'
         or change_row.timeline->'conversation'->>'kind' <> 'conversation'
         or jsonb_typeof(
           change_row.timeline->'conversation'->'id'
         ) <> 'string'
         or char_length(
           change_row.timeline->'conversation'->>'id'
         ) not between 1 and 256
         or change_row.timeline->'conversation'->>'id' !~
           '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
         or jsonb_typeof(change_row.timeline->'timelineSequence') <> 'string'
         or change_row.timeline->>'timelineSequence' !~
           '^[1-9][0-9]{0,18}$'
       ))
       or (change_row.state_kind = 'upsert' and (
         change_row.payload_reference->>'schemaId' <>
           change_row.state_schema_id
         or change_row.payload_reference->>'schemaVersion' <>
           change_row.state_schema_version
       )));
  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_domain_events event_row
   where event_row.tenant_id = new.tenant_id
     and event_row.stream_commit_id = new.stream_commit_id
     and (event_row.stream_position <> v_stream.position
       or event_row.recorded_at <> new.committed_at
       or event_row.correlation_id <> v_stream.correlation_id
       or event_row.command_ids <> v_stream.command_ids
       or event_row.client_mutation_ids <> v_stream.client_mutation_ids
       or event_row.authorization_decision_refs <>
          v_stream.authorization_decision_refs
       or (event_row.type_id = 'core:authorization.changed'
         and event_row.access_effect <> 'may_change_access')
       or not (v_stream.change_ids @> event_row.change_ids)
       or not public.inbox_v2_auth_payload_reference_safe(
         event_row.payload_reference, new.tenant_id
       )
       or (event_row.payload_reference is not null and (
         event_row.payload_reference->>'schemaId' <>
           event_row.payload_schema_id
         or event_row.payload_reference->>'schemaVersion' <>
           event_row.payload_schema_version
       ))
       or not public.inbox_v2_auth_decision_refs_safe(
         event_row.authorization_decision_refs,
         new.tenant_id,
         new.committed_at,
         true
       )
       or exists (
         select 1
           from jsonb_array_elements(event_row.subjects) subject_row
          where jsonb_typeof(subject_row) <> 'object'
             or not (subject_row ?&
               array['tenantId', 'entityTypeId', 'entityId']::text[])
             or (subject_row -
               array['tenantId', 'entityTypeId', 'entityId']::text[]) <>
                 '{}'::jsonb
             or subject_row->>'tenantId' <> new.tenant_id
             or jsonb_typeof(subject_row->'tenantId') <> 'string'
             or jsonb_typeof(subject_row->'entityTypeId') <> 'string'
             or not public.inbox_v2_auth_catalog_id_safe(
               subject_row->>'entityTypeId'
             )
             or jsonb_typeof(subject_row->'entityId') <> 'string'
             or char_length(subject_row->>'entityId') not between 1 and 512
             or subject_row->>'entityId' !~
               '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       ));
  select v_invalid_count + count(*)::integer into v_invalid_count
    from public.inbox_v2_outbox_intents intent_row
    join public.inbox_v2_domain_events event_row
      on event_row.tenant_id = intent_row.tenant_id
     and event_row.id = intent_row.event_id
   where intent_row.tenant_id = new.tenant_id
     and intent_row.stream_commit_id = new.stream_commit_id
     and (intent_row.stream_position <> v_stream.position
       or intent_row.created_at <> new.committed_at
       or intent_row.available_at < new.committed_at
       or intent_row.correlation_id <> v_stream.correlation_id
       or event_row.stream_commit_id <> new.stream_commit_id
       or event_row.mutation_id <> new.mutation_id
       or event_row.correlation_id <> intent_row.correlation_id
       or intent_row.effect_class = 'provider_io'
       or not (v_stream.change_ids @> intent_row.change_ids)
       or not (event_row.change_ids @> intent_row.change_ids)
       or not public.inbox_v2_auth_payload_reference_safe(
         intent_row.payload_reference, new.tenant_id
       ));
  if v_invalid_count <> 0 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_stream_child_mismatch';
  end if;

  select 'sha256:' || encode(sha256(convert_to(coalesce(string_agg(
           manifest_row.item_hash,
           chr(10) order by manifest_row.kind_ordinal, manifest_row.ordinal
         ), ''), 'UTF8')), 'hex')
    into v_stream_manifest_digest
    from (
      select 1 as kind_ordinal, change_row.ordinal,
             'change:' || change_row.state_hash as item_hash
        from public.inbox_v2_tenant_stream_changes change_row
       where change_row.tenant_id = new.tenant_id
         and change_row.stream_commit_id = new.stream_commit_id
      union all
      select 2, event_row.ordinal, 'event:' || event_row.event_hash
        from public.inbox_v2_domain_events event_row
       where event_row.tenant_id = new.tenant_id
         and event_row.stream_commit_id = new.stream_commit_id
      union all
      select 3, intent_row.ordinal, 'intent:' || intent_row.intent_hash
        from public.inbox_v2_outbox_intents intent_row
       where intent_row.tenant_id = new.tenant_id
         and intent_row.stream_commit_id = new.stream_commit_id
    ) manifest_row;
  if v_stream_manifest_digest <> v_stream.manifest_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_stream_digest_mismatch';
  end if;

  select count(*)::integer,
         'sha256:' || encode(sha256(convert_to(coalesce(string_agg(
           effect_row.effect_hash, chr(10) order by effect_row.ordinal
         ), ''), 'UTF8')), 'hex')
    into v_effect_count, v_effect_digest
    from public.inbox_v2_auth_revision_effects effect_row
   where effect_row.tenant_id = new.tenant_id
     and effect_row.mutation_id = new.mutation_id;
  select count(*)::integer,
         'sha256:' || encode(sha256(convert_to(coalesce(string_agg(
           write_row.write_hash, chr(10) order by write_row.ordinal
         ), ''), 'UTF8')), 'hex')
    into v_relation_count, v_relation_digest
    from public.inbox_v2_auth_relation_writes write_row
   where write_row.tenant_id = new.tenant_id
     and write_row.mutation_id = new.mutation_id;
  select count(*)::integer,
         'sha256:' || encode(sha256(convert_to(coalesce(string_agg(
           facet_row.facet_hash, chr(10) order by facet_row.ordinal
         ), ''), 'UTF8')), 'hex')
    into v_facet_count, v_facet_digest
    from public.inbox_v2_auth_audit_facets facet_row
   where facet_row.tenant_id = new.tenant_id
     and facet_row.audit_event_id = new.audit_event_id;

  if row(v_effect_count, v_effect_digest, v_relation_count,
         v_relation_digest, v_facet_count, v_facet_digest)
       is distinct from
     row(new.revision_effect_count, new.revision_effect_digest_sha256,
         new.relation_write_count, new.relation_write_digest_sha256,
         v_audit.facet_count, v_audit.facets_digest_sha256)
     or v_audit.revision_delta_hash <> v_effect_digest then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_mutation_manifest_incomplete';
  end if;

  select count(*)::integer into v_invalid_count
    from public.inbox_v2_auth_revision_effects effect_row
   where effect_row.tenant_id = new.tenant_id
     and effect_row.mutation_id = new.mutation_id
     and (effect_row.created_at <> new.committed_at or not case effect_row.effect_kind
       when 'tenant_rbac' then exists (
         select 1 from public.inbox_v2_auth_tenant_heads head_row
          where head_row.tenant_id = effect_row.tenant_id
            and head_row.tenant_rbac_revision = effect_row.after_revision
       )
       when 'shared_access' then exists (
         select 1 from public.inbox_v2_auth_tenant_heads head_row
          where head_row.tenant_id = effect_row.tenant_id
            and head_row.shared_access_revision = effect_row.after_revision
       )
       when 'employee_access' then exists (
         select 1 from public.inbox_v2_auth_employee_heads head_row
          where head_row.tenant_id = effect_row.tenant_id
            and head_row.employee_id = effect_row.employee_id
            and head_row.employee_access_revision = effect_row.after_revision
       )
       when 'employee_inbox_relation' then exists (
         select 1 from public.inbox_v2_auth_employee_heads head_row
          where head_row.tenant_id = effect_row.tenant_id
            and head_row.employee_id = effect_row.employee_id
            and head_row.employee_inbox_relation_revision =
                effect_row.after_revision
       )
        when 'resource_access' then (
         (effect_row.resource_head_id is not null and exists (
           select 1 from public.inbox_v2_auth_resource_heads head_row
            where head_row.tenant_id = effect_row.tenant_id
              and head_row.id = effect_row.resource_head_id
              and head_row.resource_access_revision = effect_row.after_revision
         )) or
         (effect_row.work_item_id is not null and exists (
           select 1 from public.inbox_v2_work_items work_item
            where work_item.tenant_id = effect_row.tenant_id
              and work_item.id = effect_row.work_item_id
              and work_item.resource_access_revision = effect_row.after_revision
          ))
        )
       when 'collaborator_set' then (
         (effect_row.resource_head_id is not null and exists (
           select 1 from public.inbox_v2_auth_resource_heads head_row
            where head_row.tenant_id = effect_row.tenant_id
              and head_row.id = effect_row.resource_head_id
              and head_row.collaborator_set_revision =
                  effect_row.after_revision
              and head_row.updated_at = effect_row.created_at
         )) or
         (effect_row.work_item_id is not null and exists (
           select 1 from public.inbox_v2_work_items work_item_row
            where work_item_row.tenant_id = effect_row.tenant_id
              and work_item_row.id = effect_row.work_item_id
              and work_item_row.reopen_cycle = effect_row.work_item_cycle
              and work_item_row.revision =
                  effect_row.resulting_work_item_revision
              and work_item_row.collaborator_set_revision =
                  effect_row.after_revision
              and work_item_row.updated_at = effect_row.created_at
         ))
       )
       else false
     end);
  if v_invalid_count <> 0 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_revision_effect_invalid';
  end if;

  select count(*)::integer into v_invalid_count
    from public.inbox_v2_auth_relation_writes write_row
   where write_row.tenant_id = new.tenant_id
     and write_row.mutation_id = new.mutation_id
     and (write_row.created_at <> new.committed_at or not case write_row.relation_kind
       when 'role' then exists (
         select 1 from public.inbox_v2_auth_role_versions version_row
          join public.inbox_v2_auth_role_heads head_row
            on head_row.tenant_id = version_row.tenant_id
           and head_row.role_id = version_row.role_id
           and head_row.current_revision = version_row.revision
          where version_row.tenant_id = write_row.tenant_id
            and version_row.role_id = write_row.role_id
            and version_row.revision = write_row.resulting_revision
            and write_row.previous_revision is not distinct from case
              when version_row.revision = 1 then null::bigint
              else version_row.revision - 1
            end
            and version_row.mutation_id = write_row.mutation_id
            and version_row.occurred_at = new.committed_at
       )
       when 'role_binding' then exists (
         select 1 from public.inbox_v2_auth_role_binding_versions version_row
          join public.inbox_v2_auth_role_binding_heads head_row
            on head_row.tenant_id = version_row.tenant_id
           and head_row.binding_id = version_row.binding_id
           and head_row.current_revision = version_row.revision
          where version_row.tenant_id = write_row.tenant_id
            and version_row.binding_id = write_row.role_binding_id
            and version_row.revision = write_row.resulting_revision
            and write_row.previous_revision is not distinct from case
              when version_row.revision = 1 then null::bigint
              else version_row.revision - 1
            end
            and version_row.mutation_id = write_row.mutation_id
            and version_row.occurred_at = new.committed_at
       )
       when 'direct_grant' then exists (
         select 1 from public.inbox_v2_auth_direct_grant_versions version_row
          join public.inbox_v2_auth_direct_grant_heads head_row
            on head_row.tenant_id = version_row.tenant_id
           and head_row.grant_id = version_row.grant_id
           and head_row.current_revision = version_row.revision
          where version_row.tenant_id = write_row.tenant_id
            and version_row.grant_id = write_row.direct_grant_id
            and version_row.revision = write_row.resulting_revision
            and write_row.previous_revision is not distinct from case
              when version_row.revision = 1 then null::bigint
              else version_row.revision - 1
            end
            and version_row.mutation_id = write_row.mutation_id
            and version_row.occurred_at = new.committed_at
       )
       when 'workforce_membership' then exists (
         select 1 from public.inbox_v2_auth_workforce_membership_versions version_row
          join public.inbox_v2_auth_workforce_membership_heads head_row
            on head_row.tenant_id = version_row.tenant_id
           and head_row.membership_id = version_row.membership_id
           and head_row.current_revision = version_row.revision
          where version_row.tenant_id = write_row.tenant_id
            and version_row.membership_id = write_row.workforce_membership_id
            and version_row.revision = write_row.resulting_revision
            and write_row.previous_revision is not distinct from case
              when version_row.revision = 1 then null::bigint
              else version_row.revision - 1
            end
            and version_row.mutation_id = write_row.mutation_id
            and version_row.occurred_at = new.committed_at
       )
       when 'structural_access' then exists (
         select 1 from public.inbox_v2_auth_structural_access_versions version_row
          join public.inbox_v2_auth_structural_access_heads head_row
            on head_row.tenant_id = version_row.tenant_id
           and head_row.binding_id = version_row.binding_id
           and head_row.current_revision = version_row.revision
          where version_row.tenant_id = write_row.tenant_id
            and version_row.binding_id = write_row.structural_access_binding_id
            and version_row.revision = write_row.resulting_revision
            and write_row.previous_revision is not distinct from case
              when version_row.revision = 1 then null::bigint
              else version_row.revision - 1
            end
            and version_row.mutation_id = write_row.mutation_id
            and version_row.occurred_at = new.committed_at
       )
       when 'conversation_collaborator' then exists (
         select 1 from public.inbox_v2_auth_collaborator_versions version_row
          join public.inbox_v2_auth_collaborator_heads head_row
            on head_row.tenant_id = version_row.tenant_id
           and head_row.collaborator_id = version_row.collaborator_id
           and head_row.current_revision = version_row.revision
          where version_row.tenant_id = write_row.tenant_id
            and version_row.collaborator_id = write_row.collaborator_id
            and version_row.revision = write_row.resulting_revision
            and write_row.previous_revision is not distinct from case
              when version_row.revision = 1 then null::bigint
              else version_row.revision - 1
            end
            and version_row.resource_kind = 'conversation'
            and version_row.mutation_id = write_row.mutation_id
            and version_row.occurred_at = new.committed_at
            and exists (
              select 1 from public.inbox_v2_auth_resource_heads resource_head
               where resource_head.tenant_id = version_row.tenant_id
                 and resource_head.resource_kind = 'conversation'
                 and resource_head.conversation_id = version_row.conversation_id
                 and resource_head.updated_at = new.committed_at
            )
       )
       when 'work_item_collaborator' then exists (
         select 1 from public.inbox_v2_auth_collaborator_versions version_row
          join public.inbox_v2_auth_collaborator_heads head_row
            on head_row.tenant_id = version_row.tenant_id
           and head_row.collaborator_id = version_row.collaborator_id
           and head_row.current_revision = version_row.revision
          where version_row.tenant_id = write_row.tenant_id
            and version_row.collaborator_id = write_row.collaborator_id
            and version_row.revision = write_row.resulting_revision
            and write_row.previous_revision is not distinct from case
              when version_row.revision = 1 then null::bigint
              else version_row.revision - 1
            end
            and version_row.resource_kind = 'work_item'
            and version_row.work_item_cycle >= 0
            and version_row.mutation_id = write_row.mutation_id
            and version_row.occurred_at = new.committed_at
            and exists (
              select 1 from public.inbox_v2_work_items work_item
               where work_item.tenant_id = version_row.tenant_id
                 and work_item.id = version_row.work_item_id
                 and work_item.reopen_cycle = version_row.work_item_cycle
            )
       )
       when 'internal_membership' then exists (
         select 1 from public.inbox_v2_participant_membership_transitions transition_row
          where transition_row.tenant_id = write_row.tenant_id
            and transition_row.id = write_row.internal_membership_transition_id
            and transition_row.resulting_revision = write_row.resulting_revision
            and transition_row.current_revision is not distinct from
                write_row.previous_revision
            and transition_row.cause_kind = 'hulee_internal_command'
            and v_command.actor_kind = 'employee'
            and transition_row.cause_actor_employee_id =
                v_command.actor_employee_id
            and transition_row.occurred_at = new.committed_at
       )
       when 'primary_responsibility' then exists (
         select 1 from public.inbox_v2_work_item_transitions transition_row
          where transition_row.tenant_id = write_row.tenant_id
            and transition_row.id = write_row.primary_responsibility_transition_id
            and transition_row.resulting_revision = write_row.resulting_revision
            and transition_row.expected_revision = write_row.previous_revision
            and (transition_row.closed_primary_assignment_id is not null
              or transition_row.opened_primary_assignment_id is not null)
            and row(
              transition_row.actor_kind::text,
              transition_row.actor_employee_id,
              transition_row.actor_trusted_service_id,
              transition_row.actor_authorization_epoch
            ) is not distinct from row(
              v_command.actor_kind::text,
              v_command.actor_employee_id,
              v_command.actor_trusted_service_id,
              case when v_command.actor_kind = 'employee'
                then v_command.authorization_epoch else null::text end
            )
            and transition_row.occurred_at = new.committed_at
       )
       when 'servicing_team' then exists (
         select 1 from public.inbox_v2_work_item_relation_transitions transition_row
          where transition_row.tenant_id = write_row.tenant_id
            and transition_row.id = write_row.servicing_team_transition_id
            and transition_row.resulting_relation_revision =
                write_row.resulting_revision
            and transition_row.expected_relation_revision =
                write_row.previous_revision
            and row(
              transition_row.actor_kind::text,
              transition_row.actor_employee_id,
              transition_row.actor_trusted_service_id,
              transition_row.actor_authorization_epoch
            ) is not distinct from row(
              v_command.actor_kind::text,
              v_command.actor_employee_id,
              v_command.actor_trusted_service_id,
              case when v_command.actor_kind = 'employee'
                then v_command.authorization_epoch else null::text end
            )
            and transition_row.occurred_at = new.committed_at
       )
       else false
     end);
  if v_invalid_count <> 0 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_relation_write_invalid';
  end if;

  select count(*) filter (
           where write_row.relation_kind in ('role', 'role_binding')
         )::integer,
         count(*) filter (
           where write_row.relation_kind in ('structural_access', 'servicing_team')
         )::integer,
         count(*) filter (
           where write_row.relation_kind in ('direct_grant', 'workforce_membership')
         )::integer,
         count(*) filter (
           where write_row.relation_kind in (
             'conversation_collaborator', 'work_item_collaborator',
             'internal_membership', 'primary_responsibility'
           )
         )::integer
    into v_role_write_count, v_structural_write_count,
         v_direct_access_write_count, v_direct_relation_write_count
    from public.inbox_v2_auth_relation_writes write_row
   where write_row.tenant_id = new.tenant_id
     and write_row.mutation_id = new.mutation_id;

  if v_role_write_count = v_relation_count then
    select count(*)::integer,
           min(effect_row.before_revision),
           max(effect_row.after_revision)
      into v_count, v_before_revision, v_after_revision
      from public.inbox_v2_auth_revision_effects effect_row
     where effect_row.tenant_id = new.tenant_id
       and effect_row.mutation_id = new.mutation_id
       and effect_row.effect_kind = 'tenant_rbac';
    if v_stream.audience_impact_kind <> 'tenant_rbac'
       or v_count <> 1 or v_effect_count <> 1
       or not (v_stream.audience_impact_manifest ?& array[
         'kind', 'impactId', 'deliveryFence',
         'previousTenantRbacRevision', 'resultingTenantRbacRevision',
         'invalidations', 'indexedFanoutPlanId'
       ]::text[])
       or (v_stream.audience_impact_manifest - array[
         'kind', 'impactId', 'deliveryFence',
         'previousTenantRbacRevision', 'resultingTenantRbacRevision',
         'invalidations', 'indexedFanoutPlanId'
       ]::text[]) <> '{}'::jsonb
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'impactId'
       ) <> 'string'
       or char_length(v_stream.audience_impact_manifest->>'impactId')
         not between 1 and 512
       or v_stream.audience_impact_manifest->>'impactId' !~
         '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       or v_stream.audience_impact_manifest->>'deliveryFence' <>
         'invalidate_before_payload'
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'previousTenantRbacRevision'
       ) <> 'string'
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'resultingTenantRbacRevision'
       ) <> 'string'
       or v_stream.audience_impact_manifest->>'previousTenantRbacRevision' <>
         v_before_revision::text
       or v_stream.audience_impact_manifest->>'resultingTenantRbacRevision' <>
         v_after_revision::text
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'indexedFanoutPlanId'
       ) <> 'string'
       or char_length(
         v_stream.audience_impact_manifest->>'indexedFanoutPlanId'
       ) not between 1 and 512
       or v_stream.audience_impact_manifest->>'indexedFanoutPlanId' !~
         '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'invalidations'
       ) <> 'array'
       or (case when jsonb_typeof(
         v_stream.audience_impact_manifest->'invalidations'
       ) = 'array' then jsonb_array_length(
         v_stream.audience_impact_manifest->'invalidations'
       ) not between 1 and 1000 else true end)
       or not public.inbox_v2_auth_invalidations_safe(
         v_stream.audience_impact_manifest->'invalidations',
         new.tenant_id,
         1000
       ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_tenant_rbac_fanout_invalid';
    end if;
  elsif v_structural_write_count = v_relation_count then
    select count(*) filter (where effect_row.effect_kind = 'shared_access')::integer,
           count(*) filter (where effect_row.effect_kind = 'resource_access')::integer
      into v_count, v_invalid_count
      from public.inbox_v2_auth_revision_effects effect_row
     where effect_row.tenant_id = new.tenant_id
       and effect_row.mutation_id = new.mutation_id;
    if v_stream.audience_impact_kind <> 'structural'
       or v_count <> 1 or v_invalid_count < 1
       or v_effect_count <> v_count + v_invalid_count then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_structural_impact_invalid';
    end if;

    with expected_targets(resource_head_id, work_item_id) as (
      select version_row.resource_head_id, null::text
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_auth_structural_access_versions version_row
          on version_row.tenant_id = write_row.tenant_id
         and version_row.binding_id = write_row.structural_access_binding_id
         and version_row.revision = write_row.resulting_revision
         and version_row.mutation_id = write_row.mutation_id
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind = 'structural_access'
      union
      select null::text, transition_row.work_item_id
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_work_item_relation_transitions transition_row
          on transition_row.tenant_id = write_row.tenant_id
         and transition_row.id = write_row.servicing_team_transition_id
         and transition_row.resulting_relation_revision =
           write_row.resulting_revision
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind = 'servicing_team'
    ), actual_targets as (
      select effect_row.resource_head_id, effect_row.work_item_id
        from public.inbox_v2_auth_revision_effects effect_row
       where effect_row.tenant_id = new.tenant_id
         and effect_row.mutation_id = new.mutation_id
         and effect_row.effect_kind = 'resource_access'
    )
    select exists (
      (select * from expected_targets except select * from actual_targets)
      union all
      (select * from actual_targets except select * from expected_targets)
    ) into v_closed;
    if v_closed then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_structural_target_set_mismatch';
    end if;

    select effect_row.before_revision, effect_row.after_revision
      into strict v_before_revision, v_after_revision
      from public.inbox_v2_auth_revision_effects effect_row
     where effect_row.tenant_id = new.tenant_id
       and effect_row.mutation_id = new.mutation_id
       and effect_row.effect_kind = 'shared_access';
    if not (v_stream.audience_impact_manifest ?& array[
         'kind', 'impactId', 'deliveryFence',
         'previousSharedAccessRevision', 'resultingSharedAccessRevision',
         'invalidations', 'indexedFanoutPlanId'
       ]::text[])
       or (v_stream.audience_impact_manifest - array[
         'kind', 'impactId', 'deliveryFence',
         'previousSharedAccessRevision', 'resultingSharedAccessRevision',
         'invalidations', 'indexedFanoutPlanId'
       ]::text[]) <> '{}'::jsonb
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'impactId'
       ) <> 'string'
       or char_length(v_stream.audience_impact_manifest->>'impactId')
         not between 1 and 512
       or v_stream.audience_impact_manifest->>'impactId' !~
         '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       or v_stream.audience_impact_manifest->>'deliveryFence' <>
         'invalidate_before_payload'
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'previousSharedAccessRevision'
       ) <> 'string'
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'resultingSharedAccessRevision'
       ) <> 'string'
       or v_stream.audience_impact_manifest->>'previousSharedAccessRevision' <>
         v_before_revision::text
       or v_stream.audience_impact_manifest->>'resultingSharedAccessRevision' <>
         v_after_revision::text
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'indexedFanoutPlanId'
       ) <> 'string'
       or char_length(
         v_stream.audience_impact_manifest->>'indexedFanoutPlanId'
       ) not between 1 and 512
       or v_stream.audience_impact_manifest->>'indexedFanoutPlanId' !~
         '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'invalidations'
       ) <> 'array'
       or (case when jsonb_typeof(
         v_stream.audience_impact_manifest->'invalidations'
       ) = 'array' then jsonb_array_length(
         v_stream.audience_impact_manifest->'invalidations'
       ) not between 1 and 1000 else true end)
       or not public.inbox_v2_auth_invalidations_safe(
         v_stream.audience_impact_manifest->'invalidations',
         new.tenant_id,
         1000
       ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_structural_audience_invalid';
    end if;
  elsif v_direct_access_write_count = v_relation_count then
    select count(*)::integer into v_count
      from public.inbox_v2_auth_revision_effects effect_row
     where effect_row.tenant_id = new.tenant_id
       and effect_row.mutation_id = new.mutation_id
       and effect_row.effect_kind = 'employee_access';
    if v_stream.audience_impact_kind <> 'direct'
       or v_count < 1 or v_count <> v_effect_count then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_employee_access_impact_invalid';
    end if;

    with expected_targets(employee_id) as (
      select version_row.employee_id
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_auth_direct_grant_versions version_row
          on version_row.tenant_id = write_row.tenant_id
         and version_row.grant_id = write_row.direct_grant_id
         and version_row.revision = write_row.resulting_revision
         and version_row.mutation_id = write_row.mutation_id
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind = 'direct_grant'
      union
      select version_row.employee_id
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_auth_workforce_membership_versions version_row
          on version_row.tenant_id = write_row.tenant_id
         and version_row.membership_id = write_row.workforce_membership_id
         and version_row.revision = write_row.resulting_revision
         and version_row.mutation_id = write_row.mutation_id
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind = 'workforce_membership'
    ), actual_targets as (
      select effect_row.employee_id
        from public.inbox_v2_auth_revision_effects effect_row
       where effect_row.tenant_id = new.tenant_id
         and effect_row.mutation_id = new.mutation_id
         and effect_row.effect_kind = 'employee_access'
    )
    select exists (
      (select * from expected_targets except select * from actual_targets)
      union all
      (select * from actual_targets except select * from expected_targets)
    ) into v_closed;
    if v_closed then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_employee_access_target_set_mismatch';
    end if;
  elsif v_direct_relation_write_count = v_relation_count then
    select count(*) filter (
             where effect_row.effect_kind = 'employee_inbox_relation'
           )::integer,
           count(*) filter (
             where effect_row.effect_kind = 'collaborator_set'
           )::integer
      into v_count, v_invalid_count
      from public.inbox_v2_auth_revision_effects effect_row
     where effect_row.tenant_id = new.tenant_id
       and effect_row.mutation_id = new.mutation_id;
    if v_stream.audience_impact_kind <> 'direct'
       or v_count < 1
       or v_count + v_invalid_count <> v_effect_count
       or (exists (
         select 1 from public.inbox_v2_auth_relation_writes write_row
          where write_row.tenant_id = new.tenant_id
            and write_row.mutation_id = new.mutation_id
            and write_row.relation_kind in (
              'conversation_collaborator', 'work_item_collaborator'
            )
       )) is distinct from (v_invalid_count = 1) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_direct_relation_impact_invalid';
    end if;

    with expected_targets(employee_id) as (
      select version_row.employee_id
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_auth_collaborator_versions version_row
          on version_row.tenant_id = write_row.tenant_id
         and version_row.collaborator_id = write_row.collaborator_id
         and version_row.revision = write_row.resulting_revision
         and version_row.mutation_id = write_row.mutation_id
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind in (
           'conversation_collaborator', 'work_item_collaborator'
         )
      union
      select participant_row.subject_employee_id
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_participant_membership_transitions transition_row
          on transition_row.tenant_id = write_row.tenant_id
         and transition_row.id = write_row.internal_membership_transition_id
         and transition_row.resulting_revision = write_row.resulting_revision
        join public.inbox_v2_conversation_participants participant_row
          on participant_row.tenant_id = transition_row.tenant_id
         and participant_row.id = transition_row.participant_id
         and participant_row.conversation_id = transition_row.conversation_id
         and participant_row.subject_kind = 'employee'
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind = 'internal_membership'
      union
      select assignment_row.employee_id
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_work_item_transitions transition_row
          on transition_row.tenant_id = write_row.tenant_id
         and transition_row.id = write_row.primary_responsibility_transition_id
         and transition_row.resulting_revision = write_row.resulting_revision
        join public.inbox_v2_work_item_primary_assignments assignment_row
          on assignment_row.tenant_id = transition_row.tenant_id
         and assignment_row.id = transition_row.closed_primary_assignment_id
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind = 'primary_responsibility'
      union
      select assignment_row.employee_id
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_work_item_transitions transition_row
          on transition_row.tenant_id = write_row.tenant_id
         and transition_row.id = write_row.primary_responsibility_transition_id
         and transition_row.resulting_revision = write_row.resulting_revision
        join public.inbox_v2_work_item_primary_assignments assignment_row
          on assignment_row.tenant_id = transition_row.tenant_id
         and assignment_row.id = transition_row.opened_primary_assignment_id
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind = 'primary_responsibility'
    ), actual_targets as (
      select effect_row.employee_id
        from public.inbox_v2_auth_revision_effects effect_row
       where effect_row.tenant_id = new.tenant_id
         and effect_row.mutation_id = new.mutation_id
         and effect_row.effect_kind = 'employee_inbox_relation'
    )
    select exists (
      (select * from expected_targets except select * from actual_targets)
      union all
      (select * from actual_targets except select * from expected_targets)
    ) into v_closed;
    if v_closed then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_direct_relation_target_set_mismatch';
    end if;

    with expected_targets(
      resource_head_id, work_item_id, work_item_cycle
    ) as (
      select resource_head.id, version_row.work_item_id,
             version_row.work_item_cycle
        from public.inbox_v2_auth_relation_writes write_row
        join public.inbox_v2_auth_collaborator_versions version_row
          on version_row.tenant_id = write_row.tenant_id
         and version_row.collaborator_id = write_row.collaborator_id
         and version_row.revision = write_row.resulting_revision
         and version_row.mutation_id = write_row.mutation_id
        left join public.inbox_v2_auth_resource_heads resource_head
          on resource_head.tenant_id = version_row.tenant_id
         and version_row.resource_kind = 'conversation'
         and resource_head.resource_kind = 'conversation'
         and resource_head.conversation_id = version_row.conversation_id
       where write_row.tenant_id = new.tenant_id
         and write_row.mutation_id = new.mutation_id
         and write_row.relation_kind in (
           'conversation_collaborator', 'work_item_collaborator'
         )
    ), actual_targets as (
      select effect_row.resource_head_id, effect_row.work_item_id,
             effect_row.work_item_cycle
        from public.inbox_v2_auth_revision_effects effect_row
       where effect_row.tenant_id = new.tenant_id
         and effect_row.mutation_id = new.mutation_id
         and effect_row.effect_kind = 'collaborator_set'
    )
    select exists (
      (select * from expected_targets except select * from actual_targets)
      union all
      (select * from actual_targets except select * from expected_targets)
    ) into v_closed;
    if v_closed then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_collaborator_set_target_mismatch';
    end if;
  else
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_mutation_relation_class_mixed';
  end if;

  if v_stream.audience_impact_kind = 'direct' then
    if not (v_stream.audience_impact_manifest ?& array[
         'kind', 'impactId', 'deliveryFence', 'affectedRecipients'
       ]::text[])
       or (v_stream.audience_impact_manifest - array[
         'kind', 'impactId', 'deliveryFence', 'affectedRecipients'
       ]::text[]) <> '{}'::jsonb
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'impactId'
       ) <> 'string'
       or char_length(v_stream.audience_impact_manifest->>'impactId')
         not between 1 and 512
       or v_stream.audience_impact_manifest->>'impactId' !~
         '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
       or v_stream.audience_impact_manifest->>'deliveryFence' <>
         'invalidate_before_payload'
       or jsonb_typeof(
         v_stream.audience_impact_manifest->'affectedRecipients'
       ) <> 'array'
       or (case when jsonb_typeof(
         v_stream.audience_impact_manifest->'affectedRecipients'
       ) = 'array' then jsonb_array_length(
         v_stream.audience_impact_manifest->'affectedRecipients'
       ) not between 1 and 1000 else true end) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_direct_audience_invalid';
    end if;

    select count(*)::integer into v_invalid_count
      from jsonb_array_elements(
        v_stream.audience_impact_manifest->'affectedRecipients'
      ) recipient_row
     where jsonb_typeof(recipient_row) <> 'object'
        or not (recipient_row ?& array[
          'employee', 'relation', 'previousAuthorizationEpoch',
          'resultingAuthorizationEpoch', 'invalidations',
          'authorizationDecisionRefs'
        ]::text[])
        or (recipient_row - array[
          'employee', 'relation', 'previousAuthorizationEpoch',
          'resultingAuthorizationEpoch', 'invalidations',
          'authorizationDecisionRefs'
        ]::text[]) <> '{}'::jsonb
        or jsonb_typeof(recipient_row->'employee') <> 'object'
        or not (recipient_row->'employee' ?&
          array['tenantId', 'kind', 'id']::text[])
        or ((recipient_row->'employee') -
          array['tenantId', 'kind', 'id']::text[]) <>
          '{}'::jsonb
        or jsonb_typeof(recipient_row->'employee'->'tenantId') <> 'string'
        or recipient_row->'employee'->>'tenantId' <> new.tenant_id
        or jsonb_typeof(recipient_row->'employee'->'kind') <> 'string'
        or recipient_row->'employee'->>'kind' <> 'employee'
        or jsonb_typeof(recipient_row->'employee'->'id') <> 'string'
        or char_length(recipient_row->'employee'->>'id') not between 1 and 256
        or recipient_row->'employee'->>'id' !~
          '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
        or jsonb_typeof(recipient_row->'relation') <> 'string'
        or recipient_row->>'relation' not in ('previous', 'resulting', 'both')
        or jsonb_typeof(
          recipient_row->'previousAuthorizationEpoch'
        ) <> 'string'
        or char_length(recipient_row->>'previousAuthorizationEpoch')
          not between 8 and 1024
        or jsonb_typeof(
          recipient_row->'resultingAuthorizationEpoch'
        ) <> 'string'
        or char_length(recipient_row->>'resultingAuthorizationEpoch')
          not between 8 and 1024
        or recipient_row->>'previousAuthorizationEpoch' =
          recipient_row->>'resultingAuthorizationEpoch'
        or jsonb_typeof(recipient_row->'invalidations') <> 'array'
        or (case when jsonb_typeof(recipient_row->'invalidations') = 'array'
          then jsonb_array_length(recipient_row->'invalidations')
            not between 1 and 64 else true end)
        or not public.inbox_v2_auth_json_tenant_safe(
          recipient_row->'invalidations', new.tenant_id
        )
        or not public.inbox_v2_auth_invalidations_safe(
          recipient_row->'invalidations', new.tenant_id, 64
        )
        or not public.inbox_v2_auth_decision_refs_safe(
          recipient_row->'authorizationDecisionRefs',
          new.tenant_id,
          new.committed_at,
          false
        )
        or not exists (
          select 1 from public.employees employee_row
           where employee_row.tenant_id = new.tenant_id
             and employee_row.id = recipient_row->'employee'->>'id'
        );
    if v_invalid_count <> 0 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_direct_recipient_invalid';
    end if;

    select count(*)::integer into v_invalid_count
      from jsonb_array_elements(
        v_stream.audience_impact_manifest->'affectedRecipients'
      ) recipient_row
     where exists (
       select 1
         from jsonb_array_elements(
           recipient_row->'authorizationDecisionRefs'
         ) decision_ref
        where decision_ref->>'authorizationEpoch' <>
            recipient_row->>'resultingAuthorizationEpoch'
           or decision_ref->'principal'->>'kind' <> 'employee'
           or decision_ref->'principal'->'employee'->>'tenantId' <>
             new.tenant_id
           or decision_ref->'principal'->'employee'->>'id' <>
             recipient_row->'employee'->>'id'
     )
        or case recipient_row->>'relation'
          when 'previous' then
            not exists (
              select 1
                from jsonb_array_elements(
                  recipient_row->'authorizationDecisionRefs'
                ) decision_ref
               where decision_ref->>'outcome' = 'denied'
            ) or exists (
              select 1
                from jsonb_array_elements(
                  recipient_row->'authorizationDecisionRefs'
                ) decision_ref
               where decision_ref->>'outcome' = 'allowed'
            )
          when 'resulting' then
            not exists (
              select 1
                from jsonb_array_elements(
                  recipient_row->'authorizationDecisionRefs'
                ) decision_ref
               where decision_ref->>'outcome' = 'allowed'
            ) or exists (
              select 1
                from jsonb_array_elements(
                  recipient_row->'authorizationDecisionRefs'
                ) decision_ref
               where decision_ref->>'outcome' = 'denied'
            )
          when 'both' then
            not exists (
              select 1
                from jsonb_array_elements(
                  recipient_row->'authorizationDecisionRefs'
                ) decision_ref
               where decision_ref->>'outcome' = 'allowed'
            )
          else true
        end
        or (
          exists (
            select 1
              from jsonb_array_elements(
                recipient_row->'authorizationDecisionRefs'
              ) decision_ref
             where decision_ref->>'outcome' = 'denied'
          ) and not exists (
            select 1
              from jsonb_array_elements(
                recipient_row->'invalidations'
              ) invalidation
             where invalidation->>'kind' = 'recipient_scope'
          )
        );
    if v_invalid_count <> 0 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_direct_recipient_relation_invalid';
    end if;

    select count(*)::integer - count(distinct
             recipient_row->'employee'->>'id')::integer
      into v_invalid_count
      from jsonb_array_elements(
        v_stream.audience_impact_manifest->'affectedRecipients'
      ) recipient_row;
    if v_invalid_count <> 0 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_direct_recipient_duplicate';
    end if;

    select coalesce((
      select to_jsonb(array_agg(
        recipient_row.value->'employee'->>'id'
        order by recipient_row.ordinal
      ))
        from jsonb_array_elements(
          v_stream.audience_impact_manifest->'affectedRecipients'
        ) with ordinality recipient_row(value, ordinal)
    ), '[]'::jsonb) is distinct from coalesce((
      select to_jsonb(array_agg(
        effect_row.employee_id order by effect_row.ordinal
      ))
        from public.inbox_v2_auth_revision_effects effect_row
       where effect_row.tenant_id = new.tenant_id
         and effect_row.mutation_id = new.mutation_id
         and effect_row.effect_kind in (
           'employee_access', 'employee_inbox_relation'
         )
    ), '[]'::jsonb) into v_closed;
    if v_closed then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_direct_recipient_set_mismatch';
    end if;
  end if;

  select stream_head.last_position = v_stream.position
         and stream_head.stream_epoch = v_stream.stream_epoch
         and stream_head.updated_at = new.committed_at
    into v_closed
    from public.inbox_v2_tenant_stream_heads stream_head
   where stream_head.tenant_id = new.tenant_id;
  if not coalesce(v_closed, false) then
    raise exception using errcode = '40001',
      message = 'inbox_v2.authorization_stream_head_not_closed';
  end if;

  v_mutation_manifest_digest := 'sha256:' || encode(sha256(convert_to(
    'effects:' || v_effect_digest || chr(10) ||
    'relations:' || v_relation_digest || chr(10) ||
    'stream:' || v_stream.commit_hash || chr(10) ||
    'audit:' || v_audit.audit_hash,
    'UTF8'
  )), 'hex');
  if v_mutation_manifest_digest <> new.manifest_digest_sha256 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_mutation_digest_mismatch';
  end if;
  return null;
exception
  when no_data_found or too_many_rows then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_mutation_parent_incomplete';
end;
$_$;



--
-- Name: inbox_v2_auth_payload_reference_safe(jsonb, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_payload_reference_safe(checked_value jsonb, checked_tenant_id text) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
  select checked_value is null or (
    jsonb_typeof(checked_value) = 'object'
    and checked_value ?&
      array['tenantId', 'recordId', 'schemaId', 'schemaVersion', 'digest']::text[]
    and (checked_value -
      array['tenantId', 'recordId', 'schemaId', 'schemaVersion', 'digest']::text[]) =
        '{}'::jsonb
    and jsonb_typeof(checked_value->'tenantId') = 'string'
    and checked_value->>'tenantId' = checked_tenant_id
    and jsonb_typeof(checked_value->'recordId') = 'string'
    and char_length(checked_value->>'recordId') between 1 and 512
    and checked_value->>'recordId' ~ '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'
    and jsonb_typeof(checked_value->'schemaId') = 'string'
    and public.inbox_v2_auth_catalog_id_safe(checked_value->>'schemaId')
    and jsonb_typeof(checked_value->'schemaVersion') = 'string'
    and char_length(checked_value->>'schemaVersion') between 1 and 64
    and checked_value->>'schemaVersion' ~
      '^[A-Za-z0-9][A-Za-z0-9._~-]*$'
    and jsonb_typeof(checked_value->'digest') = 'string'
    and checked_value->>'digest' ~ '^sha256:[0-9a-f]{64}$'
  );
$_$;



--
-- Name: inbox_v2_auth_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    if current_user = 'hulee_inbox_v2_retention_owner'
       and pg_catalog.current_setting(
         'hulee.inbox_v2_retention_prune', true
       ) = 'enabled'
       and tg_table_name in (
         'inbox_v2_tenant_stream_changes',
         'inbox_v2_domain_events',
         'inbox_v2_outbox_intents'
       ) then
      return old;
    end if;
  end if;
  raise exception using
    errcode = '23514',
    message = format('inbox_v2.authorization_immutable:%s:%s', tg_table_name, tg_op);
end;
$$;



--
-- Name: inbox_v2_auth_relation_version_commit_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_relation_version_commit_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_closed boolean := false;
  v_command_actor_kind public.inbox_v2_auth_actor_kind;
  v_command_actor_employee_id text;
  v_command_actor_trusted_service_id text;
  v_mutation_committed_at timestamptz;
begin
  select
    command_row.actor_kind,
    command_row.actor_employee_id,
    command_row.actor_trusted_service_id,
    mutation_row.committed_at
    into
      v_command_actor_kind,
      v_command_actor_employee_id,
      v_command_actor_trusted_service_id,
      v_mutation_committed_at
    from public.inbox_v2_auth_mutation_commits mutation_row
    join public.inbox_v2_auth_command_records command_row
      on command_row.tenant_id = mutation_row.tenant_id
     and command_row.id = mutation_row.command_record_id
     and command_row.mutation_id = mutation_row.mutation_id
   where mutation_row.tenant_id = new.tenant_id
     and mutation_row.mutation_id = new.mutation_id;

  if not found then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_relation_version_orphan';
  end if;

  if row(
    new.actor_kind,
    new.actor_employee_id,
    new.actor_trusted_service_id
  ) is distinct from row(
    v_command_actor_kind,
    v_command_actor_employee_id,
    v_command_actor_trusted_service_id
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_relation_actor_mismatch';
  end if;

  if new.occurred_at is distinct from v_mutation_committed_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_relation_occurred_at_mismatch';
  end if;

  case tg_table_name
    when 'inbox_v2_auth_role_versions' then
      select exists (
        select 1
          from public.inbox_v2_auth_role_heads head_row
          join public.inbox_v2_auth_relation_writes write_row
            on write_row.tenant_id = head_row.tenant_id
           and write_row.mutation_id = new.mutation_id
           and write_row.relation_kind = 'role'
           and write_row.role_id = new.role_id
           and write_row.resulting_revision = new.revision
           and write_row.previous_revision is not distinct from case
             when new.revision = 1 then null::bigint else new.revision - 1
           end
          join public.inbox_v2_auth_mutation_commits mutation_row
            on mutation_row.tenant_id = write_row.tenant_id
           and mutation_row.mutation_id = write_row.mutation_id
         where head_row.tenant_id = new.tenant_id
           and head_row.role_id = new.role_id
           and head_row.current_revision = new.revision
      ) into v_closed;
    when 'inbox_v2_auth_role_binding_versions' then
      select exists (
        select 1
          from public.inbox_v2_auth_role_binding_heads head_row
          join public.inbox_v2_auth_relation_writes write_row
            on write_row.tenant_id = head_row.tenant_id
           and write_row.mutation_id = new.mutation_id
           and write_row.relation_kind = 'role_binding'
           and write_row.role_binding_id = new.binding_id
           and write_row.resulting_revision = new.revision
           and write_row.previous_revision is not distinct from case
             when new.revision = 1 then null::bigint else new.revision - 1
           end
          join public.inbox_v2_auth_mutation_commits mutation_row
            on mutation_row.tenant_id = write_row.tenant_id
           and mutation_row.mutation_id = write_row.mutation_id
         where head_row.tenant_id = new.tenant_id
           and head_row.binding_id = new.binding_id
           and head_row.current_revision = new.revision
      ) into v_closed;
    when 'inbox_v2_auth_direct_grant_versions' then
      select exists (
        select 1
          from public.inbox_v2_auth_direct_grant_heads head_row
          join public.inbox_v2_auth_relation_writes write_row
            on write_row.tenant_id = head_row.tenant_id
           and write_row.mutation_id = new.mutation_id
           and write_row.relation_kind = 'direct_grant'
           and write_row.direct_grant_id = new.grant_id
           and write_row.resulting_revision = new.revision
           and write_row.previous_revision is not distinct from case
             when new.revision = 1 then null::bigint else new.revision - 1
           end
          join public.inbox_v2_auth_mutation_commits mutation_row
            on mutation_row.tenant_id = write_row.tenant_id
           and mutation_row.mutation_id = write_row.mutation_id
         where head_row.tenant_id = new.tenant_id
           and head_row.grant_id = new.grant_id
           and head_row.current_revision = new.revision
      ) into v_closed;
    when 'inbox_v2_auth_workforce_membership_versions' then
      select exists (
        select 1
          from public.inbox_v2_auth_workforce_membership_heads head_row
          join public.inbox_v2_auth_relation_writes write_row
            on write_row.tenant_id = head_row.tenant_id
           and write_row.mutation_id = new.mutation_id
           and write_row.relation_kind = 'workforce_membership'
           and write_row.workforce_membership_id = new.membership_id
           and write_row.resulting_revision = new.revision
           and write_row.previous_revision is not distinct from case
             when new.revision = 1 then null::bigint else new.revision - 1
           end
          join public.inbox_v2_auth_mutation_commits mutation_row
            on mutation_row.tenant_id = write_row.tenant_id
           and mutation_row.mutation_id = write_row.mutation_id
         where head_row.tenant_id = new.tenant_id
           and head_row.membership_id = new.membership_id
           and head_row.current_revision = new.revision
      ) into v_closed;
    when 'inbox_v2_auth_structural_access_versions' then
      select exists (
        select 1
          from public.inbox_v2_auth_structural_access_heads head_row
          join public.inbox_v2_auth_relation_writes write_row
            on write_row.tenant_id = head_row.tenant_id
           and write_row.mutation_id = new.mutation_id
           and write_row.relation_kind = 'structural_access'
           and write_row.structural_access_binding_id = new.binding_id
           and write_row.resulting_revision = new.revision
           and write_row.previous_revision is not distinct from case
             when new.revision = 1 then null::bigint else new.revision - 1
           end
          join public.inbox_v2_auth_mutation_commits mutation_row
            on mutation_row.tenant_id = write_row.tenant_id
           and mutation_row.mutation_id = write_row.mutation_id
         where head_row.tenant_id = new.tenant_id
           and head_row.binding_id = new.binding_id
           and head_row.current_revision = new.revision
      ) into v_closed;
    when 'inbox_v2_auth_collaborator_versions' then
      select exists (
        select 1
          from public.inbox_v2_auth_collaborator_heads head_row
          join public.inbox_v2_auth_relation_writes write_row
            on write_row.tenant_id = head_row.tenant_id
           and write_row.mutation_id = new.mutation_id
           and write_row.relation_kind = case new.resource_kind
             when 'conversation' then
               'conversation_collaborator'::public.inbox_v2_auth_relation_kind
             else 'work_item_collaborator'::public.inbox_v2_auth_relation_kind
           end
           and write_row.collaborator_id = new.collaborator_id
           and write_row.resulting_revision = new.revision
           and write_row.previous_revision is not distinct from case
             when new.revision = 1 then null::bigint else new.revision - 1
           end
          join public.inbox_v2_auth_mutation_commits mutation_row
            on mutation_row.tenant_id = write_row.tenant_id
           and mutation_row.mutation_id = write_row.mutation_id
         where head_row.tenant_id = new.tenant_id
           and head_row.collaborator_id = new.collaborator_id
           and head_row.current_revision = new.revision
      ) into v_closed;
  end case;

  if not coalesce(v_closed, false) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_relation_version_orphan';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_auth_relation_version_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_relation_version_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_current_revision bigint;
  v_head_found boolean := false;
  v_previous jsonb;
  v_incoming jsonb := to_jsonb(new);
  v_identity_matches boolean := true;
  v_temporal boolean := false;
begin
  case tg_table_name
    when 'inbox_v2_auth_role_versions' then
      select head_row.current_revision into v_current_revision
        from public.inbox_v2_auth_role_heads head_row
       where head_row.tenant_id = new.tenant_id
         and head_row.role_id = new.role_id
       for update;
      v_head_found := found;
    when 'inbox_v2_auth_role_binding_versions' then
      v_temporal := true;
      select head_row.current_revision into v_current_revision
        from public.inbox_v2_auth_role_binding_heads head_row
       where head_row.tenant_id = new.tenant_id
         and head_row.binding_id = new.binding_id
       for update;
      v_head_found := found;
      perform 1
        from public.inbox_v2_auth_role_heads role_head
       where role_head.tenant_id = new.tenant_id
         and role_head.role_id = new.role_id
         and role_head.current_revision = new.role_revision_observed
       for share;
      if not found then
        raise exception using errcode = '40001',
          message = 'inbox_v2.authorization_role_observation_stale';
      end if;
    when 'inbox_v2_auth_direct_grant_versions' then
      v_temporal := true;
      select head_row.current_revision into v_current_revision
        from public.inbox_v2_auth_direct_grant_heads head_row
       where head_row.tenant_id = new.tenant_id
         and head_row.grant_id = new.grant_id
       for update;
      v_head_found := found;
    when 'inbox_v2_auth_workforce_membership_versions' then
      v_temporal := true;
      select head_row.current_revision into v_current_revision
        from public.inbox_v2_auth_workforce_membership_heads head_row
       where head_row.tenant_id = new.tenant_id
         and head_row.membership_id = new.membership_id
       for update;
      v_head_found := found;
    when 'inbox_v2_auth_structural_access_versions' then
      v_temporal := true;
      select head_row.current_revision into v_current_revision
        from public.inbox_v2_auth_structural_access_heads head_row
       where head_row.tenant_id = new.tenant_id
         and head_row.binding_id = new.binding_id
       for update;
      v_head_found := found;
      perform 1
        from public.inbox_v2_auth_resource_heads resource_head
       where resource_head.tenant_id = new.tenant_id
         and resource_head.id = new.resource_head_id
         and row(
           resource_head.resource_kind,
           resource_head.conversation_id,
           resource_head.client_id,
           resource_head.source_account_id
         ) is not distinct from row(
           new.resource_kind,
           new.conversation_id,
           new.client_id,
           new.source_account_id
         )
       for share;
      if not found then
        raise exception using errcode = '23514',
          message = 'inbox_v2.authorization_structural_resource_mismatch';
      end if;
    when 'inbox_v2_auth_collaborator_versions' then
      v_temporal := true;
      select head_row.current_revision into v_current_revision
        from public.inbox_v2_auth_collaborator_heads head_row
       where head_row.tenant_id = new.tenant_id
         and head_row.collaborator_id = new.collaborator_id
       for update;
      v_head_found := found;
    else
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_version_guard_table_invalid';
  end case;

  if new.revision = 1 then
    if v_head_found then
      raise exception using errcode = '40001',
        message = 'inbox_v2.authorization_version_cas_conflict';
    end if;
  elsif not v_head_found or v_current_revision <> new.revision - 1 then
    raise exception using errcode = '40001',
      message = 'inbox_v2.authorization_version_cas_conflict';
  end if;

  if not v_head_found then
    if v_temporal and v_incoming->>'state' <> 'active' then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_initial_relation_state_invalid';
    end if;
    return new;
  end if;

  case tg_table_name
    when 'inbox_v2_auth_role_versions' then
      select to_jsonb(version_row) into strict v_previous
        from public.inbox_v2_auth_role_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.role_id = new.role_id
         and version_row.revision = v_current_revision;
    when 'inbox_v2_auth_role_binding_versions' then
      select to_jsonb(version_row) into strict v_previous
        from public.inbox_v2_auth_role_binding_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.binding_id = new.binding_id
         and version_row.revision = v_current_revision;
      v_identity_matches := jsonb_build_array(
        v_previous->'role_id',
        v_previous->'subject_kind',
        v_previous->'subject_employee_id',
        v_previous->'subject_team_id',
        v_previous->'subject_org_unit_id',
        v_previous->'subject_work_queue_id',
        v_previous->'scope_kind',
        v_previous->'scope_org_unit_mode',
        v_previous->'scope_org_unit_id',
        v_previous->'scope_team_id',
        v_previous->'scope_work_queue_id',
        v_previous->'scope_client_id',
        v_previous->'scope_conversation_id',
        v_previous->'scope_work_item_id',
        v_previous->'scope_source_account_id',
        v_previous->'valid_from'
      ) = jsonb_build_array(
        v_incoming->'role_id',
        v_incoming->'subject_kind',
        v_incoming->'subject_employee_id',
        v_incoming->'subject_team_id',
        v_incoming->'subject_org_unit_id',
        v_incoming->'subject_work_queue_id',
        v_incoming->'scope_kind',
        v_incoming->'scope_org_unit_mode',
        v_incoming->'scope_org_unit_id',
        v_incoming->'scope_team_id',
        v_incoming->'scope_work_queue_id',
        v_incoming->'scope_client_id',
        v_incoming->'scope_conversation_id',
        v_incoming->'scope_work_item_id',
        v_incoming->'scope_source_account_id',
        v_incoming->'valid_from'
      );
    when 'inbox_v2_auth_direct_grant_versions' then
      select to_jsonb(version_row) into strict v_previous
        from public.inbox_v2_auth_direct_grant_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.grant_id = new.grant_id
         and version_row.revision = v_current_revision;
      v_identity_matches := jsonb_build_array(
        v_previous->'employee_id',
        v_previous->'catalog_schema_id',
        v_previous->'catalog_schema_version',
        v_previous->'catalog_digest_sha256',
        v_previous->'permission_id',
        v_previous->'scope_kind',
        v_previous->'scope_org_unit_mode',
        v_previous->'scope_org_unit_id',
        v_previous->'scope_team_id',
        v_previous->'scope_work_queue_id',
        v_previous->'scope_client_id',
        v_previous->'scope_conversation_id',
        v_previous->'scope_work_item_id',
        v_previous->'scope_source_account_id',
        v_previous->'valid_from'
      ) = jsonb_build_array(
        v_incoming->'employee_id',
        v_incoming->'catalog_schema_id',
        v_incoming->'catalog_schema_version',
        v_incoming->'catalog_digest_sha256',
        v_incoming->'permission_id',
        v_incoming->'scope_kind',
        v_incoming->'scope_org_unit_mode',
        v_incoming->'scope_org_unit_id',
        v_incoming->'scope_team_id',
        v_incoming->'scope_work_queue_id',
        v_incoming->'scope_client_id',
        v_incoming->'scope_conversation_id',
        v_incoming->'scope_work_item_id',
        v_incoming->'scope_source_account_id',
        v_incoming->'valid_from'
      );
    when 'inbox_v2_auth_workforce_membership_versions' then
      select to_jsonb(version_row) into strict v_previous
        from public.inbox_v2_auth_workforce_membership_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.membership_id = new.membership_id
         and version_row.revision = v_current_revision;
      v_identity_matches := jsonb_build_array(
        v_previous->'employee_id',
        v_previous->'membership_kind',
        v_previous->'org_unit_id',
        v_previous->'team_id',
        v_previous->'work_queue_id',
        v_previous->'valid_from'
      ) = jsonb_build_array(
        v_incoming->'employee_id',
        v_incoming->'membership_kind',
        v_incoming->'org_unit_id',
        v_incoming->'team_id',
        v_incoming->'work_queue_id',
        v_incoming->'valid_from'
      );
    when 'inbox_v2_auth_structural_access_versions' then
      select to_jsonb(version_row) into strict v_previous
        from public.inbox_v2_auth_structural_access_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.binding_id = new.binding_id
         and version_row.revision = v_current_revision;
      v_identity_matches := jsonb_build_array(
        v_previous->'resource_head_id',
        v_previous->'resource_kind',
        v_previous->'conversation_id',
        v_previous->'client_id',
        v_previous->'source_account_id',
        v_previous->'target_kind',
        v_previous->'target_org_unit_id',
        v_previous->'target_team_id',
        v_previous->'policy_id',
        v_previous->'policy_revision',
        v_previous->'valid_from'
      ) = jsonb_build_array(
        v_incoming->'resource_head_id',
        v_incoming->'resource_kind',
        v_incoming->'conversation_id',
        v_incoming->'client_id',
        v_incoming->'source_account_id',
        v_incoming->'target_kind',
        v_incoming->'target_org_unit_id',
        v_incoming->'target_team_id',
        v_incoming->'policy_id',
        v_incoming->'policy_revision',
        v_incoming->'valid_from'
      );
    when 'inbox_v2_auth_collaborator_versions' then
      select to_jsonb(version_row) into strict v_previous
        from public.inbox_v2_auth_collaborator_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.collaborator_id = new.collaborator_id
         and version_row.revision = v_current_revision;
      v_identity_matches := jsonb_build_array(
        v_previous->'resource_kind',
        v_previous->'conversation_id',
        v_previous->'work_item_id',
        v_previous->'work_item_cycle',
        v_previous->'employee_id',
        v_previous->'valid_from'
      ) = jsonb_build_array(
        v_incoming->'resource_kind',
        v_incoming->'conversation_id',
        v_incoming->'work_item_id',
        v_incoming->'work_item_cycle',
        v_incoming->'employee_id',
        v_incoming->'valid_from'
      );
  end case;

  if (v_incoming->>'occurred_at')::timestamptz <
     (v_previous->>'occurred_at')::timestamptz then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_version_time_regression';
  end if;

  if v_temporal then
    if not v_identity_matches then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_relation_identity_morph';
    end if;
    if v_previous->>'state' <> 'active'
       or v_incoming->>'state' not in ('revoked', 'archived') then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_relation_state_transition_invalid';
    end if;
    if v_incoming->>'valid_until' is distinct from
       v_previous->>'valid_until' then
      raise exception using errcode = '23514',
        message = 'inbox_v2.authorization_relation_interval_morph';
    end if;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_auth_role_permission_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_role_permission_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_role_id text;
  v_role_revision bigint;
  v_expected_count integer;
  v_expected_digest text;
  v_actual_count integer;
  v_min_ordinal integer;
  v_max_ordinal integer;
  v_sorted_contiguous boolean;
  v_actual_digest text;
begin
  v_tenant_id := coalesce(to_jsonb(new)->>'tenant_id', to_jsonb(old)->>'tenant_id');
  v_role_id := coalesce(to_jsonb(new)->>'role_id', to_jsonb(old)->>'role_id');
  v_role_revision := coalesce(
    (to_jsonb(new)->>'role_revision')::bigint,
    (to_jsonb(new)->>'revision')::bigint,
    (to_jsonb(old)->>'role_revision')::bigint,
    (to_jsonb(old)->>'revision')::bigint
  );

  select version_row.permission_count,
         version_row.permission_set_digest_sha256
    into v_expected_count, v_expected_digest
    from public.inbox_v2_auth_role_versions version_row
   where version_row.tenant_id = v_tenant_id
     and version_row.role_id = v_role_id
     and version_row.revision = v_role_revision;
  if not found then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = v_tenant_id
    ) then return null; end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_role_permission_version_missing';
  end if;

  select count(*)::integer,
         min(permission_row.ordinal)::integer,
         max(permission_row.ordinal)::integer,
         coalesce(bool_and(permission_row.ordinal = permission_row.sorted_ordinal), false),
         'sha256:' || encode(sha256(convert_to(coalesce(string_agg(
           permission_row.ordinal::text || ':' ||
           octet_length(permission_row.permission_id)::text || ':' ||
           permission_row.permission_id,
           chr(10) order by permission_row.ordinal
         ), ''), 'UTF8')), 'hex')
    into v_actual_count, v_min_ordinal, v_max_ordinal,
         v_sorted_contiguous, v_actual_digest
    from (
      select permission_row.*,
             row_number() over (order by permission_row.permission_id)::integer
               as sorted_ordinal
        from public.inbox_v2_auth_role_version_permissions permission_row
       where permission_row.tenant_id = v_tenant_id
         and permission_row.role_id = v_role_id
         and permission_row.role_revision = v_role_revision
    ) permission_row;

  if v_actual_count <> v_expected_count
     or v_min_ordinal <> 1
     or v_max_ordinal <> v_expected_count
     or not v_sorted_contiguous
     or v_actual_digest <> v_expected_digest then
    raise exception using errcode = '23514',
      message = 'inbox_v2.authorization_role_permission_manifest_incomplete';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_auth_stream_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_auth_stream_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then return old; end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.tenant_stream_head_delete_forbidden';
  end if;
  if tg_op = 'INSERT' then
    if new.last_position <> 0 or new.min_retained_position <> 0
       or new.revision <> 1 or new.updated_at <> new.created_at then
      raise exception using errcode = '23514',
        message = 'inbox_v2.tenant_stream_head_initial_state_invalid';
    end if;
  elsif new.tenant_id is distinct from old.tenant_id
     or new.stream_epoch is distinct from old.stream_epoch
     or new.created_at is distinct from old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at
     or not (
       (
         new.last_position = old.last_position + 1
         and new.min_retained_position = old.min_retained_position
       ) or (
         new.last_position = old.last_position
         and new.min_retained_position > old.min_retained_position
         and new.min_retained_position <= new.last_position
         and current_user = 'hulee_inbox_v2_retention_owner'
         and pg_catalog.current_setting(
           'hulee.inbox_v2_retention_prune', true
         ) = 'enabled'
       )
     ) then
    raise exception using errcode = '40001',
      message = 'inbox_v2.tenant_stream_head_cas_conflict';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_check_account_identity_alias_trigger(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_check_account_identity_alias_trigger() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  snapshot_row record;
begin
  perform public.inbox_v2_assert_account_provisional_key(
    new.tenant_id,
    new.provisional_key_digest_sha256,
    new.canonical_source_account_id,
    new.provisional_source_connection_id,
    new.declaration_contract_id,
    new.declaration_contract_version,
    new.declaration_surface_id,
    new.provisional_connector_session_subject,
    new.provisional_observed_at
  );

  select *
    into snapshot_row
    from public.inbox_v2_source_account_identity_verified_snapshots
   where tenant_id = new.tenant_id
     and source_account_id = new.canonical_source_account_id
     and identity_revision = new.expected_account_identity_revision
     and account_generation = new.expected_account_generation
     and state = new.target_identity_state
     and canonical_key_digest_sha256 = new.canonical_key_digest_sha256;

  if not found
     or snapshot_row.source_connection_id
       is distinct from new.provisional_source_connection_id
     or snapshot_row.identity_declaration is distinct from new.identity_declaration
     or snapshot_row.canonical_realm_id is distinct from new.canonical_realm_id
     or snapshot_row.canonical_realm_version
       is distinct from new.canonical_realm_version
     or snapshot_row.canonicalization_version
       is distinct from new.canonicalization_version
     or snapshot_row.canonical_object_kind_id
       is distinct from new.canonical_object_kind_id
     or snapshot_row.canonical_scope_kind
       is distinct from new.canonical_scope_kind
     or snapshot_row.canonical_scope_source_connection_id
       is distinct from new.canonical_scope_source_connection_id
     or snapshot_row.canonical_scope_owner_key
       is distinct from new.canonical_scope_owner_key
     or snapshot_row.canonical_external_subject
       is distinct from new.canonical_external_subject then
    raise exception 'account alias differs from its immutable verified generation'
      using errcode = '23514';
  end if;

  perform 1
    from public.inbox_v2_source_account_identity_transitions transition_row
   where transition_row.tenant_id = new.tenant_id
     and transition_row.id = snapshot_row.transition_id
     and transition_row.source_account_id = new.canonical_source_account_id
     and transition_row.resulting_revision = new.expected_account_identity_revision
     and transition_row.resulting_account_generation =
       new.expected_account_generation
     and transition_row.provisional_key_digest_sha256 =
       new.provisional_key_digest_sha256
     and transition_row.provisional_observed_at = new.provisional_observed_at
     and transition_row.decision_actor_trusted_service_id =
       new.decision_actor_trusted_service_id
     and transition_row.decision_policy_id = new.decision_policy_id
     and transition_row.decision_policy_version = new.decision_policy_version
     and transition_row.decision_reason_code_id = new.decision_reason_code_id
     and transition_row.decision_verification_evidence_token =
       new.decision_verification_evidence_token
     and transition_row.decision_decided_at = new.decision_decided_at
     and transition_row.occurred_at = new.created_at;

  if not found then
    raise exception 'account alias does not match its exact verified transition'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_check_account_identity_conflict_trigger(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_check_account_identity_conflict_trigger() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if exists (
      select 1
        from public.inbox_v2_source_account_identity_conflicts
       where tenant_id = old.tenant_id
         and source_account_id = old.source_account_id
         and identity_revision = old.identity_revision
    ) then
      perform public.inbox_v2_assert_account_identity_conflict(
        old.tenant_id,
        old.source_account_id,
        old.identity_revision
      );
    end if;
    return old;
  end if;

  perform public.inbox_v2_assert_account_identity_conflict(
    new.tenant_id,
    new.source_account_id,
    new.identity_revision
  );
  return new;
end
$$;



