    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.state <> 'canonical_root'
     or new.next_client_id is not null
     or new.redirect_id is not null
     or new.maximum_inbound_depth <> 0
     or new.revision <> 1
     or new.last_graph_revision is not null then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_node_initial_state_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_client_merge_guard_node_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_client_merge_guard_node_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  redirect_row public.inbox_v2_client_merge_redirects%rowtype;
begin
  if new.tenant_id is distinct from old.tenant_id
     or new.client_id is distinct from old.client_id
     or new.last_graph_revision is null then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_node_identity_invalid';
  end if;

  select * into redirect_row
  from public.inbox_v2_client_merge_redirects event_row
  where event_row.tenant_id = new.tenant_id
    and event_row.resulting_graph_revision = new.last_graph_revision;
  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_node_event_missing';
  end if;

  if old.client_id = redirect_row.source_root_client_id then
    if row(
         old.state, old.next_client_id, old.redirect_id,
         old.maximum_inbound_depth, old.revision,
         old.last_graph_revision, old.updated_at
       ) is distinct from row(
         redirect_row.source_before_state,
         redirect_row.source_before_next_client_id,
         redirect_row.source_before_redirect_id,
         redirect_row.source_before_maximum_inbound_depth,
         redirect_row.source_before_revision,
         redirect_row.source_before_last_graph_revision,
         redirect_row.source_before_updated_at
       )
       or row(
         new.state, new.next_client_id, new.redirect_id,
         new.maximum_inbound_depth, new.revision,
         new.last_graph_revision, new.updated_at
       ) is distinct from row(
         redirect_row.source_after_state,
         redirect_row.source_after_next_client_id,
         redirect_row.source_after_redirect_id,
         redirect_row.source_after_maximum_inbound_depth,
         redirect_row.source_after_revision,
         redirect_row.source_after_last_graph_revision,
         redirect_row.source_after_updated_at
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.client_merge_source_projection_invalid';
    end if;
  elsif old.client_id = redirect_row.target_root_client_id then
    if row(
         old.state, old.next_client_id, old.redirect_id,
         old.maximum_inbound_depth, old.revision,
         old.last_graph_revision, old.updated_at
       ) is distinct from row(
         redirect_row.target_before_state,
         redirect_row.target_before_next_client_id,
         redirect_row.target_before_redirect_id,
         redirect_row.target_before_maximum_inbound_depth,
         redirect_row.target_before_revision,
         redirect_row.target_before_last_graph_revision,
         redirect_row.target_before_updated_at
       )
       or row(
         new.state, new.next_client_id, new.redirect_id,
         new.maximum_inbound_depth, new.revision,
         new.last_graph_revision, new.updated_at
       ) is distinct from row(
         redirect_row.target_after_state,
         redirect_row.target_after_next_client_id,
         redirect_row.target_after_redirect_id,
         redirect_row.target_after_maximum_inbound_depth,
         redirect_row.target_after_revision,
         redirect_row.target_after_last_graph_revision,
         redirect_row.target_after_updated_at
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.client_merge_target_projection_invalid';
    end if;
  else
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_node_event_edge_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_client_merge_guard_redirect_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_client_merge_guard_redirect_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_row public.inbox_v2_client_merge_graph_heads%rowtype;
  locked_row public.inbox_v2_client_merge_node_states%rowtype;
  source_row public.inbox_v2_client_merge_node_states%rowtype;
  target_row public.inbox_v2_client_merge_node_states%rowtype;
begin
  select * into head_row
  from public.inbox_v2_client_merge_graph_heads current_head
  where current_head.tenant_id = new.tenant_id
  for update;
  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.client_merge_head_missing';
  end if;

  for locked_row in
    select *
    from public.inbox_v2_client_merge_node_states node_row
    where node_row.tenant_id = new.tenant_id
      and node_row.client_id in (
        new.source_root_client_id,
        new.target_root_client_id
      )
    order by node_row.client_id collate "C"
    for update
  loop
    if locked_row.client_id = new.source_root_client_id then
      source_row := locked_row;
    elsif locked_row.client_id = new.target_root_client_id then
      target_row := locked_row;
    end if;
  end loop;

  if source_row.client_id is null or target_row.client_id is null then
    raise exception using
      errcode = '23503',
      message = 'inbox_v2.client_merge_root_missing';
  end if;
  if head_row.revision is distinct from new.current_graph_revision
     or head_row.updated_at is distinct from new.head_before_updated_at then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.client_merge_graph_revision_conflict';
  end if;
  if row(
       source_row.state,
       source_row.next_client_id,
       source_row.redirect_id,
       source_row.maximum_inbound_depth,
       source_row.revision,
       source_row.last_graph_revision,
       source_row.updated_at
     ) is distinct from row(
       new.source_before_state,
       new.source_before_next_client_id,
       new.source_before_redirect_id,
       new.source_before_maximum_inbound_depth,
       new.source_before_revision,
       new.source_before_last_graph_revision,
       new.source_before_updated_at
     )
     or row(
       target_row.state,
       target_row.next_client_id,
       target_row.redirect_id,
       target_row.maximum_inbound_depth,
       target_row.revision,
       target_row.last_graph_revision,
       target_row.updated_at
     ) is distinct from row(
       new.target_before_state,
       new.target_before_next_client_id,
       new.target_before_redirect_id,
       new.target_before_maximum_inbound_depth,
       new.target_before_revision,
       new.target_before_last_graph_revision,
       new.target_before_updated_at
     ) then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.client_merge_root_revision_conflict';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_client_merge_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_client_merge_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE'
     and tg_table_name = 'inbox_v2_client_merge_redirects'
     and not exists (
       select 1
       from public.tenants tenant_row
       where tenant_row.id = old.tenant_id
     ) then
    return old;
  end if;

  raise exception using
    errcode = '23514',
    message = format('inbox_v2.client_merge_immutable:%s:%s', tg_table_name, tg_op);
end;
$$;



--
-- Name: inbox_v2_conversation_client_link_assert_current_policy(text, public.inbox_v2_conversation_client_link_actor_kind, text, public.inbox_v2_tenant_policy_family, text, text, text, text, bigint, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_client_link_assert_current_policy(checked_tenant_id text, checked_actor_kind public.inbox_v2_conversation_client_link_actor_kind, checked_service_id text, checked_family public.inbox_v2_tenant_policy_family, checked_policy_id text, checked_policy_version text, checked_definition_contract_version text, checked_definition_digest_sha256 text, checked_activation_head_revision bigint, checked_occurred_at timestamp with time zone) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_row public.inbox_v2_tenant_policy_activation_heads%rowtype;
begin
  if checked_actor_kind <> 'trusted_service' then
    return;
  end if;
  select * into head_row
    from public.inbox_v2_tenant_policy_activation_heads candidate
   where candidate.tenant_id = checked_tenant_id
     and candidate.family = checked_family
     and candidate.policy_id = checked_policy_id
   for share;
  if not found
     or head_row.state <> 'active'
     or head_row.policy_version <> checked_policy_version
     or head_row.definition_contract_version <>
       checked_definition_contract_version
     or head_row.definition_digest_sha256 <>
       checked_definition_digest_sha256
     or head_row.approved_trusted_service_id <> checked_service_id
     or head_row.revision <> checked_activation_head_revision
     or head_row.activated_at > checked_occurred_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_policy_not_current';
  end if;
end;
$$;



--
-- Name: inbox_v2_conversation_client_link_assert_employee_at(text, public.inbox_v2_conversation_client_link_actor_kind, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_client_link_assert_employee_at(checked_tenant_id text, checked_actor_kind public.inbox_v2_conversation_client_link_actor_kind, checked_employee_id text, checked_occurred_at timestamp with time zone) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  employee_created_at timestamptz;
  employee_deactivated_at timestamptz;
begin
  if checked_actor_kind <> 'employee' then
    return;
  end if;

  select employee_row.created_at, employee_row.deactivated_at
    into employee_created_at, employee_deactivated_at
    from public.employees employee_row
   where employee_row.tenant_id = checked_tenant_id
     and employee_row.id = checked_employee_id
   for share;
  if not found then
    raise exception using
      errcode = '23503',
      message = 'inbox_v2.conversation_client_link_employee_missing';
  end if;

  if employee_created_at > checked_occurred_at
     or (employee_deactivated_at is not null
         and employee_deactivated_at <= checked_occurred_at) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_employee_inactive';
  end if;
end;
$$;



--
-- Name: inbox_v2_conversation_client_link_assert_open_transition(text, text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_client_link_assert_open_transition(checked_tenant_id text, checked_conversation_id text, checked_transition_id text, checked_resulting_revision bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  transition_current_revision bigint;
  head_revision bigint;
  has_head boolean := false;
begin
  select transition_row.current_revision
    into transition_current_revision
    from public.inbox_v2_conversation_client_link_transitions transition_row
   where transition_row.tenant_id = checked_tenant_id
     and transition_row.id = checked_transition_id
     and transition_row.conversation_id = checked_conversation_id
     and transition_row.resulting_revision = checked_resulting_revision;
  if not found then
    raise exception using
      errcode = '23503',
      message = 'inbox_v2.conversation_client_link_transition_missing';
  end if;

  select head_row.revision
    into head_revision
    from public.inbox_v2_conversation_client_link_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id
   for update;
  has_head := found;

  if (transition_current_revision is null and has_head)
     or (transition_current_revision is not null and (
       not has_head or head_revision <> transition_current_revision
     )) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_transition_closed';
  end if;
end;
$$;



--
-- Name: inbox_v2_conversation_client_link_deferred_claim_revocation(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_client_link_deferred_claim_revocation() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.revoked_at is not null
     and new.revoked_at is distinct from old.revoked_at
     and exists (
       select 1
         from public.inbox_v2_conversation_client_links link_row
        where link_row.tenant_id = new.tenant_id
          and link_row.provenance_kind = 'source_identity_claim'
          and link_row.provenance_claim_id = new.id
          and link_row.provenance_claim_version = new.claim_version
          and link_row.valid_from > new.revoked_at
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_client_link_claim_revocation_precedes_link';
  end if;
  if new.revoked_at is distinct from old.revoked_at then
    perform public.inbox_v2_assert_conversation_client_link_episode(
      evidence_row.tenant_id,
      evidence_row.link_id
    )
      from (
        select distinct candidate.tenant_id, candidate.link_id
          from public.inbox_v2_conversation_client_link_evidence_references candidate
         where candidate.tenant_id = new.tenant_id
           and candidate.evidence_kind = 'source_identity_claim'
           and candidate.source_identity_claim_id = new.id
      ) evidence_row;
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_conversation_client_link_deferred_contact(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_client_link_deferred_contact() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.client_id is distinct from old.client_id then
    perform public.inbox_v2_assert_conversation_client_link_episode(
      affected_row.tenant_id,
      affected_row.link_id
    )
      from (
        select distinct evidence_row.tenant_id, evidence_row.link_id
          from public.inbox_v2_conversation_client_link_evidence_references evidence_row
         where evidence_row.tenant_id = new.tenant_id
           and (
             evidence_row.client_contact_id = new.id
             or evidence_row.source_identity_claim_id in (
               select claim_row.id
                 from public.inbox_v2_source_identity_claims claim_row
                where claim_row.tenant_id = new.tenant_id
                  and claim_row.target_client_contact_id = new.id
             )
           )
        union
        select link_row.tenant_id, link_row.id
          from public.inbox_v2_conversation_client_links link_row
         where link_row.tenant_id = new.tenant_id
           and link_row.provenance_claim_target_client_contact_id = new.id
      ) affected_row;
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_conversation_client_link_deferred_episode(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_client_link_deferred_episode() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_assert_conversation_client_link_episode(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.id, old.id)
  );
  return null;
end;
$$;



