CREATE FUNCTION public.inbox_v2_conversation_client_link_deferred_operation() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_assert_conversation_client_link_transition(
