-- Name: inbox_v2_conversation_client_link_deferred_transition(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_client_link_deferred_transition() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_assert_conversation_client_link_transition(
