--
-- Name: inbox_v2_conversation_update_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_update_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.created_at is distinct from old.created_at
     or new.revision <= old.revision
     or new.last_changed_stream_position <= old.last_changed_stream_position
     or new.updated_at < old.updated_at then
