--
-- Name: inbox_v2_conversation_work_head_advance(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_work_head_advance() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
DECLARE
  v_ordinal bigint;
BEGIN
  SELECT w.ordinal INTO STRICT v_ordinal
    FROM public.inbox_v2_work_items w
   WHERE w.tenant_id = new.tenant_id AND w.id = new.work_item_id;

  UPDATE public.inbox_v2_conversation_work_heads h
     SET work_item_count = h.work_item_count + 1,
         current_outcome = 'create_work_item',
         intake_decision_high_water = CASE
           WHEN h.pending_materialization_ordinal IS NULL
             THEN h.intake_decision_high_water + 1
           ELSE h.intake_decision_high_water
         END,
         pending_materialization_ordinal = NULL,
         revision = h.revision + CASE
           WHEN h.pending_materialization_ordinal IS NULL THEN 2
           ELSE 1
         END,
         updated_at = greatest(h.updated_at, new.decided_at)
   WHERE h.tenant_id = new.tenant_id
     AND h.conversation_id = new.conversation_id
     AND h.work_item_count = v_ordinal - 1
     AND (
       (h.pending_materialization_ordinal = v_ordinal
         AND h.current_outcome = 'create_work_item'
         AND h.intake_decision_high_water >= v_ordinal)
       OR h.pending_materialization_ordinal IS NULL
     )
     AND h.revision =
       1 + h.intake_decision_high_water + h.work_item_count;
  IF NOT found THEN
    RAISE EXCEPTION 'WorkItem creation lost its Conversation Work head race'
      USING errcode = '40001';
  END IF;
  RETURN new;
END
$$;



--
-- Name: inbox_v2_conversation_work_head_bootstrap(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_work_head_bootstrap() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
BEGIN
  INSERT INTO public.inbox_v2_conversation_work_heads (
    tenant_id,
    id,
    conversation_id,
    work_item_count,
    current_outcome,
    intake_decision_high_water,
    pending_materialization_ordinal,
    revision,
    created_at,
    updated_at
  ) VALUES (
    new.tenant_id,
    'conversation_work_head:' || encode(
      sha256((new.tenant_id || chr(31) || new.id)::bytea),
      'hex'
    ),
    new.id,
    0,
    'pending_intake',
    0,
    null,
    1,
    new.created_at,
    new.created_at
  ) ON CONFLICT DO NOTHING;
  RETURN new;
END
$$;



--
-- Name: inbox_v2_conversation_work_head_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_work_head_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
DECLARE
  v_tenant_id text;
  v_conversation_id text;
  v_head public.inbox_v2_conversation_work_heads%rowtype;
  v_work_item_count bigint;
  v_creation_count bigint;
BEGIN
  v_tenant_id := new.tenant_id;
  v_conversation_id := new.conversation_id;

  SELECT * INTO v_head
    FROM public.inbox_v2_conversation_work_heads h
   WHERE h.tenant_id = v_tenant_id
     AND h.conversation_id = v_conversation_id;
  IF NOT found THEN
    RAISE EXCEPTION 'Conversation requires one authoritative Work head'
      USING errcode = '23514';
  END IF;

  SELECT count(*) INTO v_work_item_count
    FROM public.inbox_v2_work_items w
   WHERE w.tenant_id = v_tenant_id
     AND w.conversation_id = v_conversation_id;
  SELECT count(*) INTO v_creation_count
    FROM public.inbox_v2_work_item_creation_decisions d
   WHERE d.tenant_id = v_tenant_id
     AND d.conversation_id = v_conversation_id;

  IF v_head.work_item_count <> v_work_item_count
     OR v_creation_count <> v_work_item_count
     OR v_head.intake_decision_high_water < v_creation_count
     OR v_head.pending_materialization_ordinal IS NOT NULL
     OR (v_work_item_count > 0
       AND v_head.current_outcome <> 'create_work_item') THEN
    RAISE EXCEPTION 'Conversation Work head is not coherent with intake materialization'
      USING errcode = '23514';
  END IF;
  RETURN null;
END
$$;



--
-- Name: inbox_v2_conversation_work_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_work_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
BEGIN
  IF tg_op = 'DELETE' THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.inbox_v2_conversations c
       WHERE c.tenant_id = old.tenant_id AND c.id = old.conversation_id
    ) THEN
      RETURN old;
    END IF;
    RAISE EXCEPTION 'Conversation Work head cannot be deleted'
      USING errcode = '23514';
  END IF;

  IF tg_op = 'INSERT' THEN
    IF new.work_item_count <> 0
       OR new.current_outcome <> 'pending_intake'
       OR new.intake_decision_high_water <> 0
       OR new.pending_materialization_ordinal IS NOT NULL
       OR new.revision <> 1 THEN
      RAISE EXCEPTION 'Conversation Work head must start pending at revision one'
        USING errcode = '23514';
    END IF;
  ELSIF new.tenant_id IS DISTINCT FROM old.tenant_id
     OR new.id IS DISTINCT FROM old.id
     OR new.conversation_id IS DISTINCT FROM old.conversation_id
     OR new.created_at IS DISTINCT FROM old.created_at
     OR new.updated_at < old.updated_at
     OR NOT (
       (
         new.work_item_count = old.work_item_count
         AND old.pending_materialization_ordinal IS NULL
         AND new.intake_decision_high_water =
            old.intake_decision_high_water + 1
         AND new.revision = old.revision + 1
         AND (
           (new.current_outcome = 'no_work_item'
             AND new.pending_materialization_ordinal IS NULL)
           OR (new.current_outcome = 'create_work_item'
             AND new.pending_materialization_ordinal =
                old.work_item_count + 1)
         )
       ) OR (
         old.current_outcome = 'create_work_item'
         AND new.current_outcome = 'create_work_item'
         AND new.work_item_count = old.work_item_count + 1
         AND new.intake_decision_high_water =
            old.intake_decision_high_water
         AND new.revision = old.revision + 1
         AND old.pending_materialization_ordinal = new.work_item_count
         AND new.pending_materialization_ordinal IS NULL
       ) OR (
         new.current_outcome = 'create_work_item'
         AND new.work_item_count = old.work_item_count + 1
         AND new.intake_decision_high_water =
            old.intake_decision_high_water + 1
         AND new.revision = old.revision + 2
         AND old.pending_materialization_ordinal IS NULL
         AND new.pending_materialization_ordinal IS NULL
       )
     ) THEN
    RAISE EXCEPTION 'Conversation Work head requires one intake or materialization advance'
      USING errcode = '23514';
  END IF;

  RETURN new;
END
$$;



--
-- Name: inbox_v2_conversation_work_item_slot_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_conversation_work_item_slot_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_conversation_id text;
  v_slot public.inbox_v2_conversation_work_item_slots%rowtype;
  v_latest public.inbox_v2_work_items%rowtype;
  v_max_ordinal bigint;
  v_min_ordinal bigint;
  v_work_item_count bigint;
  v_expected_fence_revision bigint;
  v_expected_slot_revision bigint;
  v_creation_count bigint;
  v_lifecycle_change_count bigint;
  v_expected_class public.inbox_v2_work_item_lifecycle_class;
  v_non_terminal_count bigint;
  v_non_terminal_id text;
  v_non_terminal_ordinal bigint;
begin
  v_tenant_id := new.tenant_id;
  if tg_table_name = 'inbox_v2_conversation_work_item_slots'
     or tg_table_name = 'inbox_v2_work_items' then
    v_conversation_id := new.conversation_id;
  else
    select w.conversation_id into v_conversation_id
      from public.inbox_v2_work_items w
     where w.tenant_id = new.tenant_id and w.id = new.work_item_id;
  end if;

  select * into v_slot
    from public.inbox_v2_conversation_work_item_slots s
   where s.tenant_id = v_tenant_id
     and s.conversation_id = v_conversation_id;
  if not found then
    raise exception 'Conversation with WorkItems requires one bootstrap slot'
      using errcode = '23514';
  end if;

  select count(*), min(w.ordinal), max(w.ordinal)
    into v_work_item_count, v_min_ordinal, v_max_ordinal
    from public.inbox_v2_work_items w
   where w.tenant_id = v_tenant_id
     and w.conversation_id = v_conversation_id;

  select count(*) into v_creation_count
    from public.inbox_v2_work_item_creation_decisions d
    join public.inbox_v2_work_items w
      on w.tenant_id = d.tenant_id and w.id = d.work_item_id
   where w.tenant_id = v_tenant_id
     and w.conversation_id = v_conversation_id;
  select count(*) into v_lifecycle_change_count
    from public.inbox_v2_work_item_transitions t
    join public.inbox_v2_work_items w
      on w.tenant_id = t.tenant_id and w.id = t.work_item_id
   where w.tenant_id = v_tenant_id
     and w.conversation_id = v_conversation_id
     and t.kind in (
       'close_resolved',
       'close_dismissed',
       'reopen_unassigned',
       'reopen_assigned'
     );
  v_expected_slot_revision :=
    1 + v_creation_count + v_lifecycle_change_count;
  if v_slot.revision <> v_expected_slot_revision then
    raise exception 'Conversation WorkItem slot revision is missing a create/close/reopen CAS'
      using errcode = '23514';
  end if;

  if v_max_ordinal is null then
    if v_slot.latest_ordinal <> 0
       or v_slot.latest_work_item_id is not null
       or v_slot.latest_lifecycle_class is not null
       or v_slot.latest_lifecycle_fence_revision is not null
       or v_slot.current_non_terminal_work_item_id is not null
       or v_slot.current_non_terminal_ordinal is not null then
      raise exception 'Never-work Conversation slot must remain empty'
        using errcode = '23514';
    end if;
    return null;
  end if;

  if v_min_ordinal <> 1 or v_work_item_count <> v_max_ordinal then
    raise exception 'Conversation WorkItem ordinals must be contiguous from one'
      using errcode = '23514';
  end if;

  select * into v_latest
    from public.inbox_v2_work_items w
   where w.tenant_id = v_tenant_id
     and w.conversation_id = v_conversation_id
     and w.ordinal = v_max_ordinal;
  select
    count(*),
    max(w.id),
    max(w.ordinal)
    into v_non_terminal_count, v_non_terminal_id, v_non_terminal_ordinal
    from public.inbox_v2_work_items w
   where w.tenant_id = v_tenant_id
     and w.conversation_id = v_conversation_id
     and w.state in ('new', 'assigned', 'in_progress', 'waiting');
  v_expected_class := case
    when v_latest.state in ('resolved', 'dismissed') then 'terminal'
    else 'non_terminal'
  end;
  select coalesce(max(t.resulting_revision), 1)
    into v_expected_fence_revision
    from public.inbox_v2_work_item_transitions t
   where t.tenant_id = v_latest.tenant_id
     and t.work_item_id = v_latest.id
     and t.kind in (
       'close_resolved',
       'close_dismissed',
       'reopen_unassigned',
       'reopen_assigned'
     );

  if v_slot.latest_ordinal <> v_latest.ordinal
     or v_slot.latest_work_item_id <> v_latest.id
     or v_slot.latest_lifecycle_class <> v_expected_class
     or v_slot.latest_lifecycle_fence_revision <> v_expected_fence_revision then
    raise exception 'Conversation WorkItem slot latest pointer is not the max ordinal lifecycle fence'
      using errcode = '23514';
  end if;

  if v_expected_class = 'non_terminal' then
    if v_non_terminal_count <> 1
       or v_non_terminal_id <> v_latest.id
       or v_non_terminal_ordinal <> v_latest.ordinal
       or v_slot.current_non_terminal_work_item_id <> v_latest.id
       or v_slot.current_non_terminal_ordinal <> v_latest.ordinal then
      raise exception 'Latest non-terminal WorkItem must occupy the current slot'
        using errcode = '23514';
    end if;
  elsif v_non_terminal_count <> 0
     or v_slot.current_non_terminal_work_item_id is not null
     or v_slot.current_non_terminal_ordinal is not null then
    raise exception 'Older WorkItem cannot become non-terminal behind a terminal latest slot'
      using errcode = '23514';
  end if;

  return null;
end
$$;



--
-- Name: inbox_v2_database_reset_receipt_immutable_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_database_reset_receipt_immutable_guard() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  raise exception using
    errcode = '23514',
    message = 'inbox_v2.database_reset_receipt_immutable';
end;
$$;



--
-- Name: inbox_v2_deferred_source_action_assert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_deferred_source_action_assert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  transition_row public.inbox_v2_deferred_message_source_action_transitions%rowtype;
  occurrence_row public.inbox_v2_source_occurrences%rowtype;
  related_action_row public.inbox_v2_deferred_message_source_actions%rowtype;
  related_transition_row public.inbox_v2_deferred_message_source_action_transitions%rowtype;
  candidate_count bigint;
  candidate_min smallint;
  candidate_max smallint;
begin
  if new.state = 'pending' then
    if exists (
      select 1
      from public.inbox_v2_deferred_message_source_action_transitions t
      where t.tenant_id = new.tenant_id and t.action_id = new.id
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_pending_has_transition';
    end if;
    return null;
  end if;

  select * into transition_row
  from public.inbox_v2_deferred_message_source_action_transitions candidate_row
  where candidate_row.tenant_id = new.tenant_id
    and candidate_row.action_id = new.id;

  if not found
     or transition_row.expected_revision <> new.revision - 1
     or transition_row.resulting_revision <> new.revision
     or transition_row.after_state <> new.state
     or transition_row.effect_kind is distinct from new.effect_kind
     or (new.state not in ('stale', 'duplicate') and (
       transition_row.target_external_message_reference_id is distinct from
         new.applied_external_message_reference_id
       or transition_row.target_message_id is distinct from
         new.applied_message_id
       or transition_row.applied_message_revision is distinct from
         new.applied_message_revision
       or transition_row.applied_provider_lifecycle_operation_id is distinct
         from new.applied_provider_lifecycle_operation_id
       or transition_row.applied_provider_lifecycle_operation_revision is
         distinct from new.applied_provider_lifecycle_operation_revision
      ))
     or transition_row.related_action_id is distinct from new.related_action_id
     or transition_row.reason_id is distinct from new.state_reason_id
     or transition_row.conflict_candidate_count <>
        new.conflict_candidate_count
     or transition_row.conflict_candidate_digest_sha256 is distinct from
        new.conflict_candidate_digest_sha256
     or transition_row.recorded_at <> new.updated_at then
    raise exception using
      errcode = '23514',
    message = 'inbox_v2.deferred_source_action_transition_mismatch';
  end if;

  if new.state in ('stale', 'duplicate')
     or (new.state = 'ordering_conflict'
       and new.ordering_kind = 'monotonic_exact') then
    if transition_row.related_action_id is null
       or transition_row.expected_ordering_head_revision is null
       or transition_row.resulting_ordering_head_revision <>
          transition_row.expected_ordering_head_revision
       or transition_row.ordering_head_scope_token is null
       or transition_row.ordering_head_comparator_id is null
       or transition_row.ordering_head_comparator_revision is null then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_historical_head_missing';
    end if;

    select * into related_action_row
    from public.inbox_v2_deferred_message_source_actions candidate_row
    where candidate_row.tenant_id = new.tenant_id
      and candidate_row.id = transition_row.related_action_id;

    if not found
       or related_action_row.state <> 'applied'
       or related_action_row.message_key_digest_sha256 <>
          new.message_key_digest_sha256
       or related_action_row.external_message_key_detail <>
          new.external_message_key_detail
       or related_action_row.lane <> new.lane
       or related_action_row.ordering_kind <> 'monotonic_exact'
       or related_action_row.ordering_scope_token <>
          transition_row.ordering_head_scope_token
       or related_action_row.ordering_comparator_id <>
          transition_row.ordering_head_comparator_id
       or related_action_row.ordering_comparator_revision <>
          transition_row.ordering_head_comparator_revision
       or new.ordering_scope_token <>
          transition_row.ordering_head_scope_token
       or new.ordering_comparator_id <>
          transition_row.ordering_head_comparator_id
       or new.ordering_comparator_revision <>
          transition_row.ordering_head_comparator_revision then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_historical_head_mismatch';
    end if;

    select * into related_transition_row
    from public.inbox_v2_deferred_message_source_action_transitions candidate_row
    where candidate_row.tenant_id = new.tenant_id
      and candidate_row.action_id = related_action_row.id;

    if not found
       or related_transition_row.after_state <> 'applied'
       or related_transition_row.ordering_outcome <> 'advance'
       or related_transition_row.resulting_ordering_head_revision <>
          transition_row.expected_ordering_head_revision
       or related_transition_row.ordering_head_scope_token <>
          transition_row.ordering_head_scope_token
       or related_transition_row.ordering_head_comparator_id <>
          transition_row.ordering_head_comparator_id
       or related_transition_row.ordering_head_comparator_revision <>
          transition_row.ordering_head_comparator_revision then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_historical_head_mismatch';
    end if;

    if new.state = 'stale' and not (
         char_length(related_action_row.ordering_position) >
           char_length(new.ordering_position)
         or (
           char_length(related_action_row.ordering_position) =
             char_length(new.ordering_position)
           and related_action_row.ordering_position collate "C" >
             new.ordering_position collate "C"
         )
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_stale_position_mismatch';
    elsif new.state = 'duplicate' and (
      related_action_row.ordering_position <> new.ordering_position
      or related_action_row.semantic_id <> new.semantic_id
      or related_action_row.event_fingerprint_sha256 <>
        new.event_fingerprint_sha256
      or row(
        related_action_row.normalized_inbound_event_id,
        related_action_row.source_occurrence_id,
        related_action_row.semantic_id,
        related_action_row.event_fingerprint_sha256
      ) is not distinct from row(
        new.normalized_inbound_event_id,
        new.source_occurrence_id,
        new.semantic_id,
        new.event_fingerprint_sha256
      )
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_duplicate_identity_mismatch';
    elsif new.state = 'ordering_conflict' and (
      related_action_row.ordering_position <> new.ordering_position
      or row(
        related_action_row.semantic_id,
        related_action_row.event_fingerprint_sha256
      ) is not distinct from row(
        new.semantic_id,
        new.event_fingerprint_sha256
      )
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_ordering_conflict_identity_mismatch';
    end if;
  end if;

  if transition_row.target_external_message_reference_id is not null
     and not exists (
       select 1
       from public.inbox_v2_external_message_references reference_row
       where reference_row.tenant_id = new.tenant_id
         and reference_row.id =
           transition_row.target_external_message_reference_id
         and reference_row.message_id = transition_row.target_message_id
         and reference_row.external_thread_id = new.external_thread_id
         and reference_row.realm_id = new.message_realm_id
         and reference_row.realm_version = new.message_realm_version
         and reference_row.canonicalization_version =
           new.message_canonicalization_version
         and reference_row.scope_kind = new.message_scope_kind
         and reference_row.scope_source_account_id is not distinct from
           new.message_scope_source_account_id
         and reference_row.scope_source_thread_binding_id is not distinct from
           new.message_scope_source_thread_binding_id
         and reference_row.object_kind_id = new.message_object_kind_id
         and reference_row.canonical_external_subject =
           new.canonical_external_subject
         and reference_row.message_key_digest_sha256 =
           new.message_key_digest_sha256
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_exact_target_mismatch';
  end if;

  if new.state = 'applied' and not exists (
    select 1
    from public.inbox_v2_message_revisions revision_row
    where revision_row.tenant_id = new.tenant_id
      and revision_row.message_id = new.applied_message_id
      and revision_row.message_revision = new.applied_message_revision
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_applied_revision_missing';
  end if;

  if new.state = 'applied'
     and new.effect_kind = 'message_lifecycle'
     and new.action_kind in ('edit', 'delete')
     and not exists (
       select 1
       from public.inbox_v2_message_revisions revision_row
       join public.inbox_v2_message_provider_lifecycle_operations operation_row
         on operation_row.tenant_id = revision_row.tenant_id
        and operation_row.id = revision_row.provider_operation_id
       where revision_row.tenant_id = new.tenant_id
         and revision_row.message_id = new.applied_message_id
         and revision_row.message_revision = new.applied_message_revision
         and revision_row.change_kind = case new.action_kind
           when 'edit' then 'edited'::public.inbox_v2_message_revision_change
           else 'provider_delete_policy_tombstone'::public.inbox_v2_message_revision_change
         end
         and operation_row.message_id = new.applied_message_id
         and operation_row.action::text = new.action_kind::text
         and operation_row.origin = 'provider_observed'
         and operation_row.source_occurrence_id = new.source_occurrence_id
         and operation_row.source_account_id = new.source_account_id
         and operation_row.source_thread_binding_id = new.source_thread_binding_id
         and operation_row.binding_generation = new.binding_generation
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_lifecycle_effect_mismatch';
  end if;

  if new.state = 'applied'
     and new.effect_kind = 'provider_delete_retain_local'
     and not exists (
       select 1
       from public.inbox_v2_message_provider_lifecycle_operations operation_row
       join public.inbox_v2_message_provider_lifecycle_transitions transition_effect
         on transition_effect.tenant_id = operation_row.tenant_id
        and transition_effect.operation_id = operation_row.id
        and transition_effect.resulting_revision = operation_row.revision
       where operation_row.tenant_id = new.tenant_id
         and operation_row.id = new.applied_provider_lifecycle_operation_id
         and operation_row.revision =
           new.applied_provider_lifecycle_operation_revision
         and operation_row.message_id = new.applied_message_id
         and operation_row.action = 'delete'
         and operation_row.origin = 'provider_observed'
         and operation_row.source_occurrence_id = new.source_occurrence_id
         and operation_row.source_account_id = new.source_account_id
         and operation_row.source_thread_binding_id = new.source_thread_binding_id
         and operation_row.binding_generation = new.binding_generation
         and operation_row.outcome = 'observed'
         and operation_row.delete_local_effect = 'retain_local'
         and transition_effect.delete_local_effect = 'retain_local'
         and transition_effect.recorded_at = new.terminal_at
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_retain_local_effect_mismatch';
  end if;

  if transition_row.source_occurrence_resulting_revision is not null then
    select * into occurrence_row
    from public.inbox_v2_source_occurrences candidate_row
    where candidate_row.tenant_id = new.tenant_id
      and candidate_row.id = new.source_occurrence_id;

    if not found
       or transition_row.source_occurrence_expected_revision <>
          new.source_occurrence_revision
       or occurrence_row.resolution_state <> 'resolved'
       or occurrence_row.revision <>
          transition_row.source_occurrence_resulting_revision
       or occurrence_row.resolved_external_message_reference_id <>
          transition_row.target_external_message_reference_id
       or occurrence_row.updated_at > transition_row.recorded_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_occurrence_resolution_mismatch';
    end if;
  end if;

  select count(*), min(candidate_row.ordinal), max(candidate_row.ordinal)
  into candidate_count, candidate_min, candidate_max
  from public.inbox_v2_deferred_source_action_conflict_candidates candidate_row
  where candidate_row.tenant_id = new.tenant_id
    and candidate_row.action_id = new.id
    and candidate_row.resulting_revision = new.revision;

  if candidate_count <> new.conflict_candidate_count
     or (candidate_count > 0 and (
       candidate_min <> 0 or candidate_max <> candidate_count - 1
     )) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_candidate_set_mismatch';
  end if;

  if new.state = 'target_conflicted' and exists (
    select 1
    from public.inbox_v2_deferred_source_action_conflict_candidates candidate_row
    join public.inbox_v2_external_message_references reference_row
      on reference_row.tenant_id = candidate_row.tenant_id
     and reference_row.id = candidate_row.external_message_reference_id
    where candidate_row.tenant_id = new.tenant_id
      and candidate_row.action_id = new.id
      and (
        reference_row.realm_id <> new.message_realm_id
        or reference_row.realm_version <> new.message_realm_version
        or reference_row.canonicalization_version <>
          new.message_canonicalization_version
        or reference_row.scope_kind <> new.message_scope_kind
        or reference_row.scope_source_account_id is distinct from
          new.message_scope_source_account_id
        or reference_row.scope_source_thread_binding_id is distinct from
          new.message_scope_source_thread_binding_id
        or reference_row.object_kind_id <> new.message_object_kind_id
        or reference_row.external_thread_id <> new.external_thread_id
        or reference_row.canonical_external_subject <>
          new.canonical_external_subject
      )
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_candidate_key_mismatch';
  end if;

  if transition_row.ordering_outcome = 'advance' and not exists (
    select 1
    from public.inbox_v2_deferred_source_action_ordering_heads head_row
    where head_row.tenant_id = new.tenant_id
      and head_row.message_key_digest_sha256 = new.message_key_digest_sha256
      and head_row.message_realm_id = new.message_realm_id
      and head_row.message_realm_version = new.message_realm_version
      and head_row.message_canonicalization_version =
        new.message_canonicalization_version
      and head_row.message_scope_kind = new.message_scope_kind
      and head_row.message_scope_source_account_id is not distinct from
        new.message_scope_source_account_id
      and head_row.message_scope_source_thread_binding_id is not distinct from
        new.message_scope_source_thread_binding_id
      and head_row.message_object_kind_id = new.message_object_kind_id
      and head_row.external_thread_id = new.external_thread_id
      and head_row.canonical_external_subject =
        new.canonical_external_subject
      and head_row.external_message_key_detail =
        new.external_message_key_detail
      and head_row.lane = new.lane
      and head_row.scope_token = transition_row.ordering_head_scope_token
      and head_row.comparator_id = transition_row.ordering_head_comparator_id
      and head_row.comparator_revision =
        transition_row.ordering_head_comparator_revision
      and head_row.revision >= transition_row.resulting_ordering_head_revision
      and (
        (
          head_row.revision = transition_row.resulting_ordering_head_revision
          and head_row.latest_action_id = new.id
          and head_row.latest_position = new.ordering_position
        ) or (
          head_row.revision > transition_row.resulting_ordering_head_revision
          and (
            char_length(head_row.latest_position) >
              char_length(new.ordering_position)
            or (
              char_length(head_row.latest_position) =
                char_length(new.ordering_position)
              and head_row.latest_position collate "C" >
                new.ordering_position collate "C"
            )
          )
        )
      )
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_ordering_head_missing';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_deferred_source_action_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_deferred_source_action_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  occurrence_row public.inbox_v2_source_occurrences%rowtype;
  adapter_contract_detail jsonb;
  provider_reference_detail jsonb;
  provider_timestamp_detail jsonb;
  provider_reference_count bigint;
  provider_timestamp_count bigint;
  expected_occurrence_detail jsonb;
  immutable_columns_changed boolean;
  immutable_changed_column_names text;
begin
  if tg_op = 'DELETE' then
    if pg_trigger_depth() > 1 and not exists (
      select 1 from public.tenants tenant_row
      where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_delete';
  end if;

  if tg_op = 'INSERT' then
    if new.state <> 'pending'
       or new.revision <> 1
       or new.created_at <> new.updated_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_invalid_initial';
    end if;

    select * into occurrence_row
    from public.inbox_v2_source_occurrences candidate_row
    where candidate_row.tenant_id = new.tenant_id
      and candidate_row.id = new.source_occurrence_id
    for share;

    if not found then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_induction_mismatch';
    end if;

    select reference_summary.detail,
           reference_summary.row_count,
           timestamp_summary.detail,
           timestamp_summary.row_count
    into provider_reference_detail,
         provider_reference_count,
         provider_timestamp_detail,
         provider_timestamp_count
    from (
      select coalesce(
               jsonb_agg(
                 jsonb_build_object(
                   'kindId', child_row.kind_id,
                   'subject', child_row.subject
                 ) order by child_row.ordinal
               ),
               '[]'::jsonb
             ) as detail,
             count(*) as row_count
      from public.inbox_v2_source_occurrence_provider_references child_row
      where child_row.tenant_id = new.tenant_id
        and child_row.source_occurrence_id = new.source_occurrence_id
    ) reference_summary
    cross join (
      select coalesce(
               jsonb_agg(
                 jsonb_build_object(
                   'kindId', child_row.kind_id,
                   'timestamp', to_char(
                     child_row.timestamp at time zone 'UTC',
                     'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'
                   )
                 ) order by child_row.ordinal
               ),
               '[]'::jsonb
             ) as detail,
             count(*) as row_count
      from public.inbox_v2_source_occurrence_provider_timestamps child_row
      where child_row.tenant_id = new.tenant_id
        and child_row.source_occurrence_id = new.source_occurrence_id
    ) timestamp_summary;

    if occurrence_row.resolution_state <> 'pending'
       or occurrence_row.revision <> new.source_occurrence_revision
       or occurrence_row.normalized_inbound_event_id <>
          new.normalized_inbound_event_id
       or occurrence_row.message_realm_id <> new.message_realm_id
       or occurrence_row.message_realm_version <> new.message_realm_version
       or occurrence_row.message_canonicalization_version <>
          new.message_canonicalization_version
       or occurrence_row.message_scope_kind::text <>
          new.message_scope_kind::text
       or occurrence_row.message_scope_source_account_id is distinct from
          new.message_scope_source_account_id
       or occurrence_row.message_scope_source_thread_binding_id is distinct from
          new.message_scope_source_thread_binding_id
       or occurrence_row.message_object_kind_id <> new.message_object_kind_id
       or occurrence_row.external_thread_id <> new.external_thread_id
       or occurrence_row.canonical_external_subject <>
          new.canonical_external_subject
       or occurrence_row.message_key_digest_sha256 <>
          new.message_key_digest_sha256
       or occurrence_row.source_account_id <> new.source_account_id
       or occurrence_row.source_thread_binding_id <>
          new.source_thread_binding_id
       or occurrence_row.binding_generation <> new.binding_generation
       or occurrence_row.adapter_contract_id <> new.adapter_contract_id
       or occurrence_row.adapter_contract_version <>
          new.adapter_contract_version
       or occurrence_row.adapter_declaration_revision <>
          new.adapter_declaration_revision
       or occurrence_row.adapter_surface_id <> new.adapter_surface_id
       or occurrence_row.adapter_loaded_by_trusted_service_id <>
          new.adapter_loaded_by_trusted_service_id
       or occurrence_row.adapter_loaded_at <> new.adapter_loaded_at
       or occurrence_row.capability_revision <> new.capability_revision
       or occurrence_row.provider_actor_source_external_identity_id is distinct from
          new.actor_source_external_identity_id
       or occurrence_row.observed_at <> new.observed_at
       or occurrence_row.recorded_at <> new.recorded_at
       or new.declared_by_trusted_service_id <>
          new.adapter_loaded_by_trusted_service_id
       or new.semantic_proof_detail -> 'externalMessageReference' is distinct from
          'null'::jsonb
       or new.semantic_proof_detail -> 'sourceOccurrence' is distinct from
          'null'::jsonb
       or (new.semantic_proof_detail #>> '{occurredAt}')::timestamptz is distinct from
          new.observed_at
       or (new.semantic_proof_detail #>> '{recordedAt}')::timestamptz is distinct from
          new.recorded_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_induction_mismatch';
    end if;

    adapter_contract_detail := jsonb_build_object(
      'contractId', occurrence_row.adapter_contract_id,
      'contractVersion', occurrence_row.adapter_contract_version,
      'declarationRevision', occurrence_row.adapter_declaration_revision::text,
      'surfaceId', occurrence_row.adapter_surface_id,
      'loadedByTrustedServiceId',
        occurrence_row.adapter_loaded_by_trusted_service_id,
      'loadedAt', to_char(
        occurrence_row.adapter_loaded_at at time zone 'UTC',
        'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'
      )
    );

    expected_occurrence_detail := jsonb_build_object(
      'tenantId', occurrence_row.tenant_id,
      'id', occurrence_row.id,
      'messageKey', jsonb_build_object(
        'realm', jsonb_build_object(
          'realmId', occurrence_row.message_realm_id,
          'realmVersion', occurrence_row.message_realm_version,
          'canonicalizationVersion',
            occurrence_row.message_canonicalization_version
        ),
        'scope', case occurrence_row.message_scope_kind
          when 'provider_thread' then jsonb_build_object(
            'kind', 'provider_thread'
          )
          when 'source_account' then jsonb_build_object(
            'kind', 'source_account',
            'owner', jsonb_build_object(
              'tenantId', occurrence_row.tenant_id,
              'kind', 'source_account',
              'id', occurrence_row.message_scope_source_account_id
            )
          )
          when 'source_thread_binding' then jsonb_build_object(
            'kind', 'source_thread_binding',
            'owner', jsonb_build_object(
              'tenantId', occurrence_row.tenant_id,
              'kind', 'source_thread_binding',
              'id', occurrence_row.message_scope_source_thread_binding_id
            )
          )
        end,
        'objectKindId', occurrence_row.message_object_kind_id,
        'externalThread', jsonb_build_object(
          'tenantId', occurrence_row.tenant_id,
          'kind', 'external_thread',
          'id', occurrence_row.external_thread_id
        ),
        'canonicalExternalSubject',
          occurrence_row.canonical_external_subject
      ),
      'messageIdentityDeclaration', jsonb_build_object(
        'adapterContract', adapter_contract_detail,
        'identityKind', 'message',
        'realmId', occurrence_row.message_realm_id,
        'realmVersion', occurrence_row.message_realm_version,
        'canonicalizationVersion',
          occurrence_row.message_canonicalization_version,
        'objectKindId', occurrence_row.message_object_kind_id,
        'scopeKind', occurrence_row.message_scope_kind,
        'decisionStrength', occurrence_row.message_decision_strength
      ),
      'bindingContext', jsonb_build_object(
        'externalThread', jsonb_build_object(
          'tenantId', occurrence_row.tenant_id,
          'kind', 'external_thread',
          'id', occurrence_row.external_thread_id
        ),
        'sourceAccount', jsonb_build_object(
          'tenantId', occurrence_row.tenant_id,
          'kind', 'source_account',
          'id', occurrence_row.source_account_id
        ),
        'sourceThreadBinding', jsonb_build_object(
          'tenantId', occurrence_row.tenant_id,
          'kind', 'source_thread_binding',
          'id', occurrence_row.source_thread_binding_id
        ),
        'bindingGeneration', occurrence_row.binding_generation::text
      ),
      'origin', case occurrence_row.origin_kind
        when 'provider_response' then jsonb_build_object(
          'kind', 'provider_response',
          'sourceAccount', jsonb_build_object(
            'tenantId', occurrence_row.tenant_id,
            'kind', 'source_account',
            'id', occurrence_row.source_account_id
          ),
          'outboundDispatchAttempt', jsonb_build_object(
            'tenantId', occurrence_row.tenant_id,
            'kind', 'outbound_dispatch_attempt',
            'id', occurrence_row.outbound_dispatch_attempt_id
          )
        )
        else jsonb_build_object(
          'kind', occurrence_row.origin_kind,
          'sourceAccount', jsonb_build_object(
            'tenantId', occurrence_row.tenant_id,
            'kind', 'source_account',
            'id', occurrence_row.source_account_id
          ),
          'rawInboundEvent', jsonb_build_object(
            'tenantId', occurrence_row.tenant_id,
            'kind', 'raw_inbound_event',
            'id', occurrence_row.raw_inbound_event_id
          ),
          'normalizedInboundEvent', jsonb_build_object(
            'tenantId', occurrence_row.tenant_id,
            'kind', 'normalized_inbound_event',
            'id', occurrence_row.normalized_inbound_event_id
          )
        )
      end,
      'descriptor', jsonb_build_object(
        'adapterContract', adapter_contract_detail,
        'descriptorSchemaId', occurrence_row.descriptor_schema_id,
        'descriptorVersion', occurrence_row.descriptor_version,
        'capabilityRevision', occurrence_row.capability_revision::text,
        'providerReferences', provider_reference_detail,
        'descriptorDigestSha256', occurrence_row.descriptor_digest_sha256
      ),
      'providerActor', case occurrence_row.provider_actor_kind
        when 'source_external_identity' then jsonb_build_object(
          'kind', 'source_external_identity',
          'sourceExternalIdentity', jsonb_build_object(
            'tenantId', occurrence_row.tenant_id,
            'kind', 'source_external_identity',
            'id', occurrence_row.provider_actor_source_external_identity_id
          )
        )
        when 'provider_system' then jsonb_build_object(
          'kind', 'provider_system',
          'actorKindId', occurrence_row.provider_system_actor_kind_id,
          'actorSubject', occurrence_row.provider_system_actor_subject
        )
        else 'null'::jsonb
      end,
      'direction', occurrence_row.direction,
      'providerTimestamps', provider_timestamp_detail,
      'referencePortability', jsonb_build_object(
        'kind', occurrence_row.reference_portability_kind,
        'adapterContract', adapter_contract_detail,
        'decisionStrength',
          occurrence_row.reference_portability_decision_strength
      ),
      'resolution', jsonb_build_object(
        'state', 'pending',
        'diagnostic', jsonb_build_object(
          'codeId', occurrence_row.resolution_diagnostic_code_id,
          'retryable', occurrence_row.resolution_diagnostic_retryable,
          'correlationToken',
            occurrence_row.resolution_diagnostic_correlation_token,
          'safeOperatorHintId',
            occurrence_row.resolution_diagnostic_safe_operator_hint_id
        )
      ),
      'observedAt', to_char(
        occurrence_row.observed_at at time zone 'UTC',
        'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'
      ),
      'recordedAt', to_char(
        occurrence_row.recorded_at at time zone 'UTC',
        'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'
      ),
      'revision', occurrence_row.revision::text,
      'createdAt', to_char(
        occurrence_row.created_at at time zone 'UTC',
        'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'
      ),
      'updatedAt', to_char(
        occurrence_row.updated_at at time zone 'UTC',
        'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'
      )
    );

    if provider_reference_count <> occurrence_row.provider_reference_count
       or provider_timestamp_count <> occurrence_row.provider_timestamp_count
       or new.source_occurrence_detail is distinct from
          expected_occurrence_detail then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_action_occurrence_snapshot_mismatch';
    end if;
    return new;
  end if;

  if old.state <> 'pending'
     and (to_jsonb(new) - 'message_key_digest_sha256') is not distinct from
         (to_jsonb(old) - 'message_key_digest_sha256') then
    -- An exact replay is not a second state transition. Keeping it legal lets
    -- the deferred assertion revalidate immutable historical evidence after a
    -- later action has advanced the same ordering head.
    return new;
  end if;

  immutable_columns_changed := (
       to_jsonb(new) - array[
         'message_key_digest_sha256',
         'state', 'applied_external_message_reference_id',
         'applied_message_id', 'applied_message_revision',
         'applied_provider_lifecycle_operation_id',
         'applied_provider_lifecycle_operation_revision', 'effect_kind',
         'related_action_id', 'state_reason_id', 'conflict_candidate_count',
         'conflict_candidate_digest_sha256', 'terminal_at', 'revision',
         'updated_at'
       ]
     ) is distinct from (
       to_jsonb(old) - array[
         'message_key_digest_sha256',
         'state', 'applied_external_message_reference_id',
         'applied_message_id', 'applied_message_revision',
         'applied_provider_lifecycle_operation_id',
         'applied_provider_lifecycle_operation_revision', 'effect_kind',
         'related_action_id', 'state_reason_id', 'conflict_candidate_count',
         'conflict_candidate_digest_sha256', 'terminal_at', 'revision',
         'updated_at'
       ]
     );

  if immutable_columns_changed then
    select string_agg(keys.key, ',' order by keys.key)
    into immutable_changed_column_names
    from jsonb_object_keys(to_jsonb(new) || to_jsonb(old)) keys(key)
    where to_jsonb(new) -> keys.key is distinct from
          to_jsonb(old) -> keys.key
      and keys.key <> all (array[
        'message_key_digest_sha256',
        'state', 'applied_external_message_reference_id',
        'applied_message_id', 'applied_message_revision',
        'applied_provider_lifecycle_operation_id',
        'applied_provider_lifecycle_operation_revision', 'effect_kind',
        'related_action_id', 'state_reason_id', 'conflict_candidate_count',
        'conflict_candidate_digest_sha256', 'terminal_at', 'revision',
        'updated_at'
      ]);
  end if;

  if immutable_columns_changed
     or old.state <> 'pending'
     or new.state = 'pending'
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at
     or new.terminal_at <> new.updated_at then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.deferred_source_action_cas',
      detail = format(
        'immutable_columns_changed=%s immutable_changed_columns=%s old_state=%s new_state=%s old_revision=%s new_revision=%s old_updated_at=%s new_updated_at=%s terminal_at=%s',
        immutable_columns_changed, immutable_changed_column_names, old.state,
        new.state, old.revision, new.revision, old.updated_at, new.updated_at,
        new.terminal_at
      );
  end if;

  if new.state = 'applied' and not exists (
    select 1
    from public.inbox_v2_external_message_references reference_row
    where reference_row.tenant_id = new.tenant_id
      and reference_row.id = new.applied_external_message_reference_id
      and reference_row.message_id = new.applied_message_id
      and reference_row.external_thread_id = new.external_thread_id
      and reference_row.realm_id = new.message_realm_id
      and reference_row.realm_version = new.message_realm_version
      and reference_row.canonicalization_version =
        new.message_canonicalization_version
      and reference_row.scope_kind = new.message_scope_kind
      and reference_row.scope_source_account_id is not distinct from
        new.message_scope_source_account_id
      and reference_row.scope_source_thread_binding_id is not distinct from
        new.message_scope_source_thread_binding_id
      and reference_row.object_kind_id = new.message_object_kind_id
      and reference_row.canonical_external_subject =
        new.canonical_external_subject
      and reference_row.message_key_digest_sha256 =
        old.message_key_digest_sha256
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_action_applied_target_mismatch';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_deferred_source_candidate_assert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_deferred_source_candidate_assert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  tenant_key text;
  action_key text;
  action_row public.inbox_v2_deferred_message_source_actions%rowtype;
  candidate_count bigint;
  candidate_min smallint;
  candidate_max smallint;
begin
  tenant_key := case when tg_op = 'DELETE' then old.tenant_id else new.tenant_id end;
  action_key := case when tg_op = 'DELETE' then old.action_id else new.action_id end;

  select * into action_row
  from public.inbox_v2_deferred_message_source_actions candidate_action
  where candidate_action.tenant_id = tenant_key
    and candidate_action.id = action_key;

  if not found then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = tenant_key
    ) then
      return null;
    end if;
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_candidate_action_missing';
  end if;

  select count(*), min(candidate_row.ordinal), max(candidate_row.ordinal)
  into candidate_count, candidate_min, candidate_max
  from public.inbox_v2_deferred_source_action_conflict_candidates candidate_row
  where candidate_row.tenant_id = tenant_key
    and candidate_row.action_id = action_key
    and candidate_row.resulting_revision = action_row.revision;

  if action_row.state <> 'target_conflicted'
     or candidate_count <> action_row.conflict_candidate_count
     or candidate_count < 2
     or candidate_min <> 0
     or candidate_max <> candidate_count - 1 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_candidate_set_mismatch';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_deferred_source_head_assert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_deferred_source_head_assert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if not exists (
    select 1
    from public.inbox_v2_deferred_message_source_actions action_row
    join public.inbox_v2_deferred_message_source_action_transitions transition_row
      on transition_row.tenant_id = action_row.tenant_id
     and transition_row.action_id = action_row.id
    where action_row.tenant_id = new.tenant_id
      and action_row.id = new.latest_action_id
      and action_row.state = 'applied'
      and action_row.ordering_kind = 'monotonic_exact'
      and action_row.message_key_digest_sha256 = new.message_key_digest_sha256
      and action_row.message_realm_id = new.message_realm_id
      and action_row.message_realm_version = new.message_realm_version
      and action_row.message_canonicalization_version =
        new.message_canonicalization_version
      and action_row.message_scope_kind = new.message_scope_kind
      and action_row.message_scope_source_account_id is not distinct from
        new.message_scope_source_account_id
      and action_row.message_scope_source_thread_binding_id is not distinct from
        new.message_scope_source_thread_binding_id
      and action_row.message_object_kind_id = new.message_object_kind_id
      and action_row.external_thread_id = new.external_thread_id
      and action_row.canonical_external_subject =
        new.canonical_external_subject
      and action_row.external_message_key_detail =
        new.external_message_key_detail
      and action_row.lane = new.lane
      and action_row.ordering_scope_token = new.scope_token
      and action_row.ordering_comparator_id = new.comparator_id
      and action_row.ordering_comparator_revision = new.comparator_revision
      and action_row.ordering_position = new.latest_position
      and transition_row.ordering_outcome = 'advance'
      and transition_row.ordering_head_scope_token = new.scope_token
      and transition_row.ordering_head_comparator_id = new.comparator_id
      and transition_row.ordering_head_comparator_revision =
        new.comparator_revision
      and transition_row.resulting_ordering_head_revision = new.revision
      and transition_row.recorded_at = new.updated_at
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_ordering_head_action_mismatch';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_deferred_source_ordering_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_deferred_source_ordering_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if pg_trigger_depth() > 1 and not exists (
      select 1 from public.tenants tenant_row
      where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_ordering_head_delete';
  end if;

  if tg_op = 'INSERT' then
    if new.revision <> 1 or new.created_at <> new.updated_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.deferred_source_ordering_head_initial';
    end if;
    return new;
  end if;

  if row(
       new.tenant_id, new.message_realm_id, new.message_realm_version,
       new.message_canonicalization_version, new.message_scope_kind,
       new.message_scope_source_account_id,
       new.message_scope_source_thread_binding_id,
       new.message_object_kind_id, new.external_thread_id,
       new.canonical_external_subject, new.external_message_key_detail,
       new.external_message_key_detail_digest_sha256, new.lane,
       new.scope_token, new.comparator_id, new.comparator_revision,
       new.created_at
     ) is distinct from row(
       old.tenant_id, old.message_realm_id, old.message_realm_version,
       old.message_canonicalization_version, old.message_scope_kind,
       old.message_scope_source_account_id,
       old.message_scope_source_thread_binding_id,
       old.message_object_kind_id, old.external_thread_id,
       old.canonical_external_subject, old.external_message_key_detail,
       old.external_message_key_detail_digest_sha256, old.lane,
       old.scope_token, old.comparator_id, old.comparator_revision,
       old.created_at
     )
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at
     or char_length(new.latest_position) < char_length(old.latest_position)
     or (
       char_length(new.latest_position) = char_length(old.latest_position)
       and new.latest_position collate "C" <= old.latest_position collate "C"
     ) then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.deferred_source_ordering_head_cas';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_deferred_source_transition_assert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_deferred_source_transition_assert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  action_row public.inbox_v2_deferred_message_source_actions%rowtype;
begin
  select * into action_row
  from public.inbox_v2_deferred_message_source_actions candidate_row
  where candidate_row.tenant_id = new.tenant_id
    and candidate_row.id = new.action_id;

  if not found
     or action_row.state = 'pending'
     or action_row.revision <> new.resulting_revision
     or action_row.state <> new.after_state
     or action_row.updated_at <> new.recorded_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.deferred_source_transition_action_mismatch';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_dg_cas_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_cas_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_new jsonb;
  v_old jsonb;
  v_mutable text[];
begin
  if tg_op = 'DELETE' then
    raise exception '% CAS authority cannot be deleted', tg_table_name
      using errcode = '23514';
  end if;

  v_new := to_jsonb(new);
  if tg_op = 'UPDATE' then
    v_old := to_jsonb(old);
  end if;

  if tg_table_name = 'inbox_v2_data_governance_restore_heads' then
    if tg_op = 'INSERT' then
      if new.head_revision <> 1 or new.state <> 'open'
         or new.sealed_entry_hash is not null or new.sealed_sequence is not null
         or new.sealed_at is not null then
        raise exception 'Restore head must start open at revision 1'
          using errcode = '23514';
      end if;
    else
      v_mutable := array[
        'state', 'head_revision', 'sealed_entry_hash', 'sealed_sequence',
        'sealed_at', 'updated_at'
      ];
      if new.head_revision <> old.head_revision + 1
         or new.updated_at <= old.updated_at
         or (v_new - v_mutable) <> (v_old - v_mutable)
         or old.state <> 'open'
         or not (
           (new.state = 'open' and new.sealed_entry_hash is null
             and new.sealed_sequence is null and new.sealed_at is null)
           or (new.state = 'sealed' and new.sealed_entry_hash is not null
             and new.sealed_sequence is not null and new.sealed_at is not null)
         ) then
        raise exception 'Restore head requires immutable fence and one legal +1 CAS edge'
          using errcode = '23514';
      end if;
    end if;
    return new;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_restore_required_controls' then
    if tg_op = 'INSERT' then
      if new.row_revision <> 1 or new.reapplied_entry_hash is not null
         or new.reapplied_at is not null then
        raise exception 'Required restore control must start pending at revision 1'
          using errcode = '23514';
      end if;
    else
      v_mutable := array['row_revision', 'reapplied_entry_hash', 'reapplied_at'];
      if new.row_revision <> old.row_revision + 1
         or (v_new - v_mutable) <> (v_old - v_mutable)
         or old.reapplied_entry_hash is not null
         or new.reapplied_entry_hash is null or new.reapplied_at is null then
        raise exception 'Required restore control can be reapplied exactly once under CAS'
          using errcode = '23514';
      end if;
    end if;
    return new;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_restore_leases' then
    if tg_op = 'INSERT' then
      if new.lease_revision <> 1 or new.restore_head_revision <> 1
         or new.state <> 'active' or new.completed_at is not null then
        raise exception 'Restore lease must start active at revision 1'
          using errcode = '23514';
      end if;
    else
      v_mutable := array[
        'lease_revision', 'restore_head_revision', 'state', 'completed_at',
        'updated_at'
      ];
      if new.lease_revision <> old.lease_revision + 1
         or new.restore_head_revision <> old.restore_head_revision + 1
         or new.updated_at <= old.updated_at
         or (v_new - v_mutable) <> (v_old - v_mutable)
         or old.state <> 'active'
         or new.state not in ('active', 'completed', 'released', 'expired')
         or (new.state = 'active' and new.completed_at is not null)
         or (new.state = 'completed' and new.completed_at is null)
         or (new.state in ('released', 'expired') and new.completed_at is not null) then
        raise exception 'Restore lease requires immutable token, legal edge and +1 CAS'
          using errcode = '23514';
      end if;
    end if;
    return new;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_export_jobs' then
    if tg_op = 'INSERT' then
      if new.state_revision <> 1
         or new.state <> 'queued'
         or new.export_manifest_id is not null
         or new.export_manifest_revision is not null
         or new.export_artifact_id is not null
         or new.export_artifact_revision is not null then
        raise exception 'Export job must bootstrap queued at state revision 1'
          using errcode = '23514';
      end if;
    else
      v_mutable := array[
        'state', 'state_revision', 'export_manifest_id',
        'export_manifest_revision', 'export_artifact_id',
        'export_artifact_revision', 'updated_at'
      ];
      if new.state_revision <> old.state_revision + 1
         or new.updated_at <= old.updated_at
         or (v_new - v_mutable) <> (v_old - v_mutable)
         or not (
           (old.state = 'queued' and new.state = 'running')
           or (old.state = 'running' and new.state in ('ready', 'revoked', 'expired', 'failed_retryable'))
           or (old.state = 'ready' and new.state in ('completed', 'revoked', 'expired', 'failed_retryable'))
           or (old.state = 'failed_retryable' and new.state in ('running', 'failed_retryable', 'revoked', 'expired'))
           or (old.state = 'revoked' and new.state = 'revoked')
           or (old.state = 'expired' and new.state = 'expired')
         )
         or (
           old.state = 'queued' and (
             new.export_artifact_id is null
             or new.export_artifact_revision <> 1
           )
         )
         or (
           old.state = 'failed_retryable' and new.state = 'running' and (
             new.export_artifact_id is null
             or new.export_artifact_id = old.export_artifact_id
             or new.export_artifact_revision <> 1
           )
         )
         or (
           old.state = 'failed_retryable'
           and new.state in ('revoked', 'expired')
           and (
             new.export_artifact_id is distinct from old.export_artifact_id
             or new.export_artifact_revision is distinct from old.export_artifact_revision
           )
         )
         or (
           old.state <> 'queued'
           and not (
             old.state = 'failed_retryable'
             and new.state in ('running', 'revoked', 'expired')
           )
           and (
             new.export_artifact_id is distinct from old.export_artifact_id
             or new.export_artifact_revision <> old.export_artifact_revision + 1
           )
         ) then
        raise exception 'Export job requires immutable authority, legal edge and +1 state CAS'
          using errcode = '23514';
      end if;
    end if;
    return new;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_export_artifact_heads' then
    if tg_op = 'INSERT' then
      if new.current_revision <> 1 or new.current_state <> 'building' then
        raise exception 'Export artifact head must start building at revision 1'
          using errcode = '23514';
      end if;
    else
      v_mutable := array['current_revision', 'current_state', 'updated_at'];
      if new.current_revision <> old.current_revision + 1
         or new.updated_at <= old.updated_at
         or (v_new - v_mutable) <> (v_old - v_mutable)
         or not (
           (old.current_state = 'building' and new.current_state in ('ready', 'quarantined', 'deleted'))
           or (old.current_state = 'ready' and new.current_state in ('quarantined', 'deleted'))
           or (old.current_state = 'quarantined' and new.current_state = 'deleted')
         ) then
        raise exception 'Export artifact head requires immutable authority, legal edge and next revision'
          using errcode = '23514';
      end if;
    end if;
    return new;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_export_receipt_cas' then
    if tg_op = 'INSERT' then
      if new.revision <> 1 or new.state <> 'issued' or new.consumed_at is not null then
        raise exception 'Receipt CAS must start issued at revision 1'
          using errcode = '23514';
      end if;
    else
      if new.revision <> old.revision + 1
         or new.updated_at < old.updated_at
         or (v_new - array['state', 'revision', 'consumed_at', 'updated_at'])
            <> (v_old - array['state', 'revision', 'consumed_at', 'updated_at'])
         or not (old.state = 'issued' and new.state in ('consumed', 'revoked', 'expired')) then
        raise exception 'Receipt requires immutable lineage, legal edge and +1 CAS'
          using errcode = '23514';
      end if;
    end if;
    return new;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_destructive_checkpoint_leases' then
    perform 1
      from public.inbox_v2_data_governance_control_set_heads c
     where c.tenant_id = new.tenant_id
       and c.legal_hold_set_revision = new.legal_hold_set_revision
       and c.restriction_set_revision = new.restriction_set_revision
     for update;
    if not found then
      raise exception 'Destructive lease must lock the current control-set authority'
        using errcode = '23514';
    end if;
    if tg_op = 'INSERT' then
      if new.claim_revision <> 1 or new.state <> 'claimed'
         or new.completed_at is not null then
        raise exception 'Destructive lease must start claimed at revision 1'
          using errcode = '23514';
      end if;
    else
      v_mutable := array[
        'state', 'claim_revision', 'execution_fence_hash', 'claimed_at',
        'lease_expires_at', 'completed_at', 'updated_at'
      ];
      if new.claim_revision <> old.claim_revision + 1
         or new.updated_at < old.updated_at
         or (v_new - v_mutable) <> (v_old - v_mutable)
         or not (
           (old.state = 'claimed' and new.state in ('completed', 'released', 'expired'))
           or (old.state in ('released', 'expired') and new.state = 'claimed')
         )
         or (new.state = 'claimed' and (
           new.execution_fence_hash = old.execution_fence_hash
           or new.claimed_at <= old.updated_at
           or new.lease_expires_at <= new.claimed_at
           or new.completed_at is not null
         ))
         or (new.state = 'completed' and (
           new.execution_fence_hash <> old.execution_fence_hash
           or new.completed_at is null
           or new.completed_at < old.claimed_at
           or new.completed_at > old.lease_expires_at
         ))
         or (new.state in ('released', 'expired') and (
           new.execution_fence_hash <> old.execution_fence_hash
           or new.completed_at is not null
         )) then
        raise exception 'Destructive lease requires frozen authority, legal edge and +1 CAS'
          using errcode = '23514';
      end if;
    end if;
    return new;
  end if;

  if tg_op = 'INSERT' then
    if (v_new->>'head_revision')::bigint <> 1 then
      raise exception '% head must start at revision 1', tg_table_name
        using errcode = '23514';
    end if;
    if tg_table_name like '%_checkpoint_heads'
       and (v_new->>'current_attempt')::bigint <> 1 then
      raise exception 'Checkpoint head must start at attempt 1'
        using errcode = '23514';
    end if;
    return new;
  end if;

  v_mutable := array[
    'head_revision', 'updated_at', 'current_revision', 'current_state', 'state',
    'current_policy_version', 'current_activation_id', 'current_activation_revision',
    'current_attempt', 'current_outcome', 'legal_hold_set_revision',
    'restriction_set_revision', 'last_changed_stream_position'
  ];
  if (v_new->>'head_revision')::bigint <> (v_old->>'head_revision')::bigint + 1
     or (v_new->>'updated_at')::timestamptz < (v_old->>'updated_at')::timestamptz
     or (v_new - v_mutable) <> (v_old - v_mutable) then
    raise exception '% requires immutable identity and +1 CAS', tg_table_name
      using errcode = '23514';
  end if;

  if tg_table_name in (
       'inbox_v2_data_governance_legal_hold_heads',
       'inbox_v2_data_governance_restriction_heads',
       'inbox_v2_data_governance_privacy_request_heads'
     ) and (v_new->>'current_revision')::bigint
       <> (v_old->>'current_revision')::bigint + 1 then
    raise exception '% current revision must advance exactly once', tg_table_name
      using errcode = '23514';
  elsif tg_table_name = 'inbox_v2_data_governance_policy_activation_heads'
     and (v_new->>'current_policy_version')::bigint
       <= (v_old->>'current_policy_version')::bigint then
    raise exception 'Policy activation head cannot regress or repeat policy version'
      using errcode = '23514';
  elsif tg_table_name = 'inbox_v2_data_governance_control_set_heads'
     and ((v_new->>'legal_hold_set_revision')::bigint
            < (v_old->>'legal_hold_set_revision')::bigint
       or (v_new->>'restriction_set_revision')::bigint
            < (v_old->>'restriction_set_revision')::bigint
       or (v_new->>'last_changed_stream_position')::bigint
            <= (v_old->>'last_changed_stream_position')::bigint) then
    raise exception 'Control-set revisions/stream position must be monotonic'
      using errcode = '23514';
  elsif tg_table_name like '%_checkpoint_heads'
     and (v_new->>'current_attempt')::bigint
       <> (v_old->>'current_attempt')::bigint + 1 then
    raise exception 'Checkpoint current attempt must advance exactly once'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_dg_checkpoint_attempt_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_checkpoint_attempt_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_row jsonb;
  v_surface text;
begin
  v_row := to_jsonb(new);
  v_surface := case tg_table_name
    when 'inbox_v2_data_governance_operated_checkpoint_attempts' then 'operated'
    when 'inbox_v2_data_governance_backup_checkpoint_attempts' then 'backup'
    when 'inbox_v2_data_governance_external_checkpoint_attempts' then 'external'
  end;

  if not exists (
    select 1
      from public.inbox_v2_data_governance_deletion_checkpoint_requirements q
      join public.inbox_v2_data_governance_deletion_plans p
        on p.tenant_id = q.tenant_id
       and p.plan_id = q.plan_id
       and p.revision = q.plan_revision
      join public.inbox_v2_data_governance_destructive_checkpoint_leases l
        on l.tenant_id = q.tenant_id
       and l.plan_id = q.plan_id
       and l.plan_revision = q.plan_revision
       and l.checkpoint_id = q.checkpoint_id
      join public.inbox_v2_data_governance_contexts c
        on c.tenant_id = l.tenant_id
       and c.context_id = l.governance_context_id
       and c.version = l.governance_context_version
      join public.inbox_v2_data_governance_effective_policies ep
        on ep.tenant_id = l.tenant_id
       and ep.policy_id = l.policy_id
       and ep.version = l.policy_version
      join public.inbox_v2_data_governance_policy_activations a
        on a.tenant_id = l.tenant_id
       and a.activation_id = l.activation_id
       and a.revision = l.activation_revision
      join public.inbox_v2_data_governance_policy_activation_heads ah
        on ah.tenant_id = l.tenant_id
       and ah.policy_id = l.policy_id
       and ah.current_policy_version = l.policy_version
       and ah.current_activation_id = l.activation_id
       and ah.current_activation_revision = l.activation_revision
      join public.inbox_v2_data_governance_control_set_heads cs
        on cs.tenant_id = l.tenant_id
     where q.tenant_id = v_row->>'tenant_id'
       and q.plan_id = v_row->>'plan_id'
       and q.plan_revision = (v_row->>'plan_revision')::bigint
       and q.checkpoint_id = v_row->>'checkpoint_id'
       and q.surface::text = v_surface
       and q.requirement_hash = v_row->>'requirement_hash'
       and q.registry_id = v_row->>'registry_id'
       and q.registry_revision = (v_row->>'registry_revision')::bigint
       and q.storage_root_id = v_row->>'storage_root_id'
       and q.data_class_id = v_row->>'data_class_id'
       and q.root_record_id = v_row->>'root_record_id'
       and q.entity_type_id = v_row->>'entity_type_id'
       and q.entity_id = v_row->>'entity_id'
       and q.expected_entity_revision = (v_row->>'expected_entity_revision')::bigint
       and q.expected_lineage_revision = (v_row->>'expected_lineage_revision')::bigint
       and l.run_id = v_row->>'run_id'
       and l.run_revision = (v_row->>'run_revision')::bigint
       and l.surface::text = v_surface
       and l.requirement_hash = q.requirement_hash
       and l.registry_id = q.registry_id
       and l.registry_revision = q.registry_revision
       and l.registry_composition_hash = p.registry_composition_hash
       and l.storage_root_id = q.storage_root_id
       and l.data_class_id = q.data_class_id
       and l.root_record_id = q.root_record_id
       and l.entity_type_id = q.entity_type_id
       and l.entity_id = q.entity_id
       and l.expected_entity_revision = q.expected_entity_revision
       and l.expected_lineage_revision = q.expected_lineage_revision
       and l.execution_fence_hash = v_row->>'execution_fence_hash'
       and l.state = 'completed'
       and l.completed_at = (v_row->>'completed_at')::timestamptz
       and l.completed_at <= l.lease_expires_at
       and l.lease_expires_at = (v_row->>'lease_expires_at')::timestamptz
       and l.governance_context_id = p.governance_context_id
       and l.governance_context_version = p.governance_context_version
       and l.governance_context_hash = p.governance_context_hash
       and c.context_hash = l.governance_context_hash
       and l.policy_id = p.policy_id
       and l.policy_version = p.policy_version
       and l.policy_hash = p.policy_hash
       and ep.policy_hash = l.policy_hash
       and l.activation_id = p.activation_id
       and l.activation_revision = p.activation_revision
       and l.activation_hash = p.activation_hash
       and a.activation_hash = l.activation_hash
       and l.legal_hold_set_revision = p.legal_hold_set_revision
       and l.restriction_set_revision = p.restriction_set_revision
       and cs.legal_hold_set_revision = l.legal_hold_set_revision
       and cs.restriction_set_revision = l.restriction_set_revision
       and (v_row->>'legal_hold_set_revision')::bigint = l.legal_hold_set_revision
       and (v_row->>'restriction_set_revision')::bigint = l.restriction_set_revision
       and (
         (v_surface = 'operated'
           and q.delete_handler_id = v_row->>'delete_handler_id'
           and q.verification_handler_id = v_row->>'verification_handler_id'
           and l.execution_handler_id = q.delete_handler_id)
         or (v_surface = 'backup'
           and q.verification_handler_id = v_row->>'verification_handler_id'
           and q.expiry_ledger_handler_id = v_row->>'expiry_ledger_handler_id'
           and l.execution_handler_id = q.expiry_ledger_handler_id)
         or (v_surface = 'external'
           and q.external_delete_handler_id = v_row->>'external_delete_handler_id'
           and l.execution_handler_id = q.external_delete_handler_id)
       )
       and not exists (
         select 1
           from public.inbox_v2_data_governance_legal_hold_targets ht
           join public.inbox_v2_data_governance_legal_hold_heads hh
             on hh.tenant_id = ht.tenant_id
            and hh.hold_id = ht.hold_id
            and hh.current_revision = ht.hold_revision
            and hh.state = 'active'
          where ht.tenant_id = q.tenant_id
            and ht.storage_root_id = q.storage_root_id
            and ht.root_record_id = q.root_record_id
            and ht.entity_type_id = q.entity_type_id
            and ht.entity_id = q.entity_id
            and ht.state = 'active'
       )
  ) then
    raise exception 'Checkpoint attempt does not consume an exact live durable fence'
      using errcode = '23514';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_dg_deletion_run_terminal_export_required(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_deletion_run_terminal_export_required() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_cause text;
  v_binding_count bigint;
begin
  select p.cause, count(te.run_id)
    into v_cause, v_binding_count
    from public.inbox_v2_data_governance_deletion_plans p
    left join public.inbox_v2_data_governance_deletion_run_terminal_exports te
      on te.tenant_id = new.tenant_id
     and te.run_id = new.run_id
     and te.run_revision = new.revision
   where p.tenant_id = new.tenant_id
     and p.plan_id = new.plan_id
     and p.revision = new.plan_revision
   group by p.cause;

  if v_cause is null then
    raise exception 'Deletion run terminal-export requirement lacks its exact plan'
      using errcode = '23514';
  end if;
  if (v_cause = 'tenant_offboarding' and v_binding_count <> 1)
     or (v_cause <> 'tenant_offboarding' and v_binding_count <> 0) then
    raise exception 'Deletion run terminal-export binding does not match its cause'
      using errcode = '23514';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_dg_deletion_run_transition_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_deletion_run_transition_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_stage_one_committed_at timestamptz;
begin
  if tg_op = 'DELETE' then
    raise exception 'Deletion runs cannot be deleted' using errcode = '23514';
  end if;
  if tg_op = 'INSERT' then
    if new.state_revision <> 1
       or new.state <> 'executing'
       or new.result is not null
       or new.stage_one_state <> 'pending'
       or new.stage_one_committed_at is not null
       or new.primary_absence_verified
       or new.has_internal_residual
       or new.has_external_residual
       or new.has_backup_expiry_pending
       or new.backup_latest_possible_expiry_at is not null
       or new.completed_checkpoint_count <> 0
       or new.completed_at is not null
       or not exists (
         select 1
           from (
             select count(*) filter (where requirement.surface = 'operated') as operated_count,
                    count(*) filter (where requirement.surface = 'backup') as backup_count,
                    count(*) filter (where requirement.surface = 'external') as external_count
               from public.inbox_v2_data_governance_deletion_checkpoint_requirements requirement
              where requirement.tenant_id = new.tenant_id
                and requirement.plan_id = new.plan_id
                and requirement.plan_revision = new.plan_revision
           ) frozen
          where frozen.operated_count = new.operated_checkpoint_count
            and frozen.backup_count = new.backup_checkpoint_count
            and frozen.external_count = new.external_checkpoint_count
            and frozen.operated_count >= 1
       ) then
      raise exception 'Deletion run must start at the exact frozen checkpoint set'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if new.tenant_id is distinct from old.tenant_id
     or new.run_id is distinct from old.run_id
     or new.revision is distinct from old.revision
     or new.plan_id is distinct from old.plan_id
     or new.plan_revision is distinct from old.plan_revision
     or new.operated_checkpoint_count is distinct from old.operated_checkpoint_count
     or new.backup_checkpoint_count is distinct from old.backup_checkpoint_count
     or new.external_checkpoint_count is distinct from old.external_checkpoint_count
     or new.started_at is distinct from old.started_at then
    raise exception 'Deletion run identity, plan, start, and frozen checkpoint totals are immutable'
      using errcode = '23514';
  end if;

  if old.state = 'terminal' then
    raise exception 'Terminal deletion runs are immutable' using errcode = '23514';
  end if;
  if new.state_revision <> old.state_revision + 1 then
    raise exception 'Deletion run state_revision must advance by exactly one'
      using errcode = '40001';
  end if;
  if new.updated_at <= old.updated_at then
    raise exception 'Deletion run updated_at must advance monotonically'
      using errcode = '23514';
  end if;
  if not (
    (old.state = 'executing' and new.state in ('executing', 'verification_pending'))
    or (old.state = 'verification_pending' and new.state in ('verification_pending', 'terminal'))
  ) then
    raise exception 'Invalid deletion run state transition' using errcode = '23514';
  end if;
  if old.stage_one_state = 'content_unavailable'
     and (new.stage_one_state <> 'content_unavailable'
       or new.stage_one_committed_at is distinct from old.stage_one_committed_at) then
    raise exception 'Deletion stage one cannot be reopened or rewritten'
      using errcode = '23514';
  end if;
  if new.completed_checkpoint_count < old.completed_checkpoint_count then
    raise exception 'Deletion completed checkpoint count cannot regress'
      using errcode = '23514';
  end if;
  if new.stage_one_state = 'pending'
     and (new.state <> 'executing'
       or new.completed_checkpoint_count <> 0
       or new.primary_absence_verified
       or new.has_internal_residual
       or new.has_external_residual
       or new.has_backup_expiry_pending
       or new.backup_latest_possible_expiry_at is not null) then
    raise exception 'Pending deletion stage one cannot report destructive checkpoint aggregates'
      using errcode = '23514';
  end if;
  if old.stage_one_state = 'pending'
     and new.stage_one_state = 'content_unavailable'
     and (new.completed_checkpoint_count <> 0
       or new.primary_absence_verified
       or new.has_internal_residual
       or new.has_external_residual
       or new.has_backup_expiry_pending
       or new.backup_latest_possible_expiry_at is not null
       or new.result is not null
       or new.completed_at is not null) then
    raise exception 'Stage-one commit cannot report destructive checkpoint outcomes before lease execution'
      using errcode = '23514';
  end if;

  if new.stage_one_state = 'content_unavailable' then
    select max(target.committed_at)
      into v_stage_one_committed_at
      from public.inbox_v2_data_governance_deletion_stage_one_targets target
     where target.tenant_id = new.tenant_id
       and target.run_id = new.run_id
       and target.run_revision = new.revision;

    if v_stage_one_committed_at is null
       or new.stage_one_committed_at is distinct from v_stage_one_committed_at
       or new.stage_one_committed_at > new.updated_at
       or exists (
         select 1
           from public.inbox_v2_data_governance_deletion_checkpoint_requirements requirement
          where requirement.tenant_id = new.tenant_id
            and requirement.plan_id = new.plan_id
            and requirement.plan_revision = new.plan_revision
            and requirement.surface = 'operated'
            and not exists (
              select 1
                from public.inbox_v2_data_governance_deletion_stage_one_targets target
               where target.tenant_id = new.tenant_id
                 and target.run_id = new.run_id
                 and target.run_revision = new.revision
                 and target.plan_id = new.plan_id
                 and target.plan_revision = new.plan_revision
                 and target.checkpoint_id = requirement.checkpoint_id
                 and target.requirement_hash = requirement.requirement_hash
                 and target.storage_root_id = requirement.storage_root_id
                 and target.data_class_id = requirement.data_class_id
                 and target.root_record_id = requirement.root_record_id
                 and target.entity_type_id = requirement.entity_type_id
                 and target.entity_id = requirement.entity_id
                 and target.expected_revision = requirement.expected_entity_revision
                 and target.resulting_revision > requirement.expected_entity_revision
            )
       )
       or exists (
         select 1
           from public.inbox_v2_data_governance_deletion_stage_one_targets target
          where target.tenant_id = new.tenant_id
            and target.run_id = new.run_id
            and target.run_revision = new.revision
            and not exists (
              select 1
                from public.inbox_v2_data_governance_deletion_checkpoint_requirements requirement
               where requirement.tenant_id = target.tenant_id
                 and requirement.plan_id = target.plan_id
                 and requirement.plan_revision = target.plan_revision
                 and requirement.checkpoint_id = target.checkpoint_id
                 and requirement.surface = 'operated'
                 and requirement.requirement_hash = target.requirement_hash
                 and requirement.storage_root_id = target.storage_root_id
                 and requirement.data_class_id = target.data_class_id
                 and requirement.root_record_id = target.root_record_id
                 and requirement.entity_type_id = target.entity_type_id
                 and requirement.entity_id = target.entity_id
                 and requirement.expected_entity_revision = target.expected_revision
            )
       ) then
      raise exception 'Deletion stage one requires the exact relational operated-checkpoint proof set'
        using errcode = '23514';
    end if;
  end if;
  if new.state <> 'executing' and new.stage_one_state <> 'content_unavailable' then
    raise exception 'Deletion verification cannot start before exact stage-one commit'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_dg_deletion_stage_one_target_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_deletion_stage_one_target_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if not exists (
    select 1
      from public.inbox_v2_data_governance_deletion_runs run_row
      join public.inbox_v2_data_governance_deletion_checkpoint_requirements requirement
        on requirement.tenant_id = run_row.tenant_id
       and requirement.plan_id = run_row.plan_id
       and requirement.plan_revision = run_row.plan_revision
       and requirement.checkpoint_id = new.checkpoint_id
     where run_row.tenant_id = new.tenant_id
       and run_row.run_id = new.run_id
       and run_row.revision = new.run_revision
       and run_row.plan_id = new.plan_id
       and run_row.plan_revision = new.plan_revision
       and run_row.state = 'executing'
       and run_row.stage_one_state = 'pending'
       and requirement.surface = 'operated'
       and requirement.requirement_hash = new.requirement_hash
       and requirement.storage_root_id = new.storage_root_id
       and requirement.data_class_id = new.data_class_id
       and requirement.root_record_id = new.root_record_id
       and requirement.entity_type_id = new.entity_type_id
       and requirement.entity_id = new.entity_id
       and requirement.expected_entity_revision = new.expected_revision
       and new.resulting_revision > requirement.expected_entity_revision
       and new.committed_at >= run_row.started_at
       and new.committed_at <= clock_timestamp()
  ) then
    raise exception 'Stage-one target does not match an exact pending operated checkpoint'
      using errcode = '23514';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_dg_deletion_terminal_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_deletion_terminal_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_total bigint;
  v_operated bigint;
  v_backup bigint;
  v_external bigint;
  v_retryable boolean;
  v_internal_residual boolean;
  v_external_residual boolean;
  v_backup_pending boolean;
  v_primary_verified boolean;
  v_latest_backup_expiry timestamptz;
  v_expected_result text;
begin
  if new.state <> 'terminal' then
    return null;
  end if;

  if not exists (
    select 1
      from public.inbox_v2_data_governance_deletion_plans p
      join public.inbox_v2_data_governance_control_set_heads c
        on c.tenant_id = p.tenant_id
       and c.legal_hold_set_revision = p.legal_hold_set_revision
       and c.restriction_set_revision = p.restriction_set_revision
      join public.inbox_v2_data_governance_policy_activation_heads ah
        on ah.tenant_id = p.tenant_id and ah.policy_id = p.policy_id
       and ah.current_policy_version = p.policy_version
       and ah.current_activation_id = p.activation_id
       and ah.current_activation_revision = p.activation_revision
     where p.tenant_id = new.tenant_id
       and p.plan_id = new.plan_id
       and p.revision = new.plan_revision
       and p.earliest_execution_at <= new.started_at
  ) then
    raise exception 'Deletion run authority/control-set is stale at terminalization'
      using errcode = '23514';
  end if;

  select count(*),
         count(*) filter (where q.surface = 'operated'),
         count(*) filter (where q.surface = 'backup'),
         count(*) filter (where q.surface = 'external')
    into v_total, v_operated, v_backup, v_external
    from public.inbox_v2_data_governance_deletion_checkpoint_requirements q
   where q.tenant_id = new.tenant_id
     and q.plan_id = new.plan_id
     and q.plan_revision = new.plan_revision;

  if v_total <> new.completed_checkpoint_count
     or v_operated <> new.operated_checkpoint_count
     or v_backup <> new.backup_checkpoint_count
     or v_external <> new.external_checkpoint_count then
    raise exception 'Terminal deletion counts differ from the frozen checkpoint set'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_data_governance_deletion_checkpoint_requirements q
     where q.tenant_id = new.tenant_id
       and q.plan_id = new.plan_id
       and q.plan_revision = new.plan_revision
       and (
         (q.surface = 'operated' and not exists (
           select 1
             from public.inbox_v2_data_governance_operated_checkpoint_heads h
             join public.inbox_v2_data_governance_operated_checkpoint_attempts a
               on a.tenant_id = h.tenant_id
              and a.run_id = h.run_id
              and a.run_revision = h.run_revision
              and a.checkpoint_id = h.checkpoint_id
              and a.attempt = h.current_attempt
            where h.tenant_id = new.tenant_id
              and h.run_id = new.run_id
              and h.run_revision = new.revision
              and h.checkpoint_id = q.checkpoint_id
              and h.current_outcome = a.outcome
         )) or
         (q.surface = 'backup' and not exists (
           select 1
             from public.inbox_v2_data_governance_backup_checkpoint_heads h
             join public.inbox_v2_data_governance_backup_checkpoint_attempts a
               on a.tenant_id = h.tenant_id
              and a.run_id = h.run_id
              and a.run_revision = h.run_revision
              and a.checkpoint_id = h.checkpoint_id
              and a.attempt = h.current_attempt
            where h.tenant_id = new.tenant_id
              and h.run_id = new.run_id
              and h.run_revision = new.revision
              and h.checkpoint_id = q.checkpoint_id
              and h.current_outcome = a.outcome
         )) or
         (q.surface = 'external' and not exists (
           select 1
             from public.inbox_v2_data_governance_external_checkpoint_heads h
             join public.inbox_v2_data_governance_external_checkpoint_attempts a
               on a.tenant_id = h.tenant_id
              and a.run_id = h.run_id
              and a.run_revision = h.run_revision
              and a.checkpoint_id = h.checkpoint_id
              and a.attempt = h.current_attempt
            where h.tenant_id = new.tenant_id
              and h.run_id = new.run_id
              and h.run_revision = new.revision
              and h.checkpoint_id = q.checkpoint_id
              and h.current_outcome = a.outcome
         ))
       )
  ) then
    raise exception 'Terminal deletion run is missing an exact current checkpoint attempt'
      using errcode = '23514';
  end if;

  select
    exists (
      select 1 from public.inbox_v2_data_governance_operated_checkpoint_heads h
       where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
         and h.current_outcome in ('failed_retryable', 'blocked_by_legal_hold', 'stale_revision')
    ) or exists (
      select 1 from public.inbox_v2_data_governance_backup_checkpoint_heads h
       where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
         and h.current_outcome in ('failed_retryable', 'blocked_by_legal_hold', 'stale_revision')
    ) or exists (
      select 1 from public.inbox_v2_data_governance_external_checkpoint_heads h
       where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
         and h.current_outcome in ('requested', 'failed_retryable', 'blocked_by_legal_hold', 'stale_revision')
    ),
    exists (
      select 1 from public.inbox_v2_data_governance_operated_checkpoint_heads h
       where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
         and h.current_outcome = 'unverified_terminal'
    ) or exists (
      select 1 from public.inbox_v2_data_governance_backup_checkpoint_heads h
       where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
         and h.current_outcome = 'unverified_terminal'
    ),
    exists (
      select 1 from public.inbox_v2_data_governance_external_checkpoint_heads h
       where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
         and h.current_outcome in ('unsupported', 'unknown')
    ),
    exists (
      select 1 from public.inbox_v2_data_governance_backup_checkpoint_heads h
       where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
         and h.current_outcome = 'finite_expiry_pending'
    )
  into v_retryable, v_internal_residual, v_external_residual, v_backup_pending;

  select not exists (
    select 1
      from public.inbox_v2_data_governance_operated_checkpoint_heads h
     where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
       and h.current_outcome <> 'verified_absent'
  ) and not exists (
    select 1
      from public.inbox_v2_data_governance_backup_checkpoint_heads h
      join public.inbox_v2_data_governance_backup_checkpoint_attempts a
        on a.tenant_id = h.tenant_id and a.run_id = h.run_id
       and a.run_revision = h.run_revision and a.checkpoint_id = h.checkpoint_id
       and a.attempt = h.current_attempt
     where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision
       and not a.primary_absence_verified
  ), max(a.latest_possible_expiry_at) filter (where h.current_outcome = 'finite_expiry_pending')
  into v_primary_verified, v_latest_backup_expiry
  from public.inbox_v2_data_governance_backup_checkpoint_heads h
  left join public.inbox_v2_data_governance_backup_checkpoint_attempts a
    on a.tenant_id = h.tenant_id and a.run_id = h.run_id
   and a.run_revision = h.run_revision and a.checkpoint_id = h.checkpoint_id
   and a.attempt = h.current_attempt
  where h.tenant_id = new.tenant_id and h.run_id = new.run_id and h.run_revision = new.revision;

  if exists (
    select 1
      from public.inbox_v2_data_governance_deletion_checkpoint_requirements q
      join public.inbox_v2_data_governance_legal_hold_targets ht
        on ht.tenant_id = q.tenant_id
       and ht.storage_root_id = q.storage_root_id
       and ht.root_record_id = q.root_record_id
       and ht.entity_type_id = q.entity_type_id
       and ht.entity_id = q.entity_id
      join public.inbox_v2_data_governance_legal_hold_heads hh
        on hh.tenant_id = ht.tenant_id and hh.hold_id = ht.hold_id
       and hh.current_revision = ht.hold_revision and hh.state = 'active'
     where q.tenant_id = new.tenant_id
       and q.plan_id = new.plan_id
       and q.plan_revision = new.plan_revision
       and ht.state = 'active'
  ) then
    raise exception 'Terminal deletion run intersects an active current legal hold'
      using errcode = '23514';
  end if;

  v_expected_result := case
    when v_retryable then 'failed_retryable'
    when v_internal_residual then 'verification_blocked_internal_residual'
    when v_backup_pending then 'primary_purged_backup_expiry_pending'
    when v_external_residual then 'completed_with_external_residuals'
    else 'completed'
  end;

  if new.result::text <> v_expected_result
     or new.primary_absence_verified <> v_primary_verified
     or new.has_internal_residual <> v_internal_residual
     or new.has_external_residual <> v_external_residual
     or new.has_backup_expiry_pending <> v_backup_pending
     or new.backup_latest_possible_expiry_at is distinct from v_latest_backup_expiry then
    raise exception 'Terminal deletion result does not match exact checkpoint outcomes'
      using errcode = '23514';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_dg_erasure_ledger_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_erasure_ledger_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_entry public.inbox_v2_data_governance_erasure_restore_ledger%rowtype;
begin
  if tg_table_name = 'inbox_v2_data_governance_erasure_restore_ledger_evidence' then
    select e.* into v_entry
      from public.inbox_v2_data_governance_erasure_restore_ledger e
     where e.tenant_id = new.tenant_id
       and e.ledger_id = new.ledger_id
       and e.ledger_entry_id = new.ledger_entry_id;

    if v_entry.ledger_entry_id is null
       or (new.slot = 'primary_absence' and v_entry.kind <> 'erasure_applied')
       or (new.slot = 'backup_expiry' and v_entry.kind <> 'erasure_applied')
       or (new.slot = 'control_application' and v_entry.kind not in ('hold_applied', 'restriction_applied', 'hold_released', 'restriction_released', 'control_reapplied'))
       or (new.slot = 'restore' and v_entry.kind not in ('restore_opened', 'restore_sealed')) then
      raise exception 'Ledger evidence slot is incompatible with its entry kind'
        using errcode = '23514';
    end if;
    return null;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_erasure_restore_ledger_controls' then
    select e.* into v_entry
      from public.inbox_v2_data_governance_erasure_restore_ledger e
     where e.tenant_id = new.tenant_id
       and e.ledger_id = new.ledger_id
       and e.ledger_entry_id = new.ledger_entry_id;

    if v_entry.ledger_entry_id is null
       or (new.role = 'required' and v_entry.kind not in ('restore_opened', 'restore_sealed'))
       or (new.role = 'reapplied' and v_entry.kind not in ('control_reapplied', 'restore_sealed')) then
      raise exception 'Ledger control-set row has an incompatible parent entry'
        using errcode = '23514';
    end if;

    if not exists (
      select 1
        from public.inbox_v2_data_governance_erasure_restore_ledger source
       where source.tenant_id = new.tenant_id
         and source.ledger_id = new.ledger_id
         and source.entry_hash = new.control_entry_hash
         and source.control_kind = new.control_kind
         and source.control_id = new.control_id
         and source.control_revision = new.control_revision
         and ((new.control_kind = 'legal_hold' and source.kind = 'hold_applied')
           or (new.control_kind = 'restriction' and source.kind = 'restriction_applied'))
    ) then
      raise exception 'Ledger control-set row does not reference an applied control entry'
        using errcode = '23514';
    end if;
    return null;
  end if;

  if not exists (
    select 1
      from public.inbox_v2_data_governance_registry_versions rv
      join public.inbox_v2_data_governance_storage_roots sr
        on sr.registry_id = rv.id and sr.registry_revision = rv.revision
      join public.inbox_v2_data_governance_contexts c
        on c.tenant_id = new.tenant_id
       and c.context_id = new.governance_context_id
       and c.version = new.governance_context_version
      join public.inbox_v2_data_governance_effective_policies p
        on p.tenant_id = new.tenant_id
       and p.policy_id = new.policy_id
       and p.version = new.policy_version
      join public.inbox_v2_data_governance_policy_activations a
        on a.tenant_id = new.tenant_id
       and a.activation_id = new.activation_id
       and a.revision = new.activation_revision
     where rv.id = new.registry_id
       and rv.revision = new.registry_revision
       and rv.composition_hash = new.registry_composition_hash
       and sr.storage_root_id = new.storage_root_id
       and sr.kind = new.root_kind
       and sr.boundary = new.boundary
       and c.context_hash = new.governance_context_hash
       and c.registry_id = rv.id
       and c.registry_revision = rv.revision
       and p.policy_hash = new.policy_hash
       and p.governance_context_id = c.context_id
       and p.governance_context_version = c.version
       and p.registry_id = rv.id
       and p.registry_revision = rv.revision
       and a.activation_hash = new.activation_hash
       and a.policy_id = p.policy_id
       and a.policy_version = p.version
  ) then
    raise exception 'Ledger entry authority/root hashes are incoherent'
      using errcode = '23514';
  end if;

  if (new.sequence = 1 and new.previous_entry_hash is not null)
     or (new.sequence > 1 and not exists (
       select 1 from public.inbox_v2_data_governance_erasure_restore_ledger prev
        where prev.tenant_id = new.tenant_id
          and prev.ledger_id = new.ledger_id
          and prev.sequence = new.sequence - 1
          and prev.entry_hash = new.previous_entry_hash
          and prev.occurred_at <= new.occurred_at
          and prev.recorded_at <= new.recorded_at
          and (
            new.sync_generation > prev.sync_generation
            or (new.sync_generation = prev.sync_generation
              and new.stream_epoch = prev.stream_epoch
              and new.complete_through_position >= prev.complete_through_position)
          )
     )) then
    raise exception 'Ledger hash chain must be contiguous and high-water monotonic'
      using errcode = '23514';
  end if;

  if new.primary_verification_handler_id is not null and not exists (
    select 1 from public.inbox_v2_data_governance_lifecycle_handlers h
     where h.registry_id = new.registry_id
       and h.registry_revision = new.registry_revision
       and h.handler_id = new.primary_verification_handler_id
       and h.kind = 'verification'
  ) then
    raise exception 'Primary absence evidence uses a non-verification handler'
      using errcode = '23514';
  end if;
  if new.kind = 'erasure_applied' and not exists (
    select 1
      from public.inbox_v2_data_governance_deletion_runs r
      join public.inbox_v2_data_governance_deletion_checkpoint_requirements q
        on q.tenant_id = r.tenant_id
       and q.plan_id = r.plan_id
       and q.plan_revision = r.plan_revision
       and q.surface = 'operated'
      join public.inbox_v2_data_governance_operated_checkpoint_heads h
        on h.tenant_id = r.tenant_id
       and h.run_id = r.run_id
       and h.run_revision = r.revision
       and h.checkpoint_id = q.checkpoint_id
       and h.current_outcome = 'verified_absent'
     where r.tenant_id = new.tenant_id
       and r.run_id = new.deletion_run_id
       and r.revision = new.deletion_run_revision
       and r.state = 'terminal'
       and r.primary_absence_verified
       and q.registry_id = new.registry_id
       and q.registry_revision = new.registry_revision
       and q.storage_root_id = new.storage_root_id
       and q.data_class_id = new.data_class_id
       and q.root_record_id = new.root_record_id
       and q.entity_type_id = new.entity_type_id
       and q.entity_id = new.entity_id
       and q.expected_entity_revision = new.entity_revision
       and q.expected_lineage_revision = new.lineage_revision
  ) then
    raise exception 'Erasure ledger entry requires a terminal verified deletion run'
      using errcode = '23514';
  end if;

  if (new.kind = 'erasure_applied' and not exists (
        select 1 from public.inbox_v2_data_governance_erasure_restore_ledger_evidence ev
         where ev.tenant_id = new.tenant_id and ev.ledger_id = new.ledger_id
           and ev.ledger_entry_id = new.ledger_entry_id and ev.slot = 'primary_absence'
      )) or (new.kind = 'erasure_applied' and not exists (
        select 1 from public.inbox_v2_data_governance_erasure_restore_ledger_evidence ev
         where ev.tenant_id = new.tenant_id and ev.ledger_id = new.ledger_id
           and ev.ledger_entry_id = new.ledger_entry_id and ev.slot = 'backup_expiry'
      )) or (new.kind in ('hold_applied', 'restriction_applied', 'hold_released', 'restriction_released', 'control_reapplied') and not exists (
        select 1 from public.inbox_v2_data_governance_erasure_restore_ledger_evidence ev
         where ev.tenant_id = new.tenant_id and ev.ledger_id = new.ledger_id
           and ev.ledger_entry_id = new.ledger_entry_id and ev.slot = 'control_application'
      )) or (new.kind in ('restore_opened', 'restore_sealed') and not exists (
        select 1 from public.inbox_v2_data_governance_erasure_restore_ledger_evidence ev
         where ev.tenant_id = new.tenant_id and ev.ledger_id = new.ledger_id
           and ev.ledger_entry_id = new.ledger_entry_id and ev.slot = 'restore'
      )) then
    raise exception 'Ledger entry is missing its typed evidence slot'
      using errcode = '23514';
  end if;

  if new.control_kind = 'legal_hold' and not exists (
    select 1 from public.inbox_v2_data_governance_legal_hold_revisions h
     where h.tenant_id = new.tenant_id and h.hold_id = new.control_id
       and h.revision = new.control_revision
  ) then
    raise exception 'Ledger legal-hold reference is missing' using errcode = '23514';
  elsif new.control_kind = 'restriction' and not exists (
    select 1 from public.inbox_v2_data_governance_restriction_revisions r
     where r.tenant_id = new.tenant_id and r.restriction_id = new.control_id
       and r.revision = new.control_revision
  ) then
    raise exception 'Ledger restriction reference is missing' using errcode = '23514';
  end if;

  if new.kind = 'hold_applied' and not exists (
    select 1
      from public.inbox_v2_data_governance_legal_hold_revisions h
      join public.inbox_v2_data_governance_legal_hold_data_classes dc
        on dc.tenant_id = h.tenant_id and dc.hold_id = h.hold_id
       and dc.hold_revision = h.revision and dc.data_class_id = new.data_class_id
      join public.inbox_v2_data_governance_legal_hold_targets ht
        on ht.tenant_id = h.tenant_id and ht.hold_id = h.hold_id
       and ht.hold_revision = h.revision
     where h.tenant_id = new.tenant_id
       and h.hold_id = new.control_id and h.revision = new.control_revision
       and h.state = 'active' and ht.state = 'active'
       and ht.storage_root_id = new.storage_root_id
       and ht.root_record_id = new.root_record_id
       and ht.entity_type_id = new.entity_type_id
       and ht.entity_id = new.entity_id
       and ht.expected_entity_revision = new.entity_revision
       and ht.expected_lineage_revision = new.lineage_revision
  ) then
    raise exception 'Applied hold does not cover the exact ledger target/data class'
      using errcode = '23514';
  elsif new.kind = 'restriction_applied' and not exists (
    select 1
      from public.inbox_v2_data_governance_restriction_revisions r
      join public.inbox_v2_data_governance_scope_manifest_roots sr
        on sr.tenant_id = r.tenant_id
       and sr.manifest_id = r.scope_manifest_id
       and sr.manifest_revision = r.scope_manifest_revision
     where r.tenant_id = new.tenant_id
       and r.restriction_id = new.control_id
       and r.revision = new.control_revision
       and r.state = 'active'
       and sr.data_class_id = new.data_class_id
       and sr.storage_root_id = new.storage_root_id
       and sr.root_record_id = new.root_record_id
       and sr.entity_type_id = new.entity_type_id
       and sr.entity_id = new.entity_id
       and sr.expected_entity_revision = new.entity_revision
       and sr.expected_lineage_revision = new.lineage_revision
  ) then
    raise exception 'Applied restriction does not cover the exact ledger target'
      using errcode = '23514';
  end if;

  if new.kind = 'hold_released' and not exists (
    select 1
      from public.inbox_v2_data_governance_legal_hold_revisions h
      join public.inbox_v2_data_governance_legal_hold_data_classes dc
        on dc.tenant_id = h.tenant_id and dc.hold_id = h.hold_id
       and dc.hold_revision = h.revision and dc.data_class_id = new.data_class_id
      join public.inbox_v2_data_governance_legal_hold_targets ht
        on ht.tenant_id = h.tenant_id and ht.hold_id = h.hold_id
       and ht.hold_revision = h.revision
     where h.tenant_id = new.tenant_id
       and h.hold_id = new.control_id and h.revision = new.control_revision
       and h.state = 'released' and ht.state = 'released'
       and ht.storage_root_id = new.storage_root_id
       and ht.root_record_id = new.root_record_id
       and ht.entity_type_id = new.entity_type_id
       and ht.entity_id = new.entity_id
       and ht.expected_entity_revision = new.entity_revision
       and ht.expected_lineage_revision = new.lineage_revision
  ) then
    raise exception 'Released hold tombstone does not cover the exact ledger target/data class'
      using errcode = '23514';
  elsif new.kind = 'restriction_released' and not exists (
    select 1
      from public.inbox_v2_data_governance_restriction_revisions r
      join public.inbox_v2_data_governance_scope_manifest_roots sr
        on sr.tenant_id = r.tenant_id
       and sr.manifest_id = r.scope_manifest_id
       and sr.manifest_revision = r.scope_manifest_revision
     where r.tenant_id = new.tenant_id
       and r.restriction_id = new.control_id
       and r.revision = new.control_revision
       and r.state = 'released'
       and sr.data_class_id = new.data_class_id
       and sr.storage_root_id = new.storage_root_id
       and sr.root_record_id = new.root_record_id
       and sr.entity_type_id = new.entity_type_id
       and sr.entity_id = new.entity_id
       and sr.expected_entity_revision = new.entity_revision
       and sr.expected_lineage_revision = new.lineage_revision
  ) then
    raise exception 'Released restriction tombstone does not cover the exact ledger target'
      using errcode = '23514';
  end if;

  if new.kind in ('hold_released', 'restriction_released') and not exists (
    select 1
      from public.inbox_v2_data_governance_erasure_restore_ledger applied
     where applied.tenant_id = new.tenant_id
       and applied.ledger_id = new.ledger_id
       and applied.control_kind = new.control_kind
       and applied.control_id = new.control_id
       and applied.kind = case
         when new.kind = 'hold_released' then 'hold_applied'::public.inbox_v2_data_governance_ledger_kind
         else 'restriction_applied'::public.inbox_v2_data_governance_ledger_kind
       end
       and applied.storage_root_id = new.storage_root_id
       and applied.data_class_id = new.data_class_id
       and applied.root_record_id = new.root_record_id
       and applied.entity_type_id = new.entity_type_id
       and applied.entity_id = new.entity_id
       and applied.entity_revision = new.entity_revision
       and applied.lineage_revision = new.lineage_revision
       and applied.sequence < new.sequence
  ) then
    raise exception 'Control release tombstone requires prior applied lineage for the exact target'
      using errcode = '23514';
  end if;

  if new.kind in ('restore_opened', 'restore_sealed') and not exists (
    select 1 from public.inbox_v2_data_governance_erasure_restore_ledger e
     where e.tenant_id = new.tenant_id
       and e.ledger_id = new.ledger_id
       and e.entry_hash = new.source_erasure_entry_hash
       and e.kind = 'erasure_applied'
       and e.storage_root_id = new.storage_root_id
       and e.data_class_id = new.data_class_id
       and e.root_record_id = new.root_record_id
       and e.entity_type_id = new.entity_type_id
       and e.entity_id = new.entity_id
       and e.entity_revision = new.entity_revision
       and e.lineage_revision = new.lineage_revision
       and e.sequence < new.sequence
  ) then
    raise exception 'Restore entry does not reference the target erasure entry'
      using errcode = '23514';
  end if;

  if new.kind = 'restore_opened' and exists (
    select 1 from public.inbox_v2_data_governance_erasure_restore_ledger e
     where e.tenant_id = new.tenant_id and e.ledger_id = new.ledger_id
       and e.restore_id = new.restore_id and e.kind = 'restore_opened'
       and e.ledger_entry_id <> new.ledger_entry_id
  ) then
    raise exception 'Restore id may have only one opening entry' using errcode = '23514';
  end if;

  if new.kind = 'control_reapplied' and not exists (
    select 1
      from public.inbox_v2_data_governance_erasure_restore_ledger opened
      join public.inbox_v2_data_governance_erasure_restore_ledger control
        on control.tenant_id = opened.tenant_id
       and control.ledger_id = opened.ledger_id
       and control.entry_hash = new.source_control_entry_hash
      join public.inbox_v2_data_governance_erasure_restore_ledger_controls required
        on required.tenant_id = opened.tenant_id
       and required.ledger_id = opened.ledger_id
       and required.ledger_entry_id = opened.ledger_entry_id
       and required.role = 'required'
       and required.control_entry_hash = new.source_control_entry_hash
     where opened.tenant_id = new.tenant_id
       and opened.ledger_id = new.ledger_id
       and opened.restore_id = new.restore_id
       and opened.kind = 'restore_opened'
       and opened.sequence < new.sequence
       and opened.storage_root_id = new.storage_root_id
       and opened.data_class_id = new.data_class_id
       and opened.root_record_id = new.root_record_id
       and opened.entity_type_id = new.entity_type_id
       and opened.entity_id = new.entity_id
       and opened.entity_revision = new.entity_revision
       and opened.lineage_revision = new.lineage_revision
       and control.control_kind = new.control_kind
       and control.control_id = new.control_id
       and control.control_revision = new.control_revision
       and control.storage_root_id = new.storage_root_id
       and control.data_class_id = new.data_class_id
       and control.root_record_id = new.root_record_id
       and control.entity_type_id = new.entity_type_id
       and control.entity_id = new.entity_id
       and required.control_kind = new.control_kind
       and required.control_id = new.control_id
       and required.control_revision = new.control_revision
       and not exists (
         select 1 from public.inbox_v2_data_governance_erasure_restore_ledger duplicate
          where duplicate.tenant_id = new.tenant_id
            and duplicate.ledger_id = new.ledger_id
            and duplicate.restore_id = new.restore_id
            and duplicate.kind = 'control_reapplied'
            and duplicate.source_control_entry_hash = new.source_control_entry_hash
            and duplicate.ledger_entry_id <> new.ledger_entry_id
       )
  ) then
    raise exception 'Control reapplication lacks its restore/control source lineage'
      using errcode = '23514';
  end if;

  if new.kind = 'restore_sealed' then
    if new.required_control_hash <> new.reapplied_control_hash
       or not exists (
         select 1 from public.inbox_v2_data_governance_erasure_restore_ledger opened
          where opened.tenant_id = new.tenant_id
            and opened.ledger_id = new.ledger_id
            and opened.restore_id = new.restore_id
            and opened.kind = 'restore_opened'
            and opened.source_erasure_entry_hash = new.source_erasure_entry_hash
            and opened.required_control_hash = new.required_control_hash
            and opened.sequence < new.sequence
       )
       or exists (
         select 1
           from public.inbox_v2_data_governance_erasure_restore_ledger opened
           join public.inbox_v2_data_governance_erasure_restore_ledger_controls required
             on required.tenant_id = opened.tenant_id
            and required.ledger_id = opened.ledger_id
            and required.ledger_entry_id = opened.ledger_entry_id
            and required.role = 'required'
          where opened.tenant_id = new.tenant_id
            and opened.ledger_id = new.ledger_id
            and opened.restore_id = new.restore_id
            and opened.kind = 'restore_opened'
            and not exists (
              select 1 from public.inbox_v2_data_governance_erasure_restore_ledger_controls sealed_required
               where sealed_required.tenant_id = new.tenant_id
                 and sealed_required.ledger_id = new.ledger_id
                 and sealed_required.ledger_entry_id = new.ledger_entry_id
                 and sealed_required.role = 'required'
                 and sealed_required.control_kind = required.control_kind
                 and sealed_required.control_id = required.control_id
                 and sealed_required.control_revision = required.control_revision
                 and sealed_required.control_entry_hash = required.control_entry_hash
            )
       )
       or exists (
         select 1
           from public.inbox_v2_data_governance_erasure_restore_ledger_controls sealed_required
          where sealed_required.tenant_id = new.tenant_id
            and sealed_required.ledger_id = new.ledger_id
            and sealed_required.ledger_entry_id = new.ledger_entry_id
            and sealed_required.role = 'required'
            and not exists (
              select 1
                from public.inbox_v2_data_governance_erasure_restore_ledger opened
                join public.inbox_v2_data_governance_erasure_restore_ledger_controls required
                  on required.tenant_id = opened.tenant_id
                 and required.ledger_id = opened.ledger_id
                 and required.ledger_entry_id = opened.ledger_entry_id
                 and required.role = 'required'
               where opened.tenant_id = new.tenant_id
                 and opened.ledger_id = new.ledger_id
                 and opened.restore_id = new.restore_id
                 and opened.kind = 'restore_opened'
                 and required.control_kind = sealed_required.control_kind
                 and required.control_id = sealed_required.control_id
                 and required.control_revision = sealed_required.control_revision
                 and required.control_entry_hash = sealed_required.control_entry_hash
            )
       )
       or exists (
         select 1
           from public.inbox_v2_data_governance_erasure_restore_ledger opened
           join public.inbox_v2_data_governance_erasure_restore_ledger_controls required
             on required.tenant_id = opened.tenant_id
            and required.ledger_id = opened.ledger_id
            and required.ledger_entry_id = opened.ledger_entry_id
            and required.role = 'required'
          where opened.tenant_id = new.tenant_id
            and opened.ledger_id = new.ledger_id
            and opened.restore_id = new.restore_id
            and opened.kind = 'restore_opened'
            and not exists (
              select 1 from public.inbox_v2_data_governance_erasure_restore_ledger reapplied_entry
               where reapplied_entry.tenant_id = new.tenant_id
                 and reapplied_entry.ledger_id = new.ledger_id
                 and reapplied_entry.restore_id = new.restore_id
                 and reapplied_entry.kind = 'control_reapplied'
                 and reapplied_entry.source_control_entry_hash = required.control_entry_hash
                 and reapplied_entry.control_kind = required.control_kind
                 and reapplied_entry.control_id = required.control_id
                 and reapplied_entry.control_revision = required.control_revision
                 and reapplied_entry.sequence < new.sequence
            )
       )
       or exists (
         select 1 from public.inbox_v2_data_governance_erasure_restore_ledger reapplied_entry
          where reapplied_entry.tenant_id = new.tenant_id
            and reapplied_entry.ledger_id = new.ledger_id
            and reapplied_entry.restore_id = new.restore_id
            and reapplied_entry.kind = 'control_reapplied'
            and reapplied_entry.sequence < new.sequence
            and not exists (
              select 1
                from public.inbox_v2_data_governance_erasure_restore_ledger opened
                join public.inbox_v2_data_governance_erasure_restore_ledger_controls required
                  on required.tenant_id = opened.tenant_id
                 and required.ledger_id = opened.ledger_id
                 and required.ledger_entry_id = opened.ledger_entry_id
                 and required.role = 'required'
               where opened.tenant_id = new.tenant_id
                 and opened.ledger_id = new.ledger_id
                 and opened.restore_id = new.restore_id
                 and opened.kind = 'restore_opened'
                 and required.control_entry_hash = reapplied_entry.source_control_entry_hash
                 and required.control_kind = reapplied_entry.control_kind
                 and required.control_id = reapplied_entry.control_id
                 and required.control_revision = reapplied_entry.control_revision
            )
       )
       or exists (
         select 1
           from public.inbox_v2_data_governance_erasure_restore_ledger_controls required
          where required.tenant_id = new.tenant_id
            and required.ledger_id = new.ledger_id
            and required.ledger_entry_id = new.ledger_entry_id
            and required.role = 'required'
            and not exists (
              select 1 from public.inbox_v2_data_governance_erasure_restore_ledger_controls reapplied
               where reapplied.tenant_id = required.tenant_id
                 and reapplied.ledger_id = required.ledger_id
                 and reapplied.ledger_entry_id = required.ledger_entry_id
                 and reapplied.role = 'reapplied'
                 and reapplied.control_kind = required.control_kind
                 and reapplied.control_id = required.control_id
                 and reapplied.control_revision = required.control_revision
                 and reapplied.control_entry_hash = required.control_entry_hash
            )
       )
       or exists (
         select 1
           from public.inbox_v2_data_governance_erasure_restore_ledger_controls reapplied
          where reapplied.tenant_id = new.tenant_id
            and reapplied.ledger_id = new.ledger_id
            and reapplied.ledger_entry_id = new.ledger_entry_id
            and reapplied.role = 'reapplied'
            and not exists (
              select 1 from public.inbox_v2_data_governance_erasure_restore_ledger_controls required
               where required.tenant_id = reapplied.tenant_id
                 and required.ledger_id = reapplied.ledger_id
                 and required.ledger_entry_id = reapplied.ledger_entry_id
                 and required.role = 'required'
                 and required.control_kind = reapplied.control_kind
                 and required.control_id = reapplied.control_id
                 and required.control_revision = reapplied.control_revision
                 and required.control_entry_hash = reapplied.control_entry_hash
            )
       ) then
      raise exception 'Restore seal does not prove the exact required/reapplied control set'
        using errcode = '23514';
    end if;
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_dg_governance_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_governance_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_table_name = 'inbox_v2_data_governance_scope_manifest_roots' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_storage_roots r
       where r.registry_id = new.registry_id
         and r.registry_revision = new.registry_revision
         and r.storage_root_id = new.storage_root_id
         and r.kind = new.root_kind
         and r.boundary = new.boundary
    ) then
      raise exception 'Scope root kind/boundary differs from the registered root'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_tenant_termination_scope_authorities' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_scope_manifests sm
        join public.inbox_v2_data_governance_registry_versions rv
          on rv.id = sm.registry_id and rv.revision = sm.registry_revision
        join public.inbox_v2_data_governance_contexts c
          on c.tenant_id = sm.tenant_id
         and c.context_id = new.governance_context_id
         and c.version = new.governance_context_version
        join public.inbox_v2_data_governance_effective_policies p
          on p.tenant_id = sm.tenant_id
         and p.policy_id = new.policy_id
         and p.version = new.policy_version
        join public.inbox_v2_data_governance_policy_activations a
          on a.tenant_id = sm.tenant_id
         and a.activation_id = new.activation_id
         and a.revision = new.activation_revision
       where sm.tenant_id = new.tenant_id
         and sm.manifest_id = new.manifest_id
         and sm.revision = new.manifest_revision
         and sm.kind = 'tenant_wide'
         and rv.composition_hash = new.registry_composition_hash
         and c.context_hash = new.governance_context_hash
         and c.registry_id = sm.registry_id
         and c.registry_revision = sm.registry_revision
         and p.policy_hash = new.policy_hash
         and p.registry_id = sm.registry_id
         and p.registry_revision = sm.registry_revision
         and p.governance_context_id = c.context_id
         and p.governance_context_version = c.version
         and a.activation_hash = new.activation_hash
         and a.policy_id = p.policy_id
         and a.policy_version = p.version
         and a.governance_context_id = c.context_id
         and a.governance_context_version = c.version
         and a.governance_context_hash = c.context_hash
    ) then
      raise exception 'Tenant-termination scope authority is not exact or tenant-wide'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_subject_links' then
    if new.account_id is not null and not exists (
      select 1 from public.accounts a
       where a.id = new.account_id and a.tenant_id = new.tenant_id
    ) then
      raise exception 'Subject-link account crosses the tenant boundary'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_policy_activations' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_effective_policies p
        join public.inbox_v2_data_governance_contexts c
          on c.tenant_id = p.tenant_id
         and c.context_id = p.governance_context_id
         and c.version = p.governance_context_version
       where p.tenant_id = new.tenant_id
         and p.policy_id = new.policy_id
         and p.version = new.policy_version
         and p.policy_hash = new.candidate_policy_hash
         and c.context_id = new.governance_context_id
         and c.version = new.governance_context_version
         and c.context_hash = new.governance_context_hash
    ) then
      raise exception 'Policy activation authority hash/context mismatch'
        using errcode = '23514';
    end if;
    if new.transition_kind = 'supersede_current' and not exists (
      select 1 from public.inbox_v2_data_governance_policy_activations p
       where p.tenant_id = new.tenant_id
         and p.activation_id = new.prior_activation_id
         and p.revision = new.prior_activation_revision
         and p.policy_id = new.policy_id
         and p.policy_version = new.prior_policy_version
         and p.policy_version < new.policy_version
    ) then
      raise exception 'Policy activation prior lineage is missing or stale'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_policy_activation_heads' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_policy_activations a
       where a.tenant_id = new.tenant_id
         and a.activation_id = new.current_activation_id
         and a.revision = new.current_activation_revision
         and a.policy_id = new.policy_id
         and a.policy_version = new.current_policy_version
         and (
           (tg_op = 'INSERT' and a.transition_kind = 'initial_reviewed_bootstrap')
           or (tg_op = 'UPDATE'
             and a.transition_kind = 'supersede_current'
             and a.prior_activation_id = old.current_activation_id
             and a.prior_activation_revision = old.current_activation_revision
             and a.prior_policy_version = old.current_policy_version)
         )
    ) then
      raise exception 'Policy activation head points to a different policy lineage'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_legal_hold_targets' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_legal_hold_revisions h
        join public.inbox_v2_data_governance_scope_manifest_roots s
          on s.tenant_id = h.tenant_id
         and s.manifest_id = h.scope_manifest_id
         and s.manifest_revision = h.scope_manifest_revision
         and s.storage_root_id = new.storage_root_id
         and s.root_record_id = new.root_record_id
       where h.tenant_id = new.tenant_id
         and h.hold_id = new.hold_id
         and h.revision = new.hold_revision
         and h.state = new.state
         and h.scope_manifest_id = new.scope_manifest_id
         and h.scope_manifest_revision = new.scope_manifest_revision
         and s.entity_type_id = new.entity_type_id
         and s.entity_id = new.entity_id
         and s.expected_entity_revision = new.expected_entity_revision
         and s.expected_lineage_revision = new.expected_lineage_revision
    ) then
      raise exception 'Legal-hold target is not an exact frozen scope member'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_legal_hold_heads' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_legal_hold_revisions h
       where h.tenant_id = new.tenant_id
         and h.hold_id = new.hold_id
         and h.revision = new.current_revision
         and h.state = new.state
    ) then
      raise exception 'Legal-hold head/revision state mismatch' using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_restriction_heads' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_restriction_revisions r
       where r.tenant_id = new.tenant_id
         and r.restriction_id = new.restriction_id
         and r.revision = new.current_revision
         and r.state = new.state
    ) then
      raise exception 'Restriction head/revision state mismatch' using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_privacy_request_heads' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_privacy_request_revisions r
       where r.tenant_id = new.tenant_id
         and r.request_id = new.request_id
         and r.revision = new.current_revision
         and r.state = new.current_state
    ) then
      raise exception 'Privacy-request head/revision state mismatch' using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_export_jobs' then
    if new.product_kind = 'tenant_deployment' and not exists (
      select 1
        from public.inbox_v2_data_governance_tenant_termination_scope_authorities tsa
        join public.inbox_v2_data_governance_scope_manifests sm
          on sm.tenant_id = tsa.tenant_id
         and sm.manifest_id = tsa.manifest_id
         and sm.revision = tsa.manifest_revision
        join public.inbox_v2_data_governance_policy_activation_heads ah
          on ah.tenant_id = tsa.tenant_id
         and ah.policy_id = tsa.policy_id
       where tsa.tenant_id = new.tenant_id
         and tsa.manifest_id = new.scope_manifest_id
         and tsa.manifest_revision = new.scope_manifest_revision
         and tsa.proof_hash = new.product_authority_hash
         and tsa.manifest_id = new.product_authority_id
         and tsa.manifest_revision = new.product_authority_revision
         and tsa.governance_context_id = new.governance_context_id
         and tsa.governance_context_version = new.governance_context_version
         and tsa.governance_context_hash = new.governance_context_hash
         and tsa.policy_id = new.policy_id
         and tsa.policy_version = new.policy_version
         and tsa.policy_hash = new.policy_hash
         and tsa.activation_id = new.activation_id
         and tsa.activation_revision = new.activation_revision
         and tsa.activation_hash = new.activation_hash
         and sm.registry_id = new.registry_id
         and sm.registry_revision = new.registry_revision
         and ah.current_policy_version = tsa.policy_version
         and ah.current_activation_id = tsa.activation_id
         and ah.current_activation_revision = tsa.activation_revision
    ) then
      raise exception 'Tenant deployment export job lacks exact current scope/policy authority'
        using errcode = '23514';
    end if;
    if new.product_kind <> 'tenant_deployment' and exists (
      select 1
        from public.inbox_v2_data_governance_tenant_termination_scope_authorities tsa
       where tsa.tenant_id = new.tenant_id
         and tsa.manifest_id = new.scope_manifest_id
         and tsa.manifest_revision = new.scope_manifest_revision
    ) then
      raise exception 'Non-tenant export cannot reuse tenant-termination scope authority'
        using errcode = '23514';
    end if;
    if new.export_manifest_id is not null and not exists (
      select 1 from public.inbox_v2_data_governance_export_manifests m
       where m.tenant_id = new.tenant_id
         and m.manifest_id = new.export_manifest_id
         and m.revision = new.export_manifest_revision
         and m.job_id = new.job_id
         and m.job_revision = new.revision
    ) then
      raise exception 'Export job references a manifest from another job/revision'
        using errcode = '23514';
    end if;
    if new.export_artifact_id is not null and not exists (
      select 1
        from public.inbox_v2_data_governance_export_artifact_heads h
        join public.inbox_v2_data_governance_export_artifacts ar
          on ar.tenant_id = h.tenant_id
         and ar.artifact_id = h.artifact_id
         and ar.revision = h.current_revision
         and ar.job_id = h.job_id
         and ar.job_revision = h.job_revision
         and ar.artifact_claim_key = h.artifact_claim_key
         and ar.state = h.current_state
       where h.tenant_id = new.tenant_id
         and h.artifact_id = new.export_artifact_id
         and h.current_revision = new.export_artifact_revision
         and h.job_id = new.job_id
         and h.job_revision = new.revision
         and (
           (new.state = 'running' and h.current_state = 'building')
           or (new.state = 'ready' and h.current_state = 'ready')
           or (new.state in ('revoked', 'expired', 'failed_retryable')
             and h.current_state in ('quarantined', 'deleted'))
           or (new.state = 'completed' and h.current_state = 'deleted')
         )
    ) then
      raise exception 'Export job does not bind its exact current artifact head'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_export_manifests' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_export_jobs j
        left join public.inbox_v2_data_governance_scope_manifests sm
          on sm.tenant_id = j.tenant_id
         and sm.manifest_id = j.scope_manifest_id
         and sm.revision = j.scope_manifest_revision
        left join public.inbox_v2_data_governance_tenant_termination_scope_authorities tsa
          on tsa.tenant_id = j.tenant_id
         and tsa.manifest_id = j.scope_manifest_id
         and tsa.manifest_revision = j.scope_manifest_revision
       where j.tenant_id = new.tenant_id
         and j.job_id = new.job_id
         and j.revision = new.job_revision
         and new.scope_proof_hash = j.product_authority_hash
         and (j.export_manifest_id is null or (
           j.export_manifest_id = new.manifest_id
           and j.export_manifest_revision = new.revision
         ))
         and (
           (j.product_kind = 'manager_report'
             and new.scope_manifest_id is null
             and new.scope_manifest_revision is null)
           or (j.product_kind = 'data_subject'
             and new.scope_manifest_id = j.scope_manifest_id
             and new.scope_manifest_revision = j.scope_manifest_revision
             and new.stream_epoch = sm.stream_epoch
             and new.sync_generation = sm.sync_generation
             and new.complete_through_position = sm.complete_through_position)
           or (j.product_kind = 'tenant_deployment'
             and new.scope_manifest_id = tsa.manifest_id
             and new.scope_manifest_revision = tsa.manifest_revision
             and new.scope_proof_hash = tsa.proof_hash
             and new.root_set_hash = tsa.export_root_set_hash
             and new.stream_epoch = sm.stream_epoch
             and new.sync_generation = sm.sync_generation
             and new.complete_through_position = sm.complete_through_position)
         )
    ) then
      raise exception 'Export manifest does not bind exact job scope/root/high-water authority'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_export_artifacts' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_export_jobs j
       where j.tenant_id = new.tenant_id
         and j.job_id = new.job_id
         and j.revision = new.job_revision
    ) then
      raise exception 'Export artifact crosses its job authority'
        using errcode = '23514';
    end if;
    if new.state = 'ready' and not exists (
      select 1
        from public.inbox_v2_data_governance_export_manifests m
        join public.inbox_v2_data_governance_export_jobs j
          on j.tenant_id = m.tenant_id
         and j.job_id = m.job_id
         and j.revision = m.job_revision
       where m.tenant_id = new.tenant_id
         and m.manifest_id = new.manifest_id
         and m.revision = new.manifest_revision
         and m.manifest_hash = new.manifest_hash
         and m.job_id = new.job_id
         and m.job_revision = new.job_revision
         and (j.export_manifest_id is null or (
           j.export_manifest_id = m.manifest_id
           and j.export_manifest_revision = m.revision
         ))
    ) then
      raise exception 'Ready export artifact is not bound to its exact manifest hash'
        using errcode = '23514';
    end if;
    if (new.revision = 1 and new.state <> 'building')
       or (new.revision > 1 and not exists (
         select 1 from public.inbox_v2_data_governance_export_artifacts prior
          where prior.tenant_id = new.tenant_id
            and prior.artifact_id = new.artifact_id
            and prior.revision = new.revision - 1
            and prior.job_id = new.job_id
            and prior.job_revision = new.job_revision
            and prior.artifact_claim_key = new.artifact_claim_key
            and new.recorded_at > prior.recorded_at
            and (
              (prior.state = 'building' and new.state in ('ready', 'quarantined', 'deleted'))
              or (prior.state = 'ready' and new.state in ('quarantined', 'deleted'))
              or (prior.state = 'quarantined' and new.state = 'deleted')
            )
       )) then
      raise exception 'Export artifact revision uses a gap, changed authority or illegal edge'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_export_artifact_heads' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_export_artifacts ar
       where ar.tenant_id = new.tenant_id
         and ar.artifact_id = new.artifact_id
         and ar.revision = new.current_revision
         and ar.job_id = new.job_id
         and ar.job_revision = new.job_revision
         and ar.artifact_claim_key = new.artifact_claim_key
         and ar.state = new.current_state
    ) then
      raise exception 'Export artifact head points to a different immutable revision'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_export_claims' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_export_manifests m
        join public.inbox_v2_data_governance_export_artifact_heads h
          on h.tenant_id = m.tenant_id
         and h.job_id = m.job_id
         and h.job_revision = m.job_revision
         and h.artifact_claim_key = new.artifact_claim_key
        join public.inbox_v2_data_governance_export_artifacts ar
          on ar.tenant_id = h.tenant_id
         and ar.artifact_id = h.artifact_id
         and ar.revision = h.current_revision
         and ar.job_id = h.job_id
         and ar.job_revision = h.job_revision
         and ar.artifact_claim_key = h.artifact_claim_key
         and ar.state = h.current_state
       where m.tenant_id = new.tenant_id
         and m.manifest_id = new.manifest_id
         and m.revision = new.manifest_revision
         and m.job_id = new.job_id
         and m.job_revision = new.job_revision
         and h.current_state = 'ready'
         and ar.state = 'ready'
         and ar.manifest_id = m.manifest_id
         and ar.manifest_revision = m.revision
         and ar.manifest_hash = m.manifest_hash
         and ar.payload_checksum is not null
         and ar.packaging_proof_hash = new.packaging_proof_hash
         and ar.archive_composition_hash = new.archive_composition_hash
         and ar.ready_at <= new.created_at
         and ar.expires_at > new.created_at
         and ar.deleted_at is null
    ) then
      raise exception 'Export claim mixes job and export-manifest lineages'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_export_receipt_cas' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_export_claims c
       where c.tenant_id = new.tenant_id
         and c.artifact_claim_key = new.artifact_claim_key
         and c.receipt_key = new.receipt_key
         and c.principal_key = new.principal_key
         and c.claim_revision = new.claim_revision
         and c.job_id = new.job_id
         and c.job_revision = new.job_revision
         and c.manifest_id = new.manifest_id
         and c.manifest_revision = new.manifest_revision
         and c.packaging_proof_hash = new.packaging_proof_hash
         and c.archive_composition_hash = new.archive_composition_hash
         and c.issued_receipt_hash = new.issued_receipt_hash
    ) then
      raise exception 'Receipt CAS lineage differs from its immutable claim'
        using errcode = '23514';
    end if;
    if new.state in ('issued', 'consumed') and not exists (
      select 1
        from public.inbox_v2_data_governance_export_artifact_heads h
        join public.inbox_v2_data_governance_export_artifacts ar
          on ar.tenant_id = h.tenant_id
         and ar.artifact_id = h.artifact_id
         and ar.revision = h.current_revision
         and ar.job_id = h.job_id
         and ar.job_revision = h.job_revision
         and ar.artifact_claim_key = h.artifact_claim_key
         and ar.state = h.current_state
        join public.inbox_v2_data_governance_export_jobs j
          on j.tenant_id = h.tenant_id
         and j.job_id = h.job_id
         and j.revision = h.job_revision
         and j.export_artifact_id = h.artifact_id
         and j.export_artifact_revision = h.current_revision
       where h.tenant_id = new.tenant_id
         and h.artifact_claim_key = new.artifact_claim_key
         and h.current_state = 'ready'
         and j.job_id = new.job_id
         and j.revision = new.job_revision
         and j.state = 'ready'
         and j.export_manifest_id = new.manifest_id
         and j.export_manifest_revision = new.manifest_revision
         and ar.manifest_id = new.manifest_id
         and ar.manifest_revision = new.manifest_revision
         and ar.payload_checksum is not null
         and ar.packaging_proof_hash = new.packaging_proof_hash
         and ar.archive_composition_hash = new.archive_composition_hash
         and ar.ready_at <= new.updated_at
         and ar.expires_at > new.updated_at
         and ar.deleted_at is null
    ) then
      raise exception 'Receipt issue/consume requires the exact current ready artifact head'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_deletion_run_terminal_exports' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_deletion_runs dr
        join public.inbox_v2_data_governance_deletion_plans p
          on p.tenant_id = dr.tenant_id
         and p.plan_id = dr.plan_id
         and p.revision = dr.plan_revision
        join public.inbox_v2_data_governance_export_jobs j
          on j.tenant_id = dr.tenant_id
         and j.job_id = new.job_id
         and j.revision = new.job_revision
        join public.inbox_v2_data_governance_export_manifests m
          on m.tenant_id = j.tenant_id
         and m.manifest_id = new.manifest_id
         and m.revision = new.manifest_revision
         and m.job_id = j.job_id
         and m.job_revision = j.revision
        join public.inbox_v2_data_governance_export_artifact_heads h
          on h.tenant_id = j.tenant_id
         and h.artifact_id = new.artifact_id
         and h.job_id = j.job_id
         and h.job_revision = j.revision
        join public.inbox_v2_data_governance_export_artifacts ar
          on ar.tenant_id = h.tenant_id
         and ar.artifact_id = h.artifact_id
         and ar.revision = new.artifact_revision
         and ar.job_id = h.job_id
         and ar.job_revision = h.job_revision
         and ar.artifact_claim_key = h.artifact_claim_key
        join public.inbox_v2_data_governance_scope_manifests sm
          on sm.tenant_id = p.tenant_id
         and sm.manifest_id = p.manifest_id
         and sm.revision = p.manifest_revision
        join public.inbox_v2_data_governance_tenant_termination_scope_authorities tsa
          on tsa.tenant_id = sm.tenant_id
         and tsa.manifest_id = sm.manifest_id
         and tsa.manifest_revision = sm.revision
        join public.inbox_v2_data_governance_policy_activation_heads ah
          on ah.tenant_id = p.tenant_id
         and ah.policy_id = p.policy_id
       where dr.tenant_id = new.tenant_id
         and dr.run_id = new.run_id
         and dr.revision = new.run_revision
         and new.bound_at >= dr.started_at
         and new.bound_at <= clock_timestamp()
         and p.cause = 'tenant_offboarding'
         and j.product_kind = 'tenant_deployment'
         and j.state = 'ready'
         and j.product_authority_id = tsa.manifest_id
         and j.product_authority_revision = tsa.manifest_revision
         and j.product_authority_hash = tsa.proof_hash
         and j.scope_manifest_id = p.manifest_id
         and j.scope_manifest_revision = p.manifest_revision
         and j.registry_id = p.registry_id
         and j.registry_revision = p.registry_revision
         and j.governance_context_id = p.governance_context_id
         and j.governance_context_version = p.governance_context_version
         and j.governance_context_hash = p.governance_context_hash
         and j.policy_id = p.policy_id
         and j.policy_version = p.policy_version
         and j.policy_hash = p.policy_hash
         and j.activation_id = p.activation_id
         and j.activation_revision = p.activation_revision
         and j.activation_hash = p.activation_hash
         and j.export_manifest_id = m.manifest_id
         and j.export_manifest_revision = m.revision
         and j.export_artifact_id = h.artifact_id
         and j.export_artifact_revision = h.current_revision
         and m.scope_manifest_id = sm.manifest_id
         and m.scope_manifest_revision = sm.revision
         and m.scope_proof_hash = tsa.proof_hash
         and m.root_set_hash = tsa.export_root_set_hash
         and m.stream_epoch = p.stream_epoch
         and m.sync_generation = p.sync_generation
         and m.complete_through_position = p.complete_through_position
         and m.stream_epoch = sm.stream_epoch
         and m.sync_generation = sm.sync_generation
         and m.complete_through_position = sm.complete_through_position
         and tsa.registry_composition_hash = p.registry_composition_hash
         and tsa.governance_context_id = p.governance_context_id
         and tsa.governance_context_version = p.governance_context_version
         and tsa.governance_context_hash = p.governance_context_hash
         and tsa.policy_id = p.policy_id
         and tsa.policy_version = p.policy_version
         and tsa.policy_hash = p.policy_hash
         and tsa.activation_id = p.activation_id
         and tsa.activation_revision = p.activation_revision
         and tsa.activation_hash = p.activation_hash
         and ah.current_policy_version = p.policy_version
         and ah.current_activation_id = p.activation_id
         and ah.current_activation_revision = p.activation_revision
         and h.current_revision = ar.revision
         and h.current_state = 'ready'
         and ar.state = 'ready'
         and ar.manifest_id = m.manifest_id
         and ar.manifest_revision = m.revision
         and ar.manifest_hash = m.manifest_hash
         and ar.payload_checksum is not null
         and ar.payload_locator is not null
         and ar.ready_at <= new.bound_at
         and ar.expires_at > new.bound_at
         and ar.expires_at > clock_timestamp()
         and ar.deleted_at is null
    ) then
      raise exception 'Deletion run terminal export is not exact, current, ready or unexpired'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_deletion_plans' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_registry_versions rv
        join public.inbox_v2_data_governance_scope_manifests sm
          on sm.registry_id = rv.id and sm.registry_revision = rv.revision
        join public.inbox_v2_data_governance_contexts c
          on c.tenant_id = new.tenant_id
         and c.context_id = new.governance_context_id
         and c.version = new.governance_context_version
        join public.inbox_v2_data_governance_effective_policies p
          on p.tenant_id = new.tenant_id
         and p.policy_id = new.policy_id
         and p.version = new.policy_version
        join public.inbox_v2_data_governance_policy_activations a
          on a.tenant_id = new.tenant_id
         and a.activation_id = new.activation_id
         and a.revision = new.activation_revision
       where rv.id = new.registry_id
         and rv.revision = new.registry_revision
         and rv.composition_hash = new.registry_composition_hash
         and sm.tenant_id = new.tenant_id
         and sm.manifest_id = new.manifest_id
         and sm.revision = new.manifest_revision
         and sm.stream_epoch = new.stream_epoch
         and sm.sync_generation = new.sync_generation
         and sm.complete_through_position = new.complete_through_position
         and c.context_hash = new.governance_context_hash
         and c.registry_id = rv.id and c.registry_revision = rv.revision
         and p.policy_hash = new.policy_hash
         and p.registry_id = rv.id and p.registry_revision = rv.revision
         and p.governance_context_id = c.context_id
         and p.governance_context_version = c.version
         and a.activation_hash = new.activation_hash
         and a.policy_id = p.policy_id and a.policy_version = p.version
         and a.governance_context_id = c.context_id
         and a.governance_context_version = c.version
         and (
           new.request_id is null
           or exists (
             select 1 from public.inbox_v2_data_governance_privacy_request_revisions pr
              where pr.tenant_id = new.tenant_id
                and pr.request_id = new.request_id
                and pr.revision = new.request_revision
                and new.decision_basis_id = pr.request_id
                and new.decision_basis_hash = pr.decision_hash
                and pr.policy_id = p.policy_id and pr.policy_version = p.version
                and pr.governance_context_id = c.context_id
                and pr.governance_context_version = c.version
           )
         )
    ) then
      raise exception 'Deletion plan authority, manifest or decision lineage is incoherent'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_destructive_checkpoint_leases' then
    if not exists (
      select 1
        from public.inbox_v2_data_governance_deletion_checkpoint_requirements q
        join public.inbox_v2_data_governance_deletion_plans p
          on p.tenant_id = q.tenant_id and p.plan_id = q.plan_id
         and p.revision = q.plan_revision
        join public.inbox_v2_data_governance_policy_activation_heads ah
          on ah.tenant_id = p.tenant_id and ah.policy_id = p.policy_id
         and ah.current_policy_version = p.policy_version
         and ah.current_activation_id = p.activation_id
         and ah.current_activation_revision = p.activation_revision
        join public.inbox_v2_data_governance_control_set_heads cs
          on cs.tenant_id = p.tenant_id
         and cs.legal_hold_set_revision = p.legal_hold_set_revision
         and cs.restriction_set_revision = p.restriction_set_revision
       where q.tenant_id = new.tenant_id
         and q.plan_id = new.plan_id and q.plan_revision = new.plan_revision
         and q.checkpoint_id = new.checkpoint_id
         and q.requirement_hash = new.requirement_hash
         and q.surface = new.surface
         and q.registry_id = new.registry_id
         and q.registry_revision = new.registry_revision
         and p.registry_composition_hash = new.registry_composition_hash
         and q.storage_root_id = new.storage_root_id
         and q.data_class_id = new.data_class_id
         and q.root_record_id = new.root_record_id
         and q.entity_type_id = new.entity_type_id
         and q.entity_id = new.entity_id
         and q.expected_entity_revision = new.expected_entity_revision
         and q.expected_lineage_revision = new.expected_lineage_revision
         and p.governance_context_id = new.governance_context_id
         and p.governance_context_version = new.governance_context_version
         and p.governance_context_hash = new.governance_context_hash
         and p.policy_id = new.policy_id and p.policy_version = new.policy_version
         and p.policy_hash = new.policy_hash
         and p.activation_id = new.activation_id
         and p.activation_revision = new.activation_revision
         and p.activation_hash = new.activation_hash
         and p.legal_hold_set_revision = new.legal_hold_set_revision
         and p.restriction_set_revision = new.restriction_set_revision
         and ((q.surface = 'operated' and q.delete_handler_id = new.execution_handler_id)
           or (q.surface = 'backup' and q.expiry_ledger_handler_id = new.execution_handler_id)
           or (q.surface = 'external' and q.external_delete_handler_id = new.execution_handler_id))
         and not exists (
           select 1
             from public.inbox_v2_data_governance_legal_hold_targets ht
             join public.inbox_v2_data_governance_legal_hold_heads hh
               on hh.tenant_id = ht.tenant_id and hh.hold_id = ht.hold_id
              and hh.current_revision = ht.hold_revision and hh.state = 'active'
            where ht.tenant_id = q.tenant_id
              and ht.storage_root_id = q.storage_root_id
              and ht.root_record_id = q.root_record_id
              and ht.entity_type_id = q.entity_type_id
              and ht.entity_id = q.entity_id
              and ht.state = 'active'
         )
         and (
           p.cause <> 'tenant_offboarding'
           or exists (
             select 1
               from public.inbox_v2_data_governance_deletion_run_terminal_exports binding
               join public.inbox_v2_data_governance_export_jobs export_job
                 on export_job.tenant_id = binding.tenant_id
                and export_job.job_id = binding.job_id
                and export_job.revision = binding.job_revision
                and export_job.state = 'ready'
                and export_job.product_kind = 'tenant_deployment'
                and export_job.export_manifest_id = binding.manifest_id
                and export_job.export_manifest_revision = binding.manifest_revision
                and export_job.export_artifact_id = binding.artifact_id
                and export_job.export_artifact_revision = binding.artifact_revision
               join public.inbox_v2_data_governance_export_artifact_heads artifact_head
                 on artifact_head.tenant_id = binding.tenant_id
                and artifact_head.artifact_id = binding.artifact_id
                and artifact_head.job_id = binding.job_id
                and artifact_head.job_revision = binding.job_revision
                and artifact_head.current_revision = binding.artifact_revision
                and artifact_head.current_state = 'ready'
               join public.inbox_v2_data_governance_export_artifacts artifact
                 on artifact.tenant_id = artifact_head.tenant_id
                and artifact.artifact_id = artifact_head.artifact_id
                and artifact.revision = artifact_head.current_revision
                and artifact.job_id = artifact_head.job_id
                and artifact.job_revision = artifact_head.job_revision
                and artifact.artifact_claim_key = artifact_head.artifact_claim_key
                and artifact.state = 'ready'
                and artifact.manifest_id = binding.manifest_id
                and artifact.manifest_revision = binding.manifest_revision
              where binding.tenant_id = new.tenant_id
                and binding.run_id = new.run_id
                and binding.run_revision = new.run_revision
                and binding.bound_at <= new.claimed_at
                and artifact.ready_at <= new.claimed_at
                and artifact.expires_at > new.claimed_at
                and artifact.expires_at >= new.lease_expires_at
                and artifact.payload_locator is not null
                and artifact.payload_checksum is not null
           )
         )
    ) then
      raise exception 'Destructive lease uses stale or substituted authority'
        using errcode = '23514';
    end if;
  elsif tg_table_name = 'inbox_v2_data_governance_deletion_checkpoint_requirements' then
    if not exists (
      select 1 from public.inbox_v2_data_governance_storage_roots r
       where r.registry_id = new.registry_id
         and r.registry_revision = new.registry_revision
         and r.storage_root_id = new.storage_root_id
         and r.kind = new.root_kind
         and r.boundary = new.boundary
    ) then
      raise exception 'Checkpoint requirement root kind/boundary mismatch'
        using errcode = '23514';
    end if;
    if (new.surface = 'operated' and not (
          exists (select 1 from public.inbox_v2_data_governance_lifecycle_handlers h where h.registry_id = new.registry_id and h.registry_revision = new.registry_revision and h.handler_id = new.delete_handler_id and h.kind = 'delete_execution')
      and exists (select 1 from public.inbox_v2_data_governance_lifecycle_handlers h where h.registry_id = new.registry_id and h.registry_revision = new.registry_revision and h.handler_id = new.verification_handler_id and h.kind = 'verification')
       )) or (new.surface = 'backup' and not (
          exists (select 1 from public.inbox_v2_data_governance_lifecycle_handlers h where h.registry_id = new.registry_id and h.registry_revision = new.registry_revision and h.handler_id = new.verification_handler_id and h.kind = 'verification')
      and exists (select 1 from public.inbox_v2_data_governance_lifecycle_handlers h where h.registry_id = new.registry_id and h.registry_revision = new.registry_revision and h.handler_id = new.expiry_ledger_handler_id and h.kind = 'backup_expiry_ledger')
       )) or (new.surface = 'external' and not exists (
          select 1 from public.inbox_v2_data_governance_lifecycle_handlers h
           where h.registry_id = new.registry_id
             and h.registry_revision = new.registry_revision
             and h.handler_id = new.external_delete_handler_id
             and h.kind = 'external_deletion'
       )) then
      raise exception 'Checkpoint requirement uses a handler of the wrong kind'
        using errcode = '23514';
    end if;
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_dg_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  raise exception '% is append-only', tg_table_name using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_dg_restore_current_controls(text, text, text, text, text, text, text, bigint, bigint, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_restore_current_controls(p_tenant_id text, p_ledger_id text, p_storage_root_id text, p_data_class_id text, p_root_record_id text, p_entity_type_id text, p_entity_id text, p_entity_revision bigint, p_lineage_revision bigint, p_before_sequence bigint) RETURNS TABLE(control_kind public.inbox_v2_data_governance_control_reference_kind, control_id text, control_revision bigint, control_head_revision bigint, control_entry_hash text)
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  with ranked as (
    select ledger.control_kind,
           ledger.control_id,
           ledger.control_revision,
           ledger.sequence,
           ledger.entry_hash,
           ledger.kind,
           row_number() over (
             partition by ledger.control_kind, ledger.control_id
             order by ledger.sequence desc
           ) as rank
      from public.inbox_v2_data_governance_erasure_restore_ledger ledger
     where ledger.tenant_id = p_tenant_id
       and ledger.ledger_id = p_ledger_id
       and ledger.kind in (
         'hold_applied', 'restriction_applied',
         'hold_released', 'restriction_released'
       )
       and ledger.storage_root_id = p_storage_root_id
       and ledger.data_class_id = p_data_class_id
       and ledger.root_record_id = p_root_record_id
       and ledger.entity_type_id = p_entity_type_id
       and ledger.entity_id = p_entity_id
       and ledger.entity_revision = p_entity_revision
       and ledger.lineage_revision = p_lineage_revision
       and ledger.sequence < p_before_sequence
  )
  select ranked.control_kind,
         ranked.control_id,
         ranked.control_revision,
         ranked.sequence as control_head_revision,
         ranked.entry_hash as control_entry_hash
    from ranked
   where ranked.rank = 1
     and (
       (ranked.control_kind = 'legal_hold' and ranked.kind = 'hold_applied')
       or (ranked.control_kind = 'restriction' and ranked.kind = 'restriction_applied')
     )
$$;



--
-- Name: inbox_v2_dg_restore_state_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_dg_restore_state_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_ledger_id text;
  v_restore_id text;
  v_before_sequence bigint;
  v_head public.inbox_v2_data_governance_restore_heads%rowtype;
begin
  if tg_table_name = 'inbox_v2_data_governance_erasure_restore_ledger' then
    if new.kind not in ('restore_opened', 'control_reapplied', 'restore_sealed') then
      return null;
    end if;
    v_tenant_id := new.tenant_id;
    v_ledger_id := new.ledger_id;
    v_restore_id := new.restore_id;
  elsif tg_table_name in (
    'inbox_v2_data_governance_restore_heads',
    'inbox_v2_data_governance_restore_required_controls',
    'inbox_v2_data_governance_restore_leases'
  ) then
    v_tenant_id := new.tenant_id;
    v_ledger_id := new.ledger_id;
    v_restore_id := new.restore_id;
  else
    return null;
  end if;

  select head.* into v_head
    from public.inbox_v2_data_governance_restore_heads head
   where head.tenant_id = v_tenant_id
     and head.ledger_id = v_ledger_id
     and head.restore_id = v_restore_id;
  if v_head.restore_id is null then
    raise exception 'Restore ledger mutation lacks its database-owned head'
      using errcode = '23514';
  end if;

  select coalesce(v_head.sealed_sequence, max(ledger.sequence) + 1)
    into v_before_sequence
    from public.inbox_v2_data_governance_erasure_restore_ledger ledger
   where ledger.tenant_id = v_head.tenant_id
     and ledger.ledger_id = v_head.ledger_id;

  if not exists (
    select 1
      from public.inbox_v2_data_governance_erasure_restore_ledger opened
      join public.inbox_v2_data_governance_erasure_restore_ledger erased
        on erased.tenant_id = opened.tenant_id
       and erased.ledger_id = opened.ledger_id
       and erased.entry_hash = opened.source_erasure_entry_hash
       and erased.kind = 'erasure_applied'
     where opened.tenant_id = v_head.tenant_id
       and opened.ledger_id = v_head.ledger_id
       and opened.restore_id = v_head.restore_id
       and opened.kind = 'restore_opened'
       and opened.entry_hash = v_head.opened_entry_hash
       and opened.sequence = v_head.opened_sequence
       and opened.source_erasure_entry_hash = v_head.source_erasure_entry_hash
       and erased.sequence = v_head.source_erasure_sequence
       and opened.storage_root_id = v_head.storage_root_id
       and opened.data_class_id = v_head.data_class_id
       and opened.root_record_id = v_head.root_record_id
       and opened.entity_type_id = v_head.entity_type_id
       and opened.entity_id = v_head.entity_id
       and opened.entity_revision = v_head.entity_revision
       and opened.lineage_revision = v_head.lineage_revision
       and opened.stream_epoch = v_head.opened_stream_epoch
       and opened.sync_generation = v_head.opened_sync_generation
       and opened.complete_through_position = v_head.opened_complete_through_position
       and opened.required_control_hash = v_head.required_control_set_hash
  ) then
    raise exception 'Restore head does not bind its exact source/opening ledger state'
      using errcode = '23514';
  end if;

  if not exists (
    select 1
      from public.inbox_v2_data_governance_control_set_heads control_set
     where control_set.tenant_id = v_head.tenant_id
       and control_set.head_revision = v_head.control_set_head_revision
       and control_set.legal_hold_set_revision = v_head.legal_hold_set_revision
       and control_set.restriction_set_revision = v_head.restriction_set_revision
       and control_set.last_changed_stream_position = v_head.control_set_stream_position
       and v_head.opened_complete_through_position >= control_set.last_changed_stream_position
  ) then
    raise exception 'Restore head control-set/high-water fence is stale'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_data_governance_legal_hold_heads hold_head
      join public.inbox_v2_data_governance_legal_hold_revisions hold_revision
        on hold_revision.tenant_id = hold_head.tenant_id
       and hold_revision.hold_id = hold_head.hold_id
       and hold_revision.revision = hold_head.current_revision
      join public.inbox_v2_data_governance_legal_hold_data_classes data_class
        on data_class.tenant_id = hold_revision.tenant_id
       and data_class.hold_id = hold_revision.hold_id
       and data_class.hold_revision = hold_revision.revision
       and data_class.data_class_id = v_head.data_class_id
     where hold_head.tenant_id = v_head.tenant_id
       and hold_head.state = 'active'
       and hold_revision.state = 'active'
       and hold_revision.scope_kind = 'prospective'
  ) or exists (
    select 1
      from public.inbox_v2_data_governance_restriction_heads restriction_head
      join public.inbox_v2_data_governance_restriction_revisions restriction_revision
        on restriction_revision.tenant_id = restriction_head.tenant_id
       and restriction_revision.restriction_id = restriction_head.restriction_id
       and restriction_revision.revision = restriction_head.current_revision
     where restriction_head.tenant_id = v_head.tenant_id
       and restriction_head.state = 'active'
       and restriction_revision.state = 'active'
       and restriction_revision.scope_kind = 'prospective'
  ) then
    raise exception 'Restore cannot seal across an unresolved prospective control'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_data_governance_legal_hold_heads hold_head
      join public.inbox_v2_data_governance_legal_hold_revisions hold_revision
        on hold_revision.tenant_id = hold_head.tenant_id
       and hold_revision.hold_id = hold_head.hold_id
       and hold_revision.revision = hold_head.current_revision
       and hold_revision.state = 'active'
       and hold_revision.scope_kind = 'exact'
      join public.inbox_v2_data_governance_legal_hold_data_classes data_class
        on data_class.tenant_id = hold_revision.tenant_id
       and data_class.hold_id = hold_revision.hold_id
       and data_class.hold_revision = hold_revision.revision
       and data_class.data_class_id = v_head.data_class_id
      join public.inbox_v2_data_governance_legal_hold_targets exact_target
        on exact_target.tenant_id = hold_revision.tenant_id
       and exact_target.hold_id = hold_revision.hold_id
       and exact_target.hold_revision = hold_revision.revision
       and exact_target.state = 'active'
       and exact_target.storage_root_id = v_head.storage_root_id
       and exact_target.root_record_id = v_head.root_record_id
       and exact_target.entity_type_id = v_head.entity_type_id
       and exact_target.entity_id = v_head.entity_id
       and exact_target.expected_entity_revision = v_head.entity_revision
       and exact_target.expected_lineage_revision = v_head.lineage_revision
      left join lateral (
        select transition.control_revision
          from public.inbox_v2_data_governance_erasure_restore_ledger transition
         where transition.tenant_id = v_head.tenant_id
           and transition.ledger_id = v_head.ledger_id
           and transition.control_kind = 'legal_hold'
           and transition.control_id = hold_head.hold_id
           and transition.kind in ('hold_applied', 'hold_released')
           and transition.storage_root_id = v_head.storage_root_id
           and transition.data_class_id = v_head.data_class_id
           and transition.root_record_id = v_head.root_record_id
           and transition.entity_type_id = v_head.entity_type_id
           and transition.entity_id = v_head.entity_id
           and transition.entity_revision = v_head.entity_revision
           and transition.lineage_revision = v_head.lineage_revision
           and transition.sequence < v_before_sequence
         order by transition.sequence desc
         limit 1
      ) latest_transition on true
     where hold_head.tenant_id = v_head.tenant_id
       and hold_head.state = 'active'
       and (latest_transition.control_revision is null
         or latest_transition.control_revision < hold_head.current_revision)
  ) or exists (
    select 1
      from public.inbox_v2_data_governance_restriction_heads restriction_head
      join public.inbox_v2_data_governance_restriction_revisions restriction_revision
        on restriction_revision.tenant_id = restriction_head.tenant_id
       and restriction_revision.restriction_id = restriction_head.restriction_id
       and restriction_revision.revision = restriction_head.current_revision
       and restriction_revision.state = 'active'
       and restriction_revision.scope_kind = 'exact'
      join public.inbox_v2_data_governance_scope_manifest_roots exact_target
        on exact_target.tenant_id = restriction_revision.tenant_id
       and exact_target.manifest_id = restriction_revision.scope_manifest_id
       and exact_target.manifest_revision = restriction_revision.scope_manifest_revision
       and exact_target.storage_root_id = v_head.storage_root_id
       and exact_target.data_class_id = v_head.data_class_id
       and exact_target.root_record_id = v_head.root_record_id
       and exact_target.entity_type_id = v_head.entity_type_id
       and exact_target.entity_id = v_head.entity_id
       and exact_target.expected_entity_revision = v_head.entity_revision
       and exact_target.expected_lineage_revision = v_head.lineage_revision
      left join lateral (
        select transition.control_revision
          from public.inbox_v2_data_governance_erasure_restore_ledger transition
         where transition.tenant_id = v_head.tenant_id
           and transition.ledger_id = v_head.ledger_id
           and transition.control_kind = 'restriction'
           and transition.control_id = restriction_head.restriction_id
           and transition.kind in ('restriction_applied', 'restriction_released')
           and transition.storage_root_id = v_head.storage_root_id
           and transition.data_class_id = v_head.data_class_id
           and transition.root_record_id = v_head.root_record_id
           and transition.entity_type_id = v_head.entity_type_id
           and transition.entity_id = v_head.entity_id
           and transition.entity_revision = v_head.entity_revision
           and transition.lineage_revision = v_head.lineage_revision
           and transition.sequence < v_before_sequence
         order by transition.sequence desc
         limit 1
      ) latest_transition on true
     where restriction_head.tenant_id = v_head.tenant_id
       and restriction_head.state = 'active'
       and (latest_transition.control_revision is null
         or latest_transition.control_revision < restriction_head.current_revision)
  ) then
    raise exception 'Active exact restore control lacks a current tamper-resistant ledger transition'
      using errcode = '23514';
  end if;

  if v_head.required_control_count <> (
       select count(*)
         from public.inbox_v2_data_governance_restore_required_controls required
        where required.tenant_id = v_head.tenant_id
          and required.ledger_id = v_head.ledger_id
          and required.restore_id = v_head.restore_id
     )
     or exists (
       select 1
         from public.inbox_v2_dg_restore_current_controls(
           v_head.tenant_id, v_head.ledger_id, v_head.storage_root_id,
           v_head.data_class_id, v_head.root_record_id, v_head.entity_type_id,
           v_head.entity_id, v_head.entity_revision, v_head.lineage_revision,
           v_before_sequence
         ) current_control
        where not exists (
          select 1
            from public.inbox_v2_data_governance_restore_required_controls required
           where required.tenant_id = v_head.tenant_id
             and required.ledger_id = v_head.ledger_id
             and required.restore_id = v_head.restore_id
             and required.control_kind = current_control.control_kind
             and required.control_id = current_control.control_id
             and required.control_revision = current_control.control_revision
             and required.control_head_revision = current_control.control_head_revision
             and required.source_control_entry_hash = current_control.control_entry_hash
        )
     )
     or exists (
       select 1
         from public.inbox_v2_data_governance_restore_required_controls required
        where required.tenant_id = v_head.tenant_id
          and required.ledger_id = v_head.ledger_id
          and required.restore_id = v_head.restore_id
          and not exists (
            select 1
              from public.inbox_v2_dg_restore_current_controls(
                v_head.tenant_id, v_head.ledger_id, v_head.storage_root_id,
                v_head.data_class_id, v_head.root_record_id, v_head.entity_type_id,
                v_head.entity_id, v_head.entity_revision, v_head.lineage_revision,
                v_before_sequence
              ) current_control
             where current_control.control_kind = required.control_kind
               and current_control.control_id = required.control_id
               and current_control.control_revision = required.control_revision
               and current_control.control_head_revision = required.control_head_revision
               and current_control.control_entry_hash = required.source_control_entry_hash
          )
     ) then
    raise exception 'Restore required controls differ from the latest tamper-resistant ledger state'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_data_governance_restore_required_controls required
     where required.tenant_id = v_head.tenant_id
       and required.ledger_id = v_head.ledger_id
       and required.restore_id = v_head.restore_id
       and (
         not exists (
           select 1
             from public.inbox_v2_data_governance_erasure_restore_ledger_controls opened_control
            where opened_control.tenant_id = v_head.tenant_id
              and opened_control.ledger_id = v_head.ledger_id
              and opened_control.ledger_entry_id = v_head.opened_entry_hash
              and opened_control.role = 'required'
              and opened_control.control_kind = required.control_kind
              and opened_control.control_id = required.control_id
              and opened_control.control_revision = required.control_revision
              and opened_control.control_entry_hash = required.source_control_entry_hash
         )
         or (required.reapplied_entry_hash is not null and not exists (
           select 1
             from public.inbox_v2_data_governance_erasure_restore_ledger reapplied
            where reapplied.tenant_id = v_head.tenant_id
              and reapplied.ledger_id = v_head.ledger_id
              and reapplied.restore_id = v_head.restore_id
              and reapplied.entry_hash = required.reapplied_entry_hash
              and reapplied.kind = 'control_reapplied'
              and reapplied.source_control_entry_hash = required.source_control_entry_hash
              and reapplied.control_kind = required.control_kind
              and reapplied.control_id = required.control_id
              and reapplied.control_revision = required.control_revision
              and reapplied.sequence > v_head.opened_sequence
         ))
       )
  ) or exists (
    select 1
      from public.inbox_v2_data_governance_erasure_restore_ledger_controls opened_control
     where opened_control.tenant_id = v_head.tenant_id
       and opened_control.ledger_id = v_head.ledger_id
       and opened_control.ledger_entry_id = v_head.opened_entry_hash
       and opened_control.role = 'required'
       and not exists (
         select 1
           from public.inbox_v2_data_governance_restore_required_controls required
          where required.tenant_id = v_head.tenant_id
            and required.ledger_id = v_head.ledger_id
            and required.restore_id = v_head.restore_id
            and required.control_kind = opened_control.control_kind
            and required.control_id = opened_control.control_id
            and required.control_revision = opened_control.control_revision
            and required.source_control_entry_hash = opened_control.control_entry_hash
       )
  ) then
    raise exception 'Restore materialized control state lacks exact ledger lineage'
      using errcode = '23514';
  end if;

  if not exists (
    select 1
      from public.inbox_v2_data_governance_restore_leases lease
     where lease.tenant_id = v_head.tenant_id
       and lease.ledger_id = v_head.ledger_id
       and lease.restore_id = v_head.restore_id
       and lease.restore_head_revision = v_head.head_revision
       and ((v_head.state = 'open' and lease.state = 'active')
         or (v_head.state = 'sealed' and lease.state = 'completed'))
  ) then
    raise exception 'Restore head and lease revisions/states are incoherent'
      using errcode = '23514';
  end if;

  if v_head.state = 'sealed' then
    if exists (
      select 1
        from public.inbox_v2_data_governance_restore_required_controls required
       where required.tenant_id = v_head.tenant_id
         and required.ledger_id = v_head.ledger_id
         and required.restore_id = v_head.restore_id
         and required.reapplied_entry_hash is null
    ) or not exists (
      select 1
        from public.inbox_v2_data_governance_erasure_restore_ledger sealed
       where sealed.tenant_id = v_head.tenant_id
         and sealed.ledger_id = v_head.ledger_id
         and sealed.restore_id = v_head.restore_id
         and sealed.kind = 'restore_sealed'
         and sealed.entry_hash = v_head.sealed_entry_hash
         and sealed.sequence = v_head.sealed_sequence
         and sealed.source_erasure_entry_hash = v_head.source_erasure_entry_hash
         and sealed.complete_through_position >= v_head.control_set_stream_position
    ) then
      raise exception 'Sealed restore lacks its unique exact ledger/control proof'
        using errcode = '23514';
    end if;
  end if;

  if tg_table_name = 'inbox_v2_data_governance_erasure_restore_ledger' then
    if new.kind = 'control_reapplied' and not exists (
         select 1
           from public.inbox_v2_data_governance_restore_required_controls required
          where required.tenant_id = new.tenant_id
            and required.ledger_id = new.ledger_id
            and required.restore_id = new.restore_id
            and required.source_control_entry_hash = new.source_control_entry_hash
            and required.reapplied_entry_hash = new.entry_hash
       ) then
      raise exception 'Control reapplication did not CAS its database-owned required row'
        using errcode = '23514';
    end if;
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_ecs_read_cursor_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_ecs_read_cursor_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.last_read_sequence > 0 and not exists (
    select 1
      from public.inbox_v2_timeline_items timeline_item
     where timeline_item.tenant_id = new.tenant_id
       and timeline_item.conversation_id = new.conversation_id
       and timeline_item.timeline_sequence = new.last_read_sequence
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.employee_conversation_state_read_cursor_not_in_conversation';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_ecs_state_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_ecs_state_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'INSERT' then
    if new.revision <> 1
       or new.updated_at <> new.created_at
       or new.manual_unread_changed_at <> new.created_at
       or new.mute_changed_at <> new.created_at
       or new.notification_level_changed_at <> new.created_at
       or new.pin_changed_at <> new.created_at
       or new.archive_changed_at <> new.created_at
       or (new.last_read_sequence = 0 and new.last_read_at is not null)
       or (new.last_read_sequence > 0 and new.last_read_at <> new.created_at) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.employee_conversation_state_invalid_initial_metadata';
    end if;
    return new;
  end if;

  if new.tenant_id is distinct from old.tenant_id
     or new.employee_id is distinct from old.employee_id
     or new.conversation_id is distinct from old.conversation_id
     or new.created_at is distinct from old.created_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.employee_conversation_state_identity_immutable';
  end if;

  if new.last_read_sequence < old.last_read_sequence then
    raise exception using errcode = '23514',
      message = 'inbox_v2.employee_conversation_state_read_cursor_regression';
  end if;

  if new.revision <> old.revision + 1
     or new.last_changed_stream_position <= old.last_changed_stream_position
     or new.updated_at < old.updated_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.employee_conversation_state_revision_stream_regression';
  end if;

  if new.last_read_sequence = old.last_read_sequence then
    if new.last_read_at is distinct from old.last_read_at then
      raise exception using errcode = '23514',
        message = 'inbox_v2.employee_conversation_state_read_timestamp_without_advance';
    end if;
  elsif new.last_read_at is distinct from new.updated_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.employee_conversation_state_read_timestamp_mismatch';
  end if;

  if ((new.manual_unread is not distinct from old.manual_unread)
       and new.manual_unread_changed_at is distinct from old.manual_unread_changed_at)
     or ((new.manual_unread is distinct from old.manual_unread)
       and new.manual_unread_changed_at is distinct from new.updated_at)
     or ((new.muted is not distinct from old.muted)
       and new.mute_changed_at is distinct from old.mute_changed_at)
     or ((new.muted is distinct from old.muted)
       and new.mute_changed_at is distinct from new.updated_at)
     or ((new.notification_level is not distinct from old.notification_level)
       and new.notification_level_changed_at is distinct from old.notification_level_changed_at)
     or ((new.notification_level is distinct from old.notification_level)
       and new.notification_level_changed_at is distinct from new.updated_at)
     or ((new.pinned is not distinct from old.pinned)
       and new.pin_changed_at is distinct from old.pin_changed_at)
     or ((new.pinned is distinct from old.pinned)
       and new.pin_changed_at is distinct from new.updated_at)
     or ((new.archived is not distinct from old.archived)
       and new.archive_changed_at is distinct from old.archive_changed_at)
     or ((new.archived is distinct from old.archived)
       and new.archive_changed_at is distinct from new.updated_at) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.employee_conversation_state_field_timestamp_mismatch';
  end if;

  if new.last_read_sequence = old.last_read_sequence
     and new.manual_unread = old.manual_unread
     and new.muted = old.muted
     and new.notification_level = old.notification_level
     and new.pinned = old.pinned
     and new.archived = old.archived then
    raise exception using errcode = '23514',
      message = 'inbox_v2.employee_conversation_state_phantom_update';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_employee_fence_head_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_employee_fence_head_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_employee_id text;
  v_head public.inbox_v2_employee_assignment_fence_heads%rowtype;
  v_version public.inbox_v2_employee_assignment_fence_versions%rowtype;
  v_max_revision bigint;
begin
  v_tenant_id := new.tenant_id;
  v_employee_id := new.employee_id;

  select * into v_head
    from public.inbox_v2_employee_assignment_fence_heads h
   where h.tenant_id = v_tenant_id and h.employee_id = v_employee_id;
  select max(v.revision) into v_max_revision
    from public.inbox_v2_employee_assignment_fence_versions v
   where v.tenant_id = v_tenant_id and v.employee_id = v_employee_id;
  select * into v_version
    from public.inbox_v2_employee_assignment_fence_versions v
   where v.tenant_id = v_tenant_id
     and v.employee_id = v_employee_id
     and v.revision = v_head.current_revision;

  if v_head.current_revision is null
     or v_version.revision is null
     or v_max_revision <> v_head.current_revision
     or v_head.current_generation <> v_version.generation
     or v_head.state <> v_version.state
     or v_head.effective_from <> v_version.effective_from then
    raise exception 'Employee assignment fence head/version mismatch'
      using errcode = '23514';
  end if;

  if v_head.state = 'inactive' and exists (
    select 1
      from public.inbox_v2_work_item_primary_assignments a
     where a.tenant_id = v_head.tenant_id
       and a.employee_id = v_head.employee_id
       and a.state = 'active'
  ) then
    raise exception 'Employee fence cannot become inactive with active assignments'
      using errcode = '23514';
  end if;

  return null;
end
$$;



--
-- Name: inbox_v2_employee_fence_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_employee_fence_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.employees e
       where e.tenant_id = old.tenant_id and e.id = old.employee_id
    ) then
      return old;
    end if;
    raise exception 'Employee assignment fence head cannot be deleted'
      using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.current_revision <> 1 or new.current_generation <> 1 then
      raise exception 'Employee assignment fence must start at revision/generation 1'
        using errcode = '23514';
    end if;
  elsif not (
       (old.state = 'active' and new.state in ('active', 'draining'))
       or (old.state = 'draining' and new.state in ('draining', 'inactive', 'active'))
       or (old.state = 'inactive' and new.state in ('inactive', 'active'))
     ) then
    raise exception 'Illegal Employee assignment fence state edge: % -> %',
      old.state, new.state using errcode = '23514';
  elsif new.tenant_id is distinct from old.tenant_id
     or new.employee_id is distinct from old.employee_id
     or new.created_at is distinct from old.created_at
     or new.current_revision <> old.current_revision + 1
     or new.current_generation <> old.current_generation + 1
     or new.updated_at < old.updated_at then
    raise exception 'Employee assignment fence requires immutable identity and +1 CAS'
      using errcode = '23514';
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_employee_fence_sync(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_employee_fence_sync() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_head public.inbox_v2_employee_assignment_fence_heads%rowtype;
  v_state public.inbox_v2_employee_assignment_fence_state;
  v_effective_from timestamptz;
  v_recorded_at timestamptz;
  v_reason_id text;
begin
  if tg_op = 'UPDATE' and new.deactivated_at is not distinct from old.deactivated_at then
    return new;
  end if;

  if tg_op = 'INSERT' then
    v_state := case
      when new.deactivated_at is null then 'active'
      else 'inactive'
    end;
    v_effective_from := coalesce(new.deactivated_at, new.created_at);
    v_recorded_at := greatest(new.created_at, v_effective_from);
    v_reason_id := 'core:employee_bootstrap';

    insert into public.inbox_v2_employee_assignment_fence_versions (
      tenant_id,
      employee_id,
      revision,
      generation,
      state,
      effective_from,
      recorded_at,
      reason_id,
      changed_by_trusted_service_id
    ) values (
      new.tenant_id,
      new.id,
      1,
      1,
      v_state,
      v_effective_from,
      v_recorded_at,
      v_reason_id,
      'core:employee_lifecycle_sync'
    ) on conflict do nothing;

    insert into public.inbox_v2_employee_assignment_fence_heads (
      tenant_id,
      employee_id,
      state,
      current_generation,
      current_revision,
      effective_from,
      created_at,
      updated_at
    ) values (
      new.tenant_id,
      new.id,
      v_state,
      1,
      1,
      v_effective_from,
      new.created_at,
      v_recorded_at
    ) on conflict do nothing;

    return new;
  end if;

  select * into v_head
    from public.inbox_v2_employee_assignment_fence_heads h
   where h.tenant_id = new.tenant_id and h.employee_id = new.id
   for update;
  if not found then
    raise exception 'Employee lifecycle update is missing its assignment fence head'
      using errcode = '23514';
  end if;

  v_state := case
    when new.deactivated_at is null then 'active'
    when v_head.state = 'active' then 'draining'
    else v_head.state
  end;

  v_recorded_at := date_trunc('milliseconds', clock_timestamp());
  v_effective_from := v_recorded_at;
  v_reason_id := case
    when new.deactivated_at is null then 'core:employee_reactivated'
    else 'core:employee_deactivated'
  end;

  insert into public.inbox_v2_employee_assignment_fence_versions (
    tenant_id,
    employee_id,
    revision,
    generation,
    state,
    effective_from,
    recorded_at,
    reason_id,
    changed_by_trusted_service_id
  ) values (
    new.tenant_id,
    new.id,
    v_head.current_revision + 1,
    v_head.current_generation + 1,
    v_state,
    v_effective_from,
    v_recorded_at,
    v_reason_id,
    'core:employee_lifecycle_sync'
  );

  update public.inbox_v2_employee_assignment_fence_heads
     set state = v_state,
         current_generation = v_head.current_generation + 1,
         current_revision = v_head.current_revision + 1,
         effective_from = v_effective_from,
         updated_at = v_recorded_at
   where tenant_id = new.tenant_id and employee_id = new.id;

  return new;
end
$$;



--
-- Name: inbox_v2_external_message_reference_guard_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_external_message_reference_guard_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.scope_kind = 'source_thread_binding' then
    perform 1
      from public.inbox_v2_source_thread_bindings binding_row
     where binding_row.tenant_id = new.tenant_id
       and binding_row.id = new.scope_source_thread_binding_id
       and binding_row.external_thread_id = new.external_thread_id
     for share;

    if not found then
      raise exception using errcode = '23514',
        message = 'inbox_v2.external_message_reference_binding_thread_mismatch';
    end if;
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_file_delete_is_tenant_cascade(text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_delete_is_tenant_cascade(tenant_id_value text) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select pg_catalog.pg_trigger_depth() > 1
    and not exists (
      select 1
        from public.tenants tenant_row
       where tenant_row.id = tenant_id_value
    );
$$;



--
-- Name: inbox_v2_file_derivative_cycle_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_derivative_cycle_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  cycle_exists boolean;
begin
  -- The advisory-lock recheck depends on READ COMMITTED taking a fresh
  -- statement snapshot after the previous lock owner commits. Fail closed
  -- before touching the graph when a caller pins an older transaction
  -- snapshot (for example REPEATABLE READ or SERIALIZABLE).
  if pg_catalog.current_setting('transaction_isolation') <> 'read committed' then
    raise exception using errcode = '25001',
      message = 'inbox_v2.file_derivative_isolation_unsafe';
  end if;

  -- Serialize only this tenant's derivative graph. The domain-separated,
  -- deterministic 64-bit key avoids cross-tenant contention while making a
  -- concurrent reciprocal/path-closing insert wait for the earlier commit.
  perform pg_catalog.pg_advisory_xact_lock(
    (
      'x' || pg_catalog.substr(
        pg_catalog.md5(
          'core:inbox-v2.file-derivative-graph:' || new.tenant_id
        ),
        1,
        16
      )
    )::bit(64)::bigint
  );

  -- VOLATILE PL/pgSQL executes this query with the post-lock READ COMMITTED
  -- snapshot, so an edge committed by the previous lock owner is rechecked.
  with recursive descendants(file_version_id) as (
    select new.derived_file_version_id
    union
    select edge.derived_file_version_id
      from public.inbox_v2_file_derivative_edges edge
      join descendants prior
        on prior.file_version_id = edge.original_file_version_id
     where edge.tenant_id = new.tenant_id
  )
  select exists (
    select 1 from descendants
     where file_version_id = new.original_file_version_id
  ) into cycle_exists;

  if cycle_exists then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_derivative_cycle';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_dispatch_plan_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_dispatch_plan_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  checked_tenant_id text;
  checked_plan_id text;
  plan_row public.inbox_v2_file_outbound_dispatch_plans%rowtype;
  dispatch_valid boolean;
  artifact_total integer;
  block_total integer;
  payload_total integer;
begin
  checked_tenant_id := new.tenant_id;
  checked_plan_id := coalesce(
    to_jsonb(new) ->> 'content_plan_id',
    to_jsonb(new) ->> 'id'
  );

  select * into plan_row
    from public.inbox_v2_file_outbound_dispatch_plans candidate_row
   where candidate_row.tenant_id = checked_tenant_id
     and candidate_row.id = checked_plan_id;
  if not found then
    raise exception using errcode = '23503',
      message = 'inbox_v2.outbound_dispatch_content_plan_missing';
  end if;

  select exists (
    select 1
      from public.inbox_v2_outbound_dispatches dispatch_row
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = dispatch_row.tenant_id
       and message_row.id = dispatch_row.message_id
       and message_row.conversation_id = dispatch_row.conversation_id
       and message_row.timeline_item_id = dispatch_row.timeline_item_id
      join public.inbox_v2_outbound_routes route_row
        on route_row.tenant_id = dispatch_row.tenant_id
       and route_row.id = dispatch_row.route_id
       and route_row.conversation_id = dispatch_row.conversation_id
      join public.inbox_v2_timeline_contents content_row
        on content_row.tenant_id = message_row.tenant_id
       and content_row.id = message_row.content_id
       and content_row.revision = message_row.content_revision
     where dispatch_row.tenant_id = plan_row.tenant_id
       and dispatch_row.id = plan_row.dispatch_id
       and dispatch_row.message_id = plan_row.message_id
       and dispatch_row.conversation_id = plan_row.conversation_id
       and dispatch_row.timeline_item_id = plan_row.timeline_item_id
       and dispatch_row.route_id = plan_row.route_id
       and message_row.revision = plan_row.message_revision
       and message_row.content_id = plan_row.content_id
       and message_row.content_revision = plan_row.content_revision
       and content_row.state = 'available'
       and route_row.source_thread_binding_id = plan_row.binding_id
       and route_row.binding_revision = plan_row.binding_revision
       and route_row.capability_revision = plan_row.capability_revision
       and route_row.adapter_contract_id = plan_row.adapter_contract_id
       and route_row.adapter_contract_version = plan_row.adapter_contract_version
       and route_row.adapter_declaration_revision =
         plan_row.adapter_contract_declaration_revision
       and route_row.adapter_surface_id = plan_row.adapter_surface_id
       and route_row.adapter_loaded_by_trusted_service_id =
         plan_row.adapter_loaded_by_trusted_service_id
       and route_row.adapter_loaded_at = plan_row.adapter_loaded_at
       and route_row.selected_at <= plan_row.created_at
  ) into dispatch_valid;
  if not dispatch_valid then
    raise exception using errcode = '23503',
      message = 'inbox_v2.outbound_dispatch_content_plan_invalid';
  end if;

  select count(*) into artifact_total
    from public.inbox_v2_file_outbound_artifact_plans artifact_row
   where artifact_row.tenant_id = plan_row.tenant_id
     and artifact_row.content_plan_id = plan_row.id;
  if artifact_total <> plan_row.artifact_count or not exists (
    select 1
      from public.inbox_v2_file_outbound_artifact_plans artifact_row
     where artifact_row.tenant_id = plan_row.tenant_id
       and artifact_row.content_plan_id = plan_row.id
    having min(artifact_row.ordinal) = 1
       and max(artifact_row.ordinal) = count(*)
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_dispatch_artifact_count_invalid';
  end if;

  select count(*) into block_total
    from public.inbox_v2_file_outbound_artifact_blocks block_row
   where block_row.tenant_id = plan_row.tenant_id
     and block_row.content_plan_id = plan_row.id;
  select count(*) into payload_total
    from public.inbox_v2_timeline_content_payloads payload_row
   where payload_row.tenant_id = plan_row.tenant_id
     and payload_row.content_id = plan_row.content_id
     and payload_row.content_revision = plan_row.content_revision;
  if block_total <> plan_row.block_count
     or payload_total <> plan_row.block_count then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_dispatch_block_count_invalid';
  end if;

  if exists (
    select 1
      from public.inbox_v2_file_outbound_artifact_plans artifact_row
     where artifact_row.tenant_id = plan_row.tenant_id
       and artifact_row.content_plan_id = plan_row.id
       and (artifact_row.created_at <> plan_row.created_at
         or artifact_row.block_mapping_count <> (
          select count(*)
           from public.inbox_v2_file_outbound_artifact_blocks block_row
          where block_row.tenant_id = artifact_row.tenant_id
            and block_row.content_plan_id = artifact_row.content_plan_id
             and block_row.artifact_plan_id = artifact_row.id
       ))
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_dispatch_block_mapping_count_invalid';
  end if;

  if exists (
    select 1
      from public.inbox_v2_file_outbound_artifact_plans artifact_row
     where artifact_row.tenant_id = plan_row.tenant_id
       and artifact_row.content_plan_id = plan_row.id
       and not exists (
         select 1
           from public.inbox_v2_source_thread_binding_capability_entries capability_row
          where capability_row.tenant_id = plan_row.tenant_id
            and capability_row.binding_id = plan_row.binding_id
            and capability_row.capability_revision =
              plan_row.capability_revision
            and capability_row.capability_id = artifact_row.capability_id
            and capability_row.operation_id = artifact_row.operation_id
            and capability_row.content_kind_id is not distinct from (
              select route_row.content_kind_id
                from public.inbox_v2_outbound_routes route_row
               where route_row.tenant_id = plan_row.tenant_id
                 and route_row.id = plan_row.route_id
            )
            and capability_row.state = 'supported'
            and (capability_row.valid_until is null
              or capability_row.valid_until > plan_row.created_at)
            and not exists (
              select 1
                from public.inbox_v2_source_thread_binding_capability_required_roles required_role_row
               where required_role_row.tenant_id = capability_row.tenant_id
                 and required_role_row.binding_id = capability_row.binding_id
                 and required_role_row.materialized_by_binding_revision =
                   capability_row.materialized_by_binding_revision
                 and required_role_row.capability_revision =
                   capability_row.capability_revision
                 and required_role_row.capability_ordinal = capability_row.ordinal
                 and required_role_row.capability_id = capability_row.capability_id
                 and required_role_row.operation_id = capability_row.operation_id
                 and required_role_row.content_kind_key =
                   capability_row.content_kind_key
                 and not exists (
                   select 1
                     from public.inbox_v2_source_thread_binding_snapshots binding_snapshot_row
                     join public.inbox_v2_source_thread_binding_provider_roles provider_role_row
                       on provider_role_row.tenant_id =
                         binding_snapshot_row.tenant_id
                      and provider_role_row.binding_id =
                         binding_snapshot_row.binding_id
                      and provider_role_row.provider_access_revision =
                         binding_snapshot_row.provider_access_revision
                      and provider_role_row.provider_role_id =
                         required_role_row.provider_role_id
                    where binding_snapshot_row.tenant_id = plan_row.tenant_id
                      and binding_snapshot_row.binding_id = plan_row.binding_id
                      and binding_snapshot_row.revision =
                        plan_row.binding_revision
                 )
            )
       )
  ) then
    raise exception using errcode = '23503',
      message = 'inbox_v2.outbound_dispatch_artifact_capability_invalid';
  end if;

  -- Freeze every mutable logical/object head used by an exact planned pin.
  -- The following validation statement runs after these row locks, so a
  -- concurrent quarantine/delete/head move either wins first and is observed
  -- or waits until this plan transaction commits.
  perform 1
    from public.inbox_v2_file_outbound_artifact_blocks block_row
    join public.inbox_v2_file_objects file_row
      on file_row.tenant_id = block_row.tenant_id
     and file_row.id = block_row.file_id
     and file_row.revision = block_row.file_revision
     and file_row.state = 'ready'
     and file_row.current_file_version_id = block_row.file_version_id
     and file_row.current_object_version_id = block_row.object_version_id
    join public.inbox_v2_file_versions version_row
      on version_row.tenant_id = block_row.tenant_id
     and version_row.id = block_row.file_version_id
     and version_row.file_id = block_row.file_id
     and version_row.object_version_id = block_row.object_version_id
    join public.inbox_v2_file_object_version_heads object_head_row
      on object_head_row.tenant_id = block_row.tenant_id
     and object_head_row.object_version_id = block_row.object_version_id
     and object_head_row.state = 'ready'
   where block_row.tenant_id = plan_row.tenant_id
     and block_row.content_plan_id = plan_row.id
     and block_row.file_id is not null
   order by block_row.file_id, block_row.file_version_id,
     block_row.object_version_id
   for share of file_row, object_head_row;

  if exists (
    select 1
      from public.inbox_v2_file_outbound_artifact_blocks block_row
      left join public.inbox_v2_timeline_content_payloads payload_row
        on payload_row.tenant_id = plan_row.tenant_id
       and payload_row.content_id = plan_row.content_id
       and payload_row.content_revision = plan_row.content_revision
       and payload_row.ordinal = block_row.content_block_ordinal
       and payload_row.block_key = block_row.block_key
       and payload_row.kind::text = block_row.block_kind::text
     where block_row.tenant_id = plan_row.tenant_id
       and block_row.content_plan_id = plan_row.id
       and (
         payload_row.tenant_id is null
         or block_row.created_at <> plan_row.created_at
         or (
           block_row.block_kind in ('image', 'audio', 'video', 'file', 'sticker')
           and not (
             payload_row.attachment_state = 'ready'
             and payload_row.attachment_v2_file_id = block_row.file_id
             and payload_row.attachment_file_version_id = block_row.file_version_id
             and payload_row.attachment_object_version_id =
               block_row.object_version_id
           )
         )
         or (
           block_row.block_kind = 'extension'
           and not (
             payload_row.extension_payload_v2_file_id = block_row.file_id
             and payload_row.extension_payload_file_version_id =
               block_row.file_version_id
             and payload_row.extension_payload_object_version_id =
               block_row.object_version_id
           )
         )
         or (
           block_row.block_kind in ('text', 'location', 'contact')
           and num_nonnulls(
             block_row.file_id, block_row.file_revision,
             block_row.file_version_id, block_row.object_version_id
           ) <> 0
         )
         or (
           block_row.file_id is not null
           and not exists (
             select 1
               from public.inbox_v2_file_objects file_row
               join public.inbox_v2_file_versions version_row
                 on version_row.tenant_id = file_row.tenant_id
                and version_row.id = block_row.file_version_id
                and version_row.file_id = file_row.id
                and version_row.object_version_id =
                  block_row.object_version_id
               join public.inbox_v2_file_object_version_heads object_head_row
                 on object_head_row.tenant_id = file_row.tenant_id
                and object_head_row.object_version_id =
                  block_row.object_version_id
                and object_head_row.state = 'ready'
              where file_row.tenant_id = block_row.tenant_id
                and file_row.id = block_row.file_id
                and file_row.revision = block_row.file_revision
                and file_row.state = 'ready'
                and file_row.current_file_version_id = block_row.file_version_id
                and file_row.current_object_version_id =
                  block_row.object_version_id
           )
         )
       )
  ) then
    raise exception using errcode = '23503',
      message = 'inbox_v2.outbound_dispatch_block_mapping_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_immutable_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_immutable_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE'
     and public.inbox_v2_file_delete_is_tenant_cascade(old.tenant_id) then
    return old;
  end if;
  raise exception using
    errcode = '23514',
    message = 'inbox_v2.file_immutable';
end;
$$;



--
-- Name: inbox_v2_file_materialization_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_materialization_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  job_row public.inbox_v2_file_attachment_materialization_jobs%rowtype;
  identity_valid boolean;
  attempt_valid boolean;
  completion_valid boolean;
  requires_current_fence boolean;
begin
  if tg_table_name = 'inbox_v2_file_attachment_materialization_jobs'
     and tg_op = 'INSERT' then
    job_row := new;
  elsif tg_table_name = 'inbox_v2_file_attachment_materialization_jobs' then
    select * into job_row
      from public.inbox_v2_file_attachment_materialization_jobs candidate_row
     where candidate_row.tenant_id = new.tenant_id
       and candidate_row.id = new.id;
  else
    select * into job_row
      from public.inbox_v2_file_attachment_materialization_jobs candidate_row
     where candidate_row.tenant_id = new.tenant_id
       and candidate_row.id = new.job_id;
  end if;

  -- The immutable reservation origin remains authoritative evidence even
  -- after current content or access has moved on. Only a completed terminal
  -- materialization is required to remain attached to the exact current head;
  -- claim and pre-I/O authorization own the live-current fence for pending,
  -- active and cancelled jobs.
  requires_current_fence :=
    job_row.state in ('ready', 'failed', 'quarantined');

  select exists (
    select 1
      from public.inbox_v2_message_attachment_anchors attachment_row
      join public.inbox_v2_timeline_contents content_row
        on content_row.tenant_id = attachment_row.tenant_id
       and content_row.id = attachment_row.owner_timeline_content_id
       and content_row.id = job_row.timeline_content_id
      join public.inbox_v2_timeline_content_revisions origin_revision_row
        on origin_revision_row.tenant_id = content_row.tenant_id
       and origin_revision_row.content_id = content_row.id
       and origin_revision_row.revision = job_row.expected_content_revision
       and origin_revision_row.state = 'available'
       and origin_revision_row.recorded_stream_position =
         job_row.cause_stream_position
      left join public.inbox_v2_timeline_content_payloads origin_payload_row
        on origin_payload_row.tenant_id = content_row.tenant_id
       and origin_payload_row.content_id = content_row.id
       and origin_payload_row.content_revision = job_row.expected_content_revision
       and origin_payload_row.block_key = job_row.content_block_key
       and origin_payload_row.attachment_id = job_row.attachment_id
       and origin_payload_row.attachment_state = 'pending'
      left join public.inbox_v2_timeline_content_payloads current_payload_row
        on current_payload_row.tenant_id = content_row.tenant_id
       and current_payload_row.content_id = content_row.id
       and current_payload_row.content_revision = content_row.revision
       and current_payload_row.block_key = job_row.content_block_key
       and current_payload_row.attachment_id = job_row.attachment_id
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = content_row.tenant_id
       and message_row.id = job_row.parent_message_id
       and message_row.conversation_id = job_row.conversation_id
       and message_row.timeline_item_id = job_row.timeline_item_id
       and message_row.content_id = content_row.id
       and message_row.content_revision = content_row.revision
       and message_row.content_state = content_row.state
       and message_row.revision >= job_row.expected_parent_revision
       and content_row.owner_kind = 'message'
       and content_row.owner_id = message_row.id
      join public.inbox_v2_message_revisions origin_message_revision_row
        on origin_message_revision_row.tenant_id = message_row.tenant_id
       and origin_message_revision_row.message_id = message_row.id
       and origin_message_revision_row.timeline_item_id = message_row.timeline_item_id
       and origin_message_revision_row.message_revision =
         job_row.expected_parent_revision
       and origin_message_revision_row.after_content_id = content_row.id
       and origin_message_revision_row.after_content_revision =
         job_row.expected_content_revision
       and origin_message_revision_row.after_content_state = 'available'
       and origin_message_revision_row.recorded_stream_position =
         job_row.cause_stream_position
      join public.inbox_v2_timeline_items timeline_item_row
        on timeline_item_row.tenant_id = message_row.tenant_id
       and timeline_item_row.id = message_row.timeline_item_id
       and timeline_item_row.conversation_id = message_row.conversation_id
      left join public.inbox_v2_source_occurrences source_occurrence_row
        on source_occurrence_row.tenant_id = job_row.tenant_id
       and source_occurrence_row.id = job_row.source_occurrence_id
       and source_occurrence_row.conversation_id = job_row.conversation_id
      join public.inbox_v2_domain_events cause_event_row
        on cause_event_row.tenant_id = job_row.tenant_id
       and cause_event_row.id = job_row.cause_event_id
       and cause_event_row.mutation_id = job_row.cause_mutation_id
       and cause_event_row.stream_commit_id = job_row.cause_stream_commit_id
       and cause_event_row.stream_position = job_row.cause_stream_position
       and cause_event_row.correlation_id = job_row.correlation_id
       and cause_event_row.occurred_at = job_row.caused_at
       and cause_event_row.type_id = 'core:message.changed'
       and cause_event_row.subjects @> jsonb_build_array(
         jsonb_build_object(
           'tenantId', job_row.tenant_id,
           'entityTypeId', 'core:message',
           'entityId', message_row.id
         )
       )
      join public.inbox_v2_tenant_stream_changes cause_change_row
        on cause_change_row.tenant_id = cause_event_row.tenant_id
       and cause_change_row.stream_commit_id =
         cause_event_row.stream_commit_id
       and cause_change_row.mutation_id = cause_event_row.mutation_id
       and cause_change_row.stream_position = cause_event_row.stream_position
       and cause_change_row.entity_type_id = 'core:message'
       and cause_change_row.entity_id = message_row.id
       and cause_event_row.change_ids @>
         jsonb_build_array(cause_change_row.id)
      join public.inbox_v2_auth_command_records authorization_command_row
        on authorization_command_row.tenant_id = job_row.tenant_id
       and authorization_command_row.id = job_row.authorization_command_id
       and authorization_command_row.command_type_id =
         job_row.authorization_command_type_id
       and authorization_command_row.command_type_id in (
         'core:attachment.materialization.reserve',
         'core:attachment.materialization.reauthorize'
       )
       and authorization_command_row.client_mutation_id =
         job_row.authorization_client_mutation_id
       and authorization_command_row.mutation_id =
         job_row.authorization_mutation_id
       and authorization_command_row.authorization_decision_id =
         job_row.authorization_decision_id
       and authorization_command_row.authorization_epoch =
         job_row.authorization_epoch
       and authorization_command_row.authorized_at =
         job_row.authorization_authorized_at
       and authorization_command_row.state = 'completed'
       and authorization_command_row.result_reference->>'tenantId' =
         job_row.tenant_id
       and authorization_command_row.result_reference->>'recordId' = job_row.id
       and job_row.authorization_actor_kind = 'trusted_service'
       and authorization_command_row.actor_kind = 'trusted_service'
       and authorization_command_row.actor_trusted_service_id =
         job_row.authorization_actor_id
       and authorization_command_row.actor_employee_id is null
      join public.inbox_v2_auth_audit_events authorization_audit_row
        on authorization_audit_row.tenant_id = job_row.tenant_id
       and authorization_audit_row.command_record_id =
         job_row.authorization_command_id
       and authorization_audit_row.mutation_id =
         job_row.authorization_mutation_id
       and authorization_audit_row.grant_source_ids =
         job_row.authorization_audit_grant_source_ids
       and authorization_audit_row.policy_version is not distinct from
         job_row.authorization_audit_policy_version
      join public.inbox_v2_auth_tenant_heads authorization_tenant_head_row
        on authorization_tenant_head_row.tenant_id = job_row.tenant_id
      join public.inbox_v2_auth_resource_heads authorization_resource_head_row
        on authorization_resource_head_row.tenant_id = job_row.tenant_id
       and authorization_resource_head_row.id =
         job_row.authorization_resource_head_id
       and authorization_resource_head_row.resource_kind = 'conversation'
       and authorization_resource_head_row.conversation_id =
         job_row.conversation_id
       and not exists (
         select 1
           from unnest(job_row.authorization_audit_grant_source_ids)
                with ordinality grant_source(value, ordinal)
           left join unnest(job_row.authorization_audit_grant_source_ids)
                with ordinality previous_source(value, ordinal)
             on previous_source.ordinal = grant_source.ordinal - 1
          where grant_source.value !~ '^internal-ref:[a-f0-9]{32,64}$'
             or (grant_source.ordinal > 1
               and grant_source.value <= previous_source.value)
       )
       and jsonb_array_length(
         authorization_command_row.authorization_decision_refs
       ) = 2
       and exists (
         select 1
           from jsonb_array_elements(
             authorization_command_row.authorization_decision_refs
           ) decision
          where decision->>'id' = job_row.authorization_decision_id
            and decision->>'tenantId' = job_row.tenant_id
            and decision->>'authorizationEpoch' = job_row.authorization_epoch
            and decision->>'permissionId' = 'core:file.upload'
            and decision->>'resourceScopeId' = 'core:conversation'
            and decision->>'outcome' = 'allowed'
            and decision#>>'{principal,kind}' = 'trusted_service'
            and decision#>>'{principal,trustedServiceId}' =
              job_row.authorization_actor_id
            and decision#>>'{resource,entityTypeId}' = 'core:conversation'
            and decision#>>'{resource,entityId}' = job_row.conversation_id
            and (decision->>'resourceAccessRevision')::bigint =
              job_row.authorization_resource_access_revision
       )
       and exists (
         select 1
           from jsonb_array_elements(
             authorization_command_row.authorization_decision_refs
           ) decision
          where decision->>'tenantId' = job_row.tenant_id
            and decision->>'authorizationEpoch' = job_row.authorization_epoch
            and decision->>'permissionId' = case job_row.visibility_boundary
              when 'external_work' then 'core:conversation.read'
              when 'internal' then 'core:conversation.internal.read'
            end
            and decision->>'resourceScopeId' = 'core:conversation'
            and decision->>'outcome' = 'allowed'
            and decision#>>'{principal,kind}' = 'trusted_service'
            and decision#>>'{principal,trustedServiceId}' =
              job_row.authorization_actor_id
            and decision#>>'{resource,entityTypeId}' = 'core:conversation'
            and decision#>>'{resource,entityId}' = job_row.conversation_id
            and (decision->>'resourceAccessRevision')::bigint =
              job_row.authorization_resource_access_revision
       )
     where attachment_row.tenant_id = job_row.tenant_id
       and attachment_row.id = job_row.attachment_id
       and attachment_row.owner_message_id = job_row.parent_message_id
       and attachment_row.owner_timeline_item_id = job_row.timeline_item_id
       and attachment_row.owner_timeline_content_id =
         job_row.timeline_content_id
       and attachment_row.owner_block_key = job_row.content_block_key
       and (
         origin_payload_row.attachment_id = job_row.attachment_id
         or (
           content_row.state in ('privacy_erased', 'retention_purged')
           and origin_payload_row.attachment_id is null
         )
       )
       and content_row.revision >= job_row.expected_content_revision
       and (
         not requires_current_fence
         or (
           content_row.state = 'available'
           and message_row.lifecycle = 'active'
           and content_row.revision = job_row.result_content_revision
           and timeline_item_row.visibility = case job_row.visibility_boundary
             when 'external_work' then
               'conversation_external'::public.inbox_v2_timeline_visibility
             when 'internal' then
               'internal_participants'::public.inbox_v2_timeline_visibility
           end
           and attachment_row.materialization_state::text = job_row.state::text
           and attachment_row.revision =
             job_row.expected_attachment_revision + 1
           and current_payload_row.attachment_state::text = job_row.state::text
           and authorization_tenant_head_row.tenant_rbac_revision =
             job_row.authorization_tenant_rbac_revision
           and authorization_tenant_head_row.shared_access_revision =
             job_row.authorization_shared_access_revision
           and authorization_resource_head_row.resource_access_revision =
             job_row.authorization_resource_access_revision
           and authorization_resource_head_row.structural_relation_revision =
             job_row.authorization_structural_relation_revision
           and authorization_resource_head_row.collaborator_set_revision =
             job_row.authorization_collaborator_set_revision
         )
       )
       and (job_row.source_locator_kind <> 'provider'
         or (source_occurrence_row.id is not null
           and message_row.origin_source_occurrence_id =
             job_row.source_occurrence_id))
  ) into identity_valid;
  if not identity_valid then
    raise exception using errcode = '23503',
      message = 'inbox_v2.attachment_materialization_identity_invalid';
  end if;

  if job_row.state = 'cancelled' then
    return new;
  end if;

  if job_row.state in ('claimed', 'transferring', 'verifying',
                       'ready', 'failed', 'quarantined') then
    select exists (
      select 1
        from public.inbox_v2_file_attachment_materialization_attempts attempt_row
       where attempt_row.tenant_id = job_row.tenant_id
         and attempt_row.job_id = job_row.id
         and attempt_row.attachment_id = job_row.attachment_id
         and attempt_row.file_id = job_row.file_id
         and attempt_row.lease_generation = job_row.lease_generation
         and attempt_row.expected_file_revision = job_row.expected_file_revision
         and attempt_row.expected_attachment_revision =
           job_row.expected_attachment_revision
         and attempt_row.expected_job_revision <= job_row.revision
         and (job_row.state not in ('claimed', 'transferring', 'verifying')
           or (attempt_row.lease_token_hash = job_row.lease_token_hash
             and attempt_row.lease_owner_id = job_row.lease_owner_id
             and attempt_row.claimed_at = job_row.lease_claimed_at
             and attempt_row.lease_expires_at = job_row.lease_expires_at))
    ) into attempt_valid;
    if not attempt_valid then
      raise exception using errcode = '23503',
        message = 'inbox_v2.attachment_materialization_attempt_invalid';
    end if;
  end if;

  if job_row.state in ('ready', 'failed', 'quarantined') then
    select exists (
      select 1
        from public.inbox_v2_file_attachment_materialization_evidence evidence_row
        join public.inbox_v2_message_attachment_anchors attachment_row
          on attachment_row.tenant_id = evidence_row.tenant_id
         and attachment_row.id = evidence_row.attachment_id
         and attachment_row.revision = evidence_row.resulting_attachment_revision
        join public.inbox_v2_timeline_content_revisions revision_row
          on revision_row.tenant_id = evidence_row.tenant_id
         and revision_row.content_id = evidence_row.timeline_content_id
         and revision_row.revision = evidence_row.resulting_content_revision
         and revision_row.expected_previous_revision =
           evidence_row.expected_content_revision
         and revision_row.transition_kind = 'attachment_materialization'
         and revision_row.state = 'available'
        join public.inbox_v2_timeline_content_payloads payload_row
          on payload_row.tenant_id = evidence_row.tenant_id
         and payload_row.content_id = evidence_row.timeline_content_id
         and payload_row.content_revision = evidence_row.resulting_content_revision
         and payload_row.block_key = job_row.content_block_key
         and payload_row.attachment_id = evidence_row.attachment_id
       where evidence_row.tenant_id = job_row.tenant_id
         and evidence_row.job_id = job_row.id
         and evidence_row.attachment_id = job_row.attachment_id
         and evidence_row.file_id = job_row.file_id
         and evidence_row.lease_generation = job_row.lease_generation
         and evidence_row.expected_file_revision = job_row.expected_file_revision
         and evidence_row.expected_attachment_revision =
           job_row.expected_attachment_revision
         and evidence_row.timeline_content_id = job_row.timeline_content_id
         and evidence_row.expected_content_revision >=
           job_row.expected_content_revision
         and evidence_row.resulting_content_revision =
           evidence_row.expected_content_revision + 1
         and evidence_row.resulting_content_revision =
           job_row.result_content_revision
         and evidence_row.content_mutation_fence_sha256 =
           job_row.content_mutation_fence_sha256
         and evidence_row.outcome::text = job_row.state::text
         and evidence_row.result_file_version_id is not distinct from
           job_row.result_file_version_id
         and evidence_row.result_object_version_id is not distinct from
           job_row.result_object_version_id
         and evidence_row.resulting_file_revision is not distinct from
           job_row.result_file_revision
         and evidence_row.safe_reason_id is not distinct from
           job_row.terminal_reason_id
         and (job_row.state = 'failed' or exists (
           select 1
             from public.inbox_v2_file_object_operation_evidence operation_row
            where operation_row.tenant_id = evidence_row.tenant_id
              and operation_row.id = evidence_row.object_operation_evidence_id
              and operation_row.materialization_job_id = job_row.id
              and operation_row.object_version_id = case
                when job_row.state = 'ready'
                  then job_row.result_object_version_id
                else job_row.reserved_object_version_id
              end
              and operation_row.operation_kind::text = case
                when job_row.state = 'ready' then 'put'
                else 'quarantine'
              end
              and operation_row.outcome = 'succeeded'
         ))
         and payload_row.attachment_state::text = job_row.state::text
         and payload_row.attachment_file_version_id is not distinct from
           job_row.result_file_version_id
         and payload_row.attachment_object_version_id is not distinct from
           job_row.result_object_version_id
         and payload_row.attachment_v2_file_id is not distinct from case
           when job_row.state = 'ready' then job_row.file_id else null end
         and payload_row.attachment_file_revision is not distinct from case
           when job_row.state = 'ready'
             then job_row.result_file_revision else null end
         and payload_row.attachment_failure_reason_id is not distinct from case
           when job_row.state in ('failed', 'quarantined')
             then job_row.terminal_reason_id else null end
         and (job_row.state <> 'ready' or exists (
           select 1
             from public.inbox_v2_file_objects file_row
             join public.inbox_v2_file_versions file_version_row
               on file_version_row.tenant_id = file_row.tenant_id
              and file_version_row.id = job_row.result_file_version_id
              and file_version_row.file_id = file_row.id
              and file_version_row.object_version_id =
                job_row.result_object_version_id
             join public.inbox_v2_file_object_versions object_version_row
               on object_version_row.tenant_id = file_row.tenant_id
              and object_version_row.id = job_row.result_object_version_id
             join public.inbox_v2_file_object_version_heads object_head_row
               on object_head_row.tenant_id = object_version_row.tenant_id
              and object_head_row.object_version_id = object_version_row.id
            where file_row.tenant_id = job_row.tenant_id
              and file_row.id = job_row.file_id
              and file_row.revision = job_row.result_file_revision
              and file_row.state = 'ready'
              and file_row.current_file_version_id =
                job_row.result_file_version_id
              and file_row.current_object_version_id =
                job_row.result_object_version_id
              and object_version_row.storage_root_id =
                job_row.reserved_storage_root_id
              and object_version_row.storage_object_key =
                job_row.reserved_storage_object_key
              and object_head_row.state = 'ready'
         ))
    ) into completion_valid;
    if not completion_valid then
      raise exception using errcode = '23503',
        message = 'inbox_v2.attachment_materialization_completion_invalid';
    end if;
  end if;
  return new;
end;
$_$;



--
-- Name: inbox_v2_file_materialization_job_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_materialization_job_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  transition_valid boolean := false;
  old_active boolean;
  new_active boolean;
  reauthorization boolean := false;
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_file_delete_is_tenant_cascade(old.tenant_id) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.attachment_materialization_delete_forbidden';
  end if;

  if tg_op = 'INSERT' then
    if new.state <> 'pending'
       or new.revision <> 1
       or new.lease_generation <> 0
       or new.authorization_command_type_id <>
         'core:attachment.materialization.reserve'
       or new.terminal_reason_id is not null then
      raise exception using errcode = '23514',
        message = 'inbox_v2.attachment_materialization_initial_state_invalid';
    end if;
    return new;
  end if;

  reauthorization :=
    old.state = 'pending'
    and new.state = 'pending'
    and num_nonnulls(
      old.lease_token_hash, old.lease_owner_id,
      old.lease_claimed_at, old.lease_expires_at
    ) = 0
    and num_nonnulls(
      new.lease_token_hash, new.lease_owner_id,
      new.lease_claimed_at, new.lease_expires_at
    ) = 0
    and new.lease_generation = old.lease_generation
    and new.authorization_command_type_id =
      'core:attachment.materialization.reauthorize'
    and new.authorization_command_id is distinct from
      old.authorization_command_id
    and new.authorization_actor_kind = 'trusted_service'
    and new.authorization_authorized_at >= old.authorization_authorized_at;

  if new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.attachment_id is distinct from old.attachment_id
     or new.file_id is distinct from old.file_id
     or new.expected_file_revision is distinct from old.expected_file_revision
     or new.conversation_id is distinct from old.conversation_id
     or new.timeline_item_id is distinct from old.timeline_item_id
     or new.parent_message_id is distinct from old.parent_message_id
     or new.expected_parent_revision is distinct from
       old.expected_parent_revision
     or new.visibility_boundary is distinct from old.visibility_boundary
     or new.timeline_content_id is distinct from old.timeline_content_id
     or new.expected_content_revision is distinct from old.expected_content_revision
     or new.content_block_key is distinct from old.content_block_key
     or new.content_mutation_fence_sha256 is distinct from
       old.content_mutation_fence_sha256
     or new.source_occurrence_id is distinct from old.source_occurrence_id
     or new.source_locator_kind is distinct from old.source_locator_kind
     or new.source_locator_reference is distinct from old.source_locator_reference
     or new.source_locator_digest_sha256 is distinct from
       old.source_locator_digest_sha256
     or new.reservation_namespace_generation is distinct from
       old.reservation_namespace_generation
     or new.idempotency_token is distinct from old.idempotency_token
     or new.cause_event_id is distinct from old.cause_event_id
     or new.cause_mutation_id is distinct from old.cause_mutation_id
     or new.cause_stream_commit_id is distinct from old.cause_stream_commit_id
     or new.cause_stream_position is distinct from old.cause_stream_position
     or new.correlation_id is distinct from old.correlation_id
     or new.caused_at is distinct from old.caused_at
     or (not reauthorization and (
       new.authorization_command_id is distinct from
         old.authorization_command_id
       or new.authorization_command_type_id is distinct from
         old.authorization_command_type_id
       or new.authorization_client_mutation_id is distinct from
         old.authorization_client_mutation_id
       or new.authorization_mutation_id is distinct from
         old.authorization_mutation_id
       or new.authorization_decision_id is distinct from
         old.authorization_decision_id
       or new.authorization_epoch is distinct from old.authorization_epoch
       or new.authorization_actor_kind is distinct from
         old.authorization_actor_kind
       or new.authorization_actor_id is distinct from
         old.authorization_actor_id
       or new.authorization_authorized_at is distinct from
         old.authorization_authorized_at
       or new.authorization_decision_set_digest_sha256 is distinct from
         old.authorization_decision_set_digest_sha256
       or new.authorization_resource_fence_set_digest_sha256 is distinct from
         old.authorization_resource_fence_set_digest_sha256
       or new.authorization_tenant_rbac_revision is distinct from
         old.authorization_tenant_rbac_revision
       or new.authorization_shared_access_revision is distinct from
         old.authorization_shared_access_revision
       or new.authorization_resource_head_id is distinct from
         old.authorization_resource_head_id
       or new.authorization_resource_access_revision is distinct from
         old.authorization_resource_access_revision
       or new.authorization_structural_relation_revision is distinct from
         old.authorization_structural_relation_revision
       or new.authorization_collaborator_set_revision is distinct from
         old.authorization_collaborator_set_revision
       or new.authorization_audit_grant_source_ids is distinct from
         old.authorization_audit_grant_source_ids
       or new.authorization_audit_policy_version is distinct from
         old.authorization_audit_policy_version
     ))
     or new.expected_attachment_revision is distinct from
       old.expected_attachment_revision
     or new.reserved_file_version_id is distinct from
       old.reserved_file_version_id
     or new.reserved_object_version_id is distinct from
       old.reserved_object_version_id
     or new.reserved_storage_root_id is distinct from
       old.reserved_storage_root_id
     or new.reserved_storage_object_key is distinct from
       old.reserved_storage_object_key
     or new.created_at is distinct from old.created_at
     or new.updated_at < old.updated_at
     or new.revision <> old.revision + 1
     or new.lease_generation < old.lease_generation
     or new.lease_generation > old.lease_generation + 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.attachment_materialization_cas_invalid';
  end if;

  if old.state in ('ready', 'failed', 'quarantined', 'cancelled') then
    raise exception using errcode = '23514',
      message = 'inbox_v2.attachment_materialization_terminal';
  end if;

  old_active := old.state in ('claimed', 'transferring', 'verifying');
  new_active := new.state in ('claimed', 'transferring', 'verifying');

  if reauthorization then
    transition_valid := true;
  elsif old.state = 'pending' and new.state = 'claimed' then
    transition_valid :=
      new.lease_generation = old.lease_generation + 1;
  elsif old.state = 'pending' and new.state = 'cancelled' then
    transition_valid :=
      new.lease_generation = old.lease_generation;
  elsif old_active and new.state = 'pending' then
    transition_valid :=
      new.lease_generation = old.lease_generation
      and num_nonnulls(
        new.lease_token_hash, new.lease_owner_id,
        new.lease_claimed_at, new.lease_expires_at
      ) = 0;
  elsif old_active and new.state = old.state then
    transition_valid :=
      old.lease_expires_at <= clock_timestamp()
      and new.lease_generation = old.lease_generation + 1
      and new.lease_token_hash is distinct from old.lease_token_hash
      and new.lease_claimed_at >= old.lease_expires_at;
  elsif old_active and (
    (old.state = 'claimed' and new.state in (
      'transferring', 'verifying', 'ready', 'failed', 'quarantined',
      'cancelled'
    ))
    or (old.state = 'transferring' and new.state in (
      'verifying', 'ready', 'failed', 'quarantined', 'cancelled'
    ))
    or (old.state = 'verifying' and new.state in (
      'ready', 'failed', 'quarantined', 'cancelled'
    ))
  ) then
    transition_valid :=
      new.lease_generation = old.lease_generation
      and (
        (new_active
          and new.lease_token_hash is not distinct from old.lease_token_hash
          and new.lease_owner_id is not distinct from old.lease_owner_id
          and new.lease_claimed_at is not distinct from old.lease_claimed_at
          and new.lease_expires_at is not distinct from old.lease_expires_at)
        or (not new_active
          and num_nonnulls(
            new.lease_token_hash, new.lease_owner_id,
            new.lease_claimed_at, new.lease_expires_at
          ) = 0)
      );
  end if;

  if not transition_valid then
    raise exception using errcode = '23514',
      message = 'inbox_v2.attachment_materialization_transition_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_object_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_object_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  mapped boolean;
  materialization_valid boolean := false;
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_file_delete_is_tenant_cascade(old.tenant_id) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_object_head_delete_forbidden';
  end if;

  if tg_op = 'INSERT' and (
    new.state <> 'pending'
    or new.revision <> 1
    or new.current_file_version_id is not null
    or new.current_object_version_id is not null
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_object_head_initial_state_invalid';
  end if;

  if tg_op = 'UPDATE' then
    if new.tenant_id <> old.tenant_id
       or new.id <> old.id
       or new.data_class_id <> old.data_class_id
       or new.processing_purpose_id <> old.processing_purpose_id
       or new.retention_anchor_at <> old.retention_anchor_at
       or new.created_at <> old.created_at
       or new.revision <> old.revision + 1
       or new.updated_at < old.updated_at then
      raise exception using errcode = '23514',
        message = 'inbox_v2.file_object_head_cas_invalid';
    end if;

    if old.state <> 'pending' or new.state <> 'ready'
       or old.current_file_version_id is not null
       or old.current_object_version_id is not null
       or new.current_file_version_id is null
       or new.current_object_version_id is null then
      raise exception using errcode = '23514',
        message = 'inbox_v2.file_object_head_transition_invalid';
    end if;
  end if;

  if new.current_file_version_id is not null then
    select exists (
      select 1
        from public.inbox_v2_file_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.id = new.current_file_version_id
         and version_row.file_id = new.id
         and version_row.object_version_id = new.current_object_version_id
    ) into mapped;
    if not mapped then
      raise exception using errcode = '23503',
        message = 'inbox_v2.file_object_head_version_invalid';
    end if;
  end if;

  if tg_op = 'UPDATE' then
    select exists (
      select 1
        from public.inbox_v2_file_attachment_materialization_jobs job_row
        join public.inbox_v2_file_versions version_row
          on version_row.tenant_id = job_row.tenant_id
         and version_row.id = job_row.reserved_file_version_id
         and version_row.file_id = job_row.file_id
         and version_row.object_version_id = job_row.reserved_object_version_id
        join public.inbox_v2_file_object_version_heads object_head_row
          on object_head_row.tenant_id = job_row.tenant_id
         and object_head_row.object_version_id =
           job_row.reserved_object_version_id
         and object_head_row.state = 'ready'
        join public.inbox_v2_file_object_operation_evidence evidence_row
          on evidence_row.tenant_id = object_head_row.tenant_id
         and evidence_row.id = object_head_row.latest_operation_evidence_id
         and evidence_row.object_version_id = object_head_row.object_version_id
         and evidence_row.materialization_job_id = job_row.id
         and evidence_row.operation_kind = 'put'
         and evidence_row.outcome = 'succeeded'
         and evidence_row.completed_at = object_head_row.state_changed_at
       where job_row.tenant_id = new.tenant_id
         and job_row.file_id = new.id
         and job_row.expected_file_revision = old.revision
         and job_row.reserved_file_version_id = new.current_file_version_id
         and job_row.reserved_object_version_id = new.current_object_version_id
         and job_row.state in ('claimed', 'transferring', 'verifying')
         and evidence_row.completed_at = new.updated_at
    ) into materialization_valid;
    if not materialization_valid then
      raise exception using errcode = '23503',
        message = 'inbox_v2.file_object_head_materialization_invalid';
    end if;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_object_version_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_object_version_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  evidence_valid boolean := false;
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_file_delete_is_tenant_cascade(old.tenant_id) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_object_version_head_delete_forbidden';
  end if;

  if tg_op = 'INSERT' and (
    new.revision <> 1
    or new.state not in ('staging', 'ready')
    or (new.state = 'staging' and new.latest_operation_evidence_id is not null)
    or (new.state = 'ready' and new.latest_operation_evidence_id is null)
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_object_version_head_initial_state_invalid';
  end if;

  if tg_op = 'UPDATE' and (
    new.tenant_id <> old.tenant_id
    or new.object_version_id <> old.object_version_id
    or new.created_at <> old.created_at
    or new.revision <> old.revision + 1
    or new.state_changed_at < old.state_changed_at
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_object_version_head_cas_invalid';
  end if;

  if tg_op = 'UPDATE' and (
    old.state <> 'staging'
    or new.state <> 'ready'
    or new.latest_operation_evidence_id is null
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_object_version_head_transition_invalid';
  end if;

  if new.state = 'ready' then
    select exists (
      select 1
        from public.inbox_v2_file_object_versions object_version_row
        join public.inbox_v2_file_object_operation_evidence evidence_row
          on evidence_row.tenant_id = object_version_row.tenant_id
         and evidence_row.object_version_id = object_version_row.id
        join public.inbox_v2_file_attachment_materialization_jobs job_row
          on job_row.tenant_id = evidence_row.tenant_id
         and job_row.id = evidence_row.materialization_job_id
         and job_row.reserved_object_version_id = evidence_row.object_version_id
         and job_row.reserved_storage_root_id = evidence_row.storage_root_id
       where evidence_row.tenant_id = new.tenant_id
         and evidence_row.id = new.latest_operation_evidence_id
         and evidence_row.object_version_id = new.object_version_id
         and evidence_row.operation_kind = 'put'
         and evidence_row.outcome = 'succeeded'
         and evidence_row.safe_reason_id is null
         and evidence_row.expected_object_head_revision is null
         and evidence_row.completed_at = new.state_changed_at
         and evidence_row.requested_at <= evidence_row.completed_at
         and evidence_row.affected_bytes = object_version_row.size_bytes
         and object_version_row.storage_root_id = evidence_row.storage_root_id
         and job_row.reserved_storage_object_key =
           object_version_row.storage_object_key
         and job_row.state in ('claimed', 'transferring', 'verifying')
    ) into evidence_valid;
    if not evidence_valid then
      raise exception using errcode = '23503',
        message = 'inbox_v2.file_object_version_evidence_invalid';
    end if;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_parent_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_parent_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  parent_valid boolean := false;
  head_row record;
begin
  if tg_table_name = 'inbox_v2_file_parent_links' then
    if new.parent_kind = 'message' then
      select exists (
        select 1
          from public.inbox_v2_messages message_row
          join public.inbox_v2_timeline_items item_row
            on item_row.tenant_id = message_row.tenant_id
           and item_row.id = message_row.timeline_item_id
           and item_row.conversation_id = message_row.conversation_id
         where message_row.tenant_id = new.tenant_id
           and message_row.id = new.parent_entity_id
           and message_row.revision = new.parent_entity_revision
           and message_row.conversation_id = new.conversation_id
           and message_row.timeline_item_id = new.timeline_item_id
           and message_row.content_id = new.content_id
           and message_row.content_revision = new.content_revision
           and ((new.visibility_boundary = 'external_work'
                and item_row.visibility = 'conversation_external')
             or (new.visibility_boundary = 'internal'
                and item_row.visibility = 'internal_participants'))
      ) into parent_valid;
    elsif new.parent_kind = 'staff_note' then
      select exists (
        select 1
          from public.inbox_v2_staff_notes note_row
          join public.inbox_v2_timeline_items item_row
            on item_row.tenant_id = note_row.tenant_id
           and item_row.id = note_row.timeline_item_id
           and item_row.conversation_id = note_row.conversation_id
         where note_row.tenant_id = new.tenant_id
           and note_row.id = new.parent_entity_id
           and note_row.revision = new.parent_entity_revision
           and note_row.conversation_id = new.conversation_id
           and note_row.timeline_item_id = new.timeline_item_id
           and note_row.content_id = new.content_id
           and note_row.content_revision = new.content_revision
           and item_row.visibility = 'staff_only'
      ) into parent_valid;
    else
      select exists (
        select 1
          from public.inbox_v2_message_attachment_anchors attachment_row
         where attachment_row.tenant_id = new.tenant_id
           and attachment_row.id = new.parent_entity_id
           and attachment_row.revision = new.parent_entity_revision
           and exists (
             select 1
               from public.inbox_v2_file_attachment_materialization_jobs job_row
              where job_row.tenant_id = attachment_row.tenant_id
                and job_row.attachment_id = attachment_row.id
                and job_row.file_id = new.file_id
           )
      ) into parent_valid;
    end if;

    if parent_valid and new.parent_kind in ('message', 'staff_note') then
      select exists (
        select 1
          from public.inbox_v2_timeline_content_payloads payload_row
         where payload_row.tenant_id = new.tenant_id
           and payload_row.content_id = new.content_id
           and payload_row.content_revision = new.content_revision
           and payload_row.block_key = new.block_key
           and (
             (new.parent_purpose = 'attachment'
               and payload_row.attachment_v2_file_id = new.file_id
               and payload_row.attachment_file_version_id = new.file_version_id
               and payload_row.attachment_object_version_id =
                 new.object_version_id)
             or (new.parent_purpose = 'extension_payload'
               and payload_row.extension_payload_v2_file_id = new.file_id
               and payload_row.extension_payload_file_version_id =
                 new.file_version_id
               and payload_row.extension_payload_object_version_id =
                 new.object_version_id)
           )
      ) into parent_valid;
    end if;

    if not parent_valid then
      raise exception using errcode = '23503',
        message = 'inbox_v2.file_parent_invalid';
    end if;
  end if;

  select * into head_row
    from public.inbox_v2_file_parent_set_heads head
   where head.tenant_id = new.tenant_id
     and head.file_id = new.file_id;

  if head_row.completeness = 'complete' and (
    head_row.completeness_revision <> head_row.revision
    or head_row.live_parent_count <> (
      select count(*)
        from public.inbox_v2_file_parent_links link_row
        join public.inbox_v2_file_parent_link_heads link_head_row
          on link_head_row.tenant_id = link_row.tenant_id
         and link_head_row.link_id = link_row.id
         and link_head_row.file_id = link_row.file_id
       where link_row.tenant_id = new.tenant_id
         and link_row.file_id = new.file_id
         and link_head_row.state = 'live'
    )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_parent_set_incomplete';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_parent_link_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_parent_link_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_file_delete_is_tenant_cascade(old.tenant_id) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_parent_link_head_delete_forbidden';
  end if;
  if tg_op = 'UPDATE' and (
    old.state <> 'live' or new.state <> 'detached'
    or new.tenant_id is distinct from old.tenant_id
    or new.link_id is distinct from old.link_id
    or new.file_id is distinct from old.file_id
    or new.revision <> old.revision + 1
    or new.detached_by_event_id is null
    or new.updated_at < old.updated_at
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_parent_link_head_transition_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_parent_set_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_parent_set_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_file_delete_is_tenant_cascade(old.tenant_id) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_parent_set_head_delete_forbidden';
  end if;
  if tg_op = 'UPDATE' and (
    new.tenant_id is distinct from old.tenant_id
    or new.file_id is distinct from old.file_id
    or new.revision <> old.revision + 1
    or new.updated_at < old.updated_at
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_parent_set_head_cas_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_file_storage_orphan_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_file_storage_orphan_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  transition_valid boolean := false;
  adoption_valid boolean := false;
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_file_delete_is_tenant_cascade(old.tenant_id) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_storage_orphan_delete_forbidden';
  end if;
  if old.state in ('quarantined', 'adopted', 'deleted', 'failed')
     or new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.materialization_job_id is distinct from old.materialization_job_id
     or new.storage_root_id is distinct from old.storage_root_id
     or new.storage_object_key is distinct from old.storage_object_key
     or new.storage_version_identity is distinct from old.storage_version_identity
     or new.checksum_sha256 is distinct from old.checksum_sha256
     or new.size_bytes is distinct from old.size_bytes
     or new.detected_media_type is distinct from old.detected_media_type
     or new.quarantine_reason_code is distinct from old.quarantine_reason_code
     or new.quarantine_evidence_digest_sha256 is distinct from
       old.quarantine_evidence_digest_sha256
     or new.quarantine_physical_kind is distinct from old.quarantine_physical_kind
     or new.first_observed_at is distinct from old.first_observed_at
     or new.revision <> old.revision + 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_storage_orphan_cas_invalid';
  end if;

  if old.state = 'open' and new.state in ('claimed', 'adopted', 'failed') then
    transition_valid := true;
  elsif old.state = 'claimed' and new.state = 'claimed' then
    transition_valid :=
      old.claim_expires_at <= clock_timestamp()
      and new.claim_token_hash is distinct from old.claim_token_hash;
  elsif old.state = 'claimed' and new.state in ('adopted', 'deleted', 'failed') then
    transition_valid := true;
  end if;
  if not transition_valid then
    raise exception using errcode = '23514',
      message = 'inbox_v2.file_storage_orphan_transition_invalid';
  end if;

  if new.state = 'adopted' then
    select exists (
      select 1
        from public.inbox_v2_file_attachment_materialization_jobs job_row
        join public.inbox_v2_file_object_versions object_version_row
          on object_version_row.tenant_id = job_row.tenant_id
         and object_version_row.id = job_row.result_object_version_id
        join public.inbox_v2_file_attachment_materialization_evidence evidence_row
          on evidence_row.tenant_id = job_row.tenant_id
         and evidence_row.job_id = job_row.id
         and evidence_row.outcome = 'ready'
         and evidence_row.result_object_version_id =
           job_row.result_object_version_id
         and evidence_row.evidence_hash_sha256 =
           new.terminal_evidence_digest_sha256
       where job_row.tenant_id = new.tenant_id
         and job_row.id = new.materialization_job_id
         and job_row.state = 'ready'
         and job_row.result_object_version_id =
           new.adopted_object_version_id
         and job_row.reserved_object_version_id =
           new.adopted_object_version_id
         and object_version_row.storage_root_id = new.storage_root_id
         and object_version_row.storage_object_key = new.storage_object_key
         and object_version_row.storage_version_identity =
           new.storage_version_identity
         and object_version_row.checksum_sha256 = new.checksum_sha256
         and object_version_row.size_bytes = new.size_bytes
         and object_version_row.detected_media_type = new.detected_media_type
    ) into adoption_valid;
    if not adoption_valid then
      raise exception using errcode = '23503',
        message = 'inbox_v2.file_storage_orphan_adoption_invalid';
    end if;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_guard_account_identity_stable_edge(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_guard_account_identity_stable_edge() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if old.tenant_id is distinct from new.tenant_id
     or old.source_account_id is distinct from new.source_account_id
     or old.source_connection_id is distinct from new.source_connection_id
     or old.identity_declaration is distinct from new.identity_declaration
     or old.declaration_contract_id is distinct from new.declaration_contract_id
     or old.declaration_contract_version is distinct from new.declaration_contract_version
     or old.declaration_revision is distinct from new.declaration_revision
     or old.declaration_surface_id is distinct from new.declaration_surface_id
     or old.declaration_loaded_by_trusted_service_id
       is distinct from new.declaration_loaded_by_trusted_service_id
     or old.declaration_loaded_at is distinct from new.declaration_loaded_at
     or old.declaration_realm_id is distinct from new.declaration_realm_id
     or old.declaration_realm_version is distinct from new.declaration_realm_version
     or old.declaration_canonicalization_version
       is distinct from new.declaration_canonicalization_version
     or old.declaration_object_kind_id is distinct from new.declaration_object_kind_id
     or old.declaration_scope_kind is distinct from new.declaration_scope_kind
     or (
       old.state = 'verified'
       and new.state = 'verified'
       and (
         old.canonical_realm_id is distinct from new.canonical_realm_id
         or old.canonical_realm_version
           is distinct from new.canonical_realm_version
         or old.canonicalization_version
           is distinct from new.canonicalization_version
         or old.canonical_object_kind_id
           is distinct from new.canonical_object_kind_id
         or old.canonical_scope_kind is distinct from new.canonical_scope_kind
         or old.canonical_scope_source_connection_id
           is distinct from new.canonical_scope_source_connection_id
         or old.canonical_scope_owner_key
           is distinct from new.canonical_scope_owner_key
         or old.canonical_external_subject
           is distinct from new.canonical_external_subject
       )
     )
     or old.created_at is distinct from new.created_at then
    raise exception 'source account identity stable edge or declaration changed'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_guard_binding_collection_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_guard_binding_collection_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_new jsonb := to_jsonb(new);
  v_tenant_id text := v_new->>'tenant_id';
  v_binding_id text;
  v_binding_revision bigint;
begin
  if tg_table_name =
     'inbox_v2_source_thread_binding_transition_matched_permissions' then
    select binding_id, resulting_binding_revision
      into v_binding_id, v_binding_revision
      from public.inbox_v2_source_thread_binding_transitions
     where tenant_id = v_tenant_id
       and id = v_new->>'transition_id';
  else
    v_binding_id := v_new->>'binding_id';
    v_binding_revision :=
      (v_new->>'materialized_by_binding_revision')::bigint;
  end if;

  if v_binding_id is null or v_binding_revision is null then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding collection row lacks its materialization commit';
  end if;
  if exists (
    select 1 from public.inbox_v2_source_thread_binding_snapshots s
     where s.tenant_id = v_tenant_id
       and s.binding_id = v_binding_id
       and s.revision = v_binding_revision
  ) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding collection materialization is already closed';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_guard_binding_episode_change(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_guard_binding_episode_change() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding episodes cannot be deleted';
  end if;
  if old.ended_at is not null
     or old.revision <> 1
     or new.ended_at is null
     or new.end_evidence_set_id is null
     or new.revision <> 2
     or new.updated_at <> new.ended_at
     or row(old.tenant_id, old.id, old.binding_id, old.state,
            old.started_at, old.start_evidence_set_id)
        is distinct from
        row(new.tenant_id, new.id, new.binding_id, new.state,
            new.started_at, new.start_evidence_set_id) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding episode only permits an exact revision-1 to revision-2 close';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_guard_binding_head_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_guard_binding_head_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_transition public.inbox_v2_source_thread_binding_transitions%rowtype;
  v_old jsonb;
  v_new jsonb;
begin
  if tg_op = 'DELETE' then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding current head cannot be deleted';
  end if;

  select * into strict v_transition
    from public.inbox_v2_source_thread_binding_transitions
   where tenant_id = new.tenant_id
     and binding_id = new.binding_id
     and resulting_binding_revision = new.revision;

  if old.revision <> v_transition.expected_binding_revision
     or new.updated_at <> v_transition.occurred_at
     or new.updated_at < old.updated_at
     or (v_transition.kind <> 'administrative'
       and v_transition.actor_trusted_service_id <>
           old.account_identity_trusted_service_id)
     or row(old.tenant_id, old.binding_id, old.external_thread_id,
            old.source_connection_id, old.source_account_id, old.created_at)
        is distinct from
        row(new.tenant_id, new.binding_id, new.external_thread_id,
            new.source_connection_id, new.source_account_id, new.created_at) then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding head update lacks the exact transition CAS or changes its anchor';
  end if;

  case v_transition.kind
    when 'remote_access' then
      if old.remote_access_state <> v_transition.remote_from_state
         or old.remote_access_revision <>
            v_transition.expected_remote_access_revision then
        raise exception using errcode = '23514',
          message = 'Inbox V2 remote transition does not CAS the current axis';
      end if;
    when 'administrative' then
      if old.administrative_state <>
            v_transition.administrative_from_state
         or old.administrative_revision <>
            v_transition.expected_administrative_revision then
        raise exception using errcode = '23514',
          message = 'Inbox V2 administrative transition does not CAS the current axis';
      end if;
    when 'runtime_health' then
      if old.runtime_health_state <> v_transition.runtime_health_from_state
         or old.runtime_health_revision <>
            v_transition.expected_runtime_health_revision then
        raise exception using errcode = '23514',
          message = 'Inbox V2 runtime transition does not CAS the current axis';
      end if;
    when 'history_sync' then
      if old.history_sync_state <> v_transition.history_sync_from_state
         or old.history_sync_revision <>
            v_transition.expected_history_sync_revision
         or (v_transition.history_sync_from_state =
             v_transition.history_sync_to_state
           and row(old.history_receive_cursor, old.history_cursor,
                   old.history_provider_watermark)
             is not distinct from
             row(new.history_receive_cursor, new.history_cursor,
                 new.history_provider_watermark)) then
        raise exception using errcode = '23514',
          message = 'Inbox V2 history transition does not CAS or advance progress';
      end if;
    when 'capabilities' then
      if old.capability_revision <> v_transition.expected_capability_revision
         or old.capability_semantic_digest_sha256 =
            new.capability_semantic_digest_sha256 then
        raise exception using errcode = '23514',
          message = 'Inbox V2 capability transition does not CAS or change semantics';
      end if;
    when 'route_descriptor' then
      if old.binding_generation <> v_transition.expected_binding_generation
         or old.route_descriptor_revision <>
            v_transition.expected_route_descriptor_revision
         or row(old.route_descriptor_digest_sha256,
                old.route_attributes_digest_sha256)
           is not distinct from
           row(new.route_descriptor_digest_sha256,
               new.route_attributes_digest_sha256) then
        raise exception using errcode = '23514',
          message = 'Inbox V2 route transition does not CAS or change descriptor';
      end if;
    when 'account_generation' then
      if old.account_generation <> v_transition.expected_account_generation then
        raise exception using errcode = '23514',
          message = 'Inbox V2 account transition does not CAS current generation';
      end if;
    when 'provider_access' then
      if old.provider_access_revision <>
            v_transition.expected_provider_access_revision
         or old.binding_generation <>
            v_transition.expected_binding_generation
         or old.provider_roles_digest_sha256 =
            new.provider_roles_digest_sha256 then
        raise exception using errcode = '23514',
          message = 'Inbox V2 provider transition does not CAS or change roles';
      end if;
  end case;

  v_old := to_jsonb(old) - array['revision', 'updated_at'];
  v_new := to_jsonb(new) - array['revision', 'updated_at'];
  case v_transition.kind
    when 'remote_access' then
      v_old := v_old - array[
        'current_remote_access_episode_id', 'current_remote_access_episode_revision',
        'remote_access_state', 'remote_access_evidence_authority',
        'remote_access_revision', 'remote_access_since',
        'remote_access_evidence_set_id'
      ];
      v_new := v_new - array[
        'current_remote_access_episode_id', 'current_remote_access_episode_revision',
        'remote_access_state', 'remote_access_evidence_authority',
        'remote_access_revision', 'remote_access_since',
        'remote_access_evidence_set_id'
      ];
    when 'administrative' then
      v_old := v_old - array[
        'administrative_state', 'administrative_revision',
        'administrative_changed_at'
      ];
      v_new := v_new - array[
        'administrative_state', 'administrative_revision',
        'administrative_changed_at'
      ];
    when 'runtime_health' then
      v_old := v_old - array[
        'runtime_health_state', 'runtime_health_revision',
        'runtime_health_checked_at', 'runtime_diagnostic_code_id',
        'runtime_diagnostic_retryable', 'runtime_diagnostic_correlation_token',
        'runtime_diagnostic_safe_operator_hint_id'
      ];
      v_new := v_new - array[
        'runtime_health_state', 'runtime_health_revision',
        'runtime_health_checked_at', 'runtime_diagnostic_code_id',
        'runtime_diagnostic_retryable', 'runtime_diagnostic_correlation_token',
        'runtime_diagnostic_safe_operator_hint_id'
      ];
    when 'history_sync' then
      v_old := v_old - array[
        'history_sync_state', 'history_sync_revision', 'history_receive_cursor',
        'history_cursor', 'history_provider_watermark',
        'history_last_durable_raw_event_id', 'history_updated_at',
        'history_diagnostic_code_id', 'history_diagnostic_retryable',
        'history_diagnostic_correlation_token',
        'history_diagnostic_safe_operator_hint_id'
      ];
      v_new := v_new - array[
        'history_sync_state', 'history_sync_revision', 'history_receive_cursor',
        'history_cursor', 'history_provider_watermark',
        'history_last_durable_raw_event_id', 'history_updated_at',
        'history_diagnostic_code_id', 'history_diagnostic_retryable',
        'history_diagnostic_correlation_token',
        'history_diagnostic_safe_operator_hint_id'
      ];
    when 'capabilities' then
      v_old := v_old - array[
        'capability_contract_id', 'capability_contract_version',
        'capability_declaration_revision', 'capability_surface_id',
        'capability_loaded_by_trusted_service_id', 'capability_loaded_at',
        'capability_revision', 'capability_entry_count',
        'capability_semantic_digest_sha256', 'capability_captured_at'
      ];
      v_new := v_new - array[
        'capability_contract_id', 'capability_contract_version',
        'capability_declaration_revision', 'capability_surface_id',
        'capability_loaded_by_trusted_service_id', 'capability_loaded_at',
        'capability_revision', 'capability_entry_count',
        'capability_semantic_digest_sha256', 'capability_captured_at'
      ];
    when 'route_descriptor' then
      v_old := v_old - array[
        'binding_generation', 'route_contract_id', 'route_contract_version',
        'route_declaration_revision', 'route_surface_id',
        'route_loaded_by_trusted_service_id', 'route_loaded_at',
        'route_descriptor_schema_id', 'route_descriptor_version',
        'route_descriptor_revision', 'route_destination_kind_id',
        'route_destination_subject', 'route_descriptor_digest_sha256',
        'route_attribute_count', 'route_attributes_digest_sha256'
      ];
      v_new := v_new - array[
        'binding_generation', 'route_contract_id', 'route_contract_version',
        'route_declaration_revision', 'route_surface_id',
        'route_loaded_by_trusted_service_id', 'route_loaded_at',
        'route_descriptor_schema_id', 'route_descriptor_version',
        'route_descriptor_revision', 'route_destination_kind_id',
        'route_destination_subject', 'route_descriptor_digest_sha256',
        'route_attribute_count', 'route_attributes_digest_sha256'
      ];
    when 'account_generation' then
      v_old := v_old - array[
        'account_identity_revision', 'account_generation',
        'account_identity_state', 'account_canonical_key_digest_sha256',
        'account_identity_trusted_service_id', 'account_verified_at',
        'account_verification_evidence_set_id'
      ];
      v_new := v_new - array[
        'account_identity_revision', 'account_generation',
        'account_identity_state', 'account_canonical_key_digest_sha256',
        'account_identity_trusted_service_id', 'account_verified_at',
        'account_verification_evidence_set_id'
      ];
    when 'provider_access' then
      v_old := v_old - array[
        'binding_generation', 'provider_access_revision',
        'provider_role_count', 'provider_roles_digest_sha256',
        'provider_access_evidence_set_id', 'provider_access_observed_at'
      ];
      v_new := v_new - array[
        'binding_generation', 'provider_access_revision',
        'provider_role_count', 'provider_roles_digest_sha256',
        'provider_access_evidence_set_id', 'provider_access_observed_at'
      ];
  end case;

  if v_old is distinct from v_new then
    raise exception using errcode = '23514',
      message = 'Inbox V2 binding transition changed fields owned by another axis';
  end if;
  return new;
exception when no_data_found then
  raise exception using errcode = '23514',
    message = 'Inbox V2 binding head update requires a persisted typed transition';
end;
$$;



--
-- Name: inbox_v2_lock_conversation_identity(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_lock_conversation_identity(checked_tenant_id text, checked_conversation_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if checked_tenant_id is null or checked_conversation_id is null then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_identity_lock_key_missing';
  end if;
  perform pg_catalog.pg_advisory_xact_lock(
    pg_catalog.hashtext(checked_tenant_id),
    pg_catalog.hashtext(checked_conversation_id)
  );
end;
$$;



--
-- Name: inbox_v2_lock_conversation_membership_head_v1(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>_inbox_v2_membership_owner
--

CREATE FUNCTION public.inbox_v2_lock_conversation_membership_head_v1(checked_tenant_id text, checked_conversation_id text) RETURNS bigint
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  locked_membership_revision bigint;
begin
  if pg_catalog.current_setting('transaction_isolation') <> 'read committed' then
    raise exception using
      errcode = '25001',
      message = 'inbox_v2.membership_requires_read_committed';
  end if;
  if checked_tenant_id is null or checked_conversation_id is null then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.membership_head_lock_scope_invalid';
  end if;

  select head_row.membership_revision
    into locked_membership_revision
    from public.inbox_v2_conversation_membership_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id
   for update;

  return locked_membership_revision;
end;
$$;


ALTER FUNCTION public.inbox_v2_lock_conversation_membership_head_v1(checked_tenant_id text, checked_conversation_id text) OWNER TO hulee_inbox_v2_membership_owner;

--
-- Name: inbox_v2_lock_participant_membership_mutation_v1(text, text, bigint, text, text, public.inbox_v2_participant_membership_origin_kind, public.inbox_v2_participant_membership_state); Type: FUNCTION; Schema: public; Owner: <database-owner>_inbox_v2_membership_owner
--

CREATE FUNCTION public.inbox_v2_lock_participant_membership_mutation_v1(checked_tenant_id text, checked_conversation_id text, checked_expected_membership_revision bigint, checked_participant_id text, checked_episode_id text, checked_origin_kind public.inbox_v2_participant_membership_origin_kind, checked_target_state public.inbox_v2_participant_membership_state) RETURNS bigint
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  locked_membership_revision bigint;
  locked_employee_id text;
  locked_employee_deactivated_at timestamptz;
  locked_conversation_transport public.inbox_v2_conversation_transport;
  locked_episode_origin public.inbox_v2_participant_membership_origin_kind;
begin
  if pg_catalog.current_setting('transaction_isolation') <> 'read committed' then
    raise exception using
      errcode = '25001',
      message = 'inbox_v2.membership_requires_read_committed';
  end if;

  if checked_tenant_id is null
     or checked_conversation_id is null
     or checked_expected_membership_revision is null
     or checked_expected_membership_revision < 0
     or checked_participant_id is null
     or checked_origin_kind is null
     or checked_target_state is null then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.membership_lock_scope_invalid';
  end if;

  -- Aggregate mutex is always first. It also makes the following unlocked
  -- discovery reads stable against every supported membership writer.
  select head_row.membership_revision
    into locked_membership_revision
    from public.inbox_v2_conversation_membership_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.conversation_id = checked_conversation_id
   for update;

  if not found
     or locked_membership_revision <> checked_expected_membership_revision then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.conversation_membership_revision_conflict';
  end if;

  if checked_episode_id is not null then
    select episode_row.origin_kind
      into locked_episode_origin
      from public.inbox_v2_participant_membership_episodes episode_row
     where episode_row.tenant_id = checked_tenant_id
       and episode_row.id = checked_episode_id
       and episode_row.participant_id = checked_participant_id
       and episode_row.conversation_id = checked_conversation_id;

    if not found or locked_episode_origin <> checked_origin_kind then
      raise exception using
        errcode = '23503',
        message = 'inbox_v2.membership_episode_lock_target_missing';
    end if;
  end if;

  -- Employee fencing is second. Closing an internal episode still takes the
  -- fence, but it deliberately permits an already-deactivated Employee.
  if checked_origin_kind = 'hulee_internal_command' then
    select employee_row.id,
           employee_row.deactivated_at,
           conversation_row.transport
      into locked_employee_id,
           locked_employee_deactivated_at,
           locked_conversation_transport
      from public.inbox_v2_conversation_participants participant_row
      join public.employees employee_row
        on employee_row.tenant_id = participant_row.tenant_id
       and employee_row.id = participant_row.subject_employee_id
      join public.inbox_v2_conversations conversation_row
        on conversation_row.tenant_id = participant_row.tenant_id
       and conversation_row.id = participant_row.conversation_id
     where participant_row.tenant_id = checked_tenant_id
       and participant_row.id = checked_participant_id
       and participant_row.conversation_id = checked_conversation_id
       and participant_row.subject_kind = 'employee'
     for no key update of employee_row;

    if not found
       or locked_employee_id is null
       or locked_conversation_transport <> 'internal'
       or (
         checked_target_state in ('pending', 'active')
         and locked_employee_deactivated_at is not null
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.internal_membership_subject_or_employee_invalid';
    end if;
  end if;

  -- The exact participant and current episode are locked only after the
  -- aggregate head and optional Employee fence.
  perform 1
    from public.inbox_v2_conversation_participants participant_row
   where participant_row.tenant_id = checked_tenant_id
     and participant_row.id = checked_participant_id
     and participant_row.conversation_id = checked_conversation_id
   for update;
  if not found then
    raise exception using
      errcode = '23503',
      message = 'inbox_v2.membership_participant_lock_target_missing';
  end if;

  if checked_episode_id is not null then
    perform 1
      from public.inbox_v2_participant_membership_episodes episode_row
     where episode_row.tenant_id = checked_tenant_id
       and episode_row.id = checked_episode_id
       and episode_row.participant_id = checked_participant_id
       and episode_row.conversation_id = checked_conversation_id
       and episode_row.origin_kind = checked_origin_kind
     for update;
    if not found then
      raise exception using
        errcode = '23503',
        message = 'inbox_v2.membership_episode_lock_target_missing';
    end if;
  end if;

  return locked_membership_revision;
end;
$$;


ALTER FUNCTION public.inbox_v2_lock_participant_membership_mutation_v1(checked_tenant_id text, checked_conversation_id text, checked_expected_membership_revision bigint, checked_participant_id text, checked_episode_id text, checked_origin_kind public.inbox_v2_participant_membership_origin_kind, checked_target_state public.inbox_v2_participant_membership_state) OWNER TO hulee_inbox_v2_membership_owner;

--
-- Name: inbox_v2_msg003_action_attribution_cause_event_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_msg003_action_attribution_cause_event_coherence() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.automation_cause_event_id is null then
    return null;
  end if;

  perform 1
    from public.inbox_v2_domain_events event_row
   where event_row.tenant_id = new.tenant_id
     and event_row.id = new.automation_cause_event_id
   for key share;
  if found then
    return null;
  end if;

  perform 1
    from public.event_store event_row
   where event_row.tenant_id = new.tenant_id
     and event_row.id = new.automation_cause_event_id
   for key share;
  if found then
    return null;
  end if;

  raise exception using errcode = '23503',
    message = 'inbox_v2.action_attribution_cause_event_missing';
end;
$$;



--
-- Name: inbox_v2_msg003_attachment_anchor_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_msg003_attachment_anchor_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  changed_row jsonb;
  tenant_key text;
  content_key text;
begin
  changed_row := case when tg_op = 'DELETE' then to_jsonb(old) else to_jsonb(new) end;
  tenant_key := changed_row->>'tenant_id';
  content_key := case
    when tg_table_name = 'inbox_v2_message_attachment_anchors'
      then changed_row->>'owner_timeline_content_id'
    else coalesce(changed_row->>'id', changed_row->>'content_id')
  end;

  if content_key is null
     or not exists (select 1 from public.tenants where id = tenant_key) then
    return null;
  end if;

  if exists (
    select 1
      from public.inbox_v2_message_attachment_anchors anchor_row
      left join public.inbox_v2_timeline_contents content_row
        on content_row.tenant_id = anchor_row.tenant_id
       and content_row.id = anchor_row.owner_timeline_content_id
      left join public.inbox_v2_messages message_row
        on message_row.tenant_id = anchor_row.tenant_id
       and message_row.id = anchor_row.owner_message_id
     where anchor_row.tenant_id = tenant_key
       and anchor_row.owner_timeline_content_id = content_key
       and (
         content_row.id is null
         or content_row.owner_kind <> 'message'
         or content_row.owner_id <> anchor_row.owner_message_id
         or message_row.id is null
         or message_row.timeline_item_id <>
           anchor_row.owner_timeline_item_id
         or message_row.content_id <>
           anchor_row.owner_timeline_content_id
         or (content_row.state = 'available' and not exists (
           select 1
             from public.inbox_v2_timeline_content_payloads payload_row
            where payload_row.tenant_id = anchor_row.tenant_id
              and payload_row.content_id =
                anchor_row.owner_timeline_content_id
              and payload_row.content_revision = content_row.revision
              and payload_row.block_key = anchor_row.owner_block_key
              and payload_row.attachment_id = anchor_row.id
              and payload_row.attachment_state =
                anchor_row.materialization_state
         ))
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_attachment_anchor_owner_mismatch';
  end if;

  if exists (
    select 1
      from public.inbox_v2_timeline_contents content_row
      join public.inbox_v2_timeline_content_payloads payload_row
        on payload_row.tenant_id = content_row.tenant_id
       and payload_row.content_id = content_row.id
       and payload_row.content_revision = content_row.revision
      left join public.inbox_v2_messages message_row
        on message_row.tenant_id = content_row.tenant_id
       and message_row.id = content_row.owner_id
       and message_row.content_id = content_row.id
      left join public.inbox_v2_message_attachment_anchors anchor_row
        on anchor_row.tenant_id = payload_row.tenant_id
       and anchor_row.id = payload_row.attachment_id
       and anchor_row.owner_message_id = message_row.id
       and anchor_row.owner_timeline_item_id = message_row.timeline_item_id
       and anchor_row.owner_timeline_content_id = payload_row.content_id
       and anchor_row.owner_block_key = payload_row.block_key
       and anchor_row.materialization_state = payload_row.attachment_state
     where content_row.tenant_id = tenant_key
       and content_row.id = content_key
       and content_row.state = 'available'
       and payload_row.attachment_id is not null
       and (content_row.owner_kind <> 'message' or anchor_row.id is null)
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_attachment_payload_anchor_mismatch';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_msg003_attachment_anchor_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_msg003_attachment_anchor_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'INSERT' then
    if num_nonnulls(
      new.owner_message_id, new.owner_timeline_item_id,
      new.owner_timeline_content_id, new.owner_block_key,
      new.materialization_state
    ) <> 5 or new.revision <> 1 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_attachment_anchor_owner_required';
    end if;
    return new;
  end if;

  if tg_op = 'DELETE' then
    -- Only the nested RI delete caused by removing the owning tenant may
    -- bypass immutability. An unrelated application trigger can also raise
    -- trigger depth and therefore must not be sufficient on its own.
    if pg_catalog.pg_trigger_depth() > 1
       and not exists (
         select 1 from public.tenants tenant_row
          where tenant_row.id = old.tenant_id
       ) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_attachment_anchor_immutable';
  end if;

  if new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.owner_message_id is distinct from old.owner_message_id
     or new.owner_timeline_item_id is distinct from old.owner_timeline_item_id
     or new.owner_timeline_content_id is distinct from
       old.owner_timeline_content_id
     or new.owner_block_key is distinct from old.owner_block_key
     or new.created_at is distinct from old.created_at
     or old.materialization_state <> 'pending'
     or new.materialization_state not in ('ready', 'failed', 'quarantined')
     or new.revision <> old.revision + 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_attachment_anchor_transition_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_msg003_legacy_cause_event_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_msg003_legacy_cause_event_guard() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE'
     and pg_catalog.pg_trigger_depth() > 1
     and not exists (
       select 1 from public.tenants tenant_row
        where tenant_row.id = old.tenant_id
     ) then
    return old;
  end if;

  if exists (
    select 1
      from public.inbox_v2_action_attributions attribution_row
     where attribution_row.tenant_id = old.tenant_id
       and attribution_row.automation_cause_event_id = old.id
  ) then
    raise exception using errcode = '23503',
      message = 'inbox_v2.action_attribution_legacy_cause_event_referenced';
  end if;
  if tg_op = 'DELETE' then
    return old;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_accepted_artifact_retry_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_accepted_artifact_retry_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.state = 'accepted' then
    if pg_catalog.current_setting('transaction_isolation') <> 'read committed' then
      raise exception using errcode = '25001',
        message = 'inbox_v2.outbound_artifact_retry_isolation_unsafe';
    end if;

    perform 1
      from public.inbox_v2_outbound_dispatch_attempts attempt_row
     where attempt_row.tenant_id = new.tenant_id
       and attempt_row.id = new.attempt_id
       and attempt_row.dispatch_id = new.dispatch_id
       and attempt_row.route_id = new.route_id
       and attempt_row.message_id = new.message_id
       for update;

    if exists (
      select 1
        from public.inbox_v2_outbound_dispatch_reconciliation_decisions
          decision_row
       where decision_row.tenant_id = new.tenant_id
         and decision_row.dispatch_id = new.dispatch_id
         and decision_row.unknown_attempt_id = new.attempt_id
         and decision_row.result_state = 'retryable_failure'
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_artifact_retry_unsafe';
    end if;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_artifact_link_guard_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_artifact_link_guard_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform 1
    from public.inbox_v2_outbound_dispatch_artifacts artifact_row
    join public.inbox_v2_outbound_dispatch_attempts attempt_row
      on attempt_row.tenant_id = artifact_row.tenant_id
     and attempt_row.id = artifact_row.attempt_id
     and attempt_row.dispatch_id = artifact_row.dispatch_id
     and attempt_row.route_id = artifact_row.route_id
     and attempt_row.message_id = artifact_row.message_id
    join public.inbox_v2_outbound_routes route_row
      on route_row.tenant_id = artifact_row.tenant_id
     and route_row.id = artifact_row.route_id
    join public.inbox_v2_source_occurrences occurrence_row
      on occurrence_row.tenant_id = artifact_row.tenant_id
     and occurrence_row.id = new.source_occurrence_id
     and occurrence_row.revision = new.source_occurrence_revision
     and occurrence_row.resolution_state = 'resolved'
     and occurrence_row.resolved_external_message_reference_id =
        new.external_message_reference_id
    join public.inbox_v2_source_occurrence_resolution_transitions transition_row
      on transition_row.tenant_id = occurrence_row.tenant_id
     and transition_row.source_occurrence_id = occurrence_row.id
     and transition_row.resulting_revision = occurrence_row.revision
     and transition_row.to_state = 'resolved'
     and transition_row.resolved_external_message_reference_id =
        occurrence_row.resolved_external_message_reference_id
    join public.inbox_v2_external_message_references reference_row
      on reference_row.tenant_id = occurrence_row.tenant_id
     and reference_row.id = occurrence_row.resolved_external_message_reference_id
     and reference_row.external_thread_id = route_row.external_thread_id
     and reference_row.message_id = artifact_row.message_id
   where artifact_row.tenant_id = new.tenant_id
     and artifact_row.id = new.artifact_id
     and artifact_row.dispatch_id = new.dispatch_id
     and artifact_row.route_id = new.route_id
     and artifact_row.attempt_id = new.attempt_id
     and artifact_row.message_id = new.message_id
     and artifact_row.state = 'accepted'
     and route_row.external_thread_id = new.external_thread_id
     and route_row.source_thread_binding_id = occurrence_row.source_thread_binding_id
     and route_row.source_connection_id = occurrence_row.source_connection_id
     and route_row.source_account_id = occurrence_row.source_account_id
     and route_row.adapter_contract_id = occurrence_row.adapter_contract_id
     and route_row.adapter_contract_version = occurrence_row.adapter_contract_version
     and route_row.adapter_surface_id = occurrence_row.adapter_surface_id
     and transition_row.resolver_trusted_service_id =
        new.linked_by_trusted_service_id
     and artifact_row.created_at >= attempt_row.opened_at
     and new.linked_at >= artifact_row.created_at
     and new.linked_at >= occurrence_row.updated_at
     and new.linked_at >= reference_row.created_at
     and (
       (
         new.evidence_kind = 'provider_response_attempt'
         and occurrence_row.origin_kind = 'provider_response'
         and occurrence_row.outbound_dispatch_attempt_id = attempt_row.id
       ) or (
         new.evidence_kind = 'provider_echo_correlation'
         and occurrence_row.origin_kind = 'provider_echo'
         and attempt_row.provider_correlation_token = new.correlation_token
         and exists (
           select 1
             from public.inbox_v2_source_occurrence_provider_references provider_reference_row
            where provider_reference_row.tenant_id = occurrence_row.tenant_id
              and provider_reference_row.source_occurrence_id = occurrence_row.id
              and provider_reference_row.kind_id = new.provider_reference_kind_id
              and provider_reference_row.subject = new.correlation_token
         )
       )
     )
   for share of artifact_row, attempt_row, route_row, occurrence_row,
     transition_row, reference_row;

  if not found then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_artifact_reference_link_invalid';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_artifact_retry_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_artifact_retry_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.result_state = 'retryable_failure' then
    if pg_catalog.current_setting('transaction_isolation') <> 'read committed' then
      raise exception using errcode = '25001',
        message = 'inbox_v2.outbound_artifact_retry_isolation_unsafe';
    end if;

    -- Both sides of the invariant lock the same durable attempt row before
    -- their cross-table check. The post-lock READ COMMITTED statement then
    -- sees the winner and rejects the loser instead of allowing a write skew.
    perform 1
      from public.inbox_v2_outbound_dispatch_attempts attempt_row
     where attempt_row.tenant_id = new.tenant_id
       and attempt_row.id = new.unknown_attempt_id
       and attempt_row.dispatch_id = new.dispatch_id
       and attempt_row.route_id = new.route_id
       and attempt_row.message_id = new.message_id
       for update;

    if exists (
      select 1
        from public.inbox_v2_outbound_dispatch_artifacts artifact_row
       where artifact_row.tenant_id = new.tenant_id
         and artifact_row.dispatch_id = new.dispatch_id
         and artifact_row.attempt_id = new.unknown_attempt_id
         and artifact_row.state = 'accepted'
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_artifact_retry_unsafe';
    end if;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_attempt_guard_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_attempt_guard_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.outcome_kind <> 'pending' or new.revision <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_attempt_initial_state_invalid';
  end if;

  perform 1
    from public.inbox_v2_outbound_dispatches dispatch_row
    join public.inbox_v2_outbound_routes route_row
      on route_row.tenant_id = dispatch_row.tenant_id
     and route_row.id = dispatch_row.route_id
    join public.inbox_v2_source_thread_binding_heads binding_row
      on binding_row.tenant_id = route_row.tenant_id
     and binding_row.binding_id = route_row.source_thread_binding_id
     and binding_row.account_generation = route_row.account_generation
     and binding_row.binding_generation = route_row.binding_generation
     and binding_row.remote_access_revision = route_row.remote_access_revision
     and binding_row.administrative_revision = route_row.administrative_revision
     and binding_row.capability_revision = route_row.capability_revision
     and binding_row.route_descriptor_revision = route_row.route_descriptor_revision
   where dispatch_row.tenant_id = new.tenant_id
     and dispatch_row.id = new.dispatch_id
     and dispatch_row.route_id = new.route_id
     and dispatch_row.message_id = new.message_id
     and route_row.id = new.route_id
     and dispatch_row.state in ('queued', 'retryable_failure')
     and ((new.attempt_number = 1 and dispatch_row.state = 'queued')
       or (new.attempt_number > 1 and
         dispatch_row.state = 'retryable_failure'))
     and dispatch_row.active_attempt_id is null
     and new.attempt_number = dispatch_row.attempt_count + 1
     and dispatch_row.updated_at <= new.opened_at
     and binding_row.remote_access_state = 'active'
     and binding_row.administrative_state = 'enabled'
     and binding_row.updated_at <= new.opened_at
     and route_row.adapter_contract_snapshot =
        new.retry_safety_adapter_contract_snapshot
     and route_row.adapter_loaded_by_trusted_service_id =
        new.retry_safety_declared_by_trusted_service_id
   for update of dispatch_row
   for share of route_row, binding_row;

  if not found then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.outbound_attempt_route_binding_changed';
  end if;

  if new.attempt_number > 1 then
    perform 1
      from public.inbox_v2_outbound_dispatch_attempts previous_attempt
      join public.inbox_v2_outbound_dispatches dispatch_row
        on dispatch_row.tenant_id = previous_attempt.tenant_id
       and dispatch_row.id = previous_attempt.dispatch_id
       and dispatch_row.route_id = previous_attempt.route_id
       and dispatch_row.message_id = previous_attempt.message_id
     where previous_attempt.tenant_id = new.tenant_id
       and previous_attempt.dispatch_id = new.dispatch_id
       and previous_attempt.route_id = new.route_id
       and previous_attempt.message_id = new.message_id
       and previous_attempt.attempt_number = new.attempt_number - 1
       and (
         (
           previous_attempt.outcome_kind = 'retryable_failure'
           and previous_attempt.retry_at <= new.opened_at
           and dispatch_row.retry_authorization_decision_id is null
         ) or (
           previous_attempt.outcome_kind = 'outcome_unknown'
           and exists (
             select 1
               from public.inbox_v2_outbound_dispatch_reconciliation_decisions
                 decision_row
              where decision_row.tenant_id = previous_attempt.tenant_id
                and decision_row.id =
                   dispatch_row.retry_authorization_decision_id
                and decision_row.unknown_attempt_id = previous_attempt.id
                and decision_row.result_state = 'retryable_failure'
                and decision_row.retry_at <= new.opened_at
                and decision_row.decided_at <= new.opened_at
           )
         )
       )
     for share of previous_attempt;

    if not found then
      raise exception using errcode = '40001',
        message = 'inbox_v2.outbound_attempt_retry_boundary_conflict';
    end if;
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_attempt_guard_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_attempt_guard_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if old.outcome_kind <> 'pending'
     or to_jsonb(old) - array[
       'outcome_kind', 'completion_source', 'completed_at', 'retry_at',
       'provider_acknowledgement_token', 'diagnostic_code_id',
       'diagnostic_retryable', 'diagnostic_correlation_token',
       'diagnostic_safe_operator_hint_id', 'unknown_required_action', 'revision'
     ] <> to_jsonb(new) - array[
       'outcome_kind', 'completion_source', 'completed_at', 'retry_at',
       'provider_acknowledgement_token', 'diagnostic_code_id',
       'diagnostic_retryable', 'diagnostic_correlation_token',
       'diagnostic_safe_operator_hint_id', 'unknown_required_action', 'revision'
     ]
     or new.outcome_kind = 'pending'
     or new.revision <> 2 then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.outbound_attempt_completion_cas_conflict';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_attempt_mixed_outcome_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_attempt_mixed_outcome_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.outcome_kind = 'outcome_unknown'
     and new.diagnostic_code_id = 'core:provider-artifact-outcomes-mixed'
     and new.unknown_required_action is distinct from
       'operator_duplicate_risk_decision_required' then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_mixed_artifact_outcome_requires_operator';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_dispatch_deferred_head(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_dispatch_deferred_head() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
begin
  if tg_table_name = 'inbox_v2_outbound_dispatch_attempts'
     and tg_op = 'INSERT'
     and exists (
       select 1 from public.tenants tenant_row
        where tenant_row.id = new_row->>'tenant_id'
     )
     and not exists (
       select 1
         from public.inbox_v2_outbound_dispatch_attempts attempt_row
        where attempt_row.tenant_id = new_row->>'tenant_id'
          and attempt_row.id = new_row->>'id'
          and attempt_row.outcome_kind = 'pending'
          and attempt_row.revision = 1
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_attempt_pre_io_commit_required';
  end if;

  if tg_op <> 'INSERT' then
    perform public.inbox_v2_assert_outbound_dispatch_head(
      old_row->>'tenant_id',
      case when tg_table_name = 'inbox_v2_outbound_dispatches'
        then old_row->>'id' else old_row->>'dispatch_id' end
    );
  end if;
  if tg_op <> 'DELETE' then
    perform public.inbox_v2_assert_outbound_dispatch_head(
      new_row->>'tenant_id',
      case when tg_table_name = 'inbox_v2_outbound_dispatches'
        then new_row->>'id' else new_row->>'dispatch_id' end
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_outbound_dispatch_guard_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_dispatch_guard_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.state <> 'queued'
     or new.attempt_count <> 0
     or new.active_attempt_id is not null
     or new.last_attempt_id is not null
     or new.retry_authorization_decision_id is not null
     or new.revision <> 1
     or new.created_at <> new.updated_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_dispatch_initial_state_invalid';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_dispatch_guard_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_dispatch_guard_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if to_jsonb(old) - array[
       'state', 'attempt_count', 'active_attempt_id', 'last_attempt_id',
       'retry_authorization_decision_id', 'revision', 'updated_at'
     ] <> to_jsonb(new) - array[
       'state', 'attempt_count', 'active_attempt_id', 'last_attempt_id',
       'retry_authorization_decision_id', 'revision', 'updated_at'
     ]
     or new.revision <> old.revision + 1
     or new.attempt_count < old.attempt_count
     or new.updated_at < old.updated_at
     or old.state in ('accepted', 'terminal_failure', 'cancelled')
     or not (
       (old.state = 'queued' and
         new.state in ('attempting', 'cancelled', 'terminal_failure'))
       or (old.state = 'retryable_failure' and
         new.state in ('attempting', 'cancelled', 'terminal_failure'))
       or (old.state = 'attempting' and new.state in (
         'accepted', 'retryable_failure', 'terminal_failure',
         'outcome_unknown'
       ))
       or (old.state = 'outcome_unknown' and new.state in (
         'accepted', 'retryable_failure', 'terminal_failure'
       ))
     ) then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.outbound_dispatch_cas_conflict';
  end if;

  if old.state in ('queued', 'retryable_failure')
     and new.state = 'terminal_failure' then
    if new.attempt_count <> old.attempt_count
       or new.last_attempt_id is distinct from old.last_attempt_id
       or new.active_attempt_id is not null
       or new.retry_authorization_decision_id is not null then
      raise exception using errcode = '40001',
        message = 'inbox_v2.outbound_dispatch_route_failure_cas_conflict';
    end if;

    perform 1
      from public.inbox_v2_outbound_routes route_row
      join public.inbox_v2_source_thread_binding_heads binding_row
        on binding_row.tenant_id = route_row.tenant_id
       and binding_row.binding_id = route_row.source_thread_binding_id
     where route_row.tenant_id = new.tenant_id
       and route_row.id = new.route_id
       and binding_row.updated_at <= new.updated_at
       and (
         binding_row.remote_access_state <> 'active'
         or binding_row.administrative_state <> 'enabled'
         or binding_row.account_generation <> route_row.account_generation
         or binding_row.binding_generation <> route_row.binding_generation
         or binding_row.remote_access_revision <>
            route_row.remote_access_revision
         or binding_row.administrative_revision <>
            route_row.administrative_revision
         or binding_row.capability_revision <> route_row.capability_revision
         or binding_row.route_descriptor_revision <>
            route_row.route_descriptor_revision
       )
     for share of route_row, binding_row;

    if not found then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_dispatch_route_failure_unproven';
    end if;
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_outbound_multi_send_deferred_children(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_multi_send_deferred_children() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
begin
  if tg_op <> 'INSERT' then
    perform public.inbox_v2_assert_outbound_multi_send_children(
      old_row->>'tenant_id', coalesce(
        old_row->>'multi_send_operation_id',
        old_row->>'id',
        old_row->>'operation_id'
      )
    );
  end if;
  if tg_op <> 'DELETE' then
    perform public.inbox_v2_assert_outbound_multi_send_children(
      new_row->>'tenant_id', coalesce(
        new_row->>'multi_send_operation_id',
        new_row->>'id',
        new_row->>'operation_id'
      )
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_outbound_reconciliation_deferred(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_reconciliation_deferred() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
begin
  if tg_op <> 'INSERT' then
    perform public.inbox_v2_assert_outbound_reconciliation(
      old_row->>'tenant_id', coalesce(old_row->>'id', old_row->>'decision_id')
    );
  end if;
  if tg_op <> 'DELETE' then
    perform public.inbox_v2_assert_outbound_reconciliation(
      new_row->>'tenant_id', coalesce(new_row->>'id', new_row->>'decision_id')
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_outbound_route_guard_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_route_guard_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
begin
  perform 1
    from public.inbox_v2_source_thread_binding_snapshots snapshot_row
    join public.inbox_v2_source_thread_binding_heads head_row
      on head_row.tenant_id = snapshot_row.tenant_id
     and head_row.binding_id = snapshot_row.binding_id
     and head_row.revision = snapshot_row.revision
     and head_row.external_thread_id = snapshot_row.external_thread_id
     and head_row.source_connection_id = snapshot_row.source_connection_id
     and head_row.source_account_id = snapshot_row.source_account_id
     and head_row.account_generation = snapshot_row.account_generation
     and head_row.binding_generation = snapshot_row.binding_generation
     and head_row.remote_access_revision = snapshot_row.remote_access_revision
     and head_row.administrative_revision = snapshot_row.administrative_revision
     and head_row.capability_revision = snapshot_row.capability_revision
     and head_row.route_descriptor_revision = snapshot_row.route_descriptor_revision
   where snapshot_row.tenant_id = new.tenant_id
     and snapshot_row.binding_id = new.source_thread_binding_id
     and snapshot_row.revision = new.binding_revision
     and snapshot_row.external_thread_id = new.external_thread_id
     and snapshot_row.source_connection_id = new.source_connection_id
     and snapshot_row.source_account_id = new.source_account_id
     and snapshot_row.account_generation = new.account_generation
     and snapshot_row.binding_generation = new.binding_generation
     and snapshot_row.remote_access_revision = new.remote_access_revision
     and snapshot_row.administrative_revision = new.administrative_revision
     and snapshot_row.capability_revision = new.capability_revision
     and snapshot_row.route_descriptor_revision = new.route_descriptor_revision
     and snapshot_row.remote_access_state = 'active'
     and snapshot_row.administrative_state = 'enabled'
     and snapshot_row.route_contract_id = new.adapter_contract_id
     and snapshot_row.route_contract_version = new.adapter_contract_version
     and snapshot_row.route_declaration_revision =
        new.adapter_declaration_revision
     and snapshot_row.route_surface_id = new.adapter_surface_id
     and snapshot_row.route_loaded_by_trusted_service_id =
        new.adapter_loaded_by_trusted_service_id
     and snapshot_row.route_loaded_at = new.adapter_loaded_at
     and row(
       head_row.runtime_health_state,
       head_row.runtime_health_revision,
       head_row.runtime_health_checked_at,
       head_row.runtime_diagnostic_code_id,
       head_row.runtime_diagnostic_retryable,
       head_row.runtime_diagnostic_correlation_token,
       head_row.runtime_diagnostic_safe_operator_hint_id
     ) is not distinct from row(
       snapshot_row.runtime_health_state,
       snapshot_row.runtime_health_revision,
       snapshot_row.runtime_health_checked_at,
       snapshot_row.runtime_diagnostic_code_id,
       snapshot_row.runtime_diagnostic_retryable,
       snapshot_row.runtime_diagnostic_correlation_token,
       snapshot_row.runtime_diagnostic_safe_operator_hint_id
     )
     and new.runtime_observation_snapshot #>> '{state}' =
        snapshot_row.runtime_health_state::text
     and new.runtime_observation_snapshot #>> '{revision}' =
        snapshot_row.runtime_health_revision::text
     and (new.runtime_observation_snapshot #>> '{observedAt}')::timestamptz =
        snapshot_row.runtime_health_checked_at
     and (
       (
         snapshot_row.runtime_diagnostic_code_id is null
         and snapshot_row.runtime_diagnostic_retryable is null
         and snapshot_row.runtime_diagnostic_correlation_token is null
         and snapshot_row.runtime_diagnostic_safe_operator_hint_id is null
         and new.runtime_observation_snapshot #> '{diagnostic}' = 'null'::jsonb
       )
       or (
         snapshot_row.runtime_diagnostic_code_id =
           new.runtime_observation_snapshot #>> '{diagnostic,codeId}'
         and snapshot_row.runtime_diagnostic_retryable =
           (new.runtime_observation_snapshot #>>
             '{diagnostic,retryable}')::boolean
         and snapshot_row.runtime_diagnostic_correlation_token =
           new.runtime_observation_snapshot #>>
             '{diagnostic,correlationToken}'
         and snapshot_row.runtime_diagnostic_safe_operator_hint_id is not
           distinct from new.runtime_observation_snapshot #>>
             '{diagnostic,safeOperatorHintId}'
       )
     )
     and snapshot_row.route_descriptor_schema_id =
        new.route_descriptor_snapshot #>> '{descriptorSchemaId}'
     and snapshot_row.route_descriptor_version =
        new.route_descriptor_snapshot #>> '{descriptorVersion}'
     and snapshot_row.route_descriptor_revision::text =
        new.route_descriptor_snapshot #>> '{descriptorRevision}'
     and snapshot_row.route_destination_kind_id =
        new.route_descriptor_snapshot #>> '{destinationKindId}'
     and snapshot_row.route_destination_subject =
        new.route_descriptor_snapshot #>> '{destinationSubject}'
     and snapshot_row.route_descriptor_digest_sha256 =
        new.route_descriptor_digest_sha256
     and jsonb_typeof(new.route_descriptor_snapshot #> '{attributes}') = 'array'
     and jsonb_array_length(new.route_descriptor_snapshot #> '{attributes}') =
        snapshot_row.route_attribute_count
     and not exists (
       select 1
         from jsonb_array_elements(
           new.route_descriptor_snapshot #> '{attributes}'
         ) with ordinality as supplied_attribute(value, ordinal)
         left join public.inbox_v2_source_thread_binding_route_attributes
           stored_attribute
           on stored_attribute.tenant_id = snapshot_row.tenant_id
          and stored_attribute.binding_id = snapshot_row.binding_id
          and stored_attribute.route_descriptor_revision =
             snapshot_row.route_descriptor_revision
          and stored_attribute.ordinal = supplied_attribute.ordinal - 1
        where stored_attribute.ordinal is null
           or supplied_attribute.value is distinct from jsonb_build_object(
             'attributeId', stored_attribute.attribute_id,
             'value', stored_attribute.value
           )
     )
     and snapshot_row.updated_at <= new.created_at
   for share of snapshot_row, head_row;

  if not found then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.outbound_route_binding_fence_conflict';
  end if;

  perform 1
    from public.inbox_v2_thread_route_policy_versions policy_row
    join public.inbox_v2_thread_route_policy_heads policy_head
      on policy_head.tenant_id = policy_row.tenant_id
     and policy_head.policy_id = policy_row.policy_id
     and policy_head.revision = policy_row.revision
     and policy_head.conversation_id = policy_row.conversation_id
     and policy_head.external_thread_id = policy_row.external_thread_id
     and policy_head.operation_id = policy_row.operation_id
     and policy_head.content_kind_id is not distinct from policy_row.content_kind_id
   where policy_row.tenant_id = new.tenant_id
     and policy_row.policy_id = new.route_policy_id
     and policy_row.revision = new.route_policy_revision
     and policy_row.conversation_id = new.conversation_id
     and policy_row.external_thread_id = new.external_thread_id
     and policy_row.operation_id = new.operation_id
     and policy_row.content_kind_id is not distinct from new.content_kind_id
     and policy_row.required_conversation_permission_id =
        new.required_conversation_permission_id
     and policy_row.updated_at <= new.created_at
     and (
       new.selection_reason <> 'preferred_binding'
       or policy_row.preferred_binding_id = new.source_thread_binding_id
     )
     and (
       new.selection_reason <> 'policy_fallback'
       or exists (
         select 1
           from public.inbox_v2_thread_route_policy_fallback_bindings fallback_row
          where fallback_row.tenant_id = new.tenant_id
            and fallback_row.policy_id = new.route_policy_id
            and fallback_row.policy_revision = new.route_policy_revision
            and fallback_row.ordinal = new.fallback_policy_ordinal
            and fallback_row.external_thread_id = new.external_thread_id
            and fallback_row.binding_id = new.source_thread_binding_id
            and fallback_row.source_connection_id = new.source_connection_id
            and fallback_row.source_account_id = new.source_account_id
       )
     )
   for share of policy_row, policy_head;

  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.outbound_route_policy_mismatch';
  end if;

  if new.selection_intent_kind = 'explicit_occurrence' and not exists (
    select 1
      from public.inbox_v2_source_occurrences occurrence_row
     where occurrence_row.tenant_id = new.tenant_id
       and occurrence_row.id =
          new.selection_intent_snapshot #>> '{occurrence,id}'
       and occurrence_row.conversation_id = new.conversation_id
       and occurrence_row.external_thread_id = new.external_thread_id
       and occurrence_row.source_thread_binding_id =
          new.source_thread_binding_id
       and occurrence_row.source_connection_id = new.source_connection_id
       and occurrence_row.source_account_id = new.source_account_id
     for share
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_route_explicit_occurrence_mismatch';
  end if;

  if new.selection_intent_kind = 'explicit_reroute' and not exists (
    select 1
      from public.inbox_v2_outbound_routes original_route
     where original_route.tenant_id = new.tenant_id
       and original_route.id =
          new.selection_intent_snapshot #>> '{originalRoute,id}'
       and original_route.conversation_id = new.conversation_id
       and original_route.external_thread_id = new.external_thread_id
       and original_route.operation_id = new.operation_id
       and original_route.content_kind_id is not distinct from new.content_kind_id
       and original_route.created_at <= new.created_at
     for share
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_route_explicit_reroute_mismatch';
  end if;

  if new.reference_context_snapshot #>> '{kind}' = 'external_message'
     and not exists (
       select 1
         from public.inbox_v2_external_message_references reference_row
         join public.inbox_v2_source_occurrences occurrence_row
           on occurrence_row.tenant_id = reference_row.tenant_id
          and occurrence_row.id =
             new.reference_context_snapshot #>> '{sourceOccurrence,id}'
          and occurrence_row.external_thread_id = reference_row.external_thread_id
          and occurrence_row.resolution_state = 'resolved'
          and occurrence_row.resolved_external_message_reference_id =
             reference_row.id
         join public.inbox_v2_source_occurrence_resolution_transitions
           resolution_row
           on resolution_row.tenant_id = occurrence_row.tenant_id
          and resolution_row.source_occurrence_id = occurrence_row.id
          and resolution_row.resulting_revision = occurrence_row.revision
          and resolution_row.to_state = 'resolved'
          and resolution_row.resolved_external_message_reference_id =
             reference_row.id
        where reference_row.tenant_id = new.tenant_id
          and reference_row.id =
             new.reference_context_snapshot #>> '{externalMessageReference,id}'
          and reference_row.external_thread_id = new.external_thread_id
          and occurrence_row.source_thread_binding_id =
             new.reference_context_snapshot #>> '{originBinding,id}'
          and occurrence_row.source_account_id =
             new.reference_context_snapshot #>> '{originSourceAccount,id}'
          and occurrence_row.revision =
             (new.reference_context_snapshot #>>
               '{resolutionDecision,occurrenceRevision}')::bigint
          and occurrence_row.binding_generation =
             (new.reference_context_snapshot #>>
               '{resolutionDecision,occurrenceBindingGeneration}')::bigint
          and new.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,descriptorSchemaId}' =
             occurrence_row.descriptor_schema_id
          and new.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,descriptorVersion}' =
             occurrence_row.descriptor_version
          and new.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,capabilityRevision}' =
             occurrence_row.capability_revision::text
          and new.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,descriptorDigestSha256}' =
             occurrence_row.descriptor_digest_sha256
          and jsonb_array_length(new.reference_context_snapshot #>
             '{resolutionDecision,occurrenceDescriptor,providerReferences}') =
             occurrence_row.provider_reference_count
          and not exists (
            select 1
              from jsonb_array_elements(new.reference_context_snapshot #>
                '{resolutionDecision,occurrenceDescriptor,providerReferences}')
                with ordinality as supplied_reference(value, ordinal)
              left join public.inbox_v2_source_occurrence_provider_references
                stored_reference
                on stored_reference.tenant_id = occurrence_row.tenant_id
               and stored_reference.source_occurrence_id = occurrence_row.id
               and stored_reference.ordinal = supplied_reference.ordinal - 1
             where stored_reference.ordinal is null
                or supplied_reference.value is distinct from jsonb_build_object(
                  'kindId', stored_reference.kind_id,
                  'subject', stored_reference.subject
                )
          )
          and new.reference_context_snapshot #> '{portability}' =
             new.reference_context_snapshot #>
               '{resolutionDecision,portability}'
          and new.reference_context_snapshot #>>
             '{portability,adapterContract,contractId}' = new.adapter_contract_id
          and new.reference_context_snapshot #>>
             '{portability,adapterContract,contractVersion}' =
             new.adapter_contract_version
          and new.reference_context_snapshot #>>
             '{portability,adapterContract,declarationRevision}' =
             new.adapter_declaration_revision::text
          and new.reference_context_snapshot #>>
             '{portability,adapterContract,surfaceId}' = new.adapter_surface_id
          and new.reference_context_snapshot #>> '{portability,kind}' =
             occurrence_row.reference_portability_kind::text
          and new.reference_context_snapshot #>>
             '{portability,decisionStrength}' =
             occurrence_row.reference_portability_decision_strength::text
          and occurrence_row.adapter_contract_id = new.adapter_contract_id
          and occurrence_row.adapter_contract_version =
             new.adapter_contract_version
          and occurrence_row.adapter_declaration_revision =
             new.adapter_declaration_revision
          and occurrence_row.adapter_surface_id = new.adapter_surface_id
          and occurrence_row.adapter_loaded_by_trusted_service_id =
             new.adapter_loaded_by_trusted_service_id
          and occurrence_row.adapter_loaded_at = new.adapter_loaded_at
          and new.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,state}' = 'available'
          and new.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,tenantId}' =
             new.tenant_id
          and new.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,externalThread}' =
             new.reference_context_snapshot #> '{externalThread}'
          and new.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,externalMessageReference}' =
             new.reference_context_snapshot #> '{externalMessageReference}'
          and new.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,sourceOccurrence}' =
             new.reference_context_snapshot #> '{sourceOccurrence}'
          and new.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,occurrenceRevision}' =
             occurrence_row.revision::text
          and new.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,occurrenceDescriptorDigestSha256}' =
             occurrence_row.descriptor_digest_sha256
          and new.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,adapterContract}' =
             new.adapter_contract_snapshot
          and new.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,observedByTrustedServiceId}' =
             occurrence_row.adapter_loaded_by_trusted_service_id
          and new.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,diagnostic}' =
             'null'::jsonb
          and (new.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,observedAt}')::timestamptz
             <= new.selected_at
          and (new.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,notAfter}')::timestamptz
             >= new.selected_at
          and (
            new.reference_context_snapshot #>> '{portability,kind}' <>
              'binding_only'
            or (
              occurrence_row.source_thread_binding_id =
                new.source_thread_binding_id
              and occurrence_row.source_account_id = new.source_account_id
            )
          )
          and (
            new.selection_intent_kind <> 'explicit_occurrence'
            or new.selection_intent_snapshot #>> '{occurrence,id}' =
              occurrence_row.id
          )
          and new.reference_context_snapshot #>>
             '{resolutionDecision,externalThread,id}' =
             new.external_thread_id
          and new.reference_context_snapshot #>>
             '{resolutionDecision,externalMessageReference,id}' =
             reference_row.id
          and new.reference_context_snapshot #>>
             '{resolutionDecision,sourceOccurrence,id}' =
             occurrence_row.id
          and new.reference_context_snapshot #>>
             '{resolutionDecision,originBinding,id}' =
             occurrence_row.source_thread_binding_id
          and new.reference_context_snapshot #>>
             '{resolutionDecision,originSourceAccount,id}' =
             occurrence_row.source_account_id
          and new.reference_context_snapshot #>>
             '{resolutionDecision,loadedByTrustedServiceId}' =
             resolution_row.resolver_trusted_service_id
          and (new.reference_context_snapshot #>>
             '{resolutionDecision,decidedAt}')::timestamptz <= new.selected_at
          and (new.reference_context_snapshot #>>
             '{resolutionDecision,notAfter}')::timestamptz >= new.selected_at
          and new.reference_context_snapshot #>>
             '{resolutionDecision,referenceWindow,state}' <> 'expired'
          and (
            new.reference_context_snapshot #>>
              '{resolutionDecision,referenceWindow,state}' <> 'valid'
            or (new.reference_context_snapshot #>>
              '{resolutionDecision,referenceWindow,notAfter}')::timestamptz >=
              new.selected_at
          )
        for share of reference_row, occurrence_row, resolution_row
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_route_reference_context_mismatch';
  end if;

  if (select count(*) from jsonb_object_keys(
        new.conversation_authorization_snapshot
      )) <> 12
     or (select count(*) from jsonb_object_keys(
        new.source_account_authorization_snapshot
      )) <> 12
     or exists (
       select 1
         from (values
           (new.conversation_authorization_snapshot),
           (new.source_account_authorization_snapshot)
         ) as decision(snapshot)
         cross join lateral jsonb_array_elements(
           decision.snapshot #> '{matchedPermissionIds}'
         ) as permission(value)
        group by decision.snapshot
       having count(*) <> count(distinct permission.value)
          or bool_or(
            jsonb_typeof(permission.value) <> 'string'
            or char_length(permission.value #>> '{}') > 256
            or not (
              (
                permission.value #>> '{}' ~
                  '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'
                and char_length(split_part(
                  permission.value #>> '{}', ':', 2
                )) <= 160
              ) or (
                permission.value #>> '{}' ~
                  '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'
                and char_length(split_part(
                  permission.value #>> '{}', ':', 2
                )) <= 80
                and char_length(split_part(
                  permission.value #>> '{}', ':', 3
                )) <= 160
                and split_part(permission.value #>> '{}', ':', 2) not in (
                  'core', 'hulee', 'module', 'platform', 'system'
                )
              )
            )
          )
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbound_route_authorization_snapshot_invalid';
  end if;

  return new;
end;
$_$;



--
-- Name: inbox_v2_outbound_transport_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbound_transport_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
begin
  if tg_op = 'DELETE' and not exists (
    select 1 from public.tenants tenant_row
     where tenant_row.id = old_row->>'tenant_id'
  ) then
    return old;
  end if;

  raise exception using
    errcode = '23514',
    message = format('inbox_v2.outbound_transport_immutable:%s:%s', tg_table_name, tg_op);
end;
$$;



--
-- Name: inbox_v2_outbox_legacy_outcome_payload_bridge(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbox_legacy_outcome_payload_bridge() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_result_reference jsonb := new.result_reference;
begin
  if v_result_reference is null then
    return new;
  end if;
  if new.kind = 'retry'
     or not public.inbox_v2_auth_payload_reference_safe(
       v_result_reference, new.tenant_id
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbox_legacy_terminal_payload_invalid';
  end if;

  new.payload_reference_recorded := true;
  new.result_reference := null;
  insert into public.inbox_v2_outbox_terminal_payload_refs (
    tenant_id, intent_id, outcome_revision, result_reference, recorded_at
  ) values (
    new.tenant_id, new.intent_id, new.outcome_revision,
    v_result_reference, new.occurred_at
  );
  return new;
end;
$$;



--
-- Name: inbox_v2_outbox_legacy_work_payload_bridge(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbox_legacy_work_payload_bridge() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.terminal_result_reference is null then
    return new;
  end if;
  if new.state not in ('processed', 'dead')
     or not public.inbox_v2_auth_payload_reference_safe(
       new.terminal_result_reference, new.tenant_id
     )
     or not exists (
       select 1
         from public.inbox_v2_outbox_terminal_payload_refs payload_row
        where payload_row.tenant_id = new.tenant_id
          and payload_row.intent_id = new.intent_id
          and payload_row.outcome_revision = new.revision
          and payload_row.result_reference = new.terminal_result_reference
          and payload_row.recorded_at = new.terminal_finalized_at
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbox_legacy_terminal_payload_shadow_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_outbox_terminal_payload_ref_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbox_terminal_payload_ref_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_outcome public.inbox_v2_outbox_outcomes%rowtype;
begin

  select * into v_outcome
    from public.inbox_v2_outbox_outcomes outcome_row
   where outcome_row.tenant_id = new.tenant_id
     and outcome_row.intent_id = new.intent_id
     and outcome_row.outcome_revision = new.outcome_revision;

  if not found
     or v_outcome.kind = 'retry'
     or not v_outcome.payload_reference_recorded
     or v_outcome.occurred_at <> new.recorded_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbox_terminal_payload_reference_incoherent';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_outbox_terminal_payload_ref_delete(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbox_terminal_payload_ref_delete() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if not exists (
    select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
  ) then
    return old;
  end if;
  update public.inbox_v2_outbox_work_items work_row
     set terminal_result_reference = null
   where work_row.tenant_id = old.tenant_id
     and work_row.intent_id = old.intent_id
     and work_row.revision = old.outcome_revision
     and work_row.state in ('processed', 'dead')
     and work_row.terminal_result_reference = old.result_reference;

  if exists (
    select 1
      from public.inbox_v2_outbox_work_items work_row
     where work_row.tenant_id = old.tenant_id
       and work_row.intent_id = old.intent_id
       and work_row.revision = old.outcome_revision
       and work_row.terminal_result_reference is not null
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbox_terminal_payload_shadow_incoherent';
  end if;
  return old;
end;
$$;



--
-- Name: inbox_v2_outbox_terminal_payload_ref_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbox_terminal_payload_ref_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  raise exception using errcode = '23514',
    message = 'inbox_v2.outbox_terminal_payload_reference_immutable';
end;
$$;



--
-- Name: inbox_v2_outbox_terminal_payload_ref_insert_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_outbox_terminal_payload_ref_insert_guard() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if not exists (
    select 1
      from public.inbox_v2_outbox_work_items work_row
     where work_row.tenant_id = new.tenant_id
       and work_row.intent_id = new.intent_id
       and work_row.state = 'leased'
       and new.outcome_revision = work_row.revision + 1
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbox_terminal_payload_insert_not_finalizing';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_participant_membership_deferred_commit(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_deferred_commit() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_assert_conversation_membership_commit(
    new.tenant_id,
    new.conversation_id,
    new.resulting_membership_revision
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_participant_membership_deferred_conversation(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_deferred_conversation() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  checked_tenant_id text := coalesce(new.tenant_id, old.tenant_id);
  checked_conversation_id text := coalesce(new.id, old.id);
begin
  perform public.inbox_v2_assert_conversation_membership_head(
    checked_tenant_id,
    checked_conversation_id
  );
  perform public.inbox_v2_assert_conversation_membership_projection(
    checked_tenant_id,
    checked_conversation_id
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_participant_membership_deferred_employee(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_deferred_employee() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  current_internal_count integer;
begin
  if new.deactivated_at is null then
    return null;
  end if;
  select count(*)::integer
    into current_internal_count
    from public.inbox_v2_conversation_participants participant_row
    join public.inbox_v2_participant_membership_episodes episode_row
      on episode_row.tenant_id = participant_row.tenant_id
     and episode_row.participant_id = participant_row.id
     and episode_row.conversation_id = participant_row.conversation_id
   where participant_row.tenant_id = new.tenant_id
     and participant_row.subject_kind = 'employee'
     and participant_row.subject_employee_id = new.id
     and episode_row.origin_kind = 'hulee_internal_command'
     and episode_row.state in ('pending', 'active');
  if current_internal_count <> 0 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.employee_deactivation_has_internal_membership';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_participant_membership_deferred_episode(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_deferred_episode() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_assert_participant_membership_episode(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.id, old.id)
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_participant_membership_deferred_head(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_deferred_head() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_assert_conversation_membership_head(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.conversation_id, old.conversation_id)
  );
  perform public.inbox_v2_assert_conversation_membership_projection(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.conversation_id, old.conversation_id)
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_participant_membership_deferred_transition(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_deferred_transition() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_assert_conversation_membership_commit(
    new.tenant_id,
    new.conversation_id,
    new.membership_revision
  );
  perform public.inbox_v2_assert_participant_membership_episode(
    new.tenant_id,
    new.episode_id
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_participant_membership_guard_commit_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_guard_commit_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  current_head_revision bigint;
  predecessor_occurred_at timestamptz;
begin
  select head_row.membership_revision
    into current_head_revision
    from public.inbox_v2_conversation_membership_heads head_row
   where head_row.tenant_id = new.tenant_id
     and head_row.conversation_id = new.conversation_id
   for update;

  if not found or current_head_revision <> new.expected_membership_revision then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.conversation_membership_revision_conflict';
  end if;

  if new.expected_membership_revision > 0 then
    select commit_row.occurred_at
      into predecessor_occurred_at
      from public.inbox_v2_conversation_membership_commits commit_row
     where commit_row.tenant_id = new.tenant_id
       and commit_row.conversation_id = new.conversation_id
       and commit_row.resulting_membership_revision =
         new.expected_membership_revision;
    if not found or new.occurred_at < predecessor_occurred_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.conversation_membership_commit_time_invalid';
    end if;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_participant_membership_guard_conversation_transport(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_guard_conversation_transport() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.transport is distinct from old.transport then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_transport_immutable';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_participant_membership_guard_episode_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_guard_episode_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  latest_state public.inbox_v2_participant_membership_state;
  latest_boundary timestamptz;
  provider_shape_count integer;
  provider_ordering_head public.inbox_v2_provider_membership_ordering_heads%rowtype;
  provider_ordering_head_found boolean := false;
begin
  perform 1
    from public.inbox_v2_conversation_participants participant_row
   where participant_row.tenant_id = new.tenant_id
     and participant_row.id = new.participant_id
     and participant_row.conversation_id = new.conversation_id
   for update;
  if not found then
    raise exception using
      errcode = '23503',
      message = 'inbox_v2.membership_episode_participant_missing';
  end if;

  if new.origin_kind = 'provider_roster' then
    select count(*)::integer
      into provider_shape_count
      from public.inbox_v2_provider_roster_member_evidence member_row
      join public.inbox_v2_provider_roster_evidence roster_row
        on roster_row.tenant_id = member_row.tenant_id
       and roster_row.id = member_row.roster_evidence_id
       and roster_row.source_thread_binding_id = member_row.source_thread_binding_id
      join public.inbox_v2_source_thread_bindings binding_row
        on binding_row.tenant_id = roster_row.tenant_id
       and binding_row.id = roster_row.source_thread_binding_id
      join public.inbox_v2_external_threads thread_row
        on thread_row.tenant_id = binding_row.tenant_id
       and thread_row.id = binding_row.external_thread_id
      join public.inbox_v2_source_external_identities identity_row
        on identity_row.tenant_id = member_row.tenant_id
       and identity_row.id = member_row.source_external_identity_id
      join public.inbox_v2_conversation_participants participant_row
        on participant_row.tenant_id = member_row.tenant_id
       and participant_row.id = new.participant_id
       and participant_row.conversation_id = new.conversation_id
     where member_row.tenant_id = new.tenant_id
       and member_row.id = new.origin_provider_roster_member_evidence_id
       and member_row.roster_evidence_id = new.origin_provider_roster_evidence_id
       and member_row.source_thread_binding_id = new.origin_source_thread_binding_id
       and member_row.source_external_identity_id = new.origin_source_external_identity_id
       and participant_row.subject_kind = 'source_external_identity'
       and participant_row.subject_source_external_identity_id =
         member_row.source_external_identity_id
       and thread_row.conversation_id = new.conversation_id
       and member_row.state = 'present'
       and roster_row.authority = 'authoritative'
       and new.state = 'active'
       and new.role::text = member_row.normalized_role::text
       and new.valid_from = member_row.observed_at
       and new.valid_to is null
       and new.evidence_classification = 'confirmed'
       and new.origin_ordering_kind = roster_row.ordering_kind
       and new.origin_ordering_scope_token = roster_row.ordering_scope_token
       and new.origin_ordering_comparator_id = roster_row.ordering_comparator_id
       and new.origin_ordering_comparator_revision =
         roster_row.ordering_comparator_revision
       and new.origin_ordering_position = roster_row.ordering_position
       and new.provider_ordering_head_position = roster_row.ordering_position
       and (
         (
           identity_row.scope_kind = 'provider'
           and identity_row.declaration_contract_id = roster_row.adapter_contract_id
           and identity_row.declaration_contract_version =
             roster_row.adapter_contract_version
           and identity_row.declaration_surface_id = roster_row.adapter_surface_id
           and identity_row.declaration_loaded_by_trusted_service_id =
             roster_row.adapter_loaded_by_trusted_service_id
         ) or (
           identity_row.scope_kind = 'source_connection'
           and identity_row.scope_source_connection_id =
             binding_row.source_connection_id
         ) or (
           identity_row.scope_kind = 'source_account'
           and identity_row.scope_source_account_id = binding_row.source_account_id
         )
       );

    if provider_shape_count <> 1 then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.provider_membership_origin_invalid';
    end if;

    select *
      into provider_ordering_head
      from public.inbox_v2_provider_membership_ordering_heads head_row
     where head_row.tenant_id = new.tenant_id
       and head_row.participant_id = new.participant_id
       and head_row.source_thread_binding_id =
         new.origin_source_thread_binding_id
     for update;
    provider_ordering_head_found := found;

    if provider_ordering_head_found and row(
         provider_ordering_head.conversation_id,
         provider_ordering_head.source_external_identity_id,
         provider_ordering_head.ordering_kind,
         provider_ordering_head.ordering_scope_token,
         provider_ordering_head.ordering_comparator_id,
         provider_ordering_head.ordering_comparator_revision
       ) is distinct from row(
         new.conversation_id,
         new.origin_source_external_identity_id,
         new.origin_ordering_kind,
         new.origin_ordering_scope_token,
         new.origin_ordering_comparator_id,
         new.origin_ordering_comparator_revision
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.provider_membership_ordering_scope_invalid';
    end if;

    if provider_ordering_head_found
       and new.origin_ordering_position <=
         provider_ordering_head.ordering_position then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.provider_membership_ordering_stale';
    end if;
  end if;

  select episode_row.state,
         coalesce(episode_row.valid_to, episode_row.valid_from)
    into latest_state, latest_boundary
    from public.inbox_v2_participant_membership_episodes episode_row
   where episode_row.tenant_id = new.tenant_id
     and episode_row.participant_id = new.participant_id
      and episode_row.origin_kind = new.origin_kind
      and episode_row.origin_source_thread_binding_id is not distinct from
        new.origin_source_thread_binding_id
     and episode_row.origin_migration_provenance_id is not distinct from
       new.origin_migration_provenance_id
     and episode_row.origin_system_policy_id is not distinct from
       new.origin_system_policy_id
   order by episode_row.valid_from desc, episode_row.id desc
   limit 1;

  if found and (
       latest_state in ('pending', 'active')
       or new.valid_from < latest_boundary
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.membership_episode_history_overlap';
  end if;

  perform public.inbox_v2_assert_current_internal_membership_authority(
    new.tenant_id,
    new.participant_id,
    new.conversation_id,
    new.origin_kind,
    new.state
  );
  return new;
end;
$$;



--
-- Name: inbox_v2_participant_membership_guard_episode_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_guard_episode_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.participant_id is distinct from old.participant_id
     or new.conversation_id is distinct from old.conversation_id
     or new.origin_kind is distinct from old.origin_kind
     or new.origin_provider_roster_member_evidence_id is distinct from
       old.origin_provider_roster_member_evidence_id
     or new.origin_provider_roster_evidence_id is distinct from
       old.origin_provider_roster_evidence_id
     or new.origin_source_thread_binding_id is distinct from
       old.origin_source_thread_binding_id
     or new.origin_source_external_identity_id is distinct from
       old.origin_source_external_identity_id
     or new.origin_ordering_kind is distinct from old.origin_ordering_kind
     or new.origin_ordering_scope_token is distinct from
       old.origin_ordering_scope_token
     or new.origin_ordering_comparator_id is distinct from
       old.origin_ordering_comparator_id
     or new.origin_ordering_comparator_revision is distinct from
       old.origin_ordering_comparator_revision
     or new.origin_ordering_position is distinct from old.origin_ordering_position
     or new.origin_migration_provenance_id is distinct from old.origin_migration_provenance_id
     or new.origin_system_policy_id is distinct from old.origin_system_policy_id
     or new.valid_from is distinct from old.valid_from
     or new.evidence_classification is distinct from old.evidence_classification
     or new.revision <> old.revision + 1
     or (
       old.origin_kind = 'provider_roster'
       and (
         new.provider_ordering_head_position is null
         or new.provider_ordering_head_position <= old.provider_ordering_head_position
       )
     )
     or (
       old.origin_kind <> 'provider_roster'
       and new.provider_ordering_head_position is distinct from
         old.provider_ordering_head_position
     )
     or old.state in ('left', 'removed') then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.participant_membership_episode_stable_fields_invalid';
  end if;
  perform public.inbox_v2_assert_current_internal_membership_authority(
    new.tenant_id,
    new.participant_id,
    new.conversation_id,
    new.origin_kind,
    new.state
  );
  return new;
end;
$$;



--
-- Name: inbox_v2_participant_membership_guard_head_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_guard_head_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.tenant_id is distinct from old.tenant_id
     or new.conversation_id is distinct from old.conversation_id
     or new.created_at is distinct from old.created_at
     or new.membership_revision <> old.membership_revision + 1
     or new.updated_at < old.updated_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.conversation_membership_head_invalid_advance';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_participant_membership_guard_transition_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_participant_membership_guard_transition_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  commit_expected_revision bigint;
  current_head_revision bigint;
  predecessor_occurred_at timestamptz;
  episode_origin_kind public.inbox_v2_participant_membership_origin_kind;
  episode_origin_provider_member_id text;
  episode_origin_provider_roster_id text;
  episode_origin_binding_id text;
  episode_origin_identity_id text;
  episode_origin_ordering_kind text;
  episode_origin_ordering_scope_token text;
  episode_origin_ordering_comparator_id text;
  episode_origin_ordering_comparator_revision bigint;
  episode_origin_ordering_position bigint;
  episode_provider_ordering_head_position bigint;
  episode_migration_provenance_id text;
  episode_system_policy_id text;
  provider_shape_count integer;
begin
  select commit_row.expected_membership_revision
    into commit_expected_revision
    from public.inbox_v2_conversation_membership_commits commit_row
   where commit_row.tenant_id = new.tenant_id
     and commit_row.conversation_id = new.conversation_id
     and commit_row.resulting_membership_revision = new.membership_revision;

  select head_row.membership_revision
    into current_head_revision
    from public.inbox_v2_conversation_membership_heads head_row
   where head_row.tenant_id = new.tenant_id
     and head_row.conversation_id = new.conversation_id;

  if commit_expected_revision is null
     or current_head_revision is null
     or current_head_revision <> commit_expected_revision then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.membership_transition_commit_not_open';
  end if;

  select episode_row.origin_kind,
         episode_row.origin_provider_roster_member_evidence_id,
         episode_row.origin_provider_roster_evidence_id,
         episode_row.origin_source_thread_binding_id,
         episode_row.origin_source_external_identity_id,
         episode_row.origin_ordering_kind,
         episode_row.origin_ordering_scope_token,
         episode_row.origin_ordering_comparator_id,
         episode_row.origin_ordering_comparator_revision,
         episode_row.origin_ordering_position,
         episode_row.provider_ordering_head_position,
         episode_row.origin_migration_provenance_id,
         episode_row.origin_system_policy_id
    into episode_origin_kind,
         episode_origin_provider_member_id,
         episode_origin_provider_roster_id,
         episode_origin_binding_id,
         episode_origin_identity_id,
         episode_origin_ordering_kind,
         episode_origin_ordering_scope_token,
         episode_origin_ordering_comparator_id,
         episode_origin_ordering_comparator_revision,
         episode_origin_ordering_position,
         episode_provider_ordering_head_position,
         episode_migration_provenance_id,
         episode_system_policy_id
    from public.inbox_v2_participant_membership_episodes episode_row
   where episode_row.tenant_id = new.tenant_id
     and episode_row.id = new.episode_id
     and episode_row.participant_id = new.participant_id
     and episode_row.conversation_id = new.conversation_id;
  if not found
     or episode_origin_kind is distinct from new.cause_kind
     or episode_migration_provenance_id is distinct from
       new.cause_migration_provenance_id
     or episode_system_policy_id is distinct from new.cause_system_policy_id then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.membership_transition_origin_evidence_mismatch';
  end if;

  if new.cause_kind = 'provider_roster' then
    if new.cause_source_thread_binding_id is distinct from episode_origin_binding_id
       or new.cause_source_external_identity_id is distinct from episode_origin_identity_id
       or new.cause_ordering_kind is distinct from episode_origin_ordering_kind
       or new.cause_ordering_scope_token is distinct from
         episode_origin_ordering_scope_token
       or new.cause_ordering_comparator_id is distinct from
         episode_origin_ordering_comparator_id
       or new.cause_ordering_comparator_revision is distinct from
         episode_origin_ordering_comparator_revision
       or (
         new.current_revision is null
         and (
           new.cause_provider_evidence_kind <> 'member'
           or new.cause_provider_roster_member_evidence_id is distinct from
             episode_origin_provider_member_id
           or new.cause_provider_roster_evidence_id is distinct from
             episode_origin_provider_roster_id
           or new.cause_ordering_position is distinct from
             episode_origin_ordering_position
         )
       )
       or (
         new.current_revision is not null
         and new.cause_ordering_position <=
           episode_provider_ordering_head_position
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.provider_membership_evidence_stale_or_scope_invalid';
    end if;

    if new.cause_provider_evidence_kind = 'member' then
      select count(*)::integer
        into provider_shape_count
        from public.inbox_v2_provider_roster_member_evidence member_row
        join public.inbox_v2_provider_roster_evidence roster_row
          on roster_row.tenant_id = member_row.tenant_id
         and roster_row.id = member_row.roster_evidence_id
         and roster_row.source_thread_binding_id = member_row.source_thread_binding_id
        join public.inbox_v2_source_thread_bindings binding_row
          on binding_row.tenant_id = roster_row.tenant_id
         and binding_row.id = roster_row.source_thread_binding_id
        join public.inbox_v2_external_threads thread_row
          on thread_row.tenant_id = binding_row.tenant_id
         and thread_row.id = binding_row.external_thread_id
        join public.inbox_v2_source_external_identities identity_row
          on identity_row.tenant_id = member_row.tenant_id
         and identity_row.id = member_row.source_external_identity_id
       where member_row.tenant_id = new.tenant_id
         and member_row.id = new.cause_provider_roster_member_evidence_id
         and member_row.roster_evidence_id = new.cause_provider_roster_evidence_id
         and member_row.source_thread_binding_id = new.cause_source_thread_binding_id
         and member_row.source_external_identity_id =
           new.cause_source_external_identity_id
         and thread_row.conversation_id = new.conversation_id
         and new.occurred_at = member_row.observed_at
         and roster_row.authority = 'authoritative'
         and member_row.normalized_role::text = new.to_role::text
         and member_row.state = case new.to_state
           when 'left' then 'left'::public.inbox_v2_provider_roster_member_state
           when 'removed' then 'removed'::public.inbox_v2_provider_roster_member_state
           else 'present'::public.inbox_v2_provider_roster_member_state
         end
         and roster_row.ordering_kind = new.cause_ordering_kind
         and roster_row.ordering_scope_token = new.cause_ordering_scope_token
         and roster_row.ordering_comparator_id = new.cause_ordering_comparator_id
         and roster_row.ordering_comparator_revision =
           new.cause_ordering_comparator_revision
         and roster_row.ordering_position = new.cause_ordering_position
         and (
           (
             identity_row.scope_kind = 'provider'
             and identity_row.declaration_contract_id = roster_row.adapter_contract_id
             and identity_row.declaration_contract_version =
               roster_row.adapter_contract_version
             and identity_row.declaration_surface_id = roster_row.adapter_surface_id
             and identity_row.declaration_loaded_by_trusted_service_id =
               roster_row.adapter_loaded_by_trusted_service_id
           ) or (
             identity_row.scope_kind = 'source_connection'
             and identity_row.scope_source_connection_id =
               binding_row.source_connection_id
           ) or (
             identity_row.scope_kind = 'source_account'
             and identity_row.scope_source_account_id = binding_row.source_account_id
           )
         );
    else
      select count(*)::integer
        into provider_shape_count
        from public.inbox_v2_provider_roster_evidence roster_row
        join public.inbox_v2_source_thread_bindings binding_row
          on binding_row.tenant_id = roster_row.tenant_id
         and binding_row.id = roster_row.source_thread_binding_id
        join public.inbox_v2_external_threads thread_row
          on thread_row.tenant_id = binding_row.tenant_id
         and thread_row.id = binding_row.external_thread_id
        join public.inbox_v2_source_external_identities identity_row
          on identity_row.tenant_id = roster_row.tenant_id
         and identity_row.id = new.cause_source_external_identity_id
       where roster_row.tenant_id = new.tenant_id
         and roster_row.id = new.cause_provider_roster_evidence_id
         and roster_row.source_thread_binding_id =
           new.cause_source_thread_binding_id
         and thread_row.conversation_id = new.conversation_id
         and new.to_state in ('left', 'removed')
         and new.occurred_at = roster_row.observed_at
         and roster_row.completeness = 'complete'
         and roster_row.authority = 'authoritative'
         and roster_row.omission_policy = 'close_missing'
         and roster_row.ordering_kind = new.cause_ordering_kind
         and roster_row.ordering_scope_token = new.cause_ordering_scope_token
         and roster_row.ordering_comparator_id = new.cause_ordering_comparator_id
         and roster_row.ordering_comparator_revision =
           new.cause_ordering_comparator_revision
         and roster_row.ordering_position = new.cause_ordering_position
         and (
           (
             identity_row.scope_kind = 'provider'
             and identity_row.declaration_contract_id = roster_row.adapter_contract_id
             and identity_row.declaration_contract_version =
               roster_row.adapter_contract_version
             and identity_row.declaration_surface_id = roster_row.adapter_surface_id
             and identity_row.declaration_loaded_by_trusted_service_id =
               roster_row.adapter_loaded_by_trusted_service_id
           ) or (
             identity_row.scope_kind = 'source_connection'
             and identity_row.scope_source_connection_id =
               binding_row.source_connection_id
           ) or (
             identity_row.scope_kind = 'source_account'
             and identity_row.scope_source_account_id = binding_row.source_account_id
           )
         )
         and not exists (
           select 1
             from public.inbox_v2_provider_roster_member_evidence omitted_member
            where omitted_member.tenant_id = roster_row.tenant_id
              and omitted_member.roster_evidence_id = roster_row.id
              and omitted_member.source_external_identity_id =
                new.cause_source_external_identity_id
         );
    end if;

    if provider_shape_count <> 1 then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.provider_membership_transition_invalid';
    end if;
  end if;

  if new.current_revision is not null then
    select transition_row.occurred_at
      into predecessor_occurred_at
      from public.inbox_v2_participant_membership_transitions transition_row
     where transition_row.tenant_id = new.tenant_id
       and transition_row.episode_id = new.episode_id
       and transition_row.resulting_revision = new.current_revision;
    if predecessor_occurred_at is null
       or new.occurred_at < predecessor_occurred_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.membership_transition_predecessor_invalid';
    end if;
  end if;
  return new;
end;
$$;



