--
-- Name: inbox_v2_repository_outbox_finalize_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_repository_outbox_finalize_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_expected_kind public.inbox_v2_outbox_outcome_kind;
begin
  if old.state = 'leased' and new.state <> 'leased' then
    v_expected_kind := case new.state
      when 'pending' then 'retry'::public.inbox_v2_outbox_outcome_kind
      when 'processed' then 'processed'::public.inbox_v2_outbox_outcome_kind
      when 'dead' then 'dead'::public.inbox_v2_outbox_outcome_kind
    end;
    if not exists (
      select 1
        from public.inbox_v2_outbox_outcomes outcome_row
       where outcome_row.tenant_id = new.tenant_id
         and outcome_row.intent_id = new.intent_id
         and outcome_row.outcome_revision = new.revision
         and outcome_row.kind = v_expected_kind
         and outcome_row.lease_token_hash = old.lease_token_hash
         and outcome_row.occurred_at = new.updated_at
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbox_finalize_outcome_missing';
    end if;
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_repository_outbox_intent_work_init(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_repository_outbox_intent_work_init() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  insert into public.inbox_v2_outbox_work_items (
    tenant_id, intent_id, state, attempt_count, available_at,
    revision, created_at, updated_at
  ) values (
    new.tenant_id, new.id, 'pending', 0, new.available_at, 1,
    new.created_at, new.created_at
  );
  return new;
end;
$$;



--
-- Name: inbox_v2_repository_outbox_outcome_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_repository_outbox_outcome_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    if current_user = 'hulee_inbox_v2_retention_owner'
       and pg_catalog.current_setting(
         'hulee.inbox_v2_retention_prune', true
       ) = 'enabled' then
      return old;
    end if;
  end if;
  raise exception using errcode = '23514',
    message = 'inbox_v2.outbox_outcome_immutable';
end;
$$;



--
-- Name: inbox_v2_repository_outbox_work_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_repository_outbox_work_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'INSERT' then
    if new.state <> 'pending' or new.attempt_count <> 0
       or new.revision <> 1
       or new.updated_at <> new.created_at then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbox_work_initial_state_invalid';
    end if;
    return new;
  end if;
  if tg_op = 'DELETE' then
    return old;
  end if;
  if old.state in ('processed', 'dead')
     and new.state = old.state
     and old.terminal_result_reference is not null
     and new.terminal_result_reference is null
     and current_user = 'hulee_inbox_v2_retention_owner'
     and (to_jsonb(new) - 'terminal_result_reference') =
       (to_jsonb(old) - 'terminal_result_reference') then
    return new;
  end if;
  if new.tenant_id is distinct from old.tenant_id
     or new.intent_id is distinct from old.intent_id
     or new.created_at is distinct from old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbox_work_identity_invalid';
  end if;
  if new.state = 'leased' then
    if old.state = 'pending' then
      if new.attempt_count <> old.attempt_count + 1
         or new.lease_revision <> 1
         or new.lease_claimed_at <> new.updated_at then
        raise exception using errcode = '40001',
          message = 'inbox_v2.outbox_claim_conflict';
      end if;
    elsif old.state = 'leased' then
      if old.lease_expires_at <= new.updated_at then
        if new.attempt_count <> old.attempt_count + 1
           or new.lease_token_hash is not distinct from old.lease_token_hash
           or new.lease_revision <> old.lease_revision + 1
           or new.lease_claimed_at <> new.updated_at then
          raise exception using errcode = '40001',
            message = 'inbox_v2.outbox_reclaim_conflict';
        end if;
      elsif new.attempt_count <> old.attempt_count
         or new.lease_token_hash is distinct from old.lease_token_hash
         or new.lease_owner_id is distinct from old.lease_owner_id
         or new.lease_revision <> old.lease_revision + 1
         or new.lease_claimed_at is distinct from old.lease_claimed_at
         or new.lease_expires_at < old.lease_expires_at
      then
        raise exception using errcode = '40001',
          message = 'inbox_v2.outbox_renew_conflict';
      end if;
    else
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbox_terminal_state_immutable';
    end if;
  elsif new.state in ('pending', 'processed', 'dead') then
    if old.state <> 'leased'
       or old.lease_expires_at <= new.updated_at
       or new.attempt_count <> old.attempt_count then
      raise exception using errcode = '40001',
        message = 'inbox_v2.outbox_finalize_conflict';
    end if;
  else
    raise exception using errcode = '23514',
      message = 'inbox_v2.outbox_state_transition_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_repository_projection_checkpoint_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_repository_projection_checkpoint_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'INSERT' then
    if new.revision <> 1 or new.updated_at <> new.created_at then
      raise exception using errcode = '23514',
        message = 'inbox_v2.projection_checkpoint_initial_state_invalid';
    end if;
    return new;
  end if;
  if tg_op = 'DELETE' then
    return old;
  end if;
  if new.tenant_id is distinct from old.tenant_id
     or new.projection_id is distinct from old.projection_id
     or new.scope_id is distinct from old.scope_id
     or new.generation is distinct from old.generation
     or new.stream_epoch is distinct from old.stream_epoch
     or new.created_at is distinct from old.created_at
     or new.position <> old.position + 1
     or new.last_commit_id is null
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception using errcode = '40001',
      message = 'inbox_v2.projection_checkpoint_gap';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_repository_projection_head_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_repository_projection_head_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text := coalesce(to_jsonb(new)->>'tenant_id', to_jsonb(old)->>'tenant_id');
  v_projection_id text := coalesce(to_jsonb(new)->>'projection_id', to_jsonb(old)->>'projection_id');
  v_scope_id text := coalesce(to_jsonb(new)->>'scope_id', to_jsonb(old)->>'scope_id');
begin
  if exists (
    select 1
      from public.inbox_v2_projection_generations generation_row
     where generation_row.tenant_id = v_tenant_id
       and generation_row.projection_id = v_projection_id
       and generation_row.scope_id = v_scope_id
       and not exists (
         select 1
           from public.inbox_v2_projection_checkpoints checkpoint_row
          where checkpoint_row.tenant_id = generation_row.tenant_id
            and checkpoint_row.projection_id = generation_row.projection_id
            and checkpoint_row.scope_id = generation_row.scope_id
            and checkpoint_row.generation = generation_row.generation
            and checkpoint_row.stream_epoch = generation_row.stream_epoch
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.projection_generation_checkpoint_missing';
  end if;

  if (
    exists (
      select 1
        from public.inbox_v2_projection_heads head_row
       where head_row.tenant_id = v_tenant_id
         and head_row.projection_id = v_projection_id
         and head_row.scope_id = v_scope_id
    ) or exists (
      select 1
        from public.inbox_v2_projection_generations generation_row
       where generation_row.tenant_id = v_tenant_id
         and generation_row.projection_id = v_projection_id
         and generation_row.scope_id = v_scope_id
         and generation_row.state = 'active'
    )
  ) and not exists (
    select 1
      from public.inbox_v2_projection_heads head_row
      join public.inbox_v2_projection_generations generation_row
        on generation_row.tenant_id = head_row.tenant_id
       and generation_row.projection_id = head_row.projection_id
       and generation_row.scope_id = head_row.scope_id
       and generation_row.generation = head_row.current_generation
       and generation_row.stream_epoch = head_row.stream_epoch
       and generation_row.projection_schema_version =
           head_row.projection_schema_version
       and generation_row.state = 'active'
     where head_row.tenant_id = v_tenant_id
       and head_row.projection_id = v_projection_id
       and head_row.scope_id = v_scope_id
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.projection_head_generation_incoherent';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_repository_retention_advance_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_repository_retention_advance_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' and not exists (
    select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
  ) then
    return old;
  end if;
  raise exception using errcode = '23514',
    message = 'inbox_v2.tenant_stream_retention_advance_immutable';
end;
$$;



--
-- Name: inbox_v2_security_denial_integrity_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_security_denial_integrity_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_window_started_at timestamptz;
  v_shard_no smallint;
  v_shard public.inbox_v2_security_denial_window_shards%rowtype;
  v_detail_count bigint;
  v_review_candidate_count bigint;
  v_current_window_started_at timestamptz;
begin
  if tg_when = 'BEFORE' then
    if tg_table_name = 'inbox_v2_security_denial_window_shards' then
      if tg_op = 'UPDATE' and (
        new.tenant_id is distinct from old.tenant_id
        or new.window_started_at is distinct from old.window_started_at
        or new.shard_no is distinct from old.shard_no
      ) then
        raise exception using
          errcode = '23514',
          message = 'inbox_v2.security_denial_identity_immutable';
      end if;
      if tg_op = 'INSERT' then
        v_current_window_started_at := date_bin(
          make_interval(secs => 3600),
          clock_timestamp(),
          timestamptz '1970-01-01 00:00:00+00'
        );
        if new.window_started_at < v_current_window_started_at -
            make_interval(secs => 3600)
          or new.window_started_at > v_current_window_started_at
        then
          raise exception using
            errcode = '23514',
            message = 'inbox_v2.security_denial_window_clock_invalid';
        end if;
      end if;
    elsif tg_table_name = 'inbox_v2_security_denial_buckets' then
      if tg_op = 'INSERT' then
        select shard.*
          into v_shard
          from public.inbox_v2_security_denial_window_shards as shard
         where shard.tenant_id = new.tenant_id
           and shard.window_started_at = new.window_started_at
           and shard.shard_no = new.shard_no
         for update;
        if not found then
          raise exception using
            errcode = '23514',
            message = 'inbox_v2.security_denial_parent_missing';
        end if;
        select count(*)::bigint
          into v_detail_count
          from public.inbox_v2_security_denial_buckets as bucket
         where bucket.tenant_id = new.tenant_id
           and bucket.window_started_at = new.window_started_at
           and bucket.shard_no = new.shard_no;
        if v_detail_count >= 16 then
          raise exception using
            errcode = '23514',
            message = 'inbox_v2.security_denial_detail_budget_exceeded';
        end if;
      elsif new.tenant_id is distinct from old.tenant_id
        or new.window_started_at is distinct from old.window_started_at
        or new.shard_no is distinct from old.shard_no
        or new.dedupe_fingerprint is distinct from old.dedupe_fingerprint
      then
        raise exception using
          errcode = '23514',
          message = 'inbox_v2.security_denial_identity_immutable';
      end if;
    elsif tg_table_name = 'inbox_v2_security_denial_review_signals' then
      if tg_op = 'INSERT' then
        new.review_sequence := nextval(
          pg_get_serial_sequence(
            'public.inbox_v2_security_denial_review_signals',
            'review_sequence'
          )
        );
        if new.aggregation_kind = 'candidate' then
          select shard.*
            into v_shard
            from public.inbox_v2_security_denial_window_shards as shard
           where shard.tenant_id = new.tenant_id
             and shard.window_started_at = new.window_started_at
             and shard.shard_no = new.shard_no
           for update;
          if not found then
            raise exception using
              errcode = '23514',
              message = 'inbox_v2.security_denial_parent_missing';
          end if;
          select count(*)::bigint
            into v_review_candidate_count
            from public.inbox_v2_security_denial_review_signals as review
           where review.tenant_id = new.tenant_id
             and review.window_started_at = new.window_started_at
             and review.shard_no = new.shard_no
             and review.aggregation_kind = 'candidate';
          if v_review_candidate_count >= 4 then
            raise exception using
              errcode = '23514',
              message = 'inbox_v2.security_denial_review_budget_exceeded';
          end if;
        end if;
      elsif new.tenant_id is distinct from old.tenant_id
        or new.review_sequence is distinct from old.review_sequence
        or new.window_started_at is distinct from old.window_started_at
        or new.shard_no is distinct from old.shard_no
        or new.review_type is distinct from old.review_type
        or new.aggregation_kind is distinct from old.aggregation_kind
        or new.candidate_fingerprint is distinct from old.candidate_fingerprint
      then
        raise exception using
          errcode = '23514',
          message = 'inbox_v2.security_denial_identity_immutable';
      end if;
    end if;
    return new;
  end if;

  if tg_op = 'DELETE' then
    v_tenant_id := old.tenant_id;
    v_window_started_at := old.window_started_at;
    v_shard_no := old.shard_no;
  else
    v_tenant_id := new.tenant_id;
    v_window_started_at := new.window_started_at;
    v_shard_no := new.shard_no;
  end if;

  select shard.*
    into v_shard
    from public.inbox_v2_security_denial_window_shards as shard
   where shard.tenant_id = v_tenant_id
     and shard.window_started_at = v_window_started_at
     and shard.shard_no = v_shard_no;
  if not found then
    if tg_op = 'DELETE' then return old; end if;
    return new;
  end if;

  select count(*)::bigint
    into v_detail_count
    from public.inbox_v2_security_denial_buckets as bucket
   where bucket.tenant_id = v_tenant_id
     and bucket.window_started_at = v_window_started_at
     and bucket.shard_no = v_shard_no;
  select count(*)::bigint
    into v_review_candidate_count
    from public.inbox_v2_security_denial_review_signals as review
   where review.tenant_id = v_tenant_id
     and review.window_started_at = v_window_started_at
     and review.shard_no = v_shard_no
     and review.aggregation_kind = 'candidate';

  if v_detail_count > 16
    or v_review_candidate_count > 4
    or v_detail_count is distinct from
      v_shard.admitted_detail_bucket_count::bigint
    or v_review_candidate_count is distinct from
      v_shard.admitted_review_candidate_count::bigint
  then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.security_denial_cardinality_invalid';
  end if;
  if tg_op = 'DELETE' then return old; end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_security_denial_prune(text, integer); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_security_denial_prune(p_tenant_id text, p_batch_size integer) RETURNS TABLE(deleted_window_count bigint)
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_pruned_at timestamptz := clock_timestamp();
begin
  if p_tenant_id is null or char_length(p_tenant_id) = 0
    or p_batch_size is null or p_batch_size < 1 or p_batch_size > 1000
  then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.security_denial_prune_input_invalid';
  end if;

  perform pg_catalog.set_config('lock_timeout', '100ms', true);
  perform pg_catalog.set_config('statement_timeout', '500ms', true);

  return query
  with expired as (
    select shard.tenant_id, shard.window_started_at, shard.shard_no
    from public.inbox_v2_security_denial_window_shards as shard
    where shard.tenant_id = p_tenant_id
      and shard.expires_at <= v_pruned_at
    order by shard.expires_at, shard.window_started_at, shard.shard_no
    for update skip locked
    limit p_batch_size
  ), deleted as (
    delete from public.inbox_v2_security_denial_window_shards as shard
    using expired
    where shard.tenant_id = expired.tenant_id
      and shard.window_started_at = expired.window_started_at
      and shard.shard_no = expired.shard_no
    returning 1
  )
  select count(*)::bigint from deleted;
end;
$$;



--
-- Name: inbox_v2_security_denial_record(text, public.inbox_v2_security_denial_action, public.inbox_v2_security_denial_principal_class, text, text, text, text, public.inbox_v2_security_denial_kind, public.inbox_v2_security_denial_public_error_class, public.inbox_v2_security_denial_risk, public.inbox_v2_security_denial_review_type, public.inbox_v2_security_denial_alert_type, text, text, integer, integer, integer, integer, integer, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_security_denial_record(p_tenant_id text, p_action public.inbox_v2_security_denial_action, p_principal_class public.inbox_v2_security_denial_principal_class, p_fingerprint_key_epoch text, p_actor_fingerprint text, p_dedupe_fingerprint text, p_observation_receipt text, p_denial_kind public.inbox_v2_security_denial_kind, p_public_error_class public.inbox_v2_security_denial_public_error_class, p_risk public.inbox_v2_security_denial_risk, p_review_type public.inbox_v2_security_denial_review_type, p_alert_type public.inbox_v2_security_denial_alert_type, p_candidate_ref text, p_policy_id text, p_window_seconds integer, p_retention_seconds integer, p_shard_count integer, p_detail_bucket_limit_per_shard integer, p_review_candidate_limit_per_shard integer, p_attempt_rate_limit_per_shard integer, p_lock_timeout_milliseconds integer, p_statement_timeout_milliseconds integer) RETURNS TABLE(observation_receipt text, observed_at timestamp with time zone, disposition public.inbox_v2_security_denial_disposition, shard_no smallint, window_started_at timestamp with time zone, window_ended_at timestamp with time zone, expires_at timestamp with time zone, shard_attempt_count bigint, detail_occurrence_count bigint, admitted_detail_bucket_count smallint, overflow_count bigint, counter_saturated boolean, review_types public.inbox_v2_security_denial_review_type[], review_dispositions public.inbox_v2_security_denial_review_disposition[])
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
	  v_bigint_max constant bigint := 9223372036854775807;
	  v_observed_at timestamptz := date_trunc(
	    'milliseconds', clock_timestamp()
	  );
  v_window_started_at timestamptz;
  v_window_ended_at timestamptz;
  v_expires_at timestamptz;
  v_shard_no smallint;
  v_shard public.inbox_v2_security_denial_window_shards%rowtype;
  v_bucket public.inbox_v2_security_denial_buckets%rowtype;
  v_review public.inbox_v2_security_denial_review_signals%rowtype;
  v_detail_exists boolean := false;
  v_rate_limited boolean := false;
  v_volume_exceeded boolean := false;
  v_local_saturated boolean := false;
  v_expected_risk public.inbox_v2_security_denial_risk;
  v_expected_review_type public.inbox_v2_security_denial_review_type;
  v_expected_alert_type public.inbox_v2_security_denial_alert_type;
  v_pending_review_types public.inbox_v2_security_denial_review_type[] :=
    array[]::public.inbox_v2_security_denial_review_type[];
  v_pending_alert_types public.inbox_v2_security_denial_alert_type[] :=
    array[]::public.inbox_v2_security_denial_alert_type[];
  v_pending_candidate public.inbox_v2_security_denial_review_type[] :=
    array[]::public.inbox_v2_security_denial_review_type[];
  v_review_types public.inbox_v2_security_denial_review_type[] :=
    array[]::public.inbox_v2_security_denial_review_type[];
  v_review_dispositions public.inbox_v2_security_denial_review_disposition[] :=
    array[]::public.inbox_v2_security_denial_review_disposition[];
  v_current_review_type public.inbox_v2_security_denial_review_type;
  v_current_alert_type public.inbox_v2_security_denial_alert_type;
  v_current_candidate boolean;
  v_current_risk public.inbox_v2_security_denial_risk;
	  v_index integer;
begin
  if p_policy_id is distinct from 'core:security-denial-policy.default-v1'
    or p_window_seconds is distinct from 3600
    or p_retention_seconds is distinct from 2592000
    or p_shard_count is distinct from 16
    or p_detail_bucket_limit_per_shard is distinct from
      16
    or p_review_candidate_limit_per_shard is distinct from
      4
    or p_attempt_rate_limit_per_shard is distinct from
      600
    or p_lock_timeout_milliseconds is distinct from
      100
    or p_statement_timeout_milliseconds is distinct from
      500
  then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.security_denial_policy_mismatch';
  end if;

  perform pg_catalog.set_config(
    'lock_timeout', '100ms', true
  );
  perform pg_catalog.set_config(
    'statement_timeout', '500ms', true
  );

  if p_tenant_id is null or char_length(p_tenant_id) = 0
    or p_action is null
    or p_principal_class is null
    or p_fingerprint_key_epoch is null
    or p_fingerprint_key_epoch !~
      '^security-denial-key:[a-f0-9]{16,32}$'
    or p_actor_fingerprint is null
    or p_actor_fingerprint !~ '^hmac-sha256:[a-f0-9]{64}$'
	    or p_dedupe_fingerprint is null
	    or p_dedupe_fingerprint !~ '^hmac-sha256:[a-f0-9]{64}$'
	    or p_actor_fingerprint = p_dedupe_fingerprint
	    or p_observation_receipt is null
	    or p_observation_receipt !~
	      '^security-denial-observation:[a-f0-9]{64}$'
	    or p_denial_kind is null
    or p_public_error_class is null
	    or p_risk is null
    or (p_candidate_ref is not null and
      p_candidate_ref !~ '^internal-ref:[a-f0-9]{32,64}$')
  then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.security_denial_input_invalid';
  end if;

  if p_denial_kind in (
      'unknown_or_hidden_resource', 'cross_tenant_probe'
    ) and p_public_error_class <> 'not_found'
  then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.security_denial_public_class_invalid';
  end if;

  if (p_denial_kind = 'manual_self_claim') is distinct from
    (p_action = 'identity.claim'
      and p_public_error_class = 'identity_claim_self_forbidden')
  then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.security_denial_manual_self_claim_invalid';
  end if;

  v_expected_risk := case
    when p_denial_kind = 'cross_tenant_probe'
      or p_action = 'privacy.deletion.execute'
      then 'critical'::public.inbox_v2_security_denial_risk
    when p_denial_kind in (
        'manual_self_claim', 'unknown_or_hidden_resource'
      ) or p_action in (
        'authorization.privileged_mutation', 'identity.claim'
      ) or p_action::text like 'privacy.%'
      then 'high'::public.inbox_v2_security_denial_risk
    when p_denial_kind in ('state_guard', 'other_denied')
      then 'low'::public.inbox_v2_security_denial_risk
    else 'medium'::public.inbox_v2_security_denial_risk
  end;
  if p_risk is distinct from v_expected_risk then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.security_denial_risk_invalid';
  end if;

  if p_denial_kind = 'manual_self_claim' then
    v_expected_review_type := 'manual_self_claim';
    v_expected_alert_type := 'identity_claim_review';
  elsif p_action::text like 'privacy.%' then
    v_expected_review_type := case p_action
      when 'privacy.hold.issue' then 'privacy_hold_issue_denied'
      when 'privacy.hold.release' then 'privacy_hold_release_denied'
      when 'privacy.subject_evidence.view' then
        'privacy_evidence_access_denied'
      when 'privacy.tenant_export' then 'tenant_export_denied'
      when 'privacy.deletion.preview' then 'destructive_preview_denied'
      when 'privacy.deletion.approve' then 'destructive_approval_denied'
      when 'privacy.deletion.execute' then 'destructive_execution_denied'
      else null
    end;
    v_expected_alert_type := 'privacy_control_review';
  elsif p_denial_kind = 'cross_tenant_probe' then
    v_expected_review_type := 'cross_tenant_probe';
    v_expected_alert_type := 'security_probe_review';
  elsif p_denial_kind = 'unknown_or_hidden_resource' then
    v_expected_review_type := 'guessed_identifier_probe';
    v_expected_alert_type := 'security_probe_review';
  end if;

  if v_expected_review_type is null then
    if p_review_type is not null or p_alert_type is not null
      or p_candidate_ref is not null
    then
      raise exception using
        errcode = '22023',
        message = 'inbox_v2.security_denial_review_invalid';
    end if;
  elsif p_review_type is distinct from v_expected_review_type
    or p_alert_type is distinct from v_expected_alert_type
    or (p_denial_kind <> 'manual_self_claim'
      and p_candidate_ref is not null)
  then
    raise exception using
      errcode = '22023',
      message = 'inbox_v2.security_denial_review_invalid';
  end if;

	  v_window_started_at := date_bin(
	    make_interval(secs => 3600),
	    v_observed_at,
    timestamptz '1970-01-01 00:00:00+00'
  );
  v_window_ended_at := v_window_started_at +
    make_interval(secs => 3600);
  v_expires_at := v_window_started_at +
    make_interval(secs => 2592000);
  v_shard_no := (
    (('x' || substring(p_actor_fingerprint from 13 for 8))::bit(32)::bigint)
      % 16
  )::smallint;

  insert into public.inbox_v2_security_denial_window_shards as shard (
    tenant_id,
    window_started_at,
    shard_no,
    window_ended_at,
    policy_id,
    attempt_count,
    admitted_detail_bucket_count,
    admitted_review_candidate_count,
    overflow_count,
    counter_saturated,
    first_seen_at,
    last_seen_at,
    expires_at,
    created_at,
    updated_at
  ) values (
    p_tenant_id,
    v_window_started_at,
    v_shard_no,
    v_window_ended_at,
    p_policy_id,
    1,
    0,
    0,
    0,
    false,
    v_observed_at,
    v_observed_at,
    v_expires_at,
    v_observed_at,
    v_observed_at
  )
  on conflict on constraint inbox_v2_security_denial_window_shards_pk
  do update
  set attempt_count = case
        when shard.attempt_count = v_bigint_max then v_bigint_max
        else shard.attempt_count + 1
      end,
      counter_saturated = shard.counter_saturated
        or shard.attempt_count >= v_bigint_max - 1,
      first_seen_at = least(shard.first_seen_at, excluded.first_seen_at),
      last_seen_at = greatest(shard.last_seen_at, excluded.last_seen_at),
      updated_at = v_observed_at
  returning shard.* into v_shard;

  v_rate_limited :=
    v_shard.attempt_count > 600;

  if not v_rate_limited then
    select bucket.*
    into v_bucket
    from public.inbox_v2_security_denial_buckets as bucket
    where bucket.tenant_id = p_tenant_id
      and bucket.window_started_at = v_window_started_at
      and bucket.shard_no = v_shard_no
      and bucket.dedupe_fingerprint = p_dedupe_fingerprint
    for update;

    if found then
      if v_bucket.action is distinct from p_action
        or v_bucket.principal_class is distinct from p_principal_class
        or v_bucket.fingerprint_key_epoch is distinct from
          p_fingerprint_key_epoch
        or v_bucket.actor_fingerprint is distinct from p_actor_fingerprint
        or v_bucket.denial_kind is distinct from p_denial_kind
        or v_bucket.public_error_class is distinct from p_public_error_class
        or v_bucket.risk is distinct from p_risk
      then
        raise exception using
          errcode = '23505',
          message = 'inbox_v2.security_denial_fingerprint_conflict';
      end if;

      update public.inbox_v2_security_denial_buckets as bucket
      set occurrence_count = case
            when bucket.occurrence_count = v_bigint_max then v_bigint_max
            else bucket.occurrence_count + 1
          end,
          first_seen_at = least(bucket.first_seen_at, v_observed_at),
          last_seen_at = greatest(bucket.last_seen_at, v_observed_at),
          updated_at = v_observed_at
      where bucket.tenant_id = p_tenant_id
        and bucket.window_started_at = v_window_started_at
        and bucket.shard_no = v_shard_no
        and bucket.dedupe_fingerprint = p_dedupe_fingerprint
      returning bucket.* into v_bucket;
      v_local_saturated := v_bucket.occurrence_count = v_bigint_max;
      disposition := 'deduplicated';
      detail_occurrence_count := v_bucket.occurrence_count;
      v_detail_exists := true;
    elsif v_shard.admitted_detail_bucket_count <
      16
    then
      insert into public.inbox_v2_security_denial_buckets (
        tenant_id,
        window_started_at,
        shard_no,
        dedupe_fingerprint,
        window_ended_at,
        expires_at,
        action,
        principal_class,
        fingerprint_key_epoch,
        actor_fingerprint,
        denial_kind,
        public_error_class,
        risk,
        occurrence_count,
        first_seen_at,
        last_seen_at,
        created_at,
        updated_at
      ) values (
        p_tenant_id,
        v_window_started_at,
        v_shard_no,
        p_dedupe_fingerprint,
        v_window_ended_at,
        v_expires_at,
        p_action,
        p_principal_class,
        p_fingerprint_key_epoch,
        p_actor_fingerprint,
        p_denial_kind,
        p_public_error_class,
        p_risk,
        1,
        v_observed_at,
        v_observed_at,
        v_observed_at,
        v_observed_at
      );
      update public.inbox_v2_security_denial_window_shards as shard
      set admitted_detail_bucket_count =
            shard.admitted_detail_bucket_count + 1,
          updated_at = v_observed_at
      where shard.tenant_id = p_tenant_id
        and shard.window_started_at = v_window_started_at
        and shard.shard_no = v_shard_no
      returning shard.* into v_shard;
      disposition := 'recorded';
      detail_occurrence_count := 1;
      v_detail_exists := true;
    else
      disposition := 'aggregated_overflow';
      detail_occurrence_count := null;
      v_volume_exceeded := true;
    end if;
  else
    disposition := 'rate_limited';
    detail_occurrence_count := null;
  end if;

  if not v_detail_exists then
    update public.inbox_v2_security_denial_window_shards as shard
    set overflow_count = case
          when shard.overflow_count = v_bigint_max then v_bigint_max
          else shard.overflow_count + 1
        end,
        counter_saturated = shard.counter_saturated
          or shard.overflow_count >= v_bigint_max - 1,
        updated_at = v_observed_at
    where shard.tenant_id = p_tenant_id
      and shard.window_started_at = v_window_started_at
      and shard.shard_no = v_shard_no
    returning shard.* into v_shard;
  end if;

  if v_expected_review_type is not null then
    v_pending_review_types := array_append(
      v_pending_review_types, v_expected_review_type
    );
    v_pending_alert_types := array_append(
      v_pending_alert_types, v_expected_alert_type
    );
    if v_detail_exists then
      v_pending_candidate := array_append(
        v_pending_candidate, v_expected_review_type
      );
    end if;
  end if;
  if v_rate_limited then
    v_pending_review_types := array_append(
      v_pending_review_types, 'denial_rate_exceeded'
    );
    v_pending_alert_types := array_append(
      v_pending_alert_types, 'abuse_threshold_alert'
    );
  end if;
  if v_volume_exceeded then
    v_pending_review_types := array_append(
      v_pending_review_types, 'denial_volume_exceeded'
    );
    v_pending_alert_types := array_append(
      v_pending_alert_types, 'abuse_threshold_alert'
    );
  end if;

  if cardinality(v_pending_review_types) > 3
    or cardinality(v_pending_review_types) <>
      cardinality(v_pending_alert_types)
  then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.security_denial_review_budget_invalid';
  end if;

  for v_index in
    select generate_subscripts(v_pending_review_types, 1)
  loop
    v_current_review_type := v_pending_review_types[v_index];
    v_current_alert_type := v_pending_alert_types[v_index];
    v_current_candidate :=
      v_current_review_type = any(v_pending_candidate);
    v_current_risk := case
      when v_current_review_type in (
        'denial_rate_exceeded', 'denial_volume_exceeded'
      ) then 'high'::public.inbox_v2_security_denial_risk
      else p_risk
    end;

    if v_current_candidate then
      select review.*
      into v_review
      from public.inbox_v2_security_denial_review_signals as review
      where review.tenant_id = p_tenant_id
        and review.window_started_at = v_window_started_at
        and review.shard_no = v_shard_no
        and review.review_type = v_current_review_type
        and review.aggregation_kind = 'candidate'
        and review.candidate_fingerprint = p_dedupe_fingerprint
      for update;

      if found then
        if v_review.alert_type is distinct from v_current_alert_type
          or v_review.candidate_ref is distinct from p_candidate_ref
          or v_review.risk is distinct from v_current_risk
        then
          raise exception using
            errcode = '23505',
            message = 'inbox_v2.security_denial_review_conflict';
        end if;
        update public.inbox_v2_security_denial_review_signals as review
        set trigger_count = case
              when review.trigger_count = v_bigint_max then v_bigint_max
              else review.trigger_count + 1
            end,
            first_seen_at = least(review.first_seen_at, v_observed_at),
            last_seen_at = greatest(review.last_seen_at, v_observed_at),
            updated_at = v_observed_at
        where review.tenant_id = p_tenant_id
          and review.window_started_at = v_window_started_at
          and review.shard_no = v_shard_no
          and review.review_type = v_current_review_type
          and review.aggregation_kind = 'candidate'
          and review.candidate_fingerprint = p_dedupe_fingerprint
        returning review.* into v_review;
        v_local_saturated := v_local_saturated
          or v_review.trigger_count = v_bigint_max;
        v_review_types := array_append(
          v_review_types, v_current_review_type
        );
        v_review_dispositions := array_append(
          v_review_dispositions, 'candidate_aggregated'
        );
        continue;
      elsif v_shard.admitted_review_candidate_count <
        4
      then
        insert into public.inbox_v2_security_denial_review_signals (
          tenant_id,
          window_started_at,
          shard_no,
          review_type,
          aggregation_kind,
          candidate_fingerprint,
          alert_type,
          candidate_ref,
          risk,
          status,
          trigger_count,
          window_ended_at,
          first_seen_at,
          last_seen_at,
          expires_at,
          created_at,
          updated_at
        ) values (
          p_tenant_id,
          v_window_started_at,
          v_shard_no,
          v_current_review_type,
          'candidate',
          p_dedupe_fingerprint,
          v_current_alert_type,
          p_candidate_ref,
          v_current_risk,
          'open',
          1,
          v_window_ended_at,
          v_observed_at,
          v_observed_at,
          v_expires_at,
          v_observed_at,
          v_observed_at
        );
        update public.inbox_v2_security_denial_window_shards as shard
        set admitted_review_candidate_count =
              shard.admitted_review_candidate_count + 1,
            updated_at = v_observed_at
        where shard.tenant_id = p_tenant_id
          and shard.window_started_at = v_window_started_at
          and shard.shard_no = v_shard_no
        returning shard.* into v_shard;
        v_review_types := array_append(
          v_review_types, v_current_review_type
        );
        v_review_dispositions := array_append(
          v_review_dispositions, 'candidate_created'
        );
        continue;
      end if;
    end if;

    select review.*
    into v_review
    from public.inbox_v2_security_denial_review_signals as review
    where review.tenant_id = p_tenant_id
      and review.window_started_at = v_window_started_at
      and review.shard_no = v_shard_no
      and review.review_type = v_current_review_type
      and review.aggregation_kind = 'overflow'
    for update;
    if found then
      if v_review.alert_type is distinct from v_current_alert_type then
        raise exception using
          errcode = '23505',
          message = 'inbox_v2.security_denial_review_conflict';
      end if;
      update public.inbox_v2_security_denial_review_signals as review
      set trigger_count = case
            when review.trigger_count = v_bigint_max then v_bigint_max
            else review.trigger_count + 1
          end,
          risk = case
            when review.risk = 'critical' or v_current_risk = 'critical'
              then 'critical'::public.inbox_v2_security_denial_risk
            when review.risk = 'high' or v_current_risk = 'high'
              then 'high'::public.inbox_v2_security_denial_risk
            when review.risk = 'medium' or v_current_risk = 'medium'
              then 'medium'::public.inbox_v2_security_denial_risk
            else 'low'::public.inbox_v2_security_denial_risk
          end,
          first_seen_at = least(review.first_seen_at, v_observed_at),
          last_seen_at = greatest(review.last_seen_at, v_observed_at),
          updated_at = v_observed_at
      where review.tenant_id = p_tenant_id
        and review.window_started_at = v_window_started_at
        and review.shard_no = v_shard_no
        and review.review_type = v_current_review_type
        and review.aggregation_kind = 'overflow'
      returning review.* into v_review;
      v_local_saturated := v_local_saturated
        or v_review.trigger_count = v_bigint_max;
      v_review_types := array_append(v_review_types, v_current_review_type);
      v_review_dispositions := array_append(
        v_review_dispositions, 'overflow_aggregated'
      );
    else
      insert into public.inbox_v2_security_denial_review_signals (
        tenant_id,
        window_started_at,
        shard_no,
        review_type,
        aggregation_kind,
        candidate_fingerprint,
        alert_type,
        candidate_ref,
        risk,
        status,
        trigger_count,
        window_ended_at,
        first_seen_at,
        last_seen_at,
        expires_at,
        created_at,
        updated_at
      ) values (
        p_tenant_id,
        v_window_started_at,
        v_shard_no,
        v_current_review_type,
        'overflow',
        null,
        v_current_alert_type,
        null,
        v_current_risk,
        'open',
        1,
        v_window_ended_at,
        v_observed_at,
        v_observed_at,
        v_expires_at,
        v_observed_at,
        v_observed_at
      );
      v_review_types := array_append(v_review_types, v_current_review_type);
      v_review_dispositions := array_append(
        v_review_dispositions, 'overflow_created'
      );
    end if;
  end loop;

  if v_local_saturated then
    update public.inbox_v2_security_denial_window_shards as shard
    set counter_saturated = true,
        updated_at = v_observed_at
    where shard.tenant_id = p_tenant_id
      and shard.window_started_at = v_window_started_at
      and shard.shard_no = v_shard_no
    returning shard.* into v_shard;
  end if;

  observation_receipt := p_observation_receipt;
  observed_at := v_observed_at;
  shard_no := v_shard_no;
  window_started_at := v_window_started_at;
  window_ended_at := v_window_ended_at;
  expires_at := v_expires_at;
  shard_attempt_count := v_shard.attempt_count;
  admitted_detail_bucket_count := v_shard.admitted_detail_bucket_count;
  overflow_count := v_shard.overflow_count;
  counter_saturated := v_shard.counter_saturated;
  review_types := v_review_types;
  review_dispositions := v_review_dispositions;
  return next;
end;
$_$;



--
-- Name: inbox_v2_source_correlation_evidence_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_correlation_evidence_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'INSERT' then
    if new.expires_at <= clock_timestamp() then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_correlation_evidence_expired';
    end if;
    if not exists (
      select 1
      from public.inbox_v2_source_occurrences occurrence_row
      where occurrence_row.tenant_id = new.tenant_id
        and occurrence_row.id = new.source_occurrence_id
        and occurrence_row.recorded_at <= new.created_at
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_correlation_evidence_occurrence_mismatch';
    end if;
    return new;
  end if;

  if tg_op = 'DELETE' and (
       clock_timestamp() >= old.expires_at
       or (
         pg_trigger_depth() > 1
         and (
           not exists (
             select 1 from public.tenants tenant_row
             where tenant_row.id = old.tenant_id
           )
           or not exists (
             select 1
             from public.inbox_v2_source_occurrences occurrence_row
             where occurrence_row.tenant_id = old.tenant_id
               and occurrence_row.id = old.source_occurrence_id
           )
         )
       )
     ) then
    return old;
  end if;

  raise exception using
    errcode = '23514',
    message = format(
      'inbox_v2.source_correlation_evidence_immutable:%s', tg_op
    );
end
$$;



--
-- Name: inbox_v2_source_identity_assessment_assert_head_local(text, text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_assessment_assert_head_local(p_tenant_id text, p_assessment_id text, p_source_external_identity_id text, p_assessment_version bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_head public.inbox_v2_source_identity_assessment_heads%rowtype;
begin
  select * into v_head
  from public.inbox_v2_source_identity_assessment_heads h
  where h.tenant_id = p_tenant_id
    and h.source_external_identity_id = p_source_external_identity_id;

  if v_head.latest_assessment_version is null
     or v_head.latest_assessment_version < p_assessment_version then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_assessment_head_missing_or_behind';
  end if;

  if not exists (
       select 1
       from public.inbox_v2_source_identity_assessments current_assessment
       where current_assessment.tenant_id = p_tenant_id
         and current_assessment.id = p_assessment_id
         and current_assessment.source_external_identity_id = p_source_external_identity_id
         and current_assessment.assessment_version = p_assessment_version
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_assessment_head_pointer_missing';
  end if;

  if v_head.latest_assessment_version = p_assessment_version then
    if v_head.latest_assessment_id <> p_assessment_id
       or exists (
         select 1
         from public.inbox_v2_source_identity_assessments successor
         where successor.tenant_id = p_tenant_id
           and successor.source_external_identity_id = p_source_external_identity_id
           and successor.assessment_version = p_assessment_version + 1
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_assessment_head_not_latest';
    end if;
  elsif not exists (
    select 1
    from public.inbox_v2_source_identity_assessments successor
    where successor.tenant_id = p_tenant_id
      and successor.source_external_identity_id = p_source_external_identity_id
      and successor.assessment_version = p_assessment_version + 1
      and successor.previous_assessment_version = p_assessment_version
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_assessment_successor_missing';
  end if;
end
$$;



--
-- Name: inbox_v2_source_identity_assessment_assert_local(text, text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_assessment_assert_local(p_tenant_id text, p_assessment_id text, p_source_external_identity_id text, p_assessment_version bigint) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_head public.inbox_v2_source_identity_assessment_heads%rowtype;
begin
  select * into v_head
  from public.inbox_v2_source_identity_assessment_heads h
  where h.tenant_id = p_tenant_id
    and h.source_external_identity_id = p_source_external_identity_id;

  if v_head.latest_assessment_version is null
     or v_head.latest_assessment_version < p_assessment_version then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_assessment_head_missing_or_behind';
  end if;

  if p_assessment_version > 1
     and not exists (
       select 1
       from public.inbox_v2_source_identity_assessments predecessor
       where predecessor.tenant_id = p_tenant_id
         and predecessor.source_external_identity_id = p_source_external_identity_id
         and predecessor.assessment_version = p_assessment_version - 1
         and predecessor.previous_assessment_version is not distinct from
           case when p_assessment_version = 2 then null else p_assessment_version - 2 end
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_assessment_predecessor_missing';
  end if;

  if v_head.latest_assessment_version = p_assessment_version then
    if v_head.latest_assessment_id <> p_assessment_id then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_assessment_head_pointer_mismatch';
    end if;
  elsif not exists (
    select 1
    from public.inbox_v2_source_identity_assessments successor
    where successor.tenant_id = p_tenant_id
      and successor.source_external_identity_id = p_source_external_identity_id
      and successor.assessment_version = p_assessment_version + 1
      and successor.previous_assessment_version = p_assessment_version
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_assessment_successor_missing';
  end if;
end
$$;



--
-- Name: inbox_v2_source_identity_assessment_constraint(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_assessment_constraint() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_source_identity_assessment_assert_local(
    new.tenant_id,
    new.id,
    new.source_external_identity_id,
    new.assessment_version
  );
  return null;
end
$$;



--
-- Name: inbox_v2_source_identity_assessment_head_constraint(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_assessment_head_constraint() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_source_identity_assessment_assert_head_local(
      new.tenant_id,
      new.latest_assessment_id,
      new.source_external_identity_id,
      new.latest_assessment_version
  );
  return null;
end
$$;



--
-- Name: inbox_v2_source_identity_assessment_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_assessment_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'INSERT' then
    if new.latest_assessment_version <> 1 then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_assessment_head_initial_version';
    end if;
    return new;
  end if;

  if new.tenant_id <> old.tenant_id
     or new.source_external_identity_id <> old.source_external_identity_id
     or new.latest_assessment_version <> old.latest_assessment_version + 1
     or new.updated_at < old.updated_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_assessment_head_cas';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_source_identity_claim_assert_claim(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_assert_claim(checked_tenant_id text, checked_claim_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  claim_source_external_identity_id text;
  claim_status public.inbox_v2_source_identity_claim_status;
  claim_revoked_at timestamptz;
  identity_scope_kind public.inbox_v2_source_identity_scope_kind;
  identity_scope_source_connection_id text;
  identity_scope_source_account_id text;
  evidence_count integer;
  minimum_ordinal integer;
  maximum_ordinal integer;
  creation_count integer;
  termination_count integer;
  termination_occurred_at timestamptz;
begin
  select
    claim_row.source_external_identity_id,
    claim_row.status,
    claim_row.revoked_at
  into
    claim_source_external_identity_id,
    claim_status,
    claim_revoked_at
  from public.inbox_v2_source_identity_claims claim_row
  where claim_row.tenant_id = checked_tenant_id
    and claim_row.id = checked_claim_id;

  if not found then
    return;
  end if;

  select
    identity_row.scope_kind,
    identity_row.scope_source_connection_id,
    identity_row.scope_source_account_id
  into
    identity_scope_kind,
    identity_scope_source_connection_id,
    identity_scope_source_account_id
  from public.inbox_v2_source_external_identities identity_row
  where identity_row.tenant_id = checked_tenant_id
    and identity_row.id = claim_source_external_identity_id;

  if not found then
    return;
  end if;

  select count(*), min(evidence_row.ordinal), max(evidence_row.ordinal)
  into evidence_count, minimum_ordinal, maximum_ordinal
  from public.inbox_v2_source_identity_claim_evidence_references evidence_row
  where evidence_row.tenant_id = checked_tenant_id
    and evidence_row.claim_id = checked_claim_id;

  if evidence_count < 1
     or evidence_count > 50
     or minimum_ordinal <> 0
     or maximum_ordinal <> evidence_count - 1 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_evidence_cardinality_invalid';
  end if;

  if identity_scope_kind = 'provider'
     and not exists (
       select 1
       from public.inbox_v2_source_identity_claim_evidence_references evidence_row
       where evidence_row.tenant_id = checked_tenant_id
         and evidence_row.claim_id = checked_claim_id
         and evidence_row.evidence_kind in (
           'source_occurrence',
           'provider_roster_evidence'
         )
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_evidence_scope_invalid',
      detail = 'provider_scope_requires_exact_actor_evidence';
  end if;

  if identity_scope_kind = 'provider'
     and exists (
       select 1
       from public.inbox_v2_source_identity_claim_evidence_references supplemental_row
       where supplemental_row.tenant_id = checked_tenant_id
         and supplemental_row.claim_id = checked_claim_id
         and supplemental_row.evidence_kind in (
           'raw_inbound_event',
           'normalized_inbound_event'
         )
         and not exists (
           select 1
           from public.inbox_v2_source_identity_claim_evidence_references anchor_row
           left join public.inbox_v2_source_occurrences occurrence_row
             on anchor_row.evidence_kind = 'source_occurrence'
            and occurrence_row.tenant_id = anchor_row.tenant_id
            and occurrence_row.id = anchor_row.source_occurrence_id
           left join public.inbox_v2_provider_roster_evidence roster_row
             on anchor_row.evidence_kind = 'provider_roster_evidence'
            and roster_row.tenant_id = anchor_row.tenant_id
            and roster_row.id = anchor_row.provider_roster_evidence_id
           where anchor_row.tenant_id = supplemental_row.tenant_id
             and anchor_row.claim_id = supplemental_row.claim_id
             and (
               (
                 supplemental_row.evidence_kind = 'raw_inbound_event'
                 and coalesce(
                   occurrence_row.raw_inbound_event_id,
                   roster_row.raw_inbound_event_id
                 ) = supplemental_row.raw_inbound_event_id
               ) or (
                 supplemental_row.evidence_kind = 'normalized_inbound_event'
                 and coalesce(
                   occurrence_row.normalized_inbound_event_id,
                   roster_row.normalized_inbound_event_id
                 ) = supplemental_row.normalized_inbound_event_id
               )
             )
         )
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_evidence_scope_invalid',
      detail = 'provider_event_requires_paired_exact_actor_evidence';
  end if;

  if exists (
    select 1
    from public.inbox_v2_source_identity_claim_evidence_references evidence_row
    left join public.raw_inbound_events raw_event_row
      on evidence_row.evidence_kind = 'raw_inbound_event'
     and raw_event_row.tenant_id = evidence_row.tenant_id
     and raw_event_row.id = evidence_row.raw_inbound_event_id
    left join public.normalized_inbound_events normalized_event_row
      on evidence_row.evidence_kind = 'normalized_inbound_event'
     and normalized_event_row.tenant_id = evidence_row.tenant_id
     and normalized_event_row.id = evidence_row.normalized_inbound_event_id
    left join public.inbox_v2_source_occurrences occurrence_row
      on evidence_row.evidence_kind = 'source_occurrence'
     and occurrence_row.tenant_id = evidence_row.tenant_id
     and occurrence_row.id = evidence_row.source_occurrence_id
    left join public.inbox_v2_provider_roster_evidence roster_row
      on evidence_row.evidence_kind = 'provider_roster_evidence'
     and roster_row.tenant_id = evidence_row.tenant_id
     and roster_row.id = evidence_row.provider_roster_evidence_id
    where evidence_row.tenant_id = checked_tenant_id
      and evidence_row.claim_id = checked_claim_id
      and (
        (
          identity_scope_kind = 'source_connection'
          and coalesce(
            raw_event_row.source_connection_id,
            normalized_event_row.source_connection_id,
            occurrence_row.source_connection_id,
            roster_row.source_connection_id
          ) is distinct from identity_scope_source_connection_id
        ) or (
          identity_scope_kind = 'source_account'
          and coalesce(
            raw_event_row.source_account_id,
            normalized_event_row.source_account_id,
            occurrence_row.source_account_id,
            roster_row.source_account_id
          ) is distinct from identity_scope_source_account_id
        )
      )
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_evidence_scope_invalid';
  end if;

  select count(*)
  into creation_count
  from public.inbox_v2_source_identity_claim_transitions transition_row
  where transition_row.tenant_id = checked_tenant_id
    and transition_row.resulting_claim_id = checked_claim_id;

  if creation_count <> 1 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_creation_transition_invalid';
  end if;

  select count(*), min(transition_row.occurred_at)
  into termination_count, termination_occurred_at
  from public.inbox_v2_source_identity_claim_transitions transition_row
  where transition_row.tenant_id = checked_tenant_id
    and (
      transition_row.previous_claim_id = checked_claim_id
      or transition_row.active_claim_id = checked_claim_id
    );

  if claim_status = 'active' then
    if termination_count <> 0 or claim_revoked_at is not null then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_active_termination_invalid';
    end if;
  elsif termination_count <> 1
     or claim_revoked_at is distinct from termination_occurred_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_revocation_transition_invalid';
  end if;

  perform public.inbox_v2_source_identity_claim_assert_identity(
    checked_tenant_id,
    claim_source_external_identity_id
  );
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_assert_identity(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_assert_identity(checked_tenant_id text, checked_source_external_identity_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  identity_revision bigint;
  identity_updated_at timestamptz;
  head_status public.inbox_v2_source_identity_resolution_status;
  head_active_claim_id text;
  head_version bigint;
  latest_transition_occurred_at timestamptz;
begin
  select
    identity_row.revision,
    identity_row.updated_at,
    head_row.resolution_status,
    head_row.active_claim_id,
    head_row.latest_claim_version
  into
    identity_revision,
    identity_updated_at,
    head_status,
    head_active_claim_id,
    head_version
  from public.inbox_v2_source_external_identities identity_row
  left join public.inbox_v2_source_identity_claim_heads head_row
    on head_row.tenant_id = identity_row.tenant_id
   and head_row.source_external_identity_id = identity_row.id
  where identity_row.tenant_id = checked_tenant_id
    and identity_row.id = checked_source_external_identity_id;

  if not found then
    return;
  end if;

  if head_status is null then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_head_missing';
  end if;

  if head_version is null then
    if head_status <> 'unresolved'
       or head_active_claim_id is not null
       or identity_revision <> 1
       or exists (
         select 1
         from public.inbox_v2_source_identity_claim_transitions transition_row
         where transition_row.tenant_id = checked_tenant_id
           and transition_row.source_external_identity_id = checked_source_external_identity_id
           and transition_row.resulting_version = 1
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_initial_head_invalid';
    end if;
    return;
  end if;

  select transition_row.occurred_at
  into latest_transition_occurred_at
  from public.inbox_v2_source_identity_claim_transitions transition_row
  where transition_row.tenant_id = checked_tenant_id
    and transition_row.source_external_identity_id = checked_source_external_identity_id
    and transition_row.resulting_version = head_version;

  if not found
     or identity_revision <> head_version + 1
     or identity_updated_at is distinct from latest_transition_occurred_at
     or exists (
       select 1
       from public.inbox_v2_source_identity_claim_transitions successor_row
       where successor_row.tenant_id = checked_tenant_id
         and successor_row.source_external_identity_id = checked_source_external_identity_id
         and successor_row.current_version = head_version
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_head_clock_invalid';
  end if;

  if head_status = 'claimed' then
    if head_active_claim_id is null
       or not exists (
         select 1
         from public.inbox_v2_source_identity_claims claim_row
         where claim_row.tenant_id = checked_tenant_id
           and claim_row.id = head_active_claim_id
           and claim_row.source_external_identity_id = checked_source_external_identity_id
           and claim_row.claim_version = head_version
           and claim_row.status = 'active'
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_active_head_invalid';
    end if;
  elsif head_active_claim_id is not null
     or exists (
       select 1
       from public.inbox_v2_source_identity_claims claim_row
       where claim_row.tenant_id = checked_tenant_id
         and claim_row.source_external_identity_id = checked_source_external_identity_id
         and claim_row.status = 'active'
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_inactive_head_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_assert_transition(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_assert_transition(checked_tenant_id text, checked_transition_id text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  transition_row public.inbox_v2_source_identity_claim_transitions%rowtype;
  head_version bigint;
  predecessor_occurred_at timestamptz;
  exact_claim_found boolean;
begin
  select *
  into transition_row
  from public.inbox_v2_source_identity_claim_transitions candidate_row
  where candidate_row.tenant_id = checked_tenant_id
    and candidate_row.id = checked_transition_id;

  if not found then
    return;
  end if;

  select head_row.latest_claim_version
  into head_version
  from public.inbox_v2_source_identity_claim_heads head_row
  where head_row.tenant_id = transition_row.tenant_id
    and head_row.source_external_identity_id = transition_row.source_external_identity_id;

  if not found
     or head_version is null
     or head_version < transition_row.resulting_version
     or (
       head_version > transition_row.resulting_version
       and not exists (
         select 1
         from public.inbox_v2_source_identity_claim_transitions successor_row
         where successor_row.tenant_id = transition_row.tenant_id
           and successor_row.source_external_identity_id = transition_row.source_external_identity_id
           and successor_row.current_version = transition_row.resulting_version
       )
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_transition_chain_invalid';
  end if;

  if transition_row.current_version is not null then
    select predecessor_row.occurred_at
    into predecessor_occurred_at
    from public.inbox_v2_source_identity_claim_transitions predecessor_row
    where predecessor_row.tenant_id = transition_row.tenant_id
      and predecessor_row.source_external_identity_id = transition_row.source_external_identity_id
      and predecessor_row.resulting_version = transition_row.current_version;

    if not found or transition_row.occurred_at < predecessor_occurred_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_transition_predecessor_invalid';
    end if;
  end if;

  if transition_row.operation_kind in ('claim_employee', 'claim_client_contact') then
    select exists (
      select 1
      from public.inbox_v2_source_identity_claims claim_row
      where claim_row.tenant_id = transition_row.tenant_id
        and claim_row.id = transition_row.resulting_claim_id
        and claim_row.source_external_identity_id = transition_row.source_external_identity_id
        and claim_row.previous_claim_version is not distinct from transition_row.current_version
        and claim_row.claim_version = transition_row.resulting_version
        and claim_row.target_kind = transition_row.target_kind
        and claim_row.target_key = transition_row.target_key
        and claim_row.policy_id = transition_row.policy_id
        and claim_row.policy_version = transition_row.policy_version
        and claim_row.reason_code_id = transition_row.reason_code_id
        and claim_row.decision_kind = transition_row.decision_kind
        and claim_row.decision_actor_employee_id is not distinct from transition_row.decision_actor_employee_id
        and claim_row.decision_trusted_service_id is not distinct from transition_row.decision_trusted_service_id
        and claim_row.policy_family is not distinct from transition_row.policy_family
        and claim_row.policy_definition_contract_version is not distinct from transition_row.policy_definition_contract_version
        and claim_row.policy_definition_digest_sha256 is not distinct from transition_row.policy_definition_digest_sha256
        and claim_row.policy_activation_head_revision is not distinct from transition_row.policy_activation_head_revision
        and claim_row.created_at = transition_row.occurred_at
    ) into exact_claim_found;

    if not exact_claim_found then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_creation_exactness_invalid';
    end if;

    if transition_row.previous_claim_id is not null
       and not exists (
         select 1
         from public.inbox_v2_source_identity_claims previous_claim_row
         where previous_claim_row.tenant_id = transition_row.tenant_id
           and previous_claim_row.id = transition_row.previous_claim_id
           and previous_claim_row.source_external_identity_id = transition_row.source_external_identity_id
           and previous_claim_row.target_kind = transition_row.previous_target_kind
           and previous_claim_row.target_key = transition_row.previous_target_key
           and previous_claim_row.claim_version < transition_row.resulting_version
           and previous_claim_row.status = 'revoked'
           and previous_claim_row.revoked_at = transition_row.occurred_at
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_reassignment_exactness_invalid';
    end if;
  elsif not exists (
    select 1
    from public.inbox_v2_source_identity_claims active_claim_row
    where active_claim_row.tenant_id = transition_row.tenant_id
      and active_claim_row.id = transition_row.active_claim_id
      and active_claim_row.source_external_identity_id = transition_row.source_external_identity_id
      and active_claim_row.target_kind = transition_row.target_kind
      and active_claim_row.target_key = transition_row.target_key
      and active_claim_row.claim_version < transition_row.resulting_version
      and active_claim_row.status = 'revoked'
      and active_claim_row.revoked_at = transition_row.occurred_at
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_revoke_exactness_invalid';
  end if;

  perform public.inbox_v2_source_identity_claim_assert_identity(
    transition_row.tenant_id,
    transition_row.source_external_identity_id
  );
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_bootstrap_head(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_bootstrap_head() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  insert into public.inbox_v2_source_identity_claim_heads (
    tenant_id,
    source_external_identity_id,
    resolution_status,
    active_claim_id,
    latest_claim_version
  ) values (
    new.tenant_id,
    new.id,
    'unresolved',
    null,
    null
  )
  on conflict (tenant_id, source_external_identity_id) do nothing;
  return new;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_deferred_claim(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_deferred_claim() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_source_identity_claim_assert_claim(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.id, old.id)
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_deferred_evidence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_deferred_evidence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_source_identity_claim_assert_claim(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.claim_id, old.claim_id)
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_deferred_head(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_deferred_head() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_source_identity_claim_assert_identity(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.source_external_identity_id, old.source_external_identity_id)
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_deferred_identity(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_deferred_identity() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_source_identity_claim_assert_identity(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.id, old.id)
  );
  return null;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_deferred_transition(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_deferred_transition() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  perform public.inbox_v2_source_identity_claim_assert_transition(
    coalesce(new.tenant_id, old.tenant_id),
    coalesce(new.id, old.id)
  );

  if coalesce(new.resulting_claim_id, old.resulting_claim_id) is not null then
    perform public.inbox_v2_source_identity_claim_assert_claim(
      coalesce(new.tenant_id, old.tenant_id),
      coalesce(new.resulting_claim_id, old.resulting_claim_id)
    );
  end if;
  if coalesce(new.previous_claim_id, old.previous_claim_id) is not null then
    perform public.inbox_v2_source_identity_claim_assert_claim(
      coalesce(new.tenant_id, old.tenant_id),
      coalesce(new.previous_claim_id, old.previous_claim_id)
    );
  end if;
  if coalesce(new.active_claim_id, old.active_claim_id) is not null then
    perform public.inbox_v2_source_identity_claim_assert_claim(
      coalesce(new.tenant_id, old.tenant_id),
      coalesce(new.active_claim_id, old.active_claim_id)
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_guard_claim_change(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_guard_claim_change() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_source_identity_claim_parent_gone(
      old.tenant_id,
      old.source_external_identity_id
    ) then
      return old;
    end if;

    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_history_delete_forbidden';
  end if;

  if new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.source_external_identity_id is distinct from old.source_external_identity_id
     or new.previous_claim_version is distinct from old.previous_claim_version
     or new.claim_version is distinct from old.claim_version
     or new.target_kind is distinct from old.target_kind
     or new.target_employee_id is distinct from old.target_employee_id
     or new.target_client_contact_id is distinct from old.target_client_contact_id
     or new.confidence is distinct from old.confidence
     or new.policy_id is distinct from old.policy_id
     or new.policy_version is distinct from old.policy_version
     or new.reason_code_id is distinct from old.reason_code_id
     or new.decision_kind is distinct from old.decision_kind
     or new.decision_actor_employee_id is distinct from old.decision_actor_employee_id
     or new.decision_trusted_service_id is distinct from old.decision_trusted_service_id
     or new.policy_family is distinct from old.policy_family
     or new.policy_definition_contract_version is distinct from old.policy_definition_contract_version
     or new.policy_definition_digest_sha256 is distinct from old.policy_definition_digest_sha256
     or new.policy_activation_head_revision is distinct from old.policy_activation_head_revision
     or new.created_at is distinct from old.created_at
     or old.status <> 'active'
     or old.revoked_at is not null
     or old.revision <> 1
     or new.status <> 'revoked'
     or new.revoked_at is null
     or new.revision <> 2 then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_invalid_revocation';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_guard_head_change(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_guard_head_change() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if public.inbox_v2_source_identity_claim_parent_gone(
      old.tenant_id,
      old.source_external_identity_id
    ) then
      return old;
    end if;

    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_head_delete_forbidden';
  end if;

  if new.tenant_id is distinct from old.tenant_id
     or new.source_external_identity_id is distinct from old.source_external_identity_id
     or (
       old.latest_claim_version is null
       and new.latest_claim_version is distinct from 1
     )
     or (
       old.latest_claim_version is not null
       and new.latest_claim_version is distinct from old.latest_claim_version + 1
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_head_noncontiguous';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_guard_identity_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_guard_identity_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.realm_id is distinct from old.realm_id
     or new.realm_version is distinct from old.realm_version
     or new.canonicalization_version is distinct from old.canonicalization_version
     or new.object_kind_id is distinct from old.object_kind_id
     or new.scope_kind is distinct from old.scope_kind
     or new.scope_source_connection_id is distinct from old.scope_source_connection_id
     or new.scope_source_account_id is distinct from old.scope_source_account_id
     or new.identity_declaration is distinct from old.identity_declaration
     or new.declaration_contract_id is distinct from old.declaration_contract_id
     or new.declaration_contract_version is distinct from old.declaration_contract_version
     or new.declaration_revision is distinct from old.declaration_revision
     or new.declaration_surface_id is distinct from old.declaration_surface_id
     or new.declaration_loaded_by_trusted_service_id is distinct from old.declaration_loaded_by_trusted_service_id
     or new.declaration_loaded_at is distinct from old.declaration_loaded_at
     or new.materialized_by_trusted_service_id is distinct from old.materialized_by_trusted_service_id
     or new.materialization_authorization_token is distinct from old.materialization_authorization_token
     or new.materialized_at is distinct from old.materialized_at
     or new.canonical_external_subject is distinct from old.canonical_external_subject
     or new.stability_kind is distinct from old.stability_kind
     or new.ephemeral_raw_inbound_event_id is distinct from old.ephemeral_raw_inbound_event_id
     or new.ephemeral_normalized_inbound_event_id is distinct from old.ephemeral_normalized_inbound_event_id
     or new.ephemeral_observation_key is distinct from old.ephemeral_observation_key
     or new.created_at is distinct from old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_identity_invalid_update';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_guard_transition_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_guard_transition_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_version bigint;
  predecessor_occurred_at timestamptz;
begin
  select head_row.latest_claim_version
  into head_version
  from public.inbox_v2_source_identity_claim_heads head_row
  where head_row.tenant_id = new.tenant_id
    and head_row.source_external_identity_id = new.source_external_identity_id
  for update;

  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_identity_claim_head_missing';
  end if;

  if new.expected_version is distinct from head_version
     or new.current_version is distinct from head_version then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.source_identity_claim_revision_conflict';
  end if;

  if new.current_version is not null then
    select transition_row.occurred_at
    into predecessor_occurred_at
    from public.inbox_v2_source_identity_claim_transitions transition_row
    where transition_row.tenant_id = new.tenant_id
      and transition_row.source_external_identity_id = new.source_external_identity_id
      and transition_row.resulting_version = new.current_version;

    if not found or new.occurred_at < predecessor_occurred_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_transition_clock_invalid';
    end if;
  end if;

  if new.decision_kind = 'automatic_policy' then
    perform 1
    from public.inbox_v2_tenant_policy_activation_heads head_row
    join public.inbox_v2_tenant_policy_versions version_row
      on version_row.tenant_id = head_row.tenant_id
     and version_row.family = head_row.family
     and version_row.policy_id = head_row.policy_id
     and version_row.policy_version = head_row.policy_version
     and version_row.definition_contract_version = head_row.definition_contract_version
     and version_row.definition_digest_sha256 = head_row.definition_digest_sha256
     and version_row.approved_trusted_service_id = head_row.approved_trusted_service_id
    where head_row.tenant_id = new.tenant_id
      and head_row.family = 'source_identity_claim'
      and head_row.policy_id = new.policy_id
      and head_row.state = 'active'
      and head_row.revision = new.policy_activation_head_revision
      and head_row.policy_version = new.policy_version
      and head_row.definition_contract_version = new.policy_definition_contract_version
      and head_row.definition_digest_sha256 = new.policy_definition_digest_sha256
      and head_row.approved_trusted_service_id = new.decision_trusted_service_id
      and head_row.activated_at <= new.occurred_at
    for share of head_row, version_row;

    if not found then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_identity_claim_policy_authority_invalid';
    end if;
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_source_identity_claim_parent_gone(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_parent_gone(checked_tenant_id text, checked_source_external_identity_id text) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select
    not exists (
      select 1
      from public.tenants tenant_row
      where tenant_row.id = checked_tenant_id
    )
    or not exists (
      select 1
      from public.inbox_v2_source_external_identities identity_row
      where identity_row.tenant_id = checked_tenant_id
        and identity_row.id = checked_source_external_identity_id
    );
$$;



--
-- Name: inbox_v2_source_identity_claim_reject_history_change(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_claim_reject_history_change() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE'
     and public.inbox_v2_source_identity_claim_parent_gone(
       old.tenant_id,
       old.source_external_identity_id
     ) then
    return old;
  end if;

  raise exception using
    errcode = '23514',
    message = format(
      'inbox_v2.source_identity_claim_history_immutable:%s:%s',
      tg_table_name,
      tg_op
    );
end;
$$;



--
-- Name: inbox_v2_source_identity_resolution_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_identity_resolution_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  raise exception using
    errcode = '23514',
    message = format('inbox_v2.source_identity_resolution_immutable:%s:%s', tg_table_name, tg_op);
end
$$;



--
-- Name: inbox_v2_source_message_key_registry_assert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_message_key_registry_assert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if not exists (
    select 1
    from public.inbox_v2_source_message_key_registry registry_row
    where registry_row.tenant_id = new.tenant_id
      and registry_row.message_key_digest_sha256 =
        new.message_key_digest_sha256
      and registry_row.message_realm_id = new.message_realm_id
      and registry_row.message_realm_version = new.message_realm_version
      and registry_row.message_canonicalization_version =
        new.message_canonicalization_version
      and registry_row.message_scope_kind = new.message_scope_kind
      and registry_row.message_scope_source_account_id is not distinct from
        new.message_scope_source_account_id
      and registry_row.message_scope_source_thread_binding_id is not distinct from
        new.message_scope_source_thread_binding_id
      and registry_row.message_object_kind_id = new.message_object_kind_id
      and registry_row.external_thread_id = new.external_thread_id
      and registry_row.canonical_external_subject =
        new.canonical_external_subject
      and registry_row.external_message_key_detail =
        new.external_message_key_detail
      and registry_row.external_message_key_detail_digest_sha256 =
        new.external_message_key_detail_digest_sha256
  ) then
    raise exception using
      errcode = '23514',
      message = case tg_table_name
        when 'inbox_v2_deferred_message_source_actions' then
          'inbox_v2.deferred_source_action_message_key_registry_mismatch'
        else
          'inbox_v2.deferred_source_ordering_head_message_key_registry_mismatch'
      end;
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_source_normalization_assert_result(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_normalization_assert_result() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_work_count bigint;
  v_event_count bigint;
  v_quarantine_count bigint;
begin
  select count(*) into v_work_count
    from public.inbox_v2_source_raw_work_items work_row
   where work_row.tenant_id = new.tenant_id
     and work_row.raw_event_id = new.raw_event_id;
  select count(*) into v_event_count
    from public.inbox_v2_source_normalized_envelopes envelope_row
   where envelope_row.tenant_id = new.tenant_id
     and envelope_row.raw_event_id = new.raw_event_id;
  select count(*) into v_quarantine_count
    from public.inbox_v2_source_normalized_quarantines quarantine_row
   where quarantine_row.tenant_id = new.tenant_id
     and quarantine_row.id = new.quarantine_id
     and quarantine_row.raw_event_id = new.raw_event_id
     and quarantine_row.reason_code = new.reason_code
     and quarantine_row.digest_key_generation = new.digest_key_generation
     and quarantine_row.candidate_completion_hmac_sha256 =
       new.candidate_completion_hmac_sha256;

  if v_work_count <> 0
     or v_event_count <> new.normalized_event_count
     or (new.outcome = 'normalized' and v_event_count < 1)
     or (new.outcome <> 'normalized' and v_event_count <> 0)
     or (new.outcome = 'quarantined' and v_quarantine_count <> 1)
     or (new.outcome <> 'quarantined' and v_quarantine_count <> 0) then
    raise exception 'V2 source normalization result is not a closed aggregate'
      using errcode = '23514';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_source_normalization_complete_work_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_normalization_complete_work_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_result public.inbox_v2_source_normalization_results%rowtype;
begin
  select * into v_result
    from public.inbox_v2_source_normalization_results result_row
   where result_row.tenant_id = old.tenant_id
     and result_row.raw_event_id = old.raw_event_id;

  if old.state <> 'leased'
     or v_result.raw_event_id is null
     or v_result.worker_id <> old.lease_owner_id
     or v_result.completed_attempt_count <> old.attempt_count
     or v_result.completed_reclaim_count <> old.reclaim_count
     or v_result.completed_lease_token_hash <> old.lease_token_hash
     or v_result.completed_lease_revision <> old.lease_revision
     or v_result.completed_lease_claimed_at <> old.lease_claimed_at
     or v_result.completed_lease_expires_at <> old.lease_expires_at
     or v_result.completed_work_revision <> old.revision
     or v_result.completed_at < old.updated_at
     or v_result.completed_at >= old.lease_expires_at
     or clock_timestamp() >= old.lease_expires_at then
    raise exception 'Raw work completion requires the exact unexpired lease result'
      using errcode = '23514';
  end if;
  return old;
end
$$;



--
-- Name: inbox_v2_source_normalized_anchor_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_normalized_anchor_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if old.idempotency_key like 'source:v2:normalized:%' then
    raise exception 'V2 normalized compatibility anchor is immutable'
      using errcode = '23514';
  end if;
  return case when tg_op = 'DELETE' then old else new end;
end
$$;



--
-- Name: inbox_v2_source_normalized_assert_aggregate(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_normalized_assert_aggregate() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_normalized_event_id text;
  v_anchor public.normalized_inbound_events%rowtype;
  v_envelope public.inbox_v2_source_normalized_envelopes%rowtype;
  v_result public.inbox_v2_source_normalization_results%rowtype;
  v_evidence_count bigint;
  v_payload_count bigint;
  v_raw_event_count bigint;
begin
  v_tenant_id := new.tenant_id;
  if tg_table_name = 'normalized_inbound_events' then
    v_normalized_event_id := new.id;
  else
    v_normalized_event_id := new.normalized_event_id;
  end if;

  select * into v_anchor
    from public.normalized_inbound_events event_row
   where event_row.tenant_id = v_tenant_id
     and event_row.id = v_normalized_event_id;
  select * into v_envelope
    from public.inbox_v2_source_normalized_envelopes envelope_row
   where envelope_row.tenant_id = v_tenant_id
     and envelope_row.normalized_event_id = v_normalized_event_id;

  if v_envelope.normalized_event_id is null then
    if v_anchor.id is not null
       and v_anchor.idempotency_key like 'source:v2:normalized:%' then
      raise exception 'V2 normalized anchor requires an immutable envelope'
        using errcode = '23514';
    end if;
    return null;
  end if;

  if v_anchor.id is null
     or v_anchor.raw_event_id <> v_envelope.raw_event_id
     or v_anchor.source_connection_id <> v_envelope.source_connection_id
     or v_anchor.source_account_id is distinct from v_envelope.source_account_id
     or v_anchor.source_type <> v_envelope.source_type
     or v_anchor.source_name <> v_envelope.source_name
     or v_anchor.event_type <> v_envelope.event_type
     or v_anchor.direction <> v_envelope.direction
     or v_anchor.visibility <> v_envelope.visibility
     or v_anchor.payload_version <> v_envelope.payload_schema_version
     or v_anchor.idempotency_key <> v_envelope.idempotency_key
     or v_anchor.external_thread_id is not null
     or v_anchor.external_message_id is not null
     or v_anchor.external_user_id is not null
     or v_anchor.normalized_payload <> '{}'::jsonb
     or v_anchor.reply_capability <> '{}'::jsonb
     or v_anchor.conversation_id is not null
     or v_anchor.message_id is not null
     or v_anchor.processing_status <> 'ignored'
     or v_anchor.created_at <> v_envelope.created_at
     or v_anchor.updated_at <> v_envelope.created_at then
    raise exception 'V2 normalized compatibility anchor is unsafe or incoherent'
      using errcode = '23514';
  end if;

  select count(*) into v_evidence_count
    from public.inbox_v2_source_normalized_evidence evidence_row
   where evidence_row.tenant_id = v_tenant_id
     and evidence_row.normalized_event_id = v_normalized_event_id;
  select count(*) into v_payload_count
    from public.inbox_v2_source_normalized_evidence_payloads payload_row
   where payload_row.tenant_id = v_tenant_id
     and payload_row.normalized_event_id = v_normalized_event_id;

  if tg_table_name <> 'inbox_v2_source_normalized_evidence_payloads'
     and (v_evidence_count <> v_envelope.normalized_evidence_count
       or v_payload_count <> v_evidence_count) then
    raise exception 'V2 normalized envelope has incoherent evidence references'
      using errcode = '23514';
  end if;

  select * into v_result
    from public.inbox_v2_source_normalization_results result_row
   where result_row.tenant_id = v_tenant_id
     and result_row.raw_event_id = v_envelope.raw_event_id;
  select count(*) into v_raw_event_count
    from public.inbox_v2_source_normalized_envelopes envelope_row
   where envelope_row.tenant_id = v_tenant_id
     and envelope_row.raw_event_id = v_envelope.raw_event_id;

  if v_result.raw_event_id is null
     or v_raw_event_count <> v_result.normalized_event_count
     or (v_result.outcome = 'normalized' and v_raw_event_count < 1)
     or (v_result.outcome <> 'normalized' and v_raw_event_count <> 0) then
    raise exception 'V2 normalized aggregate requires its exact immutable terminal result'
      using errcode = '23514';
  end if;

  return null;
end
$$;



--
-- Name: inbox_v2_source_normalized_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_normalized_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_table_name = 'inbox_v2_source_normalized_evidence_payloads'
     and tg_op = 'DELETE' then
    return old;
  end if;
  raise exception '% is immutable', tg_table_name using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_source_occurrence_deferred_children(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_occurrence_deferred_children() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
begin
  if tg_table_name = 'inbox_v2_source_occurrences'
     and tg_op = 'INSERT'
     and exists (
       select 1 from public.tenants tenant_row
        where tenant_row.id = new_row->>'tenant_id'
     )
     and not exists (
       select 1
         from public.inbox_v2_source_occurrences occurrence_row
        where occurrence_row.tenant_id = new_row->>'tenant_id'
          and occurrence_row.id = new_row->>'id'
          and occurrence_row.resolution_state = 'pending'
          and occurrence_row.revision = 1
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_occurrence_initial_commit_required';
  end if;

  if tg_op <> 'INSERT' then
    perform public.inbox_v2_assert_source_occurrence_children(
      old_row->>'tenant_id',
      coalesce(old_row->>'id', old_row->>'source_occurrence_id')
    );
  end if;
  if tg_op <> 'DELETE' then
    perform public.inbox_v2_assert_source_occurrence_children(
      new_row->>'tenant_id',
      coalesce(new_row->>'id', new_row->>'source_occurrence_id')
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_source_occurrence_guard_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_occurrence_guard_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_row public.inbox_v2_source_thread_binding_heads%rowtype;
  snapshot_row public.inbox_v2_source_thread_binding_snapshots%rowtype;
  account_identity_row public.inbox_v2_source_account_identities%rowtype;
  thread_identity_declaration jsonb;
  actor_scope_kind public.inbox_v2_source_identity_scope_kind;
  actor_scope_source_connection_id text;
  actor_scope_source_account_id text;
  actor_stability_kind public.inbox_v2_source_identity_stability_kind;
  actor_ephemeral_raw_event_id text;
  actor_ephemeral_normalized_event_id text;
  actor_declaration_contract_id text;
  actor_declaration_contract_version text;
  actor_declaration_surface_id text;
  actor_declaration_loaded_by_trusted_service_id text;
  actor_declaration_loaded_at timestamptz;
  actor_materialized_at timestamptz;
  actor_created_at timestamptz;
begin
  if new.resolution_state <> 'pending'
     or new.revision <> 1
     or new.created_at <> new.updated_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_occurrence_initial_resolution_invalid';
  end if;

  select * into head_row
    from public.inbox_v2_source_thread_binding_heads candidate_row
   where candidate_row.tenant_id = new.tenant_id
     and candidate_row.binding_id = new.source_thread_binding_id
   for share;

  if not found then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_occurrence_binding_head_missing';
  end if;

  select * into snapshot_row
    from public.inbox_v2_source_thread_binding_snapshots candidate_row
   where candidate_row.tenant_id = new.tenant_id
     and candidate_row.binding_id = new.source_thread_binding_id
     and candidate_row.revision = new.binding_revision
   for share;

  if not found
     or head_row.revision <> new.binding_revision
     or head_row.external_thread_id <> new.external_thread_id
     or head_row.source_connection_id <> new.source_connection_id
     or head_row.source_account_id <> new.source_account_id
     or head_row.binding_generation <> new.binding_generation
     or head_row.capability_revision <> new.capability_revision
     or head_row.account_identity_revision <> new.account_identity_revision
     or head_row.account_generation <> new.account_generation
     or head_row.account_canonical_key_digest_sha256 <>
        new.account_canonical_key_digest_sha256
     or head_row.created_at > new.recorded_at
     or head_row.updated_at > new.recorded_at
     or snapshot_row.external_thread_id <> new.external_thread_id
     or snapshot_row.source_connection_id <> new.source_connection_id
     or snapshot_row.source_account_id <> new.source_account_id
     or snapshot_row.binding_generation <> new.binding_generation
     or snapshot_row.capability_revision <> new.capability_revision
     or snapshot_row.account_identity_revision <> new.account_identity_revision
     or snapshot_row.account_generation <> new.account_generation
     or snapshot_row.account_canonical_key_digest_sha256 <>
        new.account_canonical_key_digest_sha256
     or snapshot_row.capability_contract_id <> new.adapter_contract_id
     or snapshot_row.capability_contract_version <> new.adapter_contract_version
     or snapshot_row.capability_surface_id <> new.adapter_surface_id
     or snapshot_row.created_at > new.recorded_at
     or snapshot_row.updated_at > new.recorded_at then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.source_occurrence_binding_fence_conflict';
  end if;

  select * into account_identity_row
    from public.inbox_v2_source_account_identities candidate_row
   where candidate_row.tenant_id = new.tenant_id
     and candidate_row.source_account_id = new.source_account_id
   for share;

  if not found
     or account_identity_row.source_connection_id <> new.source_connection_id
     or account_identity_row.state <> 'verified'
     or account_identity_row.revision <> new.account_identity_revision
     or account_identity_row.account_generation <> new.account_generation
     or account_identity_row.canonical_key_digest_sha256 <>
        new.account_canonical_key_digest_sha256
     or account_identity_row.declaration_contract_id <>
        new.adapter_contract_id
     or account_identity_row.declaration_contract_version <>
        new.adapter_contract_version
     or account_identity_row.declaration_surface_id <>
        new.adapter_surface_id
     or account_identity_row.updated_at > new.recorded_at then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.source_occurrence_account_identity_fence_conflict';
  end if;

  select thread_row.identity_declaration
    into thread_identity_declaration
    from public.inbox_v2_external_threads thread_row
   where thread_row.tenant_id = new.tenant_id
     and thread_row.id = new.external_thread_id
     and thread_row.conversation_id = new.conversation_id
     and thread_row.revision = new.external_thread_revision
     and thread_row.created_at <= new.recorded_at
   for share;

  if not found
     or thread_identity_declaration #>> '{adapterContract,contractId}' is distinct from
        new.adapter_contract_id
     or thread_identity_declaration #>> '{adapterContract,contractVersion}' is distinct from
        new.adapter_contract_version
     or thread_identity_declaration #>> '{adapterContract,surfaceId}' is distinct from
        new.adapter_surface_id then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_occurrence_adapter_surface_mismatch';
  end if;

  if new.origin_kind <> 'provider_response' then
    perform 1
      from public.raw_inbound_events raw_event_row
      join public.normalized_inbound_events normalized_event_row
        on normalized_event_row.tenant_id = raw_event_row.tenant_id
       and normalized_event_row.raw_event_id = raw_event_row.id
       and normalized_event_row.source_connection_id =
          raw_event_row.source_connection_id
       and normalized_event_row.source_account_id is not distinct from
          raw_event_row.source_account_id
     where raw_event_row.tenant_id = new.tenant_id
       and raw_event_row.id = new.raw_inbound_event_id
       and raw_event_row.source_connection_id = new.source_connection_id
       and raw_event_row.source_account_id = new.source_account_id
       and normalized_event_row.id = new.normalized_inbound_event_id
       and normalized_event_row.created_at <= new.recorded_at
       and raw_event_row.received_at <= new.recorded_at
     for share of raw_event_row, normalized_event_row;

    if not found then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_occurrence_event_pair_mismatch';
    end if;
  else
    perform 1
      from public.inbox_v2_outbound_dispatch_attempts attempt_row
      join public.inbox_v2_outbound_dispatches dispatch_row
        on dispatch_row.tenant_id = attempt_row.tenant_id
       and dispatch_row.id = attempt_row.dispatch_id
       and dispatch_row.route_id = attempt_row.route_id
       and dispatch_row.message_id = attempt_row.message_id
       and dispatch_row.last_attempt_id = attempt_row.id
      join public.inbox_v2_outbound_routes route_row
        on route_row.tenant_id = attempt_row.tenant_id
       and route_row.id = attempt_row.route_id
       and route_row.source_thread_binding_id = new.source_thread_binding_id
       and route_row.external_thread_id = new.external_thread_id
       and route_row.source_connection_id = new.source_connection_id
       and route_row.source_account_id = new.source_account_id
     where attempt_row.tenant_id = new.tenant_id
       and attempt_row.id = new.outbound_dispatch_attempt_id
       and route_row.adapter_contract_id = new.adapter_contract_id
       and route_row.adapter_contract_version = new.adapter_contract_version
       and route_row.adapter_surface_id = new.adapter_surface_id
       and route_row.account_generation = head_row.account_generation
       and route_row.binding_generation = head_row.binding_generation
       and route_row.remote_access_revision = head_row.remote_access_revision
       and route_row.administrative_revision =
          head_row.administrative_revision
       and route_row.capability_revision = head_row.capability_revision
       and route_row.route_descriptor_revision =
          head_row.route_descriptor_revision
       and route_row.created_at <= attempt_row.opened_at
       and attempt_row.opened_at <= new.observed_at
     for share of attempt_row, dispatch_row, route_row;

    if not found then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_occurrence_provider_response_chain_mismatch';
    end if;
  end if;

  if new.provider_actor_kind = 'source_external_identity' then
    select
      identity_row.scope_kind,
      identity_row.scope_source_connection_id,
      identity_row.scope_source_account_id,
      identity_row.stability_kind,
      identity_row.ephemeral_raw_inbound_event_id,
      identity_row.ephemeral_normalized_inbound_event_id,
      identity_row.declaration_contract_id,
      identity_row.declaration_contract_version,
      identity_row.declaration_surface_id,
      identity_row.declaration_loaded_by_trusted_service_id,
      identity_row.declaration_loaded_at,
      identity_row.materialized_at,
      identity_row.created_at
    into
      actor_scope_kind,
      actor_scope_source_connection_id,
      actor_scope_source_account_id,
      actor_stability_kind,
      actor_ephemeral_raw_event_id,
      actor_ephemeral_normalized_event_id,
      actor_declaration_contract_id,
      actor_declaration_contract_version,
      actor_declaration_surface_id,
      actor_declaration_loaded_by_trusted_service_id,
      actor_declaration_loaded_at,
      actor_materialized_at,
      actor_created_at
    from public.inbox_v2_source_external_identities identity_row
    where identity_row.tenant_id = new.tenant_id
      and identity_row.id = new.provider_actor_source_external_identity_id
    for share;

    if not found
       or actor_created_at > new.recorded_at
       or actor_declaration_loaded_at > new.recorded_at
       or actor_materialized_at > new.recorded_at
       or (actor_scope_kind = 'source_connection' and
           actor_scope_source_connection_id <> new.source_connection_id)
       or (actor_scope_kind = 'source_account' and
           actor_scope_source_account_id <> new.source_account_id)
       or (
         actor_scope_kind = 'provider'
         and (
           actor_declaration_contract_id <> new.adapter_contract_id
           or actor_declaration_contract_version <> new.adapter_contract_version
           or actor_declaration_surface_id <> new.adapter_surface_id
           or actor_declaration_loaded_by_trusted_service_id <>
              new.adapter_loaded_by_trusted_service_id
         )
       )
       or (
         actor_stability_kind = 'observation_ephemeral'
         and not (
           (
             actor_ephemeral_raw_event_id = new.raw_inbound_event_id
             and actor_ephemeral_normalized_event_id is null
           ) or (
             actor_ephemeral_raw_event_id is null
             and actor_ephemeral_normalized_event_id =
                new.normalized_inbound_event_id
           )
         )
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_occurrence_provider_actor_scope_invalid';
    end if;
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_source_occurrence_guard_resolution_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_occurrence_guard_resolution_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  immutable_old jsonb;
  immutable_new jsonb;
begin
  immutable_old := to_jsonb(old) - array[
    'resolution_state',
    'resolved_external_message_reference_id',
    'resolution_candidate_count',
    'resolution_candidate_digest_sha256',
    'resolution_diagnostic_code_id',
    'resolution_diagnostic_retryable',
    'resolution_diagnostic_correlation_token',
    'resolution_diagnostic_safe_operator_hint_id',
    'message_scope_owner_key',
    'message_key_digest_sha256',
    'revision',
    'updated_at'
  ];
  immutable_new := to_jsonb(new) - array[
    'resolution_state',
    'resolved_external_message_reference_id',
    'resolution_candidate_count',
    'resolution_candidate_digest_sha256',
    'resolution_diagnostic_code_id',
    'resolution_diagnostic_retryable',
    'resolution_diagnostic_correlation_token',
    'resolution_diagnostic_safe_operator_hint_id',
    'message_scope_owner_key',
    'message_key_digest_sha256',
    'revision',
    'updated_at'
  ];

  if immutable_old <> immutable_new
     or old.resolution_state = 'resolved'
     or new.resolution_state = 'pending'
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.source_occurrence_resolution_cas_conflict';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_source_occurrence_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_occurrence_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row
       where tenant_row.id = old_row->>'tenant_id'
    ) then
      return old;
    end if;

    if tg_table_name <>
       'inbox_v2_source_occurrences'
       and not exists (
         select 1
           from public.inbox_v2_source_occurrences occurrence_row
          where occurrence_row.tenant_id = old_row->>'tenant_id'
            and occurrence_row.id = old_row->>'source_occurrence_id'
       ) then
      return old;
    end if;
  end if;

  raise exception using
    errcode = '23514',
    message = format(
      'inbox_v2.source_occurrence_immutable:%s:%s',
      tg_table_name,
      tg_op
    );
end;
$$;



--
-- Name: inbox_v2_source_occurrence_resolution_deferred(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_occurrence_resolution_deferred() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
begin
  if tg_op <> 'INSERT'
     and tg_table_name <> 'inbox_v2_source_occurrences' then
    perform public.inbox_v2_assert_source_occurrence_resolution(
      old_row->>'tenant_id',
      case when tg_table_name = 'inbox_v2_source_occurrences'
        then old_row->>'id' else old_row->>'source_occurrence_id' end,
      case when tg_table_name = 'inbox_v2_source_occurrences'
        then (old_row->>'revision')::bigint
        else (old_row->>'resulting_revision')::bigint end
    );
  end if;
  if tg_op <> 'DELETE' then
    perform public.inbox_v2_assert_source_occurrence_resolution(
      new_row->>'tenant_id',
      case when tg_table_name = 'inbox_v2_source_occurrences'
        then new_row->>'id' else new_row->>'source_occurrence_id' end,
      case when tg_table_name = 'inbox_v2_source_occurrences'
        then (new_row->>'revision')::bigint
        else (new_row->>'resulting_revision')::bigint end
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_source_occurrence_resolution_guard_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_occurrence_resolution_guard_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  occurrence_row public.inbox_v2_source_occurrences%rowtype;
begin
  select * into occurrence_row
    from public.inbox_v2_source_occurrences candidate_row
   where candidate_row.tenant_id = new.tenant_id
     and candidate_row.id = new.source_occurrence_id
   for update;

  if not found
     or occurrence_row.revision <> new.expected_revision
     or occurrence_row.resolution_state <> new.from_state
     or occurrence_row.resolution_state = 'resolved'
     or occurrence_row.adapter_loaded_by_trusted_service_id <>
        new.resolver_trusted_service_id
     or occurrence_row.updated_at > new.changed_at then
    raise exception using errcode = '40001',
      message = 'inbox_v2.source_occurrence_resolution_transition_cas_conflict';
  end if;

  if new.to_state = 'resolved' and not exists (
    select 1
      from public.inbox_v2_external_message_references reference_row
     where reference_row.tenant_id = new.tenant_id
       and reference_row.id = new.resolved_external_message_reference_id
       and reference_row.realm_id = occurrence_row.message_realm_id
       and reference_row.realm_version = occurrence_row.message_realm_version
       and reference_row.canonicalization_version =
          occurrence_row.message_canonicalization_version
       and reference_row.scope_kind::text =
          occurrence_row.message_scope_kind::text
       and reference_row.scope_source_account_id is not distinct from
          occurrence_row.message_scope_source_account_id
       and reference_row.scope_source_thread_binding_id is not distinct from
          occurrence_row.message_scope_source_thread_binding_id
       and reference_row.object_kind_id = occurrence_row.message_object_kind_id
       and reference_row.external_thread_id = occurrence_row.external_thread_id
       and reference_row.canonical_external_subject =
          occurrence_row.canonical_external_subject
       and reference_row.message_key_digest_sha256 =
          occurrence_row.message_key_digest_sha256
     for share
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_occurrence_resolved_reference_key_mismatch';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_source_onboarding_canonical_json_text(jsonb); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_onboarding_canonical_json_text(value jsonb) RETURNS text
    LANGUAGE plpgsql IMMUTABLE STRICT PARALLEL SAFE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  value_kind text := jsonb_typeof(value);
  canonical_text text;
begin
  case value_kind
    when 'object' then
      select '{' || coalesce(string_agg(
        to_json(object_entry.key)::text || ':' ||
          public.inbox_v2_source_onboarding_canonical_json_text(
            object_entry.value
          ),
        ',' order by object_entry.key collate "C"
      ), '') || '}'
        into canonical_text
        from jsonb_each(value) object_entry;
      return canonical_text;
    when 'array' then
      select '[' || coalesce(string_agg(
        public.inbox_v2_source_onboarding_canonical_json_text(array_entry.value),
        ',' order by array_entry.ordinality
      ), '') || ']'
        into canonical_text
        from jsonb_array_elements(value) with ordinality array_entry;
      return canonical_text;
    when 'string' then
      return to_json(value #>> '{}')::text;
    when 'boolean' then
      return value::text;
    when 'null' then
      return 'null';
    else
      raise exception using errcode = '23514',
        message = 'inbox_v2.source_onboarding_numeric_json_forbidden';
  end case;
end
$$;



--
-- Name: inbox_v2_source_onboarding_result_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_onboarding_result_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  v_tenant_id text;
  v_mutation_id text;
  v_commit public.inbox_v2_auth_mutation_commits%rowtype;
  v_command public.inbox_v2_auth_command_records%rowtype;
  v_stream public.inbox_v2_tenant_stream_commits%rowtype;
  v_audit public.inbox_v2_auth_audit_events%rowtype;
  v_result public.inbox_v2_source_onboarding_result_snapshots%rowtype;
  v_transition public.inbox_v2_source_registry_transitions%rowtype;
  v_connection public.source_connections%rowtype;
  v_result_count integer;
  v_change_count integer;
  v_facet_count integer;
begin
  v_tenant_id := coalesce(new.tenant_id, old.tenant_id);
  v_mutation_id := coalesce(new.mutation_id, old.mutation_id);

  select * into v_commit
    from public.inbox_v2_auth_mutation_commits commit_row
   where commit_row.tenant_id = v_tenant_id
     and commit_row.mutation_id = v_mutation_id;
  if not found then
    if tg_op = 'DELETE' then
      if not exists (
        select 1 from public.tenants tenant_row
         where tenant_row.id = old.tenant_id
      ) then
        return old;
      end if;
      if not exists (
        select 1 from public.inbox_v2_auth_command_records command_row
         where command_row.tenant_id = old.tenant_id
           and (
             command_row.id = old.command_record_id
             or command_row.result_reference->>'recordId' = old.id
           )
      ) and exists (
        select 1
          from public.inbox_v2_tenant_stream_commits stream_row
          join public.inbox_v2_tenant_stream_heads head_row
            on head_row.tenant_id = stream_row.tenant_id
           and head_row.stream_epoch = stream_row.stream_epoch
         where stream_row.tenant_id = old.tenant_id
           and stream_row.id = old.stream_commit_id
           and stream_row.mutation_id = old.mutation_id
           and stream_row.command_ids @>
             jsonb_build_array(old.command_record_id)
           and stream_row.position < head_row.min_retained_position
           and exists (
             select 1
               from public.inbox_v2_tenant_stream_retention_advances
                 advance_row
              where advance_row.tenant_id = stream_row.tenant_id
                and advance_row.stream_epoch = stream_row.stream_epoch
                and stream_row.position >=
                  greatest(advance_row.from_position, 1)
                and stream_row.position < advance_row.to_position
                and advance_row.to_position <=
                  head_row.min_retained_position
                and advance_row.resulting_head_revision <= head_row.revision
           )
      ) and not exists (
        select 1 from public.inbox_v2_tenant_stream_changes change_row
         where change_row.tenant_id = old.tenant_id
           and (
             change_row.stream_commit_id = old.stream_commit_id
             or change_row.mutation_id = old.mutation_id
             or change_row.payload_reference->>'recordId' = old.id
             or change_row.domain_commit_reference->>'recordId' = old.id
           )
      ) and not exists (
        select 1 from public.inbox_v2_domain_events event_row
         where event_row.tenant_id = old.tenant_id
           and (
             event_row.stream_commit_id = old.stream_commit_id
             or event_row.mutation_id = old.mutation_id
             or event_row.command_ids @>
               jsonb_build_array(old.command_record_id)
             or event_row.payload_reference->>'recordId' = old.id
           )
      ) and not exists (
        select 1 from public.inbox_v2_outbox_intents intent_row
         where intent_row.tenant_id = old.tenant_id
           and (
             intent_row.stream_commit_id = old.stream_commit_id
             or intent_row.mutation_id = old.mutation_id
             or intent_row.payload_reference->>'recordId' = old.id
           )
      ) and not exists (
        select 1 from public.inbox_v2_outbox_work_items work_row
         where work_row.tenant_id = old.tenant_id
           and work_row.terminal_result_reference->>'recordId' = old.id
      ) and not exists (
        select 1 from public.inbox_v2_outbox_outcomes outcome_row
         where outcome_row.tenant_id = old.tenant_id
           and outcome_row.result_reference->>'recordId' = old.id
      ) and not exists (
        select 1 from public.inbox_v2_auth_audit_events audit_row
         where audit_row.tenant_id = old.tenant_id
           and (
             audit_row.mutation_id = old.mutation_id
             or audit_row.command_record_id = old.command_record_id
             or audit_row.internal_target_ref = old.audit_target_ref
             or audit_row.evidence_reference->>'recordId' = old.id
           )
      ) and not exists (
        select 1 from public.inbox_v2_auth_audit_facets facet_row
         where facet_row.tenant_id = old.tenant_id
           and facet_row.internal_entity_ref = old.tenant_facet_ref
      ) then
        return old;
      end if;
      raise exception using errcode = '23514',
        message = 'inbox_v2.source_onboarding_result_delete_forbidden';
    end if;
    return new;
  end if;

  if tg_op = 'DELETE' then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_onboarding_result_delete_forbidden';
  end if;

  select * into strict v_command
    from public.inbox_v2_auth_command_records command_row
   where command_row.tenant_id = v_commit.tenant_id
     and command_row.id = v_commit.command_record_id
     and command_row.mutation_id = v_commit.mutation_id;
  select count(*)::integer into v_result_count
    from public.inbox_v2_source_onboarding_result_snapshots result_row
   where result_row.tenant_id = v_commit.tenant_id
     and result_row.mutation_id = v_commit.mutation_id;

  if v_command.command_type_id <> 'core:source-connection.create' then
    if v_result_count <> 0 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.source_onboarding_result_wrong_command';
    end if;
    if tg_op = 'DELETE' then return old; end if;
    return new;
  end if;
  if v_result_count <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_onboarding_result_missing';
  end if;

  select * into strict v_result
    from public.inbox_v2_source_onboarding_result_snapshots result_row
   where result_row.tenant_id = v_commit.tenant_id
     and result_row.mutation_id = v_commit.mutation_id;
  select * into strict v_stream
    from public.inbox_v2_tenant_stream_commits stream_row
   where stream_row.tenant_id = v_commit.tenant_id
     and stream_row.id = v_commit.stream_commit_id
     and stream_row.mutation_id = v_commit.mutation_id;
  select * into strict v_audit
    from public.inbox_v2_auth_audit_events audit_row
   where audit_row.tenant_id = v_commit.tenant_id
     and audit_row.id = v_commit.audit_event_id
     and audit_row.mutation_id = v_commit.mutation_id;
  select * into strict v_transition
    from public.inbox_v2_source_registry_transitions transition_row
   where transition_row.tenant_id = v_result.tenant_id
     and transition_row.transition_id = v_result.source_transition_id
     and transition_row.authority_id = v_result.source_connection_id
     and transition_row.resulting_revision = v_result.source_registry_revision;
  select * into strict v_connection
    from public.source_connections connection_row
   where connection_row.tenant_id = v_result.tenant_id
     and connection_row.id = v_result.source_connection_id;

  perform public.inbox_v2_assert_source_registry_lineage(
    v_result.tenant_id,
    v_result.registry_id,
    v_result.registry_revision,
    v_result.registry_composition_hash,
    v_result.data_class_id,
    v_result.storage_root_id,
    v_result.purpose_id,
    v_result.canonical_anchor_id,
    v_result.lineage_revision,
    v_result.effective_policy_id,
    v_result.effective_policy_version,
    v_result.effective_rule_id,
    v_result.effective_rule_revision,
    v_result.policy_activation_id,
    v_result.policy_activation_revision,
    v_result.policy_activation_head_revision,
    v_result.legal_hold_set_revision,
    v_result.restriction_set_revision,
    true
  );

  if v_command.public_result_code <> 'core:source-connection.created'
     or v_command.result_reference is distinct from jsonb_build_object(
       'tenantId', v_result.tenant_id,
       'recordId', v_result.id,
       'schemaId', 'core:inbox-v2.source-onboarding-result',
       'schemaVersion', 'v1',
       'digest', v_result.result_digest_sha256
     )
     or v_command.sensitive_result_reference is not null
     or v_result.copy_slot <> 'source_onboarding_result_snapshot'
     or v_result.data_class_id <>
        'core:source_account_connector_metadata'
     or v_result.storage_root_id <> 'core:source-registry-sql'
     or v_result.purpose_id <> 'core:source_replay_and_diagnostics'
     or v_result.canonical_anchor_id <>
        'core:disconnect_or_account_termination'
     or v_result.registry_id is distinct from
        v_result.state_payload->'payload'->'lifecycle'->'registry'->>'id'
     or v_result.registry_revision::text is distinct from
        v_result.state_payload->'payload'->'lifecycle'->'registry'->>'revision'
     or 'sha256:' || v_result.registry_composition_hash is distinct from
        v_result.state_payload->'payload'->'lifecycle'->'registry'->>
          'compositionHash'
     or v_result.command_record_id <> v_command.id
     or v_result.client_mutation_id <> v_command.client_mutation_id
     or v_result.stream_commit_id <> v_stream.id
     or v_result.created_at <> v_commit.committed_at
     or v_result.created_at <> v_stream.committed_at
     or v_result.created_at <> v_audit.recorded_at
     or v_result.audit_target_ref <> v_audit.internal_target_ref
     or public.inbox_v2_source_onboarding_canonical_json_text(
          v_result.result_canonical_json::jsonb
        ) is distinct from v_result.result_canonical_json
     or public.inbox_v2_source_onboarding_canonical_json_text(
          v_result.state_payload
        ) is distinct from v_result.state_canonical_json
     or public.inbox_v2_source_onboarding_canonical_json_text(
          v_result.transition_payload
        ) is distinct from v_result.transition_canonical_json
     or jsonb_typeof(v_result.result_canonical_json::jsonb) <> 'object'
     or (v_result.result_canonical_json::jsonb ?&
          array['protocol', 'connection']::text[]) is not true
     or (v_result.result_canonical_json::jsonb -
          array['protocol', 'connection']::text[]) <> '{}'::jsonb
     or jsonb_typeof(
          v_result.result_canonical_json::jsonb->'connection'
        ) <> 'object'
     or ((v_result.result_canonical_json::jsonb->'connection') ?& array[
          'id', 'tenantId', 'sourceType', 'sourceName', 'displayName',
          'status', 'authType', 'capabilities', 'config', 'diagnostics',
          'metadata', 'createdByEmployeeId', 'createdAt', 'updatedAt'
        ]::text[]) is not true
     or ((v_result.result_canonical_json::jsonb->'connection') - array[
          'id', 'tenantId', 'sourceType', 'sourceName', 'displayName',
          'status', 'authType', 'capabilities', 'config', 'diagnostics',
          'metadata', 'createdByEmployeeId', 'createdAt', 'updatedAt'
        ]::text[]) <> '{}'::jsonb
     or v_result.result_canonical_json::jsonb->>'protocol' is distinct from
        'core:inbox-v2.source-onboarding-result@v1'
     or v_result.result_canonical_json::jsonb->'connection'->>'id'
        is distinct from v_result.source_connection_id
     or v_result.result_canonical_json::jsonb->'connection'->>'tenantId'
        is distinct from v_result.tenant_id
     or v_result.result_canonical_json::jsonb->'connection'->>'sourceType'
        is distinct from v_result.source_type
     or v_result.result_canonical_json::jsonb->'connection'->>'sourceName'
        is distinct from v_result.source_name
     or v_result.result_canonical_json::jsonb->'connection'->>'displayName'
        is distinct from v_result.display_name
     or v_result.result_canonical_json::jsonb->'connection'->>'status'
        is distinct from v_result.status
     or v_result.result_canonical_json::jsonb->'connection'->>'authType'
        is distinct from v_result.auth_type
     or v_result.result_canonical_json::jsonb->'connection'->>'createdByEmployeeId'
        is distinct from v_result.created_by_employee_id
     or v_result.result_canonical_json::jsonb->'connection'->'capabilities'
        is distinct from '{}'::jsonb
     or v_result.result_canonical_json::jsonb->'connection'->'config'
        is distinct from '{}'::jsonb
     or v_result.result_canonical_json::jsonb->'connection'->'diagnostics'
        is distinct from '{}'::jsonb
     or v_result.result_canonical_json::jsonb->'connection'->'metadata'
        is distinct from '{}'::jsonb
     or v_result.result_canonical_json::jsonb->'connection'->'createdAt'
        is distinct from v_result.transition_payload->'payload'->'committedAt'
     or v_result.result_canonical_json::jsonb->'connection'->'updatedAt'
        is distinct from v_result.transition_payload->'payload'->'committedAt'
     or (v_result.result_canonical_json::jsonb->'connection'->>'createdAt')::timestamptz
        is distinct from v_result.connection_created_at
     or (v_result.result_canonical_json::jsonb->'connection'->>'updatedAt')::timestamptz
        is distinct from v_result.connection_updated_at
     or v_audit.grant_source_ids <> array(
       select mapping->>'internalReference'
         from jsonb_array_elements(v_result.grant_source_mappings) mapping
        order by mapping->>'internalReference'
     )
     or exists (
       select 1
         from jsonb_array_elements(v_result.grant_source_mappings) mapping
         where jsonb_typeof(mapping) <> 'object'
            or (mapping ?& array[
              'internalReference', 'authorizationDecisionId'
            ]::text[]) is not true
            or jsonb_typeof(mapping->'internalReference') <> 'string'
            or jsonb_typeof(mapping->'authorizationDecisionId') <> 'string'
           or (mapping - array[
             'internalReference', 'authorizationDecisionId'
           ]::text[]) <> '{}'::jsonb
           or mapping->>'internalReference' !~
             '^internal-ref:[a-f0-9]{64}$'
           or not exists (
             select 1
               from jsonb_array_elements(
                 v_command.authorization_decision_refs
               ) decision_ref
              where decision_ref->>'id' =
                mapping->>'authorizationDecisionId'
           )
     )
     or (select count(*) from jsonb_array_elements(
           v_result.grant_source_mappings
         )) <>
        (select count(distinct mapping->>'internalReference')
           from jsonb_array_elements(
              v_result.grant_source_mappings
            ) mapping)
     or (select count(*) from jsonb_array_elements(
           v_result.grant_source_mappings
         )) <>
        (select count(distinct mapping->>'authorizationDecisionId')
           from jsonb_array_elements(
             v_result.grant_source_mappings
           ) mapping)
     or v_transition.intent <> 'create'
     or v_transition.authority_kind <> 'source_connection'
     or v_transition.resulting_revision <> 1
     or v_transition.occurred_at <> v_result.created_at
     or v_result.transition_digest_sha256 <>
        'sha256:' || v_transition.transition_digest_sha256
     or row(v_result.source_type, v_result.source_name,
            v_result.display_name, v_result.status, v_result.auth_type,
            v_result.created_by_employee_id,
            v_result.connection_created_at,
            v_result.connection_updated_at)
        is distinct from
        row(v_connection.source_type, v_connection.source_name,
            v_connection.display_name, v_connection.status,
            v_connection.auth_type, v_connection.created_by_employee_id,
            v_connection.created_at, v_connection.updated_at)
     or v_result.state_payload->>'schemaId' is distinct from
        'core:inbox-v2.source-connection-registry-state'
     or v_result.state_payload->>'schemaVersion' is distinct from 'v1'
     or v_result.state_payload->'payload'->>'tenantId' is distinct from
        v_result.tenant_id
     or v_result.state_payload->'payload'->>'entityKind' is distinct from
        'source_connection'
     or v_result.state_payload->'payload'->'sourceConnection'->>'tenantId'
        is distinct from v_result.tenant_id
     or v_result.state_payload->'payload'->'sourceConnection'->>'id'
        is distinct from v_result.source_connection_id
     or v_result.state_payload->'payload'->>'sourceName' is distinct from
        v_result.source_name
     or v_result.state_payload->'payload'->>'displayName' is distinct from
        v_result.display_name
     or v_result.state_payload->'payload'->>'revision' is distinct from '1'
     or v_result.state_payload->'payload'->>'status' is distinct from 'pending'
     or v_result.state_payload->'payload'->'createdBy'->>'kind'
        is distinct from 'employee'
     or v_result.state_payload->'payload'->'createdBy'->'employee'->>'tenantId'
        is distinct from v_result.tenant_id
     or v_result.state_payload->'payload'->'createdBy'->'employee'->>'id'
        is distinct from v_result.created_by_employee_id
     or v_result.transition_payload->'payload'->'cas'->'expectedRevision'
        is distinct from 'null'::jsonb
     or v_result.transition_payload->'payload'->'cas'->'expectedRouteGeneration'
        is distinct from 'null'::jsonb
     or v_result.transition_payload->'payload'->'cas'->>'resultingRevision'
        is distinct from '1'
     or v_result.transition_payload->'payload'->'cas'->>'resultingRouteGeneration'
        is distinct from '1'
     or v_result.transition_payload->'payload'->'previousState'
        is distinct from 'null'::jsonb
     or v_result.transition_payload->'payload'->'lifecycle'
        is distinct from v_result.state_payload->'payload'->'lifecycle'
     or v_result.transition_payload->'payload'->'actor'
        is distinct from v_result.state_payload->'payload'->'createdBy'
     or v_result.transition_payload->'payload'->'committedAt'
        is distinct from v_result.state_payload->'payload'->'createdAt'
     or v_result.transition_payload->'payload'->'committedAt'
        is distinct from v_result.state_payload->'payload'->'updatedAt'
     or v_result.transition_payload->>'schemaId' is distinct from
        'core:inbox-v2.source-registry-transition'
     or v_result.transition_payload->>'schemaVersion' is distinct from 'v1'
     or v_result.transition_payload->'payload'->>'tenantId' is distinct from
        v_result.tenant_id
     or v_result.transition_payload->'payload'->>'entityKind' is distinct from
        'source_connection'
     or v_result.transition_payload->'payload'->>'intent' is distinct from
        'create'
     or v_result.transition_payload->'payload'->>'transitionId'
        is distinct from v_result.source_transition_id
     or v_result.transition_payload->'payload'->'resultingState'
        is distinct from v_result.state_payload then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_onboarding_result_mismatch';
  end if;

  select count(*)::integer into v_change_count
    from public.inbox_v2_tenant_stream_changes change_row
   where change_row.tenant_id = v_result.tenant_id
     and change_row.stream_commit_id = v_result.stream_commit_id
     and change_row.mutation_id = v_result.mutation_id
     and change_row.entity_type_id = 'core:source-connection'
     and change_row.entity_id = v_result.source_connection_id
     and change_row.payload_reference = jsonb_build_object(
       'tenantId', v_result.tenant_id,
       'recordId', v_result.id,
       'schemaId', v_result.state_payload->>'schemaId',
       'schemaVersion', v_result.state_payload->>'schemaVersion',
       'digest', v_result.state_digest_sha256
     )
     and change_row.domain_commit_reference = jsonb_build_object(
       'tenantId', v_result.tenant_id,
       'recordId', v_result.id,
       'schemaId', v_result.transition_payload->>'schemaId',
       'schemaVersion', v_result.transition_payload->>'schemaVersion',
       'digest', v_result.transition_digest_sha256
     );
  select count(*)::integer into v_facet_count
    from public.inbox_v2_auth_audit_facets facet_row
   where facet_row.tenant_id = v_result.tenant_id
     and facet_row.audit_event_id = v_audit.id
     and facet_row.dimension = 'tenant'
     and facet_row.internal_entity_ref = v_result.tenant_facet_ref;
  if v_change_count <> 1 or v_facet_count <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_onboarding_result_reference_mismatch';
  end if;
  if tg_op = 'DELETE' then return old; end if;
  return new;
end
$_$;



--
-- Name: inbox_v2_source_onboarding_result_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_onboarding_result_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  raise exception using errcode = '55000',
    message = 'inbox_v2.source_onboarding_result_immutable';
end
$$;



--
-- Name: inbox_v2_source_onboarding_terminal_payload_ref_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_onboarding_terminal_payload_ref_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if exists (
    select 1
      from public.inbox_v2_outbox_terminal_payload_refs payload_row
     where payload_row.tenant_id = old.tenant_id
       and payload_row.result_reference->>'recordId' = old.id
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.source_onboarding_result_delete_forbidden';
  end if;
  return old;
end;
$$;



--
-- Name: inbox_v2_source_raw_admission_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_raw_admission_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       )
       or old.state <> 'skeleton_handed_off'
       or clock_timestamp() < old.guarantee_until then
      raise exception 'Raw admission is not retention eligible'
        using errcode = '23514';
    end if;
    return old;
  end if;

  if tg_op = 'INSERT' then
    if new.state <> 'skeleton_pending'
       or new.terminal_skeleton_id is not null
       or new.terminal_outcome_hmac_sha256 is not null
       or new.skeleton_handed_off_at is not null
       or new.revision <> 1
       or new.updated_at <> new.created_at then
      raise exception 'Raw admission must start skeleton_pending at revision one'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if new.tenant_id <> old.tenant_id
     or new.purpose_id <> old.purpose_id
     or new.key_generation <> old.key_generation
     or new.hmac_key_secret_ref <> old.hmac_key_secret_ref
     or new.identity_hmac_sha256 <> old.identity_hmac_sha256
     or new.identity_kind <> old.identity_kind
     or new.source_connection_id <> old.source_connection_id
     or new.source_account_id is distinct from old.source_account_id
     or new.source_account_scope_key <> old.source_account_scope_key
     or new.raw_event_id <> old.raw_event_id
     or new.safe_envelope_digest_sha256 <> old.safe_envelope_digest_sha256
     or new.guarantee_until <> old.guarantee_until
     or new.created_at <> old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception 'Raw admission mutation requires immutable identity and +1 CAS'
      using errcode = '23514';
  end if;

  if old.state = 'skeleton_pending'
     and new.state = 'skeleton_handed_off'
     and new.terminal_skeleton_id is not null
     and new.terminal_outcome_hmac_sha256 is not null
     and new.skeleton_handed_off_at = new.updated_at
     and new.skeleton_handed_off_at >= old.created_at then
    return new;
  end if;

  raise exception 'Illegal raw admission state transition'
    using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_source_raw_assert_aggregate(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_raw_assert_aggregate() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_raw_event_id text;
  v_anchor public.raw_inbound_events%rowtype;
  v_envelope public.inbox_v2_source_raw_envelopes%rowtype;
  v_work_count bigint;
  v_payload_count bigint;
  v_header_count bigint;
  v_admission_count bigint;
begin
  v_tenant_id := new.tenant_id;
  if tg_table_name = 'raw_inbound_events' then
    v_raw_event_id := new.id;
  else
    v_raw_event_id := new.raw_event_id;
  end if;

  select * into v_anchor
    from public.raw_inbound_events r
   where r.tenant_id = v_tenant_id and r.id = v_raw_event_id;
  select * into v_envelope
    from public.inbox_v2_source_raw_envelopes e
   where e.tenant_id = v_tenant_id and e.raw_event_id = v_raw_event_id;

  if v_envelope.raw_event_id is null then
    if v_anchor.id is not null
       and v_anchor.idempotency_key like 'source:v2:raw:%' then
      raise exception 'V2 raw anchor requires an immutable envelope'
        using errcode = '23514';
    end if;
    return null;
  end if;

  if v_anchor.id is null
     or v_anchor.source_connection_id <> v_envelope.source_connection_id
     or v_anchor.source_account_scope_key <>
        v_envelope.source_account_scope_key
     or v_anchor.idempotency_key <> v_envelope.idempotency_key
     or v_anchor.received_at <> v_envelope.accepted_at
     or v_anchor.external_event_id is not null
     or v_anchor.event_signature is not null
     or v_anchor.payload <> '{}'::jsonb
     or v_anchor.headers <> '{}'::jsonb
     or v_anchor.processing_status <> 'ignored'
     or v_anchor.error_code is not null
     or v_anchor.error_message is not null then
    raise exception 'V2 raw compatibility anchor contains unsafe or incoherent data'
      using errcode = '23514';
  end if;

  select count(*) into v_work_count
    from public.inbox_v2_source_raw_work_items w
   where w.tenant_id = v_tenant_id and w.raw_event_id = v_raw_event_id;
  select count(*) filter (where e.evidence_kind = 'provider_payload'),
         count(*) filter (where e.evidence_kind = 'allowed_headers')
    into v_payload_count, v_header_count
    from public.inbox_v2_source_raw_evidence e
   where e.tenant_id = v_tenant_id and e.raw_event_id = v_raw_event_id;
  select count(*) into v_admission_count
    from public.inbox_v2_source_raw_admissions admission
   where admission.tenant_id = v_tenant_id
     and admission.raw_event_id = v_raw_event_id
     and admission.safe_envelope_digest_sha256 =
       v_envelope.safe_envelope_digest_sha256;

  if v_work_count <> 1
     or (
       v_envelope.event_identity_digest_sha256 like 'hmac-sha256:%'
       and v_admission_count <> 1
     )
     or (
       v_envelope.event_identity_digest_sha256 like 'sha256:%'
       and v_admission_count <> 0
     )
     or (
       tg_table_name <> 'inbox_v2_source_raw_work_items'
       and (
         (v_envelope.provider_payload_evidence_present and v_payload_count <> 1)
         or (not v_envelope.provider_payload_evidence_present and v_payload_count <> 0)
         or (v_envelope.allowed_headers_evidence_present and v_header_count <> 1)
         or (not v_envelope.allowed_headers_evidence_present and v_header_count <> 0)
       )
     ) then
    raise exception 'V2 raw aggregate requires one work head and exact evidence flags'
      using errcode = '23514';
  end if;

  return null;
end
$$;



--
-- Name: inbox_v2_source_raw_evidence_delete_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_raw_evidence_delete_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if exists (
    select 1
      from public.inbox_v2_source_raw_work_items work_row
     where work_row.tenant_id = old.tenant_id
       and work_row.raw_event_id = old.raw_event_id
  ) then
    raise exception 'Raw source evidence cannot be purged before normalization completes'
      using errcode = '23514';
  end if;
  return old;
end
$$;



--
-- Name: inbox_v2_source_raw_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_raw_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_table_name = 'inbox_v2_source_raw_quarantines'
     and tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       )
       or old.event_identity_digest_sha256 not like 'hmac-sha256:%'
       or old.event_identity_key_generation is null
       or old.event_identity_hmac_key_secret_ref is null
       or old.event_identity_guarantee_until is null
       or clock_timestamp() < old.event_identity_guarantee_until then
      raise exception 'Raw quarantine is not retention eligible'
        using errcode = '23514';
    end if;
    return old;
  end if;
  if tg_table_name = 'inbox_v2_source_raw_evidence' and tg_op = 'DELETE' then
    if exists (
      select 1
        from public.inbox_v2_source_raw_admissions admission
       where admission.tenant_id = old.tenant_id
         and admission.raw_event_id = old.raw_event_id
         and admission.state = 'skeleton_pending'
    ) then
      raise exception 'Raw evidence cannot compact before skeleton handoff'
        using errcode = '23514';
    end if;
    return old;
  end if;
  raise exception '% is immutable', tg_table_name using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_source_raw_work_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_raw_work_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    raise exception 'Raw work head cannot be deleted' using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.state <> 'pending'
       or new.attempt_count <> 0
       or new.reclaim_count <> 0
       or new.revision <> 1
       or new.available_at < new.created_at
       or new.updated_at <> new.created_at then
      raise exception 'Raw work head must start pending at revision one'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if new.tenant_id <> old.tenant_id
     or new.raw_event_id <> old.raw_event_id
     or new.created_at <> old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception 'Raw work mutation requires immutable identity and +1 CAS'
      using errcode = '23514';
  end if;

  if old.state = 'pending' and new.state = 'leased' then
    if new.available_at <> old.available_at
       or old.available_at > new.lease_claimed_at
       or new.lease_claimed_at <> new.updated_at
       or new.attempt_count <> old.attempt_count + 1
       or new.reclaim_count <> old.reclaim_count
       or new.last_reclaimed_at is distinct from old.last_reclaimed_at
       or new.last_reclaimed_from_expires_at is distinct from
          old.last_reclaimed_from_expires_at
       or new.last_reclaimed_lease_owner_id is distinct from
          old.last_reclaimed_lease_owner_id
       or new.last_reclaimed_lease_token_hash is distinct from
          old.last_reclaimed_lease_token_hash
       or new.last_reclaimed_lease_revision is distinct from
          old.last_reclaimed_lease_revision then
      raise exception 'Pending raw work requires one exact due claim'
        using errcode = '23514';
    end if;
  elsif old.state = 'leased' and new.state = 'leased' then
    if new.lease_claimed_at >= old.lease_expires_at then
      if new.available_at <> old.available_at
         or new.lease_claimed_at <> new.updated_at
         or new.attempt_count <> old.attempt_count + 1
         or new.reclaim_count <> old.reclaim_count + 1
         or new.last_reclaimed_at <> new.lease_claimed_at
         or new.last_reclaimed_from_expires_at <> old.lease_expires_at
         or new.last_reclaimed_lease_owner_id <> old.lease_owner_id
         or new.last_reclaimed_lease_token_hash <> old.lease_token_hash
         or new.last_reclaimed_lease_revision <> old.lease_revision then
        raise exception 'Expired raw lease requires exact fenced reclaim evidence'
          using errcode = '23514';
      end if;
    elsif new.lease_owner_id = old.lease_owner_id
       and new.lease_token_hash = old.lease_token_hash
       and new.lease_claimed_at = old.lease_claimed_at then
      if new.updated_at >= old.lease_expires_at
         or new.lease_expires_at <= old.lease_expires_at
         or new.available_at <> old.available_at
         or new.attempt_count <> old.attempt_count
         or new.reclaim_count <> old.reclaim_count
         or new.last_reclaimed_at is distinct from old.last_reclaimed_at
         or new.last_reclaimed_from_expires_at is distinct from
            old.last_reclaimed_from_expires_at
         or new.last_reclaimed_lease_owner_id is distinct from
            old.last_reclaimed_lease_owner_id
         or new.last_reclaimed_lease_token_hash is distinct from
            old.last_reclaimed_lease_token_hash
         or new.last_reclaimed_lease_revision is distinct from
            old.last_reclaimed_lease_revision then
        raise exception 'Raw lease renewal requires the unexpired exact lease'
          using errcode = '23514';
      end if;
    else
      raise exception 'Raw lease cannot be replaced before expiry'
        using errcode = '23514';
    end if;
  elsif old.state = 'leased' and new.state = 'pending' then
    if new.updated_at >= old.lease_expires_at
       or new.available_at < new.updated_at
       or new.attempt_count <> old.attempt_count
       or new.reclaim_count <> old.reclaim_count
       or new.last_reclaimed_at is distinct from old.last_reclaimed_at
       or new.last_reclaimed_from_expires_at is distinct from
          old.last_reclaimed_from_expires_at
       or new.last_reclaimed_lease_owner_id is distinct from
          old.last_reclaimed_lease_owner_id
       or new.last_reclaimed_lease_token_hash is distinct from
          old.last_reclaimed_lease_token_hash
       or new.last_reclaimed_lease_revision is distinct from
          old.last_reclaimed_lease_revision then
      raise exception 'Raw lease release requires the unexpired exact lease'
        using errcode = '23514';
    end if;
  else
    raise exception 'Illegal raw work state transition' using errcode = '23514';
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_source_reconciliation_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_reconciliation_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE'
     and pg_trigger_depth() > 1
     and not exists (
       select 1 from public.tenants tenant_row
       where tenant_row.id = old.tenant_id
     ) then
    return old;
  end if;
  raise exception using
    errcode = '23514',
    message = format(
      'inbox_v2.source_reconciliation_immutable:%s:%s',
      tg_table_name,
      tg_op
    );
end
$$;



--
-- Name: inbox_v2_source_registry_account_fence_deferred(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_registry_account_fence_deferred() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  changed_row jsonb;
  checked_tenant_id text;
  checked_source_account_id text;
begin
  changed_row := case when tg_op = 'DELETE' then to_jsonb(old) else to_jsonb(new) end;
  checked_tenant_id := changed_row->>'tenant_id';
  checked_source_account_id := changed_row->>'source_account_id';

  if checked_source_account_id is null then
    return null;
  end if;

  if exists (
    select 1
      from public.inbox_v2_source_registry_heads head_row
     where head_row.tenant_id = checked_tenant_id
       and head_row.source_account_id = checked_source_account_id
       and head_row.route_authority_state in ('enabled', 'inbound_only')
       and (
         not exists (
           select 1
             from public.inbox_v2_source_account_identities identity_head
            where identity_head.tenant_id = head_row.tenant_id
              and identity_head.source_account_id = head_row.source_account_id
              and identity_head.revision = head_row.account_identity_revision
              and identity_head.account_generation = head_row.account_generation
              and identity_head.state = 'verified'
              and identity_head.canonical_key_digest_sha256 = head_row.account_canonical_key_digest_sha256
         )
         or not exists (
           select 1
             from public.inbox_v2_auth_resource_heads access_head
            where access_head.tenant_id = head_row.tenant_id
              and access_head.id = head_row.account_access_resource_head_id
              and access_head.resource_kind = 'source_account'
              and access_head.source_account_id = head_row.source_account_id
              and access_head.resource_access_revision = head_row.account_resource_access_revision
              and access_head.structural_relation_revision = head_row.account_structural_relation_revision
         )
       )
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_routable_account_fence_stale';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_source_registry_artifact_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_registry_artifact_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op <> 'INSERT' then
    raise exception using
      errcode = '55000',
      message = 'inbox_v2.source_registry_artifact_immutable';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_source_registry_assert_transition(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_registry_assert_transition() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  changed_row jsonb;
  checked_tenant_id text;
  checked_authority_id text;
  checked_revision bigint;
  artifact_row record;
  secret_row record;
  route_row record;
  related_row record;
  registry_head record;
begin
  changed_row := case when tg_op = 'DELETE' then to_jsonb(old) else to_jsonb(new) end;
  checked_tenant_id := changed_row->>'tenant_id';
  checked_authority_id := coalesce(
    changed_row->>'parent_authority_id',
    changed_row->>'authority_id'
  );
  checked_revision := coalesce(
    (changed_row->>'revision')::bigint,
    (changed_row->>'resulting_revision')::bigint,
    (changed_row->>'parent_authority_revision')::bigint,
    (changed_row->>'authority_revision')::bigint
  );

  if not exists (
    select 1
      from public.inbox_v2_source_registry_heads head_row
      join public.inbox_v2_source_registry_transitions transition_row
        on transition_row.tenant_id = head_row.tenant_id
       and transition_row.transition_id = head_row.last_transition_id
       and transition_row.authority_id = head_row.authority_id
       and transition_row.resulting_revision = head_row.revision
       and transition_row.expected_revision = head_row.revision - 1
       and transition_row.authority_kind = head_row.authority_kind
       and transition_row.source_connection_id = head_row.source_connection_id
       and transition_row.source_account_id is not distinct from head_row.source_account_id
       and transition_row.connector_id is not distinct from head_row.connector_id
       and transition_row.session_id is not distinct from head_row.session_id
       and transition_row.auth_challenge_id is not distinct from head_row.auth_challenge_id
       and transition_row.to_state = head_row.state
       and transition_row.route_generation = head_row.route_generation
       and transition_row.route_authority_state = head_row.route_authority_state
       and transition_row.route_authority_reason_code_id = head_row.route_authority_reason_code_id
       and transition_row.route_authority_changed_at = head_row.route_authority_changed_at
       and transition_row.account_identity_transition_id is not distinct from head_row.account_identity_transition_id
       and transition_row.account_identity_revision is not distinct from head_row.account_identity_revision
       and transition_row.account_generation is not distinct from head_row.account_generation
       and transition_row.account_identity_state is not distinct from head_row.account_identity_state
       and transition_row.account_identity_fence_digest_sha256 is not distinct from head_row.account_identity_fence_digest_sha256
       and transition_row.account_canonical_key_digest_sha256 is not distinct from head_row.account_canonical_key_digest_sha256
       and transition_row.account_access_resource_head_id is not distinct from head_row.account_access_resource_head_id
       and transition_row.account_resource_access_revision is not distinct from head_row.account_resource_access_revision
       and transition_row.account_structural_relation_revision is not distinct from head_row.account_structural_relation_revision
       and transition_row.adapter_contract_id = head_row.adapter_contract_id
       and transition_row.adapter_contract_version = head_row.adapter_contract_version
       and transition_row.adapter_declaration_revision = head_row.adapter_declaration_revision
       and transition_row.adapter_surface_id = head_row.adapter_surface_id
       and transition_row.adapter_loaded_by_trusted_service_id = head_row.adapter_loaded_by_trusted_service_id
       and transition_row.adapter_loaded_at = head_row.adapter_loaded_at
       and transition_row.adapter_handler_id is not distinct from head_row.adapter_handler_id
       and transition_row.authority_copy_slot = head_row.authority_copy_slot
       and transition_row.authority_registry_id = head_row.authority_registry_id
       and transition_row.authority_registry_composition_hash = head_row.authority_registry_composition_hash
       and transition_row.authority_registry_revision = head_row.authority_registry_revision
       and transition_row.authority_data_class_id = head_row.authority_data_class_id
       and transition_row.authority_storage_root_id = head_row.authority_storage_root_id
       and transition_row.authority_purpose_id = head_row.authority_purpose_id
       and transition_row.authority_canonical_anchor_id = head_row.authority_canonical_anchor_id
       and transition_row.authority_lineage_revision = head_row.authority_lineage_revision
       and transition_row.authority_effective_policy_id = head_row.authority_effective_policy_id
       and transition_row.authority_effective_policy_version = head_row.authority_effective_policy_version
       and transition_row.authority_effective_rule_id = head_row.authority_effective_rule_id
       and transition_row.authority_effective_rule_revision = head_row.authority_effective_rule_revision
       and transition_row.authority_policy_activation_id = head_row.authority_policy_activation_id
       and transition_row.authority_policy_activation_revision = head_row.authority_policy_activation_revision
       and transition_row.authority_policy_activation_head_revision = head_row.authority_policy_activation_head_revision
       and transition_row.authority_legal_hold_set_revision = head_row.authority_legal_hold_set_revision
       and transition_row.authority_restriction_set_revision = head_row.authority_restriction_set_revision
       and transition_row.created_by_actor_kind = head_row.created_by_actor_kind
       and transition_row.created_by_employee_id is not distinct from head_row.created_by_employee_id
       and transition_row.created_by_trusted_service_id is not distinct from head_row.created_by_trusted_service_id
       and transition_row.created_by_authorization_epoch is not distinct from head_row.created_by_authorization_epoch
       and transition_row.authority_created_at = head_row.created_at
       and transition_row.occurred_at = head_row.updated_at
     where head_row.tenant_id = checked_tenant_id
       and head_row.authority_id = checked_authority_id
       and head_row.revision = checked_revision
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_head_transition_mismatch';
  end if;

  select *
    into registry_head
    from public.inbox_v2_source_registry_heads head_row
   where head_row.tenant_id = checked_tenant_id
     and head_row.authority_id = checked_authority_id
     and head_row.revision = checked_revision;

  perform public.inbox_v2_assert_source_registry_lineage(
    registry_head.tenant_id,
    registry_head.authority_registry_id,
    registry_head.authority_registry_revision,
    registry_head.authority_registry_composition_hash,
    registry_head.authority_data_class_id,
    registry_head.authority_storage_root_id,
    registry_head.authority_purpose_id,
    registry_head.authority_canonical_anchor_id,
    registry_head.authority_lineage_revision,
    registry_head.authority_effective_policy_id,
    registry_head.authority_effective_policy_version,
    registry_head.authority_effective_rule_id,
    registry_head.authority_effective_rule_revision,
    registry_head.authority_policy_activation_id,
    registry_head.authority_policy_activation_revision,
    registry_head.authority_policy_activation_head_revision,
    registry_head.authority_legal_hold_set_revision,
    registry_head.authority_restriction_set_revision,
    registry_head.authority_kind in (
      'source_connection', 'source_account', 'channel_connector'
    )
  );

  if checked_revision > 1 and not exists (
    select 1
      from public.inbox_v2_source_registry_transitions current_transition
      join public.inbox_v2_source_registry_transitions predecessor
        on predecessor.tenant_id = current_transition.tenant_id
       and predecessor.authority_id = current_transition.authority_id
       and predecessor.resulting_revision = current_transition.expected_revision
       and predecessor.route_generation = current_transition.expected_route_generation
       and predecessor.to_state = current_transition.from_state
       and predecessor.authority_kind = current_transition.authority_kind
       and predecessor.source_connection_id = current_transition.source_connection_id
       and predecessor.source_account_id is not distinct from current_transition.source_account_id
       and predecessor.connector_id is not distinct from current_transition.connector_id
       and predecessor.session_id is not distinct from current_transition.session_id
       and predecessor.auth_challenge_id is not distinct from current_transition.auth_challenge_id
       and predecessor.occurred_at <= current_transition.occurred_at
     where current_transition.tenant_id = checked_tenant_id
       and current_transition.authority_id = checked_authority_id
       and current_transition.resulting_revision = checked_revision
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_transition_predecessor_mismatch';
  end if;

  if exists (
    select 1
      from public.inbox_v2_source_registry_heads head_row
     where head_row.tenant_id = checked_tenant_id
       and head_row.authority_id = checked_authority_id
       and head_row.revision = checked_revision
       and head_row.source_account_id is not null
       and not exists (
         select 1
           from public.inbox_v2_source_account_identity_transitions identity_transition
           join public.inbox_v2_source_account_identities identity_head
             on identity_head.tenant_id = identity_transition.tenant_id
            and identity_head.source_account_id = identity_transition.source_account_id
            and identity_head.revision = identity_transition.resulting_revision
            and identity_head.account_generation = identity_transition.resulting_account_generation
            and identity_head.state = identity_transition.to_state
          where identity_transition.tenant_id = head_row.tenant_id
            and identity_transition.id = head_row.account_identity_transition_id
            and identity_transition.source_account_id = head_row.source_account_id
            and identity_transition.resulting_revision = head_row.account_identity_revision
            and identity_transition.resulting_account_generation = head_row.account_generation
            and identity_transition.to_state = head_row.account_identity_state
            and (
              (head_row.account_identity_state = 'provisional'
                and head_row.account_identity_fence_digest_sha256 = identity_head.provisional_key_digest_sha256)
              or (head_row.account_identity_state = 'verified'
                and head_row.account_identity_fence_digest_sha256 = identity_head.canonical_key_digest_sha256
                and head_row.account_canonical_key_digest_sha256 = identity_head.canonical_key_digest_sha256)
              or (head_row.account_identity_state = 'conflicted'
                and head_row.account_identity_fence_digest_sha256 is not null)
            )
       )
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_identity_fence_stale';
  end if;

  if exists (
    select 1
      from public.inbox_v2_source_registry_heads head_row
     where head_row.tenant_id = checked_tenant_id
       and head_row.authority_id = checked_authority_id
       and head_row.revision = checked_revision
       and head_row.source_account_id is not null
       and head_row.route_authority_state in ('enabled', 'inbound_only')
       and (
         head_row.account_identity_state <> 'verified'
         or not exists (
           select 1
             from public.inbox_v2_source_account_identities identity_head
            where identity_head.tenant_id = head_row.tenant_id
              and identity_head.source_account_id = head_row.source_account_id
              and identity_head.revision = head_row.account_identity_revision
              and identity_head.account_generation = head_row.account_generation
              and identity_head.state = head_row.account_identity_state
              and identity_head.canonical_key_digest_sha256 = head_row.account_canonical_key_digest_sha256
         )
         or not exists (
           select 1
             from public.inbox_v2_auth_resource_heads access_head
            where access_head.tenant_id = head_row.tenant_id
              and access_head.id = head_row.account_access_resource_head_id
              and access_head.resource_kind = 'source_account'
              and access_head.source_account_id = head_row.source_account_id
              and access_head.resource_access_revision = head_row.account_resource_access_revision
              and access_head.structural_relation_revision = head_row.account_structural_relation_revision
         )
       )
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_routable_account_fence_stale';
  end if;

  for artifact_row in
    select *
      from public.inbox_v2_source_registry_artifact_refs
     where tenant_id = checked_tenant_id
       and authority_id = checked_authority_id
       and authority_revision = checked_revision
  loop
    perform public.inbox_v2_assert_source_registry_lineage(
      artifact_row.tenant_id,
      artifact_row.registry_id,
      artifact_row.registry_revision,
      artifact_row.registry_composition_hash,
      artifact_row.data_class_id,
      artifact_row.storage_root_id,
      artifact_row.purpose_id,
      artifact_row.canonical_anchor_id,
      artifact_row.lineage_revision,
      artifact_row.effective_policy_id,
      artifact_row.effective_policy_version,
      artifact_row.effective_rule_id,
      artifact_row.effective_rule_revision,
      artifact_row.policy_activation_id,
      artifact_row.policy_activation_revision,
      artifact_row.policy_activation_head_revision,
      artifact_row.legal_hold_set_revision,
      artifact_row.restriction_set_revision,
      artifact_row.artifact_kind <> 'diagnostic'
    );
  end loop;

  for secret_row in
    select *
      from public.inbox_v2_source_registry_secret_refs
     where tenant_id = checked_tenant_id
       and authority_id = checked_authority_id
       and authority_revision = checked_revision
  loop
    perform public.inbox_v2_assert_source_registry_lineage(
      secret_row.tenant_id,
      secret_row.registry_id,
      secret_row.registry_revision,
      secret_row.registry_composition_hash,
      secret_row.data_class_id,
      secret_row.storage_root_id,
      secret_row.purpose_id,
      secret_row.canonical_anchor_id,
      secret_row.lineage_revision,
      secret_row.effective_policy_id,
      secret_row.effective_policy_version,
      secret_row.effective_rule_id,
      secret_row.effective_rule_revision,
      secret_row.policy_activation_id,
      secret_row.policy_activation_revision,
      secret_row.policy_activation_head_revision,
      secret_row.legal_hold_set_revision,
      secret_row.restriction_set_revision,
      false
    );
  end loop;

  for route_row in
    select *
     from public.inbox_v2_source_registry_ingress_routes
     where tenant_id = checked_tenant_id
       and parent_authority_id = checked_authority_id
       and parent_authority_revision = checked_revision
  loop
    perform public.inbox_v2_assert_source_registry_lineage(
      route_row.tenant_id,
      route_row.registry_id,
      route_row.registry_revision,
      route_row.registry_composition_hash,
      route_row.data_class_id,
      route_row.storage_root_id,
      route_row.purpose_id,
      route_row.canonical_anchor_id,
      route_row.lineage_revision,
      route_row.effective_policy_id,
      route_row.effective_policy_version,
      route_row.effective_rule_id,
      route_row.effective_rule_revision,
      route_row.policy_activation_id,
      route_row.policy_activation_revision,
      route_row.policy_activation_head_revision,
      route_row.legal_hold_set_revision,
      route_row.restriction_set_revision,
      true
    );
    if route_row.adapter_handler_id is distinct from (
      select head_row.adapter_handler_id
        from public.inbox_v2_source_registry_heads head_row
       where head_row.tenant_id = checked_tenant_id
         and head_row.authority_id = checked_authority_id
         and head_row.revision = checked_revision
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_registry_route_adapter_mismatch';
    end if;
  end loop;

  for related_row in
    select *
      from public.inbox_v2_source_registry_related_authority_refs
     where tenant_id = checked_tenant_id
       and parent_authority_id = checked_authority_id
       and parent_authority_revision = checked_revision
  loop
    perform public.inbox_v2_assert_source_registry_lineage(
      related_row.tenant_id,
      related_row.registry_id,
      related_row.registry_revision,
      related_row.registry_composition_hash,
      related_row.data_class_id,
      related_row.storage_root_id,
      related_row.purpose_id,
      related_row.canonical_anchor_id,
      related_row.lineage_revision,
      related_row.effective_policy_id,
      related_row.effective_policy_version,
      related_row.effective_rule_id,
      related_row.effective_rule_revision,
      related_row.policy_activation_id,
      related_row.policy_activation_revision,
      related_row.policy_activation_head_revision,
      related_row.legal_hold_set_revision,
      related_row.restriction_set_revision,
      related_row.kind in ('channel_connector', 'source_ingress_route')
    );

    if related_row.status = 'active' and (
      (related_row.kind = 'channel_connector' and not exists (
        select 1
          from public.inbox_v2_source_registry_heads child_head
         where child_head.tenant_id = related_row.tenant_id
           and child_head.authority_id = related_row.authority_id
           and child_head.revision = related_row.authority_revision
           and child_head.authority_kind = 'channel_connector'
           and child_head.source_connection_id = related_row.source_connection_id
           and child_head.state not in ('replaced', 'deleted')
      ))
      or (related_row.kind = 'channel_session' and not exists (
        select 1
          from public.inbox_v2_source_registry_heads child_head
          join public.inbox_v2_source_registry_heads connector_head
            on connector_head.tenant_id = child_head.tenant_id
           and connector_head.authority_id = related_row.connector_authority_id
           and connector_head.authority_kind = 'channel_connector'
           and connector_head.connector_id = child_head.connector_id
         where child_head.tenant_id = related_row.tenant_id
           and child_head.authority_id = related_row.authority_id
           and child_head.revision = related_row.authority_revision
           and child_head.authority_kind = 'channel_session'
           and child_head.source_connection_id = related_row.source_connection_id
           and child_head.state not in ('replaced', 'deleted')
      ))
      or (related_row.kind = 'channel_session_event' and not exists (
        select 1
          from public.channel_session_events event_row
          join public.inbox_v2_source_registry_heads session_head
            on session_head.tenant_id = event_row.tenant_id
           and session_head.authority_id = related_row.session_authority_id
           and session_head.authority_kind = 'channel_session'
           and session_head.session_id = event_row.session_id
          join public.inbox_v2_source_registry_heads connector_head
            on connector_head.tenant_id = event_row.tenant_id
           and connector_head.authority_id = related_row.connector_authority_id
           and connector_head.authority_kind = 'channel_connector'
           and connector_head.connector_id = event_row.connector_id
         where event_row.tenant_id = related_row.tenant_id
           and event_row.id = related_row.authority_id
           and session_head.source_connection_id = related_row.source_connection_id
           and connector_head.source_connection_id = related_row.source_connection_id
      ))
      or (related_row.kind = 'channel_auth_challenge' and not exists (
        select 1
          from public.inbox_v2_source_registry_heads child_head
          join public.inbox_v2_source_registry_heads connector_head
            on connector_head.tenant_id = child_head.tenant_id
           and connector_head.authority_id = related_row.connector_authority_id
           and connector_head.authority_kind = 'channel_connector'
           and connector_head.connector_id = child_head.connector_id
         where child_head.tenant_id = related_row.tenant_id
           and child_head.authority_id = related_row.authority_id
           and child_head.revision = related_row.authority_revision
           and child_head.authority_kind = 'channel_auth_challenge'
           and child_head.source_connection_id = related_row.source_connection_id
           and child_head.state not in ('replaced', 'deleted')
      ))
      or (related_row.kind = 'source_ingress_route' and not exists (
        select 1
          from public.inbox_v2_source_registry_ingress_routes route_check
         where route_check.tenant_id = related_row.tenant_id
           and route_check.route_id = related_row.authority_id
           and route_check.route_revision = related_row.authority_revision
           and route_check.parent_authority_id = related_row.parent_authority_id
           and route_check.route_generation = related_row.handler_generation
           and route_check.invalidated_at is null
      ))
    ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_registry_related_authority_stale';
    end if;
  end loop;
  return null;
end;
$$;



--
-- Name: inbox_v2_source_registry_child_head_deferred(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_registry_child_head_deferred() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if exists (
    select 1
      from public.inbox_v2_source_registry_related_authority_refs related_row
      join public.inbox_v2_source_registry_heads parent_head
        on parent_head.tenant_id = related_row.tenant_id
       and parent_head.authority_id = related_row.parent_authority_id
       and parent_head.revision = related_row.parent_authority_revision
     where related_row.tenant_id = new.tenant_id
       and related_row.authority_id = new.authority_id
       and related_row.status = 'active'
       and related_row.kind in (
         'channel_connector', 'channel_session', 'channel_auth_challenge'
       )
       and related_row.authority_revision <> new.revision
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_related_authority_stale';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_source_registry_head_after_update(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_registry_head_after_update() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.route_generation <> old.route_generation
     or new.route_authority_state = 'denied'
     or new.adapter_handler_id is distinct from old.adapter_handler_id then
    update public.inbox_v2_source_registry_ingress_routes route_row
       set invalidated_at = statement_timestamp(),
           invalidated_by_transition_id = new.last_transition_id,
           invalidation_reason_code = case
             when new.route_authority_state = 'denied' then 'authority_not_routable'
             when new.adapter_handler_id is distinct from old.adapter_handler_id then 'adapter_handler_replaced'
             else 'authority_revised'
           end
     where route_row.tenant_id = old.tenant_id
       and route_row.parent_authority_id = old.authority_id
       and route_row.invalidated_at is null
       and (
         route_row.route_generation <> new.route_generation
         or route_row.adapter_handler_id is distinct from new.adapter_handler_id
         or new.route_authority_state = 'denied'
       );
  end if;

  if new.revision <> old.revision then
    update public.inbox_v2_source_registry_secret_refs secret_row
       set revoked_at = statement_timestamp(),
           revoked_by_transition_id = new.last_transition_id
     where secret_row.tenant_id = old.tenant_id
       and secret_row.authority_id = old.authority_id
       and secret_row.revoked_at is null
       and secret_row.authority_revision < new.revision;
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_source_registry_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_source_registry_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    raise exception using
      errcode = '55000',
      message = 'inbox_v2.source_registry_head_delete_forbidden';
  end if;
  if tg_op = 'INSERT' then
    if new.revision <> 1 or new.route_generation <> 1 then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.source_registry_initial_head_invalid';
    end if;
    return new;
  end if;
  if new.tenant_id is distinct from old.tenant_id
     or new.authority_id is distinct from old.authority_id
     or new.authority_kind is distinct from old.authority_kind
     or new.source_connection_id is distinct from old.source_connection_id
     or new.source_account_id is distinct from old.source_account_id
     or new.connector_id is distinct from old.connector_id
     or new.session_id is distinct from old.session_id
     or new.auth_challenge_id is distinct from old.auth_challenge_id
     or new.created_by_actor_kind is distinct from old.created_by_actor_kind
     or new.created_by_employee_id is distinct from old.created_by_employee_id
     or new.created_by_trusted_service_id is distinct from old.created_by_trusted_service_id
     or new.created_at is distinct from old.created_at
     or new.revision <> old.revision + 1
     or new.route_generation < old.route_generation
     or new.updated_at < old.updated_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.source_registry_head_cas_or_edge_invalid';
  end if;
  if not exists (
    select 1
      from public.inbox_v2_source_registry_transitions transition_row
     where transition_row.tenant_id = old.tenant_id
       and transition_row.transition_id = new.last_transition_id
       and transition_row.authority_id = old.authority_id
       and transition_row.expected_revision = old.revision
       and transition_row.expected_route_generation = old.route_generation
       and transition_row.from_state = old.state
       and transition_row.resulting_revision = new.revision
       and transition_row.route_generation = new.route_generation
  ) then
    raise exception using
      errcode = '40001',
      message = 'inbox_v2.source_registry_head_cas_conflict';
  end if;
  return new;
end;
$$;



