--
-- Name: inbox_v2_src_assert_pressure(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_assert_pressure() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_connection_id text;
  v_scope_key text;
  v_pressure public.inbox_v2_source_account_pressure_heads%rowtype;
  v_in_flight bigint;
  v_queued bigint;
begin
  v_tenant_id := coalesce(new.tenant_id, old.tenant_id);
  if tg_table_name = 'inbox_v2_source_processing_work_heads' then
    v_connection_id := coalesce(new.source_connection_id, old.source_connection_id);
    v_scope_key := coalesce(
      new.source_account_scope_key, old.source_account_scope_key
    );
  else
    v_connection_id := coalesce(new.source_connection_id, old.source_connection_id);
    v_scope_key := coalesce(
      new.source_account_scope_key, old.source_account_scope_key
    );
  end if;
  select * into v_pressure
    from public.inbox_v2_source_account_pressure_heads pressure_row
   where pressure_row.tenant_id = v_tenant_id
     and pressure_row.source_connection_id = v_connection_id
     and pressure_row.source_account_scope_key = v_scope_key;
  select count(*) filter (where work_row.state = 'leased'),
         count(*) filter (where work_row.state in ('pending', 'retry_scheduled'))
    into v_in_flight, v_queued
    from public.inbox_v2_source_processing_work_heads work_row
   where work_row.tenant_id = v_tenant_id
     and work_row.source_connection_id = v_connection_id
     and work_row.source_account_scope_key = v_scope_key
     and work_row.stage <> 'raw_ingest';
  if v_pressure.tenant_id is null then
    if v_in_flight <> 0 or v_queued <> 0 then
      raise exception 'Runtime work requires a pressure head'
        using errcode = '23514';
    end if;
    return null;
  end if;
  if v_pressure.in_flight <> v_in_flight
     or v_pressure.queued <> v_queued then
    raise exception 'Pressure head counters do not match durable work heads'
      using errcode = '23514';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_src_assert_work_closure(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_assert_work_closure() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_work_id text;
  v_work public.inbox_v2_source_processing_work_heads%rowtype;
  v_attempt public.inbox_v2_source_processing_attempts%rowtype;
  v_dlq_count bigint;
  v_replay_count bigint;
begin
  v_tenant_id := coalesce(new.tenant_id, old.tenant_id);
  v_work_id := coalesce(new.work_id, old.work_id);
  select * into v_work
    from public.inbox_v2_source_processing_work_heads work_row
   where work_row.tenant_id = v_tenant_id
     and work_row.work_id = v_work_id;
  if v_work.work_id is null then
    return null;
  end if;

  if v_work.stage = 'raw_ingest'
     and v_work.state = 'processed'
     and v_work.attempt_count = 0 then
    return null;
  end if;

  if v_work.processing_generation > 1
     and v_work.state = 'pending'
     and v_work.attempt_count = 0 then
    select count(*) into v_replay_count
      from public.inbox_v2_source_replay_requests replay_row
     where replay_row.tenant_id = v_work.tenant_id
       and replay_row.state = 'applied'
       and replay_row.result_work_id = v_work.work_id
       and replay_row.result_processing_generation =
           v_work.processing_generation
       and replay_row.result_work_revision = v_work.revision;
    if v_replay_count <> 1 then
      raise exception 'Replay work generation requires one exact applied request'
        using errcode = '23514';
    end if;
  end if;

  if v_work.state not in (
       'retry_scheduled', 'processed', 'ignored', 'duplicate', 'dead_lettered'
     ) then
    return null;
  end if;

  select * into v_attempt
    from public.inbox_v2_source_processing_attempts attempt_row
   where attempt_row.tenant_id = v_work.tenant_id
     and attempt_row.work_id = v_work.work_id
     and attempt_row.processing_generation = v_work.processing_generation
     and attempt_row.attempt_number = v_work.attempt_count
     and attempt_row.work_revision = v_work.revision;

  if v_attempt.attempt_id is null
     or v_attempt.outcome::text <> v_work.state::text
     or v_attempt.diagnostic_code_id is distinct from
         v_work.last_diagnostic_code_id
     or v_attempt.retryability is distinct from v_work.retryability
     or not (
       (v_work.processing_generation = 1 and v_work.attempt_count = 1
         and v_attempt.origin = 'initial')
       or (v_work.processing_generation > 1 and v_work.attempt_count = 1
         and v_attempt.origin = 'replay')
       or (v_work.attempt_count > 1 and v_attempt.origin = 'retry')
     ) then
    raise exception 'Terminal or retry work head requires its exact attempt fact'
      using errcode = '23514';
  end if;

  select count(*) into v_dlq_count
    from public.inbox_v2_source_processing_dead_letters dlq_row
   where dlq_row.tenant_id = v_work.tenant_id
     and dlq_row.work_id = v_work.work_id
     and dlq_row.processing_generation = v_work.processing_generation
     and dlq_row.work_revision = v_work.revision;
  if (v_work.state = 'dead_lettered' and v_dlq_count <> 1)
     or (v_work.state <> 'dead_lettered' and v_dlq_count <> 0) then
    raise exception 'Work head and dead-letter closure are incoherent'
      using errcode = '23514';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_src_attempt_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_attempt_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_work public.inbox_v2_source_processing_work_heads%rowtype;
begin
  if tg_op = 'UPDATE' then
    raise exception 'Source processing attempts are immutable'
      using errcode = '23514';
  end if;
  if tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       ) or clock_timestamp() < old.expires_at then
      raise exception 'Source processing attempt is not retention eligible'
        using errcode = '23514';
    end if;
    return old;
  end if;

  select * into v_work
    from public.inbox_v2_source_processing_work_heads work_row
   where work_row.tenant_id = new.tenant_id
     and work_row.work_id = new.work_id;

  if v_work.work_id is null
     or v_work.raw_event_id <> new.raw_event_id
     or v_work.stage <> new.stage
     or v_work.processing_generation <> new.processing_generation
     or v_work.attempt_count <> new.attempt_number
     or v_work.max_attempts <> new.max_attempts
     or not (
       (v_work.state = 'leased'
         and new.work_revision = v_work.revision + 1
         and new.worker_id = v_work.lease_owner_id
         and new.lease_token_hash = v_work.lease_token_hash
         and new.lease_revision = v_work.lease_revision
         and new.lease_claimed_at = v_work.lease_claimed_at
         and new.lease_expires_at = v_work.lease_expires_at)
       or (v_work.state in (
           'retry_scheduled', 'processed', 'ignored', 'duplicate',
           'dead_lettered'
         ) and new.work_revision = v_work.revision)
     ) then
    raise exception 'Source processing attempt does not close its exact lease'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_cursor_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_cursor_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_key public.inbox_v2_source_processing_key_generations%rowtype;
  v_work public.inbox_v2_source_processing_work_heads%rowtype;
  v_quarantine public.inbox_v2_source_raw_quarantines%rowtype;
  v_cursor_secret_purpose text;
begin
  if tg_op = 'DELETE' then
    raise exception 'Ingress cursor checkpoints cannot be deleted'
      using errcode = '23514';
  end if;
  select * into v_key
    from public.inbox_v2_source_processing_key_generations key_row
   where key_row.tenant_id = new.tenant_id
     and key_row.purpose_id = new.purpose_id
     and key_row.generation = new.key_generation;
  select * into v_work
    from public.inbox_v2_source_processing_work_heads work_row
   where work_row.tenant_id = new.tenant_id
     and work_row.work_id = new.durable_work_id;
  select * into v_quarantine
    from public.inbox_v2_source_raw_quarantines quarantine_row
   where quarantine_row.tenant_id = new.tenant_id
     and quarantine_row.id = new.quarantine_id;
  select secret_row.purpose into v_cursor_secret_purpose
    from public.tenant_secrets secret_row
   where secret_row.tenant_id = new.tenant_id
     and secret_row.secret_ref = new.cursor_value_secret_ref;
  if v_key.generation is null
     or v_key.state <> 'active'
     or v_key.secret_ref = new.cursor_value_secret_ref
     or v_cursor_secret_purpose is distinct from
         'inbox_v2.source_cursor_value'
     or new.acknowledged_at < v_key.activated_at
     or new.acknowledged_at >= v_key.use_until
     or (new.durable_target_kind = 'raw_work' and (
       v_work.work_id is null
       or v_work.stage <> 'raw_ingest'
       or v_work.raw_event_id <> new.last_durable_raw_event_id
       or v_work.source_connection_id <> new.source_connection_id
       or v_work.source_account_id is distinct from new.source_account_id
       or v_work.source_account_scope_key <> new.source_account_scope_key
       or v_work.revision <> new.durable_work_revision
       or v_work.state <> new.durable_work_state
       or v_work.updated_at <> new.persisted_at
     ))
     or (new.durable_target_kind = 'quarantine' and (
       v_quarantine.id is null
       or v_quarantine.source_connection_id <> new.source_connection_id
       or v_quarantine.source_account_id is distinct from new.source_account_id
       or v_quarantine.source_account_scope_key <>
          new.source_account_scope_key
       or v_quarantine.quarantine_fingerprint_sha256 <>
          new.quarantine_fingerprint_sha256
       or v_quarantine.recorded_at <> new.persisted_at
     ))
     or not public.inbox_v2_src_runtime_route_is_current(
       new.tenant_id,
       new.source_connection_id,
       new.source_account_id,
       new.route_generation
     )
     or (new.cursor_owner = 'source_thread_binding' and not exists (
       select 1
         from public.inbox_v2_source_thread_bindings binding_row
        where binding_row.tenant_id = new.tenant_id
          and binding_row.id = new.source_thread_binding_id
          and binding_row.source_connection_id = new.source_connection_id
          and binding_row.source_account_id = new.source_account_id
     )) then
    raise exception 'Ingress cursor key, owner or durable target is incoherent'
      using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.revision <> 1 then
      raise exception 'Ingress cursor must start at revision 1'
        using errcode = '23514';
    end if;
    return new;
  end if;
  if (to_jsonb(new) - array[
       'route_generation', 'key_generation', 'cursor_value_secret_ref',
       'cursor_hmac_sha256', 'durable_target_kind',
       'last_durable_raw_event_id', 'durable_work_id',
       'durable_work_revision', 'durable_work_state', 'quarantine_id',
       'quarantine_fingerprint_sha256', 'revision',
       'persisted_at', 'acknowledged_at', 'updated_at'
     ]) <> (to_jsonb(old) - array[
       'route_generation', 'key_generation', 'cursor_value_secret_ref',
       'cursor_hmac_sha256', 'durable_target_kind',
       'last_durable_raw_event_id', 'durable_work_id',
       'durable_work_revision', 'durable_work_state', 'quarantine_id',
       'quarantine_fingerprint_sha256', 'revision',
       'persisted_at', 'acknowledged_at', 'updated_at'
     ])
     or new.revision <> old.revision + 1
     or new.persisted_at < old.persisted_at
     or new.acknowledged_at <= old.acknowledged_at
     or new.updated_at <= old.updated_at then
    raise exception 'Ingress cursor owner or monotonic checkpoint changed'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_dedupe_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_dedupe_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_key public.inbox_v2_source_processing_key_generations%rowtype;
  v_replay_deadline timestamptz;
begin
  if tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       )
       or old.lifecycle_state <> 'expired'
       or clock_timestamp() < old.skeleton_expires_at
       or exists (
         select 1
           from public.inbox_v2_source_raw_admissions admission_row
          where admission_row.tenant_id = old.tenant_id
            and admission_row.state = 'skeleton_handed_off'
            and admission_row.terminal_skeleton_id = old.id
            and admission_row.terminal_outcome_hmac_sha256 =
                old.outcome_hmac_sha256
       ) then
      raise exception 'Dedupe skeleton is not retention eligible'
        using errcode = '23514';
    end if;
    return old;
  end if;

  if tg_op = 'UPDATE' then
    if (to_jsonb(new) - array[
         'replayability_state', 'replay_until',
         'replayability_reason_code_id', 'lifecycle_state', 'expired_at',
         'revision', 'updated_at'
       ]) <> (to_jsonb(old) - array[
         'replayability_state', 'replay_until',
         'replayability_reason_code_id', 'lifecycle_state', 'expired_at',
         'revision', 'updated_at'
       ])
       or new.revision <> old.revision + 1
       or new.updated_at < old.updated_at
       or new.updated_at > clock_timestamp() then
      raise exception 'Dedupe skeleton identity or CAS revision changed'
        using errcode = '23514';
    end if;

    if old.lifecycle_state = 'active'
       and new.lifecycle_state = 'active'
       and old.replayability_state = 'replayable'
       and new.replayability_state = 'expired' then
      v_replay_deadline := case
        when old.phase = 'raw' then least(
          old.replay_until,
          old.raw_payload_expires_at,
          old.allowed_raw_headers_expires_at,
          old.key_verify_until,
          old.guarantee_until
        )
        else least(
          old.replay_until,
          old.normalized_payload_expires_at,
          old.key_verify_until,
          old.guarantee_until
        )
      end;
      if new.replay_until is not null
         or new.replayability_reason_code_id is null
         or new.expired_at is not null
         or new.updated_at < v_replay_deadline
         or clock_timestamp() < v_replay_deadline then
        raise exception 'Invalid dedupe replayability expiry transition'
          using errcode = '23514';
      end if;
      return new;
    end if;

    if old.lifecycle_state = 'active'
       and new.lifecycle_state = 'expired' then
      if old.replayability_state = 'replayable'
         or new.replayability_state <> old.replayability_state
         or new.replay_until is distinct from old.replay_until
         or new.replayability_reason_code_id is distinct from
             old.replayability_reason_code_id
         or new.expired_at <> new.updated_at
         or new.updated_at < new.skeleton_expires_at
         or clock_timestamp() < new.skeleton_expires_at then
        raise exception 'Invalid dedupe skeleton lifecycle expiry transition'
          using errcode = '23514';
      end if;
      return new;
    end if;

    raise exception 'Invalid dedupe skeleton transition'
      using errcode = '23514';
  end if;

  select * into v_key
    from public.inbox_v2_source_processing_key_generations key_row
   where key_row.tenant_id = new.tenant_id
     and key_row.purpose_id = new.purpose_id
     and key_row.generation = new.key_generation;

  if new.revision <> 1
     or new.created_at <> new.updated_at
     or new.replayability_state = 'expired'
     or new.lifecycle_state <> 'active'
     or new.expired_at is not null
     or v_key.generation is null
     or v_key.state not in ('active', 'verify_only')
     or clock_timestamp() >= v_key.verify_until
     or new.terminal_at < v_key.activated_at
     or new.terminal_at >= v_key.use_until
     or new.guarantee_until > v_key.guarantee_not_after
     or new.guarantee_until > v_key.verify_until
     or new.key_verify_until <> v_key.verify_until
     or not public.inbox_v2_src_runtime_route_is_current(
       new.tenant_id,
       new.source_connection_id,
       new.source_account_id,
       new.route_generation
     )
     or (new.normalized_event_id is not null and not exists (
       select 1
         from public.inbox_v2_source_normalized_envelopes normalized_row
        where normalized_row.tenant_id = new.tenant_id
          and normalized_row.normalized_event_id = new.normalized_event_id
          and normalized_row.raw_event_id = new.raw_event_id
          and normalized_row.source_connection_id = new.source_connection_id
          and normalized_row.source_account_id is not distinct from
              new.source_account_id
          and normalized_row.source_account_scope_key =
              new.source_account_scope_key
     )) then
    raise exception 'Dedupe skeleton key, route or target is incoherent'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_dlq_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_dlq_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_attempt public.inbox_v2_source_processing_attempts%rowtype;
begin
  if tg_op = 'UPDATE' then
    raise exception 'Source processing dead-letter facts are immutable'
      using errcode = '23514';
  end if;
  if tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       ) or clock_timestamp() < old.expires_at
       or exists (
         select 1
           from public.inbox_v2_source_replay_requests replay_row
          where replay_row.tenant_id = old.tenant_id
            and replay_row.dead_letter_id = old.id
       ) then
      raise exception 'Source processing dead-letter fact is not retention eligible'
        using errcode = '23514';
    end if;
    return old;
  end if;

  select * into v_attempt
    from public.inbox_v2_source_processing_attempts attempt_row
   where attempt_row.tenant_id = new.tenant_id
     and attempt_row.attempt_id = new.attempt_id;
  if v_attempt.attempt_id is null
     or v_attempt.work_id <> new.work_id
     or v_attempt.raw_event_id <> new.raw_event_id
     or v_attempt.stage <> new.stage
     or v_attempt.processing_generation <> new.processing_generation
     or v_attempt.attempt_number <> new.attempt_number
     or v_attempt.work_revision <> new.work_revision
     or v_attempt.outcome <> 'dead_lettered'
     or v_attempt.diagnostic_code_id <> new.diagnostic_code_id
     or v_attempt.retryability <> new.retryability
     or v_attempt.diagnostic_correlation_token <>
         new.diagnostic_correlation_token
     or v_attempt.diagnostic_safe_operator_hint_id is distinct from
         new.diagnostic_safe_operator_hint_id
     or (new.reason = 'attempts_exhausted'
       and v_attempt.attempt_number <> v_attempt.max_attempts) then
    raise exception 'Dead-letter fact does not match its exact terminal attempt'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_pressure_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_pressure_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    raise exception 'Source account pressure heads cannot be deleted'
      using errcode = '23514';
  end if;
  if tg_op = 'INSERT' then
    if new.revision <> 1 or new.created_at <> new.updated_at then
      raise exception 'Pressure head must start at revision 1'
        using errcode = '23514';
    end if;
    return new;
  end if;
  if new.tenant_id <> old.tenant_id
     or new.source_connection_id <> old.source_connection_id
     or new.source_account_id is distinct from old.source_account_id
     or new.source_account_scope_key <> old.source_account_scope_key
     or new.created_at <> old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at <= old.updated_at then
    raise exception 'Pressure head identity or CAS revision changed'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_proc_key_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_proc_key_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_secret_purpose text;
begin
  if tg_op <> 'DELETE' then
    select secret_row.purpose into v_secret_purpose
      from public.tenant_secrets secret_row
     where secret_row.tenant_id = new.tenant_id
       and secret_row.secret_ref = new.secret_ref;
    if v_secret_purpose is distinct from
       'inbox_v2.source_processing_hmac' then
      raise exception 'Processing key generation requires an HMAC tenant secret'
        using errcode = '23514';
    end if;
  end if;

  if tg_op = 'INSERT' then
    if new.revision <> 1
       or new.state <> 'active'
       or new.retired_at is not null
       or new.created_at <> new.updated_at then
      raise exception 'Processing key generation must start as active revision 1'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       )
       or old.state <> 'retired'
       or clock_timestamp() < old.retired_at
       or exists (
         select 1
           from public.inbox_v2_source_delivery_dedupe_skeletons skeleton_row
          where skeleton_row.tenant_id = old.tenant_id
            and skeleton_row.purpose_id = old.purpose_id
            and skeleton_row.key_generation = old.generation
       )
       or exists (
         select 1
           from public.inbox_v2_source_raw_admissions admission_row
          where admission_row.tenant_id = old.tenant_id
            and admission_row.purpose_id = old.purpose_id
            and admission_row.key_generation = old.generation
            and admission_row.hmac_key_secret_ref = old.secret_ref
       )
       or exists (
         select 1
           from public.inbox_v2_source_raw_quarantines quarantine_row
          where quarantine_row.tenant_id = old.tenant_id
            and quarantine_row.event_identity_key_generation = old.generation
            and quarantine_row.event_identity_hmac_key_secret_ref =
                old.secret_ref
            and quarantine_row.event_identity_guarantee_until >
                clock_timestamp()
       )
       or exists (
         select 1
           from public.inbox_v2_source_ingress_cursor_checkpoints cursor_row
          where cursor_row.tenant_id = old.tenant_id
            and cursor_row.purpose_id = old.purpose_id
            and cursor_row.key_generation = old.generation
       ) then
      raise exception 'Processing key generation is not retention eligible'
        using errcode = '23514';
    end if;
    return old;
  end if;

  if new.tenant_id <> old.tenant_id
     or new.purpose_id <> old.purpose_id
     or new.generation <> old.generation
     or new.secret_ref <> old.secret_ref
     or new.activated_at <> old.activated_at
     or new.use_until <> old.use_until
     or new.guarantee_not_after <> old.guarantee_not_after
     or new.verify_until <> old.verify_until
     or new.created_at <> old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at
     or not (
       (old.state = 'active'
         and new.state = 'verify_only'
         and new.retired_at is null
         and new.updated_at >= old.activated_at)
       or (old.state = 'verify_only'
         and new.state = 'retired'
         and new.retired_at = new.updated_at
         and new.updated_at >= old.verify_until)
     ) then
    raise exception 'Invalid processing key generation transition'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_raw_runtime_bridge(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_raw_runtime_bridge() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_envelope public.inbox_v2_source_raw_envelopes%rowtype;
  v_route_generation bigint;
  v_raw_work_id text;
begin
  select * into strict v_envelope
    from public.inbox_v2_source_raw_envelopes envelope_row
   where envelope_row.tenant_id = new.tenant_id
     and envelope_row.raw_event_id = new.raw_event_id;
  v_route_generation := public.inbox_v2_src_runtime_route_generation(
    v_envelope.tenant_id,
    v_envelope.source_connection_id,
    v_envelope.source_account_id
  );
  if v_route_generation is null then
    return new;
  end if;
  v_raw_work_id := 'srcwork:' || encode(sha256(convert_to(
    'source-processing-work:v1|' || v_envelope.tenant_id || chr(31) ||
    v_envelope.raw_event_id || chr(31) || '0:' || chr(31) || 'raw_ingest',
    'UTF8')), 'hex');
  insert into public.inbox_v2_source_processing_work_heads (
    tenant_id, work_id, raw_event_id, normalized_event_id,
    normalized_event_scope_key, stage, source_connection_id,
    source_account_id, source_account_scope_key, route_generation, state,
    processing_generation, available_at, max_attempts, attempt_count,
    lease_owner_id, lease_token_hash, lease_revision, lease_claimed_at,
    lease_expires_at, last_diagnostic_code_id, retryability,
    rate_limit_reset_at, dead_lettered_at, completed_at, revision,
    created_at, updated_at
  ) values (
    v_envelope.tenant_id, v_raw_work_id, v_envelope.raw_event_id, null,
    '0:', 'raw_ingest', v_envelope.source_connection_id,
    v_envelope.source_account_id, v_envelope.source_account_scope_key,
    v_route_generation, 'processed', 1, new.available_at, 100, 0,
    null, null, null, null, null, null, null, null, null, new.updated_at,
    1, new.created_at, new.updated_at
  );
  return new;
end
$$;



--
-- Name: inbox_v2_src_replay_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_replay_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_scope_key text;
  v_target_work public.inbox_v2_source_processing_work_heads%rowtype;
  v_dlq public.inbox_v2_source_processing_dead_letters%rowtype;
  v_has_evidence boolean;
begin
  if tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       ) or old.state not in ('applied', 'denied', 'expired')
       or clock_timestamp() < old.expires_at
       or exists (
         select 1
           from public.inbox_v2_source_processing_work_heads work_row
          where work_row.tenant_id = old.tenant_id
            and work_row.work_id = old.result_work_id
            and work_row.processing_generation =
                old.result_processing_generation
            and work_row.state in ('pending', 'retry_scheduled', 'leased')
       ) then
      raise exception 'Source replay request is not retention eligible'
        using errcode = '23514';
    end if;
    return old;
  end if;

  v_scope_key := case when new.normalized_event_id is null then '0:' else
    '1:' || octet_length(new.normalized_event_id)::text || ':' ||
    new.normalized_event_id end;
  select * into v_target_work
    from public.inbox_v2_source_processing_work_heads work_row
   where work_row.tenant_id = new.tenant_id
     and work_row.work_id = new.target_work_id;
  select * into v_dlq
    from public.inbox_v2_source_processing_dead_letters dlq_row
   where dlq_row.tenant_id = new.tenant_id
     and dlq_row.id = new.dead_letter_id;

  v_has_evidence := case
    when new.stage in ('raw_ingest', 'normalization') then exists (
      select 1
        from public.inbox_v2_source_raw_evidence evidence_row
       where evidence_row.tenant_id = new.tenant_id
         and evidence_row.raw_event_id = new.raw_event_id
         and evidence_row.evidence_kind = 'provider_payload'
         and evidence_row.purpose_ids ? 'core:source_replay_and_diagnostics'
    )
    else exists (
      select 1
        from public.inbox_v2_source_normalized_evidence_payloads payload_row
        join public.inbox_v2_source_normalized_evidence evidence_row
          on evidence_row.tenant_id = payload_row.tenant_id
         and evidence_row.normalized_event_id = payload_row.normalized_event_id
         and evidence_row.evidence_key = payload_row.evidence_key
       where payload_row.tenant_id = new.tenant_id
         and payload_row.normalized_event_id = new.normalized_event_id
         and evidence_row.purpose_ids ? 'core:source_replay_and_diagnostics'
    )
  end;

  if tg_op = 'INSERT' then
    if new.revision <> 1
       or new.state not in ('pending', 'denied', 'expired')
       or new.requested_at > new.updated_at
       or new.updated_at > clock_timestamp()
       or v_target_work.work_id is null
       or v_target_work.work_id <> new.target_work_id
       or v_target_work.raw_event_id <> new.raw_event_id
       or v_target_work.normalized_event_id is distinct from
           new.normalized_event_id
       or v_target_work.normalized_event_scope_key <> v_scope_key
       or new.normalized_event_scope_key <> v_scope_key
       or v_target_work.stage <> new.stage
       or v_target_work.source_connection_id <> new.source_connection_id
       or v_target_work.source_account_id is distinct from
           new.source_account_id
       or v_target_work.source_account_scope_key <>
           new.source_account_scope_key
       or v_target_work.route_generation <> new.route_generation then
      raise exception 'Replay request target snapshot is incoherent'
        using errcode = '23514';
    end if;

    if new.state = 'pending' and (
      new.dead_letter_id is null
      or v_target_work.state <> 'dead_lettered'
      or v_target_work.revision <> new.expected_target_revision
      or v_dlq.id is null
      or v_dlq.work_id <> v_target_work.work_id
      or v_dlq.raw_event_id <> v_target_work.raw_event_id
      or v_dlq.stage <> v_target_work.stage
      or v_dlq.processing_generation <>
          v_target_work.processing_generation
      or v_dlq.attempt_number <> v_target_work.attempt_count
      or v_dlq.work_revision <> v_target_work.revision
      or v_dlq.recorded_at <> v_target_work.dead_lettered_at
      or new.replay_not_after <> v_dlq.replay_not_after
      or new.expires_at > v_dlq.expires_at
      or new.requested_at <> new.updated_at
      or new.updated_at >= new.replay_not_after
      or clock_timestamp() >= new.replay_not_after
      or not v_has_evidence
      or not public.inbox_v2_src_runtime_route_is_current(
        v_target_work.tenant_id,
        v_target_work.source_connection_id,
        v_target_work.source_account_id,
        new.route_generation
      )
    ) then
      raise exception 'Pending replay request is not currently eligible'
        using errcode = '23514';
    end if;
    if new.state in ('denied', 'expired')
       and new.dead_letter_id is not null
       and (v_dlq.id is null
         or v_dlq.work_id <> v_target_work.work_id
         or v_dlq.raw_event_id <> v_target_work.raw_event_id
         or v_dlq.stage <> v_target_work.stage
         or v_dlq.processing_generation <>
             v_target_work.processing_generation
         or v_dlq.attempt_number <> v_target_work.attempt_count
         or v_dlq.work_revision <> v_target_work.revision
         or v_dlq.recorded_at <> v_target_work.dead_lettered_at
         or new.expires_at > v_dlq.expires_at) then
      raise exception 'Terminal replay DLQ snapshot is incoherent'
        using errcode = '23514';
    end if;
    if new.state = 'expired' and (
      new.completed_at < new.replay_not_after
      or clock_timestamp() < new.replay_not_after
    ) then
      raise exception 'Expired replay decision predates its durable deadline'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if (to_jsonb(new) - array[
       'state', 'available_at', 'lease_owner_id', 'lease_token_hash',
       'lease_revision', 'lease_claimed_at', 'lease_expires_at',
       'result_processing_generation', 'result_replay_episode_id',
       'result_work_id', 'result_work_revision', 'rejection_reason',
       'diagnostic_code_id', 'diagnostic_retryability',
       'diagnostic_correlation_token', 'diagnostic_safe_operator_hint_id',
       'revision', 'updated_at', 'completed_at'
     ]) <> (to_jsonb(old) - array[
       'state', 'available_at', 'lease_owner_id', 'lease_token_hash',
       'lease_revision', 'lease_claimed_at', 'lease_expires_at',
       'result_processing_generation', 'result_replay_episode_id',
       'result_work_id', 'result_work_revision', 'rejection_reason',
       'diagnostic_code_id', 'diagnostic_retryability',
       'diagnostic_correlation_token', 'diagnostic_safe_operator_hint_id',
       'revision', 'updated_at', 'completed_at'
     ])
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at
     or new.updated_at > clock_timestamp()
     or v_target_work.work_id is null
     or v_target_work.raw_event_id <> new.raw_event_id
     or v_target_work.normalized_event_id is distinct from
         new.normalized_event_id
     or v_target_work.normalized_event_scope_key <>
         new.normalized_event_scope_key
     or v_target_work.stage <> new.stage
     or v_target_work.source_connection_id <> new.source_connection_id
     or v_target_work.source_account_id is distinct from new.source_account_id
     or v_target_work.source_account_scope_key <>
         new.source_account_scope_key
     or v_target_work.route_generation <> new.route_generation
     or v_dlq.id is null
     or v_dlq.work_id <> new.target_work_id
     or v_dlq.raw_event_id <> new.raw_event_id
     or v_dlq.stage <> new.stage
     or v_dlq.work_revision <> new.expected_target_revision
     or v_dlq.replay_not_after <> new.replay_not_after
     or new.expires_at > v_dlq.expires_at then
    raise exception 'Replay request identity or CAS revision changed'
      using errcode = '23514';
  end if;

  if old.state = 'pending' and new.state = 'leased' then
    if old.available_at > new.updated_at
       or new.lease_revision <> new.revision
       or new.lease_claimed_at <> new.updated_at
       or new.lease_expires_at > new.replay_not_after
       or new.updated_at >= new.replay_not_after
       or clock_timestamp() >= new.replay_not_after
       or not v_has_evidence
       or not (
         (v_target_work.state = 'dead_lettered'
           and v_target_work.revision = new.expected_target_revision
           and v_target_work.processing_generation =
               v_dlq.processing_generation)
         or (v_target_work.state = 'pending'
           and v_target_work.revision = new.expected_target_revision + 1
           and v_target_work.processing_generation =
               v_dlq.processing_generation + 1)
       )
       or not public.inbox_v2_src_runtime_route_is_current(
         v_target_work.tenant_id,
         v_target_work.source_connection_id,
         v_target_work.source_account_id,
         new.route_generation
       ) then
      raise exception 'Invalid replay request lease claim'
        using errcode = '23514';
    end if;
    return new;
  end if;
  if old.state = 'leased' and new.state = 'leased' then
    if new.lease_owner_id <> old.lease_owner_id
       or new.lease_token_hash <> old.lease_token_hash
       or new.lease_claimed_at <> old.lease_claimed_at
       or new.lease_revision <> new.revision
       or new.lease_expires_at <= old.lease_expires_at
       or new.lease_expires_at > new.replay_not_after
       or clock_timestamp() >= old.lease_expires_at
       or clock_timestamp() >= new.replay_not_after
       or not v_has_evidence
       or not (
         (v_target_work.state = 'dead_lettered'
           and v_target_work.revision = new.expected_target_revision
           and v_target_work.processing_generation =
               v_dlq.processing_generation)
         or (v_target_work.state = 'pending'
           and v_target_work.revision = new.expected_target_revision + 1
           and v_target_work.processing_generation =
               v_dlq.processing_generation + 1)
       )
       or not public.inbox_v2_src_runtime_route_is_current(
         v_target_work.tenant_id,
         v_target_work.source_connection_id,
         v_target_work.source_account_id,
         new.route_generation
       ) then
      raise exception 'Invalid replay request lease renewal'
        using errcode = '23514';
    end if;
    return new;
  end if;
  if old.state = 'leased' and new.state = 'applied' then
    if clock_timestamp() >= old.lease_expires_at
       or clock_timestamp() >= new.replay_not_after
       or new.updated_at >= new.replay_not_after
       or not v_has_evidence
       or v_target_work.state <> 'pending'
       or v_target_work.work_id <> new.target_work_id
       or new.result_work_id <> new.target_work_id
       or v_target_work.revision <> new.expected_target_revision + 1
       or new.result_work_revision <> new.expected_target_revision + 1
       or new.result_work_revision <> v_target_work.revision
       or v_target_work.processing_generation <>
           v_dlq.processing_generation + 1
       or new.result_processing_generation <>
           v_dlq.processing_generation + 1
       or new.result_processing_generation <>
           v_target_work.processing_generation
       or v_target_work.attempt_count <> 0
       or not public.inbox_v2_src_runtime_route_is_current(
         v_target_work.tenant_id,
         v_target_work.source_connection_id,
         v_target_work.source_account_id,
         new.route_generation
       ) then
      raise exception 'Applied replay does not expose the exact reset target'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if old.state in ('pending', 'leased') and new.state = 'denied' then
    return new;
  end if;

  if old.state in ('pending', 'leased') and new.state = 'expired' then
    if new.completed_at < new.replay_not_after
       or clock_timestamp() < new.replay_not_after then
      raise exception 'Replay request cannot expire before its DB deadline'
        using errcode = '23514';
    end if;
    return new;
  end if;
  raise exception 'Invalid replay request transition' using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_src_runtime_raw_admission_terminal_skeleton_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_runtime_raw_admission_terminal_skeleton_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.state <> 'skeleton_handed_off' then
    return new;
  end if;

  -- A later DELETE in the same retention transaction removes the aggregate
  -- obligation; otherwise the exact handed-off admission must still exist.
  if not exists (
    select 1
      from public.inbox_v2_source_raw_admissions current_admission
     where current_admission.tenant_id = new.tenant_id
       and current_admission.purpose_id = new.purpose_id
       and current_admission.key_generation = new.key_generation
       and current_admission.identity_hmac_sha256 =
           new.identity_hmac_sha256
       and current_admission.state = 'skeleton_handed_off'
       and current_admission.revision = new.revision
  ) then
    return new;
  end if;

  if not exists (
    select 1
      from public.inbox_v2_source_delivery_dedupe_skeletons skeleton_row
     where skeleton_row.tenant_id = new.tenant_id
       and skeleton_row.id = new.terminal_skeleton_id
       and skeleton_row.source_connection_id = new.source_connection_id
       and skeleton_row.source_account_id is not distinct from
           new.source_account_id
       and skeleton_row.source_account_scope_key =
           new.source_account_scope_key
       and skeleton_row.phase = 'raw'
       and skeleton_row.raw_event_id = new.raw_event_id
       and skeleton_row.normalized_event_id is null
       and skeleton_row.purpose_id = new.purpose_id
       and skeleton_row.key_generation = new.key_generation
       and skeleton_row.identity_hmac_sha256 = new.identity_hmac_sha256
       and skeleton_row.outcome_hmac_sha256 =
           new.terminal_outcome_hmac_sha256
       and skeleton_row.terminal_at = new.skeleton_handed_off_at
       and skeleton_row.guarantee_until = new.guarantee_until
  ) then
    raise exception 'Raw admission handoff requires its exact terminal skeleton'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_runtime_reject_truncate(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_runtime_reject_truncate() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  raise exception '% cannot be truncated', tg_table_name using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_src_runtime_route_generation(text, text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_runtime_route_generation(p_tenant_id text, p_source_connection_id text, p_source_account_id text) RETURNS bigint
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select head_row.route_generation
    from public.inbox_v2_source_registry_heads head_row
   where head_row.tenant_id = p_tenant_id
     and head_row.source_connection_id = p_source_connection_id
     and head_row.state in ('active', 'degraded')
     and head_row.route_authority_state in ('enabled', 'inbound_only')
     and (
       (p_source_account_id is not null
         and head_row.authority_kind = 'source_account'
         and head_row.source_account_id = p_source_account_id)
       or (head_row.authority_kind = 'source_connection'
         and head_row.source_account_id is null)
     )
   order by case when head_row.authority_kind = 'source_account' then 0 else 1 end,
            head_row.revision desc
   limit 1
$$;



--
-- Name: inbox_v2_src_runtime_route_is_current(text, text, text, bigint); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_runtime_route_is_current(p_tenant_id text, p_source_connection_id text, p_source_account_id text, p_route_generation bigint) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select coalesce(
    public.inbox_v2_src_runtime_route_generation(
      p_tenant_id,
      p_source_connection_id,
      p_source_account_id
    ) = p_route_generation,
    false
  )
$$;



--
-- Name: inbox_v2_src_runtime_terminal_skeleton_admission_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_runtime_terminal_skeleton_admission_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if exists (
    select 1
      from public.inbox_v2_source_raw_admissions admission_row
     where admission_row.tenant_id = old.tenant_id
       and admission_row.state = 'skeleton_handed_off'
       and admission_row.terminal_skeleton_id = old.id
       and admission_row.purpose_id = old.purpose_id
       and admission_row.key_generation = old.key_generation
       and admission_row.identity_hmac_sha256 = old.identity_hmac_sha256
       and admission_row.terminal_outcome_hmac_sha256 =
           old.outcome_hmac_sha256
  ) then
    raise exception 'Terminal skeleton remains referenced by a raw admission'
      using errcode = '23514';
  end if;
  return old;
end
$$;



--
-- Name: inbox_v2_src_secret_purpose_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_secret_purpose_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.purpose = old.purpose then
    return new;
  end if;
  if exists (
    select 1
      from public.inbox_v2_source_processing_key_generations key_row
     where key_row.tenant_id = old.tenant_id
       and key_row.secret_ref = old.secret_ref
  ) and new.purpose <> 'inbox_v2.source_processing_hmac' then
    raise exception 'Referenced source-processing HMAC secret purpose cannot drift'
      using errcode = '23514';
  end if;
  if exists (
    select 1
      from public.inbox_v2_source_ingress_cursor_checkpoints cursor_row
     where cursor_row.tenant_id = old.tenant_id
       and cursor_row.cursor_value_secret_ref = old.secret_ref
  ) and new.purpose <> 'inbox_v2.source_cursor_value' then
    raise exception 'Referenced source cursor value secret purpose cannot drift'
      using errcode = '23514';
  end if;
  return new;
end
$$;



--
-- Name: inbox_v2_src_work_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_src_work_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_expected_work_id text;
begin
  if tg_op = 'DELETE' then
    if not pg_catalog.pg_has_role(
         current_user, 'hulee_inbox_v2_retention_owner', 'member'
       ) or old.state not in (
         'processed', 'ignored', 'duplicate', 'dead_lettered'
       ) then
      raise exception 'Source processing work head is not retention eligible'
        using errcode = '23514';
    end if;
    if exists (
         select 1
           from public.inbox_v2_source_processing_attempts attempt_row
          where attempt_row.tenant_id = old.tenant_id
            and attempt_row.work_id = old.work_id
       ) or exists (
         select 1
           from public.inbox_v2_source_processing_dead_letters dlq_row
          where dlq_row.tenant_id = old.tenant_id
            and dlq_row.work_id = old.work_id
       ) or exists (
         select 1
           from public.inbox_v2_source_replay_requests replay_row
          where replay_row.tenant_id = old.tenant_id
            and (replay_row.target_work_id = old.work_id
              or replay_row.result_work_id = old.work_id)
       ) or exists (
         select 1
           from public.inbox_v2_source_ingress_cursor_checkpoints cursor_row
          where cursor_row.tenant_id = old.tenant_id
            and cursor_row.durable_work_id = old.work_id
       ) then
      raise exception 'Source processing work head still has runtime dependents'
        using errcode = '23514';
    end if;
    return old;
  end if;

  if tg_op = 'INSERT' then
    v_expected_work_id := 'srcwork:' || encode(sha256(convert_to(
      'source-processing-work:v1|' || new.tenant_id || chr(31) ||
      new.raw_event_id || chr(31) || new.normalized_event_scope_key || chr(31) ||
      new.stage::text, 'UTF8')), 'hex');

    if new.revision <> 1
       or new.processing_generation <> 1
       or new.created_at <> new.updated_at
       or not public.inbox_v2_src_runtime_route_is_current(
         new.tenant_id,
         new.source_connection_id,
         new.source_account_id,
         new.route_generation
       )
       or new.work_id <> v_expected_work_id
       or not (
         (new.stage = 'raw_ingest'
           and new.state = 'processed'
           and new.attempt_count = 0
           and new.completed_at = new.updated_at
           and exists (
             select 1
               from public.inbox_v2_source_raw_work_items raw_work
              where raw_work.tenant_id = new.tenant_id
                and raw_work.raw_event_id = new.raw_event_id
           ))
         or (new.stage <> 'raw_ingest'
           and new.state = 'pending'
           and new.attempt_count = 0
           and new.dead_lettered_at is null
           and new.completed_at is null)
       ) then
      raise exception 'Invalid initial source processing work head'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if (to_jsonb(new) - array[
       'state', 'processing_generation', 'available_at', 'attempt_count',
       'lease_owner_id', 'lease_token_hash', 'lease_revision',
       'lease_claimed_at', 'lease_expires_at', 'last_diagnostic_code_id',
       'retryability', 'rate_limit_reset_at', 'dead_lettered_at',
       'completed_at', 'revision', 'updated_at'
     ]) <> (to_jsonb(old) - array[
       'state', 'processing_generation', 'available_at', 'attempt_count',
       'lease_owner_id', 'lease_token_hash', 'lease_revision',
       'lease_claimed_at', 'lease_expires_at', 'last_diagnostic_code_id',
       'retryability', 'rate_limit_reset_at', 'dead_lettered_at',
       'completed_at', 'revision', 'updated_at'
     ])
     or new.revision <> old.revision + 1
     or new.updated_at <= old.updated_at then
    raise exception 'Source processing work identity or CAS revision changed'
      using errcode = '23514';
  end if;

  if old.state in ('pending', 'retry_scheduled') and new.state = 'leased' then
    if old.available_at > new.updated_at
       or new.attempt_count <> old.attempt_count + 1
       or new.attempt_count > new.max_attempts
       or new.processing_generation <> old.processing_generation
       or new.lease_revision <> new.revision
       or new.lease_claimed_at <> new.updated_at
       or not public.inbox_v2_src_runtime_route_is_current(
         new.tenant_id,
         new.source_connection_id,
         new.source_account_id,
         new.route_generation
       ) then
      raise exception 'Invalid source processing lease claim'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if old.state = 'leased'
     and new.state = 'leased'
     and clock_timestamp() >= old.lease_expires_at then
    if new.processing_generation <> old.processing_generation
       or new.attempt_count <> old.attempt_count
       or new.available_at <> old.available_at
       or new.lease_token_hash = old.lease_token_hash
       or new.lease_revision <> new.revision
       or new.lease_claimed_at <> new.updated_at
       or new.updated_at < old.lease_expires_at
       or new.updated_at > clock_timestamp()
       or new.lease_expires_at <= new.updated_at
       or new.last_diagnostic_code_id is distinct from
           old.last_diagnostic_code_id
       or new.retryability is distinct from old.retryability
       or new.rate_limit_reset_at is distinct from old.rate_limit_reset_at
       or exists (
         select 1
           from public.inbox_v2_source_processing_attempts attempt_row
          where attempt_row.tenant_id = old.tenant_id
            and attempt_row.work_id = old.work_id
            and attempt_row.processing_generation =
                old.processing_generation
            and attempt_row.attempt_number = old.attempt_count
       )
       or not public.inbox_v2_src_runtime_route_is_current(
         new.tenant_id,
         new.source_connection_id,
         new.source_account_id,
         new.route_generation
       ) then
      raise exception 'Invalid same-attempt expired lease reclaim'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if old.state = 'leased' and new.state = 'leased' then
    if new.processing_generation <> old.processing_generation
       or new.attempt_count <> old.attempt_count
       or new.lease_owner_id <> old.lease_owner_id
       or new.lease_token_hash <> old.lease_token_hash
       or new.lease_claimed_at <> old.lease_claimed_at
       or new.lease_revision <> new.revision
       or new.lease_expires_at <= old.lease_expires_at
       or clock_timestamp() >= old.lease_expires_at then
      raise exception 'Invalid source processing lease renewal'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if old.state = 'leased'
     and new.state in (
       'retry_scheduled', 'processed', 'ignored', 'duplicate', 'dead_lettered'
     ) then
    if clock_timestamp() >= old.lease_expires_at
       or new.processing_generation <> old.processing_generation
       or new.attempt_count <> old.attempt_count then
      raise exception 'Invalid source processing leased completion'
        using errcode = '23514';
    end if;
    return new;
  end if;

  if old.state = 'dead_lettered' and new.state = 'pending' then
    if new.processing_generation <> old.processing_generation + 1
       or new.attempt_count <> 0
       or new.available_at < new.updated_at
       or new.last_diagnostic_code_id is not null
       or new.retryability is not null
       or new.rate_limit_reset_at is not null
       or new.dead_lettered_at is not null
       or new.completed_at is not null
       or not exists (
         select 1
           from public.inbox_v2_source_replay_requests request_row
           join public.inbox_v2_source_processing_dead_letters dlq_row
             on dlq_row.tenant_id = request_row.tenant_id
            and dlq_row.id = request_row.dead_letter_id
          where request_row.tenant_id = old.tenant_id
            and request_row.target_work_id = old.work_id
            and request_row.raw_event_id = old.raw_event_id
            and request_row.normalized_event_id is not distinct from
                old.normalized_event_id
            and request_row.normalized_event_scope_key =
                old.normalized_event_scope_key
            and request_row.stage = old.stage
            and request_row.source_connection_id = old.source_connection_id
            and request_row.source_account_id is not distinct from
                old.source_account_id
            and request_row.source_account_scope_key =
                old.source_account_scope_key
            and request_row.route_generation = old.route_generation
            and request_row.expected_target_revision = old.revision
            and request_row.state in ('pending', 'leased')
            and request_row.replay_not_after > new.updated_at
            and clock_timestamp() < request_row.replay_not_after
            and dlq_row.work_id = old.work_id
            and dlq_row.raw_event_id = old.raw_event_id
            and dlq_row.stage = old.stage
            and dlq_row.processing_generation = old.processing_generation
            and dlq_row.work_revision = old.revision
       ) then
      raise exception 'Invalid source processing replay reset'
        using errcode = '23514';
    end if;
    return new;
  end if;

  raise exception 'Invalid source processing work transition'
    using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_system_event_timeline_binding_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_system_event_timeline_binding_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.subject_kind <> 'system_event' then
    return new;
  end if;

  if not exists (
    select 1
      from public.inbox_v2_timeline_items item
      inner join public.event_store event_row
        on event_row.tenant_id = item.tenant_id
       and event_row.id = new.system_event_id
     where item.tenant_id = new.tenant_id
       and item.id = new.timeline_item_id
       and item.subject_kind = 'system_event'
       and event_row.payload->>'schemaId' =
         'core:inbox-v2.conversation-system-event-payload'
       and event_row.payload->>'schemaVersion' = 'v1'
       and event_row.payload#>>'{conversation,tenantId}' = new.tenant_id
       and event_row.payload#>>'{conversation,kind}' = 'conversation'
       and event_row.payload#>>'{conversation,id}' = item.conversation_id
       and event_row.payload->>'recordedAt' = to_char(
         event_row.created_at at time zone 'UTC',
         'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'
       )
       and event_row.occurred_at = item.occurred_at
       and event_row.created_at = item.received_at
     for share of event_row
  ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.system_event_timeline_binding_invalid';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_tenant_policy_activation_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tenant_policy_activation_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  version_approved_at timestamptz;
  transition_exists boolean;
  actor_id text;
  actor_at timestamptz;
  actor_created_at timestamptz;
  actor_deactivated_at timestamptz;
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_head_delete_forbidden';
  end if;

  select exists (
    select 1
      from public.inbox_v2_tenant_policy_activation_transitions transition_row
     where transition_row.tenant_id = new.tenant_id
       and transition_row.family = new.family
       and transition_row.policy_id = new.policy_id
       and transition_row.resulting_head_revision = new.revision
       and transition_row.resulting_state = new.state
       and transition_row.resulting_policy_version = new.policy_version
       and transition_row.resulting_definition_contract_version =
           new.definition_contract_version
       and transition_row.resulting_definition_digest_sha256 =
           new.definition_digest_sha256
       and transition_row.resulting_approved_trusted_service_id =
           new.approved_trusted_service_id
       and (
         (
           new.state = 'active'
           and transition_row.operation = 'activate'
           and transition_row.actor_employee_id = new.activated_by_employee_id
           and transition_row.occurred_at = new.activated_at
         ) or (
           new.state = 'revoked'
           and transition_row.operation = 'revoke'
           and transition_row.actor_employee_id = new.revoked_by_employee_id
           and transition_row.occurred_at = new.revoked_at
         )
       )
  ) into transition_exists;

  if not transition_exists then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_transition_missing';
  end if;

  select version_row.approved_at
    into version_approved_at
    from public.inbox_v2_tenant_policy_versions version_row
   where version_row.tenant_id = new.tenant_id
     and version_row.family = new.family
     and version_row.policy_id = new.policy_id
     and version_row.policy_version = new.policy_version
     and version_row.definition_contract_version =
         new.definition_contract_version
     and version_row.definition_digest_sha256 = new.definition_digest_sha256
     and version_row.approved_trusted_service_id =
         new.approved_trusted_service_id
   for share;

  if not found or version_approved_at > new.activated_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_version_invalid';
  end if;

  if tg_op = 'INSERT' then
    if new.state <> 'active'
       or new.revision <> 1
       or new.created_at <> new.activated_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.tenant_policy_activation_bootstrap_invalid';
    end if;
    actor_id := new.activated_by_employee_id;
    actor_at := new.activated_at;
  else
    if row(new.tenant_id, new.family, new.policy_id, new.created_at)
       is distinct from
       row(old.tenant_id, old.family, old.policy_id, old.created_at)
       or new.revision <> old.revision + 1 then
      raise exception using
        errcode = '40001',
        message = 'inbox_v2.tenant_policy_activation_cas_conflict';
    end if;

    if old.state = 'active' then
      if new.state <> 'revoked'
         or row(
           new.policy_version,
           new.definition_contract_version,
           new.definition_digest_sha256,
           new.approved_trusted_service_id,
           new.activated_by_employee_id,
           new.activated_at
         ) is distinct from row(
           old.policy_version,
           old.definition_contract_version,
           old.definition_digest_sha256,
           old.approved_trusted_service_id,
           old.activated_by_employee_id,
           old.activated_at
         ) then
        raise exception using
          errcode = '23514',
          message = 'inbox_v2.tenant_policy_revocation_transition_invalid';
      end if;
      actor_id := new.revoked_by_employee_id;
      actor_at := new.revoked_at;
    else
      if new.state <> 'active'
         or new.revoked_by_employee_id is not null
         or new.revoked_at is not null
         or new.activated_at < old.revoked_at then
        raise exception using
          errcode = '23514',
          message = 'inbox_v2.tenant_policy_reactivation_transition_invalid';
      end if;
      actor_id := new.activated_by_employee_id;
      actor_at := new.activated_at;
    end if;
  end if;

  select employee_row.created_at, employee_row.deactivated_at
    into actor_created_at, actor_deactivated_at
    from public.employees employee_row
   where employee_row.tenant_id = new.tenant_id
     and employee_row.id = actor_id
   for share;

  if actor_id is null
     or actor_at is null
     or not found
     or actor_created_at > actor_at
     or (
       actor_deactivated_at is not null
       and actor_deactivated_at <= actor_at
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_actor_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_tenant_policy_activation_transition_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tenant_policy_activation_transition_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  head_row public.inbox_v2_tenant_policy_activation_heads%rowtype;
  version_approved_at timestamptz;
  actor_created_at timestamptz;
  actor_deactivated_at timestamptz;
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_transition_immutable';
  end if;

  if tg_op = 'UPDATE' then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_transition_immutable';
  end if;

  select * into head_row
    from public.inbox_v2_tenant_policy_activation_heads head_candidate
   where head_candidate.tenant_id = new.tenant_id
     and head_candidate.family = new.family
     and head_candidate.policy_id = new.policy_id
   for update;

  if new.expected_head_revision is null then
    if found or new.resulting_head_revision <> 1
       or new.previous_state is not null then
      raise exception using
        errcode = '40001',
        message = 'inbox_v2.tenant_policy_activation_cas_conflict';
    end if;
  else
    if not found
       or head_row.revision <> new.expected_head_revision
       or new.resulting_head_revision <> new.expected_head_revision + 1
       or row(
         new.previous_state,
         new.previous_policy_version,
         new.previous_definition_contract_version,
         new.previous_definition_digest_sha256,
         new.previous_approved_trusted_service_id
       ) is distinct from row(
         head_row.state,
         head_row.policy_version,
         head_row.definition_contract_version,
         head_row.definition_digest_sha256,
         head_row.approved_trusted_service_id
       ) then
      raise exception using
        errcode = '40001',
        message = 'inbox_v2.tenant_policy_activation_cas_conflict';
    end if;
  end if;

  if new.operation = 'activate' then
    if new.resulting_state <> 'active'
       or (
         new.expected_head_revision is not null
         and (
           head_row.state <> 'revoked'
           or new.occurred_at < head_row.revoked_at
         )
       ) then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.tenant_policy_activation_transition_invalid';
    end if;
  elsif new.operation = 'revoke' then
    if new.expected_head_revision is null
       or head_row.state <> 'active'
       or new.resulting_state <> 'revoked'
       or row(
         new.resulting_policy_version,
         new.resulting_definition_contract_version,
         new.resulting_definition_digest_sha256,
         new.resulting_approved_trusted_service_id
       ) is distinct from row(
         head_row.policy_version,
         head_row.definition_contract_version,
         head_row.definition_digest_sha256,
         head_row.approved_trusted_service_id
       )
       or new.occurred_at < head_row.activated_at then
      raise exception using
        errcode = '23514',
        message = 'inbox_v2.tenant_policy_revocation_transition_invalid';
    end if;
  end if;

  select version_row.approved_at
    into version_approved_at
    from public.inbox_v2_tenant_policy_versions version_row
   where version_row.tenant_id = new.tenant_id
     and version_row.family = new.family
     and version_row.policy_id = new.policy_id
     and version_row.policy_version = new.resulting_policy_version
     and version_row.definition_contract_version =
         new.resulting_definition_contract_version
     and version_row.definition_digest_sha256 =
         new.resulting_definition_digest_sha256
     and version_row.approved_trusted_service_id =
         new.resulting_approved_trusted_service_id
   for share;

  if not found or version_approved_at > new.occurred_at then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_version_invalid';
  end if;

  select employee_row.created_at, employee_row.deactivated_at
    into actor_created_at, actor_deactivated_at
    from public.employees employee_row
   where employee_row.tenant_id = new.tenant_id
     and employee_row.id = new.actor_employee_id
   for share;

  if not found
     or actor_created_at > new.occurred_at
     or (
       actor_deactivated_at is not null
       and actor_deactivated_at <= new.occurred_at
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_activation_actor_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_tenant_policy_version_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tenant_policy_version_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  employee_created_at timestamptz;
  employee_deactivated_at timestamptz;
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_version_immutable';
  end if;

  if tg_op = 'UPDATE' then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_version_immutable';
  end if;

  select employee_row.created_at, employee_row.deactivated_at
    into employee_created_at, employee_deactivated_at
    from public.employees employee_row
   where employee_row.tenant_id = new.tenant_id
     and employee_row.id = new.approved_by_employee_id
   for share;

  if not found
     or employee_created_at > new.approved_at
     or (
       employee_deactivated_at is not null
       and employee_deactivated_at <= new.approved_at
     ) then
    raise exception using
      errcode = '23514',
      message = 'inbox_v2.tenant_policy_approver_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_thread_route_policy_deferred_fallbacks(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_thread_route_policy_deferred_fallbacks() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
begin
  if tg_op <> 'INSERT' then
    perform public.inbox_v2_assert_thread_route_policy_fallbacks(
      old_row->>'tenant_id', old_row->>'policy_id',
      coalesce(old_row->>'revision', old_row->>'policy_revision')::bigint
    );
  end if;
  if tg_op <> 'DELETE' then
    perform public.inbox_v2_assert_thread_route_policy_fallbacks(
      new_row->>'tenant_id', new_row->>'policy_id',
      coalesce(new_row->>'revision', new_row->>'policy_revision')::bigint
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_thread_route_policy_deferred_head(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_thread_route_policy_deferred_head() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
begin
  if tg_op <> 'INSERT' then
    perform public.inbox_v2_assert_thread_route_policy_head(
      old_row->>'tenant_id', old_row->>'policy_id'
    );
  end if;
  if tg_op <> 'DELETE' then
    perform public.inbox_v2_assert_thread_route_policy_head(
      new_row->>'tenant_id', new_row->>'policy_id'
    );
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_thread_route_policy_guard_head_write(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_thread_route_policy_guard_head_write() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'INSERT' then
    if exists (
      select 1
        from public.inbox_v2_thread_route_policy_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.policy_id = new.policy_id
         and version_row.revision <> new.revision
    ) then
      raise exception using errcode = '40001',
        message = 'inbox_v2.thread_route_policy_head_initial_revision_conflict';
    end if;
  elsif to_jsonb(old) - array['revision', 'updated_at'] <>
        to_jsonb(new) - array['revision', 'updated_at']
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception using errcode = '40001',
      message = 'inbox_v2.thread_route_policy_head_cas_conflict';
  end if;

  perform 1
    from public.inbox_v2_thread_route_policy_versions version_row
   where version_row.tenant_id = new.tenant_id
     and version_row.policy_id = new.policy_id
     and version_row.revision = new.revision
     and version_row.conversation_id = new.conversation_id
     and version_row.external_thread_id = new.external_thread_id
     and version_row.operation_id = new.operation_id
     and version_row.content_kind_id is not distinct from new.content_kind_id
     and version_row.updated_at = new.updated_at
   for share;
  if not found then
    raise exception using errcode = '23514',
      message = 'inbox_v2.thread_route_policy_head_version_mismatch';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_thread_route_policy_guard_version_insert(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_thread_route_policy_guard_version_insert() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  current_head public.inbox_v2_thread_route_policy_heads%rowtype;
  first_version public.inbox_v2_thread_route_policy_versions%rowtype;
begin
  select * into current_head
    from public.inbox_v2_thread_route_policy_heads head_row
   where head_row.tenant_id = new.tenant_id
     and head_row.policy_id = new.policy_id
   for update;

  if current_head.policy_id is null then
    if (new.revision = 1 and new.created_at <> new.updated_at) or exists (
      select 1
        from public.inbox_v2_thread_route_policy_versions version_row
       where version_row.tenant_id = new.tenant_id
         and version_row.policy_id = new.policy_id
    ) then
      raise exception using errcode = '40001',
        message = 'inbox_v2.thread_route_policy_initial_revision_conflict';
    end if;
    return new;
  end if;

  select * into first_version
    from public.inbox_v2_thread_route_policy_versions version_row
   where version_row.tenant_id = new.tenant_id
     and version_row.policy_id = new.policy_id
   order by version_row.revision
   limit 1
   for share;

  if current_head.policy_id is null
     or first_version.policy_id is null
     or current_head.revision + 1 <> new.revision
     or current_head.conversation_id <> new.conversation_id
     or current_head.external_thread_id <> new.external_thread_id
     or current_head.operation_id <> new.operation_id
     or current_head.content_kind_id is distinct from new.content_kind_id
     or current_head.updated_at > new.updated_at
     or first_version.created_at <> new.created_at then
    raise exception using errcode = '40001',
      message = 'inbox_v2.thread_route_policy_version_cas_conflict';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_tm_action_attribution_valid(text, text, text, boolean); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_action_attribution_valid(checked_tenant_id text, checked_attribution_id text, expected_conversation_id text, source_attribution_allowed boolean) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select exists (
    select 1
      from public.inbox_v2_action_attributions attribution_row
      left join public.inbox_v2_conversation_participants participant_row
        on participant_row.tenant_id = attribution_row.tenant_id
       and participant_row.id = attribution_row.action_participant_id
       and participant_row.conversation_id = attribution_row.conversation_id
      left join public.inbox_v2_source_occurrences occurrence_row
        on occurrence_row.tenant_id = attribution_row.tenant_id
       and occurrence_row.id = attribution_row.source_occurrence_id
     where attribution_row.tenant_id = checked_tenant_id
       and attribution_row.id = checked_attribution_id
       and attribution_row.conversation_id = expected_conversation_id
       and (
         (attribution_row.app_actor_kind = 'employee'
           and attribution_row.source_occurrence_id is null
           and attribution_row.automation_kind is null
           and participant_row.subject_kind = 'employee'
           and participant_row.subject_employee_id =
             attribution_row.app_actor_employee_id)
         or (attribution_row.app_actor_kind = 'trusted_service'
           and attribution_row.source_occurrence_id is null
           and attribution_row.automation_kind is not null
           and (
             attribution_row.action_participant_id is null
             or participant_row.subject_kind = 'bot'
           ))
         or (source_attribution_allowed
           and attribution_row.app_actor_kind is null
           and attribution_row.source_occurrence_id is not null
           and attribution_row.automation_kind is null
           and (
              (occurrence_row.provider_actor_kind = 'source_external_identity'
                and participant_row.subject_kind = 'source_external_identity'
                and participant_row.subject_source_external_identity_id =
                  occurrence_row.provider_actor_source_external_identity_id)
              or (occurrence_row.provider_actor_kind = 'provider_system'
                and (
                  attribution_row.action_participant_id is null
                  or participant_row.subject_kind = 'system'
                ))
              or (occurrence_row.provider_actor_kind is null
                and attribution_row.action_participant_id is null)
            ))
       )
  );
$$;



--
-- Name: inbox_v2_tm_append_only_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_append_only_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  old_row jsonb := to_jsonb(old);
  parent_exists boolean := true;
  parent_key text;
  parent_offset integer;
begin
  -- FK cascades invoke the child guard below their RI trigger (depth > 1).
  -- Direct application DELETE reaches this guard at depth 1 and stays blocked.
  if tg_op = 'DELETE' and pg_trigger_depth() > 1 then
    return old;
  end if;

  if tg_op = 'DELETE' and not exists (
    select 1 from public.tenants tenant_row
     where tenant_row.id = old_row->>'tenant_id'
  ) then
    return old;
  end if;

  if tg_op = 'DELETE' and tg_nargs > 0 and tg_nargs % 3 = 0 then
    for parent_offset in 0..(tg_nargs / 3 - 1) loop
      parent_key := old_row->>tg_argv[parent_offset * 3 + 2];
      if parent_key is not null then
        execute format(
          'select exists (select 1 from %s where tenant_id = $1 and %I = $2)',
          tg_argv[parent_offset * 3]::regclass,
          tg_argv[parent_offset * 3 + 1]
        )
          into parent_exists
          using old_row->>'tenant_id', parent_key;

        if not parent_exists then
          return old;
        end if;
      end if;
    end loop;
  end if;

  raise exception using
    errcode = '23514',
    message = format(
      'inbox_v2.timeline_message_append_only:%s:%s',
      tg_table_name,
      tg_op
    );
end;
$_$;



--
-- Name: inbox_v2_tm_assert_reference_context(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_assert_reference_context(tenant_key text, message_key text) RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  message_kind public.inbox_v2_message_reference_kind;
  context_kind public.inbox_v2_message_reference_context_kind;
  provenance public.inbox_v2_provider_forward_provenance;
  message_origin public.inbox_v2_message_origin_kind;
  message_conversation_id text;
  canonical_count integer;
  external_count integer;
  unresolved_count integer;
begin
  select message_row.reference_kind, context_row.kind,
         context_row.provenance_completeness, message_row.origin_kind,
         message_row.conversation_id
    into message_kind, context_kind, provenance, message_origin,
         message_conversation_id
    from public.inbox_v2_messages message_row
    left join public.inbox_v2_message_reference_contexts context_row
      on context_row.tenant_id = message_row.tenant_id
     and context_row.message_id = message_row.id
   where message_row.tenant_id = tenant_key
     and message_row.id = message_key;

  if context_kind is null then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_reference_context_missing';
  end if;

  select count(*) into canonical_count
    from public.inbox_v2_message_reference_canonical_targets
   where tenant_id = tenant_key and message_id = message_key;
  select count(*) into external_count
    from public.inbox_v2_message_reference_external_targets
   where tenant_id = tenant_key and message_id = message_key;
  select count(*) into unresolved_count
    from public.inbox_v2_message_reference_unresolved_targets
   where tenant_id = tenant_key and message_id = message_key;

  if not (
    (message_kind = 'none' and context_kind = 'none'
      and canonical_count = 0 and external_count = 0 and unresolved_count = 0)
    or (message_kind = 'reply_resolved_internal' and context_kind = 'reply'
      and canonical_count = 1 and external_count = 0 and unresolved_count = 0)
    or (message_kind = 'reply_resolved_external' and context_kind = 'reply'
      and canonical_count = 1 and external_count = 1 and unresolved_count = 0)
    or (message_kind = 'reply_unresolved_source' and context_kind = 'reply'
      and canonical_count = 0 and external_count = 0 and unresolved_count = 1)
    or (message_kind = 'forward_content_copy'
      and context_kind = 'forward_content_copy'
      and canonical_count between 1 and 32
      and external_count = 0 and unresolved_count = 0)
    or (message_kind = 'forward_provider_native'
      and context_kind = 'forward_provider_native'
      and external_count = 1
      and canonical_count = 0 and unresolved_count = 0)
    or (message_kind = 'forward_provider_observed'
      and context_kind = 'forward_provider_observed'
      and external_count between 0 and 32
      and canonical_count = 0 and unresolved_count = 0
      and (provenance <> 'exact' or external_count >= 1))
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_reference_context_shape';
  end if;

  if exists (
    select 1
      from public.inbox_v2_message_reference_canonical_targets target_row
     where target_row.tenant_id = tenant_key
       and target_row.message_id = message_key
       and target_row.target_message_id = message_key
  ) or exists (
    select 1
      from public.inbox_v2_message_reference_external_targets target_row
      join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = target_row.tenant_id
       and reference_row.id = target_row.external_message_reference_id
     where target_row.tenant_id = tenant_key
       and target_row.message_id = message_key
       and reference_row.message_id = message_key
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_reference_self_target';
  end if;

  if message_kind in ('reply_resolved_internal', 'reply_resolved_external')
     and exists (
       select 1
         from public.inbox_v2_message_reference_canonical_targets target_row
         join public.inbox_v2_messages target_message
           on target_message.tenant_id = target_row.tenant_id
          and target_message.id = target_row.target_message_id
        where target_row.tenant_id = tenant_key
          and target_row.message_id = message_key
          and target_message.conversation_id <> message_conversation_id
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_reply_target_conversation_mismatch';
  end if;

  if message_kind = 'reply_resolved_external' and not exists (
    select 1
      from public.inbox_v2_message_reference_canonical_targets canonical_row
      join public.inbox_v2_message_reference_external_targets external_row
        on external_row.tenant_id = canonical_row.tenant_id
       and external_row.message_id = canonical_row.message_id
      join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = external_row.tenant_id
       and reference_row.id = external_row.external_message_reference_id
       and reference_row.message_id = canonical_row.target_message_id
       and reference_row.timeline_item_id = canonical_row.target_timeline_item_id
     where canonical_row.tenant_id = tenant_key
       and canonical_row.message_id = message_key
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_reply_target_identity_mismatch';
  end if;

  if message_kind = 'forward_content_copy'
     and message_origin = 'hulee_external' then
    perform 1
      from public.inbox_v2_message_reference_canonical_targets canonical_row
      join public.inbox_v2_message_revisions source_revision
        on source_revision.tenant_id = canonical_row.tenant_id
       and source_revision.message_id = canonical_row.target_message_id
       and source_revision.timeline_item_id =
         canonical_row.target_timeline_item_id
       and source_revision.message_revision =
         canonical_row.target_message_revision
      join public.inbox_v2_messages source_message
        on source_message.tenant_id = source_revision.tenant_id
       and source_message.id = source_revision.message_id
       and source_message.timeline_item_id = source_revision.timeline_item_id
       and source_message.revision = source_revision.message_revision
       and source_message.lifecycle = 'active'
       and source_message.content_id = source_revision.after_content_id
       and source_message.content_revision =
         source_revision.after_content_revision
       and source_message.content_state = source_revision.after_content_state
      join public.inbox_v2_timeline_contents source_content
        on source_content.tenant_id = source_message.tenant_id
       and source_content.id = source_message.content_id
       and source_content.owner_kind = 'message'
       and source_content.owner_id = source_message.id
       and source_content.revision = source_message.content_revision
       and source_content.state = 'available'
      join public.inbox_v2_messages destination_message
        on destination_message.tenant_id = canonical_row.tenant_id
       and destination_message.id = canonical_row.message_id
       and destination_message.origin_kind = 'hulee_external'
      join public.inbox_v2_timeline_contents destination_content
        on destination_content.tenant_id = destination_message.tenant_id
       and destination_content.id = destination_message.content_id
       and destination_content.owner_kind = 'message'
       and destination_content.owner_id = destination_message.id
       and destination_content.revision = destination_message.content_revision
       and destination_content.state = 'available'
     where canonical_row.tenant_id = tenant_key
       and canonical_row.message_id = message_key
       and canonical_count = 1
       and source_revision.after_content_state = 'available'
       and source_content.content_digest_sha256 is not null
       and destination_content.content_digest_sha256 is not null
       -- Content-copy preserves every ordered semantic field and immutable
       -- file/object pin. MessageAttachment ids are deliberately excluded:
       -- they are owner-scoped anchors and the destination must receive a new
       -- one. Keeping the comparison relational lets PostgreSQL validate the
       -- copy independently from the application-level normalized digest.
       and (
         select coalesce(
           jsonb_agg(
             to_jsonb(source_payload) - array[
               'content_id', 'content_revision', 'attachment_id', 'created_at'
             ]::text[]
             order by source_payload.ordinal
           ),
           '[]'::jsonb
         )
           from public.inbox_v2_timeline_content_payloads source_payload
          where source_payload.tenant_id = source_content.tenant_id
            and source_payload.content_id = source_content.id
            and source_payload.content_revision = source_content.revision
       ) = (
         select coalesce(
           jsonb_agg(
             to_jsonb(destination_payload) - array[
               'content_id', 'content_revision', 'attachment_id', 'created_at'
             ]::text[]
             order by destination_payload.ordinal
           ),
           '[]'::jsonb
         )
           from public.inbox_v2_timeline_content_payloads destination_payload
          where destination_payload.tenant_id = destination_content.tenant_id
            and destination_payload.content_id = destination_content.id
            and destination_payload.content_revision =
              destination_content.revision
       )
       and (
         select coalesce(
           jsonb_agg(
             to_jsonb(source_value) - array[
               'content_id', 'content_revision'
             ]::text[]
             order by source_value.block_ordinal, source_value.value_ordinal
           ),
           '[]'::jsonb
         )
           from public.inbox_v2_timeline_content_contact_values source_value
          where source_value.tenant_id = source_content.tenant_id
            and source_value.content_id = source_content.id
            and source_value.content_revision = source_content.revision
       ) = (
         select coalesce(
           jsonb_agg(
             to_jsonb(destination_value) - array[
               'content_id', 'content_revision'
             ]::text[]
             order by destination_value.block_ordinal,
                      destination_value.value_ordinal
           ),
           '[]'::jsonb
         )
           from public.inbox_v2_timeline_content_contact_values destination_value
          where destination_value.tenant_id = destination_content.tenant_id
            and destination_value.content_id = destination_content.id
            and destination_value.content_revision =
              destination_content.revision
       )
       and not exists (
         select 1
           from public.inbox_v2_timeline_content_payloads source_payload
           join public.inbox_v2_timeline_content_payloads destination_payload
             on destination_payload.tenant_id = source_payload.tenant_id
            and destination_payload.content_id = destination_content.id
            and destination_payload.content_revision =
              destination_content.revision
            and destination_payload.attachment_id =
              source_payload.attachment_id
          where source_payload.tenant_id = source_content.tenant_id
            and source_payload.content_id = source_content.id
            and source_payload.content_revision = source_content.revision
            and source_payload.attachment_id is not null
       )
     for share of source_message, source_content;

    if not found then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_content_copy_source_drift';
    end if;
  end if;

  if exists (
    select 1
      from public.inbox_v2_message_reference_external_targets target_row
      left join public.inbox_v2_source_occurrences occurrence_row
        on occurrence_row.tenant_id = target_row.tenant_id
       and occurrence_row.id = target_row.source_occurrence_id
      left join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = target_row.tenant_id
       and reference_row.id = target_row.external_message_reference_id
     where target_row.tenant_id = tenant_key
       and target_row.message_id = message_key
       and (
         occurrence_row.id is null or reference_row.id is null
         or occurrence_row.resolution_state <> 'resolved'
         or occurrence_row.resolved_external_message_reference_id <>
            target_row.external_message_reference_id
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_external_reference_target_invalid';
  end if;

  if exists (
    select 1
      from public.inbox_v2_message_reference_unresolved_targets target_row
      join public.inbox_v2_source_occurrences occurrence_row
        on occurrence_row.tenant_id = target_row.tenant_id
       and occurrence_row.id = target_row.source_occurrence_id
     where target_row.tenant_id = tenant_key
       and target_row.message_id = message_key
       and (
         occurrence_row.message_key_digest_sha256 <>
           target_row.external_message_key_digest_sha256
         or occurrence_row.resolution_state::text <>
           target_row.resolution_state
         or (target_row.resolution_state = 'pending' and exists (
           select 1
             from public.inbox_v2_message_reference_unresolved_candidates candidate_row
            where candidate_row.tenant_id = target_row.tenant_id
              and candidate_row.message_id = target_row.message_id
         ))
         or (target_row.resolution_state = 'conflicted' and (
           select count(*) = occurrence_row.resolution_candidate_count
              and min(candidate_row.ordinal) = 0
              and max(candidate_row.ordinal) =
                occurrence_row.resolution_candidate_count - 1
             from public.inbox_v2_message_reference_unresolved_candidates candidate_row
            where candidate_row.tenant_id = target_row.tenant_id
              and candidate_row.message_id = target_row.message_id
         ) is not true)
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_unresolved_reference_invalid';
  end if;

  if exists (
    select 1
      from public.inbox_v2_message_reference_unresolved_candidates candidate_row
      join public.inbox_v2_message_reference_unresolved_targets target_row
        on target_row.tenant_id = candidate_row.tenant_id
       and target_row.message_id = candidate_row.message_id
      left join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = candidate_row.tenant_id
       and reference_row.id = candidate_row.external_message_reference_id
     where candidate_row.tenant_id = tenant_key
       and candidate_row.message_id = message_key
       and (
         reference_row.id is null
         or reference_row.message_key_digest_sha256 <>
           target_row.external_message_key_digest_sha256
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_unresolved_candidate_invalid';
  end if;
end;
$$;



--
-- Name: inbox_v2_tm_aux_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_aux_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  changed_row jsonb;
  tenant_key text;
  message_key text;
  operation_key text;
  reaction_key text;
  receipt_key text;
  commit_token_key text;
begin
  changed_row := case when tg_op = 'DELETE' then to_jsonb(old) else to_jsonb(new) end;
  tenant_key := changed_row->>'tenant_id';

  if not exists (select 1 from public.tenants where id = tenant_key) then
    return null;
  end if;

  if tg_table_name in (
    'inbox_v2_message_transport_fact_commits',
    'inbox_v2_message_delivery_observations',
    'inbox_v2_provider_receipt_observations'
  ) then
    commit_token_key := changed_row->>'commit_token';

    if exists (
      select 1 from public.inbox_v2_message_transport_fact_commits ledger_row
       where ledger_row.tenant_id = tenant_key
         and ledger_row.commit_token = commit_token_key
    ) or exists (
      select 1 from public.inbox_v2_message_delivery_observations delivery_row
       where delivery_row.tenant_id = tenant_key
         and delivery_row.commit_token = commit_token_key
    ) or exists (
      select 1 from public.inbox_v2_provider_receipt_observations receipt_row
       where receipt_row.tenant_id = tenant_key
         and receipt_row.commit_token = commit_token_key
    ) then
      if not exists (
        select 1
          from public.inbox_v2_message_transport_fact_commits ledger_row
         where ledger_row.tenant_id = tenant_key
           and ledger_row.commit_token = commit_token_key
           and (
             (ledger_row.fact_kind = 'delivery'
               and exists (
                 select 1
                   from public.inbox_v2_message_delivery_observations delivery_row
                  where delivery_row.tenant_id = ledger_row.tenant_id
                    and delivery_row.commit_token = ledger_row.commit_token
                    and delivery_row.id = ledger_row.observation_id
                    and delivery_row.message_id = ledger_row.message_id
                    and delivery_row.commit_digest_sha256 =
                      ledger_row.commit_digest_sha256
                    and delivery_row.observed_at = ledger_row.observed_at
                    and delivery_row.recorded_at = ledger_row.recorded_at
                    and delivery_row.recorded_stream_position =
                      ledger_row.recorded_stream_position
                    and delivery_row.revision = ledger_row.revision
               )
               and not exists (
                 select 1
                   from public.inbox_v2_provider_receipt_observations receipt_row
                  where receipt_row.tenant_id = ledger_row.tenant_id
                    and receipt_row.commit_token = ledger_row.commit_token
               ))
             or (ledger_row.fact_kind = 'receipt'
               and exists (
                 select 1
                   from public.inbox_v2_provider_receipt_observations receipt_row
                  where receipt_row.tenant_id = ledger_row.tenant_id
                    and receipt_row.commit_token = ledger_row.commit_token
                    and receipt_row.id = ledger_row.observation_id
                    and receipt_row.target_message_id is not distinct from
                      ledger_row.message_id
                    and receipt_row.commit_digest_sha256 =
                      ledger_row.commit_digest_sha256
                    and receipt_row.observed_at = ledger_row.observed_at
                    and receipt_row.recorded_at = ledger_row.recorded_at
                    and receipt_row.recorded_stream_position =
                      ledger_row.recorded_stream_position
                    and receipt_row.revision = ledger_row.revision
               )
               and not exists (
                 select 1
                   from public.inbox_v2_message_delivery_observations delivery_row
                  where delivery_row.tenant_id = ledger_row.tenant_id
                    and delivery_row.commit_token = ledger_row.commit_token
               ))
           )
      ) then
        raise exception using errcode = '23514',
          message = 'inbox_v2.message_transport_fact_commit_coherence';
      end if;
    end if;
  end if;

  if tg_table_name = 'inbox_v2_outbound_route_consumptions'
     and tg_op <> 'DELETE' then
    if not exists (
      select 1
        from public.inbox_v2_outbound_route_consumptions consumption_row
        join public.inbox_v2_outbound_routes route_row
          on route_row.tenant_id = consumption_row.tenant_id
         and route_row.id = consumption_row.outbound_route_id
         and route_row.mutation_token = consumption_row.mutation_token
         and route_row.idempotency_token = consumption_row.idempotency_token
         and route_row.correlation_token = consumption_row.correlation_token
         and route_row.adapter_loaded_by_trusted_service_id =
           consumption_row.consumed_by_trusted_service_id
        join public.inbox_v2_messages message_row
          on message_row.tenant_id = consumption_row.tenant_id
         and message_row.id = consumption_row.message_id
         and message_row.conversation_id = route_row.conversation_id
       where consumption_row.tenant_id = tenant_key
         and consumption_row.id = changed_row->>'id'
         and (
           (consumption_row.consumer_kind = 'message_creation'
             and consumption_row.consumer_id = message_row.id
             and message_row.origin_kind = 'hulee_external'
             and message_row.origin_outbound_route_id = route_row.id
             and message_row.created_at = consumption_row.consumed_at)
           or (consumption_row.consumer_kind = 'provider_lifecycle'
             and exists (
               select 1
                 from public.inbox_v2_message_provider_lifecycle_operations op_row
                where op_row.tenant_id = consumption_row.tenant_id
                  and op_row.id = consumption_row.consumer_id
                  and op_row.message_id = consumption_row.message_id
                  and op_row.origin = 'hulee_requested'
                  and op_row.outbound_route_id = route_row.id
                  and op_row.recorded_at = consumption_row.consumed_at
             ))
           or (consumption_row.consumer_kind = 'reaction'
             and exists (
               select 1
                 from public.inbox_v2_message_reaction_transitions transition_row
                 join public.inbox_v2_message_reactions reaction_row
                   on reaction_row.tenant_id = transition_row.tenant_id
                  and reaction_row.id = transition_row.reaction_id
                where transition_row.tenant_id = consumption_row.tenant_id
                  and transition_row.id = consumption_row.consumer_id
                  and transition_row.mode = 'external_request'
                  and transition_row.outbound_route_id = route_row.id
                  and transition_row.recorded_at = consumption_row.consumed_at
                  and reaction_row.message_id = consumption_row.message_id
             ))
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.outbound_route_consumption_coherence';
    end if;
  end if;

  if tg_table_name = 'inbox_v2_message_transport_links' then
    message_key := changed_row->>'message_id';
    if tg_op <> 'DELETE' and not public.inbox_v2_tm_transport_occurrence_link_valid(
      tenant_key,
      changed_row->>'id'
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.transport_occurrence_link_invalid';
    end if;
  elsif tg_table_name = 'inbox_v2_message_transport_link_heads' then
    message_key := changed_row->>'message_id';
  end if;

  if message_key is not null and (
    exists (
      select 1 from public.inbox_v2_message_transport_links
       where tenant_id = tenant_key and message_id = message_key
    ) or exists (
      select 1 from public.inbox_v2_message_transport_link_heads
       where tenant_id = tenant_key and message_id = message_key
    )
  ) and not exists (
    select 1
      from public.inbox_v2_message_transport_link_heads head_row
      join public.inbox_v2_message_transport_links latest_row
        on latest_row.tenant_id = head_row.tenant_id
       and latest_row.id = head_row.latest_link_id
       and latest_row.message_id = head_row.message_id
       and latest_row.resulting_head_revision = head_row.revision
       and latest_row.recorded_stream_position =
         head_row.last_changed_stream_position
       and latest_row.linked_at = head_row.updated_at
     where head_row.tenant_id = tenant_key
       and head_row.message_id = message_key
       and head_row.link_count = (
         select count(*)
           from public.inbox_v2_message_transport_links link_row
          where link_row.tenant_id = head_row.tenant_id
            and link_row.message_id = head_row.message_id
       )
       and head_row.revision = head_row.link_count
       and 1 = (
         select min(link_row.resulting_head_revision)
           from public.inbox_v2_message_transport_links link_row
          where link_row.tenant_id = head_row.tenant_id
            and link_row.message_id = head_row.message_id
       )
       and head_row.revision = (
         select max(link_row.resulting_head_revision)
           from public.inbox_v2_message_transport_links link_row
          where link_row.tenant_id = head_row.tenant_id
            and link_row.message_id = head_row.message_id
       )
       and latest_row.id = (
         select link_row.id
           from public.inbox_v2_message_transport_links link_row
          where link_row.tenant_id = head_row.tenant_id
            and link_row.message_id = head_row.message_id
          order by link_row.resulting_head_revision desc
          limit 1
       )
       and not exists (
         select 1
           from public.inbox_v2_message_transport_links chain_row
          where chain_row.tenant_id = head_row.tenant_id
            and chain_row.message_id = head_row.message_id
            and chain_row.resulting_head_revision > 1
            and not exists (
              select 1
                from public.inbox_v2_message_transport_links predecessor_row
               where predecessor_row.tenant_id = chain_row.tenant_id
                 and predecessor_row.message_id = chain_row.message_id
                 and predecessor_row.resulting_head_revision =
                   chain_row.resulting_head_revision - 1
                 and predecessor_row.linked_at <= chain_row.linked_at
                 and predecessor_row.recorded_stream_position <
                   chain_row.recorded_stream_position
            )
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.transport_link_head_coherence';
  end if;

  if tg_table_name = 'inbox_v2_message_provider_lifecycle_operations' then
    operation_key := changed_row->>'id';
  elsif tg_table_name = 'inbox_v2_message_provider_lifecycle_transitions' then
    operation_key := changed_row->>'operation_id';
  end if;

  if operation_key is not null and exists (
    select 1 from public.inbox_v2_message_provider_lifecycle_operations
     where tenant_id = tenant_key and id = operation_key
  ) and not exists (
    select 1
      from public.inbox_v2_message_provider_lifecycle_operations op_row
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = op_row.tenant_id
       and message_row.id = op_row.message_id
      join public.inbox_v2_source_occurrences occurrence_row
        on occurrence_row.tenant_id = op_row.tenant_id
       and occurrence_row.id = op_row.source_occurrence_id
       and occurrence_row.source_account_id = op_row.source_account_id
       and occurrence_row.source_thread_binding_id = op_row.source_thread_binding_id
       and occurrence_row.binding_generation = op_row.binding_generation
       and occurrence_row.adapter_contract_id = op_row.adapter_contract_id
       and occurrence_row.adapter_contract_version =
         op_row.adapter_contract_version
       and occurrence_row.adapter_declaration_revision =
         op_row.adapter_declaration_revision
       and occurrence_row.adapter_surface_id = op_row.adapter_surface_id
       and occurrence_row.adapter_loaded_by_trusted_service_id =
         op_row.adapter_loaded_by_trusted_service_id
       and occurrence_row.adapter_loaded_at = op_row.adapter_loaded_at
       and occurrence_row.resolution_state = 'resolved'
       and occurrence_row.resolved_external_message_reference_id =
         op_row.external_message_reference_id
      join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = op_row.tenant_id
       and reference_row.id = op_row.external_message_reference_id
       and reference_row.message_id = op_row.message_id
      left join public.inbox_v2_outbound_routes lifecycle_route_row
        on lifecycle_route_row.tenant_id = op_row.tenant_id
       and lifecycle_route_row.id = op_row.outbound_route_id
     where op_row.tenant_id = tenant_key
       and op_row.id = operation_key
       and public.inbox_v2_tm_provider_lifecycle_history_valid(
         op_row.tenant_id,
         op_row.id
       )
       and (
         (op_row.origin = 'provider_observed' and op_row.outbound_route_id is null)
         or (op_row.origin = 'hulee_requested'
           and lifecycle_route_row.id is not null
            and lifecycle_route_row.required_conversation_permission_id =
              'core:conversation.read'
           and public.inbox_v2_tm_outbound_route_action_valid(
             op_row.tenant_id,
             op_row.outbound_route_id,
             op_row.message_id,
             op_row.message_id,
             message_row.conversation_id,
             op_row.recorded_at,
             op_row.recorded_at,
             'core:message.' || op_row.action::text,
             lifecycle_route_row.required_conversation_permission_id,
             op_row.external_message_reference_id,
             op_row.source_occurrence_id,
             op_row.source_account_id,
             op_row.source_thread_binding_id,
             op_row.binding_generation,
             op_row.adapter_contract_id,
             op_row.adapter_contract_version,
             op_row.adapter_declaration_revision,
             op_row.adapter_surface_id,
             op_row.adapter_loaded_by_trusted_service_id,
             op_row.adapter_loaded_at,
             'core:message-' || op_row.action::text,
             op_row.capability_revision,
             op_row.action_attribution_id,
             false
           )
           and exists (
             select 1
               from public.inbox_v2_outbound_route_consumptions consumption_row
              where consumption_row.tenant_id = op_row.tenant_id
                and consumption_row.consumer_kind = 'provider_lifecycle'
                and consumption_row.consumer_id = op_row.id
                and consumption_row.message_id = op_row.message_id
                and consumption_row.outbound_route_id = op_row.outbound_route_id
           ))
       )
       and (
         op_row.origin <> 'provider_observed'
         or (
           occurrence_row.normalized_inbound_event_id =
             op_row.provider_semantic_normalized_inbound_event_id
           and occurrence_row.provider_actor_source_external_identity_id
             is not distinct from
               op_row.provider_semantic_actor_external_identity_id
           and op_row.provider_semantic_capability_revision =
             occurrence_row.capability_revision
           and op_row.provider_semantic_proof_detail #>>
             '{adapterContract,contractId}' = op_row.adapter_contract_id
           and op_row.provider_semantic_proof_detail #>>
             '{adapterContract,contractVersion}' =
               op_row.adapter_contract_version
           and op_row.provider_semantic_proof_detail #>>
             '{adapterContract,declarationRevision}' =
               op_row.adapter_declaration_revision::text
           and op_row.provider_semantic_proof_detail #>>
             '{adapterContract,surfaceId}' = op_row.adapter_surface_id
           and op_row.provider_semantic_proof_detail #>>
             '{adapterContract,loadedByTrustedServiceId}' =
               op_row.adapter_loaded_by_trusted_service_id
           and (op_row.provider_semantic_proof_detail #>>
             '{adapterContract,loadedAt}')::timestamptz =
               op_row.adapter_loaded_at
           and (op_row.provider_semantic_proof_detail #>> '{occurredAt}')::timestamptz =
             op_row.occurred_at
           and (op_row.provider_semantic_proof_detail #>> '{recordedAt}')::timestamptz =
             op_row.recorded_at
         )
       )
       and not exists (
         select 1
           from public.inbox_v2_message_provider_lifecycle_transitions chain_row
          where chain_row.tenant_id = op_row.tenant_id
            and chain_row.operation_id = op_row.id
            and (
              chain_row.resulting_revision > op_row.revision
              or (
                chain_row.expected_revision > 1
                and not exists (
                  select 1
                    from public.inbox_v2_message_provider_lifecycle_transitions predecessor_row
                   where predecessor_row.tenant_id = chain_row.tenant_id
                     and predecessor_row.operation_id = chain_row.operation_id
                     and predecessor_row.resulting_revision =
                       chain_row.expected_revision
                )
              )
            )
       )
       and (
         (op_row.revision = 1 and not exists (
           select 1
             from public.inbox_v2_message_provider_lifecycle_transitions transition_row
            where transition_row.tenant_id = op_row.tenant_id
              and transition_row.operation_id = op_row.id
         ))
         or (op_row.revision > 1 and exists (
           select 1
             from public.inbox_v2_message_provider_lifecycle_transitions transition_row
            where transition_row.tenant_id = op_row.tenant_id
              and transition_row.operation_id = op_row.id
              and transition_row.resulting_revision = op_row.revision
              and transition_row.outcome = op_row.outcome
              and transition_row.outcome_retryable is not distinct from
                op_row.outcome_retryable
              and transition_row.outcome_reason_id is not distinct from
                op_row.outcome_reason_id
              and transition_row.delete_local_effect is not distinct from
                op_row.delete_local_effect
              and transition_row.policy_decision_event_id is not distinct from
                op_row.policy_decision_event_id
              and transition_row.policy_decision_revision is not distinct from
                op_row.policy_decision_revision
              and transition_row.policy_decided_at is not distinct from
                op_row.policy_decided_at
              and transition_row.recorded_at = op_row.updated_at
              and transition_row.recorded_stream_position =
                op_row.last_changed_stream_position
         ))
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.provider_lifecycle_operation_coherence';
  end if;

  if tg_table_name = 'inbox_v2_message_reactions' then
    reaction_key := changed_row->>'id';
  elsif tg_table_name in (
    'inbox_v2_message_reaction_transitions',
    'inbox_v2_message_reaction_slot_heads'
  ) then
    reaction_key := changed_row->>'reaction_id';
  elsif tg_table_name = 'inbox_v2_message_provider_reaction_observations' then
    select transition_row.reaction_id into reaction_key
      from public.inbox_v2_message_reaction_transitions transition_row
     where transition_row.tenant_id = tenant_key
       and transition_row.id = changed_row->>'transition_id';
  end if;

  if tg_table_name = 'inbox_v2_message_reaction_transitions'
     and tg_op <> 'DELETE'
     and exists (
       select 1
         from public.inbox_v2_message_reaction_transitions transition_row
        where transition_row.tenant_id = tenant_key
          and transition_row.id = changed_row->>'id'
          and transition_row.mode = 'external_request'
     )
     and not exists (
       select 1
         from public.inbox_v2_message_reaction_transitions transition_row
         join public.inbox_v2_message_reactions reaction_row
           on reaction_row.tenant_id = transition_row.tenant_id
          and reaction_row.id = transition_row.reaction_id
         join public.inbox_v2_outbound_route_consumptions consumption_row
           on consumption_row.tenant_id = transition_row.tenant_id
          and consumption_row.consumer_kind = 'reaction'
          and consumption_row.consumer_id = transition_row.id
          and consumption_row.message_id = reaction_row.message_id
          and consumption_row.outbound_route_id = transition_row.outbound_route_id
        where transition_row.tenant_id = tenant_key
          and transition_row.id = changed_row->>'id'
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.reaction_route_consumption_missing';
  end if;

  if reaction_key is not null and exists (
    select 1 from public.inbox_v2_message_reactions
     where tenant_id = tenant_key and id = reaction_key
  ) and not exists (
    select 1
      from public.inbox_v2_message_reactions reaction_row
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = reaction_row.tenant_id
       and message_row.id = reaction_row.message_id
      join public.inbox_v2_message_reaction_slot_heads slot_row
        on slot_row.tenant_id = reaction_row.tenant_id
       and slot_row.message_id = reaction_row.message_id
       and slot_row.semantic_slot_key = reaction_row.semantic_slot_key
       and slot_row.reaction_id = reaction_row.id
       and slot_row.state_kind = reaction_row.state_kind
       and slot_row.revision = reaction_row.revision
     where reaction_row.tenant_id = tenant_key
       and reaction_row.id = reaction_key
       and (
         reaction_row.actor_participant_id is null or exists (
           select 1 from public.inbox_v2_conversation_participants participant_row
            where participant_row.tenant_id = reaction_row.tenant_id
              and participant_row.id = reaction_row.actor_participant_id
              and participant_row.conversation_id = message_row.conversation_id
         )
       )
       and not exists (
         select 1
           from public.inbox_v2_message_reaction_transitions chain_row
          where chain_row.tenant_id = reaction_row.tenant_id
            and chain_row.reaction_id = reaction_row.id
            and (
             chain_row.resulting_revision > reaction_row.revision
             or ((chain_row.mode = 'provider_observed') <>
               exists (
                 select 1
                   from public.inbox_v2_message_provider_reaction_observations
                     observation_row
                  where observation_row.tenant_id = chain_row.tenant_id
                    and observation_row.transition_id = chain_row.id
               ))
              or (
               chain_row.expected_revision is null
               and chain_row.recorded_at <> reaction_row.created_at
             )
             or (
               chain_row.expected_revision is not null
                and not exists (
                  select 1
                    from public.inbox_v2_message_reaction_transitions predecessor_row
                   where predecessor_row.tenant_id = chain_row.tenant_id
                     and predecessor_row.reaction_id = chain_row.reaction_id
                     and predecessor_row.resulting_revision =
                       chain_row.expected_revision
                     and predecessor_row.after_state_kind =
                       chain_row.before_state_kind
                     and predecessor_row.after_state_detail =
                       chain_row.before_state_detail
                      and predecessor_row.after_state_detail_digest_sha256 =
                        chain_row.before_state_detail_digest_sha256
                      and predecessor_row.recorded_at <= chain_row.recorded_at
                      and predecessor_row.recorded_stream_position <
                        chain_row.recorded_stream_position
                 )
              )
            )
       )
       and exists (
         select 1 from public.inbox_v2_message_reaction_transitions transition_row
          where transition_row.tenant_id = reaction_row.tenant_id
            and transition_row.reaction_id = reaction_row.id
            and transition_row.semantic_slot_key = reaction_row.semantic_slot_key
            and transition_row.resulting_revision = reaction_row.revision
            and transition_row.after_state_kind = reaction_row.state_kind
            and transition_row.value_kind = reaction_row.value_kind
            and transition_row.unicode_value is not distinct from
              reaction_row.unicode_value
            and transition_row.provider_reaction_kind_id is not distinct from
              reaction_row.provider_reaction_kind_id
            and transition_row.provider_canonical_code is not distinct from
              reaction_row.provider_canonical_code
            and transition_row.after_state_detail = reaction_row.state_detail
            and transition_row.after_state_detail_digest_sha256 =
              reaction_row.state_detail_digest_sha256
            and transition_row.recorded_at = reaction_row.updated_at
            and transition_row.result_token is not distinct from
              reaction_row.result_token
            and transition_row.result_digest_sha256 is not distinct from
              reaction_row.result_digest_sha256
            and (
              reaction_row.state_kind = 'active'
              or (
                reaction_row.state_kind = 'cleared'
                and (reaction_row.state_detail #>>
                  '{clearedAt}')::timestamptz = reaction_row.cleared_at
              )
              or (
                reaction_row.state_kind = 'pending_external'
                and transition_row.operation =
                  reaction_row.external_operation
                and reaction_row.state_detail #>> '{operation}' =
                  reaction_row.external_operation::text
                and reaction_row.state_detail #>>
                  '{outboundRoute,tenantId}' = reaction_row.tenant_id
                and reaction_row.state_detail #>> '{outboundRoute,kind}' =
                  'outbound_route'
                and reaction_row.state_detail #>> '{outboundRoute,id}' =
                  reaction_row.outbound_route_id
                and reaction_row.state_detail #>>
                  '{requestTransition,tenantId}' = reaction_row.tenant_id
                and reaction_row.state_detail #>>
                  '{requestTransition,kind}' = 'message_reaction_transition'
                and reaction_row.state_detail #>> '{requestTransition,id}' =
                  reaction_row.request_transition_id
                and reaction_row.request_transition_id = transition_row.id
                and reaction_row.request_attribution_id =
                  transition_row.action_attribution_id
                and (reaction_row.state_detail #>>
                  '{requestedAt}')::timestamptz = reaction_row.updated_at
              )
              or (
                reaction_row.state_kind = 'external_terminal'
                and transition_row.operation =
                  reaction_row.external_operation
                and reaction_row.state_detail #>> '{operation}' =
                  reaction_row.external_operation::text
                and reaction_row.state_detail #>>
                  '{outboundRoute,tenantId}' = reaction_row.tenant_id
                and reaction_row.state_detail #>> '{outboundRoute,kind}' =
                  'outbound_route'
                and reaction_row.state_detail #>> '{outboundRoute,id}' =
                  reaction_row.outbound_route_id
                and reaction_row.state_detail #>>
                  '{requestTransition,tenantId}' = reaction_row.tenant_id
                and reaction_row.state_detail #>>
                  '{requestTransition,kind}' = 'message_reaction_transition'
                and reaction_row.state_detail #>> '{requestTransition,id}' =
                  reaction_row.request_transition_id
                and reaction_row.state_detail #>> '{outcome}' =
                  reaction_row.external_outcome
                and reaction_row.state_detail #>> '{resultToken}' =
                  reaction_row.result_token
                and reaction_row.state_detail #>> '{resultDigestSha256}' =
                  reaction_row.result_digest_sha256
                and (reaction_row.state_detail #>>
                  '{resolvedAt}')::timestamptz = reaction_row.resolved_at
              )
            )
            and transition_row.recorded_stream_position =
              reaction_row.last_changed_stream_position
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_reaction_head_coherence';
  end if;

  if tg_table_name = 'inbox_v2_message_delivery_observations'
     and tg_op <> 'DELETE' then
    if not exists (
      select 1
        from public.inbox_v2_message_delivery_observations observation_row
       where observation_row.tenant_id = tenant_key
         and observation_row.id = changed_row->>'id'
         and exists (
           select 1
             from public.inbox_v2_source_thread_binding_snapshots snapshot_row
            where snapshot_row.tenant_id = observation_row.tenant_id
              and snapshot_row.binding_id =
                observation_row.source_thread_binding_id
              and snapshot_row.source_account_id =
                observation_row.source_account_id
              and snapshot_row.binding_generation =
                observation_row.binding_generation
              and snapshot_row.capability_contract_id =
                observation_row.adapter_contract_id
              and snapshot_row.capability_contract_version =
                observation_row.adapter_contract_version
              and snapshot_row.capability_declaration_revision =
                observation_row.adapter_declaration_revision
              and snapshot_row.capability_surface_id =
                observation_row.adapter_surface_id
              and snapshot_row.capability_loaded_by_trusted_service_id =
                observation_row.adapter_loaded_by_trusted_service_id
              and snapshot_row.capability_loaded_at =
                observation_row.adapter_loaded_at
              and snapshot_row.capability_revision =
                observation_row.capability_revision
              and exists (
                select 1
                  from public.inbox_v2_source_thread_binding_capability_entries capability_row
                 where capability_row.tenant_id = snapshot_row.tenant_id
                   and capability_row.binding_id = snapshot_row.binding_id
                   and capability_row.materialized_by_binding_revision =
                     snapshot_row.revision
                   and capability_row.capability_revision =
                     snapshot_row.capability_revision
                   and capability_row.capability_id =
                     observation_row.capability_id
              )
         )
         and (
           (observation_row.scope_kind = 'dispatch' and exists (
             select 1
               from public.inbox_v2_outbound_dispatches dispatch_row
               join public.inbox_v2_outbound_dispatch_attempts attempt_row
                 on attempt_row.tenant_id = dispatch_row.tenant_id
                and attempt_row.id = observation_row.scope_attempt_id
                and attempt_row.dispatch_id = dispatch_row.id
                and attempt_row.route_id = dispatch_row.route_id
                and attempt_row.message_id = dispatch_row.message_id
               join public.inbox_v2_outbound_routes route_row
                 on route_row.tenant_id = dispatch_row.tenant_id
                and route_row.id = dispatch_row.route_id
               join public.inbox_v2_messages message_row
                 on message_row.tenant_id = dispatch_row.tenant_id
                and message_row.id = dispatch_row.message_id
               where dispatch_row.tenant_id = observation_row.tenant_id
                 and dispatch_row.id = observation_row.scope_dispatch_id
                 and dispatch_row.message_id = observation_row.message_id
                 and dispatch_row.state <> 'queued'
                 and dispatch_row.last_attempt_id = attempt_row.id
                 and dispatch_row.attempt_count >= attempt_row.attempt_number
                 and message_row.origin_kind = 'hulee_external'
                 and message_row.origin_outbound_route_id = route_row.id
                 and route_row.source_account_id = observation_row.source_account_id
                 and route_row.source_thread_binding_id =
                   observation_row.source_thread_binding_id
                 and route_row.binding_generation =
                   observation_row.binding_generation
                 and route_row.adapter_contract_id =
                   observation_row.adapter_contract_id
                 and route_row.adapter_contract_version =
                   observation_row.adapter_contract_version
                 and route_row.adapter_declaration_revision =
                   observation_row.adapter_declaration_revision
                 and route_row.adapter_surface_id = observation_row.adapter_surface_id
                 and route_row.adapter_loaded_by_trusted_service_id =
                   observation_row.adapter_loaded_by_trusted_service_id
                 and route_row.adapter_loaded_at = observation_row.adapter_loaded_at
                 and route_row.capability_revision =
                   observation_row.capability_revision
                 and (
                   observation_row.scope_artifact_id is null
                   or exists (
                    select 1
                      from public.inbox_v2_outbound_dispatch_artifacts artifact_row
                     where artifact_row.tenant_id = dispatch_row.tenant_id
                       and artifact_row.id = observation_row.scope_artifact_id
                       and artifact_row.dispatch_id = dispatch_row.id
                       and artifact_row.route_id = dispatch_row.route_id
                       and artifact_row.message_id = dispatch_row.message_id
                       and artifact_row.attempt_id =
                         observation_row.scope_attempt_id
                  )
                 )
            ))
            or (observation_row.scope_kind = 'external_reference' and exists (
              select 1
                from public.inbox_v2_external_message_references reference_row
                join public.inbox_v2_source_occurrences occurrence_row
                  on occurrence_row.tenant_id = reference_row.tenant_id
                 and occurrence_row.id = observation_row.scope_source_occurrence_id
                 and occurrence_row.resolution_state = 'resolved'
                 and occurrence_row.resolved_external_message_reference_id =
                   reference_row.id
                 and occurrence_row.external_thread_id =
                   reference_row.external_thread_id
                 and occurrence_row.conversation_id = reference_row.conversation_id
                 and occurrence_row.message_key_digest_sha256 =
                   reference_row.message_key_digest_sha256
               where reference_row.tenant_id = observation_row.tenant_id
                 and reference_row.id =
                   observation_row.scope_external_message_reference_id
                 and reference_row.message_id = observation_row.message_id
            ))
            or (observation_row.scope_kind = 'recipient' and exists (
              select 1
                from public.inbox_v2_external_message_references reference_row
               where reference_row.tenant_id = observation_row.tenant_id
                 and reference_row.id =
                   observation_row.scope_external_message_reference_id
                 and reference_row.message_id = observation_row.message_id
            ))
          )
         and (
           (observation_row.evidence_kind = 'provider_result' and exists (
             select 1
               from public.inbox_v2_outbound_dispatch_attempts attempt_row
               join public.inbox_v2_outbound_routes route_row
                 on route_row.tenant_id = attempt_row.tenant_id
                and route_row.id = attempt_row.route_id
              where attempt_row.tenant_id = observation_row.tenant_id
                and attempt_row.id = observation_row.evidence_attempt_id
                and attempt_row.dispatch_id = observation_row.scope_dispatch_id
                and attempt_row.id = observation_row.scope_attempt_id
                and attempt_row.message_id = observation_row.message_id
                and route_row.source_account_id =
                  observation_row.source_account_id
                and route_row.source_thread_binding_id =
                  observation_row.source_thread_binding_id
                and route_row.binding_generation =
                  observation_row.binding_generation
                and route_row.adapter_contract_id =
                  observation_row.adapter_contract_id
                and route_row.adapter_contract_version =
                  observation_row.adapter_contract_version
                and route_row.adapter_declaration_revision =
                  observation_row.adapter_declaration_revision
                and route_row.adapter_surface_id =
                  observation_row.adapter_surface_id
                and route_row.adapter_loaded_by_trusted_service_id =
                  observation_row.adapter_loaded_by_trusted_service_id
                and route_row.adapter_loaded_at = observation_row.adapter_loaded_at
                 and route_row.capability_revision =
                   observation_row.capability_revision
                 and attempt_row.completion_source = 'provider_result'
                 and (
                   (observation_row.fact = 'accepted'
                     and attempt_row.outcome_kind = 'accepted')
                   or (observation_row.fact = 'failed'
                     and attempt_row.outcome_kind in (
                       'retryable_failure', 'terminal_failure'
                     ))
                 )
            ))
           or (observation_row.evidence_kind = 'provider_artifact' and exists (
             select 1
               from public.inbox_v2_outbound_dispatch_artifacts artifact_row
               join public.inbox_v2_outbound_dispatch_attempts attempt_row
                 on attempt_row.tenant_id = artifact_row.tenant_id
                and attempt_row.id = artifact_row.attempt_id
                and attempt_row.dispatch_id = artifact_row.dispatch_id
                and attempt_row.route_id = artifact_row.route_id
                and attempt_row.message_id = artifact_row.message_id
               join public.inbox_v2_outbound_routes route_row
                 on route_row.tenant_id = attempt_row.tenant_id
                and route_row.id = attempt_row.route_id
              where artifact_row.tenant_id = observation_row.tenant_id
                and artifact_row.id = observation_row.evidence_artifact_id
                and artifact_row.id = observation_row.scope_artifact_id
                and artifact_row.attempt_id = observation_row.evidence_attempt_id
                and artifact_row.attempt_id = observation_row.scope_attempt_id
                and artifact_row.dispatch_id = observation_row.scope_dispatch_id
                and artifact_row.message_id = observation_row.message_id
                and route_row.source_account_id =
                  observation_row.source_account_id
                and route_row.source_thread_binding_id =
                  observation_row.source_thread_binding_id
                and route_row.binding_generation =
                  observation_row.binding_generation
                and route_row.adapter_contract_id =
                  observation_row.adapter_contract_id
                and route_row.adapter_contract_version =
                  observation_row.adapter_contract_version
                and route_row.adapter_declaration_revision =
                  observation_row.adapter_declaration_revision
                and route_row.adapter_surface_id =
                  observation_row.adapter_surface_id
                and route_row.adapter_loaded_by_trusted_service_id =
                  observation_row.adapter_loaded_by_trusted_service_id
                and route_row.adapter_loaded_at = observation_row.adapter_loaded_at
                 and route_row.capability_revision =
                   observation_row.capability_revision
                 and (
                   (observation_row.fact = 'accepted'
                     and artifact_row.state = 'accepted')
                   or (observation_row.fact = 'failed'
                     and artifact_row.state = 'failed')
                 )
            ))
           or (observation_row.evidence_kind = 'provider_event' and exists (
               select 1
                 from public.inbox_v2_source_occurrences occurrence_row
                 join public.inbox_v2_external_message_references reference_row
                   on reference_row.tenant_id = occurrence_row.tenant_id
                   and reference_row.id =
                     observation_row.evidence_external_message_reference_id
                   and reference_row.message_id = observation_row.message_id
                   and reference_row.external_thread_id =
                     occurrence_row.external_thread_id
                   and reference_row.conversation_id = occurrence_row.conversation_id
                   and reference_row.message_key_digest_sha256 =
                     occurrence_row.message_key_digest_sha256
                 where occurrence_row.tenant_id = observation_row.tenant_id
                  and occurrence_row.id =
                    observation_row.evidence_source_occurrence_id
                  and occurrence_row.normalized_inbound_event_id =
                    observation_row.evidence_normalized_inbound_event_id
                  and occurrence_row.source_account_id =
                    observation_row.source_account_id
                  and occurrence_row.source_thread_binding_id =
                    observation_row.source_thread_binding_id
                  and occurrence_row.binding_generation =
                    observation_row.binding_generation
                  and occurrence_row.adapter_contract_id =
                    observation_row.adapter_contract_id
                  and occurrence_row.adapter_contract_version =
                    observation_row.adapter_contract_version
                  and occurrence_row.adapter_declaration_revision =
                    observation_row.adapter_declaration_revision
                  and occurrence_row.adapter_surface_id =
                    observation_row.adapter_surface_id
                  and occurrence_row.adapter_loaded_by_trusted_service_id =
                    observation_row.adapter_loaded_by_trusted_service_id
                  and occurrence_row.adapter_loaded_at =
                    observation_row.adapter_loaded_at
                   and occurrence_row.capability_revision =
                     observation_row.capability_revision
                   and occurrence_row.resolution_state = 'resolved'
                   and occurrence_row.resolved_external_message_reference_id =
                     observation_row.evidence_external_message_reference_id
                   and occurrence_row.origin_kind <> 'provider_response'
                   and (
                     observation_row.scope_kind <> 'dispatch'
                     or (
                       occurrence_row.origin_kind = 'provider_echo'
                       and occurrence_row.direction = 'outbound'
                     )
                   )
                   and (
                     observation_row.scope_kind = 'dispatch'
                     or (observation_row.scope_kind = 'external_reference'
                       and observation_row.scope_external_message_reference_id =
                         reference_row.id
                       and observation_row.scope_source_occurrence_id =
                         occurrence_row.id)
                     or (observation_row.scope_kind = 'recipient'
                       and observation_row.scope_external_message_reference_id =
                         reference_row.id)
                   )
              ))
         )
         and (
           (observation_row.evidence_kind <> 'provider_event'
             and observation_row.semantic_proof_detail is null
             and observation_row.semantic_proof_digest_sha256 is null)
           or (observation_row.evidence_kind = 'provider_event'
             and observation_row.semantic_proof_digest_sha256 is not null
             and public.inbox_v2_tm_provider_fact_semantic_proof_valid(
               observation_row.semantic_proof_detail,
               observation_row.tenant_id,
               observation_row.evidence_normalized_inbound_event_id,
               observation_row.evidence_external_message_reference_id,
               observation_row.evidence_source_occurrence_id,
               observation_row.source_account_id,
               observation_row.source_thread_binding_id,
               observation_row.binding_generation,
               observation_row.adapter_contract_id,
               observation_row.adapter_contract_version,
               observation_row.adapter_declaration_revision,
               observation_row.adapter_surface_id,
               observation_row.adapter_loaded_by_trusted_service_id,
               observation_row.adapter_loaded_at,
               observation_row.capability_id,
               observation_row.capability_revision,
               'core:message.delivery.' || observation_row.fact::text,
               case when observation_row.scope_kind = 'recipient'
                 then observation_row.scope_recipient_source_identity_id
                 else null
               end,
               observation_row.observed_at,
               observation_row.recorded_at
             ))
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_delivery_observation_coherence';
    end if;
  end if;

  if tg_table_name = 'inbox_v2_provider_receipt_observations'
     and tg_op <> 'DELETE' then
    receipt_key := changed_row->>'id';
  elsif tg_table_name = 'inbox_v2_provider_receipt_opaque_payloads'
     and tg_op <> 'DELETE' then
    receipt_key := changed_row->>'receipt_observation_id';
  end if;

  if receipt_key is not null then
    if not exists (
      select 1
        from public.inbox_v2_provider_receipt_observations receipt_row
       where receipt_row.tenant_id = tenant_key
         and receipt_row.id = receipt_key
         and exists (
           select 1
             from public.inbox_v2_source_thread_binding_snapshots snapshot_row
             join public.normalized_inbound_events event_row
               on event_row.tenant_id = snapshot_row.tenant_id
              and event_row.id = receipt_row.evidence_normalized_inbound_event_id
              and event_row.source_connection_id =
                snapshot_row.source_connection_id
              and event_row.source_account_id = snapshot_row.source_account_id
            where snapshot_row.tenant_id = receipt_row.tenant_id
              and snapshot_row.binding_id = receipt_row.source_thread_binding_id
              and snapshot_row.source_account_id = receipt_row.source_account_id
              and snapshot_row.binding_generation =
                receipt_row.binding_generation
              and snapshot_row.capability_contract_id =
                receipt_row.adapter_contract_id
              and snapshot_row.capability_contract_version =
                receipt_row.adapter_contract_version
              and snapshot_row.capability_declaration_revision =
                receipt_row.adapter_declaration_revision
              and snapshot_row.capability_surface_id =
                receipt_row.adapter_surface_id
              and snapshot_row.capability_loaded_by_trusted_service_id =
                receipt_row.adapter_loaded_by_trusted_service_id
              and snapshot_row.capability_loaded_at = receipt_row.adapter_loaded_at
              and snapshot_row.capability_revision =
                receipt_row.capability_revision
              and exists (
                select 1
                  from public.inbox_v2_source_thread_binding_capability_entries capability_row
                 where capability_row.tenant_id = snapshot_row.tenant_id
                   and capability_row.binding_id = snapshot_row.binding_id
                   and capability_row.materialized_by_binding_revision =
                     snapshot_row.revision
                   and capability_row.capability_revision =
                     snapshot_row.capability_revision
                   and capability_row.capability_id = receipt_row.capability_id
              )
         )
         and (
           receipt_row.target_kind <> 'exact_message' or exists (
             select 1
               from public.inbox_v2_messages message_row
                join public.inbox_v2_source_occurrences occurrence_row
                  on occurrence_row.tenant_id = message_row.tenant_id
                 and occurrence_row.id = receipt_row.target_source_occurrence_id
                 and occurrence_row.resolution_state = 'resolved'
                 and occurrence_row.source_account_id = receipt_row.source_account_id
                 and occurrence_row.source_thread_binding_id =
                   receipt_row.source_thread_binding_id
                and occurrence_row.binding_generation =
                  receipt_row.binding_generation
                 and occurrence_row.normalized_inbound_event_id =
                   receipt_row.evidence_normalized_inbound_event_id
                 and occurrence_row.resolved_external_message_reference_id =
                   receipt_row.target_external_message_reference_id
                 and occurrence_row.origin_kind <> 'provider_response'
                 and occurrence_row.adapter_contract_id =
                   receipt_row.adapter_contract_id
                 and occurrence_row.adapter_contract_version =
                   receipt_row.adapter_contract_version
                 and occurrence_row.adapter_declaration_revision =
                   receipt_row.adapter_declaration_revision
                 and occurrence_row.adapter_surface_id = receipt_row.adapter_surface_id
                 and occurrence_row.adapter_loaded_by_trusted_service_id =
                   receipt_row.adapter_loaded_by_trusted_service_id
                 and occurrence_row.adapter_loaded_at = receipt_row.adapter_loaded_at
                 and occurrence_row.capability_revision =
                   receipt_row.capability_revision
                join public.inbox_v2_external_message_references reference_row
                  on reference_row.tenant_id = message_row.tenant_id
                 and reference_row.id =
                   receipt_row.target_external_message_reference_id
                 and reference_row.message_id = message_row.id
                 and reference_row.external_thread_id =
                   occurrence_row.external_thread_id
                 and reference_row.conversation_id = occurrence_row.conversation_id
                 and reference_row.message_key_digest_sha256 =
                   occurrence_row.message_key_digest_sha256
               where message_row.tenant_id = receipt_row.tenant_id
                 and message_row.id = receipt_row.target_message_id
                 and (
                   (occurrence_row.provider_actor_kind =
                       'source_external_identity'
                     and receipt_row.reader_kind = 'source_external_identity'
                     and receipt_row.reader_source_external_identity_id =
                       occurrence_row.provider_actor_source_external_identity_id)
                   or (occurrence_row.provider_actor_kind is distinct from
                         'source_external_identity'
                     and receipt_row.reader_kind = 'aggregate_only')
                 )
            )
         )
         and (
           (receipt_row.opaque_payload_id is null
             and receipt_row.opaque_data_class_id is null
             and receipt_row.provider_watermark_digest_sha256 is null
             and receipt_row.reader_aggregate_key_digest_sha256 is null
             and not exists (
               select 1
                 from public.inbox_v2_provider_receipt_opaque_payloads payload_row
                where payload_row.tenant_id = receipt_row.tenant_id
                  and payload_row.receipt_observation_id = receipt_row.id
             ))
           or (receipt_row.opaque_payload_id is not null
             and receipt_row.opaque_data_class_id =
               'core:source_occurrence_and_external_reference'
             and exists (
               select 1
                 from public.inbox_v2_provider_receipt_opaque_payloads payload_row
                where payload_row.tenant_id = receipt_row.tenant_id
                  and payload_row.id = receipt_row.opaque_payload_id
                  and payload_row.receipt_observation_id = receipt_row.id
                  and payload_row.data_class_id = receipt_row.opaque_data_class_id
                  and (payload_row.provider_watermark is null) =
                    (receipt_row.provider_watermark_digest_sha256 is null)
                  and (payload_row.reader_aggregate_key is null) =
                    (receipt_row.reader_aggregate_key_digest_sha256 is null)
                  and (payload_row.provider_watermark is null or
                    encode(sha256(convert_to(
                      payload_row.provider_watermark, 'UTF8'
                    )), 'hex') =
                      receipt_row.provider_watermark_digest_sha256)
                  and (payload_row.reader_aggregate_key is null or
                    encode(sha256(convert_to(
                      payload_row.reader_aggregate_key, 'UTF8'
                    )), 'hex') =
                      receipt_row.reader_aggregate_key_digest_sha256)
             ))
         )
         and public.inbox_v2_tm_provider_fact_semantic_proof_valid(
           receipt_row.semantic_proof_detail,
           receipt_row.tenant_id,
           receipt_row.evidence_normalized_inbound_event_id,
           case when receipt_row.target_kind = 'exact_message'
             then receipt_row.target_external_message_reference_id
             else null
           end,
           case when receipt_row.target_kind = 'exact_message'
             then receipt_row.target_source_occurrence_id
             else null
           end,
           receipt_row.source_account_id,
           receipt_row.source_thread_binding_id,
           receipt_row.binding_generation,
           receipt_row.adapter_contract_id,
           receipt_row.adapter_contract_version,
           receipt_row.adapter_declaration_revision,
           receipt_row.adapter_surface_id,
           receipt_row.adapter_loaded_by_trusted_service_id,
           receipt_row.adapter_loaded_at,
           receipt_row.capability_id,
           receipt_row.capability_revision,
           'core:message.receipt.read',
           case when receipt_row.reader_kind = 'source_external_identity'
             then receipt_row.reader_source_external_identity_id
             else null
           end,
           receipt_row.observed_at,
           receipt_row.recorded_at
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.provider_receipt_observation_coherence';
    end if;
  end if;

  return null;
end;
$$;



--
-- Name: inbox_v2_tm_content_history_valid(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_content_history_valid(checked_tenant_id text, checked_content_id text) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select exists (
    select 1
      from public.inbox_v2_timeline_contents content_row
      join public.inbox_v2_timeline_content_revisions latest_row
        on latest_row.tenant_id = content_row.tenant_id
       and latest_row.content_id = content_row.id
       and latest_row.revision = content_row.revision
       and latest_row.state = content_row.state
       and latest_row.recorded_stream_position =
         content_row.last_changed_stream_position
     where content_row.tenant_id = checked_tenant_id
       and content_row.id = checked_content_id
       and content_row.state_changed_at = case latest_row.transition_kind
         when 'created' then latest_row.recorded_at
         else latest_row.occurred_at
       end
       and content_row.updated_at = case latest_row.transition_kind
         when 'created' then latest_row.recorded_at
         else latest_row.occurred_at
       end
       and content_row.tombstone_event_id is not distinct from case
         when latest_row.transition_kind in (
           'privacy_erasure', 'retention_purge'
         ) then latest_row.event_id
         else null
       end
       and content_row.tombstone_reason_id is not distinct from
         latest_row.reason_id
       and content_row.retention_policy_id is not distinct from
         latest_row.retention_policy_id
       and content_row.retention_policy_version is not distinct from
         latest_row.retention_policy_version
       and content_row.retention_policy_revision is not distinct from
         latest_row.retention_policy_revision
       and (
         select count(*) = content_row.revision
            and min(history_row.revision) = 1
            and max(history_row.revision) = content_row.revision
           from public.inbox_v2_timeline_content_revisions history_row
          where history_row.tenant_id = content_row.tenant_id
            and history_row.content_id = content_row.id
       )
       and exists (
         select 1
           from public.inbox_v2_timeline_content_revisions first_row
          where first_row.tenant_id = content_row.tenant_id
            and first_row.content_id = content_row.id
            and first_row.revision = 1
            and first_row.expected_previous_revision is null
            and first_row.transition_kind = 'created'
            and first_row.state = 'available'
            and first_row.event_id is null
            and first_row.reason_id is null
            and first_row.retention_policy_id is null
             and first_row.retention_policy_version is null
             and first_row.retention_policy_revision is null
             and first_row.occurred_at = content_row.retention_anchor_at
             and first_row.recorded_at = content_row.created_at
        )
       and (
         (content_row.owner_kind = 'message' and exists (
           select 1
             from public.inbox_v2_messages owner_row
             join public.inbox_v2_message_revisions first_owner_revision_row
               on first_owner_revision_row.tenant_id = owner_row.tenant_id
              and first_owner_revision_row.message_id = owner_row.id
              and first_owner_revision_row.message_revision = 1
              and first_owner_revision_row.change_kind = 'created'
              and first_owner_revision_row.after_content_id = content_row.id
              and first_owner_revision_row.after_content_revision = 1
              and first_owner_revision_row.after_content_state = 'available'
            where owner_row.tenant_id = content_row.tenant_id
              and owner_row.id = content_row.owner_id
              and owner_row.content_id = content_row.id
         ))
         or (content_row.owner_kind = 'staff_note' and exists (
           select 1
             from public.inbox_v2_staff_notes owner_row
             join public.inbox_v2_staff_note_revisions first_owner_revision_row
               on first_owner_revision_row.tenant_id = owner_row.tenant_id
              and first_owner_revision_row.staff_note_id = owner_row.id
              and first_owner_revision_row.staff_note_revision = 1
              and first_owner_revision_row.change_kind = 'created'
              and first_owner_revision_row.after_content_id = content_row.id
              and first_owner_revision_row.after_content_revision = 1
              and first_owner_revision_row.after_content_state = 'available'
            where owner_row.tenant_id = content_row.tenant_id
              and owner_row.id = content_row.owner_id
              and owner_row.content_id = content_row.id
         ))
       )
       and not exists (
         select 1
           from public.inbox_v2_timeline_content_revisions history_row
          where history_row.tenant_id = content_row.tenant_id
            and history_row.content_id = content_row.id
            and not (
              (content_row.owner_kind = 'message' and 1 = (
                select count(*)
                  from public.inbox_v2_message_revisions owner_revision_row
                 where owner_revision_row.tenant_id = content_row.tenant_id
                   and owner_revision_row.message_id = content_row.owner_id
                   and owner_revision_row.after_content_id = content_row.id
                   and owner_revision_row.after_content_revision =
                     history_row.revision
                   and owner_revision_row.after_content_state = history_row.state
                   and owner_revision_row.recorded_stream_position =
                     history_row.recorded_stream_position
                   and owner_revision_row.recorded_at = history_row.recorded_at
                   and owner_revision_row.change_kind::text = case
                     history_row.transition_kind
                     when 'created' then 'created'
                     when 'edit' then 'edited'
                     when 'attachment_materialization' then
                       'attachment_materialized'
                     when 'privacy_erasure' then 'privacy_erasure_tombstone'
                     when 'retention_purge' then 'retention_purge_tombstone'
                   end
              ))
              or (content_row.owner_kind = 'staff_note' and 1 = (
                select count(*)
                  from public.inbox_v2_staff_note_revisions owner_revision_row
                 where owner_revision_row.tenant_id = content_row.tenant_id
                   and owner_revision_row.staff_note_id = content_row.owner_id
                   and owner_revision_row.after_content_id = content_row.id
                   and owner_revision_row.after_content_revision =
                     history_row.revision
                   and owner_revision_row.after_content_state = history_row.state
                   and owner_revision_row.recorded_stream_position =
                     history_row.recorded_stream_position
                   and owner_revision_row.recorded_at = history_row.recorded_at
                   and owner_revision_row.change_kind::text = case
                     history_row.transition_kind
                     when 'created' then 'created'
                     when 'edit' then 'edited'
                     when 'privacy_erasure' then 'privacy_erasure_tombstone'
                     when 'retention_purge' then 'retention_purge_tombstone'
                     else null
                   end
              ))
            )
       )
       and not exists (
         select 1
           from public.inbox_v2_timeline_content_revisions history_row
          where history_row.tenant_id = content_row.tenant_id
            and history_row.content_id = content_row.id
            and (
              (history_row.revision > 1 and not exists (
                select 1
                  from public.inbox_v2_timeline_content_revisions predecessor_row
                 where predecessor_row.tenant_id = history_row.tenant_id
                   and predecessor_row.content_id = history_row.content_id
                   and predecessor_row.revision = history_row.revision - 1
                   and history_row.expected_previous_revision =
                     predecessor_row.revision
                   and predecessor_row.state = 'available'
                   and predecessor_row.recorded_at <= history_row.recorded_at
                   and predecessor_row.occurred_at <= history_row.occurred_at
                   and predecessor_row.recorded_stream_position <
                     history_row.recorded_stream_position
              ))
              or (history_row.transition_kind in (
                    'created', 'edit', 'attachment_materialization'
                  ) and history_row.state <> 'available')
              or (history_row.transition_kind in (
                    'edit', 'attachment_materialization'
                  ) and history_row.event_id is null)
              or (history_row.transition_kind = 'privacy_erasure' and not (
                history_row.state = 'privacy_erased'
                and history_row.event_id is not null
                and history_row.reason_id is not null
                and history_row.retention_policy_id is null
                and history_row.retention_policy_version is null
                and history_row.retention_policy_revision is null
              ))
              or (history_row.transition_kind = 'retention_purge' and not (
                history_row.state = 'retention_purged'
                and history_row.event_id is not null
                and history_row.reason_id is null
                and history_row.retention_policy_id is not null
                and history_row.retention_policy_version is not null
                and history_row.retention_policy_revision is not null
              ))
              or (history_row.transition_kind in (
                    'created', 'edit', 'attachment_materialization'
                  ) and num_nonnulls(
                    history_row.reason_id,
                    history_row.retention_policy_id,
                    history_row.retention_policy_version,
                    history_row.retention_policy_revision
                  ) <> 0)
            )
       )
  );
$$;



--
-- Name: inbox_v2_tm_core_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_core_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  changed_row jsonb;
  tenant_key text;
  timeline_key text;
  message_key text;
  note_key text;
  content_key text;
  conversation_key text;
  actual_count bigint;
  latest_item record;
begin
  changed_row := case when tg_op = 'DELETE' then to_jsonb(old) else to_jsonb(new) end;
  tenant_key := changed_row->>'tenant_id';

  if not exists (select 1 from public.tenants where id = tenant_key) then
    return null;
  end if;

  if tg_table_name = 'inbox_v2_timeline_items' then
    timeline_key := changed_row->>'id';
    conversation_key := changed_row->>'conversation_id';
  else
    timeline_key := changed_row->>'timeline_item_id';
  end if;

  if tg_table_name = 'inbox_v2_messages' then
    message_key := changed_row->>'id';
    content_key := changed_row->>'content_id';
    conversation_key := changed_row->>'conversation_id';
  elsif tg_table_name = 'inbox_v2_message_revisions' then
    message_key := changed_row->>'message_id';
  elsif tg_table_name = 'inbox_v2_outbound_dispatches' then
    message_key := changed_row->>'message_id';
  elsif tg_table_name like 'inbox_v2_message_reference_%' then
    message_key := changed_row->>'message_id';
  elsif tg_table_name = 'inbox_v2_staff_notes' then
    note_key := changed_row->>'id';
    content_key := changed_row->>'content_id';
    conversation_key := changed_row->>'conversation_id';
  elsif tg_table_name = 'inbox_v2_staff_note_revisions' then
    note_key := changed_row->>'staff_note_id';
  elsif tg_table_name in (
    'inbox_v2_timeline_contents', 'inbox_v2_timeline_content_revisions',
    'inbox_v2_timeline_content_payloads',
    'inbox_v2_timeline_content_contact_values'
  ) then
    content_key := coalesce(changed_row->>'id', changed_row->>'content_id');
  end if;

  if tg_table_name = 'inbox_v2_outbound_dispatches'
     and tg_op = 'INSERT'
     and not exists (
       select 1
         from public.inbox_v2_messages message_row
        where message_row.tenant_id = tenant_key
          and message_row.id = changed_row->>'message_id'
          and message_row.conversation_id =
            changed_row->>'conversation_id'
          and message_row.timeline_item_id =
            changed_row->>'timeline_item_id'
          and message_row.origin_kind = 'hulee_external'
          and message_row.origin_outbound_route_id = changed_row->>'route_id'
          and message_row.revision = 1
          and message_row.created_at =
            (changed_row->>'created_at')::timestamptz
          and changed_row->>'state' = 'queued'
          and (changed_row->>'attempt_count')::integer = 0
          and (changed_row->>'revision')::bigint = 1
          and (changed_row->>'created_at')::timestamptz =
            (changed_row->>'updated_at')::timestamptz
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.message_creation_dispatch_mismatch';
  end if;

  if timeline_key is not null and exists (
    select 1 from public.inbox_v2_timeline_items
     where tenant_id = tenant_key and id = timeline_key
  ) then
    if not exists (
      select 1
        from public.inbox_v2_timeline_items item_row
       where item_row.tenant_id = tenant_key
         and item_row.id = timeline_key
         and (
           (item_row.subject_kind = 'message' and exists (
             select 1 from public.inbox_v2_messages message_row
              where message_row.tenant_id = item_row.tenant_id
                and message_row.id = item_row.subject_id
                and message_row.timeline_item_id = item_row.id
                and message_row.conversation_id = item_row.conversation_id
                and message_row.revision = item_row.revision
           ))
           or (item_row.subject_kind = 'staff_note' and exists (
             select 1 from public.inbox_v2_staff_notes note_row
              where note_row.tenant_id = item_row.tenant_id
                and note_row.id = item_row.subject_id
                and note_row.timeline_item_id = item_row.id
                and note_row.conversation_id = item_row.conversation_id
                and note_row.revision = item_row.revision
           ))
           or (item_row.subject_kind not in ('message', 'staff_note') and exists (
             select 1 from public.inbox_v2_timeline_subject_details detail_row
              where detail_row.tenant_id = item_row.tenant_id
                and detail_row.timeline_item_id = item_row.id
                and detail_row.subject_kind = item_row.subject_kind
                and item_row.subject_id = case detail_row.subject_kind
                  when 'call' then detail_row.source_object_id
                  when 'review' then detail_row.source_object_id
                  when 'module_event' then detail_row.source_object_id
                  when 'participant_change' then detail_row.participant_transition_id
                  when 'work_change' then coalesce(
                    detail_row.work_item_transition_id,
                    detail_row.work_item_relation_transition_id
                  )
                  when 'system_event' then detail_row.system_event_id
                end
                and (
                  detail_row.actor_participant_id is null or exists (
                    select 1 from public.inbox_v2_conversation_participants participant_row
                     where participant_row.tenant_id = item_row.tenant_id
                       and participant_row.id = detail_row.actor_participant_id
                       and participant_row.conversation_id = item_row.conversation_id
                  )
                )
           ))
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.timeline_subject_coherence';
    end if;
  end if;

  if message_key is not null and exists (
    select 1 from public.inbox_v2_messages
     where tenant_id = tenant_key and id = message_key
  ) then
    if not exists (
      select 1
        from public.inbox_v2_messages message_row
        join public.inbox_v2_timeline_items item_row
          on item_row.tenant_id = message_row.tenant_id
         and item_row.id = message_row.timeline_item_id
         and item_row.conversation_id = message_row.conversation_id
         and item_row.subject_kind = 'message'
         and item_row.subject_id = message_row.id
         and item_row.revision = message_row.revision
        join public.inbox_v2_timeline_contents content_row
          on content_row.tenant_id = message_row.tenant_id
         and content_row.id = message_row.content_id
         and content_row.owner_kind = 'message'
         and content_row.owner_id = message_row.id
         and content_row.revision = message_row.content_revision
         and content_row.state = message_row.content_state
        join public.inbox_v2_timeline_content_revisions content_revision_row
          on content_revision_row.tenant_id = content_row.tenant_id
         and content_revision_row.content_id = content_row.id
         and content_revision_row.revision = content_row.revision
         and content_revision_row.state = content_row.state
         and content_revision_row.recorded_stream_position =
           content_row.last_changed_stream_position
        join public.inbox_v2_message_revisions revision_row
          on revision_row.tenant_id = message_row.tenant_id
         and revision_row.message_id = message_row.id
         and revision_row.timeline_item_id = message_row.timeline_item_id
         and revision_row.message_revision = message_row.revision
         and revision_row.recorded_stream_position =
           message_row.last_changed_stream_position
        join public.inbox_v2_action_attributions attribution_row
          on attribution_row.tenant_id = message_row.tenant_id
         and attribution_row.id = message_row.creation_attribution_id
         and attribution_row.conversation_id = message_row.conversation_id
        join public.inbox_v2_conversation_participants author_row
          on author_row.tenant_id = message_row.tenant_id
         and author_row.id = message_row.author_participant_id
         and author_row.conversation_id = message_row.conversation_id
        left join public.inbox_v2_source_occurrences origin_occurrence_row
          on origin_occurrence_row.tenant_id = message_row.tenant_id
         and origin_occurrence_row.id = message_row.origin_source_occurrence_id
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and attribution_row.action_participant_id =
           message_row.author_participant_id
         and (
           (message_row.origin_kind = 'source_originated'
             and attribution_row.source_occurrence_id =
               message_row.origin_source_occurrence_id
             and attribution_row.app_actor_kind is null
             and author_row.subject_kind = 'source_external_identity'
             and origin_occurrence_row.provider_actor_kind =
               'source_external_identity'
             and author_row.subject_source_external_identity_id =
               origin_occurrence_row.provider_actor_source_external_identity_id)
           or (message_row.origin_kind in ('hulee_external', 'internal')
             and attribution_row.source_occurrence_id is null
             and (
               (attribution_row.app_actor_kind = 'employee'
                 and author_row.subject_kind = 'employee'
                 and author_row.subject_employee_id =
                   attribution_row.app_actor_employee_id)
               or (attribution_row.app_actor_kind = 'trusted_service'
                 and attribution_row.automation_kind is not null
                 and author_row.subject_kind = 'bot')
             ))
           or (message_row.origin_kind = 'migration'
             and attribution_row.source_occurrence_id is null
             and attribution_row.app_actor_kind = 'trusted_service'
             and attribution_row.automation_kind is not null
             and author_row.subject_kind in ('legacy_unknown', 'system'))
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_head_coherence';
    end if;

    if not public.inbox_v2_tm_message_history_valid(
      tenant_key,
      message_key
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_revision_history_coherence';
    end if;

    if exists (
      select 1
        from public.inbox_v2_messages message_row
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and message_row.origin_kind = 'source_originated'
    ) and not exists (
      select 1
        from public.inbox_v2_messages message_row
        join public.inbox_v2_source_occurrences occurrence_row
          on occurrence_row.tenant_id = message_row.tenant_id
         and occurrence_row.id = message_row.origin_source_occurrence_id
         and occurrence_row.conversation_id = message_row.conversation_id
         and occurrence_row.direction::text =
           message_row.origin_source_direction::text
         and occurrence_row.origin_kind not in (
           'provider_echo', 'provider_response'
         )
         and occurrence_row.provider_actor_kind = 'source_external_identity'
         and occurrence_row.resolution_state = 'resolved'
        join public.inbox_v2_external_message_references reference_row
          on reference_row.tenant_id = message_row.tenant_id
         and reference_row.id =
           occurrence_row.resolved_external_message_reference_id
         and reference_row.external_thread_id = occurrence_row.external_thread_id
         and reference_row.conversation_id = message_row.conversation_id
         and reference_row.timeline_item_id = message_row.timeline_item_id
         and reference_row.message_id = message_row.id
         and reference_row.message_key_digest_sha256 =
           occurrence_row.message_key_digest_sha256
         and reference_row.created_at = message_row.created_at
         and reference_row.revision = 1
        join public.inbox_v2_message_transport_links origin_link_row
          on origin_link_row.tenant_id = message_row.tenant_id
         and origin_link_row.message_id = message_row.id
         and origin_link_row.source_occurrence_id = occurrence_row.id
         and origin_link_row.external_message_reference_id = reference_row.id
         and origin_link_row.role = case message_row.origin_source_direction
           when 'inbound' then 'origin'::public.inbox_v2_message_transport_link_role
           when 'outbound' then 'native_outbound'::public.inbox_v2_message_transport_link_role
         end
         and origin_link_row.resulting_head_revision = 1
         and origin_link_row.revision = 1
         and origin_link_row.linked_at = message_row.created_at
        join public.inbox_v2_message_transport_link_heads head_row
          on head_row.tenant_id = message_row.tenant_id
         and head_row.message_id = message_row.id
         and head_row.link_count >= 1
         and head_row.revision = head_row.link_count
         and head_row.updated_at >= message_row.created_at
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and public.inbox_v2_tm_transport_occurrence_link_valid(
           origin_link_row.tenant_id,
           origin_link_row.id
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_source_origin_transport_coherence';
    end if;

    if exists (
      select 1
        from public.inbox_v2_messages message_row
        join public.inbox_v2_message_transport_links link_row
          on link_row.tenant_id = message_row.tenant_id
         and link_row.message_id = message_row.id
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and message_row.origin_kind in ('internal', 'migration')
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_local_transport_link_forbidden';
    end if;

    if exists (
      select 1
        from public.inbox_v2_messages message_row
        left join public.inbox_v2_message_reference_contexts context_row
          on context_row.tenant_id = message_row.tenant_id
         and context_row.message_id = message_row.id
        left join lateral (
          select count(*)::integer as target_count,
                 min(target_row.external_message_reference_id) as
                   external_message_reference_id,
                 min(target_row.source_occurrence_id) as source_occurrence_id
            from public.inbox_v2_message_reference_external_targets target_row
           where target_row.tenant_id = message_row.tenant_id
             and target_row.message_id = message_row.id
        ) external_target on true
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and message_row.origin_kind = 'hulee_external'
         and not (
           (
             context_row.kind in ('none', 'forward_content_copy')
             and external_target.target_count = 0
           )
           or (
             context_row.kind in ('reply', 'forward_provider_native')
             and external_target.target_count = 1
           )
         )
         or message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and message_row.origin_kind = 'hulee_external'
         and not (
           public.inbox_v2_tm_outbound_route_action_valid(
           message_row.tenant_id,
           message_row.origin_outbound_route_id,
           message_row.id,
           null,
           message_row.conversation_id,
           message_row.created_at,
           message_row.created_at,
           case context_row.kind
             when 'none' then 'core:message.send'
             when 'reply' then 'core:message.reply'
             when 'forward_content_copy' then
               'core:message.forward_content_copy'
             when 'forward_provider_native' then
               'core:message.forward_provider_native'
           end,
           case context_row.kind
             when 'none' then 'core:message.reply_external'
             when 'reply' then 'core:message.reply_external'
             when 'forward_content_copy' then
               'core:message.forward_external'
             when 'forward_provider_native' then
               'core:message.forward_external'
           end,
           case when context_row.kind in ('reply', 'forward_provider_native')
             then external_target.external_message_reference_id
             else null
           end,
           case when context_row.kind in ('reply', 'forward_provider_native')
             then external_target.source_occurrence_id
             else null
           end,
           null,
           null,
           null,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_adapter_contract_id
             else null
           end,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_adapter_contract_version
             else null
           end,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_adapter_declaration_revision
             else null
           end,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_adapter_surface_id
             else null
           end,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_adapter_loaded_by_trusted_service_id
             else null
           end,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_adapter_loaded_at
             else null
           end,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_capability_id
             else null
           end,
           case when context_row.kind = 'forward_provider_native'
             then context_row.native_capability_revision
             else null
           end,
           message_row.creation_attribution_id,
             false
           )
           and exists (
             select 1
               from public.inbox_v2_outbound_routes route_row
              where route_row.tenant_id = message_row.tenant_id
                and route_row.id = message_row.origin_outbound_route_id
                and route_row.created_at = message_row.created_at
           )
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_origin_route_mismatch';
    end if;

    if exists (
      select 1
        from public.inbox_v2_messages message_row
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and (
           (
             message_row.origin_kind = 'hulee_external'
             and (
               1 <> (
                 select count(*)
                   from public.inbox_v2_outbound_dispatches dispatch_row
                  where dispatch_row.tenant_id = message_row.tenant_id
                    and dispatch_row.message_id = message_row.id
               )
               or not exists (
                 select 1
                   from public.inbox_v2_outbound_dispatches dispatch_row
                  where dispatch_row.tenant_id = message_row.tenant_id
                    and dispatch_row.message_id = message_row.id
                    and dispatch_row.conversation_id =
                      message_row.conversation_id
                    and dispatch_row.timeline_item_id =
                      message_row.timeline_item_id
                    and dispatch_row.route_id =
                      message_row.origin_outbound_route_id
                    and dispatch_row.created_at = message_row.created_at
               )
             )
           )
           or (
             message_row.origin_kind <> 'hulee_external'
             and exists (
               select 1
                 from public.inbox_v2_outbound_dispatches dispatch_row
                where dispatch_row.tenant_id = message_row.tenant_id
                  and dispatch_row.message_id = message_row.id
             )
           )
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_dispatch_coherence';
    end if;

    if exists (
      select 1 from public.inbox_v2_messages message_row
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and message_row.origin_kind = 'hulee_external'
         and not exists (
           select 1
             from public.inbox_v2_outbound_route_consumptions consumption_row
            where consumption_row.tenant_id = message_row.tenant_id
              and consumption_row.consumer_kind = 'message_creation'
              and consumption_row.consumer_id = message_row.id
              and consumption_row.message_id = message_row.id
              and consumption_row.outbound_route_id =
                message_row.origin_outbound_route_id
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_route_consumption_missing';
    end if;

    if exists (
      select 1 from public.inbox_v2_messages message_row
       where message_row.tenant_id = tenant_key
         and message_row.id = message_key
         and message_row.lifecycle = 'provider_delete_tombstone'
         and not exists (
           select 1
             from public.inbox_v2_message_provider_lifecycle_operations op_row
            where op_row.tenant_id = message_row.tenant_id
              and op_row.id = message_row.lifecycle_provider_operation_id
              and op_row.message_id = message_row.id
              and op_row.action = 'delete'
              and op_row.delete_local_effect = 'tombstone_local'
         )
    ) then
      raise exception using errcode = '23514',
        message = 'inbox_v2.message_lifecycle_operation_mismatch';
    end if;

    perform public.inbox_v2_tm_assert_reference_context(tenant_key, message_key);
  end if;

  if note_key is not null and exists (
    select 1 from public.inbox_v2_staff_notes
     where tenant_id = tenant_key and id = note_key
  ) and not exists (
    select 1
      from public.inbox_v2_staff_notes note_row
      join public.inbox_v2_timeline_items item_row
        on item_row.tenant_id = note_row.tenant_id
       and item_row.id = note_row.timeline_item_id
       and item_row.subject_kind = 'staff_note'
       and item_row.subject_id = note_row.id
       and item_row.visibility = 'staff_only'
       and item_row.revision = note_row.revision
      join public.inbox_v2_timeline_contents content_row
        on content_row.tenant_id = note_row.tenant_id
       and content_row.id = note_row.content_id
       and content_row.owner_kind = 'staff_note'
       and content_row.owner_id = note_row.id
       and content_row.revision = note_row.content_revision
       and content_row.state = note_row.content_state
      join public.inbox_v2_staff_note_revisions revision_row
        on revision_row.tenant_id = note_row.tenant_id
       and revision_row.staff_note_id = note_row.id
       and revision_row.timeline_item_id = note_row.timeline_item_id
       and revision_row.staff_note_revision = note_row.revision
       and revision_row.recorded_stream_position =
         note_row.last_changed_stream_position
       and revision_row.after_content_id = note_row.content_id
       and revision_row.after_content_revision = note_row.content_revision
       and revision_row.after_content_state = note_row.content_state
     where note_row.tenant_id = tenant_key and note_row.id = note_key
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.staff_note_head_coherence';
  end if;

  if note_key is not null and exists (
    select 1 from public.inbox_v2_staff_notes
     where tenant_id = tenant_key and id = note_key
  ) and not public.inbox_v2_tm_staff_note_history_valid(
    tenant_key,
    note_key
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.staff_note_revision_history_coherence';
  end if;

  if content_key is not null and exists (
    select 1 from public.inbox_v2_timeline_contents
     where tenant_id = tenant_key and id = content_key
  ) and tg_table_name = 'inbox_v2_timeline_contents'
    and tg_op = 'INSERT'
    and not exists (
      select 1
        from public.inbox_v2_timeline_contents content_row
       where content_row.tenant_id = tenant_key
         and content_row.id = content_key
         and (
           (content_row.owner_kind = 'message' and exists (
             select 1
               from public.inbox_v2_messages owner_row
               join public.inbox_v2_conversations conversation_row
                 on conversation_row.tenant_id = owner_row.tenant_id
                and conversation_row.id = owner_row.conversation_id
              where owner_row.tenant_id = content_row.tenant_id
                and owner_row.id = content_row.owner_id
                and conversation_row.purpose_id =
                  content_row.processing_purpose_id
           ))
           or (content_row.owner_kind = 'staff_note' and exists (
             select 1
               from public.inbox_v2_staff_notes owner_row
               join public.inbox_v2_conversations conversation_row
                 on conversation_row.tenant_id = owner_row.tenant_id
                and conversation_row.id = owner_row.conversation_id
              where owner_row.tenant_id = content_row.tenant_id
                and owner_row.id = content_row.owner_id
                and conversation_row.purpose_id =
                  content_row.processing_purpose_id
           ))
         )
    ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.timeline_content_creation_classification_coherence';
  end if;

  if content_key is not null and exists (
    select 1 from public.inbox_v2_timeline_contents
     where tenant_id = tenant_key and id = content_key
  ) and not exists (
    select 1
      from public.inbox_v2_timeline_contents content_row
      join public.inbox_v2_timeline_content_revisions revision_row
        on revision_row.tenant_id = content_row.tenant_id
       and revision_row.content_id = content_row.id
       and revision_row.revision = content_row.revision
       and revision_row.state = content_row.state
       and revision_row.recorded_stream_position =
         content_row.last_changed_stream_position
     where content_row.tenant_id = tenant_key
       and content_row.id = content_key
       and (
         (content_row.owner_kind = 'message' and exists (
           select 1 from public.inbox_v2_messages message_row
            where message_row.tenant_id = content_row.tenant_id
              and message_row.id = content_row.owner_id
              and message_row.content_id = content_row.id
         ))
         or (content_row.owner_kind = 'staff_note' and exists (
           select 1 from public.inbox_v2_staff_notes note_row
            where note_row.tenant_id = content_row.tenant_id
              and note_row.id = content_row.owner_id
              and note_row.content_id = content_row.id
         ))
       )
       and (
         (content_row.state = 'available' and (
           select count(*) between 1 and 64
             from public.inbox_v2_timeline_content_payloads payload_row
            where payload_row.tenant_id = content_row.tenant_id
              and payload_row.content_id = content_row.id
              and payload_row.content_revision = content_row.revision
         ) and (
           select min(payload_row.ordinal) = 0
              and max(payload_row.ordinal) = count(*) - 1
             from public.inbox_v2_timeline_content_payloads payload_row
            where payload_row.tenant_id = content_row.tenant_id
              and payload_row.content_id = content_row.id
              and payload_row.content_revision = content_row.revision
         ) and not exists (
           select 1
             from public.inbox_v2_timeline_content_payloads payload_row
             left join lateral (
               select count(*)::integer as value_count,
                      min(value_row.value_ordinal) as minimum_ordinal,
                      max(value_row.value_ordinal) as maximum_ordinal
                 from public.inbox_v2_timeline_content_contact_values value_row
                where value_row.tenant_id = payload_row.tenant_id
                  and value_row.content_id = payload_row.content_id
                  and value_row.content_revision = payload_row.content_revision
                  and value_row.block_ordinal = payload_row.ordinal
             ) contact_values on true
            where payload_row.tenant_id = content_row.tenant_id
              and payload_row.content_id = content_row.id
              and payload_row.content_revision = content_row.revision
              and (
                (payload_row.kind = 'contact' and not (
                  contact_values.value_count between 1 and 64
                  and contact_values.minimum_ordinal = 0
                  and contact_values.maximum_ordinal =
                    contact_values.value_count - 1
                ))
                or (payload_row.kind <> 'contact'
                  and contact_values.value_count <> 0)
              )
         ))
         or (content_row.state <> 'available' and not exists (
           select 1 from public.inbox_v2_timeline_content_payloads payload_row
            where payload_row.tenant_id = content_row.tenant_id
              and payload_row.content_id = content_row.id
         ))
       )
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.timeline_content_head_coherence';
  end if;

  if content_key is not null and exists (
    select 1 from public.inbox_v2_timeline_contents
     where tenant_id = tenant_key and id = content_key
  ) and not public.inbox_v2_tm_content_history_valid(
    tenant_key,
    content_key
  ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.timeline_content_revision_history_coherence';
  end if;

  if conversation_key is not null then
    select item_row.id, item_row.timeline_sequence, item_row.occurred_at
      into latest_item
      from public.inbox_v2_timeline_items item_row
     where item_row.tenant_id = tenant_key
       and item_row.conversation_id = conversation_key
       and item_row.activity_kind = 'eligible'
     order by item_row.timeline_sequence desc
     limit 1;

    select count(*) into actual_count
      from public.inbox_v2_conversation_heads head_row
     where head_row.tenant_id = tenant_key
       and head_row.conversation_id = conversation_key
       and head_row.latest_timeline_sequence = coalesce((
         select max(item_row.timeline_sequence)
           from public.inbox_v2_timeline_items item_row
          where item_row.tenant_id = tenant_key
            and item_row.conversation_id = conversation_key
       ), 0)
       and (
         (latest_item.id is null
           and head_row.latest_activity_item_id is null
           and head_row.latest_activity_timeline_sequence is null
           and head_row.latest_activity_at is null)
         or (latest_item.id is not null
           and head_row.latest_activity_item_id = latest_item.id
           and head_row.latest_activity_timeline_sequence =
             latest_item.timeline_sequence
           and head_row.latest_activity_at = latest_item.occurred_at)
       );

    if actual_count <> 1 then
      raise exception using errcode = '23514',
        message = 'inbox_v2.conversation_timeline_head_coherence';
    end if;
  end if;

  return null;
end;
$$;



--
-- Name: inbox_v2_tm_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  old_row jsonb := to_jsonb(old);
  new_row jsonb := to_jsonb(new);
  mutable_columns text[];
begin
  if tg_op = 'DELETE' then
    if pg_trigger_depth() > 1 then
      return old;
    end if;

    if not exists (
      select 1 from public.tenants tenant_row
       where tenant_row.id = old_row->>'tenant_id'
    ) then
      return old;
    end if;

    if tg_table_name in (
      'inbox_v2_message_transport_link_heads',
      'inbox_v2_message_provider_lifecycle_operations',
      'inbox_v2_message_reactions',
      'inbox_v2_message_reaction_slot_heads'
    ) and not exists (
      select 1 from public.inbox_v2_messages message_row
       where message_row.tenant_id = old_row->>'tenant_id'
         and message_row.id = old_row->>'message_id'
    ) then
      return old;
    end if;

    raise exception using errcode = '23514',
      message = format('inbox_v2.timeline_message_head_delete:%s', tg_table_name);
  end if;

  case tg_table_name
    when 'inbox_v2_timeline_items' then
      mutable_columns := array[
        'revision', 'last_changed_stream_position', 'updated_at'
      ];
    when 'inbox_v2_messages' then
      mutable_columns := array[
        'content_revision', 'content_state', 'lifecycle',
        'lifecycle_revision_id', 'lifecycle_reason_id',
        'lifecycle_provider_operation_id', 'lifecycle_policy_reason_id',
        'lifecycle_changed_at', 'revision', 'last_changed_stream_position',
        'updated_at'
      ];
    when 'inbox_v2_staff_notes' then
      mutable_columns := array[
        'content_revision', 'content_state', 'revision',
        'last_changed_stream_position', 'updated_at'
      ];
    when 'inbox_v2_timeline_contents' then
      mutable_columns := array[
        'state', 'content_digest_sha256', 'tombstone_event_id',
        'tombstone_reason_id', 'retention_policy_id',
        'retention_policy_version', 'retention_policy_revision',
        'state_changed_at', 'revision', 'last_changed_stream_position',
        'updated_at'
      ];
    when 'inbox_v2_message_transport_link_heads' then
      mutable_columns := array[
        'link_count', 'latest_link_id', 'revision',
        'last_changed_stream_position', 'updated_at'
      ];
    when 'inbox_v2_message_provider_lifecycle_operations' then
      mutable_columns := array[
        'outcome', 'outcome_retryable', 'outcome_reason_id',
        'delete_local_effect', 'policy_decision_event_id',
        'policy_decision_revision', 'policy_decided_at', 'revision',
        'last_changed_stream_position', 'updated_at'
      ];
    when 'inbox_v2_message_reactions' then
      mutable_columns := array[
        'opaque_actor_key', 'opaque_actor_key_digest_sha256',
        'provider_actor_subject', 'provider_actor_subject_digest_sha256',
        'actor_identity_state', 'actor_identity_tombstone_event_id',
        'actor_identity_purged_at', 'state_kind', 'value_kind',
        'unicode_value', 'provider_reaction_kind_id',
        'provider_canonical_code', 'cleared_at', 'external_operation',
        'outbound_route_id', 'request_transition_id',
        'request_attribution_id', 'external_outcome', 'result_token',
        'result_digest_sha256', 'resolved_at', 'state_detail',
        'state_detail_digest_sha256', 'revision',
        'last_changed_stream_position', 'updated_at'
      ];
    when 'inbox_v2_message_reaction_slot_heads' then
      mutable_columns := array[
        'reaction_id', 'state_kind', 'revision',
        'last_changed_stream_position', 'updated_at'
      ];
    else
      raise exception using errcode = '23514',
        message = format('inbox_v2.timeline_message_unknown_head:%s', tg_table_name);
  end case;

  if (new_row - mutable_columns) is distinct from (old_row - mutable_columns) then
    raise exception using errcode = '23514',
      message = format('inbox_v2.timeline_message_immutable_identity:%s', tg_table_name);
  end if;

  if (new_row->>'revision')::bigint <> (old_row->>'revision')::bigint + 1
     or (new_row->>'last_changed_stream_position')::bigint <=
        (old_row->>'last_changed_stream_position')::bigint
     or (new_row->>'updated_at')::timestamptz <
        (old_row->>'updated_at')::timestamptz then
    raise exception using errcode = '23514',
      message = format('inbox_v2.timeline_message_stale_head:%s', tg_table_name);
  end if;

  if tg_table_name = 'inbox_v2_message_transport_link_heads'
     and (new_row->>'link_count')::bigint <>
        (old_row->>'link_count')::bigint + 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.transport_link_head_noncontiguous';
  end if;

  return new;
end;
$$;



--
-- Name: inbox_v2_tm_json_exact_keys(jsonb, text[], text[]); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_json_exact_keys(document jsonb, allowed_keys text[], required_keys text[]) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select coalesce(
    jsonb_typeof(document) = 'object'
    and pg_column_size(document) <= 65536
    and document ?& required_keys
    and document - allowed_keys = '{}'::jsonb,
    false
  );
$$;



--
-- Name: inbox_v2_tm_json_family_valid(text, jsonb); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_json_family_valid(family text, document jsonb) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  kind text := document->>'kind';
begin
  if family = 'reference' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array['tenantId', 'kind', 'id'],
      array['tenantId', 'kind', 'id']
    ) and public.inbox_v2_tm_json_string_fields(
      document, array['tenantId', 'kind', 'id']
    );
  elsif family = 'adapter_contract' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array[
        'contractId', 'contractVersion', 'declarationRevision', 'surfaceId',
        'loadedByTrustedServiceId', 'loadedAt'
      ],
      array[
        'contractId', 'contractVersion', 'declarationRevision', 'surfaceId',
        'loadedByTrustedServiceId', 'loadedAt'
      ]
    ) and public.inbox_v2_tm_json_string_fields(
      document,
      array[
        'contractId', 'contractVersion', 'declarationRevision', 'surfaceId',
        'loadedByTrustedServiceId', 'loadedAt'
      ]
    );
  elsif family = 'provider_ordering' then
    if kind = 'monotonic_exact' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'scopeToken', 'position', 'comparatorId', 'comparatorRevision'],
        array['kind', 'scopeToken', 'position', 'comparatorId', 'comparatorRevision']
      ) and public.inbox_v2_tm_json_string_fields(
        document,
        array['kind', 'scopeToken', 'position', 'comparatorId', 'comparatorRevision']
      );
    elsif kind = 'incomparable' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'conflictToken'],
        array['kind', 'conflictToken']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'conflictToken']
      );
    elsif kind = 'unavailable' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'reasonId'],
        array['kind', 'reasonId']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'reasonId']
      );
    end if;
    return false;
  elsif family = 'provider_ordering_head' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array[
        'tenantId', 'semanticFamilyId', 'externalMessageReference',
        'sourceAccount', 'sourceThreadBinding', 'bindingGeneration',
        'scopeToken', 'comparatorId', 'comparatorRevision', 'position',
        'normalizedInboundEvent', 'proofToken', 'revision', 'updatedAt'
      ],
      array[
        'tenantId', 'semanticFamilyId', 'externalMessageReference',
        'sourceAccount', 'sourceThreadBinding', 'bindingGeneration',
        'scopeToken', 'comparatorId', 'comparatorRevision', 'position',
        'normalizedInboundEvent', 'proofToken', 'revision', 'updatedAt'
      ]
    )
    and public.inbox_v2_tm_json_string_fields(
      document,
      array[
        'tenantId', 'semanticFamilyId', 'bindingGeneration', 'scopeToken',
        'comparatorId', 'comparatorRevision', 'position', 'proofToken',
        'revision', 'updatedAt'
      ]
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'externalMessageReference'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'sourceAccount'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'sourceThreadBinding'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'normalizedInboundEvent'
    );
  elsif family = 'provider_semantic_proof' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array[
        'tenantId', 'normalizedInboundEvent', 'externalMessageReference',
        'sourceOccurrence', 'sourceAccount', 'sourceThreadBinding',
        'bindingGeneration', 'adapterContract', 'capabilityId',
        'capabilityRevision', 'semanticId', 'semanticRevision', 'actor',
        'ordering', 'declaredByTrustedServiceId', 'proofToken', 'occurredAt',
        'recordedAt', 'revision'
      ],
      array[
        'tenantId', 'normalizedInboundEvent', 'externalMessageReference',
        'sourceOccurrence', 'sourceAccount', 'sourceThreadBinding',
        'bindingGeneration', 'adapterContract', 'capabilityId',
        'capabilityRevision', 'semanticId', 'semanticRevision', 'actor',
        'ordering', 'declaredByTrustedServiceId', 'proofToken', 'occurredAt',
        'recordedAt', 'revision'
      ]
    )
    and public.inbox_v2_tm_json_string_fields(
      document,
      array[
        'tenantId', 'bindingGeneration', 'capabilityId',
        'capabilityRevision', 'semanticId', 'semanticRevision',
        'declaredByTrustedServiceId', 'proofToken', 'occurredAt',
        'recordedAt', 'revision'
      ]
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'normalizedInboundEvent'
    )
    and (
      (document->'externalMessageReference' = 'null'::jsonb
        and document->'sourceOccurrence' = 'null'::jsonb)
      or (public.inbox_v2_tm_json_family_valid(
          'reference', document->'externalMessageReference'
        ) and public.inbox_v2_tm_json_family_valid(
          'reference', document->'sourceOccurrence'
        ))
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'sourceAccount'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'sourceThreadBinding'
    )
    and public.inbox_v2_tm_json_family_valid(
      'adapter_contract', document->'adapterContract'
    )
    and (
      document->'actor' = 'null'::jsonb
      or public.inbox_v2_tm_json_family_valid('reference', document->'actor')
    )
    and public.inbox_v2_tm_json_family_valid(
      'provider_ordering', document->'ordering'
    );
  elsif family = 'provider_ordering_commit' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array['tenantId', 'semanticFamilyId', 'before', 'proof', 'after', 'committedAt'],
      array['tenantId', 'semanticFamilyId', 'before', 'proof', 'after', 'committedAt']
    )
    and public.inbox_v2_tm_json_string_fields(
      document, array['tenantId', 'semanticFamilyId', 'committedAt']
    )
    and (
      document->'before' = 'null'::jsonb
      or public.inbox_v2_tm_json_family_valid(
        'provider_ordering_head', document->'before'
      )
    )
    and public.inbox_v2_tm_json_family_valid(
      'provider_semantic_proof', document->'proof'
    )
    and public.inbox_v2_tm_json_family_valid(
      'provider_ordering_head', document->'after'
    );
  elsif family = 'provider_result_proof' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array[
        'tenantId', 'operation', 'outboundRoute', 'adapterContract',
        'capabilityId', 'capabilityRevision', 'semanticId',
        'semanticRevision', 'resultState', 'declaredByTrustedServiceId',
        'resultToken', 'resultDigestSha256', 'recordedAt', 'revision'
      ],
      array[
        'tenantId', 'operation', 'outboundRoute', 'adapterContract',
        'capabilityId', 'capabilityRevision', 'semanticId',
        'semanticRevision', 'resultState', 'declaredByTrustedServiceId',
        'resultToken', 'resultDigestSha256', 'recordedAt', 'revision'
      ]
    )
    and public.inbox_v2_tm_json_string_fields(
      document,
      array[
        'tenantId', 'capabilityId', 'capabilityRevision', 'semanticId',
        'semanticRevision', 'resultState', 'declaredByTrustedServiceId',
        'resultToken', 'resultDigestSha256', 'recordedAt', 'revision'
      ]
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'operation'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'outboundRoute'
    )
    and public.inbox_v2_tm_json_family_valid(
      'adapter_contract', document->'adapterContract'
    );
  elsif family = 'reaction_value' then
    if kind = 'unicode' then
      return public.inbox_v2_tm_json_exact_keys(
        document, array['kind', 'value'], array['kind', 'value']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'value']
      );
    elsif kind = 'provider_custom' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'providerKindId', 'canonicalCode'],
        array['kind', 'providerKindId', 'canonicalCode']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'providerKindId', 'canonicalCode']
      );
    end if;
    return false;
  elsif family = 'reaction_capability' then
    if kind = 'internal' then
      return public.inbox_v2_tm_json_exact_keys(
        document, array['kind', 'cardinality'], array['kind', 'cardinality']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'cardinality']
      );
    elsif kind = 'external' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array[
          'kind', 'capabilityId', 'capabilityRevision', 'cardinality',
          'adapterContract'
        ],
        array[
          'kind', 'capabilityId', 'capabilityRevision', 'cardinality',
          'adapterContract'
        ]
      ) and public.inbox_v2_tm_json_string_fields(
        document,
        array['kind', 'capabilityId', 'capabilityRevision', 'cardinality']
      ) and public.inbox_v2_tm_json_family_valid(
        'adapter_contract', document->'adapterContract'
      );
    end if;
    return false;
  elsif family in ('reaction_canonical', 'reaction_desired') then
    if kind = 'active' then
      return public.inbox_v2_tm_json_exact_keys(
        document, array['kind', 'value'], array['kind', 'value']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind']
      ) and public.inbox_v2_tm_json_family_valid(
        'reaction_value', document->'value'
      );
    elsif kind = 'cleared' then
      if family = 'reaction_canonical' then
        return public.inbox_v2_tm_json_exact_keys(
          document,
          array['kind', 'lastValue', 'clearedAt'],
          array['kind', 'lastValue', 'clearedAt']
        ) and public.inbox_v2_tm_json_string_fields(
          document, array['kind', 'clearedAt']
        ) and public.inbox_v2_tm_json_family_valid(
          'reaction_value', document->'lastValue'
        );
      end if;
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'lastValue'],
        array['kind', 'lastValue']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind']
      ) and public.inbox_v2_tm_json_family_valid(
        'reaction_value', document->'lastValue'
      );
    end if;
    return false;
  elsif family = 'app_actor' then
    if kind = 'employee' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'employee', 'authorizationEpoch'],
        array['kind', 'employee', 'authorizationEpoch']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'authorizationEpoch']
      ) and public.inbox_v2_tm_json_family_valid(
        'reference', document->'employee'
      );
    elsif kind = 'trusted_service' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'trustedServiceId'],
        array['kind', 'trustedServiceId']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'trustedServiceId']
      );
    end if;
    return false;
  elsif family = 'automation_causation' then
    if kind = 'employee_command' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'initiatingActor', 'causeEvent', 'correlationId', 'causedAt'],
        array['kind', 'initiatingActor', 'causeEvent', 'correlationId', 'causedAt']
      )
      and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'correlationId', 'causedAt']
      )
      and public.inbox_v2_tm_json_family_valid(
        'app_actor', document->'initiatingActor'
      )
      and public.inbox_v2_tm_json_family_valid(
        'reference', document->'causeEvent'
      );
    elsif kind = 'system_event' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array['kind', 'causeEvent', 'correlationId', 'causedAt'],
        array['kind', 'causeEvent', 'correlationId', 'causedAt']
      ) and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'correlationId', 'causedAt']
      ) and public.inbox_v2_tm_json_family_valid(
        'reference', document->'causeEvent'
      );
    end if;
    return false;
  elsif family = 'reaction_attribution' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array[
        'actionParticipant', 'appActor', 'sourceOccurrence',
        'automationCausation'
      ],
      array[
        'actionParticipant', 'appActor', 'sourceOccurrence',
        'automationCausation'
      ]
    )
    and (
      document->'actionParticipant' = 'null'::jsonb
      or public.inbox_v2_tm_json_family_valid(
        'reference', document->'actionParticipant'
      )
    )
    and (
      document->'appActor' = 'null'::jsonb
      or public.inbox_v2_tm_json_family_valid(
        'app_actor', document->'appActor'
      )
    )
    and (
      document->'sourceOccurrence' = 'null'::jsonb
      or public.inbox_v2_tm_json_family_valid(
        'reference', document->'sourceOccurrence'
      )
    )
    and (
      document->'automationCausation' = 'null'::jsonb
      or public.inbox_v2_tm_json_family_valid(
        'automation_causation', document->'automationCausation'
      )
    );
  elsif family = 'reaction_state' then
    if kind in ('active', 'cleared') then
      return public.inbox_v2_tm_json_family_valid(
        'reaction_canonical', document
      );
    elsif kind = 'pending_external' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array[
          'kind', 'operation', 'desired', 'confirmedBefore', 'outboundRoute',
          'requestTransition', 'requestAttribution', 'requestedAt'
        ],
        array[
          'kind', 'operation', 'desired', 'confirmedBefore', 'outboundRoute',
          'requestTransition', 'requestAttribution', 'requestedAt'
        ]
      )
      and public.inbox_v2_tm_json_string_fields(
        document, array['kind', 'operation', 'requestedAt']
      )
      and public.inbox_v2_tm_json_family_valid(
        'reaction_desired', document->'desired'
      )
      and (
        document->'confirmedBefore' = 'null'::jsonb
        or public.inbox_v2_tm_json_family_valid(
          'reaction_canonical', document->'confirmedBefore'
        )
      )
      and public.inbox_v2_tm_json_family_valid(
        'reference', document->'outboundRoute'
      )
      and public.inbox_v2_tm_json_family_valid(
        'reference', document->'requestTransition'
      )
      and public.inbox_v2_tm_json_family_valid(
        'reaction_attribution', document->'requestAttribution'
      );
    elsif kind = 'external_terminal' then
      return public.inbox_v2_tm_json_exact_keys(
        document,
        array[
          'kind', 'operation', 'desired', 'confirmedState', 'outboundRoute',
          'requestTransition', 'outcome', 'resultToken', 'resultDigestSha256',
          'resolvedAt'
        ],
        array[
          'kind', 'operation', 'desired', 'confirmedState', 'outboundRoute',
          'requestTransition', 'outcome', 'resultToken', 'resultDigestSha256',
          'resolvedAt'
        ]
      )
      and public.inbox_v2_tm_json_string_fields(
        document,
        array[
          'kind', 'operation', 'outcome', 'resultToken',
          'resultDigestSha256', 'resolvedAt'
        ]
      )
      and public.inbox_v2_tm_json_family_valid(
        'reaction_desired', document->'desired'
      )
      and (
        document->'confirmedState' = 'null'::jsonb
        or public.inbox_v2_tm_json_family_valid(
          'reaction_canonical', document->'confirmedState'
        )
      )
      and public.inbox_v2_tm_json_family_valid(
        'reference', document->'outboundRoute'
      )
      and public.inbox_v2_tm_json_family_valid(
        'reference', document->'requestTransition'
      );
    end if;
    return false;
  elsif family = 'reaction_fence' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array[
        'capabilityId', 'capabilityRevision', 'adapterContract', 'decision',
        'evaluatedAt', 'notAfter'
      ],
      array[
        'capabilityId', 'capabilityRevision', 'adapterContract', 'decision',
        'evaluatedAt', 'notAfter'
      ]
    ) and public.inbox_v2_tm_json_string_fields(
      document,
      array[
        'capabilityId', 'capabilityRevision', 'decision',
        'evaluatedAt', 'notAfter'
      ]
    ) and public.inbox_v2_tm_json_family_valid(
      'adapter_contract', document->'adapterContract'
    );
  elsif family = 'reaction_authority' then
    return public.inbox_v2_tm_json_exact_keys(
      document,
      array[
        'externalMessageReference', 'sourceOccurrence', 'sourceAccount',
        'sourceThreadBinding', 'bindingGeneration', 'outboundRoute',
        'adapterContract', 'capabilityFence'
      ],
      array[
        'externalMessageReference', 'sourceOccurrence', 'sourceAccount',
        'sourceThreadBinding', 'bindingGeneration', 'outboundRoute',
        'adapterContract', 'capabilityFence'
      ]
    )
    and public.inbox_v2_tm_json_string_fields(
      document, array['bindingGeneration']
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'externalMessageReference'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'sourceOccurrence'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'sourceAccount'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reference', document->'sourceThreadBinding'
    )
    and (
      document->'outboundRoute' = 'null'::jsonb
      or public.inbox_v2_tm_json_family_valid(
        'reference', document->'outboundRoute'
      )
    )
    and public.inbox_v2_tm_json_family_valid(
      'adapter_contract', document->'adapterContract'
    )
    and public.inbox_v2_tm_json_family_valid(
      'reaction_fence', document->'capabilityFence'
    );
  end if;

  return false;
end;
$$;



--
-- Name: inbox_v2_tm_json_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_json_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  valid boolean := false;
begin
  case tg_table_name
    when 'inbox_v2_message_provider_lifecycle_operations' then
      valid := (
        (new.provider_semantic_proof_detail is null
          and new.semantic_ordering_commit_detail is null)
        or (public.inbox_v2_tm_json_family_valid(
            'provider_semantic_proof', new.provider_semantic_proof_detail
          ) and public.inbox_v2_tm_json_family_valid(
            'provider_ordering_commit', new.semantic_ordering_commit_detail
          ))
      );
    when 'inbox_v2_message_provider_lifecycle_transitions' then
      valid := new.result_proof_adapter_contract_detail is null
        or public.inbox_v2_tm_json_family_valid(
          'adapter_contract', new.result_proof_adapter_contract_detail
        );
    when 'inbox_v2_message_reactions' then
      valid := public.inbox_v2_tm_json_family_valid(
        'reaction_capability', new.capability_detail
      ) and public.inbox_v2_tm_json_family_valid(
        'reaction_state', new.state_detail
      ) and public.inbox_v2_tm_reaction_value_flat_valid(
        new.state_detail,
        new.state_kind::text,
        new.value_kind::text,
        new.unicode_value,
        new.provider_reaction_kind_id,
        new.provider_canonical_code
      ) and new.capability_detail #>> '{kind}' = new.capability_kind::text
      and new.capability_detail #>> '{cardinality}' = new.cardinality::text
      and (
        new.capability_kind = 'internal'
        or (
          new.capability_detail #>> '{capabilityId}' = new.capability_id
          and new.capability_detail #>> '{capabilityRevision}' =
            new.capability_revision::text
          and new.capability_detail #>> '{adapterContract,contractId}' =
            new.adapter_contract_id
          and new.capability_detail #>> '{adapterContract,contractVersion}' =
            new.adapter_contract_version
        )
      )
      and (
        new.state_kind = 'active'
        or (
          new.state_kind = 'cleared'
          and (new.state_detail #>> '{clearedAt}')::timestamptz =
            new.cleared_at
        )
        or (
          new.state_kind = 'pending_external'
          and new.state_detail #>> '{operation}' =
            new.external_operation::text
          and new.state_detail #>> '{outboundRoute,tenantId}' = new.tenant_id
          and new.state_detail #>> '{outboundRoute,kind}' = 'outbound_route'
          and new.state_detail #>> '{outboundRoute,id}' =
            new.outbound_route_id
          and new.state_detail #>> '{requestTransition,tenantId}' =
            new.tenant_id
          and new.state_detail #>> '{requestTransition,kind}' =
            'message_reaction_transition'
          and new.state_detail #>> '{requestTransition,id}' =
            new.request_transition_id
          and (new.state_detail #>> '{requestedAt}')::timestamptz =
            new.updated_at
        )
        or (
          new.state_kind = 'external_terminal'
          and new.state_detail #>> '{operation}' =
            new.external_operation::text
          and new.state_detail #>> '{outboundRoute,tenantId}' = new.tenant_id
          and new.state_detail #>> '{outboundRoute,kind}' = 'outbound_route'
          and new.state_detail #>> '{outboundRoute,id}' =
            new.outbound_route_id
          and new.state_detail #>> '{requestTransition,tenantId}' =
            new.tenant_id
          and new.state_detail #>> '{requestTransition,kind}' =
            'message_reaction_transition'
          and new.state_detail #>> '{requestTransition,id}' =
            new.request_transition_id
          and new.state_detail #>> '{outcome}' = new.external_outcome
          and new.state_detail #>> '{resultToken}' = new.result_token
          and new.state_detail #>> '{resultDigestSha256}' =
            new.result_digest_sha256
          and (new.state_detail #>> '{resolvedAt}')::timestamptz =
            new.resolved_at
        )
      );
    when 'inbox_v2_message_reaction_transitions' then
      valid := (
        new.before_state_detail is null
        or public.inbox_v2_tm_json_family_valid(
          'reaction_state', new.before_state_detail
        )
      )
      and public.inbox_v2_tm_json_family_valid(
        'reaction_state', new.after_state_detail
      )
      and public.inbox_v2_tm_reaction_value_flat_valid(
        new.after_state_detail,
        new.after_state_kind::text,
        new.value_kind::text,
        new.unicode_value,
        new.provider_reaction_kind_id,
        new.provider_canonical_code
      )
      and public.inbox_v2_tm_reaction_transition_state_valid(
        new.before_state_detail,
        new.after_state_detail,
        new.mode::text,
        new.operation::text,
        new.recorded_at
      )
      and (
        (
          new.after_state_kind = 'active'
          and new.mode in ('internal_apply', 'provider_observed')
        )
        or (
          new.after_state_kind = 'cleared'
          and new.mode in ('internal_apply', 'provider_observed')
          and (new.after_state_detail #>> '{clearedAt}')::timestamptz =
            new.recorded_at
        )
        or (
          new.after_state_kind = 'pending_external'
          and new.mode = 'external_request'
          and new.after_state_detail #>> '{operation}' = new.operation::text
          and new.after_state_detail #>> '{outboundRoute,tenantId}' =
            new.tenant_id
          and new.after_state_detail #>> '{outboundRoute,kind}' =
            'outbound_route'
          and new.after_state_detail #>> '{outboundRoute,id}' =
            new.outbound_route_id
          and new.after_state_detail #>> '{requestTransition,tenantId}' =
            new.tenant_id
          and new.after_state_detail #>> '{requestTransition,kind}' =
            'message_reaction_transition'
          and new.after_state_detail #>> '{requestTransition,id}' = new.id
          and public.inbox_v2_tm_reaction_attribution_row_valid(
            new.tenant_id,
            new.action_attribution_id,
            new.after_state_detail -> 'requestAttribution',
            new.recorded_at
          )
          and (new.after_state_detail #>> '{requestedAt}')::timestamptz =
            new.recorded_at
        )
        or (
          new.after_state_kind = 'external_terminal'
          and new.mode = 'provider_result'
          and new.before_state_detail #>> '{kind}' = 'pending_external'
          and public.inbox_v2_tm_reaction_attribution_row_valid(
            new.tenant_id,
            new.action_attribution_id,
            new.before_state_detail -> 'requestAttribution',
            new.recorded_at
          )
          and new.after_state_detail #>> '{operation}' = new.operation::text
          and new.after_state_detail -> 'outboundRoute' =
            new.before_state_detail -> 'outboundRoute'
          and new.after_state_detail -> 'requestTransition' =
            new.before_state_detail -> 'requestTransition'
          and new.after_state_detail #>> '{outboundRoute,tenantId}' =
            new.tenant_id
          and new.after_state_detail #>> '{outboundRoute,kind}' =
            'outbound_route'
          and new.after_state_detail #>> '{requestTransition,tenantId}' =
            new.tenant_id
          and new.after_state_detail #>> '{requestTransition,kind}' =
            'message_reaction_transition'
          and new.after_state_detail #>> '{outcome}' =
            new.provider_result_proof_detail #>> '{resultState}'
          and new.after_state_detail #>> '{resultToken}' = new.result_token
          and new.after_state_detail #>> '{resultDigestSha256}' =
            new.result_digest_sha256
          and (new.after_state_detail #>> '{resolvedAt}')::timestamptz =
            new.recorded_at
          and new.provider_result_proof_detail #>> '{tenantId}' =
            new.tenant_id
          and new.provider_result_proof_detail #>> '{operation,tenantId}' =
            new.tenant_id
          and new.provider_result_proof_detail #>> '{operation,kind}' =
            'message_reaction_transition'
          and new.provider_result_proof_detail #>> '{operation,id}' =
            new.after_state_detail #>> '{requestTransition,id}'
          and new.provider_result_proof_detail #>>
            '{outboundRoute,tenantId}' = new.tenant_id
          and new.provider_result_proof_detail #>> '{outboundRoute,kind}' =
            'outbound_route'
          and new.provider_result_proof_detail #>> '{outboundRoute,id}' =
            new.after_state_detail #>> '{outboundRoute,id}'
          and new.provider_result_proof_detail #>> '{resultToken}' =
            new.result_token
          and new.provider_result_proof_detail #>> '{resultDigestSha256}' =
            new.result_digest_sha256
          and (new.provider_result_proof_detail #>>
            '{recordedAt}')::timestamptz = new.recorded_at
        )
      )
      and (
        new.external_authority_detail is null
        or public.inbox_v2_tm_json_family_valid(
          'reaction_authority', new.external_authority_detail
        )
      )
      and (
        new.mode not in ('external_request', 'provider_observed')
        or public.inbox_v2_tm_reaction_authority_flat_valid(
          new.external_authority_detail,
          new.tenant_id,
          new.external_message_reference_id,
          new.source_occurrence_id,
          new.source_account_id,
          new.source_thread_binding_id,
          new.binding_generation,
          new.outbound_route_id,
          new.adapter_contract_id,
          new.adapter_contract_version,
          new.capability_id,
          new.capability_revision,
          new.occurred_at
        )
      )
      and (
        new.mode <> 'external_request'
        or exists (
          select 1
            from public.inbox_v2_message_reactions reaction_row
            join public.inbox_v2_messages message_row
              on message_row.tenant_id = reaction_row.tenant_id
             and message_row.id = reaction_row.message_id
           where reaction_row.tenant_id = new.tenant_id
             and reaction_row.id = new.reaction_id
             and public.inbox_v2_tm_outbound_route_action_valid(
               new.tenant_id,
               new.outbound_route_id,
               reaction_row.message_id,
               reaction_row.message_id,
               message_row.conversation_id,
               new.occurred_at,
               new.recorded_at,
               'core:message.reaction.' || new.operation::text,
               'core:message.reaction.' || new.operation::text || '_external',
               new.external_message_reference_id,
               new.source_occurrence_id,
               new.source_account_id,
               new.source_thread_binding_id,
               new.binding_generation,
               new.adapter_contract_id,
               new.adapter_contract_version,
               (new.external_authority_detail #>>
                 '{adapterContract,declarationRevision}')::bigint,
               new.external_authority_detail #>>
                 '{adapterContract,surfaceId}',
               new.external_authority_detail #>>
                 '{adapterContract,loadedByTrustedServiceId}',
               (new.external_authority_detail #>>
                 '{adapterContract,loadedAt}')::timestamptz,
               new.capability_id,
               new.capability_revision,
               new.action_attribution_id,
               true
             )
        )
      )
      and (
        new.provider_result_proof_detail is null
        or public.inbox_v2_tm_json_family_valid(
          'provider_result_proof', new.provider_result_proof_detail
        )
      )
      and (
        new.mode <> 'provider_result'
        or exists (
          select 1
            from public.inbox_v2_message_reactions reaction_row
            join public.inbox_v2_messages message_row
              on message_row.tenant_id = reaction_row.tenant_id
             and message_row.id = reaction_row.message_id
            join public.inbox_v2_outbound_routes route_row
              on route_row.tenant_id = reaction_row.tenant_id
             and route_row.id = new.provider_result_proof_detail #>>
               '{outboundRoute,id}'
             and route_row.conversation_id = message_row.conversation_id
            join public.inbox_v2_message_reaction_transitions request_row
              on request_row.tenant_id = reaction_row.tenant_id
             and request_row.id = new.provider_result_proof_detail #>>
               '{operation,id}'
             and request_row.reaction_id = reaction_row.id
             and request_row.mode = 'external_request'
             and request_row.resulting_revision = new.expected_revision
             and request_row.outbound_route_id = route_row.id
           where reaction_row.tenant_id = new.tenant_id
             and reaction_row.id = new.reaction_id
             and reaction_row.capability_kind = 'external'
             and new.provider_result_proof_detail #>> '{revision}' = '1'
             and new.provider_result_proof_detail #>> '{capabilityId}' =
               reaction_row.capability_id
             and new.provider_result_proof_detail #>>
               '{capabilityRevision}' = reaction_row.capability_revision::text
             and new.provider_result_proof_detail -> 'adapterContract' =
               reaction_row.capability_detail -> 'adapterContract'
             and new.provider_result_proof_detail #>> '{semanticId}' =
               'core:message.reaction.' || new.operation::text || '.result'
             and new.provider_result_proof_detail #>> '{semanticRevision}' ~
               '^[1-9][0-9]*$'
             and char_length(new.provider_result_proof_detail #>>
               '{semanticRevision}') <= 19
             and (
               char_length(new.provider_result_proof_detail #>>
                 '{semanticRevision}') < 19
               or (new.provider_result_proof_detail #>>
                 '{semanticRevision}') collate "C" <=
                   '9223372036854775807'
             )
             and new.provider_result_proof_detail #>>
               '{declaredByTrustedServiceId}' =
                 new.provider_result_proof_detail #>>
                   '{adapterContract,loadedByTrustedServiceId}'
             and isfinite((new.provider_result_proof_detail #>>
               '{adapterContract,loadedAt}')::timestamptz)
             and (new.provider_result_proof_detail #>>
               '{adapterContract,loadedAt}')::timestamptz <= new.recorded_at
             and route_row.adapter_contract_id =
               new.provider_result_proof_detail #>>
                 '{adapterContract,contractId}'
             and route_row.adapter_contract_version =
               new.provider_result_proof_detail #>>
                 '{adapterContract,contractVersion}'
             and route_row.adapter_declaration_revision::text =
               new.provider_result_proof_detail #>>
                 '{adapterContract,declarationRevision}'
             and route_row.adapter_surface_id =
               new.provider_result_proof_detail #>>
                 '{adapterContract,surfaceId}'
             and route_row.adapter_loaded_by_trusted_service_id =
               new.provider_result_proof_detail #>>
                 '{adapterContract,loadedByTrustedServiceId}'
             and route_row.adapter_loaded_at =
               (new.provider_result_proof_detail #>>
                 '{adapterContract,loadedAt}')::timestamptz
             and route_row.capability_revision =
               reaction_row.capability_revision
        )
      )
      and exists (
        select 1
          from public.inbox_v2_message_reactions reaction_row
          join public.inbox_v2_action_attributions attribution_row
            on attribution_row.tenant_id = new.tenant_id
           and attribution_row.id = new.action_attribution_id
         where reaction_row.tenant_id = new.tenant_id
           and reaction_row.id = new.reaction_id
           and (
             new.operation <> 'replace'
             or (
               reaction_row.capability_kind = 'external'
               and reaction_row.cardinality = 'single_value'
             )
           )
           and (
             (
               new.mode = 'internal_apply'
               and reaction_row.capability_kind = 'internal'
               and attribution_row.app_actor_kind is not null
               and attribution_row.source_occurrence_id is null
             )
             or (
               new.mode in ('external_request', 'provider_result')
               and reaction_row.capability_kind = 'external'
               and attribution_row.app_actor_kind is not null
               and attribution_row.source_occurrence_id is null
             )
             or (
               new.mode = 'provider_observed'
               and reaction_row.capability_kind = 'external'
               and attribution_row.app_actor_kind is null
               and attribution_row.source_occurrence_id =
                 new.source_occurrence_id
             )
           )
      );
    when 'inbox_v2_message_provider_reaction_observations' then
      valid := public.inbox_v2_tm_json_family_valid(
        'provider_semantic_proof', new.semantic_proof_detail
      ) and public.inbox_v2_tm_json_family_valid(
        'provider_ordering_commit', new.ordering_commit_detail
      );
    when 'inbox_v2_provider_semantic_ordering_heads' then
      valid := public.inbox_v2_tm_json_family_valid(
        'provider_ordering_head', new.head_detail
      );
    when 'inbox_v2_message_delivery_observations' then
      valid := new.semantic_proof_detail is null
        or public.inbox_v2_tm_json_family_valid(
          'provider_semantic_proof', new.semantic_proof_detail
        );
    when 'inbox_v2_provider_receipt_observations' then
      valid := public.inbox_v2_tm_json_family_valid(
        'provider_semantic_proof', new.semantic_proof_detail
      );
    else
      valid := false;
  end case;

  if not coalesce(valid, false) then
    raise exception using errcode = '23514',
      message = format(
        'inbox_v2.timeline_message_json_contract:%s', tg_table_name
      );
  end if;

  return new;
end;
$_$;



--
-- Name: inbox_v2_tm_json_string_fields(jsonb, text[]); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_json_string_fields(document jsonb, field_names text[]) RETURNS boolean
    LANGUAGE sql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select coalesce(
    jsonb_typeof(document) = 'object'
    and not exists (
      select 1
        from unnest(field_names) as field_name
       where jsonb_typeof(document->field_name) is distinct from 'string'
    ),
    false
  );
$$;



--
-- Name: inbox_v2_tm_message_history_valid(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_message_history_valid(checked_tenant_id text, checked_message_id text) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select exists (
    select 1
      from public.inbox_v2_messages message_row
      join public.inbox_v2_message_revisions latest_row
        on latest_row.tenant_id = message_row.tenant_id
       and latest_row.message_id = message_row.id
       and latest_row.timeline_item_id = message_row.timeline_item_id
       and latest_row.message_revision = message_row.revision
       and latest_row.recorded_stream_position =
         message_row.last_changed_stream_position
      join public.inbox_v2_timeline_items timeline_row
        on timeline_row.tenant_id = message_row.tenant_id
       and timeline_row.id = message_row.timeline_item_id
       and timeline_row.conversation_id = message_row.conversation_id
       and timeline_row.subject_kind = 'message'
       and timeline_row.subject_id = message_row.id
       and timeline_row.revision = message_row.revision
       and timeline_row.last_changed_stream_position =
         message_row.last_changed_stream_position
       and timeline_row.updated_at = latest_row.recorded_at
      join lateral (
        select content_head_row.*
          from public.inbox_v2_message_revisions content_head_row
         where content_head_row.tenant_id = message_row.tenant_id
           and content_head_row.message_id = message_row.id
           and content_head_row.after_content_id is not null
         order by content_head_row.message_revision desc
         limit 1
      ) latest_content_row on true
      left join lateral (
        select lifecycle_head_row.*
          from public.inbox_v2_message_revisions lifecycle_head_row
         where lifecycle_head_row.tenant_id = message_row.tenant_id
           and lifecycle_head_row.message_id = message_row.id
           and lifecycle_head_row.change_kind in (
             'local_delete_tombstone',
             'provider_delete_policy_tombstone'
           )
         order by lifecycle_head_row.message_revision desc
         limit 1
      ) latest_lifecycle_row on true
      where message_row.tenant_id = checked_tenant_id
        and message_row.id = checked_message_id
        and timeline_row.created_at = message_row.created_at
        and message_row.updated_at = latest_row.recorded_at
       and (
         select count(*) = message_row.revision
            and min(history_row.message_revision) = 1
            and max(history_row.message_revision) = message_row.revision
           from public.inbox_v2_message_revisions history_row
          where history_row.tenant_id = message_row.tenant_id
            and history_row.message_id = message_row.id
       )
       and exists (
         select 1
           from public.inbox_v2_message_revisions first_row
          where first_row.tenant_id = message_row.tenant_id
            and first_row.message_id = message_row.id
            and first_row.timeline_item_id = message_row.timeline_item_id
            and first_row.message_revision = 1
            and first_row.expected_previous_revision is null
            and first_row.change_kind = 'created'
            and first_row.before_content_id is null
            and first_row.before_content_revision is null
            and first_row.before_content_state is null
            and first_row.after_content_id is not null
            and first_row.after_content_revision = 1
            and first_row.after_content_state = 'available'
            and first_row.provider_operation_id is null
            and first_row.reason_id is null
            and first_row.action_attribution_id =
              message_row.creation_attribution_id
            and first_row.occurred_at = timeline_row.occurred_at
            and first_row.recorded_at = message_row.created_at
       )
       and not exists (
         select 1
           from public.inbox_v2_message_revisions history_row
           join public.inbox_v2_action_attributions attribution_row
             on attribution_row.tenant_id = history_row.tenant_id
            and attribution_row.id = history_row.action_attribution_id
            left join public.inbox_v2_message_revisions predecessor_row
              on predecessor_row.tenant_id = history_row.tenant_id
             and predecessor_row.message_id = history_row.message_id
             and predecessor_row.message_revision =
               history_row.message_revision - 1
            left join lateral (
              select content_predecessor_candidate_row.*
                from public.inbox_v2_message_revisions
                  content_predecessor_candidate_row
               where content_predecessor_candidate_row.tenant_id =
                       history_row.tenant_id
                 and content_predecessor_candidate_row.message_id =
                       history_row.message_id
                 and content_predecessor_candidate_row.message_revision <
                       history_row.message_revision
                 and content_predecessor_candidate_row.after_content_id is not null
               order by content_predecessor_candidate_row.message_revision desc
               limit 1
            ) content_predecessor_row on true
          where history_row.tenant_id = message_row.tenant_id
            and history_row.message_id = message_row.id
            and (
              history_row.timeline_item_id <> message_row.timeline_item_id
              or not (
                public.inbox_v2_tm_action_attribution_valid(
                  history_row.tenant_id,
                  history_row.action_attribution_id,
                  message_row.conversation_id,
                  true
                )
                or (
                  history_row.message_revision = 1
                  and history_row.change_kind = 'created'
                  and message_row.origin_kind = 'migration'
                  and attribution_row.conversation_id =
                    message_row.conversation_id
                  and attribution_row.action_participant_id =
                    message_row.author_participant_id
                  and attribution_row.app_actor_kind = 'trusted_service'
                  and attribution_row.app_trusted_service_id is not null
                  and attribution_row.source_occurrence_id is null
                  and attribution_row.automation_kind is not null
                  and exists (
                    select 1
                      from public.inbox_v2_conversation_participants
                        migration_author_row
                     where migration_author_row.tenant_id =
                             message_row.tenant_id
                       and migration_author_row.id =
                             message_row.author_participant_id
                       and migration_author_row.conversation_id =
                             message_row.conversation_id
                       and migration_author_row.subject_kind in (
                         'legacy_unknown', 'system'
                       )
                  )
                )
              )
              or attribution_row.created_at <> history_row.recorded_at
              or (history_row.message_revision > 1 and (
                predecessor_row.id is null
                or history_row.expected_previous_revision <>
                  predecessor_row.message_revision
                or predecessor_row.recorded_at > history_row.recorded_at
                or predecessor_row.recorded_stream_position >=
                  history_row.recorded_stream_position
              ))
              or (history_row.message_revision > 1 and exists (
                select 1
                  from public.inbox_v2_message_revisions terminal_row
                 where terminal_row.tenant_id = history_row.tenant_id
                   and terminal_row.message_id = history_row.message_id
                   and terminal_row.message_revision <
                     history_row.message_revision
                   and terminal_row.change_kind in (
                     'privacy_erasure_tombstone',
                     'retention_purge_tombstone'
                   )
              ))
              or (history_row.change_kind in (
                    'edited', 'attachment_materialized',
                    'local_delete_tombstone',
                    'provider_delete_policy_tombstone'
                  ) and exists (
                select 1
                  from public.inbox_v2_message_revisions lifecycle_row
                 where lifecycle_row.tenant_id = history_row.tenant_id
                   and lifecycle_row.message_id = history_row.message_id
                   and lifecycle_row.message_revision <
                     history_row.message_revision
                   and lifecycle_row.change_kind in (
                     'local_delete_tombstone',
                     'provider_delete_policy_tombstone'
                   )
              ))
              or (history_row.change_kind in (
                    'edited', 'attachment_materialized',
                    'privacy_erasure_tombstone',
                    'retention_purge_tombstone'
                  ) and not (
                history_row.before_content_id =
                  content_predecessor_row.after_content_id
                and history_row.before_content_revision =
                  content_predecessor_row.after_content_revision
                and history_row.before_content_state =
                  content_predecessor_row.after_content_state
                and history_row.before_content_state = 'available'
                and history_row.after_content_id =
                  history_row.before_content_id
                and history_row.after_content_revision =
                  history_row.before_content_revision + 1
                and history_row.after_content_state = case history_row.change_kind
                  when 'privacy_erasure_tombstone' then
                    'privacy_erased'::public.inbox_v2_timeline_content_state
                  when 'retention_purge_tombstone' then
                    'retention_purged'::public.inbox_v2_timeline_content_state
                  else 'available'::public.inbox_v2_timeline_content_state
                end
              ))
              or (history_row.change_kind in (
                    'local_delete_tombstone',
                    'provider_delete_policy_tombstone'
                  ) and num_nonnulls(
                    history_row.before_content_id,
                    history_row.before_content_revision,
                    history_row.before_content_state,
                    history_row.after_content_id,
                    history_row.after_content_revision,
                    history_row.after_content_state
                  ) <> 0)
              or (history_row.after_content_id is not null and not exists (
                select 1
                  from public.inbox_v2_timeline_content_revisions content_revision_row
                 where content_revision_row.tenant_id = history_row.tenant_id
                   and content_revision_row.content_id =
                     history_row.after_content_id
                   and content_revision_row.revision =
                     history_row.after_content_revision
                    and content_revision_row.state =
                      history_row.after_content_state
                    and content_revision_row.recorded_stream_position =
                      history_row.recorded_stream_position
                    and content_revision_row.recorded_at = history_row.recorded_at
                    and content_revision_row.transition_kind =
                     case history_row.change_kind
                       when 'created' then
                         'created'::public.inbox_v2_timeline_content_transition_kind
                       when 'edited' then
                         'edit'::public.inbox_v2_timeline_content_transition_kind
                       when 'attachment_materialized' then
                         'attachment_materialization'::public.inbox_v2_timeline_content_transition_kind
                       when 'privacy_erasure_tombstone' then
                         'privacy_erasure'::public.inbox_v2_timeline_content_transition_kind
                       when 'retention_purge_tombstone' then
                         'retention_purge'::public.inbox_v2_timeline_content_transition_kind
                     end
              ))
              or (history_row.change_kind = 'local_delete_tombstone' and not (
                history_row.reason_id is not null
                and history_row.provider_operation_id is null
              ))
              or (history_row.change_kind =
                    'provider_delete_policy_tombstone' and not (
                history_row.reason_id is not null
                and history_row.provider_operation_id is not null
              ))
              or (history_row.change_kind not in (
                    'edited', 'provider_delete_policy_tombstone'
                  ) and history_row.provider_operation_id is not null)
              or (history_row.change_kind not in (
                    'local_delete_tombstone',
                    'provider_delete_policy_tombstone'
                  )
                and history_row.reason_id is not null)
              or (history_row.change_kind = 'edited' and (
                (message_row.origin_kind in (
                    'source_originated', 'hulee_external'
                  )) <> (history_row.provider_operation_id is not null)
              ))
              or (history_row.change_kind in (
                    'attachment_materialized',
                    'privacy_erasure_tombstone',
                  'retention_purge_tombstone'
                  ) and attribution_row.app_actor_kind is distinct from
                    'trusted_service')
              or (history_row.change_kind = 'local_delete_tombstone'
                and attribution_row.app_actor_kind is null)
              or (history_row.change_kind = 'edited'
                and message_row.origin_kind in ('internal', 'migration')
                and attribution_row.app_actor_kind is null)
              or (history_row.message_revision > 1
                and attribution_row.source_occurrence_id is not null
                and history_row.provider_operation_id is null)
              or (history_row.provider_operation_id is not null and not exists (
                select 1
                  from public.inbox_v2_message_provider_lifecycle_operations op_row
                 where op_row.tenant_id = history_row.tenant_id
                   and op_row.id = history_row.provider_operation_id
                   and op_row.message_id = history_row.message_id
                   and op_row.action = case history_row.change_kind
                     when 'edited' then
                       'edit'::public.inbox_v2_provider_lifecycle_action
                     when 'provider_delete_policy_tombstone' then
                       'delete'::public.inbox_v2_provider_lifecycle_action
                   end
                   and (
                     history_row.change_kind = 'edited'
                     or (
                       op_row.delete_local_effect = 'tombstone_local'
                       and op_row.policy_decided_at <= history_row.recorded_at
                     )
                   )
                   and (
                     (op_row.origin = 'provider_observed'
                       and op_row.action_attribution_id is null
                       and attribution_row.app_actor_kind is null
                       and attribution_row.source_occurrence_id =
                         op_row.source_occurrence_id
                       and attribution_row.automation_kind is null)
                      or (op_row.origin = 'hulee_requested'
                        and attribution_row.app_actor_kind is not null
                        and attribution_row.source_occurrence_id is null
                        and exists (
                          select 1
                            from public.inbox_v2_action_attributions
                              operation_attribution_row
                           where operation_attribution_row.tenant_id =
                                   op_row.tenant_id
                             and operation_attribution_row.id =
                                   op_row.action_attribution_id
                             and operation_attribution_row.action_participant_id
                                   is not distinct from
                                   attribution_row.action_participant_id
                             and operation_attribution_row.app_actor_kind
                                   is not distinct from
                                   attribution_row.app_actor_kind
                             and operation_attribution_row.app_actor_employee_id
                                   is not distinct from
                                   attribution_row.app_actor_employee_id
                             and operation_attribution_row.app_authorization_epoch
                                   is not distinct from
                                   attribution_row.app_authorization_epoch
                             and operation_attribution_row.app_trusted_service_id
                                   is not distinct from
                                   attribution_row.app_trusted_service_id
                             and operation_attribution_row.source_occurrence_id
                                   is not distinct from
                                   attribution_row.source_occurrence_id
                             and operation_attribution_row.automation_kind
                                   is not distinct from
                                   attribution_row.automation_kind
                             and operation_attribution_row.automation_cause_event_id
                                   is not distinct from
                                   attribution_row.automation_cause_event_id
                             and operation_attribution_row.automation_correlation_id
                                   is not distinct from
                                   attribution_row.automation_correlation_id
                             and operation_attribution_row.automation_caused_at
                                   is not distinct from
                                   attribution_row.automation_caused_at
                             and operation_attribution_row
                                   .automation_initiating_employee_id
                                   is not distinct from
                                   attribution_row.automation_initiating_employee_id
                             and operation_attribution_row
                                   .automation_initiating_authorization_epoch
                                   is not distinct from
                                   attribution_row
                                     .automation_initiating_authorization_epoch
                        ))
                   )
              ))
            )
       )
       and message_row.content_id = latest_content_row.after_content_id
       and message_row.content_revision = latest_content_row.after_content_revision
       and message_row.content_state = latest_content_row.after_content_state
       and (
         (latest_lifecycle_row.change_kind = 'local_delete_tombstone'
           and message_row.lifecycle = 'local_delete_tombstone'
           and message_row.lifecycle_revision_id = latest_lifecycle_row.id
           and message_row.lifecycle_reason_id = latest_lifecycle_row.reason_id
           and message_row.lifecycle_provider_operation_id is null
           and message_row.lifecycle_policy_reason_id is null
           and message_row.lifecycle_changed_at = latest_lifecycle_row.recorded_at)
         or (latest_lifecycle_row.change_kind =
               'provider_delete_policy_tombstone'
           and message_row.lifecycle = 'provider_delete_tombstone'
           and message_row.lifecycle_revision_id = latest_lifecycle_row.id
           and message_row.lifecycle_provider_operation_id =
             latest_lifecycle_row.provider_operation_id
           and message_row.lifecycle_reason_id is null
           and message_row.lifecycle_policy_reason_id =
             latest_lifecycle_row.reason_id
           and message_row.lifecycle_changed_at =
             latest_lifecycle_row.recorded_at)
         or (latest_lifecycle_row.id is null
           and message_row.lifecycle = 'active'
           and message_row.lifecycle_revision_id is null
           and message_row.lifecycle_reason_id is null
           and message_row.lifecycle_provider_operation_id is null
           and message_row.lifecycle_policy_reason_id is null
           and message_row.lifecycle_changed_at is null)
       )
  );
$$;



--
-- Name: inbox_v2_tm_outbound_route_action_valid(text, text, text, text, text, timestamp with time zone, timestamp with time zone, text, text, text, text, text, text, bigint, text, text, bigint, text, text, timestamp with time zone, text, bigint, text, boolean); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_outbound_route_action_valid(expected_tenant_id text, expected_route_id text, expected_message_id text, expected_reference_owner_message_id text, expected_conversation_id text, expected_authority_at timestamp with time zone, expected_attribution_created_at timestamp with time zone, expected_operation_id text, expected_required_permission_id text, expected_external_message_reference_id text, expected_source_occurrence_id text, expected_source_account_id text, expected_source_thread_binding_id text, expected_binding_generation bigint, expected_adapter_contract_id text, expected_adapter_contract_version text, expected_adapter_declaration_revision bigint, expected_adapter_surface_id text, expected_adapter_loaded_by_trusted_service_id text, expected_adapter_loaded_at timestamp with time zone, expected_capability_id text, expected_capability_revision bigint, expected_attribution_id text, require_explicit_occurrence boolean) RETURNS boolean
    LANGUAGE plpgsql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  return exists (
    select 1
      from public.inbox_v2_outbound_routes route_row
      join public.inbox_v2_action_attributions attribution_row
        on attribution_row.tenant_id = route_row.tenant_id
       and attribution_row.id = expected_attribution_id
       and attribution_row.conversation_id = route_row.conversation_id
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = route_row.tenant_id
       and message_row.id = expected_message_id
       and message_row.conversation_id = route_row.conversation_id
      join public.inbox_v2_source_thread_binding_snapshots binding_snapshot
        on binding_snapshot.tenant_id = route_row.tenant_id
       and binding_snapshot.binding_id = route_row.source_thread_binding_id
       and binding_snapshot.revision = route_row.binding_revision
       and binding_snapshot.external_thread_id = route_row.external_thread_id
       and binding_snapshot.source_connection_id = route_row.source_connection_id
       and binding_snapshot.source_account_id = route_row.source_account_id
       and binding_snapshot.account_generation = route_row.account_generation
       and binding_snapshot.binding_generation = route_row.binding_generation
       and binding_snapshot.remote_access_revision =
         route_row.remote_access_revision
       and binding_snapshot.administrative_revision =
         route_row.administrative_revision
       and binding_snapshot.capability_revision = route_row.capability_revision
       and binding_snapshot.route_descriptor_revision =
         route_row.route_descriptor_revision
      left join public.inbox_v2_source_occurrences occurrence_row
        on occurrence_row.tenant_id = route_row.tenant_id
       and occurrence_row.id = expected_source_occurrence_id
       and occurrence_row.conversation_id = route_row.conversation_id
       and occurrence_row.external_thread_id = route_row.external_thread_id
       and occurrence_row.adapter_contract_id = route_row.adapter_contract_id
       and occurrence_row.adapter_contract_version =
         route_row.adapter_contract_version
       and occurrence_row.adapter_declaration_revision =
         route_row.adapter_declaration_revision
       and occurrence_row.adapter_surface_id = route_row.adapter_surface_id
       and occurrence_row.adapter_loaded_by_trusted_service_id =
         route_row.adapter_loaded_by_trusted_service_id
       and occurrence_row.adapter_loaded_at = route_row.adapter_loaded_at
       and occurrence_row.resolution_state = 'resolved'
       and occurrence_row.resolved_external_message_reference_id =
         expected_external_message_reference_id
      left join public.inbox_v2_source_occurrence_resolution_transitions
        resolution_row
        on resolution_row.tenant_id = occurrence_row.tenant_id
       and resolution_row.source_occurrence_id = occurrence_row.id
       and resolution_row.resulting_revision = occurrence_row.revision
       and resolution_row.to_state = 'resolved'
       and resolution_row.resolved_external_message_reference_id =
         expected_external_message_reference_id
      left join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = route_row.tenant_id
       and reference_row.id = expected_external_message_reference_id
       and reference_row.external_thread_id = route_row.external_thread_id
      left join public.inbox_v2_source_thread_binding_capability_entries capability_row
        on capability_row.tenant_id = route_row.tenant_id
       and capability_row.binding_id = route_row.source_thread_binding_id
       and capability_row.materialized_by_binding_revision =
         route_row.binding_revision
       and capability_row.capability_revision = route_row.capability_revision
       and (
         expected_capability_id is null
         or capability_row.capability_id = expected_capability_id
       )
       and capability_row.operation_id = route_row.operation_id
       and capability_row.content_kind_id is not distinct from
         route_row.content_kind_id
     where route_row.tenant_id = expected_tenant_id
       and route_row.id = expected_route_id
       and route_row.conversation_id = expected_conversation_id
       and route_row.operation_id = expected_operation_id
       and route_row.required_conversation_permission_id =
         expected_required_permission_id
       and (
         expected_source_account_id is null
         or route_row.source_account_id = expected_source_account_id
       )
       and (
         expected_source_thread_binding_id is null
         or route_row.source_thread_binding_id =
           expected_source_thread_binding_id
       )
       and (
         expected_binding_generation is null
         or route_row.binding_generation = expected_binding_generation
       )
       and (
         expected_adapter_contract_id is null
         or (
           route_row.adapter_contract_id = expected_adapter_contract_id
           and route_row.adapter_contract_version =
             expected_adapter_contract_version
           and route_row.adapter_declaration_revision =
             expected_adapter_declaration_revision
           and route_row.adapter_surface_id = expected_adapter_surface_id
           and route_row.adapter_loaded_by_trusted_service_id =
             expected_adapter_loaded_by_trusted_service_id
           and route_row.adapter_loaded_at = expected_adapter_loaded_at
         )
       )
       and (
         expected_capability_revision is null
         or route_row.capability_revision = expected_capability_revision
       )
       and binding_snapshot.remote_access_state = 'active'
       and binding_snapshot.administrative_state = 'enabled'
       and binding_snapshot.runtime_health_state::text =
         route_row.runtime_observation_snapshot #>> '{state}'
       and binding_snapshot.runtime_health_revision::text =
         route_row.runtime_observation_snapshot #>> '{revision}'
       and binding_snapshot.runtime_health_checked_at =
         (route_row.runtime_observation_snapshot #>>
           '{observedAt}')::timestamptz
       and binding_snapshot.capability_contract_id =
         route_row.adapter_contract_id
       and binding_snapshot.capability_contract_version =
         route_row.adapter_contract_version
       and binding_snapshot.capability_declaration_revision =
         route_row.adapter_declaration_revision
       and binding_snapshot.capability_surface_id = route_row.adapter_surface_id
       and binding_snapshot.capability_loaded_by_trusted_service_id =
         route_row.adapter_loaded_by_trusted_service_id
       and binding_snapshot.capability_loaded_at = route_row.adapter_loaded_at
       and binding_snapshot.updated_at <= expected_authority_at
       and binding_snapshot.capability_captured_at <= expected_authority_at
       and (
         (
           expected_external_message_reference_id is null
           and expected_source_occurrence_id is null
           and route_row.reference_context_snapshot =
             '{"kind":"none"}'::jsonb
         )
         or (
           expected_external_message_reference_id is not null
           and expected_source_occurrence_id is not null
           and occurrence_row.id is not null
           and reference_row.id is not null
           and resolution_row.id is not null
           and (
             expected_reference_owner_message_id is null
             or reference_row.message_id =
               expected_reference_owner_message_id
           )
           and route_row.reference_context_snapshot #>> '{kind}' =
             'external_message'
           and route_row.reference_context_snapshot #>>
             '{externalMessageReference,id}' =
               expected_external_message_reference_id
           and route_row.reference_context_snapshot #>>
             '{sourceOccurrence,id}' = expected_source_occurrence_id
           and route_row.reference_context_snapshot #>>
             '{externalThread,id}' = route_row.external_thread_id
           and route_row.reference_context_snapshot #>>
             '{originBinding,id}' = occurrence_row.source_thread_binding_id
           and route_row.reference_context_snapshot #>>
             '{originSourceAccount,id}' = occurrence_row.source_account_id
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,externalThread}' =
               route_row.reference_context_snapshot #> '{externalThread}'
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,externalMessageReference}' =
               route_row.reference_context_snapshot #>
                 '{externalMessageReference}'
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,sourceOccurrence}' =
               route_row.reference_context_snapshot #> '{sourceOccurrence}'
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,originBinding}' =
               route_row.reference_context_snapshot #> '{originBinding}'
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,originSourceAccount}' =
               route_row.reference_context_snapshot #> '{originSourceAccount}'
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,portability}' =
               route_row.reference_context_snapshot #> '{portability}'
           and occurrence_row.revision =
             (route_row.reference_context_snapshot #>>
               '{resolutionDecision,occurrenceRevision}')::bigint
           and occurrence_row.binding_generation =
             (route_row.reference_context_snapshot #>>
               '{resolutionDecision,occurrenceBindingGeneration}')::bigint
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,descriptorSchemaId}' =
               occurrence_row.descriptor_schema_id
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,descriptorVersion}' =
               occurrence_row.descriptor_version
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,capabilityRevision}' =
               occurrence_row.capability_revision::text
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,occurrenceDescriptor,descriptorDigestSha256}' =
               occurrence_row.descriptor_digest_sha256
           and jsonb_array_length(route_row.reference_context_snapshot #>
             '{resolutionDecision,occurrenceDescriptor,providerReferences}') =
               occurrence_row.provider_reference_count
           and not exists (
             select 1
               from jsonb_array_elements(route_row.reference_context_snapshot #>
                 '{resolutionDecision,occurrenceDescriptor,providerReferences}')
                 with ordinality as supplied_reference(value, ordinal)
               left join public.inbox_v2_source_occurrence_provider_references
                 stored_reference
                 on stored_reference.tenant_id = occurrence_row.tenant_id
                and stored_reference.source_occurrence_id = occurrence_row.id
                and stored_reference.ordinal = supplied_reference.ordinal - 1
              where stored_reference.ordinal is null
                 or supplied_reference.value is distinct from jsonb_build_object(
                   'kindId', stored_reference.kind_id,
                   'subject', stored_reference.subject
                 )
           )
           and route_row.reference_context_snapshot #>>
             '{portability,kind}' =
               occurrence_row.reference_portability_kind::text
           and route_row.reference_context_snapshot #>>
             '{portability,decisionStrength}' =
               occurrence_row.reference_portability_decision_strength::text
           and route_row.reference_context_snapshot #>
             '{portability,adapterContract}' =
               route_row.adapter_contract_snapshot
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,loadedByTrustedServiceId}' =
               resolution_row.resolver_trusted_service_id
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,state}' = 'available'
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,tenantId}' =
               route_row.tenant_id
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,externalThread}' =
               route_row.reference_context_snapshot #> '{externalThread}'
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,externalMessageReference}' =
               route_row.reference_context_snapshot #>
                 '{externalMessageReference}'
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,sourceOccurrence}' =
               route_row.reference_context_snapshot #> '{sourceOccurrence}'
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,occurrenceRevision}' =
               occurrence_row.revision::text
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,occurrenceDescriptorDigestSha256}' =
               occurrence_row.descriptor_digest_sha256
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,adapterContract}' =
               route_row.adapter_contract_snapshot
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,observedByTrustedServiceId}' =
               occurrence_row.adapter_loaded_by_trusted_service_id
           and route_row.reference_context_snapshot #>
             '{resolutionDecision,availabilityObservation,diagnostic}' =
               'null'::jsonb
           and (route_row.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,observedAt}')::timestamptz
               <= expected_authority_at
           and (route_row.reference_context_snapshot #>>
             '{resolutionDecision,availabilityObservation,notAfter}')::timestamptz
               >= expected_authority_at
           and (
             route_row.reference_context_snapshot #>>
               '{portability,kind}' <> 'binding_only'
             or (
               occurrence_row.source_thread_binding_id =
                 route_row.source_thread_binding_id
               and occurrence_row.source_account_id =
                 route_row.source_account_id
               and occurrence_row.binding_generation =
                 route_row.binding_generation
             )
           )
           and (
             route_row.selection_intent_kind <> 'explicit_occurrence'
             or (
               route_row.selection_reason = 'explicit_occurrence'
               and route_row.selection_intent_snapshot #>>
                 '{occurrence,id}' = occurrence_row.id
               and occurrence_row.source_thread_binding_id =
                 route_row.source_thread_binding_id
               and occurrence_row.source_account_id =
                 route_row.source_account_id
               and occurrence_row.binding_generation =
                 route_row.binding_generation
             )
           )
         )
       )
       and (
         not require_explicit_occurrence
         or (
           route_row.selection_intent_kind = 'explicit_occurrence'
           and route_row.selection_reason = 'explicit_occurrence'
           and route_row.selection_intent_snapshot #>> '{occurrence,id}' =
             expected_source_occurrence_id
         )
       )
       and attribution_row.created_at = expected_attribution_created_at
       and attribution_row.source_occurrence_id is null
       and (
         (
           attribution_row.app_actor_kind = 'employee'
           and route_row.principal_kind = 'employee'
           and route_row.principal_employee_id =
             attribution_row.app_actor_employee_id
           and route_row.authorization_epoch =
             attribution_row.app_authorization_epoch
           and attribution_row.app_trusted_service_id is null
         )
         or (
           attribution_row.app_actor_kind = 'trusted_service'
           and route_row.principal_kind = 'trusted_service'
           and route_row.principal_trusted_service_id =
             attribution_row.app_trusted_service_id
           and attribution_row.app_actor_employee_id is null
           and attribution_row.app_authorization_epoch is null
         )
       )
       and capability_row.state = 'supported'
       and (
         capability_row.valid_until is null
         or capability_row.valid_until > expected_authority_at
       )
       and not exists (
         select 1
           from public.inbox_v2_source_thread_binding_capability_required_roles
             required_role
          where required_role.tenant_id = capability_row.tenant_id
            and required_role.binding_id = capability_row.binding_id
            and required_role.capability_revision =
              capability_row.capability_revision
            and required_role.capability_ordinal = capability_row.ordinal
            and not exists (
              select 1
                from public.inbox_v2_source_thread_binding_provider_roles
                  provider_role
               where provider_role.tenant_id = required_role.tenant_id
                 and provider_role.binding_id = required_role.binding_id
                 and provider_role.provider_access_revision =
                   binding_snapshot.provider_access_revision
                 and provider_role.provider_role_id =
                   required_role.provider_role_id
            )
       )
       and (route_row.runtime_observation_snapshot #>>
         '{observedAt}')::timestamptz <= expected_authority_at
       and route_row.selected_at <= expected_authority_at
       and route_row.created_at <= expected_authority_at
       and route_row.candidate_snapshot_not_after >= expected_authority_at
       and (route_row.conversation_authorization_snapshot #>>
         '{notAfter}')::timestamptz >= expected_authority_at
       and (route_row.source_account_authorization_snapshot #>>
         '{notAfter}')::timestamptz >= expected_authority_at
       and (
         expected_external_message_reference_id is null
         or (
           (route_row.reference_context_snapshot #>>
             '{resolutionDecision,notAfter}')::timestamptz >=
               expected_authority_at
           and route_row.reference_context_snapshot #>>
             '{resolutionDecision,referenceWindow,state}' <> 'expired'
           and (
             route_row.reference_context_snapshot #>>
               '{resolutionDecision,referenceWindow,state}' <> 'valid'
             or (route_row.reference_context_snapshot #>>
               '{resolutionDecision,referenceWindow,notAfter}')::timestamptz >=
                 expected_authority_at
           )
         )
       )
  );
exception when others then
  return false;
end;
$$;



--
-- Name: inbox_v2_tm_payload_exact_pin_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_payload_exact_pin_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if new.attachment_v2_file_id is not null and not exists (
    select 1
      from public.inbox_v2_file_objects file_row
      join public.inbox_v2_file_versions version_row
        on version_row.tenant_id = file_row.tenant_id
       and version_row.id = new.attachment_file_version_id
       and version_row.file_id = file_row.id
       and version_row.object_version_id = new.attachment_object_version_id
      join public.inbox_v2_file_object_versions object_version_row
        on object_version_row.tenant_id = version_row.tenant_id
       and object_version_row.id = version_row.object_version_id
      join public.inbox_v2_file_object_version_heads object_head_row
        on object_head_row.tenant_id = object_version_row.tenant_id
       and object_head_row.object_version_id = object_version_row.id
     where file_row.tenant_id = new.tenant_id
       and file_row.id = new.attachment_v2_file_id
       and file_row.revision = new.attachment_file_revision
       and file_row.state = 'ready'
       and file_row.current_file_version_id = version_row.id
       and file_row.current_object_version_id = version_row.object_version_id
       and object_head_row.state = 'ready'
  ) then
    raise exception using errcode = '23503',
      message = 'inbox_v2.timeline_payload_attachment_exact_pin_invalid';
  end if;

  if new.extension_payload_v2_file_id is not null and not exists (
    select 1
      from public.inbox_v2_file_objects file_row
      join public.inbox_v2_file_versions version_row
        on version_row.tenant_id = file_row.tenant_id
       and version_row.id = new.extension_payload_file_version_id
       and version_row.file_id = file_row.id
       and version_row.object_version_id =
         new.extension_payload_object_version_id
      join public.inbox_v2_file_object_versions object_version_row
        on object_version_row.tenant_id = version_row.tenant_id
       and object_version_row.id = version_row.object_version_id
      join public.inbox_v2_file_object_version_heads object_head_row
        on object_head_row.tenant_id = object_version_row.tenant_id
       and object_head_row.object_version_id = object_version_row.id
     where file_row.tenant_id = new.tenant_id
       and file_row.id = new.extension_payload_v2_file_id
       and file_row.revision = new.extension_payload_file_revision
       and file_row.state = 'ready'
       and file_row.current_file_version_id = version_row.id
       and file_row.current_object_version_id = version_row.object_version_id
       and object_head_row.state = 'ready'
  ) then
    raise exception using errcode = '23503',
      message = 'inbox_v2.timeline_payload_extension_exact_pin_invalid';
  end if;
  return null;
end;
$$;



--
-- Name: inbox_v2_tm_payload_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_payload_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    return old;
  end if;

  raise exception using
    errcode = '23514',
    message = format('inbox_v2.timeline_content_payload_immutable:%s', tg_table_name);
end;
$$;



--
-- Name: inbox_v2_tm_provider_fact_semantic_proof_valid(jsonb, text, text, text, text, text, text, bigint, text, text, bigint, text, text, timestamp with time zone, text, bigint, text, text, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_provider_fact_semantic_proof_valid(proof_detail jsonb, expected_tenant_id text, expected_normalized_event_id text, expected_external_reference_id text, expected_source_occurrence_id text, expected_source_account_id text, expected_source_thread_binding_id text, expected_binding_generation bigint, expected_adapter_contract_id text, expected_adapter_contract_version text, expected_adapter_declaration_revision bigint, expected_adapter_surface_id text, expected_adapter_loaded_by_trusted_service_id text, expected_adapter_loaded_at timestamp with time zone, expected_capability_id text, expected_capability_revision bigint, expected_semantic_id text, expected_actor_id text, expected_occurred_at timestamp with time zone, expected_recorded_at timestamp with time zone) RETURNS boolean
    LANGUAGE plpgsql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  return coalesce(
    public.inbox_v2_tm_json_family_valid(
      'provider_semantic_proof', proof_detail
    )
    and proof_detail #>> '{tenantId}' = expected_tenant_id
    and proof_detail #>> '{normalizedInboundEvent,tenantId}' =
      expected_tenant_id
    and proof_detail #>> '{normalizedInboundEvent,kind}' =
      'normalized_inbound_event'
    and proof_detail #>> '{normalizedInboundEvent,id}' =
      expected_normalized_event_id
    and (
      (expected_external_reference_id is null
        and expected_source_occurrence_id is null
        and proof_detail -> 'externalMessageReference' = 'null'::jsonb
        and proof_detail -> 'sourceOccurrence' = 'null'::jsonb)
      or (expected_external_reference_id is not null
        and expected_source_occurrence_id is not null
        and proof_detail #>> '{externalMessageReference,tenantId}' =
          expected_tenant_id
        and proof_detail #>> '{externalMessageReference,kind}' =
          'external_message_reference'
        and proof_detail #>> '{externalMessageReference,id}' =
          expected_external_reference_id
        and proof_detail #>> '{sourceOccurrence,tenantId}' =
          expected_tenant_id
        and proof_detail #>> '{sourceOccurrence,kind}' = 'source_occurrence'
        and proof_detail #>> '{sourceOccurrence,id}' =
          expected_source_occurrence_id)
    )
    and proof_detail #>> '{sourceAccount,tenantId}' = expected_tenant_id
    and proof_detail #>> '{sourceAccount,kind}' = 'source_account'
    and proof_detail #>> '{sourceAccount,id}' = expected_source_account_id
    and proof_detail #>> '{sourceThreadBinding,tenantId}' = expected_tenant_id
    and proof_detail #>> '{sourceThreadBinding,kind}' =
      'source_thread_binding'
    and proof_detail #>> '{sourceThreadBinding,id}' =
      expected_source_thread_binding_id
    and proof_detail #>> '{bindingGeneration}' =
      expected_binding_generation::text
    and proof_detail #>> '{adapterContract,contractId}' =
      expected_adapter_contract_id
    and proof_detail #>> '{adapterContract,contractVersion}' =
      expected_adapter_contract_version
    and proof_detail #>> '{adapterContract,declarationRevision}' =
      expected_adapter_declaration_revision::text
    and proof_detail #>> '{adapterContract,surfaceId}' =
      expected_adapter_surface_id
    and proof_detail #>> '{adapterContract,loadedByTrustedServiceId}' =
      expected_adapter_loaded_by_trusted_service_id
    and (proof_detail #>> '{adapterContract,loadedAt}')::timestamptz =
      expected_adapter_loaded_at
    and proof_detail #>> '{capabilityId}' = expected_capability_id
    and proof_detail #>> '{capabilityRevision}' =
      expected_capability_revision::text
    and proof_detail #>> '{semanticId}' = expected_semantic_id
    and proof_detail #>> '{semanticRevision}' = '1'
    and proof_detail #>> '{declaredByTrustedServiceId}' =
      expected_adapter_loaded_by_trusted_service_id
    and proof_detail #>> '{revision}' = '1'
    and (
      (expected_actor_id is null and proof_detail -> 'actor' = 'null'::jsonb)
      or (expected_actor_id is not null
        and proof_detail #>> '{actor,tenantId}' = expected_tenant_id
        and proof_detail #>> '{actor,kind}' = 'source_external_identity'
        and proof_detail #>> '{actor,id}' = expected_actor_id)
    )
    and (proof_detail #>> '{occurredAt}')::timestamptz =
      expected_occurred_at
    and (proof_detail #>> '{recordedAt}')::timestamptz =
      expected_recorded_at,
    false
  );
exception when others then
  return false;
end;
$$;



--
-- Name: inbox_v2_tm_provider_lifecycle_history_valid(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_provider_lifecycle_history_valid(expected_tenant_id text, expected_operation_id text) RETURNS boolean
    LANGUAGE plpgsql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  operation_row record;
  transition_row record;
  predecessor_row record;
  before_outcome text;
  before_outcome_retryable integer;
  before_outcome_reason_id text;
  before_delete_local_effect text;
  before_policy_decision_event_id text;
  before_policy_decision_revision bigint;
  before_policy_decided_at timestamptz;
  outcome_changed boolean;
  policy_changed boolean;
  proof_field_count integer;
begin
  select * into operation_row
    from public.inbox_v2_message_provider_lifecycle_operations
   where tenant_id = expected_tenant_id
     and id = expected_operation_id;
  if not found then
    return false;
  end if;

  for transition_row in
    select *
      from public.inbox_v2_message_provider_lifecycle_transitions
     where tenant_id = expected_tenant_id
       and operation_id = expected_operation_id
     order by resulting_revision
  loop
    if transition_row.resulting_revision > operation_row.revision then
      return false;
    end if;

    if transition_row.expected_revision = 1 then
      if transition_row.recorded_at < operation_row.created_at
         or transition_row.recorded_stream_position <=
           operation_row.created_stream_position then
        return false;
      end if;
      before_outcome := operation_row.initial_outcome::text;
      before_outcome_retryable := operation_row.initial_outcome_retryable;
      before_outcome_reason_id := operation_row.initial_outcome_reason_id;
      before_delete_local_effect :=
        operation_row.initial_delete_local_effect::text;
      before_policy_decision_event_id :=
        operation_row.initial_policy_decision_event_id;
      before_policy_decision_revision :=
        operation_row.initial_policy_decision_revision;
      before_policy_decided_at := operation_row.initial_policy_decided_at;
    else
      select * into predecessor_row
        from public.inbox_v2_message_provider_lifecycle_transitions
       where tenant_id = transition_row.tenant_id
         and operation_id = transition_row.operation_id
         and resulting_revision = transition_row.expected_revision;
      if not found then
        return false;
      end if;
      if transition_row.recorded_at < predecessor_row.recorded_at
         or transition_row.recorded_stream_position <=
           predecessor_row.recorded_stream_position then
        return false;
      end if;
      before_outcome := predecessor_row.outcome::text;
      before_outcome_retryable := predecessor_row.outcome_retryable;
      before_outcome_reason_id := predecessor_row.outcome_reason_id;
      before_delete_local_effect := predecessor_row.delete_local_effect::text;
      before_policy_decision_event_id :=
        predecessor_row.policy_decision_event_id;
      before_policy_decision_revision :=
        predecessor_row.policy_decision_revision;
      before_policy_decided_at := predecessor_row.policy_decided_at;
    end if;

    outcome_changed :=
      before_outcome is distinct from transition_row.outcome::text
      or before_outcome_retryable is distinct from
        transition_row.outcome_retryable
      or before_outcome_reason_id is distinct from
        transition_row.outcome_reason_id;
    policy_changed :=
      before_delete_local_effect is distinct from
        transition_row.delete_local_effect::text
      or before_policy_decision_event_id is distinct from
        transition_row.policy_decision_event_id
      or before_policy_decision_revision is distinct from
        transition_row.policy_decision_revision
      or before_policy_decided_at is distinct from
        transition_row.policy_decided_at;
    if not outcome_changed and not policy_changed then
      return false;
    end if;

    if outcome_changed then
      if operation_row.origin <> 'hulee_requested' then
        return false;
      end if;
      if not (
        (before_outcome = 'pending' and transition_row.outcome in (
          'accepted', 'confirmed', 'failed', 'unsupported', 'outcome_unknown'
        ))
        or (before_outcome = 'accepted' and transition_row.outcome in (
          'confirmed', 'failed', 'outcome_unknown'
        ))
        or (before_outcome = 'outcome_unknown' and
          transition_row.outcome in ('confirmed', 'failed'))
      ) then
        return false;
      end if;
    end if;

    if policy_changed and (
      before_delete_local_effect is null
      or before_delete_local_effect <> 'not_evaluated'
      or transition_row.delete_local_effect is null
    ) then
      return false;
    end if;

    proof_field_count := num_nonnulls(
      transition_row.result_token,
      transition_row.result_digest_sha256,
      transition_row.result_proof_outbound_route_id,
      transition_row.result_proof_capability_id,
      transition_row.result_proof_capability_revision,
      transition_row.result_proof_semantic_id,
      transition_row.result_proof_semantic_revision,
      transition_row.result_proof_state,
      transition_row.result_proof_declared_by_trusted_service_id,
      transition_row.result_proof_recorded_at,
      transition_row.result_proof_adapter_contract_detail,
      transition_row.result_proof_adapter_contract_detail_digest_sha256
    );
    if not outcome_changed then
      if proof_field_count <> 0 then
        return false;
      end if;
    elsif proof_field_count <> 12
      or operation_row.outbound_route_id is null
      or transition_row.result_proof_outbound_route_id <>
        operation_row.outbound_route_id
      or transition_row.result_proof_capability_id <>
        'core:message-' || operation_row.action::text
      or transition_row.result_proof_capability_revision <>
        operation_row.capability_revision
      or transition_row.result_proof_state <> transition_row.outcome::text
      or transition_row.result_proof_semantic_id <>
        'core:message.lifecycle.' || operation_row.action::text ||
          '.result.' || transition_row.outcome::text
      or transition_row.result_proof_declared_by_trusted_service_id <>
        operation_row.adapter_loaded_by_trusted_service_id
      or transition_row.result_proof_recorded_at <> transition_row.recorded_at
      or transition_row.result_proof_adapter_contract_detail #>>
        '{contractId}' <> operation_row.adapter_contract_id
      or transition_row.result_proof_adapter_contract_detail #>>
        '{contractVersion}' <> operation_row.adapter_contract_version
      or transition_row.result_proof_adapter_contract_detail #>>
        '{declarationRevision}' <>
          operation_row.adapter_declaration_revision::text
      or transition_row.result_proof_adapter_contract_detail #>>
        '{surfaceId}' <> operation_row.adapter_surface_id
      or transition_row.result_proof_adapter_contract_detail #>>
        '{loadedByTrustedServiceId}' <>
          operation_row.adapter_loaded_by_trusted_service_id
      or (transition_row.result_proof_adapter_contract_detail #>>
        '{loadedAt}')::timestamptz <> operation_row.adapter_loaded_at
    then
      return false;
    end if;
  end loop;
  return true;
exception when others then
  return false;
end;
$$;





--
-- Name: inbox_v2_provider_semantic_ordering_heads; Type: TABLE; Schema: public; Owner: <database-owner>
--

CREATE TABLE public.inbox_v2_provider_semantic_ordering_heads (
    tenant_id text NOT NULL,
    external_message_reference_id text NOT NULL,
    semantic_family_id text NOT NULL,
    source_account_id text NOT NULL,
    source_thread_binding_id text NOT NULL,
    binding_generation bigint NOT NULL,
    scope_token text NOT NULL,
    comparator_id text NOT NULL,
    comparator_revision bigint NOT NULL,
    "position" text NOT NULL,
    normalized_inbound_event_id text NOT NULL,
    proof_token text NOT NULL,
    revision bigint NOT NULL,
    head_detail jsonb NOT NULL,
    head_detail_digest_sha256 text NOT NULL,
    last_changed_stream_position bigint NOT NULL,
    created_at timestamp(3) with time zone NOT NULL,
    updated_at timestamp(3) with time zone NOT NULL,
    CONSTRAINT inbox_v2_provider_semantic_ordering_heads_clock_check CHECK ((isfinite(created_at) AND isfinite(updated_at) AND (updated_at >= created_at))),
    CONSTRAINT inbox_v2_provider_semantic_ordering_heads_detail_check CHECK ((((head_detail #>> '{tenantId}'::text[]) = tenant_id) AND ((head_detail #>> '{semanticFamilyId}'::text[]) = semantic_family_id) AND ((head_detail #>> '{externalMessageReference,tenantId}'::text[]) = tenant_id) AND ((head_detail #>> '{externalMessageReference,kind}'::text[]) = 'external_message_reference'::text) AND ((head_detail #>> '{externalMessageReference,id}'::text[]) = external_message_reference_id) AND ((head_detail #>> '{sourceAccount,tenantId}'::text[]) = tenant_id) AND ((head_detail #>> '{sourceAccount,kind}'::text[]) = 'source_account'::text) AND ((head_detail #>> '{sourceAccount,id}'::text[]) = source_account_id) AND ((head_detail #>> '{sourceThreadBinding,tenantId}'::text[]) = tenant_id) AND ((head_detail #>> '{sourceThreadBinding,kind}'::text[]) = 'source_thread_binding'::text) AND ((head_detail #>> '{sourceThreadBinding,id}'::text[]) = source_thread_binding_id) AND ((head_detail #>> '{bindingGeneration}'::text[]) = (binding_generation)::text) AND ((head_detail #>> '{scopeToken}'::text[]) = scope_token) AND ((head_detail #>> '{comparatorId}'::text[]) = comparator_id) AND ((head_detail #>> '{comparatorRevision}'::text[]) = (comparator_revision)::text) AND ((head_detail #>> '{position}'::text[]) = "position") AND ((head_detail #>> '{normalizedInboundEvent,tenantId}'::text[]) = tenant_id) AND ((head_detail #>> '{normalizedInboundEvent,kind}'::text[]) = 'normalized_inbound_event'::text) AND ((head_detail #>> '{normalizedInboundEvent,id}'::text[]) = normalized_inbound_event_id) AND ((head_detail #>> '{proofToken}'::text[]) = proof_token) AND ((head_detail #>> '{revision}'::text[]) = (revision)::text) AND (((head_detail #>> '{updatedAt}'::text[]))::timestamp with time zone = updated_at))),
    CONSTRAINT inbox_v2_provider_semantic_ordering_heads_values_check CHECK ((COALESCE(((char_length(semantic_family_id) <= 256) AND (((semantic_family_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(semantic_family_id, ':'::text, 2)) <= 160)) OR ((semantic_family_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(semantic_family_id, ':'::text, 2)) <= 80) AND (char_length(split_part(semantic_family_id, ':'::text, 3)) <= 160) AND (split_part(semantic_family_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text]))))), false) AND (binding_generation >= 1) AND COALESCE(((char_length(scope_token) >= 8) AND (char_length(scope_token) <= 256) AND (scope_token ~ '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'::text)), false) AND COALESCE(((char_length(comparator_id) <= 256) AND (((comparator_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(comparator_id, ':'::text, 2)) <= 160)) OR ((comparator_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(comparator_id, ':'::text, 2)) <= 80) AND (char_length(split_part(comparator_id, ':'::text, 3)) <= 160) AND (split_part(comparator_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text]))))), false) AND (comparator_revision >= 1) AND ("position" ~ '^(0|[1-9][0-9]*)$'::text) AND COALESCE(((char_length(proof_token) >= 8) AND (char_length(proof_token) <= 256) AND (proof_token ~ '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'::text)), false) AND (revision >= 1) AND COALESCE((head_detail_digest_sha256 ~ '^[a-f0-9]{64}$'::text), false) AND (last_changed_stream_position >= 1) AND (jsonb_typeof(head_detail) = 'object'::text) AND (pg_column_size(head_detail) <= 65536)))
);



--
-- Name: inbox_v2_tm_provider_semantic_consumer_count(public.inbox_v2_provider_semantic_ordering_heads, jsonb, boolean); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_provider_semantic_consumer_count(head_row public.inbox_v2_provider_semantic_ordering_heads, expected_before jsonb, require_before boolean) RETURNS bigint
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
  select
    (
      select count(*)
        from public.inbox_v2_message_provider_lifecycle_operations operation_row
       where operation_row.tenant_id = (head_row).tenant_id
         and operation_row.origin = 'provider_observed'
         and operation_row.external_message_reference_id =
           (head_row).external_message_reference_id
         and operation_row.source_account_id = (head_row).source_account_id
         and operation_row.source_thread_binding_id =
           (head_row).source_thread_binding_id
         and operation_row.binding_generation = (head_row).binding_generation
         and operation_row.provider_semantic_normalized_inbound_event_id =
           (head_row).normalized_inbound_event_id
         and operation_row.provider_semantic_proof_token =
           (head_row).proof_token
         and operation_row.provider_semantic_ordering_scope_token =
           (head_row).scope_token
         and operation_row.provider_semantic_ordering_position =
           (head_row).position
         and operation_row.provider_semantic_ordering_comparator_id =
           (head_row).comparator_id
         and operation_row.provider_semantic_ordering_comparator_revision =
           (head_row).comparator_revision
         and operation_row.semantic_ordering_commit_detail #>>
           '{semanticFamilyId}' = (head_row).semantic_family_id
         and operation_row.semantic_ordering_commit_detail #>>
           '{tenantId}' = (head_row).tenant_id
         and public.inbox_v2_tm_provider_semantic_proof_scope_valid(
           operation_row.provider_semantic_proof_detail,
           (head_row).tenant_id
         )
         and operation_row.semantic_ordering_commit_detail -> 'proof' =
           operation_row.provider_semantic_proof_detail
         and operation_row.semantic_ordering_commit_detail -> 'after' =
           (head_row).head_detail
         and (not require_before or
           operation_row.semantic_ordering_commit_detail -> 'before' =
             expected_before)
         and (operation_row.semantic_ordering_commit_detail #>>
           '{committedAt}')::timestamptz = (head_row).updated_at
         and operation_row.semantic_ordering_commit_digest_sha256 ~
           '^[a-f0-9]{64}$'
         and operation_row.provider_semantic_proof_digest_sha256 ~
           '^[a-f0-9]{64}$'
         and operation_row.created_stream_position =
           (head_row).last_changed_stream_position
    ) + (
      select count(*)
        from public.inbox_v2_message_provider_reaction_observations observation_row
        join public.inbox_v2_message_reaction_transitions transition_row
          on transition_row.tenant_id = observation_row.tenant_id
         and transition_row.id = observation_row.transition_id
        join public.inbox_v2_message_reactions reaction_row
          on reaction_row.tenant_id = transition_row.tenant_id
         and reaction_row.id = transition_row.reaction_id
        join public.inbox_v2_external_message_references reference_row
          on reference_row.tenant_id = transition_row.tenant_id
         and reference_row.id = transition_row.external_message_reference_id
         and reference_row.message_id = reaction_row.message_id
        join public.inbox_v2_action_attributions attribution_row
          on attribution_row.tenant_id = transition_row.tenant_id
         and attribution_row.id = transition_row.action_attribution_id
        join public.inbox_v2_source_occurrences occurrence_actor_row
          on occurrence_actor_row.tenant_id = observation_row.tenant_id
         and occurrence_actor_row.id = observation_row.source_occurrence_id
       where observation_row.tenant_id = (head_row).tenant_id
         and transition_row.mode = 'provider_observed'
         and transition_row.external_message_reference_id =
           (head_row).external_message_reference_id
         and transition_row.source_occurrence_id =
           observation_row.source_occurrence_id
         and transition_row.source_account_id = (head_row).source_account_id
         and transition_row.source_thread_binding_id =
           (head_row).source_thread_binding_id
         and transition_row.binding_generation =
           (head_row).binding_generation
         and transition_row.external_authority_detail #>>
           '{externalMessageReference,id}' =
             transition_row.external_message_reference_id
         and transition_row.external_authority_detail #>>
           '{externalMessageReference,tenantId}' = (head_row).tenant_id
         and transition_row.external_authority_detail #>>
           '{externalMessageReference,kind}' = 'external_message_reference'
         and transition_row.external_authority_detail #>>
           '{sourceOccurrence,id}' = transition_row.source_occurrence_id
         and transition_row.external_authority_detail #>>
           '{sourceOccurrence,tenantId}' = (head_row).tenant_id
         and transition_row.external_authority_detail #>>
           '{sourceOccurrence,kind}' = 'source_occurrence'
         and transition_row.external_authority_detail #>>
           '{sourceAccount,id}' = transition_row.source_account_id
         and transition_row.external_authority_detail #>>
           '{sourceAccount,tenantId}' = (head_row).tenant_id
         and transition_row.external_authority_detail #>>
           '{sourceAccount,kind}' = 'source_account'
         and transition_row.external_authority_detail #>>
           '{sourceThreadBinding,id}' =
             transition_row.source_thread_binding_id
         and transition_row.external_authority_detail #>>
           '{sourceThreadBinding,tenantId}' = (head_row).tenant_id
         and transition_row.external_authority_detail #>>
           '{sourceThreadBinding,kind}' = 'source_thread_binding'
         and transition_row.external_authority_detail #>>
           '{bindingGeneration}' = transition_row.binding_generation::text
         and transition_row.adapter_contract_id =
           observation_row.semantic_proof_detail #>>
             '{adapterContract,contractId}'
         and transition_row.adapter_contract_version =
           observation_row.semantic_proof_detail #>>
             '{adapterContract,contractVersion}'
         and transition_row.capability_id =
           observation_row.semantic_proof_detail #>> '{capabilityId}'
         and transition_row.capability_revision::text =
           observation_row.semantic_proof_detail #>> '{capabilityRevision}'
         and transition_row.external_authority_detail -> 'adapterContract' =
           observation_row.semantic_proof_detail -> 'adapterContract'
         and transition_row.external_authority_detail #>
           '{capabilityFence,adapterContract}' =
             observation_row.semantic_proof_detail -> 'adapterContract'
         and transition_row.external_authority_detail #>>
           '{capabilityFence,capabilityId}' = transition_row.capability_id
         and transition_row.external_authority_detail #>>
           '{capabilityFence,capabilityRevision}' =
             transition_row.capability_revision::text
         and transition_row.external_authority_detail #>>
           '{capabilityFence,decision}' = 'supported'
         and isfinite((transition_row.external_authority_detail #>>
           '{capabilityFence,evaluatedAt}')::timestamptz)
         and isfinite((transition_row.external_authority_detail #>>
           '{capabilityFence,notAfter}')::timestamptz)
         and (transition_row.external_authority_detail #>>
           '{capabilityFence,evaluatedAt}')::timestamptz <=
             transition_row.occurred_at
         and (transition_row.external_authority_detail #>>
           '{capabilityFence,notAfter}')::timestamptz >=
             transition_row.occurred_at
         and (observation_row.semantic_proof_detail #>>
           '{adapterContract,loadedAt}')::timestamptz <=
             transition_row.occurred_at
         and observation_row.semantic_proof_detail #>>
           '{declaredByTrustedServiceId}' =
             observation_row.semantic_proof_detail #>>
               '{adapterContract,loadedByTrustedServiceId}'
         and reaction_row.capability_kind = 'external'
         and reaction_row.capability_id = transition_row.capability_id
         and reaction_row.capability_revision =
           transition_row.capability_revision
         and reaction_row.adapter_contract_id =
           transition_row.adapter_contract_id
         and reaction_row.adapter_contract_version =
           transition_row.adapter_contract_version
         and reaction_row.capability_detail #>> '{kind}' = 'external'
         and reaction_row.capability_detail #>> '{capabilityId}' =
           transition_row.capability_id
         and reaction_row.capability_detail #>> '{capabilityRevision}' =
           transition_row.capability_revision::text
         and reaction_row.capability_detail #>> '{cardinality}' =
           reaction_row.cardinality::text
         and reaction_row.capability_detail -> 'adapterContract' =
           observation_row.semantic_proof_detail -> 'adapterContract'
         and transition_row.external_authority_detail -> 'outboundRoute' =
           'null'::jsonb
         and attribution_row.source_occurrence_id =
           observation_row.source_occurrence_id
         and attribution_row.conversation_id = reference_row.conversation_id
         and observation_row.normalized_inbound_event_id =
           (head_row).normalized_inbound_event_id
         and observation_row.ordering_position = (head_row).position
         and observation_row.semantic_proof_detail #>>
           '{normalizedInboundEvent,id}' =
             observation_row.normalized_inbound_event_id
         and observation_row.semantic_proof_detail #>>
           '{externalMessageReference,id}' =
             (head_row).external_message_reference_id
         and observation_row.semantic_proof_detail #>>
           '{sourceOccurrence,id}' = observation_row.source_occurrence_id
         and observation_row.semantic_proof_detail #>> '{semanticId}' =
           observation_row.semantic_id
         and observation_row.semantic_id =
           'core:message.reaction.' || transition_row.operation::text
         and observation_row.semantic_proof_detail #>> '{revision}' = '1'
         and observation_row.semantic_proof_detail #>> '{semanticRevision}'
           ~ '^[1-9][0-9]*$'
         and char_length(observation_row.semantic_proof_detail #>>
           '{semanticRevision}') <= 19
         and (
           char_length(observation_row.semantic_proof_detail #>>
             '{semanticRevision}') < 19
           or (observation_row.semantic_proof_detail #>>
             '{semanticRevision}') collate "C" <= '9223372036854775807'
         )
         and observation_row.semantic_proof_detail #>>
           '{ordering,position}' = observation_row.ordering_position
         and observation_row.semantic_proof_detail #>> '{sourceAccount,id}' =
           (head_row).source_account_id
         and observation_row.semantic_proof_detail #>>
           '{sourceThreadBinding,id}' = (head_row).source_thread_binding_id
         and observation_row.semantic_proof_detail #>> '{bindingGeneration}' =
           (head_row).binding_generation::text
         and observation_row.semantic_proof_detail #>> '{proofToken}' =
           (head_row).proof_token
         and observation_row.semantic_proof_detail #>> '{ordering,scopeToken}' =
           (head_row).scope_token
         and observation_row.semantic_proof_detail #>>
           '{ordering,comparatorId}' = (head_row).comparator_id
         and observation_row.semantic_proof_detail #>>
           '{ordering,comparatorRevision}' =
             (head_row).comparator_revision::text
         and observation_row.ordering_commit_detail #>>
           '{semanticFamilyId}' = (head_row).semantic_family_id
         and (head_row).semantic_family_id = 'core:message.reaction'
         and observation_row.ordering_commit_detail #>>
           '{tenantId}' = (head_row).tenant_id
         and public.inbox_v2_tm_provider_semantic_proof_scope_valid(
           observation_row.semantic_proof_detail,
           (head_row).tenant_id
         )
         and observation_row.ordering_commit_detail -> 'proof' =
           observation_row.semantic_proof_detail
         and observation_row.ordering_commit_detail -> 'after' =
           (head_row).head_detail
         and (not require_before or
           observation_row.ordering_commit_detail -> 'before' =
             expected_before)
         and (observation_row.ordering_commit_detail #>>
           '{committedAt}')::timestamptz = (head_row).updated_at
         and (observation_row.semantic_proof_detail #>>
           '{occurredAt}')::timestamptz = observation_row.observed_at
         and (observation_row.semantic_proof_detail #>>
           '{recordedAt}')::timestamptz = observation_row.recorded_at
         and transition_row.occurred_at = observation_row.observed_at
         and observation_row.recorded_at <= transition_row.recorded_at
         and transition_row.recorded_at = (head_row).updated_at
         and transition_row.after_state_kind =
           observation_row.normalized_state_kind
         and transition_row.value_kind = observation_row.normalized_value_kind
         and transition_row.unicode_value is not distinct from
           observation_row.normalized_unicode_value
         and transition_row.provider_reaction_kind_id is not distinct from
           observation_row.normalized_provider_reaction_kind_id
         and transition_row.provider_canonical_code is not distinct from
           observation_row.normalized_provider_canonical_code
         and transition_row.after_state_detail #>> '{kind}' =
           transition_row.after_state_kind::text
         and transition_row.after_state_detail #>> (
           case when transition_row.after_state_kind = 'active'
             then array['value', 'kind']
             else array['lastValue', 'kind']
           end
         ) = transition_row.value_kind::text
         and (
           (
             transition_row.value_kind = 'unicode'
             and transition_row.after_state_detail #>> (
               case when transition_row.after_state_kind = 'active'
                 then array['value', 'value']
                 else array['lastValue', 'value']
               end
             ) = transition_row.unicode_value
             and transition_row.provider_reaction_kind_id is null
             and transition_row.provider_canonical_code is null
           )
           or (
             transition_row.value_kind = 'provider_custom'
             and transition_row.unicode_value is null
             and transition_row.after_state_detail #>> (
               case when transition_row.after_state_kind = 'active'
                 then array['value', 'providerKindId']
                 else array['lastValue', 'providerKindId']
               end
             ) = transition_row.provider_reaction_kind_id
             and transition_row.after_state_detail #>> (
               case when transition_row.after_state_kind = 'active'
                 then array['value', 'canonicalCode']
                 else array['lastValue', 'canonicalCode']
               end
             ) = transition_row.provider_canonical_code
           )
         )
         and (
           transition_row.after_state_kind = 'active'
           or (transition_row.after_state_detail #>>
             '{clearedAt}')::timestamptz = transition_row.recorded_at
         )
         and (
           (
             coalesce(
               transition_row.before_state_kind = 'pending_external'
               or (
                 transition_row.before_state_kind = 'external_terminal'
                 and transition_row.before_state_detail #>> '{outcome}' =
                   'outcome_unknown'
               ),
               false
             )
             and (
               observation_row.semantic_proof_detail #>> '{actor,id}' is null
               or occurrence_actor_row.provider_actor_source_external_identity_id
                 is null
               or observation_row.semantic_proof_detail #>> '{actor,id}' =
                 occurrence_actor_row.provider_actor_source_external_identity_id
             )
             and (
               (
                 coalesce(
                   observation_row.semantic_proof_detail #>> '{actor,id}',
                   occurrence_actor_row.provider_actor_source_external_identity_id
                 ) is null
                 and observation_row.provider_actor_participant_id is null
                 and attribution_row.action_participant_id is null
               )
               or (
                 attribution_row.action_participant_id =
                   observation_row.provider_actor_participant_id
                 and exists (
                   select 1
                     from public.inbox_v2_conversation_participants participant_row
                    where participant_row.tenant_id =
                      observation_row.tenant_id
                      and participant_row.id =
                        observation_row.provider_actor_participant_id
                      and participant_row.conversation_id =
                        reference_row.conversation_id
                      and participant_row.subject_kind =
                        'source_external_identity'
                      and participant_row.subject_source_external_identity_id =
                        coalesce(
                          observation_row.semantic_proof_detail #>>
                            '{actor,id}',
                          occurrence_actor_row.provider_actor_source_external_identity_id
                        )
                 )
               )
             )
           )
           or (
             not coalesce(
               transition_row.before_state_kind = 'pending_external'
               or (
                 transition_row.before_state_kind = 'external_terminal'
                 and transition_row.before_state_detail #>> '{outcome}' =
                   'outcome_unknown'
               ),
               false
             )
             and (
               (
                 occurrence_actor_row.provider_actor_kind =
                   'source_external_identity'
                 and observation_row.semantic_proof_detail #>> '{actor,id}' =
                   occurrence_actor_row.provider_actor_source_external_identity_id
                 and attribution_row.action_participant_id =
                   observation_row.provider_actor_participant_id
                 and reaction_row.actor_kind = 'participant'
                 and reaction_row.actor_participant_id =
                   observation_row.provider_actor_participant_id
                 and exists (
                   select 1
                     from public.inbox_v2_conversation_participants participant_row
                    where participant_row.tenant_id =
                      observation_row.tenant_id
                      and participant_row.id =
                        observation_row.provider_actor_participant_id
                      and participant_row.conversation_id =
                        reference_row.conversation_id
                      and participant_row.subject_kind =
                        'source_external_identity'
                      and participant_row.subject_source_external_identity_id =
                        occurrence_actor_row.provider_actor_source_external_identity_id
                 )
               )
               or (
                 occurrence_actor_row.provider_actor_kind = 'provider_system'
                 and observation_row.semantic_proof_detail -> 'actor' =
                   'null'::jsonb
                 and observation_row.provider_actor_participant_id is null
                 and attribution_row.action_participant_id is null
                 and reaction_row.actor_kind = 'provider_system'
                 and reaction_row.actor_source_occurrence_id =
                   occurrence_actor_row.id
                 and reaction_row.provider_actor_kind_id =
                   occurrence_actor_row.provider_system_actor_kind_id
                 and reaction_row.provider_actor_subject =
                   occurrence_actor_row.provider_system_actor_subject
               )
               or (
                 occurrence_actor_row.provider_actor_kind is null
                 and observation_row.semantic_proof_detail -> 'actor' =
                   'null'::jsonb
                 and observation_row.provider_actor_participant_id is null
                 and attribution_row.action_participant_id is null
                 and reaction_row.actor_kind in (
                   'unattributed_source_observation', 'aggregate_only'
                 )
                 and reaction_row.actor_source_occurrence_id =
                   occurrence_actor_row.id
               )
             )
           )
         )
         and observation_row.ordering_proof_digest_sha256 ~
           '^[a-f0-9]{64}$'
         and observation_row.semantic_proof_digest_sha256 ~
           '^[a-f0-9]{64}$'
         and transition_row.recorded_stream_position =
           (head_row).last_changed_stream_position
         and exists (
           select 1
             from public.inbox_v2_source_occurrences occurrence_row
            where occurrence_row.tenant_id = observation_row.tenant_id
              and occurrence_row.id = observation_row.source_occurrence_id
              and occurrence_row.normalized_inbound_event_id =
                observation_row.normalized_inbound_event_id
              and occurrence_row.source_account_id =
                (head_row).source_account_id
              and occurrence_row.source_thread_binding_id =
                (head_row).source_thread_binding_id
              and occurrence_row.binding_generation =
                (head_row).binding_generation
              and occurrence_row.adapter_contract_id =
                observation_row.semantic_proof_detail #>>
                  '{adapterContract,contractId}'
              and occurrence_row.adapter_contract_version =
                observation_row.semantic_proof_detail #>>
                  '{adapterContract,contractVersion}'
              and occurrence_row.adapter_declaration_revision::text =
                observation_row.semantic_proof_detail #>>
                  '{adapterContract,declarationRevision}'
              and occurrence_row.adapter_surface_id =
                observation_row.semantic_proof_detail #>>
                  '{adapterContract,surfaceId}'
              and occurrence_row.adapter_loaded_by_trusted_service_id =
                observation_row.semantic_proof_detail #>>
                  '{adapterContract,loadedByTrustedServiceId}'
              and occurrence_row.adapter_loaded_at =
                (observation_row.semantic_proof_detail #>>
                  '{adapterContract,loadedAt}')::timestamptz
              and occurrence_row.capability_revision::text =
                observation_row.semantic_proof_detail #>>
                  '{capabilityRevision}'
              and occurrence_row.resolution_state = 'resolved'
              and occurrence_row.resolved_external_message_reference_id =
                (head_row).external_message_reference_id
         )
    );
$_$;



--
-- Name: inbox_v2_tm_provider_semantic_consumer_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_provider_semantic_consumer_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $_$
declare
  matching_head_count bigint;
  matching_consumer_count bigint;
  matching_total_consumer_count bigint;
  consumer_before jsonb;
  consumer_after jsonb;
  consumer_stream_position bigint;
begin
  if tg_table_name = 'inbox_v2_message_provider_lifecycle_operations' then
    if new.semantic_ordering_commit_detail is null then
      return new;
    end if;
    if not exists (
      select 1
        from public.inbox_v2_messages message_row
       where message_row.tenant_id = new.tenant_id
         and message_row.id = new.message_id
    ) then
      return new;
    end if;
    consumer_before := new.semantic_ordering_commit_detail -> 'before';
    consumer_after := new.semantic_ordering_commit_detail -> 'after';
    consumer_stream_position := new.created_stream_position;
    select count(*)
      into matching_head_count
      from public.inbox_v2_provider_semantic_ordering_heads head_row
     where head_row.tenant_id = new.tenant_id
       and head_row.external_message_reference_id =
         new.external_message_reference_id
       and head_row.semantic_family_id =
         new.semantic_ordering_commit_detail #>> '{semanticFamilyId}'
       and new.semantic_ordering_commit_detail #>> '{tenantId}' =
         head_row.tenant_id
       and public.inbox_v2_tm_provider_semantic_proof_scope_valid(
         new.provider_semantic_proof_detail,
         head_row.tenant_id
       )
       and head_row.source_account_id = new.source_account_id
       and head_row.source_thread_binding_id = new.source_thread_binding_id
       and head_row.binding_generation = new.binding_generation
       and head_row.normalized_inbound_event_id =
         new.provider_semantic_normalized_inbound_event_id
       and head_row.proof_token = new.provider_semantic_proof_token
       and head_row.scope_token =
         new.provider_semantic_ordering_scope_token
       and head_row.position = new.provider_semantic_ordering_position
       and head_row.comparator_id =
         new.provider_semantic_ordering_comparator_id
       and head_row.comparator_revision =
         new.provider_semantic_ordering_comparator_revision
       and head_row.head_detail =
         new.semantic_ordering_commit_detail -> 'after'
       and new.semantic_ordering_commit_detail -> 'proof' =
         new.provider_semantic_proof_detail
       and (new.semantic_ordering_commit_detail #>>
         '{committedAt}')::timestamptz = head_row.updated_at
       and new.semantic_ordering_commit_digest_sha256 ~ '^[a-f0-9]{64}$'
       and new.provider_semantic_proof_digest_sha256 ~ '^[a-f0-9]{64}$'
       and head_row.last_changed_stream_position =
         new.created_stream_position;
  elsif tg_table_name =
    'inbox_v2_message_provider_reaction_observations' then
    if not exists (
      select 1
        from public.inbox_v2_message_reaction_transitions transition_row
       where transition_row.tenant_id = new.tenant_id
         and transition_row.id = new.transition_id
    ) then
      return new;
    end if;
    consumer_before := new.ordering_commit_detail -> 'before';
    consumer_after := new.ordering_commit_detail -> 'after';
    select transition_row.recorded_stream_position
      into consumer_stream_position
      from public.inbox_v2_message_reaction_transitions transition_row
     where transition_row.tenant_id = new.tenant_id
       and transition_row.id = new.transition_id;
    select count(*)
      into matching_head_count
      from public.inbox_v2_provider_semantic_ordering_heads head_row
      join public.inbox_v2_message_reaction_transitions transition_row
        on transition_row.tenant_id = new.tenant_id
       and transition_row.id = new.transition_id
      join public.inbox_v2_message_reactions reaction_row
        on reaction_row.tenant_id = transition_row.tenant_id
       and reaction_row.id = transition_row.reaction_id
      join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = transition_row.tenant_id
       and reference_row.id = transition_row.external_message_reference_id
       and reference_row.message_id = reaction_row.message_id
      join public.inbox_v2_action_attributions attribution_row
        on attribution_row.tenant_id = transition_row.tenant_id
       and attribution_row.id = transition_row.action_attribution_id
      join public.inbox_v2_source_occurrences occurrence_actor_row
        on occurrence_actor_row.tenant_id = new.tenant_id
       and occurrence_actor_row.id = new.source_occurrence_id
     where head_row.tenant_id = new.tenant_id
       and transition_row.mode = 'provider_observed'
       and head_row.external_message_reference_id =
         new.semantic_proof_detail #>> '{externalMessageReference,id}'
       and transition_row.external_message_reference_id =
         head_row.external_message_reference_id
       and transition_row.source_occurrence_id = new.source_occurrence_id
       and transition_row.source_account_id = head_row.source_account_id
       and transition_row.source_thread_binding_id =
         head_row.source_thread_binding_id
       and transition_row.binding_generation = head_row.binding_generation
       and transition_row.external_authority_detail #>>
         '{externalMessageReference,id}' =
           transition_row.external_message_reference_id
       and transition_row.external_authority_detail #>>
         '{externalMessageReference,tenantId}' = head_row.tenant_id
       and transition_row.external_authority_detail #>>
         '{externalMessageReference,kind}' = 'external_message_reference'
       and transition_row.external_authority_detail #>>
         '{sourceOccurrence,id}' = transition_row.source_occurrence_id
       and transition_row.external_authority_detail #>>
         '{sourceOccurrence,tenantId}' = head_row.tenant_id
       and transition_row.external_authority_detail #>>
         '{sourceOccurrence,kind}' = 'source_occurrence'
       and transition_row.external_authority_detail #>>
         '{sourceAccount,id}' = transition_row.source_account_id
       and transition_row.external_authority_detail #>>
         '{sourceAccount,tenantId}' = head_row.tenant_id
       and transition_row.external_authority_detail #>>
         '{sourceAccount,kind}' = 'source_account'
       and transition_row.external_authority_detail #>>
         '{sourceThreadBinding,id}' =
           transition_row.source_thread_binding_id
       and transition_row.external_authority_detail #>>
         '{sourceThreadBinding,tenantId}' = head_row.tenant_id
       and transition_row.external_authority_detail #>>
         '{sourceThreadBinding,kind}' = 'source_thread_binding'
       and transition_row.external_authority_detail #>>
         '{bindingGeneration}' = transition_row.binding_generation::text
       and transition_row.adapter_contract_id =
         new.semantic_proof_detail #>> '{adapterContract,contractId}'
       and transition_row.adapter_contract_version =
         new.semantic_proof_detail #>> '{adapterContract,contractVersion}'
       and transition_row.capability_id =
         new.semantic_proof_detail #>> '{capabilityId}'
       and transition_row.capability_revision::text =
         new.semantic_proof_detail #>> '{capabilityRevision}'
       and transition_row.external_authority_detail -> 'adapterContract' =
         new.semantic_proof_detail -> 'adapterContract'
       and transition_row.external_authority_detail #>
         '{capabilityFence,adapterContract}' =
           new.semantic_proof_detail -> 'adapterContract'
       and transition_row.external_authority_detail #>>
         '{capabilityFence,capabilityId}' = transition_row.capability_id
       and transition_row.external_authority_detail #>>
         '{capabilityFence,capabilityRevision}' =
           transition_row.capability_revision::text
       and transition_row.external_authority_detail #>>
         '{capabilityFence,decision}' = 'supported'
       and isfinite((transition_row.external_authority_detail #>>
         '{capabilityFence,evaluatedAt}')::timestamptz)
       and isfinite((transition_row.external_authority_detail #>>
         '{capabilityFence,notAfter}')::timestamptz)
       and (transition_row.external_authority_detail #>>
         '{capabilityFence,evaluatedAt}')::timestamptz <=
           transition_row.occurred_at
       and (transition_row.external_authority_detail #>>
         '{capabilityFence,notAfter}')::timestamptz >=
           transition_row.occurred_at
       and (new.semantic_proof_detail #>>
         '{adapterContract,loadedAt}')::timestamptz <=
           transition_row.occurred_at
       and new.semantic_proof_detail #>> '{declaredByTrustedServiceId}' =
         new.semantic_proof_detail #>>
           '{adapterContract,loadedByTrustedServiceId}'
       and reaction_row.capability_kind = 'external'
       and reaction_row.capability_id = transition_row.capability_id
       and reaction_row.capability_revision = transition_row.capability_revision
       and reaction_row.adapter_contract_id = transition_row.adapter_contract_id
       and reaction_row.adapter_contract_version =
         transition_row.adapter_contract_version
       and reaction_row.capability_detail #>> '{kind}' = 'external'
       and reaction_row.capability_detail #>> '{capabilityId}' =
         transition_row.capability_id
       and reaction_row.capability_detail #>> '{capabilityRevision}' =
         transition_row.capability_revision::text
       and reaction_row.capability_detail #>> '{cardinality}' =
         reaction_row.cardinality::text
       and reaction_row.capability_detail -> 'adapterContract' =
         new.semantic_proof_detail -> 'adapterContract'
       and transition_row.external_authority_detail -> 'outboundRoute' =
         'null'::jsonb
       and attribution_row.source_occurrence_id = new.source_occurrence_id
       and attribution_row.conversation_id = reference_row.conversation_id
       and new.semantic_proof_detail #>> '{normalizedInboundEvent,id}' =
         new.normalized_inbound_event_id
       and new.semantic_proof_detail #>> '{sourceOccurrence,id}' =
         new.source_occurrence_id
       and new.semantic_proof_detail #>> '{semanticId}' = new.semantic_id
       and new.semantic_id =
         'core:message.reaction.' || transition_row.operation::text
       and new.semantic_proof_detail #>> '{revision}' = '1'
       and new.semantic_proof_detail #>> '{semanticRevision}' ~
         '^[1-9][0-9]*$'
       and char_length(new.semantic_proof_detail #>> '{semanticRevision}') <=
         19
       and (
         char_length(new.semantic_proof_detail #>> '{semanticRevision}') < 19
         or (new.semantic_proof_detail #>> '{semanticRevision}') collate "C" <=
           '9223372036854775807'
       )
       and new.semantic_proof_detail #>> '{ordering,position}' =
         new.ordering_position
       and head_row.semantic_family_id =
         new.ordering_commit_detail #>> '{semanticFamilyId}'
       and head_row.semantic_family_id = 'core:message.reaction'
       and new.ordering_commit_detail #>> '{tenantId}' = head_row.tenant_id
       and public.inbox_v2_tm_provider_semantic_proof_scope_valid(
         new.semantic_proof_detail,
         head_row.tenant_id
       )
       and head_row.source_account_id =
         new.semantic_proof_detail #>> '{sourceAccount,id}'
       and head_row.source_thread_binding_id =
         new.semantic_proof_detail #>> '{sourceThreadBinding,id}'
       and head_row.binding_generation::text =
         new.semantic_proof_detail #>> '{bindingGeneration}'
       and head_row.normalized_inbound_event_id =
         new.normalized_inbound_event_id
       and head_row.proof_token =
         new.semantic_proof_detail #>> '{proofToken}'
       and head_row.scope_token =
         new.semantic_proof_detail #>> '{ordering,scopeToken}'
       and head_row.position = new.ordering_position
       and head_row.comparator_id =
         new.semantic_proof_detail #>> '{ordering,comparatorId}'
       and head_row.comparator_revision::text =
         new.semantic_proof_detail #>> '{ordering,comparatorRevision}'
       and head_row.head_detail = new.ordering_commit_detail -> 'after'
       and new.ordering_commit_detail -> 'proof' = new.semantic_proof_detail
       and (new.ordering_commit_detail #>> '{committedAt}')::timestamptz =
         head_row.updated_at
       and (new.semantic_proof_detail #>> '{occurredAt}')::timestamptz =
         new.observed_at
       and (new.semantic_proof_detail #>> '{recordedAt}')::timestamptz =
         new.recorded_at
       and transition_row.occurred_at = new.observed_at
       and new.recorded_at <= transition_row.recorded_at
       and transition_row.recorded_at = head_row.updated_at
       and transition_row.after_state_kind = new.normalized_state_kind
       and transition_row.value_kind = new.normalized_value_kind
       and transition_row.unicode_value is not distinct from
         new.normalized_unicode_value
       and transition_row.provider_reaction_kind_id is not distinct from
         new.normalized_provider_reaction_kind_id
       and transition_row.provider_canonical_code is not distinct from
         new.normalized_provider_canonical_code
       and transition_row.after_state_detail #>> '{kind}' =
         transition_row.after_state_kind::text
       and transition_row.after_state_detail #>> (
         case when transition_row.after_state_kind = 'active'
           then array['value', 'kind']
           else array['lastValue', 'kind']
         end
       ) = transition_row.value_kind::text
       and (
         (
           transition_row.value_kind = 'unicode'
           and transition_row.after_state_detail #>> (
             case when transition_row.after_state_kind = 'active'
               then array['value', 'value']
               else array['lastValue', 'value']
             end
           ) = transition_row.unicode_value
           and transition_row.provider_reaction_kind_id is null
           and transition_row.provider_canonical_code is null
         )
         or (
           transition_row.value_kind = 'provider_custom'
           and transition_row.unicode_value is null
           and transition_row.after_state_detail #>> (
             case when transition_row.after_state_kind = 'active'
               then array['value', 'providerKindId']
               else array['lastValue', 'providerKindId']
             end
           ) = transition_row.provider_reaction_kind_id
           and transition_row.after_state_detail #>> (
             case when transition_row.after_state_kind = 'active'
               then array['value', 'canonicalCode']
               else array['lastValue', 'canonicalCode']
             end
           ) = transition_row.provider_canonical_code
         )
       )
       and (
         transition_row.after_state_kind = 'active'
         or (transition_row.after_state_detail #>>
           '{clearedAt}')::timestamptz = transition_row.recorded_at
       )
       and (
         (
           coalesce(
             transition_row.before_state_kind = 'pending_external'
             or (
               transition_row.before_state_kind = 'external_terminal'
               and transition_row.before_state_detail #>> '{outcome}' =
                 'outcome_unknown'
             ),
             false
           )
           and (
             new.semantic_proof_detail #>> '{actor,id}' is null
             or occurrence_actor_row.provider_actor_source_external_identity_id
               is null
             or new.semantic_proof_detail #>> '{actor,id}' =
               occurrence_actor_row.provider_actor_source_external_identity_id
           )
           and (
             (
               coalesce(
                 new.semantic_proof_detail #>> '{actor,id}',
                 occurrence_actor_row.provider_actor_source_external_identity_id
               ) is null
               and new.provider_actor_participant_id is null
               and attribution_row.action_participant_id is null
             )
             or (
               attribution_row.action_participant_id =
                 new.provider_actor_participant_id
               and exists (
                 select 1
                   from public.inbox_v2_conversation_participants participant_row
                  where participant_row.tenant_id = new.tenant_id
                    and participant_row.id =
                      new.provider_actor_participant_id
                    and participant_row.conversation_id =
                      reference_row.conversation_id
                    and participant_row.subject_kind =
                      'source_external_identity'
                    and participant_row.subject_source_external_identity_id =
                      coalesce(
                        new.semantic_proof_detail #>> '{actor,id}',
                        occurrence_actor_row.provider_actor_source_external_identity_id
                      )
               )
             )
           )
         )
         or (
           not coalesce(
             transition_row.before_state_kind = 'pending_external'
             or (
               transition_row.before_state_kind = 'external_terminal'
               and transition_row.before_state_detail #>> '{outcome}' =
                 'outcome_unknown'
             ),
             false
           )
           and (
             (
               occurrence_actor_row.provider_actor_kind =
                 'source_external_identity'
               and new.semantic_proof_detail #>> '{actor,id}' =
                 occurrence_actor_row.provider_actor_source_external_identity_id
               and attribution_row.action_participant_id =
                 new.provider_actor_participant_id
               and reaction_row.actor_kind = 'participant'
               and reaction_row.actor_participant_id =
                 new.provider_actor_participant_id
               and exists (
                 select 1
                   from public.inbox_v2_conversation_participants participant_row
                  where participant_row.tenant_id = new.tenant_id
                    and participant_row.id =
                      new.provider_actor_participant_id
                    and participant_row.conversation_id =
                      reference_row.conversation_id
                    and participant_row.subject_kind =
                      'source_external_identity'
                    and participant_row.subject_source_external_identity_id =
                      occurrence_actor_row.provider_actor_source_external_identity_id
               )
             )
             or (
               occurrence_actor_row.provider_actor_kind = 'provider_system'
               and new.semantic_proof_detail -> 'actor' = 'null'::jsonb
               and new.provider_actor_participant_id is null
               and attribution_row.action_participant_id is null
               and reaction_row.actor_kind = 'provider_system'
               and reaction_row.actor_source_occurrence_id =
                 occurrence_actor_row.id
               and reaction_row.provider_actor_kind_id =
                 occurrence_actor_row.provider_system_actor_kind_id
               and reaction_row.provider_actor_subject =
                 occurrence_actor_row.provider_system_actor_subject
             )
             or (
               occurrence_actor_row.provider_actor_kind is null
               and new.semantic_proof_detail -> 'actor' = 'null'::jsonb
               and new.provider_actor_participant_id is null
               and attribution_row.action_participant_id is null
               and reaction_row.actor_kind in (
                 'unattributed_source_observation', 'aggregate_only'
               )
               and reaction_row.actor_source_occurrence_id =
                 occurrence_actor_row.id
             )
           )
         )
       )
       and new.ordering_proof_digest_sha256 ~ '^[a-f0-9]{64}$'
       and new.semantic_proof_digest_sha256 ~ '^[a-f0-9]{64}$'
       and head_row.last_changed_stream_position =
         transition_row.recorded_stream_position
       and exists (
         select 1
           from public.inbox_v2_source_occurrences occurrence_row
          where occurrence_row.tenant_id = new.tenant_id
            and occurrence_row.id = new.source_occurrence_id
            and occurrence_row.normalized_inbound_event_id =
              new.normalized_inbound_event_id
            and occurrence_row.source_account_id = head_row.source_account_id
            and occurrence_row.source_thread_binding_id =
              head_row.source_thread_binding_id
            and occurrence_row.binding_generation =
              head_row.binding_generation
            and occurrence_row.adapter_contract_id =
              new.semantic_proof_detail #>> '{adapterContract,contractId}'
            and occurrence_row.adapter_contract_version =
              new.semantic_proof_detail #>> '{adapterContract,contractVersion}'
            and occurrence_row.adapter_declaration_revision::text =
              new.semantic_proof_detail #>>
                '{adapterContract,declarationRevision}'
            and occurrence_row.adapter_surface_id =
              new.semantic_proof_detail #>> '{adapterContract,surfaceId}'
            and occurrence_row.adapter_loaded_by_trusted_service_id =
              new.semantic_proof_detail #>>
                '{adapterContract,loadedByTrustedServiceId}'
            and occurrence_row.adapter_loaded_at =
              (new.semantic_proof_detail #>>
                '{adapterContract,loadedAt}')::timestamptz
            and occurrence_row.capability_revision::text =
              new.semantic_proof_detail #>> '{capabilityRevision}'
            and occurrence_row.resolution_state = 'resolved'
            and occurrence_row.resolved_external_message_reference_id =
              head_row.external_message_reference_id
       );
  else
    raise exception using errcode = '23514',
      message = 'inbox_v2.provider_semantic_ordering_consumer_table_invalid';
  end if;

  if matching_head_count <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.provider_semantic_ordering_consumer_head_invalid';
  end if;
  select
    public.inbox_v2_tm_provider_semantic_consumer_count(
      head_row, consumer_before, true
    ),
    public.inbox_v2_tm_provider_semantic_consumer_count(
      head_row, 'null'::jsonb, false
    )
    into matching_consumer_count, matching_total_consumer_count
    from public.inbox_v2_provider_semantic_ordering_heads head_row
   where head_row.tenant_id = new.tenant_id
     and head_row.head_detail = consumer_after
     and head_row.last_changed_stream_position = consumer_stream_position;
  if coalesce(matching_consumer_count, 0) <> 1
     or coalesce(matching_total_consumer_count, 0) <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.provider_semantic_ordering_consumer_count_invalid';
  end if;
  return new;
end;
$_$;



--
-- Name: inbox_v2_tm_provider_semantic_head_consumer_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_provider_semantic_head_consumer_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  matching_consumer_count bigint;
  matching_before_count bigint;
  expected_before jsonb;
begin
  if not exists (
    select 1
      from public.inbox_v2_external_message_references reference_row
     where reference_row.tenant_id = new.tenant_id
       and reference_row.id = new.external_message_reference_id
  ) then
    return new;
  end if;

  expected_before := case tg_op
    when 'INSERT' then 'null'::jsonb
    else old.head_detail
  end;
  matching_consumer_count :=
    public.inbox_v2_tm_provider_semantic_consumer_count(
      new, 'null'::jsonb, false
    );
  matching_before_count :=
    public.inbox_v2_tm_provider_semantic_consumer_count(
      new, expected_before, true
    );

  if matching_consumer_count <> 1 or matching_before_count <> 1 then
    raise exception using errcode = '23514',
      message = 'inbox_v2.provider_semantic_ordering_head_consumer_invalid';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_tm_provider_semantic_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_provider_semantic_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if pg_trigger_depth() > 1 then
      return old;
    end if;
    if not exists (
      select 1 from public.tenants tenant_row where tenant_row.id = old.tenant_id
    ) then
      return old;
    end if;
    raise exception using errcode = '23514',
      message = 'inbox_v2.provider_semantic_ordering_head_delete';
  end if;

  if tg_op = 'INSERT' then
    if new.revision <> 1 or new.created_at <> new.updated_at then
      raise exception using errcode = '23514',
        message = 'inbox_v2.provider_semantic_ordering_head_invalid_initial';
    end if;
    return new;
  end if;

  if row(
       new.tenant_id, new.external_message_reference_id,
       new.semantic_family_id, new.scope_token,
       new.comparator_id, new.comparator_revision,
       new.created_at
     ) is distinct from row(
       old.tenant_id, old.external_message_reference_id,
       old.semantic_family_id, old.scope_token,
       old.comparator_id, old.comparator_revision,
       old.created_at
     )
     or new.revision <> old.revision + 1
     or new.last_changed_stream_position <= old.last_changed_stream_position
     or new.updated_at < old.updated_at
     or char_length(new.position) < char_length(old.position)
     or (
       char_length(new.position) = char_length(old.position)
       and new.position collate "C" <= old.position collate "C"
     ) then
    raise exception using errcode = '23514',
      message = 'inbox_v2.provider_semantic_ordering_head_invalid_advance';
  end if;
  return new;
end;
$$;



--
-- Name: inbox_v2_tm_provider_semantic_proof_scope_valid(jsonb, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_provider_semantic_proof_scope_valid(proof_detail jsonb, expected_tenant_id text) RETURNS boolean
    LANGUAGE sql IMMUTABLE STRICT
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select
    proof_detail #>> '{tenantId}' = expected_tenant_id
    and proof_detail #>> '{normalizedInboundEvent,tenantId}' =
      expected_tenant_id
    and proof_detail #>> '{normalizedInboundEvent,kind}' =
      'normalized_inbound_event'
    and proof_detail #>> '{externalMessageReference,tenantId}' =
      expected_tenant_id
    and proof_detail #>> '{externalMessageReference,kind}' =
      'external_message_reference'
    and proof_detail #>> '{sourceOccurrence,tenantId}' =
      expected_tenant_id
    and proof_detail #>> '{sourceOccurrence,kind}' = 'source_occurrence'
    and proof_detail #>> '{sourceAccount,tenantId}' = expected_tenant_id
    and proof_detail #>> '{sourceAccount,kind}' = 'source_account'
    and proof_detail #>> '{sourceThreadBinding,tenantId}' =
      expected_tenant_id
    and proof_detail #>> '{sourceThreadBinding,kind}' =
      'source_thread_binding'
    and (
      proof_detail -> 'actor' = 'null'::jsonb
      or (
        proof_detail #>> '{actor,tenantId}' = expected_tenant_id
        and proof_detail #>> '{actor,kind}' = 'source_external_identity'
      )
    );
$$;



--
-- Name: inbox_v2_tm_reaction_attribution_row_valid(text, text, jsonb, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_reaction_attribution_row_valid(expected_tenant_id text, expected_attribution_id text, attribution_detail jsonb, expected_created_at timestamp with time zone) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select exists (
    select 1
      from public.inbox_v2_action_attributions attribution_row
     where attribution_row.tenant_id = expected_tenant_id
       and attribution_row.id = expected_attribution_id
       and attribution_row.created_at = expected_created_at
       and (
         (
           attribution_detail -> 'actionParticipant' = 'null'::jsonb
           and attribution_row.action_participant_id is null
         )
         or (
           attribution_detail #>> '{actionParticipant,tenantId}' =
             expected_tenant_id
           and attribution_detail #>> '{actionParticipant,kind}' =
             'conversation_participant'
           and attribution_detail #>> '{actionParticipant,id}' =
             attribution_row.action_participant_id
         )
       )
       and (
         (
           attribution_detail -> 'appActor' = 'null'::jsonb
           and num_nonnulls(
             attribution_row.app_actor_kind,
             attribution_row.app_actor_employee_id,
             attribution_row.app_authorization_epoch,
             attribution_row.app_trusted_service_id
           ) = 0
         )
         or (
           attribution_detail #>> '{appActor,kind}' = 'employee'
           and attribution_detail #>> '{appActor,employee,tenantId}' =
             expected_tenant_id
           and attribution_detail #>> '{appActor,employee,kind}' = 'employee'
           and attribution_row.app_actor_kind = 'employee'
           and attribution_detail #>> '{appActor,employee,id}' =
             attribution_row.app_actor_employee_id
           and attribution_detail #>> '{appActor,authorizationEpoch}' =
             attribution_row.app_authorization_epoch
           and attribution_row.app_trusted_service_id is null
         )
         or (
           attribution_detail #>> '{appActor,kind}' = 'trusted_service'
           and attribution_row.app_actor_kind = 'trusted_service'
           and attribution_detail #>> '{appActor,trustedServiceId}' =
             attribution_row.app_trusted_service_id
           and attribution_row.app_actor_employee_id is null
           and attribution_row.app_authorization_epoch is null
         )
       )
       and (
         (
           attribution_detail -> 'sourceOccurrence' = 'null'::jsonb
           and attribution_row.source_occurrence_id is null
         )
         or (
           attribution_detail #>> '{sourceOccurrence,tenantId}' =
             expected_tenant_id
           and attribution_detail #>> '{sourceOccurrence,kind}' =
             'source_occurrence'
           and attribution_detail #>> '{sourceOccurrence,id}' =
             attribution_row.source_occurrence_id
         )
       )
       and (
         (
           attribution_detail -> 'automationCausation' = 'null'::jsonb
           and num_nonnulls(
             attribution_row.automation_kind,
             attribution_row.automation_cause_event_id,
             attribution_row.automation_correlation_id,
             attribution_row.automation_caused_at,
             attribution_row.automation_initiating_employee_id,
             attribution_row.automation_initiating_authorization_epoch
           ) = 0
         )
         or (
           attribution_detail #>> '{automationCausation,kind}' =
             'system_event'
           and attribution_row.automation_kind = 'system_event'
           and attribution_detail #>>
             '{automationCausation,causeEvent,tenantId}' = expected_tenant_id
           and attribution_detail #>>
             '{automationCausation,causeEvent,kind}' = 'event'
           and attribution_detail #>>
             '{automationCausation,causeEvent,id}' =
               attribution_row.automation_cause_event_id
           and attribution_detail #>>
             '{automationCausation,correlationId}' =
               attribution_row.automation_correlation_id
           and (attribution_detail #>>
             '{automationCausation,causedAt}')::timestamptz =
               attribution_row.automation_caused_at
           and attribution_row.automation_initiating_employee_id is null
           and attribution_row.automation_initiating_authorization_epoch is null
         )
         or (
           attribution_detail #>> '{automationCausation,kind}' =
             'employee_command'
           and attribution_row.automation_kind = 'employee_command'
           and attribution_detail #>>
             '{automationCausation,causeEvent,tenantId}' = expected_tenant_id
           and attribution_detail #>>
             '{automationCausation,causeEvent,kind}' = 'event'
           and attribution_detail #>>
             '{automationCausation,causeEvent,id}' =
               attribution_row.automation_cause_event_id
           and attribution_detail #>>
             '{automationCausation,correlationId}' =
               attribution_row.automation_correlation_id
           and (attribution_detail #>>
             '{automationCausation,causedAt}')::timestamptz =
               attribution_row.automation_caused_at
           and attribution_detail #>>
             '{automationCausation,initiatingActor,kind}' = 'employee'
           and attribution_detail #>>
             '{automationCausation,initiatingActor,employee,tenantId}' =
               expected_tenant_id
           and attribution_detail #>>
             '{automationCausation,initiatingActor,employee,kind}' = 'employee'
           and attribution_detail #>>
             '{automationCausation,initiatingActor,employee,id}' =
               attribution_row.automation_initiating_employee_id
           and attribution_detail #>>
             '{automationCausation,initiatingActor,authorizationEpoch}' =
               attribution_row.automation_initiating_authorization_epoch
         )
       )
  );
$$;



--
-- Name: inbox_v2_tm_reaction_authority_flat_valid(jsonb, text, text, text, text, text, bigint, text, text, text, text, bigint, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_reaction_authority_flat_valid(authority_detail jsonb, expected_tenant_id text, expected_external_message_reference_id text, expected_source_occurrence_id text, expected_source_account_id text, expected_source_thread_binding_id text, expected_binding_generation bigint, expected_outbound_route_id text, expected_adapter_contract_id text, expected_adapter_contract_version text, expected_capability_id text, expected_capability_revision bigint, expected_occurred_at timestamp with time zone) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  return
    authority_detail #>> '{externalMessageReference,tenantId}' =
      expected_tenant_id
    and authority_detail #>> '{externalMessageReference,kind}' =
      'external_message_reference'
    and authority_detail #>> '{externalMessageReference,id}' =
      expected_external_message_reference_id
    and authority_detail #>> '{sourceOccurrence,tenantId}' =
      expected_tenant_id
    and authority_detail #>> '{sourceOccurrence,kind}' = 'source_occurrence'
    and authority_detail #>> '{sourceOccurrence,id}' =
      expected_source_occurrence_id
    and authority_detail #>> '{sourceAccount,tenantId}' = expected_tenant_id
    and authority_detail #>> '{sourceAccount,kind}' = 'source_account'
    and authority_detail #>> '{sourceAccount,id}' = expected_source_account_id
    and authority_detail #>> '{sourceThreadBinding,tenantId}' =
      expected_tenant_id
    and authority_detail #>> '{sourceThreadBinding,kind}' =
      'source_thread_binding'
    and authority_detail #>> '{sourceThreadBinding,id}' =
      expected_source_thread_binding_id
    and authority_detail #>> '{bindingGeneration}' =
      expected_binding_generation::text
    and (
      (
        expected_outbound_route_id is null
        and authority_detail -> 'outboundRoute' = 'null'::jsonb
      )
      or (
        expected_outbound_route_id is not null
        and authority_detail #>> '{outboundRoute,tenantId}' =
          expected_tenant_id
        and authority_detail #>> '{outboundRoute,kind}' = 'outbound_route'
        and authority_detail #>> '{outboundRoute,id}' =
          expected_outbound_route_id
      )
    )
    and authority_detail #>> '{adapterContract,contractId}' =
      expected_adapter_contract_id
    and authority_detail #>> '{adapterContract,contractVersion}' =
      expected_adapter_contract_version
    and authority_detail -> 'adapterContract' =
      authority_detail #> '{capabilityFence,adapterContract}'
    and authority_detail #>> '{capabilityFence,capabilityId}' =
      expected_capability_id
    and authority_detail #>> '{capabilityFence,capabilityRevision}' =
      expected_capability_revision::text
    and authority_detail #>> '{capabilityFence,decision}' = 'supported'
    and isfinite((authority_detail #>>
      '{adapterContract,loadedAt}')::timestamptz)
    and (authority_detail #>> '{adapterContract,loadedAt}')::timestamptz <=
      expected_occurred_at
    and isfinite((authority_detail #>>
      '{capabilityFence,evaluatedAt}')::timestamptz)
    and isfinite((authority_detail #>>
      '{capabilityFence,notAfter}')::timestamptz)
    and (authority_detail #>>
      '{capabilityFence,evaluatedAt}')::timestamptz <= expected_occurred_at
    and (authority_detail #>>
      '{capabilityFence,notAfter}')::timestamptz >= expected_occurred_at;
exception when others then
  return false;
end;
$$;



--
-- Name: inbox_v2_tm_reaction_transition_state_valid(jsonb, jsonb, text, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_reaction_transition_state_valid(before_state_detail jsonb, after_state_detail jsonb, transition_mode text, transition_operation text, transition_recorded_at timestamp with time zone) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  before_kind text := before_state_detail #>> '{kind}';
  after_kind text := after_state_detail #>> '{kind}';
  before_confirmed jsonb;
  after_desired jsonb;
  confirming_request boolean;
begin
  before_confirmed := case
    when before_state_detail is null then 'null'::jsonb
    when before_kind = 'pending_external' then
      before_state_detail -> 'confirmedBefore'
    when before_kind = 'external_terminal' then
      before_state_detail -> 'confirmedState'
    else before_state_detail
  end;

  after_desired := case
    when after_kind = 'active' then jsonb_build_object(
      'kind', 'active', 'value', after_state_detail -> 'value'
    )
    when after_kind = 'cleared' then jsonb_build_object(
      'kind', 'cleared', 'lastValue', after_state_detail -> 'lastValue'
    )
    when after_kind in ('pending_external', 'external_terminal') then
      after_state_detail -> 'desired'
    else null
  end;
  if after_desired is null then
    return false;
  end if;

  if transition_mode = 'provider_result' then
    return coalesce(before_kind = 'pending_external'
      and after_kind = 'external_terminal'
      and before_state_detail #>> '{operation}' = transition_operation
      and after_state_detail #>> '{operation}' = transition_operation
      and after_state_detail -> 'desired' =
        before_state_detail -> 'desired'
      and after_state_detail -> 'confirmedState' =
        before_state_detail -> 'confirmedBefore'
      and after_state_detail -> 'outboundRoute' =
        before_state_detail -> 'outboundRoute'
      and after_state_detail -> 'requestTransition' =
        before_state_detail -> 'requestTransition'
      and (after_state_detail #>> '{resolvedAt}')::timestamptz =
        transition_recorded_at, false);
  end if;

  if transition_mode = 'external_request'
     and (
       after_kind <> 'pending_external'
       or after_state_detail -> 'confirmedBefore' is distinct from
         before_confirmed
     ) then
    return false;
  end if;

  confirming_request := transition_mode = 'provider_observed'
    and (
      before_kind = 'pending_external'
      or (
        before_kind = 'external_terminal'
        and before_state_detail #>> '{outcome}' = 'outcome_unknown'
      )
    );
  if confirming_request then
    return coalesce(
      before_state_detail #>> '{operation}' = transition_operation
        and before_state_detail -> 'desired' = after_desired,
      false
    );
  end if;

  if transition_operation = 'set' then
    return coalesce((
        before_confirmed = 'null'::jsonb
        or before_confirmed #>> '{kind}' = 'cleared'
      )
      and after_desired #>> '{kind}' = 'active', false);
  end if;
  if transition_operation = 'replace' then
    return coalesce(before_confirmed #>> '{kind}' = 'active'
      and after_desired #>> '{kind}' = 'active'
      and before_confirmed -> 'value' is distinct from
        after_desired -> 'value', false);
  end if;
  if transition_operation = 'clear' then
    return coalesce(before_confirmed #>> '{kind}' = 'active'
      and after_desired #>> '{kind}' = 'cleared'
      and before_confirmed -> 'value' = after_desired -> 'lastValue', false);
  end if;
  return false;
exception when others then
  return false;
end;
$$;



--
-- Name: inbox_v2_tm_reaction_value_flat_valid(jsonb, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_reaction_value_flat_valid(state_detail jsonb, expected_state_kind text, expected_value_kind text, expected_unicode_value text, expected_provider_reaction_kind_id text, expected_provider_canonical_code text) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  desired_detail jsonb;
  value_detail jsonb;
begin
  if state_detail #>> '{kind}' is distinct from expected_state_kind then
    return false;
  end if;

  desired_detail := case expected_state_kind
    when 'active' then state_detail
    when 'cleared' then state_detail
    when 'pending_external' then state_detail -> 'desired'
    when 'external_terminal' then state_detail -> 'desired'
    else null
  end;
  if desired_detail is null then
    return false;
  end if;

  value_detail := case desired_detail #>> '{kind}'
    when 'active' then desired_detail -> 'value'
    when 'cleared' then desired_detail -> 'lastValue'
    else null
  end;
  if value_detail is null
     or value_detail #>> '{kind}' is distinct from expected_value_kind then
    return false;
  end if;

  if expected_value_kind = 'unicode' then
    return value_detail #>> '{value}' is not distinct from
        expected_unicode_value
      and expected_provider_reaction_kind_id is null
      and expected_provider_canonical_code is null;
  end if;
  if expected_value_kind = 'provider_custom' then
    return expected_unicode_value is null
      and value_detail #>> '{providerKindId}' is not distinct from
        expected_provider_reaction_kind_id
      and value_detail #>> '{canonicalCode}' is not distinct from
        expected_provider_canonical_code;
  end if;
  return false;
end;
$$;



--
-- Name: inbox_v2_tm_staff_note_history_valid(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_staff_note_history_valid(checked_tenant_id text, checked_staff_note_id text) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select exists (
    select 1
      from public.inbox_v2_staff_notes note_row
      join public.inbox_v2_staff_note_revisions latest_row
        on latest_row.tenant_id = note_row.tenant_id
       and latest_row.staff_note_id = note_row.id
       and latest_row.timeline_item_id = note_row.timeline_item_id
       and latest_row.staff_note_revision = note_row.revision
       and latest_row.recorded_stream_position =
         note_row.last_changed_stream_position
      join public.inbox_v2_timeline_items timeline_row
        on timeline_row.tenant_id = note_row.tenant_id
       and timeline_row.id = note_row.timeline_item_id
       and timeline_row.conversation_id = note_row.conversation_id
       and timeline_row.subject_kind = 'staff_note'
       and timeline_row.subject_id = note_row.id
       and timeline_row.revision = note_row.revision
       and timeline_row.last_changed_stream_position =
         note_row.last_changed_stream_position
       and timeline_row.updated_at = latest_row.recorded_at
      join public.inbox_v2_action_attributions creation_attribution_row
        on creation_attribution_row.tenant_id = note_row.tenant_id
       and creation_attribution_row.id = note_row.creation_attribution_id
       and creation_attribution_row.conversation_id = note_row.conversation_id
      where note_row.tenant_id = checked_tenant_id
        and note_row.id = checked_staff_note_id
        and timeline_row.created_at = note_row.created_at
        and note_row.updated_at = latest_row.recorded_at
       and note_row.content_id = latest_row.after_content_id
       and note_row.content_revision = latest_row.after_content_revision
       and note_row.content_state = latest_row.after_content_state
       and (
         select count(*) = note_row.revision
            and min(history_row.staff_note_revision) = 1
            and max(history_row.staff_note_revision) = note_row.revision
           from public.inbox_v2_staff_note_revisions history_row
          where history_row.tenant_id = note_row.tenant_id
            and history_row.staff_note_id = note_row.id
       )
       and exists (
         select 1
           from public.inbox_v2_staff_note_revisions first_row
           join public.inbox_v2_action_attributions creation_attribution_row
             on creation_attribution_row.tenant_id = first_row.tenant_id
            and creation_attribution_row.id = first_row.action_attribution_id
            and creation_attribution_row.conversation_id = note_row.conversation_id
          where first_row.tenant_id = note_row.tenant_id
            and first_row.staff_note_id = note_row.id
            and first_row.timeline_item_id = note_row.timeline_item_id
            and first_row.staff_note_revision = 1
            and first_row.expected_previous_revision is null
            and first_row.change_kind = 'created'
            and first_row.before_content_id is null
            and first_row.before_content_revision is null
            and first_row.before_content_state is null
            and first_row.after_content_id = note_row.content_id
            and first_row.after_content_revision = 1
            and first_row.after_content_state = 'available'
            and first_row.action_attribution_id = note_row.creation_attribution_id
            and creation_attribution_row.action_participant_id =
              note_row.author_participant_id
            and first_row.occurred_at = timeline_row.occurred_at
            and first_row.recorded_at = note_row.created_at
       )
       and not exists (
         select 1
           from public.inbox_v2_staff_note_revisions history_row
           join public.inbox_v2_action_attributions attribution_row
             on attribution_row.tenant_id = history_row.tenant_id
            and attribution_row.id = history_row.action_attribution_id
           left join public.inbox_v2_staff_note_revisions predecessor_row
             on predecessor_row.tenant_id = history_row.tenant_id
            and predecessor_row.staff_note_id = history_row.staff_note_id
            and predecessor_row.staff_note_revision =
              history_row.staff_note_revision - 1
          where history_row.tenant_id = note_row.tenant_id
            and history_row.staff_note_id = note_row.id
            and (
              history_row.timeline_item_id <> note_row.timeline_item_id
              or not public.inbox_v2_tm_action_attribution_valid(
                history_row.tenant_id,
                history_row.action_attribution_id,
                note_row.conversation_id,
                false
              )
              or attribution_row.created_at <> history_row.recorded_at
              or (history_row.staff_note_revision > 1 and (
                predecessor_row.id is null
                or history_row.expected_previous_revision <>
                  predecessor_row.staff_note_revision
                or predecessor_row.after_content_state <> 'available'
                or predecessor_row.recorded_at > history_row.recorded_at
                or predecessor_row.recorded_at > history_row.occurred_at
                or predecessor_row.recorded_stream_position >=
                  history_row.recorded_stream_position
                or history_row.before_content_id <>
                  predecessor_row.after_content_id
                or history_row.before_content_revision <>
                  predecessor_row.after_content_revision
                or history_row.before_content_state <>
                  predecessor_row.after_content_state
              ))
              or (history_row.change_kind <> 'created' and not (
                history_row.before_content_state = 'available'
                and history_row.after_content_id =
                  history_row.before_content_id
                and history_row.after_content_revision =
                  history_row.before_content_revision + 1
                and history_row.after_content_revision =
                  history_row.staff_note_revision
                and history_row.after_content_state = case history_row.change_kind
                  when 'privacy_erasure_tombstone' then
                    'privacy_erased'::public.inbox_v2_timeline_content_state
                  when 'retention_purge_tombstone' then
                    'retention_purged'::public.inbox_v2_timeline_content_state
                  else 'available'::public.inbox_v2_timeline_content_state
                end
              ))
              or not exists (
                select 1
                  from public.inbox_v2_timeline_content_revisions content_revision_row
                 where content_revision_row.tenant_id = history_row.tenant_id
                   and content_revision_row.content_id =
                     history_row.after_content_id
                   and content_revision_row.revision =
                     history_row.after_content_revision
                    and content_revision_row.state =
                      history_row.after_content_state
                    and content_revision_row.recorded_stream_position =
                      history_row.recorded_stream_position
                    and content_revision_row.recorded_at = history_row.recorded_at
                    and (
                      history_row.staff_note_revision = 1
                      or content_revision_row.occurred_at =
                        history_row.recorded_at
                    )
                    and content_revision_row.transition_kind =
                      case history_row.change_kind
                        when 'created' then
                          'created'::public.inbox_v2_timeline_content_transition_kind
                        when 'edited' then
                         'edit'::public.inbox_v2_timeline_content_transition_kind
                       when 'attachment_materialized' then
                         'attachment_materialization'::public.inbox_v2_timeline_content_transition_kind
                       when 'privacy_erasure_tombstone' then
                         'privacy_erasure'::public.inbox_v2_timeline_content_transition_kind
                       when 'retention_purge_tombstone' then
                         'retention_purge'::public.inbox_v2_timeline_content_transition_kind
                     end
              )
              or (history_row.change_kind not in ('created', 'edited')
                and attribution_row.app_actor_kind is distinct from
                  'trusted_service')
              or (attribution_row.app_actor_kind = 'trusted_service'
                and attribution_row.action_participant_id is not null
                and not (
                  attribution_row.action_participant_id =
                    note_row.author_participant_id
                  and creation_attribution_row.app_actor_kind =
                    'trusted_service'
                  and creation_attribution_row.app_trusted_service_id =
                    attribution_row.app_trusted_service_id
                ))
            )
       )
  );
$$;



--
-- Name: inbox_v2_tm_transport_occurrence_link_valid(text, text); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_tm_transport_occurrence_link_valid(checked_tenant_id text, checked_link_id text) RETURNS boolean
    LANGUAGE sql STABLE
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
  select exists (
    select 1
      from public.inbox_v2_message_transport_links link_row
      join public.inbox_v2_messages message_row
        on message_row.tenant_id = link_row.tenant_id
       and message_row.id = link_row.message_id
      join public.inbox_v2_source_occurrences occurrence_row
        on occurrence_row.tenant_id = link_row.tenant_id
       and occurrence_row.id = link_row.source_occurrence_id
       and occurrence_row.conversation_id = message_row.conversation_id
       and occurrence_row.resolution_state = 'resolved'
       and occurrence_row.resolved_external_message_reference_id =
         link_row.external_message_reference_id
      join public.inbox_v2_external_message_references reference_row
        on reference_row.tenant_id = link_row.tenant_id
       and reference_row.id = link_row.external_message_reference_id
       and reference_row.message_id = link_row.message_id
       and reference_row.conversation_id = message_row.conversation_id
       and reference_row.timeline_item_id = message_row.timeline_item_id
       and reference_row.external_thread_id = occurrence_row.external_thread_id
       and reference_row.message_key_digest_sha256 =
         occurrence_row.message_key_digest_sha256
      join public.inbox_v2_external_threads thread_row
        on thread_row.tenant_id = reference_row.tenant_id
       and thread_row.id = reference_row.external_thread_id
       and thread_row.conversation_id = message_row.conversation_id
      left join public.inbox_v2_outbound_routes route_row
        on route_row.tenant_id = message_row.tenant_id
       and route_row.id = message_row.origin_outbound_route_id
      left join public.inbox_v2_source_occurrences origin_occurrence_row
        on origin_occurrence_row.tenant_id = message_row.tenant_id
       and origin_occurrence_row.id = message_row.origin_source_occurrence_id
     where link_row.tenant_id = checked_tenant_id
       and link_row.id = checked_link_id
       and link_row.revision = 1
       and link_row.linked_at >= message_row.created_at
       and (
         (message_row.origin_kind = 'source_originated'
           and reference_row.created_at = message_row.created_at
           and origin_occurrence_row.resolution_state = 'resolved'
           and origin_occurrence_row.resolved_external_message_reference_id =
             reference_row.id
           and origin_occurrence_row.external_thread_id = reference_row.external_thread_id
           and origin_occurrence_row.conversation_id = message_row.conversation_id
           and origin_occurrence_row.direction::text =
             message_row.origin_source_direction::text
           and origin_occurrence_row.origin_kind not in (
             'provider_echo', 'provider_response'
           )
           and origin_occurrence_row.provider_actor_kind =
             'source_external_identity'
           and origin_occurrence_row.message_key_digest_sha256 =
             reference_row.message_key_digest_sha256
           and (
             (occurrence_row.id = origin_occurrence_row.id
               and link_row.resulting_head_revision = 1
               and link_row.linked_at = message_row.created_at
               and link_row.role = case message_row.origin_source_direction
                 when 'inbound' then 'origin'::public.inbox_v2_message_transport_link_role
                 when 'outbound' then 'native_outbound'::public.inbox_v2_message_transport_link_role
               end)
             or (occurrence_row.id <> origin_occurrence_row.id
               and (
                 (message_row.origin_source_direction = 'inbound'
                   and link_row.role = 'additional_artifact'
                   and occurrence_row.direction = 'inbound'
                   and occurrence_row.origin_kind not in (
                     'provider_echo', 'provider_response'
                   )
                   and occurrence_row.provider_actor_kind =
                     'source_external_identity')
                 or (message_row.origin_source_direction = 'outbound'
                   and occurrence_row.direction = 'outbound'
                   and (
                     (link_row.role = 'native_outbound'
                       and occurrence_row.origin_kind not in (
                         'provider_echo', 'provider_response'
                       )
                       and occurrence_row.provider_actor_kind =
                         'source_external_identity')
                     or (link_row.role = 'provider_echo'
                       and occurrence_row.origin_kind = 'provider_echo')
                   ))
               ))
           ))
         or (message_row.origin_kind = 'hulee_external'
           and route_row.conversation_id = message_row.conversation_id
           and route_row.external_thread_id = reference_row.external_thread_id
           and route_row.external_thread_id = occurrence_row.external_thread_id
           and route_row.adapter_contract_id = occurrence_row.adapter_contract_id
           and route_row.adapter_contract_version =
             occurrence_row.adapter_contract_version
           and route_row.adapter_declaration_revision =
             occurrence_row.adapter_declaration_revision
           and route_row.adapter_surface_id = occurrence_row.adapter_surface_id
           and route_row.adapter_loaded_by_trusted_service_id =
             occurrence_row.adapter_loaded_by_trusted_service_id
           and route_row.adapter_loaded_at = occurrence_row.adapter_loaded_at
           and (
             (route_row.source_account_id = occurrence_row.source_account_id
               and route_row.source_thread_binding_id =
                 occurrence_row.source_thread_binding_id
               and route_row.binding_generation =
                 occurrence_row.binding_generation)
             or (not (
                 route_row.source_account_id = occurrence_row.source_account_id
                 and route_row.source_thread_binding_id =
                   occurrence_row.source_thread_binding_id
               )
               and link_row.role = 'provider_echo'
               and occurrence_row.origin_kind = 'provider_echo'
               and occurrence_row.message_scope_kind = 'provider_thread'
               and occurrence_row.message_decision_strength = 'authoritative'
               and reference_row.scope_kind = 'provider_thread'
               and thread_row.scope_kind = 'provider'
               and thread_row.identity_declaration ->> 'decisionStrength' =
                 'authoritative')
           )
           and (
             (link_row.role = 'provider_echo'
               and occurrence_row.origin_kind = 'provider_echo')
             or (link_row.role = 'provider_response'
               and occurrence_row.origin_kind = 'provider_response')
           ))
       )
  );
$$;



--
-- Name: inbox_v2_work_assignment_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_assignment_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_work_revision bigint;
  v_decision public.inbox_v2_work_queue_eligibility_decisions%rowtype;
  v_fence_head public.inbox_v2_employee_assignment_fence_heads%rowtype;
  v_end_fence public.inbox_v2_employee_assignment_fence_versions%rowtype;
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.inbox_v2_work_items w
       where w.tenant_id = old.tenant_id and w.id = old.work_item_id
    ) then
      return old;
    end if;
    raise exception 'Primary assignment history cannot be deleted'
      using errcode = '23514';
  end if;

  select w.revision into v_work_revision
    from public.inbox_v2_work_items w
   where w.tenant_id = new.tenant_id and w.id = new.work_item_id
   for update;
  if v_work_revision is null then
    raise exception 'Primary assignment requires a locked WorkItem'
      using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.state <> 'active' or new.revision <> 1 then
      raise exception 'Primary assignment must be inserted as active revision one'
        using errcode = '23514';
    end if;
    select * into v_decision
      from public.inbox_v2_work_queue_eligibility_decisions d
     where d.tenant_id = new.tenant_id
       and d.id = new.eligibility_decision_id;
    if v_decision.id is null
       or v_decision.work_item_id <> new.work_item_id
       or v_decision.work_queue_id <> new.queue_at_start_id
       or v_decision.work_queue_revision <> new.queue_at_start_revision
       or v_decision.employee_id <> new.employee_id
       or v_decision.effect <> 'allow'
       or v_decision.employee_fence_generation <>
          new.employee_fence_generation_at_start
       or v_work_revision not in (
         v_decision.expected_work_item_revision,
         v_decision.expected_work_item_revision + 1
       )
       or new.started_at < v_decision.decided_at
       or new.started_at > v_decision.not_after
       or new.started_at < v_decision.employee_fence_effective_from then
      raise exception 'Primary assignment requires the exact live allow decision'
        using errcode = '23514';
    end if;

    select * into v_fence_head
      from public.inbox_v2_employee_assignment_fence_heads h
     where h.tenant_id = new.tenant_id and h.employee_id = new.employee_id
     for update;
    if v_fence_head.current_revision <> v_decision.employee_fence_revision
       or v_fence_head.current_generation <>
          new.employee_fence_generation_at_start
       or v_fence_head.state <> 'active'
       or v_fence_head.effective_from <>
          v_decision.employee_fence_effective_from then
      raise exception 'Primary assignment lost the Employee fence race'
        using errcode = '40001';
    end if;
  else
    if old.state <> 'active'
       or new.state <> 'ended'
       or old.revision <> 1
       or new.revision <> 2
       or row(
         new.tenant_id,
         new.id,
         new.work_item_id,
         new.queue_at_start_id,
         new.queue_at_start_revision,
         new.employee_id,
         new.source,
         new.eligibility_decision_id,
         new.employee_fence_generation_at_start,
         new.started_at,
         new.started_actor_kind,
         new.started_actor_employee_id,
         new.started_actor_authorization_epoch,
         new.started_actor_trusted_service_id,
         new.start_reason_id,
         new.created_at
       ) is distinct from row(
         old.tenant_id,
         old.id,
         old.work_item_id,
         old.queue_at_start_id,
         old.queue_at_start_revision,
         old.employee_id,
         old.source,
         old.eligibility_decision_id,
         old.employee_fence_generation_at_start,
         old.started_at,
         old.started_actor_kind,
         old.started_actor_employee_id,
         old.started_actor_authorization_epoch,
         old.started_actor_trusted_service_id,
         old.start_reason_id,
         old.created_at
       ) then
      raise exception 'Primary assignment permits one immutable active-to-ended closure'
        using errcode = '23514';
    end if;

    if new.end_basis = 'employee_fence_time' then
      select * into v_fence_head
        from public.inbox_v2_employee_assignment_fence_heads h
       where h.tenant_id = new.tenant_id and h.employee_id = new.employee_id
       for update;
      select * into v_end_fence
        from public.inbox_v2_employee_assignment_fence_versions v
       where v.tenant_id = new.tenant_id
         and v.employee_id = new.employee_id
         and v.revision = new.end_employee_fence_revision;
      if v_end_fence.revision is null
         or v_fence_head.current_revision <> new.end_employee_fence_revision
         or v_fence_head.current_generation <>
            new.end_employee_fence_generation
         or v_fence_head.state <> new.end_employee_fence_state
         or v_fence_head.effective_from <>
            new.end_employee_fence_effective_from
         or v_end_fence.generation <> new.end_employee_fence_generation
         or v_end_fence.state <> new.end_employee_fence_state
         or v_end_fence.effective_from <> new.end_employee_fence_effective_from
         or new.end_employee_fence_loaded_at <> new.end_recorded_at then
        raise exception 'Assignment fence-time closure requires the exact fence version'
          using errcode = '23514';
      end if;
    end if;
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_work_assignment_non_overlap(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_assignment_non_overlap() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if exists (
    select 1
      from public.inbox_v2_work_item_primary_assignments other
     where other.tenant_id = new.tenant_id
       and other.work_item_id = new.work_item_id
       and other.id <> new.id
       and other.started_at < coalesce(new.ended_at, 'infinity'::timestamptz)
       and new.started_at < coalesce(other.ended_at, 'infinity'::timestamptz)
  ) then
    raise exception 'Primary assignment intervals cannot overlap'
      using errcode = '23P01';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_work_eligibility_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_eligibility_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_work public.inbox_v2_work_items%rowtype;
  v_queue_head_revision bigint;
  v_queue public.inbox_v2_work_queue_versions%rowtype;
  v_fence_head public.inbox_v2_employee_assignment_fence_heads%rowtype;
  v_fence public.inbox_v2_employee_assignment_fence_versions%rowtype;
begin
  select * into v_work
    from public.inbox_v2_work_items w
   where w.tenant_id = new.tenant_id and w.id = new.work_item_id
   for update;
  if not found
     or v_work.revision <> new.expected_work_item_revision
     or v_work.queue_id <> new.work_queue_id
     or v_work.queue_revision <> new.work_queue_revision then
    raise exception 'Eligibility decision requires the exact locked WorkItem head'
      using errcode = '23514';
  end if;

  select h.current_revision into v_queue_head_revision
    from public.inbox_v2_work_queue_heads h
   where h.tenant_id = new.tenant_id
     and h.work_queue_id = new.work_queue_id
   for update;
  select * into v_queue
    from public.inbox_v2_work_queue_versions v
   where v.tenant_id = new.tenant_id
     and v.work_queue_id = new.work_queue_id
     and v.revision = new.work_queue_revision;
  if v_queue_head_revision is null
     or v_queue_head_revision <> new.work_queue_revision
     or v_queue.lifecycle <> new.work_queue_lifecycle
     or v_queue.eligibility_policy_id <> new.policy_id
     or v_queue.eligibility_policy_version <> new.policy_version
     or v_queue.eligibility_policy_revision <> new.policy_revision then
    raise exception 'Eligibility decision must snapshot the current WorkQueue policy'
      using errcode = '23514';
  end if;

  select * into v_fence_head
    from public.inbox_v2_employee_assignment_fence_heads h
   where h.tenant_id = new.tenant_id and h.employee_id = new.employee_id
   for update;
  select * into v_fence
    from public.inbox_v2_employee_assignment_fence_versions v
   where v.tenant_id = new.tenant_id
     and v.employee_id = new.employee_id
     and v.revision = new.employee_fence_revision;
  if v_fence_head.current_revision is null
     or v_fence_head.current_revision <> new.employee_fence_revision
     or v_fence_head.current_generation <> new.employee_fence_generation
     or v_fence_head.state <> new.employee_fence_state
     or v_fence_head.effective_from <> new.employee_fence_effective_from
     or v_fence.generation <> new.employee_fence_generation
     or v_fence.state <> new.employee_fence_state
     or v_fence.effective_from <> new.employee_fence_effective_from
     or (new.effect = 'allow' and (
       new.work_queue_lifecycle <> 'active'
       or new.employee_fence_state <> 'active'
     )) then
    raise exception 'Eligibility decision must snapshot the current Employee fence'
      using errcode = '23514';
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_work_item_aggregate_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_item_aggregate_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_work_item_id text;
  v_work public.inbox_v2_work_items%rowtype;
  v_creation public.inbox_v2_work_item_creation_decisions%rowtype;
  v_creation_queue public.inbox_v2_work_queue_versions%rowtype;
  v_creation_sla public.inbox_v2_work_item_sla_snapshots%rowtype;
  v_sla public.inbox_v2_work_item_sla_snapshots%rowtype;
  v_sla_count bigint;
  v_sla_min_revision bigint;
  v_sla_max_revision bigint;
  v_sla_cycle_count bigint;
  v_sla_min_cycle bigint;
  v_sla_max_cycle bigint;
  v_slot_revision bigint;
  v_conversation_transport public.inbox_v2_conversation_transport;
  v_expected_creation_slot_revision bigint;
  v_active_assignment_count bigint;
  v_active_assignment_id text;
  v_last_effect_opened_assignment_id text;
  v_last_effect_closed_assignment_id text;
  v_active_team_count bigint;
  v_active_team_episode_id text;
  v_active_team_id text;
  v_active_team_cycle bigint;
  v_last_effect_opened_team_episode_id text;
  v_last_effect_closed_team_episode_id text;
  v_proof_count bigint;
  v_distinct_proof_count bigint;
  v_min_proof_revision bigint;
  v_max_proof_revision bigint;
  v_collaborator_effect_count bigint;
  v_distinct_collaborator_revision_count bigint;
  v_min_collaborator_revision bigint;
  v_max_collaborator_revision bigint;
  v_reopen_count bigint;
  v_access_change_count bigint;
  v_relation_count bigint;
  v_distinct_relation_count bigint;
  v_min_relation_revision bigint;
  v_max_relation_revision bigint;
  v_transition public.inbox_v2_work_item_transitions%rowtype;
  v_relation public.inbox_v2_work_item_relation_transitions%rowtype;
  v_chain_state public.inbox_v2_work_item_state;
  v_chain_queue_id text;
  v_chain_queue_revision bigint;
  v_chain_relation_revision bigint;
  v_revision_proof record;
begin
  v_tenant_id := new.tenant_id;
  if tg_table_name = 'inbox_v2_work_items' then
    v_work_item_id := new.id;
  else
    v_work_item_id := new.work_item_id;
  end if;

  select * into v_work
    from public.inbox_v2_work_items w
   where w.tenant_id = v_tenant_id and w.id = v_work_item_id;
  if not found then
    return null;
  end if;

  select * into v_sla
    from public.inbox_v2_work_item_sla_snapshots s
   where s.tenant_id = v_work.tenant_id
     and s.work_item_id = v_work.id
     and s.sla_cycle = v_work.sla_cycle
     and s.revision = v_work.sla_snapshot_revision;
  if not found then
    raise exception 'WorkItem SLA head must reference an exact immutable snapshot'
      using errcode = '23514';
  end if;
  select count(*), min(s.revision), max(s.revision)
    into v_sla_count, v_sla_min_revision, v_sla_max_revision
    from public.inbox_v2_work_item_sla_snapshots s
   where s.tenant_id = v_work.tenant_id
     and s.work_item_id = v_work.id
     and s.sla_cycle = v_work.sla_cycle;
  if v_sla_min_revision <> 1
     or v_sla_max_revision <> v_work.sla_snapshot_revision
     or v_sla_count <> v_work.sla_snapshot_revision then
    raise exception 'WorkItem SLA snapshot revisions must be contiguous through the cycle head'
      using errcode = '23514';
  end if;
  select count(distinct s.sla_cycle), min(s.sla_cycle), max(s.sla_cycle)
    into v_sla_cycle_count, v_sla_min_cycle, v_sla_max_cycle
    from public.inbox_v2_work_item_sla_snapshots s
   where s.tenant_id = v_work.tenant_id and s.work_item_id = v_work.id;
  if v_sla_min_cycle <> 1
     or v_sla_max_cycle <> v_work.sla_cycle
     or v_sla_cycle_count <> v_work.sla_cycle
     or exists (
       select 1
         from public.inbox_v2_work_item_sla_snapshots s
        where s.tenant_id = v_work.tenant_id
          and s.work_item_id = v_work.id
        group by s.sla_cycle
       having min(s.revision) <> 1 or count(*) <> max(s.revision)
     ) then
    raise exception 'WorkItem SLA cycles and per-cycle revisions must be gap-free'
      using errcode = '23514';
  end if;

  select * into v_creation
    from public.inbox_v2_work_item_creation_decisions d
   where d.tenant_id = v_work.tenant_id and d.work_item_id = v_work.id;
  select * into v_creation_queue
    from public.inbox_v2_work_queue_versions q
   where q.tenant_id = v_creation.tenant_id
     and q.work_queue_id = v_creation.work_queue_id
     and q.revision = v_creation.work_queue_revision;
  select * into v_creation_sla
    from public.inbox_v2_work_item_sla_snapshots s
   where s.tenant_id = v_work.tenant_id
     and s.work_item_id = v_work.id
     and s.sla_cycle = 1
     and s.revision = 1;
  select c.transport into v_conversation_transport
    from public.inbox_v2_conversations c
   where c.tenant_id = v_work.tenant_id and c.id = v_work.conversation_id;
  select s.revision into v_slot_revision
    from public.inbox_v2_conversation_work_item_slots s
   where s.tenant_id = v_work.tenant_id
     and s.conversation_id = v_work.conversation_id;
  select 1 + v_work.ordinal + count(t.id)
    into v_expected_creation_slot_revision
    from public.inbox_v2_work_items prior
    join public.inbox_v2_work_item_transitions t
      on t.tenant_id = prior.tenant_id and t.work_item_id = prior.id
   where prior.tenant_id = v_work.tenant_id
     and prior.conversation_id = v_work.conversation_id
     and prior.ordinal < v_work.ordinal
     and t.kind in (
       'close_resolved',
       'close_dismissed',
       'reopen_unassigned',
       'reopen_assigned'
     );
  if v_creation.work_item_id is null
     or v_creation.conversation_id <> v_work.conversation_id
     or v_creation.transport <> v_conversation_transport
     or v_creation.reason_id <> v_work.creation_reason_id
     or v_work.created_actor_kind <> 'trusted_service'
     or v_creation.decided_by_trusted_service_id <>
        v_work.created_actor_trusted_service_id
     or v_creation.decided_at > v_work.created_at
     or v_creation.slot_after_revision > v_slot_revision
     or v_creation.slot_after_revision <>
        v_expected_creation_slot_revision
     or (v_work.ordinal = 1 and
       v_creation.latest_terminal_handling <> 'no_latest_work_item')
     or (v_work.ordinal > 1 and
       v_creation.latest_terminal_handling <> 'create_sequential') then
    raise exception 'WorkItem must retain its exact creation decision authority'
      using errcode = '23514';
  end if;

  if v_creation_sla.revision is null
     or v_creation_sla.kind <> v_creation_queue.default_sla_kind
     or v_creation_sla.calculated_at <> v_work.created_at
     or v_creation_sla.created_at <> v_work.created_at
     or (
       v_creation_queue.default_sla_kind = 'tracked'
       and (
         v_creation_sla.policy_id <>
            v_creation_queue.default_sla_policy_id
         or v_creation_sla.policy_version <>
            v_creation_queue.default_sla_policy_version
         or v_creation_sla.policy_revision <>
            v_creation_queue.default_sla_policy_revision
         or v_creation_sla.input_revision <> 1
         or v_creation_sla.business_calendar_id <>
            v_creation_queue.default_business_calendar_id
         or v_creation_sla.business_calendar_version <>
            v_creation_queue.default_business_calendar_version
         or v_creation_sla.business_calendar_revision <>
            v_creation_queue.default_business_calendar_revision
         or v_creation_sla.time_zone <>
            v_creation_queue.default_sla_time_zone
         or v_creation_sla.clock_state <> 'running'
         or v_creation_sla.started_at <> v_work.created_at
         or v_creation_sla.paused_at is not null
         or v_creation_sla.pause_condition_id is not null
         or v_creation_sla.stopped_at is not null
         or v_creation_sla.first_human_response_at is not null
       )
     ) then
    raise exception 'WorkItem cycle-one SLA must retain exact creation Queue defaults'
      using errcode = '23514';
  end if;

  if v_work.revision = 1 and (
    v_work.state <> 'new'
    or v_work.queue_id <> v_creation.work_queue_id
    or v_work.queue_revision <> v_creation.work_queue_revision
    or v_work.reopen_cycle <> 0
    or v_work.servicing_team_relation_revision <> 1
    or v_work.collaborator_set_revision <> 1
    or v_work.resource_access_revision <> 1
    or v_work.priority_id <> v_creation_queue.default_priority_id
    or v_work.sla_cycle <> 1
    or v_work.sla_snapshot_revision <> 1
    or v_work.current_primary_assignment_id is not null
    or v_work.current_servicing_team_episode_id is not null
  ) then
    raise exception 'Revision-one WorkItem must be the unassigned creation snapshot'
      using errcode = '23514';
  end if;

  if v_sla.kind = 'tracked' and (
       (v_work.state in ('resolved', 'dismissed') and
         (
           v_sla.clock_state <> 'stopped'
           or v_sla.stopped_at <> v_work.updated_at
           or v_sla.calculated_at <> v_work.updated_at
         ))
       or (v_work.state in ('new', 'assigned', 'in_progress', 'waiting') and
         v_sla.clock_state = 'stopped')
     ) then
    raise exception 'Tracked SLA clock state must follow WorkItem terminality'
      using errcode = '23514';
  end if;

  select
    count(*) filter (where a.state = 'active'),
    max(a.id) filter (where a.state = 'active')
    into v_active_assignment_count, v_active_assignment_id
    from public.inbox_v2_work_item_primary_assignments a
   where a.tenant_id = v_work.tenant_id and a.work_item_id = v_work.id;
  if (
      v_work.state in ('assigned', 'in_progress', 'waiting')
      and (
        v_active_assignment_count <> 1
        or v_work.current_primary_assignment_id is distinct from
           v_active_assignment_id
      )
    ) or (
      v_work.state in ('new', 'resolved', 'dismissed')
      and (
        v_active_assignment_count <> 0
        or v_work.current_primary_assignment_id is not null
      )
    ) then
    raise exception 'WorkItem state and active primary-assignment head diverged'
      using errcode = '23514';
  end if;
  if v_work.last_primary_assignment_id is not null and not exists (
    select 1
      from public.inbox_v2_work_item_primary_assignments a
     where a.tenant_id = v_work.tenant_id
       and a.work_item_id = v_work.id
       and a.id = v_work.last_primary_assignment_id
  ) then
    raise exception 'WorkItem last primary-assignment pointer crosses aggregate scope'
      using errcode = '23514';
  end if;
  select t.opened_primary_assignment_id, t.closed_primary_assignment_id
    into v_last_effect_opened_assignment_id,
         v_last_effect_closed_assignment_id
    from public.inbox_v2_work_item_transitions t
   where t.tenant_id = v_work.tenant_id
     and t.work_item_id = v_work.id
     and (
       t.opened_primary_assignment_id is not null
       or t.closed_primary_assignment_id is not null
     )
   order by t.resulting_revision desc
   limit 1;
  if v_work.last_primary_assignment_id is distinct from coalesce(
       v_last_effect_opened_assignment_id,
       v_last_effect_closed_assignment_id
     )
     or (v_work.state in ('assigned', 'in_progress', 'waiting') and
       v_work.current_primary_assignment_id is distinct from
         v_last_effect_opened_assignment_id) then
    raise exception 'WorkItem primary-assignment pointers must follow the latest assignment effect'
      using errcode = '23514';
  end if;

  select
    count(*) filter (where e.state = 'active'),
    max(e.id) filter (where e.state = 'active'),
    max(e.team_id) filter (where e.state = 'active'),
    max(e.work_item_cycle) filter (where e.state = 'active')
    into v_active_team_count,
         v_active_team_episode_id,
         v_active_team_id,
         v_active_team_cycle
    from public.inbox_v2_work_item_servicing_team_episodes e
   where e.tenant_id = v_work.tenant_id and e.work_item_id = v_work.id;
  if v_work.state in ('resolved', 'dismissed') and v_active_team_count <> 0 then
    raise exception 'Terminal WorkItem cannot retain an active servicing team'
      using errcode = '23514';
  end if;
  if (
      v_work.current_servicing_team_episode_id is null
      and (v_active_team_count <> 0 or v_work.current_servicing_team_id is not null)
    ) or (
      v_work.current_servicing_team_episode_id is not null
      and (
        v_active_team_count <> 1
        or v_work.current_servicing_team_episode_id is distinct from
           v_active_team_episode_id
        or v_work.current_servicing_team_id is distinct from v_active_team_id
        or v_work.reopen_cycle <> v_active_team_cycle
      )
    ) then
    raise exception 'WorkItem servicing-team head is not the exact active episode'
      using errcode = '23514';
  end if;
  if v_work.last_servicing_team_episode_id is not null and not exists (
    select 1
      from public.inbox_v2_work_item_servicing_team_episodes e
     where e.tenant_id = v_work.tenant_id
       and e.work_item_id = v_work.id
       and e.id = v_work.last_servicing_team_episode_id
  ) then
    raise exception 'WorkItem last servicing-team pointer crosses aggregate scope'
      using errcode = '23514';
  end if;
  select effect.opened_episode_id, effect.closed_episode_id
    into v_last_effect_opened_team_episode_id,
         v_last_effect_closed_team_episode_id
    from (
      select
        r.resulting_work_item_revision as work_item_revision,
        r.next_episode_id as opened_episode_id,
        r.previous_episode_id as closed_episode_id
      from public.inbox_v2_work_item_relation_transitions r
      where r.tenant_id = v_work.tenant_id and r.work_item_id = v_work.id
      union all
      select
        t.resulting_revision as work_item_revision,
        null::text as opened_episode_id,
        t.closed_servicing_team_episode_id as closed_episode_id
      from public.inbox_v2_work_item_transitions t
      where t.tenant_id = v_work.tenant_id
        and t.work_item_id = v_work.id
        and t.closed_servicing_team_episode_id is not null
    ) effect
   order by effect.work_item_revision desc
   limit 1;
  if v_work.last_servicing_team_episode_id is distinct from coalesce(
       v_last_effect_opened_team_episode_id,
       v_last_effect_closed_team_episode_id
     )
     or (v_work.current_servicing_team_episode_id is not null and
       v_work.current_servicing_team_episode_id is distinct from
         v_last_effect_opened_team_episode_id) then
    raise exception 'WorkItem servicing-team pointers must follow the latest relation effect'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_primary_assignments a
     where a.tenant_id = v_work.tenant_id
       and a.work_item_id = v_work.id
       and a.state = 'ended'
       and not exists (
         select 1
           from public.inbox_v2_work_item_transitions t
          where t.tenant_id = a.tenant_id
            and t.work_item_id = a.work_item_id
            and t.id = a.termination_transition_id
            and t.closed_primary_assignment_id = a.id
            and t.occurred_at = a.end_recorded_at
            and t.actor_kind = a.ended_actor_kind
            and t.actor_employee_id is not distinct from a.ended_actor_employee_id
            and t.actor_authorization_epoch is not distinct from
                a.ended_actor_authorization_epoch
            and t.actor_trusted_service_id is not distinct from
                a.ended_actor_trusted_service_id
            and t.reason_id = a.end_reason_id
            and (
              (t.kind in ('recovery_requeue', 'recovery_transfer')
                and a.end_basis = 'employee_fence_time')
              or (t.kind in (
                'release',
                'transfer',
                'close_resolved',
                'close_dismissed'
              ) and a.end_basis = 'command_time')
            )
       )
  ) then
    raise exception 'Ended assignment must name its exact WorkItem transition'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_primary_assignments a
      join public.inbox_v2_work_queue_eligibility_decisions d
        on d.tenant_id = a.tenant_id and d.id = a.eligibility_decision_id
     where a.tenant_id = v_work.tenant_id
       and a.work_item_id = v_work.id
       and not exists (
         select 1
           from public.inbox_v2_work_item_transitions t
          where t.tenant_id = a.tenant_id
            and t.work_item_id = a.work_item_id
            and t.opened_primary_assignment_id = a.id
            and t.expected_revision = d.expected_work_item_revision
            and t.destination_queue_id = a.queue_at_start_id
            and t.destination_queue_revision = a.queue_at_start_revision
            and t.occurred_at = a.started_at
            and a.created_at = t.occurred_at
            and d.decided_at = t.occurred_at
            and d.employee_fence_loaded_at = t.occurred_at
            and t.actor_kind = a.started_actor_kind
            and t.actor_employee_id is not distinct from a.started_actor_employee_id
            and t.actor_authorization_epoch is not distinct from
                a.started_actor_authorization_epoch
            and t.actor_trusted_service_id is not distinct from
                a.started_actor_trusted_service_id
            and t.reason_id = a.start_reason_id
            and (
              (t.kind = 'claim'
                and a.source = 'claim'
                and t.actor_kind = 'employee'
                and t.actor_employee_id = a.employee_id)
              or (t.kind = 'assign' and
                a.source in ('manual_assignment', 'policy_assignment'))
              or (t.kind = 'transfer' and a.source = 'transfer')
              or (t.kind = 'reopen_assigned' and a.source = 'reopen')
              or (t.kind = 'recovery_transfer' and
                a.source = 'recovery_transfer')
            )
       )
  ) then
    raise exception 'Primary assignment must retain its exact opening transition'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_transitions t
     where t.tenant_id = v_work.tenant_id
       and t.work_item_id = v_work.id
       and (
         (t.opened_primary_assignment_id is not null and not exists (
           select 1
             from public.inbox_v2_work_item_primary_assignments a
             join public.inbox_v2_work_queue_eligibility_decisions d
               on d.tenant_id = a.tenant_id
              and d.id = a.eligibility_decision_id
            where a.tenant_id = t.tenant_id
              and a.work_item_id = t.work_item_id
              and a.id = t.opened_primary_assignment_id
              and d.expected_work_item_revision = t.expected_revision
              and a.queue_at_start_id = t.destination_queue_id
              and a.queue_at_start_revision = t.destination_queue_revision
              and a.started_at = t.occurred_at
              and a.created_at = t.occurred_at
              and d.decided_at = t.occurred_at
              and d.employee_fence_loaded_at = t.occurred_at
              and a.started_actor_kind = t.actor_kind
              and a.started_actor_employee_id is not distinct from
                  t.actor_employee_id
              and a.started_actor_authorization_epoch is not distinct from
                  t.actor_authorization_epoch
              and a.started_actor_trusted_service_id is not distinct from
                  t.actor_trusted_service_id
              and a.start_reason_id = t.reason_id
              and (
                (t.kind = 'claim'
                  and a.source = 'claim'
                  and t.actor_kind = 'employee'
                  and t.actor_employee_id = a.employee_id)
                or (t.kind = 'assign' and
                  a.source in ('manual_assignment', 'policy_assignment'))
                or (t.kind = 'transfer' and a.source = 'transfer')
                or (t.kind = 'reopen_assigned' and a.source = 'reopen')
                or (t.kind = 'recovery_transfer' and
                  a.source = 'recovery_transfer')
              )
         ))
         or (t.closed_primary_assignment_id is not null and not exists (
           select 1
             from public.inbox_v2_work_item_primary_assignments a
            where a.tenant_id = t.tenant_id
              and a.work_item_id = t.work_item_id
              and a.id = t.closed_primary_assignment_id
              and a.state = 'ended'
              and a.termination_transition_id = t.id
              and a.end_recorded_at = t.occurred_at
              and a.ended_actor_kind = t.actor_kind
              and a.ended_actor_employee_id is not distinct from
                  t.actor_employee_id
              and a.ended_actor_authorization_epoch is not distinct from
                  t.actor_authorization_epoch
              and a.ended_actor_trusted_service_id is not distinct from
                  t.actor_trusted_service_id
              and a.end_reason_id = t.reason_id
              and (
                (t.kind in ('recovery_requeue', 'recovery_transfer')
                  and a.end_basis = 'employee_fence_time')
                or (t.kind in (
                  'release',
                  'transfer',
                  'close_resolved',
                  'close_dismissed'
                ) and a.end_basis = 'command_time')
              )
         ))
       )
  ) then
    raise exception 'WorkItem transition assignment effect lacks exact bidirectional history'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_transitions t
      join public.inbox_v2_work_item_primary_assignments closed
        on closed.tenant_id = t.tenant_id
       and closed.id = t.closed_primary_assignment_id
      join public.inbox_v2_work_item_primary_assignments opened
        on opened.tenant_id = t.tenant_id
       and opened.id = t.opened_primary_assignment_id
     where t.tenant_id = v_work.tenant_id
       and t.work_item_id = v_work.id
       and t.kind in ('transfer', 'recovery_transfer')
       and closed.employee_id = opened.employee_id
       and closed.queue_at_start_id = opened.queue_at_start_id
       and closed.queue_at_start_revision = opened.queue_at_start_revision
  ) then
    raise exception 'Primary transfer must change Employee or Queue'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_servicing_team_episodes e
     where e.tenant_id = v_work.tenant_id
       and e.work_item_id = v_work.id
       and e.state = 'ended'
       and (
         (e.end_cause = 'relation_command' and not exists (
           select 1
             from public.inbox_v2_work_item_relation_transitions r
            where r.tenant_id = e.tenant_id
              and r.work_item_id = e.work_item_id
              and r.id = e.end_relation_transition_id
              and r.previous_episode_id = e.id
              and r.occurred_at = e.end_recorded_at
              and r.occurred_at = e.ended_at
         ))
         or (e.end_cause = 'work_item_terminal' and not exists (
           select 1
             from public.inbox_v2_work_item_transitions t
            where t.tenant_id = e.tenant_id
              and t.work_item_id = e.work_item_id
              and t.id = e.end_work_item_transition_id
              and t.kind in ('close_resolved', 'close_dismissed')
              and t.closed_servicing_team_episode_id = e.id
              and t.occurred_at = e.end_recorded_at
              and t.occurred_at = e.ended_at
         ))
       )
  ) then
    raise exception 'Ended servicing-team episode must name its exact transition'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_relation_transitions r
      join public.inbox_v2_work_item_servicing_team_episodes previous
        on previous.tenant_id = r.tenant_id
       and previous.id = r.previous_episode_id
      join public.inbox_v2_work_item_servicing_team_episodes following
        on following.tenant_id = r.tenant_id
       and following.id = r.next_episode_id
     where r.tenant_id = v_work.tenant_id
       and r.work_item_id = v_work.id
       and r.kind = 'servicing_team_change'
       and previous.team_id = following.team_id
  ) then
    raise exception 'Servicing-team change must target a different Team'
      using errcode = '23514';
  end if;

  select count(*), count(distinct p.resulting_revision),
         min(p.resulting_revision), max(p.resulting_revision)
    into v_proof_count, v_distinct_proof_count,
         v_min_proof_revision, v_max_proof_revision
    from (
      select t.resulting_revision
        from public.inbox_v2_work_item_transitions t
       where t.tenant_id = v_work.tenant_id and t.work_item_id = v_work.id
      union all
      select r.resulting_work_item_revision
        from public.inbox_v2_work_item_relation_transitions r
       where r.tenant_id = v_work.tenant_id and r.work_item_id = v_work.id
      union all
      select effect_row.resulting_work_item_revision
        from public.inbox_v2_auth_revision_effects effect_row
       where effect_row.tenant_id = v_work.tenant_id
         and effect_row.effect_kind = 'collaborator_set'
         and effect_row.work_item_id = v_work.id
    ) p;
  if (v_work.revision = 1 and v_proof_count <> 0)
     or (v_work.revision > 1 and (
       v_proof_count <> v_work.revision - 1
       or v_distinct_proof_count <> v_proof_count
       or v_min_proof_revision <> 2
       or v_max_proof_revision <> v_work.revision
     )) then
    raise exception 'WorkItem revision chain requires exactly one immutable proof per +1'
      using errcode = '23514';
  end if;

  select count(*) into v_reopen_count
    from public.inbox_v2_work_item_transitions t
   where t.tenant_id = v_work.tenant_id
     and t.work_item_id = v_work.id
     and t.kind in ('reopen_unassigned', 'reopen_assigned');
  select count(*), count(distinct effect_row.after_revision),
         min(effect_row.before_revision), max(effect_row.after_revision)
    into v_collaborator_effect_count,
         v_distinct_collaborator_revision_count,
         v_min_collaborator_revision, v_max_collaborator_revision
    from public.inbox_v2_auth_revision_effects effect_row
   where effect_row.tenant_id = v_work.tenant_id
     and effect_row.effect_kind = 'collaborator_set'
     and effect_row.work_item_id = v_work.id;
  if v_work.reopen_cycle <> v_reopen_count
     or v_work.collaborator_set_revision < 1
     or v_collaborator_effect_count <>
        v_work.collaborator_set_revision - 1
     or v_distinct_collaborator_revision_count <>
        v_collaborator_effect_count
     or (v_collaborator_effect_count > 0 and (
       v_min_collaborator_revision <> 1
       or v_max_collaborator_revision <> v_work.collaborator_set_revision
     ))
     or exists (
       select 1
         from public.inbox_v2_auth_revision_effects effect_row
        where effect_row.tenant_id = v_work.tenant_id
          and effect_row.effect_kind = 'collaborator_set'
          and effect_row.work_item_id = v_work.id
          and (
            effect_row.resulting_work_item_revision <>
              effect_row.expected_work_item_revision + 1
            or effect_row.work_item_cycle <> (
              select count(*)
                from public.inbox_v2_work_item_transitions reopen
               where reopen.tenant_id = effect_row.tenant_id
                 and reopen.work_item_id = effect_row.work_item_id
                 and reopen.resulting_revision <=
                   effect_row.expected_work_item_revision
                 and reopen.kind in ('reopen_unassigned', 'reopen_assigned')
            )
          )
     ) then
    raise exception 'WorkItem reopen/collaborator revisions lack exact history proof'
      using errcode = '23514';
  end if;

  select count(*) into v_access_change_count
    from (
      select t.id
        from public.inbox_v2_work_item_transitions t
       where t.tenant_id = v_work.tenant_id
         and t.work_item_id = v_work.id
         and (
           t.opened_primary_assignment_id is not null
           or t.closed_primary_assignment_id is not null
           or t.source_queue_id <> t.destination_queue_id
           or t.source_queue_revision <> t.destination_queue_revision
           or t.from_state in ('resolved', 'dismissed')
           or t.to_state in ('resolved', 'dismissed')
         )
      union all
      select r.id
        from public.inbox_v2_work_item_relation_transitions r
       where r.tenant_id = v_work.tenant_id and r.work_item_id = v_work.id
    ) access_change;
  if v_work.resource_access_revision <> 1 + v_access_change_count then
    raise exception 'WorkItem resource-access revision lacks exact authority-change proof'
      using errcode = '23514';
  end if;

  v_chain_state := 'new';
  v_chain_queue_id := v_creation.work_queue_id;
  v_chain_queue_revision := v_creation.work_queue_revision;
  for v_transition in
    select *
      from public.inbox_v2_work_item_transitions t
     where t.tenant_id = v_work.tenant_id and t.work_item_id = v_work.id
     order by t.resulting_revision
  loop
    if v_transition.from_state <> v_chain_state
       or v_transition.source_queue_id <> v_chain_queue_id
       or v_transition.source_queue_revision <> v_chain_queue_revision then
      raise exception 'WorkItem transition source breaks the persisted lifecycle chain'
        using errcode = '23514';
    end if;
    v_chain_state := v_transition.to_state;
    v_chain_queue_id := v_transition.destination_queue_id;
    v_chain_queue_revision := v_transition.destination_queue_revision;
  end loop;
  if v_chain_state <> v_work.state
     or v_chain_queue_id <> v_work.queue_id
     or v_chain_queue_revision <> v_work.queue_revision then
    raise exception 'WorkItem lifecycle transition chain does not induce the head'
      using errcode = '23514';
  end if;

  v_chain_relation_revision := 1;
  for v_revision_proof in
    select
      t.resulting_revision as work_item_revision,
      t.expected_servicing_team_relation_revision as expected_relation_revision,
      t.resulting_servicing_team_relation_revision as resulting_relation_revision
    from public.inbox_v2_work_item_transitions t
    where t.tenant_id = v_work.tenant_id and t.work_item_id = v_work.id
    union all
    select
      r.resulting_work_item_revision as work_item_revision,
      r.expected_relation_revision,
      r.resulting_relation_revision
    from public.inbox_v2_work_item_relation_transitions r
    where r.tenant_id = v_work.tenant_id and r.work_item_id = v_work.id
    order by work_item_revision
  loop
    if v_revision_proof.expected_relation_revision <>
         v_chain_relation_revision then
      raise exception 'WorkItem proof breaks the servicing-team relation chain'
        using errcode = '23514';
    end if;
    v_chain_relation_revision := v_revision_proof.resulting_relation_revision;
  end loop;
  if v_chain_relation_revision <> v_work.servicing_team_relation_revision then
    raise exception 'Servicing-team relation proof chain does not induce the head'
      using errcode = '23514';
  end if;

  select * into v_transition
    from public.inbox_v2_work_item_transitions t
   where t.tenant_id = v_work.tenant_id
     and t.work_item_id = v_work.id
     and t.resulting_revision = v_work.revision;
  if found and (
    v_transition.occurred_at <> v_work.updated_at
    or v_transition.resulting_servicing_team_relation_revision <>
       v_work.servicing_team_relation_revision
  ) then
    raise exception 'Latest WorkItem transition timestamp/relation does not induce the head'
      using errcode = '23514';
  end if;

  select count(*), count(distinct p.resulting_relation_revision),
         min(p.resulting_relation_revision), max(p.resulting_relation_revision)
    into v_relation_count, v_distinct_relation_count,
         v_min_relation_revision, v_max_relation_revision
    from (
      select r.resulting_relation_revision
        from public.inbox_v2_work_item_relation_transitions r
       where r.tenant_id = v_work.tenant_id and r.work_item_id = v_work.id
      union all
      select t.resulting_servicing_team_relation_revision
        from public.inbox_v2_work_item_transitions t
       where t.tenant_id = v_work.tenant_id
         and t.work_item_id = v_work.id
         and t.closed_servicing_team_episode_id is not null
    ) p;
  if (v_work.servicing_team_relation_revision = 1 and v_relation_count <> 0)
     or (v_work.servicing_team_relation_revision > 1 and (
       v_relation_count <> v_work.servicing_team_relation_revision - 1
       or v_distinct_relation_count <> v_relation_count
       or v_min_relation_revision <> 2
       or v_max_relation_revision <> v_work.servicing_team_relation_revision
     )) then
    raise exception 'Servicing-team relation revision chain is not contiguous'
      using errcode = '23514';
  end if;

  select * into v_relation
    from public.inbox_v2_work_item_relation_transitions r
   where r.tenant_id = v_work.tenant_id
     and r.work_item_id = v_work.id
     and r.resulting_work_item_revision = v_work.revision;
  if found then
    if v_relation.resulting_relation_revision <>
         v_work.servicing_team_relation_revision
       or v_relation.occurred_at <> v_work.updated_at
       or (v_relation.kind = 'servicing_team_add' and (
         v_work.current_servicing_team_episode_id is distinct from
           v_relation.next_episode_id
         or v_relation.previous_episode_id is not null
       ))
       or (v_relation.kind = 'servicing_team_remove' and (
         v_work.current_servicing_team_episode_id is not null
         or v_relation.next_episode_id is not null
       ))
       or (v_relation.kind = 'servicing_team_change' and
         v_work.current_servicing_team_episode_id is distinct from
           v_relation.next_episode_id) then
      raise exception 'Latest servicing-team transition does not induce the relation head'
        using errcode = '23514';
    end if;
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_relation_transitions r
     where r.tenant_id = v_work.tenant_id
       and r.work_item_id = v_work.id
       and (
         (r.previous_episode_id is not null and not exists (
           select 1
             from public.inbox_v2_work_item_servicing_team_episodes e
            where e.tenant_id = r.tenant_id
              and e.work_item_id = r.work_item_id
              and e.id = r.previous_episode_id
              and e.state = 'ended'
              and e.end_cause = 'relation_command'
              and e.end_relation_transition_id = r.id
              and e.end_recorded_at = r.occurred_at
              and e.ended_at = r.occurred_at
              and e.ended_actor_kind = r.actor_kind
              and e.ended_actor_employee_id is not distinct from
                  r.actor_employee_id
              and e.ended_actor_authorization_epoch is not distinct from
                  r.actor_authorization_epoch
              and e.ended_actor_trusted_service_id is not distinct from
                  r.actor_trusted_service_id
              and e.end_reason_id = r.reason_id
         ))
         or (r.next_episode_id is not null and not exists (
           select 1
             from public.inbox_v2_work_item_servicing_team_episodes e
            where e.tenant_id = r.tenant_id
              and e.work_item_id = r.work_item_id
              and e.id = r.next_episode_id
              and e.started_at = r.occurred_at
              and e.started_actor_kind = r.actor_kind
              and e.started_actor_employee_id is not distinct from
                  r.actor_employee_id
              and e.started_actor_authorization_epoch is not distinct from
                  r.actor_authorization_epoch
              and e.started_actor_trusted_service_id is not distinct from
                  r.actor_trusted_service_id
              and e.start_reason_id = r.reason_id
              and e.work_item_cycle = (
                select count(*)
                  from public.inbox_v2_work_item_transitions reopen
                 where reopen.tenant_id = r.tenant_id
                   and reopen.work_item_id = r.work_item_id
                   and reopen.resulting_revision <=
                       r.expected_work_item_revision
                   and reopen.kind in (
                     'reopen_unassigned',
                     'reopen_assigned'
                   )
              )
         ))
       )
  ) then
    raise exception 'Servicing-team transition episode pointers cross aggregate scope'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_servicing_team_episodes e
     where e.tenant_id = v_work.tenant_id
       and e.work_item_id = v_work.id
       and not exists (
         select 1
           from public.inbox_v2_work_item_relation_transitions r
          where r.tenant_id = e.tenant_id
            and r.work_item_id = e.work_item_id
            and r.next_episode_id = e.id
            and r.occurred_at = e.started_at
            and r.actor_kind = e.started_actor_kind
            and r.actor_employee_id is not distinct from
                e.started_actor_employee_id
            and r.actor_authorization_epoch is not distinct from
                e.started_actor_authorization_epoch
            and r.actor_trusted_service_id is not distinct from
                e.started_actor_trusted_service_id
            and r.reason_id = e.start_reason_id
            and e.work_item_cycle = (
              select count(*)
                from public.inbox_v2_work_item_transitions reopen
               where reopen.tenant_id = r.tenant_id
                 and reopen.work_item_id = r.work_item_id
                 and reopen.resulting_revision <=
                     r.expected_work_item_revision
                 and reopen.kind in ('reopen_unassigned', 'reopen_assigned')
            )
       )
  ) then
    raise exception 'Servicing-team episode must retain its exact opening relation transition'
      using errcode = '23514';
  end if;

  if exists (
    select 1
      from public.inbox_v2_work_item_transitions t
     where t.tenant_id = v_work.tenant_id
       and t.work_item_id = v_work.id
       and t.closed_servicing_team_episode_id is not null
       and not exists (
         select 1
           from public.inbox_v2_work_item_servicing_team_episodes e
          where e.tenant_id = t.tenant_id
            and e.work_item_id = t.work_item_id
            and e.id = t.closed_servicing_team_episode_id
            and e.state = 'ended'
            and e.end_cause = 'work_item_terminal'
            and e.end_work_item_transition_id = t.id
            and e.end_recorded_at = t.occurred_at
            and e.ended_at = t.occurred_at
            and e.ended_actor_kind = t.actor_kind
            and e.ended_actor_employee_id is not distinct from
                t.actor_employee_id
            and e.ended_actor_authorization_epoch is not distinct from
                t.actor_authorization_epoch
            and e.ended_actor_trusted_service_id is not distinct from
                t.actor_trusted_service_id
            and e.end_reason_id = t.reason_id
       )
  ) then
    raise exception 'Terminal WorkItem relation proof must close its exact team episode'
      using errcode = '23514';
  end if;

  return null;
end
$$;



--
-- Name: inbox_v2_work_item_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_item_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_queue_revision bigint;
  v_queue_lifecycle public.inbox_v2_work_queue_lifecycle;
  v_queue_default_priority_id text;
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.inbox_v2_conversations c
       where c.tenant_id = old.tenant_id and c.id = old.conversation_id
    ) then
      return old;
    end if;
    raise exception 'WorkItem cannot be deleted' using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.revision <> 1 or new.created_at <> new.updated_at then
      raise exception 'WorkItem must start at revision 1 with one timestamp'
        using errcode = '23514';
    end if;

    select h.current_revision, v.lifecycle, v.default_priority_id
      into v_queue_revision, v_queue_lifecycle, v_queue_default_priority_id
      from public.inbox_v2_work_queue_heads h
      join public.inbox_v2_work_queue_versions v
        on v.tenant_id = h.tenant_id
       and v.work_queue_id = h.work_queue_id
       and v.revision = h.current_revision
     where h.tenant_id = new.tenant_id
       and h.work_queue_id = new.queue_id
     for update of h;

    if v_queue_revision is null
       or v_queue_revision <> new.queue_revision
       or v_queue_lifecycle <> 'active' then
      raise exception 'WorkItem creation requires the current active WorkQueue version'
        using errcode = '23514';
    end if;
    if new.state <> 'new'
       or new.priority_id <> v_queue_default_priority_id
       or new.sla_cycle <> 1
       or new.sla_snapshot_revision <> 1
       or new.current_primary_assignment_id is not null
       or new.last_primary_assignment_id is not null
       or new.current_servicing_team_episode_id is not null
       or new.current_servicing_team_id is not null
       or new.last_servicing_team_episode_id is not null
       or new.servicing_team_relation_revision <> 1
       or new.collaborator_set_revision <> 1
       or new.resource_access_revision <> 1
       or new.reopen_cycle <> 0
       or new.last_reopen_snapshot is not null
       or new.terminal_snapshot is not null then
      raise exception 'WorkItem insert must be the exact revision-one Queue default head'
        using errcode = '23514';
    end if;
  else
    if new.tenant_id is distinct from old.tenant_id
       or new.id is distinct from old.id
       or new.conversation_id is distinct from old.conversation_id
       or new.ordinal is distinct from old.ordinal
       or new.created_at is distinct from old.created_at
       or new.created_actor_kind is distinct from old.created_actor_kind
       or new.created_actor_employee_id is distinct from old.created_actor_employee_id
       or new.created_actor_authorization_epoch is distinct from old.created_actor_authorization_epoch
       or new.created_actor_trusted_service_id is distinct from old.created_actor_trusted_service_id
       or new.creation_reason_id is distinct from old.creation_reason_id
       or new.revision <> old.revision + 1
       or new.updated_at < old.updated_at then
      raise exception 'WorkItem update requires immutable identity and +1 CAS'
        using errcode = '23514';
    end if;
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_work_item_mutation_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_item_mutation_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_transition_count bigint;
  v_relation_transition_count bigint;
  v_collaborator_effect_count bigint;
  v_collaborator_effect record;
  v_transition public.inbox_v2_work_item_transitions%rowtype;
  v_relation public.inbox_v2_work_item_relation_transitions%rowtype;
  v_old_sla public.inbox_v2_work_item_sla_snapshots%rowtype;
  v_new_sla public.inbox_v2_work_item_sla_snapshots%rowtype;
  v_destination_queue public.inbox_v2_work_queue_versions%rowtype;
  v_previous_team_id text;
  v_next_team_id text;
  v_expected_access_revision bigint;
begin
  if not exists (
    select 1
      from public.inbox_v2_work_items w
     where w.tenant_id = new.tenant_id and w.id = new.id
  ) then
    return null;
  end if;

  select count(*) into v_transition_count
    from public.inbox_v2_work_item_transitions t
   where t.tenant_id = new.tenant_id
     and t.work_item_id = new.id
     and t.resulting_revision = new.revision;
  select count(*) into v_relation_transition_count
    from public.inbox_v2_work_item_relation_transitions r
   where r.tenant_id = new.tenant_id
     and r.work_item_id = new.id
     and r.resulting_work_item_revision = new.revision;
  select count(*) into v_collaborator_effect_count
    from public.inbox_v2_auth_revision_effects effect_row
   where effect_row.tenant_id = new.tenant_id
     and effect_row.effect_kind = 'collaborator_set'
     and effect_row.work_item_id = new.id
     and effect_row.resulting_work_item_revision = new.revision;

  if v_transition_count + v_relation_transition_count +
       v_collaborator_effect_count <> 1 then
    raise exception 'Each WorkItem +1 mutation requires exactly one lifecycle XOR servicing-team XOR collaborator-set proof'
      using errcode = '23514';
  end if;

  if v_transition_count = 1 then
    select * into strict v_transition
      from public.inbox_v2_work_item_transitions t
     where t.tenant_id = new.tenant_id
       and t.work_item_id = new.id
       and t.resulting_revision = new.revision;

    if v_transition.expected_revision <> old.revision
       or v_transition.resulting_revision <> new.revision
       or v_transition.from_state <> old.state
       or v_transition.to_state <> new.state
       or v_transition.source_queue_id <> old.queue_id
       or v_transition.source_queue_revision <> old.queue_revision
       or v_transition.destination_queue_id <> new.queue_id
       or v_transition.destination_queue_revision <> new.queue_revision
       or v_transition.occurred_at <> new.updated_at
       or v_transition.expected_servicing_team_relation_revision <>
          old.servicing_team_relation_revision
       or v_transition.resulting_servicing_team_relation_revision <>
          new.servicing_team_relation_revision then
      raise exception 'WorkItem lifecycle proof does not bind the exact OLD and NEW heads'
        using errcode = '23514';
    end if;

    if v_transition.opened_primary_assignment_id is not null then
      if (
          v_transition.closed_primary_assignment_id is null
          and old.current_primary_assignment_id is not null
        )
        or (
          v_transition.closed_primary_assignment_id is not null
          and old.current_primary_assignment_id is distinct from
              v_transition.closed_primary_assignment_id
        )
        or new.current_primary_assignment_id is distinct from
            v_transition.opened_primary_assignment_id
        or new.last_primary_assignment_id is distinct from
            v_transition.opened_primary_assignment_id then
        raise exception 'WorkItem assignment opening does not induce the exact OLD and NEW pointers'
          using errcode = '23514';
      end if;
    elsif v_transition.closed_primary_assignment_id is not null then
      if old.current_primary_assignment_id is distinct from
           v_transition.closed_primary_assignment_id
         or new.current_primary_assignment_id is not null
         or new.last_primary_assignment_id is distinct from
           v_transition.closed_primary_assignment_id then
        raise exception 'WorkItem assignment closure does not induce the exact OLD and NEW pointers'
          using errcode = '23514';
      end if;
    elsif new.current_primary_assignment_id is distinct from
            old.current_primary_assignment_id
       or new.last_primary_assignment_id is distinct from
            old.last_primary_assignment_id then
      raise exception 'WorkItem transition without assignment effect changed assignment pointers'
        using errcode = '23514';
    end if;

    if v_transition.kind in ('close_resolved', 'close_dismissed') then
      if v_transition.closed_servicing_team_episode_id is distinct from
           old.current_servicing_team_episode_id then
        raise exception 'Terminal WorkItem transition must close the exact OLD servicing-team head'
          using errcode = '23514';
      end if;
    elsif v_transition.closed_servicing_team_episode_id is not null then
      raise exception 'Non-terminal WorkItem transition cannot close a servicing-team episode'
        using errcode = '23514';
    end if;

    if v_transition.closed_servicing_team_episode_id is not null then
      select e.team_id into strict v_previous_team_id
        from public.inbox_v2_work_item_servicing_team_episodes e
       where e.tenant_id = new.tenant_id
         and e.work_item_id = new.id
         and e.id = v_transition.closed_servicing_team_episode_id;
      if old.current_servicing_team_id is distinct from v_previous_team_id
         or new.current_servicing_team_episode_id is not null
         or new.current_servicing_team_id is not null
         or new.last_servicing_team_episode_id is distinct from
            v_transition.closed_servicing_team_episode_id then
        raise exception 'Terminal WorkItem relation closure does not induce the exact OLD and NEW pointers'
          using errcode = '23514';
      end if;
    elsif new.current_servicing_team_episode_id is distinct from
            old.current_servicing_team_episode_id
       or new.current_servicing_team_id is distinct from
            old.current_servicing_team_id
       or new.last_servicing_team_episode_id is distinct from
            old.last_servicing_team_episode_id then
      raise exception 'Lifecycle transition without team closure changed servicing-team pointers'
        using errcode = '23514';
    end if;

    if v_transition.kind = 'priority_change' then
      if new.priority_id is not distinct from old.priority_id then
        raise exception 'Priority change cannot be a no-op'
          using errcode = '23514';
      end if;
    elsif new.priority_id is distinct from old.priority_id then
      raise exception 'Only priority_change may mutate WorkItem priority'
        using errcode = '23514';
    end if;

    select * into v_old_sla
      from public.inbox_v2_work_item_sla_snapshots s
     where s.tenant_id = old.tenant_id
       and s.work_item_id = old.id
       and s.sla_cycle = old.sla_cycle
       and s.revision = old.sla_snapshot_revision;
    select * into v_new_sla
      from public.inbox_v2_work_item_sla_snapshots s
     where s.tenant_id = new.tenant_id
       and s.work_item_id = new.id
       and s.sla_cycle = new.sla_cycle
       and s.revision = new.sla_snapshot_revision;
    if v_old_sla.revision is null or v_new_sla.revision is null then
      raise exception 'WorkItem mutation must retain exact OLD and NEW SLA snapshots'
        using errcode = '23514';
    end if;
    if v_transition.kind = 'sla_refresh' then
      if new.sla_cycle <> old.sla_cycle
         or new.sla_snapshot_revision <> old.sla_snapshot_revision + 1
         or v_old_sla.kind <> 'tracked'
         or v_new_sla.kind <> 'tracked'
         or v_new_sla.policy_id <> v_old_sla.policy_id
         or v_new_sla.policy_version <> v_old_sla.policy_version
         or v_new_sla.policy_revision <> v_old_sla.policy_revision
         or v_new_sla.business_calendar_id <>
            v_old_sla.business_calendar_id
         or v_new_sla.business_calendar_version <>
            v_old_sla.business_calendar_version
         or v_new_sla.business_calendar_revision <>
            v_old_sla.business_calendar_revision
         or v_new_sla.time_zone <> v_old_sla.time_zone
         or v_new_sla.started_at <> v_old_sla.started_at
         or v_new_sla.input_revision < v_old_sla.input_revision
         or (v_old_sla.first_human_response_at is not null and
           v_new_sla.first_human_response_at is distinct from
             v_old_sla.first_human_response_at) then
        raise exception 'SLA refresh must advance one tracked SLA snapshot revision'
          using errcode = '23514';
      end if;
    elsif v_transition.kind not in (
      'close_resolved',
      'close_dismissed',
      'reopen_unassigned',
      'reopen_assigned'
    ) and (
      new.sla_cycle <> old.sla_cycle
      or new.sla_snapshot_revision <> old.sla_snapshot_revision
    ) then
      raise exception 'This WorkItem transition cannot mutate SLA'
        using errcode = '23514';
    end if;
    if (
         new.sla_cycle <> old.sla_cycle
         or new.sla_snapshot_revision <> old.sla_snapshot_revision
       )
       and (
         v_new_sla.calculated_at <> new.updated_at
         or v_new_sla.created_at <> new.updated_at
       ) then
      raise exception 'New WorkItem SLA snapshot must be recorded at transition time'
        using errcode = '23514';
    end if;
    if v_transition.kind in ('close_resolved', 'close_dismissed') then
      if v_old_sla.kind = 'not_applied' then
        if new.sla_cycle <> old.sla_cycle
           or new.sla_snapshot_revision <> old.sla_snapshot_revision then
          raise exception 'Terminal close cannot synthesize an absent SLA'
            using errcode = '23514';
        end if;
      elsif new.sla_cycle <> old.sla_cycle
         or new.sla_snapshot_revision <> old.sla_snapshot_revision + 1
         or v_new_sla.kind <> 'tracked'
         or v_new_sla.policy_id <> v_old_sla.policy_id
         or v_new_sla.policy_version <> v_old_sla.policy_version
         or v_new_sla.policy_revision <> v_old_sla.policy_revision
         or v_new_sla.business_calendar_id <>
            v_old_sla.business_calendar_id
         or v_new_sla.business_calendar_version <>
            v_old_sla.business_calendar_version
         or v_new_sla.business_calendar_revision <>
            v_old_sla.business_calendar_revision
         or v_new_sla.time_zone <> v_old_sla.time_zone
         or v_new_sla.started_at <> v_old_sla.started_at
         or v_new_sla.clock_state <> 'stopped'
         or v_new_sla.stopped_at <> new.updated_at then
        raise exception 'Terminal close must append the exact stopped SLA revision'
          using errcode = '23514';
      end if;
    elsif v_transition.kind in ('reopen_unassigned', 'reopen_assigned') then
      if new.last_reopen_snapshot ->> 'slaMode' = 'new_cycle' then
        select * into v_destination_queue
          from public.inbox_v2_work_queue_versions q
         where q.tenant_id = v_transition.tenant_id
           and q.work_queue_id = v_transition.destination_queue_id
           and q.revision = v_transition.destination_queue_revision;
        if v_destination_queue.revision is null
           or new.sla_cycle <> old.sla_cycle + 1
           or new.sla_snapshot_revision <> 1
           or v_new_sla.kind <> v_destination_queue.default_sla_kind
           or (
             v_destination_queue.default_sla_kind = 'tracked'
             and (
               v_new_sla.policy_id <>
                  v_destination_queue.default_sla_policy_id
               or v_new_sla.policy_version <>
                  v_destination_queue.default_sla_policy_version
               or v_new_sla.policy_revision <>
                  v_destination_queue.default_sla_policy_revision
               or v_new_sla.input_revision <> 1
               or v_new_sla.business_calendar_id <>
                  v_destination_queue.default_business_calendar_id
               or v_new_sla.business_calendar_version <>
                  v_destination_queue.default_business_calendar_version
               or v_new_sla.business_calendar_revision <>
                  v_destination_queue.default_business_calendar_revision
               or v_new_sla.time_zone <>
                  v_destination_queue.default_sla_time_zone
               or v_new_sla.clock_state <> 'running'
               or v_new_sla.started_at <> new.updated_at
               or v_new_sla.paused_at is not null
               or v_new_sla.pause_condition_id is not null
               or v_new_sla.stopped_at is not null
               or v_new_sla.first_human_response_at is not null
             )
           ) then
          raise exception 'New-cycle reopen must reset SLA to exact destination Queue defaults'
            using errcode = '23514';
        end if;
      elsif new.last_reopen_snapshot ->> 'slaMode' = 'resume_remaining' then
        if v_old_sla.kind = 'not_applied' then
          if new.sla_cycle <> old.sla_cycle
             or new.sla_snapshot_revision <>
                old.sla_snapshot_revision then
            raise exception 'Resume cannot invent an SLA absent from the prior cycle'
              using errcode = '23514';
          end if;
        elsif new.sla_cycle <> old.sla_cycle
           or new.sla_snapshot_revision <> old.sla_snapshot_revision + 1
           or v_new_sla.kind <> 'tracked'
           or v_new_sla.policy_id <> v_old_sla.policy_id
           or v_new_sla.policy_version <> v_old_sla.policy_version
           or v_new_sla.policy_revision <> v_old_sla.policy_revision
           or v_new_sla.business_calendar_id <>
              v_old_sla.business_calendar_id
           or v_new_sla.business_calendar_version <>
              v_old_sla.business_calendar_version
           or v_new_sla.business_calendar_revision <>
              v_old_sla.business_calendar_revision
           or v_new_sla.time_zone <> v_old_sla.time_zone
           or v_new_sla.started_at <> v_old_sla.started_at
           or v_new_sla.clock_state = 'stopped' then
          raise exception 'Resume reopen must append one non-stopped SLA revision in the same cycle'
            using errcode = '23514';
        end if;
      else
        raise exception 'Reopen snapshot must select new_cycle or resume_remaining SLA mode'
          using errcode = '23514';
      end if;
    end if;
    if v_new_sla.kind = 'tracked' and (
      (new.state in ('resolved', 'dismissed') and
        v_new_sla.clock_state <> 'stopped')
      or (new.state in ('new', 'assigned', 'in_progress', 'waiting') and
        v_new_sla.clock_state = 'stopped')
    ) then
      raise exception 'Every WorkItem mutation must retain lifecycle-correct SLA clock state'
        using errcode = '23514';
    end if;

    if v_transition.kind in ('reopen_unassigned', 'reopen_assigned') then
      if new.reopen_cycle <> old.reopen_cycle + 1
         or new.last_reopen_snapshot is not distinct from
            old.last_reopen_snapshot
         or old.terminal_snapshot is null
         or new.terminal_snapshot is not null then
        raise exception 'Reopen must advance exact cycle and snapshot fields'
          using errcode = '23514';
      end if;
    elsif v_transition.kind in ('close_resolved', 'close_dismissed') then
      if new.reopen_cycle <> old.reopen_cycle
         or new.last_reopen_snapshot is distinct from old.last_reopen_snapshot
         or old.terminal_snapshot is not null
         or new.terminal_snapshot is null then
        raise exception 'Terminal close must preserve reopen history and append terminal snapshot'
          using errcode = '23514';
      end if;
    elsif new.reopen_cycle <> old.reopen_cycle
       or new.last_reopen_snapshot is distinct from old.last_reopen_snapshot
       or new.terminal_snapshot is distinct from old.terminal_snapshot then
      raise exception 'Only terminal close or reopen may mutate lifecycle snapshots'
        using errcode = '23514';
    end if;

    if new.collaborator_set_revision <> old.collaborator_set_revision then
      raise exception 'Lifecycle transition cannot mutate collaborator-set revision'
        using errcode = '23514';
    end if;

    v_expected_access_revision := old.resource_access_revision;
    if new.current_primary_assignment_id is distinct from
         old.current_primary_assignment_id
       or new.queue_id <> old.queue_id
       or new.queue_revision <> old.queue_revision
       or old.state in ('resolved', 'dismissed')
       or new.state in ('resolved', 'dismissed') then
      v_expected_access_revision := v_expected_access_revision + 1;
    end if;
    if new.resource_access_revision <> v_expected_access_revision then
      raise exception 'WorkItem mutation has an invalid resource-access revision step'
        using errcode = '23514';
    end if;
  elsif v_relation_transition_count = 1 then
    select * into strict v_relation
      from public.inbox_v2_work_item_relation_transitions r
     where r.tenant_id = new.tenant_id
       and r.work_item_id = new.id
       and r.resulting_work_item_revision = new.revision;

    if v_relation.expected_work_item_revision <> old.revision
       or v_relation.resulting_work_item_revision <> new.revision
       or v_relation.occurred_at <> new.updated_at
       or v_relation.expected_relation_revision <>
          old.servicing_team_relation_revision
       or v_relation.resulting_relation_revision <>
          new.servicing_team_relation_revision then
      raise exception 'Servicing-team relation proof does not bind the exact OLD and NEW heads'
        using errcode = '23514';
    end if;
    if old.state in ('resolved', 'dismissed')
       or new.state <> old.state
       or new.queue_id <> old.queue_id
       or new.queue_revision <> old.queue_revision
       or new.priority_id <> old.priority_id
       or new.sla_cycle <> old.sla_cycle
       or new.sla_snapshot_revision <> old.sla_snapshot_revision
       or new.current_primary_assignment_id is distinct from
          old.current_primary_assignment_id
       or new.last_primary_assignment_id is distinct from
          old.last_primary_assignment_id
       or new.collaborator_set_revision <> old.collaborator_set_revision
       or new.reopen_cycle <> old.reopen_cycle
       or new.last_reopen_snapshot is distinct from old.last_reopen_snapshot
       or new.terminal_snapshot is distinct from old.terminal_snapshot then
      raise exception 'Servicing-team relation command mutated an unrelated WorkItem field'
        using errcode = '23514';
    end if;
    if new.resource_access_revision <> old.resource_access_revision + 1 then
      raise exception 'Servicing-team relation command must advance resource access once'
        using errcode = '23514';
    end if;

    if v_relation.previous_episode_id is not null then
      select e.team_id into strict v_previous_team_id
        from public.inbox_v2_work_item_servicing_team_episodes e
       where e.tenant_id = new.tenant_id
         and e.work_item_id = new.id
         and e.id = v_relation.previous_episode_id;
      if old.current_servicing_team_episode_id is distinct from
           v_relation.previous_episode_id
         or old.current_servicing_team_id is distinct from
           v_previous_team_id then
        raise exception 'Servicing-team relation command did not close the exact OLD head'
          using errcode = '23514';
      end if;
    elsif old.current_servicing_team_episode_id is not null
       or old.current_servicing_team_id is not null then
      raise exception 'Servicing-team add requires an empty OLD relation head'
        using errcode = '23514';
    end if;

    if v_relation.next_episode_id is not null then
      select e.team_id into strict v_next_team_id
        from public.inbox_v2_work_item_servicing_team_episodes e
       where e.tenant_id = new.tenant_id
         and e.work_item_id = new.id
         and e.id = v_relation.next_episode_id;
      if new.current_servicing_team_episode_id is distinct from
           v_relation.next_episode_id
         or new.current_servicing_team_id is distinct from v_next_team_id
         or new.last_servicing_team_episode_id is distinct from
           v_relation.next_episode_id then
        raise exception 'Servicing-team relation command did not open the exact NEW head'
          using errcode = '23514';
      end if;
    elsif new.current_servicing_team_episode_id is not null
       or new.current_servicing_team_id is not null
       or new.last_servicing_team_episode_id is distinct from
          v_relation.previous_episode_id then
      raise exception 'Servicing-team removal did not induce the exact NEW head'
        using errcode = '23514';
    end if;
  else
    select * into strict v_collaborator_effect
      from public.inbox_v2_auth_revision_effects effect_row
     where effect_row.tenant_id = new.tenant_id
       and effect_row.effect_kind = 'collaborator_set'
       and effect_row.work_item_id = new.id
       and effect_row.resulting_work_item_revision = new.revision;

    if v_collaborator_effect.before_revision <>
         old.collaborator_set_revision
       or v_collaborator_effect.after_revision <>
         new.collaborator_set_revision
       or v_collaborator_effect.expected_work_item_revision <> old.revision
       or v_collaborator_effect.resulting_work_item_revision <> new.revision
       or v_collaborator_effect.work_item_cycle <> new.reopen_cycle
       or v_collaborator_effect.created_at <> new.updated_at
       or new.collaborator_set_revision <>
         old.collaborator_set_revision + 1
       or (to_jsonb(new) - array[
         'revision', 'updated_at', 'collaborator_set_revision'
       ]::text[]) is distinct from (to_jsonb(old) - array[
         'revision', 'updated_at', 'collaborator_set_revision'
       ]::text[]) then
      raise exception 'Collaborator-set proof does not bind the exact OLD and NEW WorkItem heads'
        using errcode = '23514';
    end if;
  end if;

  return null;
end
$$;



--
-- Name: inbox_v2_work_item_reject_immutable(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_item_reject_immutable() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if tg_table_name = 'inbox_v2_work_queue_versions'
       and not exists (
         select 1 from public.work_queues q
          where q.tenant_id = to_jsonb(old)->>'tenant_id'
            and q.id = to_jsonb(old)->>'work_queue_id'
       ) then
      return old;
    elsif tg_table_name = 'inbox_v2_employee_assignment_fence_versions'
       and not exists (
         select 1 from public.employees e
          where e.tenant_id = to_jsonb(old)->>'tenant_id'
            and e.id = to_jsonb(old)->>'employee_id'
       ) then
      return old;
    elsif tg_table_name in (
      'inbox_v2_work_item_sla_snapshots',
      'inbox_v2_work_queue_eligibility_decisions',
      'inbox_v2_work_item_transitions',
      'inbox_v2_work_item_relation_transitions'
    ) and not exists (
      select 1 from public.inbox_v2_work_items w
       where w.tenant_id = to_jsonb(old)->>'tenant_id'
         and w.id = to_jsonb(old)->>'work_item_id'
    ) then
      return old;
    elsif tg_table_name = 'inbox_v2_work_item_creation_decisions'
       and (
         not exists (
           select 1 from public.inbox_v2_work_items w
            where w.tenant_id = to_jsonb(old)->>'tenant_id'
              and w.id = to_jsonb(old)->>'work_item_id'
         )
         or not exists (
           select 1 from public.inbox_v2_conversations c
            where c.tenant_id = to_jsonb(old)->>'tenant_id'
              and c.id = to_jsonb(old)->>'conversation_id'
         )
       ) then
      return old;
    end if;
  end if;
  raise exception '% is append-only', tg_table_name using errcode = '23514';
end
$$;



--
-- Name: inbox_v2_work_item_slot_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_item_slot_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.inbox_v2_conversations c
       where c.tenant_id = old.tenant_id and c.id = old.conversation_id
    ) then
      return old;
    end if;
    raise exception 'Conversation WorkItem slot cannot be deleted'
      using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.revision <> 1 then
      raise exception 'Conversation WorkItem slot must start at revision 1'
        using errcode = '23514';
    end if;
  elsif new.tenant_id is distinct from old.tenant_id
     or new.id is distinct from old.id
     or new.conversation_id is distinct from old.conversation_id
     or new.created_at is distinct from old.created_at
     or new.revision <> old.revision + 1
     or new.updated_at < old.updated_at then
    raise exception 'Conversation WorkItem slot requires immutable identity and +1 CAS'
      using errcode = '23514';
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_work_queue_head_coherence(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_queue_head_coherence() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_tenant_id text;
  v_work_queue_id text;
  v_head_revision bigint;
  v_max_revision bigint;
begin
  v_tenant_id := new.tenant_id;
  v_work_queue_id := new.work_queue_id;

  select h.current_revision
    into v_head_revision
    from public.inbox_v2_work_queue_heads h
   where h.tenant_id = v_tenant_id
     and h.work_queue_id = v_work_queue_id;

  select max(v.revision)
    into v_max_revision
    from public.inbox_v2_work_queue_versions v
   where v.tenant_id = v_tenant_id
     and v.work_queue_id = v_work_queue_id;

  if v_head_revision is null
     or v_max_revision is null
     or v_head_revision <> v_max_revision then
    raise exception 'WorkQueue head must point to the latest immutable version'
      using errcode = '23514';
  end if;

  return null;
end
$$;



--
-- Name: inbox_v2_work_queue_head_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_queue_head_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.work_queues q
       where q.tenant_id = old.tenant_id and q.id = old.work_queue_id
    ) then
      return old;
    end if;
    raise exception 'WorkQueue head cannot be deleted' using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.current_revision <> 1 then
      raise exception 'WorkQueue head must start at revision 1'
        using errcode = '23514';
    end if;
  elsif new.tenant_id is distinct from old.tenant_id
     or new.work_queue_id is distinct from old.work_queue_id
     or new.created_at is distinct from old.created_at
     or new.current_revision <> old.current_revision + 1
     or new.updated_at < old.updated_at then
    raise exception 'WorkQueue head requires immutable identity and +1 CAS'
      using errcode = '23514';
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_work_relation_transition_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_relation_transition_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_work_revision bigint;
  v_relation_revision bigint;
begin
  select w.revision, w.servicing_team_relation_revision
    into v_work_revision, v_relation_revision
    from public.inbox_v2_work_items w
   where w.tenant_id = new.tenant_id and w.id = new.work_item_id
   for update;
  if v_work_revision not in (
       new.expected_work_item_revision,
       new.resulting_work_item_revision
     )
     or v_relation_revision not in (
       new.expected_relation_revision,
       new.resulting_relation_revision
     ) then
    raise exception 'Servicing-team transition lost its WorkItem/relation CAS race'
      using errcode = '40001';
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_work_team_episode_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_team_episode_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_work public.inbox_v2_work_items%rowtype;
begin
  if tg_op = 'DELETE' then
    if not exists (
      select 1 from public.inbox_v2_work_items w
       where w.tenant_id = old.tenant_id and w.id = old.work_item_id
    ) then
      return old;
    end if;
    raise exception 'Servicing-team history cannot be deleted'
      using errcode = '23514';
  end if;

  select * into v_work
    from public.inbox_v2_work_items w
   where w.tenant_id = new.tenant_id and w.id = new.work_item_id
   for update;
  if not found then
    raise exception 'Servicing-team episode requires a locked WorkItem'
      using errcode = '23514';
  end if;

  if tg_op = 'INSERT' then
    if new.state <> 'active' or new.revision <> 1 then
      raise exception 'Servicing-team episode must be inserted as active revision one'
        using errcode = '23514';
    elsif v_work.state in ('resolved', 'dismissed')
       or v_work.reopen_cycle <> new.work_item_cycle then
      raise exception 'Servicing-team episode must start in the current non-terminal cycle'
        using errcode = '23514';
    end if;
  elsif old.state <> 'active'
     or new.state <> 'ended'
     or old.revision <> 1
     or new.revision <> 2
     or row(
       new.tenant_id,
       new.id,
       new.work_item_id,
       new.work_item_cycle,
       new.team_id,
       new.started_at,
       new.started_actor_kind,
       new.started_actor_employee_id,
       new.started_actor_authorization_epoch,
       new.started_actor_trusted_service_id,
       new.start_reason_id,
       new.created_at
     ) is distinct from row(
       old.tenant_id,
       old.id,
       old.work_item_id,
       old.work_item_cycle,
       old.team_id,
       old.started_at,
       old.started_actor_kind,
       old.started_actor_employee_id,
       old.started_actor_authorization_epoch,
       old.started_actor_trusted_service_id,
       old.start_reason_id,
       old.created_at
     ) then
    raise exception 'Servicing-team episode permits one immutable active-to-ended closure'
      using errcode = '23514';
  end if;

  return new;
end
$$;



--
-- Name: inbox_v2_work_team_episode_non_overlap(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_team_episode_non_overlap() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
begin
  if exists (
    select 1
      from public.inbox_v2_work_item_servicing_team_episodes other
     where other.tenant_id = new.tenant_id
       and other.work_item_id = new.work_item_id
       and other.id <> new.id
       and other.started_at < coalesce(new.ended_at, 'infinity'::timestamptz)
       and new.started_at < coalesce(other.ended_at, 'infinity'::timestamptz)
  ) then
    raise exception 'Servicing-team intervals cannot overlap'
      using errcode = '23P01';
  end if;
  return null;
end
$$;



--
-- Name: inbox_v2_work_transition_guard(); Type: FUNCTION; Schema: public; Owner: <database-owner>
--

CREATE FUNCTION public.inbox_v2_work_transition_guard() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'pg_catalog', 'public', 'pg_temp'
    AS $$
declare
  v_work public.inbox_v2_work_items%rowtype;
  v_slot public.inbox_v2_conversation_work_item_slots%rowtype;
  v_destination_revision bigint;
  v_destination_lifecycle public.inbox_v2_work_queue_lifecycle;
  v_needs_destination_snapshot boolean;
begin
  select * into v_work
    from public.inbox_v2_work_items w
   where w.tenant_id = new.tenant_id and w.id = new.work_item_id
   for update;
  if not found or v_work.revision not in (
    new.expected_revision,
    new.resulting_revision
  ) then
    raise exception 'WorkItem transition lost its expected revision race'
      using errcode = '40001';
  end if;

  if v_work.revision = new.expected_revision and (
    v_work.state <> new.from_state
    or v_work.queue_id <> new.source_queue_id
    or v_work.queue_revision <> new.source_queue_revision
    or v_work.servicing_team_relation_revision <>
       new.expected_servicing_team_relation_revision
  ) then
    raise exception 'WorkItem transition source does not match the locked head'
      using errcode = '23514';
  elsif v_work.revision = new.resulting_revision and (
    v_work.state <> new.to_state
    or v_work.queue_id <> new.destination_queue_id
    or v_work.queue_revision <> new.destination_queue_revision
    or v_work.servicing_team_relation_revision <>
       new.resulting_servicing_team_relation_revision
  ) then
    raise exception 'WorkItem transition destination does not match the updated head'
      using errcode = '23514';
  end if;

  v_needs_destination_snapshot :=
    new.source_queue_id is distinct from new.destination_queue_id
    or new.source_queue_revision is distinct from new.destination_queue_revision
    or new.opened_primary_assignment_id is not null
    or new.kind in (
      'reopen_unassigned',
      'queue_transfer',
      'recovery_requeue'
    );
  if v_needs_destination_snapshot then
    select h.current_revision, v.lifecycle
      into v_destination_revision, v_destination_lifecycle
      from public.inbox_v2_work_queue_heads h
      join public.inbox_v2_work_queue_versions v
        on v.tenant_id = h.tenant_id
       and v.work_queue_id = h.work_queue_id
       and v.revision = h.current_revision
     where h.tenant_id = new.tenant_id
       and h.work_queue_id = new.destination_queue_id
     for update of h;
    if v_destination_revision is null
       or v_destination_revision <> new.destination_queue_revision
       or v_destination_lifecycle <> 'active' then
      raise exception 'Queue-changing/opening transition requires the current active destination Queue'
        using errcode = '23514';
    end if;
  end if;

  if new.kind in (
    'close_resolved',
    'close_dismissed',
    'reopen_unassigned',
    'reopen_assigned'
  ) then
    select * into v_slot
      from public.inbox_v2_conversation_work_item_slots s
     where s.tenant_id = v_work.tenant_id
       and s.conversation_id = v_work.conversation_id
     for update;
    if not found or v_slot.latest_work_item_id <> new.work_item_id then
      raise exception 'Close/reopen transition is allowed only for the latest WorkItem'
        using errcode = '23514';
    end if;
  end if;

  return new;
end
$$;



