--
-- Name: inbox_v2_action_attributions; Type: TABLE; Schema: public; Owner: <database-owner>
--

CREATE TABLE public.inbox_v2_action_attributions (
    tenant_id text NOT NULL,
    id text NOT NULL,
    conversation_id text NOT NULL,
    action_participant_id text,
    app_actor_kind public.inbox_v2_app_actor_kind,
    app_actor_employee_id text,
    app_authorization_epoch text,
    app_trusted_service_id text,
    source_occurrence_id text,
    automation_kind public.inbox_v2_automation_causation_kind,
    automation_cause_event_id text,
    automation_correlation_id text,
    automation_caused_at timestamp(3) with time zone,
    automation_initiating_employee_id text,
    automation_initiating_authorization_epoch text,
    created_at timestamp(3) with time zone NOT NULL,
    CONSTRAINT inbox_v2_action_attributions_actor_check CHECK (((num_nonnulls(app_actor_kind, source_occurrence_id) = 1) AND (((app_actor_kind = 'employee'::public.inbox_v2_app_actor_kind) AND (app_actor_employee_id IS NOT NULL) AND (app_authorization_epoch IS NOT NULL) AND (app_trusted_service_id IS NULL) AND (action_participant_id IS NOT NULL) AND (automation_kind IS NULL)) OR ((app_actor_kind = 'trusted_service'::public.inbox_v2_app_actor_kind) AND (app_actor_employee_id IS NULL) AND (app_authorization_epoch IS NULL) AND (app_trusted_service_id IS NOT NULL) AND (automation_kind IS NOT NULL)) OR ((app_actor_kind IS NULL) AND (source_occurrence_id IS NOT NULL) AND (automation_kind IS NULL))))),
    CONSTRAINT inbox_v2_action_attributions_automation_check CHECK ((((automation_kind IS NULL) AND (num_nonnulls(automation_cause_event_id, automation_correlation_id, automation_caused_at, automation_initiating_employee_id, automation_initiating_authorization_epoch) = 0)) OR ((automation_kind = 'system_event'::public.inbox_v2_automation_causation_kind) AND (automation_cause_event_id IS NOT NULL) AND (automation_correlation_id IS NOT NULL) AND (automation_caused_at IS NOT NULL) AND (automation_initiating_employee_id IS NULL) AND (automation_initiating_authorization_epoch IS NULL)) OR ((automation_kind = 'employee_command'::public.inbox_v2_automation_causation_kind) AND (num_nonnulls(automation_cause_event_id, automation_correlation_id, automation_caused_at, automation_initiating_employee_id, automation_initiating_authorization_epoch) = 5)))),
    CONSTRAINT inbox_v2_action_attributions_timestamp_check CHECK ((COALESCE(((char_length(id) <= 256) AND (id ~ '^action_attribution:[A-Za-z0-9][A-Za-z0-9._~:-]{0,199}$'::text)), false) AND isfinite(created_at) AND ((automation_caused_at IS NULL) OR (isfinite(automation_caused_at) AND (automation_caused_at <= created_at)))))
);



