);



--
-- Name: inbox_v2_auth_audit_events; Type: TABLE; Schema: public; Owner: <database-owner>
--

CREATE TABLE public.inbox_v2_auth_audit_events (
    tenant_id text NOT NULL,
    id text NOT NULL,
    mutation_id text NOT NULL,
    command_record_id text NOT NULL,
    category text NOT NULL,
    action_id text NOT NULL,
    actor_kind public.inbox_v2_auth_actor_kind NOT NULL,
    actor_employee_id text,
    actor_trusted_service_id text,
    target_type_id text NOT NULL,
    internal_target_ref text NOT NULL,
    facet_count smallint NOT NULL,
    facets_digest_sha256 text NOT NULL,
    authorization_decision_refs jsonb NOT NULL,
    authorization_epoch text NOT NULL,
    revision_delta_hash text NOT NULL,
    reason_code_id text NOT NULL,
    client_mutation_id text NOT NULL,
    command_type_id text NOT NULL,
    request_hash text NOT NULL,
    correlation_id text NOT NULL,
    matched_permission_ids text[] NOT NULL,
    grant_source_ids text[] NOT NULL,
    scope_ids text[] NOT NULL,
    override_reason_id text,
    policy_version text,
    evidence_reference jsonb,
    outcome text NOT NULL,
    previous_audit_hash text,
    audit_hash text NOT NULL,
    occurred_at timestamp(3) with time zone NOT NULL,
    recorded_at timestamp(3) with time zone NOT NULL,
    expires_at timestamp(3) with time zone NOT NULL,
    created_at timestamp(3) with time zone NOT NULL,
    CONSTRAINT inbox_v2_auth_audit_events_actor_check CHECK ((((actor_kind = 'employee'::public.inbox_v2_auth_actor_kind) AND (actor_employee_id IS NOT NULL) AND (actor_trusted_service_id IS NULL)) OR ((actor_kind = 'trusted_service'::public.inbox_v2_auth_actor_kind) AND (actor_employee_id IS NULL) AND (actor_trusted_service_id IS NOT NULL) AND (char_length(actor_trusted_service_id) <= 256) AND (((actor_trusted_service_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(actor_trusted_service_id, ':'::text, 2)) <= 160)) OR ((actor_trusted_service_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(actor_trusted_service_id, ':'::text, 2)) <= 80) AND (char_length(split_part(actor_trusted_service_id, ':'::text, 3)) <= 160) AND (split_part(actor_trusted_service_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text]))))))),
    CONSTRAINT inbox_v2_auth_audit_events_reference_check CHECK (((category = 'privileged_security'::text) AND (char_length(action_id) <= 256) AND (((action_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(action_id, ':'::text, 2)) <= 160)) OR ((action_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(action_id, ':'::text, 2)) <= 80) AND (char_length(split_part(action_id, ':'::text, 3)) <= 160) AND (split_part(action_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text])))) AND (char_length(target_type_id) <= 256) AND (((target_type_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(target_type_id, ':'::text, 2)) <= 160)) OR ((target_type_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(target_type_id, ':'::text, 2)) <= 80) AND (char_length(split_part(target_type_id, ':'::text, 3)) <= 160) AND (split_part(target_type_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text])))) AND (internal_target_ref ~ '^internal-ref:[a-f0-9]{32,64}$'::text) AND ((facet_count >= 1) AND (facet_count <= 64)) AND (facets_digest_sha256 ~ '^sha256:[0-9a-f]{64}$'::text) AND (jsonb_typeof(authorization_decision_refs) = 'array'::text) AND ((jsonb_array_length(authorization_decision_refs) >= 1) AND (jsonb_array_length(authorization_decision_refs) <= 64)) AND ((char_length(authorization_epoch) >= 8) AND (char_length(authorization_epoch) <= 1024)) AND (revision_delta_hash ~ '^sha256:[0-9a-f]{64}$'::text) AND (char_length(reason_code_id) <= 256) AND (((reason_code_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(reason_code_id, ':'::text, 2)) <= 160)) OR ((reason_code_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_