CREATE TABLE public.inbox_v2_source_identity_claim_heads (
    tenant_id text NOT NULL,
    source_external_identity_id text NOT NULL,
    resolution_status public.inbox_v2_source_identity_resolution_status NOT NULL,
    active_claim_id text,
    latest_claim_version bigint,
    CONSTRAINT inbox_v2_source_identity_claim_heads_shape_check CHECK ((((resolution_status = 'unresolved'::public.inbox_v2_source_identity_resolution_status) AND (active_claim_id IS NULL) AND (latest_claim_version IS NULL)) OR ((resolution_status = ANY (ARRAY['unresolved'::public.inbox_v2_source_identity_resolution_status, 'conflicted'::public.inbox_v2_source_identity_resolution_status])) AND (active_claim_id IS NULL) AND (latest_claim_version IS NOT NULL)) OR ((resolution_status = 'claimed'::public.inbox_v2_source_identity_resolution_status) AND (active_claim_id IS NOT NULL) AND (latest_claim_version IS NOT NULL)))),
    CONSTRAINT inbox_v2_source_identity_claim_heads_version_check CHECK (((latest_claim_version IS NULL) OR (latest_claim_version >= 1)))
);



--
-- Name: inbox_v2_source_identity_claim_transitions; Type: TABLE; Schema: public; Owner: <database-owner>
--

CREATE TABLE public.inbox_v2_source_identity_claim_transitions (
    tenant_id text NOT NULL,
    id text NOT NULL,
    source_external_identity_id text NOT NULL,
    operation_kind public.inbox_v2_source_identity_claim_operation_kind NOT NULL,
    target_kind public.inbox_v2_source_identity_claim_target_kind NOT NULL,
    target_employee_id text,
    target_client_contact_id text,
    target_key text GENERATED ALWAYS AS (
CASE target_kind
    WHEN 'employee'::public.inbox_v2_source_identity_claim_target_kind THEN ((('employee|'::text || (octet_length(target_employee_id))::text) || ':'::text) || target_employee_id)
    WHEN 'client_contact'::public.inbox_v2_source_identity_claim_target_kind THEN ((('client_contact|'::text || (octet_length(target_client_contact_id))::text) || ':'::text) || target_client_contact_id)
    ELSE NULL::text
END) STORED NOT NULL,
    previous_claim_id text,
    previous_target_kind public.inbox_v2_source_identity_claim_target_kind,
    previous_target_employee_id text,
    previous_target_client_contact_id text,
    previous_target_key text GENERATED ALWAYS AS (
CASE previous_target_kind
    WHEN 'employee'::public.inbox_v2_source_identity_claim_target_kind THEN ((('employee|'::text || (octet_length(previous_target_employee_id))::text) || ':'::text) || previous_target_employee_id)
    WHEN 'client_contact'::public.inbox_v2_source_identity_claim_target_kind THEN ((('client_contact|'::text || (octet_length(previous_target_client_contact_id))::text) || ':'::text) || previous_target_client_contact_id)
    ELSE NULL::text
END) STORED,
    resulting_claim_id text,
    active_claim_id text,
    decision_kind public.inbox_v2_source_identity_claim_decision_kind NOT NULL,
    decision_actor_employee_id text,
    decision_trusted_service_id text,
    policy_family public.inbox_v2_tenant_policy_family,
    policy_definition_contract_version text,
    policy_definition_digest_sha256 text,
    policy_activation_head_revision bigint,
    policy_id text NOT NULL,
    policy_version text NOT NULL,
    reason_code_id text NOT NULL,
    expected_version bigint,
    current_version bigint,
    resulting_version bigint NOT NULL,
    occurred_at timestamp(3) with time zone NOT NULL,
    CONSTRAINT inbox_v2_identity_claim_transition_cas_check CHECK ((((expected_version IS NULL) AND (current_version IS NULL) AND (resulting_version = 1)) OR ((expected_version IS NOT NULL) AND (current_version = expected_version) AND (resulting_version = (current_version + 1))))),
    CONSTRAINT inbox_v2_identity_claim_transition_catalog_check CHECK (((char_length(policy_id) <= 256) AND (((policy_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(policy_id, ':'::text, 2)) <= 160)) OR ((policy_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(policy_id, ':'::text, 2)) <= 80) AND (char_length(split_part(policy_id, ':'::text, 3)) <= 160) AND (split_part(policy_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text])))) AND (policy_version ~ '^v[1-9][0-9]*$'::text) AND (char_length(reason_code_id) <= 256) AND (((reason_code_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(reason_code_id, ':'::text, 2)) <= 160)) OR ((reason_code_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(reason_code_id, ':'::text, 2)) <= 80) AND (char_length(split_part(reason_code_id, ':'::text, 3)) <= 160) AND (split_part(reason_code_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text])))))),
    CONSTRAINT inbox_v2_identity_claim_transition_clock_check CHECK (isfinite(occurred_at)),
    CONSTRAINT inbox_v2_identity_claim_transition_decision_check CHECK ((((decision_kind = 'manual'::public.inbox_v2_source_identity_claim_decision_kind) AND (decision_actor_employee_id IS NOT NULL) AND (decision_trusted_service_id IS NULL)) OR ((decision_kind = ANY (ARRAY['automatic_policy'::public.inbox_v2_source_identity_claim_decision_kind, 'migration'::public.inbox_v2_source_identity_claim_decision_kind])) AND (decision_actor_employee_id IS NULL) AND (decision_trusted_service_id IS NOT NULL) AND (char_length(decision_trusted_service_id) <= 256) AND (((decision_trusted_service_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(decision_trusted_service_id, ':'::text, 2)) <= 160)) OR ((decision_trusted_service_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(decision_trusted_service_id, ':'::text, 2)) <= 80) AND (char_length(split_part(decision_trusted_service_id, ':'::text, 3)) <= 160) AND (split_part(decision_trusted_service_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text]))))))),
    CONSTRAINT inbox_v2_identity_claim_transition_id_format_check CHECK (((char_length(id) <= 256) AND (id ~ '^source_identity_claim_transition:[A-Za-z0-9][A-Za-z0-9._~:-]{0,199}$'::text))),
    CONSTRAINT inbox_v2_identity_claim_transition_operation_check CHECK ((((operation_kind = 'claim_employee'::public.inbox_v2_source_identity_claim_operation_kind) AND (target_kind = 'employee'::public.inbox_v2_source_identity_claim_target_kind) AND (resulting_claim_id IS NOT NULL) AND (active_claim_id IS NULL)) OR ((operation_kind = 'claim_client_contact'::public.inbox_v2_source_identity_claim_operation_kind) AND (target_kind = 'client_contact'::public.inbox_v2_source_identity_claim_target_kind) AND (resulting_claim_id IS NOT NULL) AND (active_claim_id IS NULL)) OR ((operation_kind = 'revoke'::public.inbox_v2_source_identity_claim_operation_kind) AND (resulting_claim_id IS NULL) AND (active_claim_id IS NOT NULL) AND (previous_claim_id IS NULL)))),
    CONSTRAINT inbox_v2_identity_claim_transition_policy_authority_check CHECK ((((decision_kind = 'automatic_policy'::public.inbox_v2_source_identity_claim_decision_kind) AND (policy_family = 'source_identity_claim'::public.inbox_v2_tenant_policy_family) AND (policy_definition_contract_version IS NOT NULL) AND (policy_definition_contract_version ~ '^v[1-9][0-9]*$'::text) AND (policy_definition_digest_sha256 IS NOT NULL) AND (policy_definition_digest_sha256 ~ '^[a-f0-9]{64}$'::text) AND (policy_activation_head_revision >= 1)) OR ((decision_kind <> 'automatic_policy'::public.inbox_v2_source_identity_claim_decision_kind) AND (policy_family IS NULL) AND (policy_definition_contract_version IS NULL) AND (policy_definition_digest_sha256 IS NULL) AND (policy_activation_head_revision IS NULL)))),
    CONSTRAINT inbox_v2_identity_claim_transition_previous_target_check CHECK ((((previous_claim_id IS NULL) AND (previous_target_kind IS NULL) AND (previous_target_employee_id IS NULL) AND (previous_target_client_contact_id IS NULL) AND (previous_target_key IS NULL)) OR (((previous_claim_id IS NOT NULL) AND (previous_target_kind IS NOT NULL) AND (previous_target_key IS NOT NULL) AND ((previous_target_kind = 'employee'::public.inbox_v2_source_identity_claim_target_kind) AND (previous_target_employee_id IS NOT NULL) AND (previous_target_client_contact_id IS NULL))) OR ((previous_target_kind = 'client_contact'::public.inbox_v2_source_identity_claim_target_kind) AND (previous_target_employee_id IS NULL) AND (previous_target_client_contact_id IS NOT NULL))))),
    CONSTRAINT inbox_v2_identity_claim_transition_self_claim_check CHECK (((operation_kind <> 'claim_employee'::public.inbox_v2_source_identity_claim_operation_kind) OR (decision_kind <> 'manual'::public.inbox_v2_source_identity_claim_decision_kind) OR (target_employee_id <> decision_actor_employee_id))),
    CONSTRAINT inbox_v2_identity_claim_transition_target_check CHECK ((((target_kind = 'employee'::public.inbox_v2_source_identity_claim_target_kind) AND (target_employee_id IS NOT NULL) AND (target_client_contact_id IS NULL)) OR ((target_kind = 'client_contact'::public.inbox_v2_source_identity_claim_target_kind) AND (target_employee_id IS NULL) AND (target_client_contact_id IS NOT NULL))))
);



