    CONSTRAINT inbox_v2_identity_claims_decision_catalog_check CHECK (((char_length(policy_id) <= 256) AND (((policy_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(policy_id, ':'::text, 2)) <= 160)) OR ((policy_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(policy_id, ':'::text, 2)) <= 80) AND (char_length(split_part(policy_id, ':'::text, 3)) <= 160) AND (split_part(policy_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text])))) AND (policy_version ~ '^v[1-9][0-9]*$'::text) AND (char_length(reason_code_id) <= 256) AND (((reason_code_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(reason_code_id, ':'::text, 2)) <= 160)) OR ((reason_code_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(reason_code_id, ':'::text, 2)) <= 80) AND (char_length(split_part(reason_code_id, ':'::text, 3)) <= 160) AND (split_part(reason_code_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text])))))),
    CONSTRAINT inbox_v2_identity_claims_decision_check CHECK ((((decision_kind = 'manual'::public.inbox_v2_source_identity_claim_decision_kind) AND (decision_actor_employee_id IS NOT NULL) AND (decision_trusted_service_id IS NULL)) OR ((decision_kind = ANY (ARRAY['automatic_policy'::public.inbox_v2_source_identity_claim_decision_kind, 'migration'::public.inbox_v2_source_identity_claim_decision_kind])) AND (decision_actor_employee_id IS NULL) AND (decision_trusted_service_id IS NOT NULL) AND (char_length(decision_trusted_service_id) <= 256) AND (((decision_trusted_service_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(decision_trusted_service_id, ':'::text, 2)) <= 160)) OR ((decision_trusted_service_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(decision_trusted_service_id, ':'::text, 2)) <= 80) AND (char_length(split_part(decision_trusted_service_id, ':'::text, 3)) <= 160) AND (split_part(decision_trusted_service_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text]))))))),
    CONSTRAINT inbox_v2_identity_claims_id_format_check CHECK (((char_length(id) <= 256) AND (id ~ '^source_identity_claim:[A-Za-z0-9][A-Za-z0-9._~:-]{0,199}$'::text))),
    CONSTRAINT inbox_v2_identity_claims_manual_self_claim_check CHECK (((decision_kind <> 'manual'::public.inbox_v2_source_identity_claim_decision_kind) OR (target_kind <> 'employee'::public.inbox_v2_source_identity_claim_target_kind) OR (target_employee_id <> decision_actor_employee_id))),
    CONSTRAINT inbox_v2_identity_claims_policy_authority_check CHECK ((((decision_kind = 'automatic_policy'::public.inbox_v2_source_identity_claim_decision_kind) AND (policy_family = 'source_identity_claim'::public.inbox_v2_tenant_policy_family) AND (policy_definition_contract_version IS NOT NULL) AND (policy_definition_contract_version ~ '^v[1-9][0-9]*$'::text) AND (policy_definition_digest_sha256 IS NOT NULL) AND (policy_definition_digest_sha256 ~ '^[a-f0-9]{64}$'::text) AND (policy_activation_head_revision >= 1)) OR ((decision_kind <> 'automatic_policy'::public.inbox_v2_source_identity_claim_decision_kind) AND (policy_family IS NULL) AND (policy_definition_contract_version IS NULL) AND (policy_definition_digest_sha256 IS NULL) AND (policy_activation_head_revision IS NULL)))),
    CONSTRAINT inbox_v2_identity_claims_state_check CHECK ((((status = 'active'::public.inbox_v2_source_identity_claim_status) AND (revoked_at IS NULL) AND (revision = 1)) OR ((status = 'revoked'::public.inbox_v2_source_identity_claim_status) AND (revoked_at IS NOT NULL) AND isfinite(revoked_at) AND (revoked_at >= created_at) AND (revision = 2)))),
    CONSTRAINT inbox_v2_identity_claims_target_check CHECK ((((target_kind = 'employee'::public.inbox_v2_source_identity_claim_target_kind) AND (target_employee_id IS NOT NULL) AND (target_client_contact_id IS NULL)) OR ((target_kind = 'client_contact'::public.inbox_v2_source_identity_claim_target_kind) AND (target_employee_id IS NULL) AND (target_client_contact_id IS NOT NULL)))),
    CONSTRAINT inbox_v2_identity_claims_version_check CHECK ((((previous_claim_version IS NULL) AND (claim_version = 1)) OR ((previous_claim_version IS NOT NULL) AND (claim_version = (previous_claim_version + 1)))))
);



