    acknowledged_at timestamp(3) with time zone NOT NULL,
    created_at timestamp(3) with time zone NOT NULL,
    updated_at timestamp(3) with time zone NOT NULL,
    CONSTRAINT inbox_v2_src_cursor_identity_check CHECK (((char_length(cursor_slot_id) >= 1) AND (char_length(cursor_slot_id) <= 128) AND (cursor_slot_id ~ '^[a-z][a-z0-9]*([._:-][a-z0-9]+)*$'::text) AND (route_generation >= 1) AND (purpose_id = 'core:source_ingress_cursor'::text) AND ((char_length(key_generation) >= 1) AND (char_length(key_generation) <= 128)) AND (key_generation ~ '^[A-Za-z0-9][A-Za-z0-9._~:-]*$'::text) AND ((char_length(cursor_value_secret_ref) >= 8) AND (char_length(cursor_value_secret_ref) <= 512)) AND (cursor_value_secret_ref ~ '^secret:[A-Za-z0-9][A-Za-z0-9._~:/-]*$'::text) AND (cursor_hmac_sha256 ~ '^hmac-sha256:[0-9a-f]{64}$'::text) AND (((durable_target_kind = 'raw_work'::public.inbox_v2_source_cursor_durable_target_kind) AND ((char_length(durable_work_id) >= 8) AND (char_length(durable_work_id) <= 256)) AND (durable_work_id ~ '^[A-Za-z0-9][A-Za-z0-9._~:/-]*$'::text) AND (durable_work_revision >= 1) AND (last_durable_raw_event_id IS NOT NULL) AND (durable_work_state IS NOT NULL) AND (quarantine_id IS NULL) AND (quarantine_fingerprint_sha256 IS NULL)) OR ((durable_target_kind = 'quarantine'::public.inbox_v2_source_cursor_durable_target_kind) AND (last_durable_raw_event_id IS NULL) AND (durable_work_id IS NULL) AND (durable_work_revision IS NULL) AND (durable_work_state IS NULL) AND ((char_length(quarantine_id) >= 8) AND (char_length(quarantine_id) <= 256)) AND (quarantine_id ~ '^[A-Za-z0-9][A-Za-z0-9._~:/-]*$'::text) AND (quarantine_fingerprint_sha256 ~ '^sha256:[0-9a-f]{64}$'::text))) AND (revision >= 1))),
    CONSTRAINT inbox_v2_src_cursor_owner_check CHECK ((((cursor_owner = 'source_connection'::public.inbox_v2_source_cursor_owner) AND (source_thread_binding_id IS NULL)) OR ((cursor_owner = 'source_account'::public.inbox_v2_source_cursor_owner) AND (source_account_id IS NOT NULL) AND (source_thread_binding_id IS NULL)) OR ((cursor_owner = 'source_thread_binding'::public.inbox_v2_source_cursor_owner) AND (source_account_id IS NOT NULL) AND (source_thread_binding_id IS NOT NULL)))),
    CONSTRAINT inbox_v2_src_cursor_scope_check CHECK ((source_account_scope_key =
CASE
    WHEN (source_account_id IS NULL) THEN '0:'::text
    ELSE ((('1:'::text || (octet_length(source_account_id))::text) || ':'::text) || source_account_id)
END)),
    CONSTRAINT inbox_v2_src_cursor_times_check CHECK ((isfinite(persisted_at) AND isfinite(acknowledged_at) AND isfinite(created_at) AND isfinite(updated_at) AND (created_at <= persisted_at) AND (persisted_at <= acknowledged_at) AND (acknowledged_at <= updated_at)))
);



--
-- Name: inbox_v2_source_message_correlation_evidence; Type: TABLE; Schema: public; Owner: <database-owner>
--

CREATE TABLE public.inbox_v2_source_message_correlation_evidence (
    tenant_id text NOT NULL,
