    expiry_action text DEFAULT 'hard_delete'::text NOT NULL,
    created_at timestamp(3) with time zone NOT NULL,
    CONSTRAINT inbox_v2_source_message_correlation_evidence_governance_check CHECK (((data_class_id = 'core:operational_log_trace_diagnostic'::text) AND (sensitivity_class = 'security_evidence'::text) AND (processing_purpose_id = 'core:source_replay_and_diagnostics'::text) AND (canonical_anchor_id = 'core:creation'::text) AND (expiry_action = 'hard_delete'::text))),
    CONSTRAINT inbox_v2_source_message_correlation_evidence_values_check CHECK (((ordinal >= 0) AND (ordinal <= 7) AND COALESCE(((char_length(code_id) <= 256) AND (((code_id ~ '^core:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(code_id, ':'::text, 2)) <= 160)) OR ((code_id ~ '^module:[a-z][a-z0-9]*([._-][a-z0-9]+)*:[a-z][a-z0-9]*([._-][a-z0-9]+)*$'::text) AND (char_length(split_part(code_id, ':'::text, 2)) <= 80) AND (char_length(split_part(code_id, ':'::text, 3)) <= 160) AND (split_part(code_id, ':'::text, 2) <> ALL (ARRAY['core'::text, 'hulee'::text, 'module'::text, 'platform'::text, 'system'::text]))))), false) AND COALESCE((evidence_hmac_sha256 ~ '^hmac-sha256:[a-f0-9]{64}$'::text), false) AND isfinite(created_at) AND isfinite(expires_at) AND (expires_at > created_at) AND (expires_at <= (created_at + '30 days'::interval))))
